import * as fs from 'fs';
import * as path from 'path';

const localesDir = path.join(process.cwd(), 'src/i18n/locales');
const sourceFile = 'en.json';
const targetFiles = ['ru.json', 'kk.json', 'uk.json', 'uz.json'];

function flattenKeys(obj: any, prefix = ''): string[] {
    let keys: string[] = [];
    for (const key in obj) {
        if (typeof obj[key] === 'object' && obj[key] !== null && !Array.isArray(obj[key])) {
            keys = keys.concat(flattenKeys(obj[key], prefix + key + '.'));
        } else {
            keys.push(prefix + key);
        }
    }
    return keys;
}

function loadJson(filename: string): any {
    const filePath = path.join(localesDir, filename);
    const content = fs.readFileSync(filePath, 'utf-8');
    return JSON.parse(content);
}

try {
    console.log(`Loading source: ${sourceFile}`);
    const sourceData = loadJson(sourceFile);
    const sourceKeys = new Set(flattenKeys(sourceData));
    console.log(`Source keys count: ${sourceKeys.size}`);

    for (const targetFile of targetFiles) {
        console.log(`\nChecking ${targetFile}...`);
        try {
            const targetData = loadJson(targetFile);
            const targetKeys = new Set(flattenKeys(targetData));

            const missingKeys = Array.from(sourceKeys).filter(k => !targetKeys.has(k));

            console.log(`Total keys: ${targetKeys.size}`);
            console.log(`Missing keys count: ${missingKeys.length}`);
            if (missingKeys.length > 0) {
                console.log('Sample missing keys (first 10):');
                missingKeys.slice(0, 10).forEach(k => console.log(`  - ${k}`));
            }
        } catch (error: any) {
            console.error(`Error processing ${targetFile}:`, error.message);
        }
    }

} catch (error: any) {
    console.error('Fatal error:', error.message);
}

const path = "c:\\Users\\admin\\OneDrive - УО 'Алматы Менеджмент Университет'\\Документы\\inkmax\\src\\i18n\\locales\\kk.json";

try {
    const content = await Deno.readTextFile(path);
    const data = JSON.parse(content);

    // Ensure translation object exists
    if (!data.translation) {
        console.log("No translation object found!");
        Deno.exit(1);
    }

    const t = data.translation;
    const rootKeys = ['experts', 'themes', 'gallery', 'footer', 'pricing', 'seo', 'pwa', 'teams', 'friends', 'gift', 'telegram', 'product', 'paidContent', 'adminVerification', 'collab', 'rewards', 'onboarding', 'landing', 'blocks', 'auth', 'common', 'errors', 'form', 'newsletter', 'success', 'actions', 'profile', 'verification', 'frames', 'nameAnimation', 'profileEditor', 'blockTypes', 'recommendations', 'settings', 'niche', 'niches'];
    // Added more keys that might be at root. Based on previous inspections, specifically 'experts', 'themes', 'gallery', 'footer', 'pricing' were seen at root.

    // We should also check for duplicates INSIDE translation object that usually cause linter errors.
    // However, JSON.parse behaves by taking the LAST occurrence of a duplicate key.
    // So simply parsing and stringifying removes duplicates automatically!
    // The main task is to move misplaced root keys into translation object.

    // Specific root keys we saw in the file view:
    const keysToMove = ['experts', 'themes', 'gallery', 'footer', 'pricing'];

    for (const key of keysToMove) {
        if (data[key]) {
            console.log(`Processing root key: ${key}`);

            if (!t[key]) {
                t[key] = data[key];
            } else {
                // Merge if exists
                console.log(`Merging ${key} into translation.${key}`);
                if (typeof t[key] === 'object' && typeof data[key] === 'object') {
                    Object.assign(t[key], data[key]);
                }
            }
            delete data[key];
        }
    }

    // Write back
    await Deno.writeTextFile(path, JSON.stringify(data, null, 2));
    console.log("Successfully fixed kk.json structure and removed syntax duplicates via parse/stringify");

} catch (e) {
    console.error("Error:", e);
}

import { useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Badge } from '@/components/ui/badge';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { AnalyticsFilterPanel } from './AnalyticsFilterPanel';
import { useAdminAnalytics, COLORS } from '@/hooks/admin/useAdminAnalytics';
import {
  AreaChart, Area, BarChart, Bar, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer
} from 'recharts';
import {
  Loader2, Eye, MousePointer, TrendingUp, TrendingDown,
  Users, Activity, Calendar,
  Monitor, Smartphone, Tablet, Globe
} from 'lucide-react';

export function AdminAnalyticsDashboard() {
  const { t } = useTranslation();

  const {
    loading,
    period,
    setPeriod,
    analytics,
    filters,
    setFilters,
    filteredAnalytics
  } = useAdminAnalytics();

  const getDayNames = () => [
    t('admin.dayNames.sun'),
    t('admin.dayNames.mon'),
    t('admin.dayNames.tue'),
    t('admin.dayNames.wed'),
    t('admin.dayNames.thu'),
    t('admin.dayNames.fri'),
    t('admin.dayNames.sat')
  ];

  const availableDevices = useMemo(
    () => analytics?.eventsByDevice.map(d => d.name.toLowerCase()) || [],
    [analytics]
  );

  const availableSources = useMemo(
    () => analytics?.eventsBySource.map(s => s.name.toLowerCase()) || [],
    [analytics]
  );

  const availablePages = useMemo(
    () => analytics?.topPages.map(p => p.slug) || [],
    [analytics]
  );

  const dayNamesArr = getDayNames();

  // Transform engagementByDay to use localized names
  const displayedAnalytics = useMemo(() => {
    if (!analytics) return null;
    return {
      ...analytics,
      engagementByDay: analytics.engagementByDay.map(d => ({
        ...d,
        day: dayNamesArr[parseInt(d.day)] || d.day
      }))
    };
  }, [analytics, dayNamesArr]);

  const formatNumber = (num: number) => {
    if (num >= 1000000) return (num / 1000000).toFixed(1) + 'M';
    if (num >= 1000) return (num / 1000).toFixed(1) + 'K';
    return num.toLocaleString();
  };

  const renderTrend = (value: number) => {
    if (value === 0) return <span className="text-muted-foreground">-</span>;
    const isPositive = value > 0;
    return (
      <span className={`flex items-center text-xs ${isPositive ? 'text-green-500' : 'text-red-500'}`}>
        {isPositive ? <TrendingUp className="h-3 w-3 mr-1" /> : <TrendingDown className="h-3 w-3 mr-1" />}
        {Math.abs(value)}%
      </span>
    );
  };

  if (loading) {
    return (
      <div className="flex h-[400px] w-full items-center justify-center">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  if (!analytics || !filteredAnalytics) {
    return <div className="p-4 text-center">{t('admin.noData')}</div>;
  }

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold tracking-tight">{t('admin.analyticsTitle')}</h2>
          <p className="text-muted-foreground">{t('admin.analyticsSubtitle')}</p>
        </div>
        <div className="flex items-center gap-2">
          <Select value={period} onValueChange={(v: any) => setPeriod(v)}>
            <SelectTrigger className="w-[180px]">
              <Calendar className="mr-2 h-4 w-4" />
              <SelectValue placeholder={t('admin.selectPeriod')} />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="7d">{t('admin.periods.7d')}</SelectItem>
              <SelectItem value="14d">{t('admin.periods.14d')}</SelectItem>
              <SelectItem value="30d">{t('admin.periods.30d')}</SelectItem>
              <SelectItem value="90d">{t('admin.periods.90d')}</SelectItem>
            </SelectContent>
          </Select>
        </div>
      </div>

      <AnalyticsFilterPanel
        filters={filters}
        onFiltersChange={setFilters}
        availableDevices={availableDevices}
        availableSources={availableSources}
        availablePages={availablePages}
      />

      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">{t('admin.totalViews')}</CardTitle>
            <Eye className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{formatNumber(analytics.totalViews)}</div>
            <p className="text-xs text-muted-foreground mt-1 flex items-center gap-1">
              {renderTrend(analytics.viewsTrend)} {t('admin.vsPrevPeriod')}
            </p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">{t('admin.totalClicks')}</CardTitle>
            <MousePointer className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{formatNumber(analytics.totalClicks)}</div>
            <p className="text-xs text-muted-foreground mt-1 flex items-center gap-1">
              {renderTrend(analytics.clicksTrend)} {t('admin.vsPrevPeriod')}
            </p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">{t('admin.uniqueVisitors')}</CardTitle>
            <Users className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{formatNumber(analytics.uniqueVisitors)}</div>
            <p className="text-xs text-muted-foreground mt-1">
              {formatNumber(analytics.totalSessions)} {t('admin.sessions')}
            </p>
          </CardContent>
        </Card>
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">{t('admin.conversionRate')}</CardTitle>
            <Activity className="h-4 w-4 text-muted-foreground" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">
              {analytics.totalViews > 0
                ? ((analytics.totalClicks / analytics.totalViews) * 100).toFixed(1)
                : '0.0'}%
            </div>
            <p className="text-xs text-muted-foreground mt-1">
              Test CTR
            </p>
          </CardContent>
        </Card>
      </div>

      <Tabs defaultValue="overview" className="space-y-4">
        <TabsList>
          <TabsTrigger value="overview">{t('admin.tabs.overview')}</TabsTrigger>
          <TabsTrigger value="engagement">{t('admin.tabs.engagement')}</TabsTrigger>
          <TabsTrigger value="top">{t('admin.tabs.topContent')}</TabsTrigger>
        </TabsList>

        <TabsContent value="overview" className="space-y-4">
          <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-7">
            <Card className="col-span-4">
              <CardHeader>
                <CardTitle>{t('admin.activityOverview')}</CardTitle>
              </CardHeader>
              <CardContent className="pl-2">
                <ResponsiveContainer width="100%" height={350}>
                  <AreaChart data={analytics.dailyEvents}>
                    <defs>
                      <linearGradient id="colorViews" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor={COLORS.views} stopOpacity={0.8} />
                        <stop offset="95%" stopColor={COLORS.views} stopOpacity={0} />
                      </linearGradient>
                      <linearGradient id="colorClicks" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor={COLORS.clicks} stopOpacity={0.8} />
                        <stop offset="95%" stopColor={COLORS.clicks} stopOpacity={0} />
                      </linearGradient>
                    </defs>
                    <XAxis
                      dataKey="date"
                      stroke="#888888"
                      fontSize={12}
                      tickLine={false}
                      axisLine={false}
                    />
                    <YAxis
                      stroke="#888888"
                      fontSize={12}
                      tickLine={false}
                      axisLine={false}
                      tickFormatter={(value) => `${value}`}
                    />
                    <CartesianGrid strokeDasharray="3 3" vertical={false} />
                    <Tooltip
                      contentStyle={{ backgroundColor: 'hsl(var(--card))', borderRadius: '8px' }}
                      labelStyle={{ color: 'hsl(var(--foreground))' }}
                    />
                    <Area
                      type="monotone"
                      dataKey="views"
                      stroke={COLORS.views}
                      fillOpacity={1}
                      fill="url(#colorViews)"
                      name={t('admin.views')}
                    />
                    <Area
                      type="monotone"
                      dataKey="clicks"
                      stroke={COLORS.clicks}
                      fillOpacity={1}
                      fill="url(#colorClicks)"
                      name={t('admin.clicks')}
                    />
                  </AreaChart>
                </ResponsiveContainer>
              </CardContent>
            </Card>

            <div className="col-span-3 space-y-4">
              {/* Devices */}
              <Card className="overflow-hidden">
                <CardHeader className="pb-2 md:pb-4">
                  <CardTitle className="text-base md:text-lg flex items-center gap-2">
                    <Monitor className="h-4 w-4" />
                    {t('admin.devices')}
                  </CardTitle>
                </CardHeader>
                <CardContent className="p-3 md:p-6 pt-0">
                  <div className="h-[160px] md:h-[200px]">
                    <ResponsiveContainer width="100%" height="100%">
                      <PieChart>
                        <Pie
                          data={filteredAnalytics.eventsByDevice}
                          cx="50%"
                          cy="50%"
                          innerRadius={35}
                          outerRadius={60}
                          paddingAngle={2}
                          dataKey="count"
                        >
                          {filteredAnalytics.eventsByDevice.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={entry.color} />
                          ))}
                        </Pie>
                        <Tooltip contentStyle={{ fontSize: '12px', backgroundColor: 'hsl(var(--card))', border: '1px solid hsl(var(--border))', borderRadius: '6px' }} />
                      </PieChart>
                    </ResponsiveContainer>
                  </div>
                  <div className="space-y-1.5 mt-2">
                    {filteredAnalytics.eventsByDevice.map((item) => (
                      <div key={item.name} className="flex items-center justify-between text-xs md:text-sm">
                        <div className="flex items-center gap-1.5">
                          {item.name === 'Desktop' && <Monitor className="h-3.5 w-3.5" />}
                          {item.name === 'Mobile' && <Smartphone className="h-3.5 w-3.5" />}
                          {item.name === 'Tablet' && <Tablet className="h-3.5 w-3.5" />}
                          <span>{item.name}</span>
                        </div>
                        <span className="font-medium">{formatNumber(item.count)}</span>
                      </div>
                    ))}
                  </div>
                </CardContent>
              </Card>

              {/* Traffic Sources */}
              <Card className="overflow-hidden">
                <CardHeader className="pb-2 md:pb-4">
                  <CardTitle className="text-base md:text-lg flex items-center gap-2">
                    <Globe className="h-4 w-4" />
                    {t('admin.sources')}
                  </CardTitle>
                </CardHeader>
                <CardContent className="p-3 md:p-6 pt-0">
                  <div className="h-[160px] md:h-[200px]">
                    <ResponsiveContainer width="100%" height="100%">
                      <PieChart>
                        <Pie
                          data={filteredAnalytics.eventsBySource}
                          cx="50%"
                          cy="50%"
                          innerRadius={35}
                          outerRadius={60}
                          paddingAngle={2}
                          dataKey="count"
                        >
                          {filteredAnalytics.eventsBySource.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={entry.color} />
                          ))}
                        </Pie>
                        <Tooltip contentStyle={{ fontSize: '12px', backgroundColor: 'hsl(var(--card))', border: '1px solid hsl(var(--border))', borderRadius: '6px' }} />
                      </PieChart>
                    </ResponsiveContainer>
                  </div>
                  <div className="space-y-1.5 mt-2">
                    {filteredAnalytics.eventsBySource.map((item) => (
                      <div key={item.name} className="flex items-center justify-between text-xs md:text-sm">
                        <div className="flex items-center gap-1.5">
                          <div className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: item.color }} />
                          <span>{item.name}</span>
                        </div>
                        <span className="font-medium">{formatNumber(item.count)}</span>
                      </div>
                    ))}
                  </div>
                </CardContent>
              </Card>
            </div>
          </div>
        </TabsContent>

        {/* Engagement Tab */}
        <TabsContent value="engagement" className="space-y-4 md:space-y-6">
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 md:gap-6">
            {/* By Hour of Day */}
            <Card className="overflow-hidden">
              <CardHeader className="pb-2 md:pb-4">
                <CardTitle className="text-base md:text-lg">{t('admin.byHours')}</CardTitle>
                <CardDescription className="text-xs md:text-sm">{t('admin.activityDuringDay')}</CardDescription>
              </CardHeader>
              <CardContent className="p-2 md:p-6 pt-0">
                <div className="h-[200px] md:h-[280px] -mx-2 md:mx-0">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={analytics.engagementByHour}>
                      <CartesianGrid strokeDasharray="3 3" className="stroke-border" />
                      <XAxis dataKey="hour" tick={{ fontSize: 8 }} tickFormatter={(h) => `${h}`} interval={2} />
                      <YAxis tick={{ fontSize: 9 }} width={30} />
                      <Tooltip
                        labelFormatter={(h) => `${h}:00`}
                        contentStyle={{
                          backgroundColor: 'hsl(var(--card))',
                          border: '1px solid hsl(var(--border))',
                          borderRadius: '8px',
                          fontSize: '12px'
                        }}
                      />
                      <Bar dataKey="events" name={t('admin.events')} fill={COLORS.sessions} radius={[2, 2, 0, 0]} />
                    </BarChart>
                  </ResponsiveContainer>
                </div>
              </CardContent>
            </Card>

            {/* By Day of Week */}
            <Card className="overflow-hidden">
              <CardHeader className="pb-2 md:pb-4">
                <CardTitle className="text-base md:text-lg">{t('admin.byDaysOfWeek')}</CardTitle>
                <CardDescription className="text-xs md:text-sm">{t('admin.activityDistribution')}</CardDescription>
              </CardHeader>
              <CardContent className="p-2 md:p-6 pt-0">
                <div className="h-[200px] md:h-[280px] -mx-2 md:mx-0">
                  <ResponsiveContainer width="100%" height="100%">
                    <BarChart data={displayedAnalytics?.engagementByDay || []} layout="vertical">
                      <CartesianGrid strokeDasharray="3 3" className="stroke-border" />
                      <XAxis type="number" tick={{ fontSize: 9 }} />
                      <YAxis dataKey="day" type="category" tick={{ fontSize: 10 }} width={25} />
                      <Tooltip
                        contentStyle={{
                          backgroundColor: 'hsl(var(--card))',
                          border: '1px solid hsl(var(--border))',
                          borderRadius: '8px',
                          fontSize: '12px'
                        }}
                      />
                      <Bar dataKey="events" name={t('admin.events')} fill={COLORS.visitors} radius={[0, 4, 4, 0]} />
                    </BarChart>
                  </ResponsiveContainer>
                </div>
              </CardContent>
            </Card>
          </div>
        </TabsContent>

        {/* Top Content Tab */}
        <TabsContent value="top" className="space-y-4 md:space-y-6">
          <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 md:gap-6">
            {/* Top Pages */}
            <Card className="overflow-hidden">
              <CardHeader className="pb-2 md:pb-4">
                <CardTitle className="text-base md:text-lg">{t('admin.topPages')}</CardTitle>
                <CardDescription className="text-xs md:text-sm">{t('admin.byViews')}</CardDescription>
              </CardHeader>
              <CardContent className="p-3 md:p-6 pt-0">
                <div className="space-y-2 md:space-y-3 max-h-[350px] overflow-y-auto">
                  {filteredAnalytics.topPages.length === 0 ? (
                    <p className="text-xs md:text-sm text-muted-foreground py-4 text-center">{t('admin.noData')}</p>
                  ) : (
                    filteredAnalytics.topPages.map((page, index) => (
                      <div key={page.page_id} className="flex items-center justify-between py-1.5 md:py-2 border-b border-border/50 last:border-0">
                        <div className="flex items-center gap-2 md:gap-3 min-w-0 flex-1">
                          <span className="text-muted-foreground font-mono text-xs md:text-sm w-5 md:w-6 shrink-0">#{index + 1}</span>
                          <div className="min-w-0 flex-1">
                            <p className="font-medium text-xs md:text-sm truncate">/{page.slug}</p>
                            <div className="flex gap-2 md:gap-4 text-[10px] md:text-xs text-muted-foreground">
                              <span>{formatNumber(page.views)} {t('admin.viewsShort')}</span>
                              <span>{formatNumber(page.clicks)} {t('admin.clicksShort')}</span>
                            </div>
                          </div>
                        </div>
                        <Badge variant={page.ctr >= 10 ? 'default' : 'secondary'} className="text-[10px] md:text-xs shrink-0 ml-2">
                          {page.ctr}%
                        </Badge>
                      </div>
                    ))
                  )}
                </div>
              </CardContent>
            </Card>

            {/* Top Blocks */}
            <Card className="overflow-hidden">
              <CardHeader className="pb-2 md:pb-4">
                <CardTitle className="text-base md:text-lg">{t('admin.topBlocks')}</CardTitle>
                <CardDescription className="text-xs md:text-sm">{t('admin.byClicks')}</CardDescription>
              </CardHeader>
              <CardContent className="p-3 md:p-6 pt-0">
                <div className="space-y-2 md:space-y-3 max-h-[350px] overflow-y-auto">
                  {filteredAnalytics.topBlocks.length === 0 ? (
                    <p className="text-xs md:text-sm text-muted-foreground py-4 text-center">{t('admin.noData')}</p>
                  ) : (
                    filteredAnalytics.topBlocks.map((block, index) => (
                      <div key={block.block_id} className="flex items-center justify-between py-1.5 md:py-2 border-b border-border/50 last:border-0">
                        <div className="flex items-center gap-2 md:gap-3">
                          <span className="text-muted-foreground font-mono text-xs md:text-sm w-5 md:w-6">#{index + 1}</span>
                          <Badge variant="outline" className="text-[10px] md:text-xs">{block.type}</Badge>
                        </div>
                        <span className="font-medium text-xs md:text-sm">{formatNumber(block.clicks)}</span>
                      </div>
                    ))
                  )}
                </div>
              </CardContent>
            </Card>
          </div>
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { useEffect, useState, useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { supabase } from '@/platform/supabase/client';
import {
  LineChart, Line, AreaChart, Area, BarChart, Bar, PieChart, Pie, Cell,
  XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, Legend
} from 'recharts';
import { format, subDays, startOfDay, eachDayOfInterval } from 'date-fns';
import { Loader2 } from 'lucide-react';

interface DailyData {
  date: string;
  users: number;
  pages: number;
  views: number;
  clicks: number;
  shares: number;
  blocks: number;
  friendships: number;
  collabs: number;
}

interface UserStatusData {
  name: string;
  value: number;
  color: string;
  [key: string]: string | number;
}

interface EventTypeData {
  name: string;
  count: number;
  color: string;
}

interface SocialStatsData {
  name: string;
  total: number;
  accepted: number;
}

const COLORS = {
  primary: 'hsl(var(--primary))',
  users: '#8b5cf6',
  pages: '#10b981',
  views: '#06b6d4',
  clicks: '#f97316',
  shares: '#ec4899',
  premium: '#eab308',
  trial: '#3b82f6',
  free: '#6b7280'
};

export function AdminCharts() {
  const { t } = useTranslation();
  const [loading, setLoading] = useState(true);
  const [dailyData, setDailyData] = useState<DailyData[]>([]);
  const [userStatusData, setUserStatusData] = useState<UserStatusData[]>([]);
  const [eventTypeData, setEventTypeData] = useState<EventTypeData[]>([]);
  const [cumulativeUsers, setCumulativeUsers] = useState<{ date: string; total: number }[]>([]);
  const [socialStats, setSocialStats] = useState<SocialStatsData[]>([]);
  const [blockTypeStats, setBlockTypeStats] = useState<{ name: string; count: number; color: string }[]>([]);

  const loadChartData = useCallback(async () => {
    setLoading(true);
    await Promise.all([
      loadDailyGrowth(),
      loadUserStatus(),
      loadEventTypes(),
      loadCumulativeUsers(),
      loadSocialStats(),
      loadBlockTypeStats()
    ]);
    setLoading(false);
  }, []);

  const loadDailyGrowth = async () => {
    try {
      const days = 14;
      const startDate = subDays(new Date(), days);

      // Get all data in parallel
      const [
        { data: usersData },
        { data: pagesData },
        { data: analyticsData },
        { data: blocksData },
        { data: friendshipsData },
        { data: collabsData }
      ] = await Promise.all([
        supabase.from('user_profiles').select('created_at').gte('created_at', startDate.toISOString()),
        supabase.from('pages').select('created_at').gte('created_at', startDate.toISOString()),
        supabase.from('analytics').select('event_type, created_at').gte('created_at', startDate.toISOString()),
        supabase.from('blocks').select('created_at').gte('created_at', startDate.toISOString()),
        supabase.from('friendships').select('created_at').gte('created_at', startDate.toISOString()),
        supabase.from('collaborations').select('created_at').gte('created_at', startDate.toISOString())
      ]);

      // Generate daily breakdown
      const dateRange = eachDayOfInterval({ start: startDate, end: new Date() });

      const dailyStats = dateRange.map(day => {
        const dayStart = startOfDay(day);
        const dayEnd = new Date(dayStart);
        dayEnd.setDate(dayEnd.getDate() + 1);

        const dateStr = format(day, 'dd.MM');

        const filterByDay = (items: any[] | null) =>
          items?.filter(item => {
            if (!item.created_at) return false;
            const d = new Date(item.created_at);
            return d >= dayStart && d < dayEnd;
          }).length || 0;

        const dayEvents = analyticsData?.filter(e => {
          if (!e.created_at) return false;
          const d = new Date(e.created_at);
          return d >= dayStart && d < dayEnd;
        }) || [];

        return {
          date: dateStr,
          users: filterByDay(usersData),
          pages: filterByDay(pagesData),
          views: dayEvents.filter(e => e.event_type === 'view').length,
          clicks: dayEvents.filter(e => e.event_type === 'click').length,
          shares: dayEvents.filter(e => e.event_type === 'share').length,
          blocks: filterByDay(blocksData),
          friendships: filterByDay(friendshipsData),
          collabs: filterByDay(collabsData)
        };
      });

      setDailyData(dailyStats);
    } catch (error) {
      console.error('Error loading daily growth:', error);
    }
  };

  const loadUserStatus = async () => {
    try {
      const now = new Date().toISOString();

      const { count: premiumCount } = await supabase
        .from('user_profiles')
        .select('*', { count: 'exact', head: true })
        .eq('is_premium', true);

      const { count: trialCount } = await supabase
        .from('user_profiles')
        .select('*', { count: 'exact', head: true })
        .eq('is_premium', false)
        .gt('trial_ends_at', now);

      const { count: totalCount } = await supabase
        .from('user_profiles')
        .select('*', { count: 'exact', head: true });

      const freeCount = (totalCount || 0) - (premiumCount || 0) - (trialCount || 0);

      setUserStatusData([
        { name: 'Premium', value: premiumCount || 0, color: COLORS.premium },
        { name: 'Trial', value: trialCount || 0, color: COLORS.trial },
        { name: 'Free', value: Math.max(0, freeCount), color: COLORS.free }
      ]);
    } catch (error) {
      console.error('Error loading user status:', error);
    }
  };

  const loadEventTypes = async () => {
    try {
      const { data } = await supabase
        .from('analytics')
        .select('event_type');

      const counts = {
        view: 0,
        click: 0,
        share: 0
      };

      data?.forEach(e => {
        if (e.event_type in counts) {
          counts[e.event_type as keyof typeof counts]++;
        }
      });

      setEventTypeData([
        { name: t('adminCharts.events.views', 'Просмотры'), count: counts.view, color: COLORS.views },
        { name: t('adminCharts.events.clicks', 'Клики'), count: counts.click, color: COLORS.clicks },
        { name: t('adminCharts.events.shares', 'Шейры'), count: counts.share, color: COLORS.shares }
      ]);
    } catch (error) {
      console.error('Error loading event types:', error);
    }
  };

  const loadCumulativeUsers = async () => {
    try {
      const { data } = await supabase
        .from('user_profiles')
        .select('created_at')
        .order('created_at', { ascending: true });

      if (!data || data.length === 0) {
        setCumulativeUsers([]);
        return;
      }

      // Group by date and calculate cumulative
      const dateMap = new Map<string, number>();
      let cumulative = 0;

      data.forEach(u => {
        if (!u.created_at) return;
        const dateStr = format(new Date(u.created_at), 'dd.MM');
        cumulative++;
        dateMap.set(dateStr, cumulative);
      });

      // Get last 30 days or all data if less
      const entries = Array.from(dateMap.entries());
      const last30 = entries.slice(-30);

      setCumulativeUsers(last30.map(([date, total]) => ({ date, total })));
    } catch (error) {
      console.error('Error loading cumulative users:', error);
    }
  };

  const loadSocialStats = async () => {
    try {
      const [
        { count: totalFriends },
        { count: acceptedFriends },
        { count: totalCollabs },
        { count: acceptedCollabs },
        { count: totalTeams }
      ] = await Promise.all([
        supabase.from('friendships').select('*', { count: 'exact', head: true }),
        supabase.from('friendships').select('*', { count: 'exact', head: true }).eq('status', 'accepted'),
        supabase.from('collaborations').select('*', { count: 'exact', head: true }),
        supabase.from('collaborations').select('*', { count: 'exact', head: true }).eq('status', 'accepted'),
        supabase.from('teams').select('*', { count: 'exact', head: true })
      ]);

      setSocialStats([
        { name: t('adminCharts.social.friendships', 'Дружбы'), total: totalFriends || 0, accepted: acceptedFriends || 0 },
        { name: t('adminCharts.social.collaborations', 'Коллаборации'), total: totalCollabs || 0, accepted: acceptedCollabs || 0 },
        { name: t('adminCharts.social.teams', 'Команды'), total: totalTeams || 0, accepted: totalTeams || 0 }
      ]);
    } catch (error) {
      console.error('Error loading social stats:', error);
    }
  };

  const loadBlockTypeStats = async () => {
    try {
      const { data } = await supabase
        .from('blocks')
        .select('type');

      const typeCounts: Record<string, number> = {};
      data?.forEach(block => {
        typeCounts[block.type] = (typeCounts[block.type] || 0) + 1;
      });

      const colorPalette = [
        '#8b5cf6', '#10b981', '#06b6d4', '#f97316', '#ec4899',
        '#eab308', '#3b82f6', '#ef4444', '#14b8a6', '#a855f7'
      ];

      const sortedTypes = Object.entries(typeCounts)
        .sort((a, b) => b[1] - a[1])
        .slice(0, 10)
        .map(([name, count], index) => ({
          name: name.charAt(0).toUpperCase() + name.slice(1),
          count,
          color: colorPalette[index % colorPalette.length]
        }));

      setBlockTypeStats(sortedTypes);
    } catch (error) {
      console.error('Error loading block type stats:', error);
    }
  };

  useEffect(() => {
    void loadChartData();
  }, [loadChartData]);

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* User Growth Chart */}
      <Card>
        <CardHeader>
          <CardTitle>{t('adminCharts.userGrowth', 'Рост пользователей')}</CardTitle>
        </CardHeader>
        <CardContent>
          <div className="h-[300px]">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={cumulativeUsers}>
                <defs>
                  <linearGradient id="userGradient" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor={COLORS.users} stopOpacity={0.3} />
                    <stop offset="95%" stopColor={COLORS.users} stopOpacity={0} />
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" className="stroke-border" />
                <XAxis
                  dataKey="date"
                  tick={{ fontSize: 12 }}
                  className="text-muted-foreground"
                />
                <YAxis
                  tick={{ fontSize: 12 }}
                  className="text-muted-foreground"
                />
                <Tooltip
                  contentStyle={{
                    backgroundColor: 'hsl(var(--card))',
                    border: '1px solid hsl(var(--border))',
                    borderRadius: '8px'
                  }}
                  labelStyle={{ color: 'hsl(var(--foreground))' }}
                />
                <Area
                  type="monotone"
                  dataKey="total"
                  name={t('adminCharts.totalUsers', 'Всего пользователей')}
                  stroke={COLORS.users}
                  fill="url(#userGradient)"
                  strokeWidth={2}
                />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </CardContent>
      </Card>

      {/* Daily Activity Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* New Registrations */}
        <Card>
          <CardHeader>
            <CardTitle>{t('adminCharts.newRegistrations', 'Новые регистрации (14 дней)')}</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="h-[250px]">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={dailyData}>
                  <CartesianGrid strokeDasharray="3 3" className="stroke-border" />
                  <XAxis
                    dataKey="date"
                    tick={{ fontSize: 11 }}
                    className="text-muted-foreground"
                  />
                  <YAxis
                    tick={{ fontSize: 11 }}
                    className="text-muted-foreground"
                    allowDecimals={false}
                  />
                  <Tooltip
                    contentStyle={{
                      backgroundColor: 'hsl(var(--card))',
                      border: '1px solid hsl(var(--border))',
                      borderRadius: '8px'
                    }}
                  />
                  <Bar
                    dataKey="users"
                    name={t('adminCharts.users', 'Пользователи')}
                    fill={COLORS.users}
                    radius={[4, 4, 0, 0]}
                  />
                  <Bar
                    dataKey="pages"
                    name={t('adminCharts.pages', 'Страницы')}
                    fill={COLORS.pages}
                    radius={[4, 4, 0, 0]}
                  />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </CardContent>
        </Card>

        {/* Events Chart */}
        <Card>
          <CardHeader>
            <CardTitle>{t('adminCharts.eventsTitle', 'События (14 дней)')}</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="h-[250px]">
              <ResponsiveContainer width="100%" height="100%">
                <LineChart data={dailyData}>
                  <CartesianGrid strokeDasharray="3 3" className="stroke-border" />
                  <XAxis
                    dataKey="date"
                    tick={{ fontSize: 11 }}
                    className="text-muted-foreground"
                  />
                  <YAxis
                    tick={{ fontSize: 11 }}
                    className="text-muted-foreground"
                  />
                  <Tooltip
                    contentStyle={{
                      backgroundColor: 'hsl(var(--card))',
                      border: '1px solid hsl(var(--border))',
                      borderRadius: '8px'
                    }}
                  />
                  <Legend />
                  <Line
                    type="monotone"
                    dataKey="views"
                    name={t('adminCharts.events.views', 'Просмотры')}
                    stroke={COLORS.views}
                    strokeWidth={2}
                    dot={false}
                  />
                  <Line
                    type="monotone"
                    dataKey="clicks"
                    name={t('adminCharts.events.clicks', 'Клики')}
                    stroke={COLORS.clicks}
                    strokeWidth={2}
                    dot={false}
                  />
                  <Line
                    type="monotone"
                    dataKey="shares"
                    name={t('adminCharts.events.shares', 'Шейры')}
                    stroke={COLORS.shares}
                    strokeWidth={2}
                    dot={false}
                  />
                </LineChart>
              </ResponsiveContainer>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Pie Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* User Status Distribution */}
        <Card>
          <CardHeader>
            <CardTitle>{t('adminCharts.userDistribution', 'Распределение пользователей')}</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="h-[250px]">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={userStatusData}
                    cx="50%"
                    cy="50%"
                    innerRadius={60}
                    outerRadius={90}
                    paddingAngle={2}
                    dataKey="value"
                    label={({ name, percent }) => `${name} ${((percent || 0) * 100).toFixed(0)}%`}
                    labelLine={false}
                  >
                    {userStatusData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry.color} />
                    ))}
                  </Pie>
                  <Tooltip
                    contentStyle={{
                      backgroundColor: 'hsl(var(--card))',
                      border: '1px solid hsl(var(--border))',
                      borderRadius: '8px'
                    }}
                  />
                </PieChart>
              </ResponsiveContainer>
            </div>
            <div className="flex justify-center gap-6 mt-4">
              {userStatusData.map((item) => (
                <div key={item.name} className="flex items-center gap-2">
                  <div
                    className="w-3 h-3 rounded-full"
                    style={{ backgroundColor: item.color }}
                  />
                  <span className="text-sm text-muted-foreground">
                    {item.name}: {item.value}
                  </span>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>

        {/* Event Types Distribution */}
        <Card>
          <CardHeader>
            <CardTitle>{t('adminCharts.eventTypes', 'Типы событий')}</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="h-[250px]">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={eventTypeData} layout="vertical">
                  <CartesianGrid strokeDasharray="3 3" className="stroke-border" />
                  <XAxis type="number" tick={{ fontSize: 11 }} />
                  <YAxis
                    dataKey="name"
                    type="category"
                    tick={{ fontSize: 12 }}
                    width={80}
                  />
                  <Tooltip
                    contentStyle={{
                      backgroundColor: 'hsl(var(--card))',
                      border: '1px solid hsl(var(--border))',
                      borderRadius: '8px'
                    }}
                  />
                  <Bar
                    dataKey="count"
                    name={t('adminCharts.count', 'Количество')}
                    radius={[0, 4, 4, 0]}
                  >
                    {eventTypeData.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry.color} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </div>
          </CardContent>
        </Card>
      </div>

      {/* Social & Community Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Social Activity */}
        <Card>
          <CardHeader>
            <CardTitle>{t('adminCharts.socialActivity', 'Социальная активность')}</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="h-[250px]">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={socialStats}>
                  <CartesianGrid strokeDasharray="3 3" className="stroke-border" />
                  <XAxis
                    dataKey="name"
                    tick={{ fontSize: 12 }}
                    className="text-muted-foreground"
                  />
                  <YAxis tick={{ fontSize: 11 }} className="text-muted-foreground" />
                  <Tooltip
                    contentStyle={{
                      backgroundColor: 'hsl(var(--card))',
                      border: '1px solid hsl(var(--border))',
                      borderRadius: '8px'
                    }}
                  />
                  <Legend />
                  <Bar dataKey="total" name={t('adminCharts.total', 'Всего')} fill={COLORS.users} radius={[4, 4, 0, 0]} />
                  <Bar dataKey="accepted" name={t('adminCharts.accepted', 'Принято')} fill={COLORS.pages} radius={[4, 4, 0, 0]} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </CardContent>
        </Card>

        {/* Block Types Distribution */}
        <Card>
          <CardHeader>
            <CardTitle>{t('adminCharts.popularBlockTypes', 'Популярные типы блоков')}</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="h-[250px]">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={blockTypeStats} layout="vertical">
                  <CartesianGrid strokeDasharray="3 3" className="stroke-border" />
                  <XAxis type="number" tick={{ fontSize: 11 }} />
                  <YAxis
                    dataKey="name"
                    type="category"
                    tick={{ fontSize: 11 }}
                    width={80}
                  />
                  <Tooltip
                    contentStyle={{
                      backgroundColor: 'hsl(var(--card))',
