});

import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Button } from '@/components/ui/button';
import { MediaUpload } from '@/components/form-fields/MediaUpload';
import { withBlockEditor, type BaseBlockEditorProps } from './BlockEditorWrapper';
import { validateCarouselBlock } from '@/lib/blocks/block-validators';
import { useTranslation } from 'react-i18next';
import { Trash2 } from 'lucide-react';
import { MultilingualInput } from '@/components/form-fields/MultilingualInput';
import { migrateToMultilingual } from '@/lib/i18n-helpers';

import { CarouselBlock } from '@/types/page';

interface CarouselImage {
  url: string;
  alt: any; // Using any for I18nText temporarily to avoid complexity, or better: migrateToMultilingual result type
  link?: string;
}

function CarouselBlockEditorComponent({ formData, onChange }: BaseBlockEditorProps) {
  const { t } = useTranslation();
  const data = formData as Partial<CarouselBlock>;
  const images = data.images || [];
  const handleChange = (updates: Partial<CarouselBlock>) => onChange(updates);

  const addImage = () => handleChange({ ...data, images: [...images, { url: '', alt: { ru: '', en: '', kk: '' }, link: '' }] });
  const removeImage = (index: number) => handleChange({ ...data, images: images.filter((_, i) => i !== index) });
  const updateImage = (index: number, field: keyof CarouselImage, value: any) => {
    const updated = [...images];
    updated[index] = { ...updated[index], [field]: value };
    handleChange({ ...data, images: updated });
  };

  return (
    <div className="space-y-4">
      <MultilingualInput
        label={`${t('fields.title', 'Title')} (${t('fields.optional', 'optional')})`}
        value={migrateToMultilingual(data.title)}
        onChange={(value) => handleChange({ ...data, title: value })}
        placeholder="Gallery"
      />

      <div className="space-y-4">
        <div className="flex items-center justify-between">
          <Label>{t('fields.images', 'Images')}</Label>
          <Button type="button" variant="outline" size="sm" onClick={addImage}>{t('actions.addImage', 'Add Image')}</Button>
        </div>

        {images.map((image, index) => (
          <div key={index} className="border border-border rounded-lg p-3 space-y-3">
            <div className="flex items-center justify-between">
              <span className="text-sm font-medium">{t('fields.image', 'Image')} {index + 1}</span>
              <Button type="button" variant="ghost" size="sm" onClick={() => removeImage(index)}><Trash2 className="h-4 w-4" /></Button>
            </div>
            <MediaUpload value={image.url} onChange={(url) => updateImage(index, 'url', url)} accept="image/*" />
            <MultilingualInput
              label={t('fields.altText', 'Alt Text')}
              value={migrateToMultilingual(image.alt)}
              onChange={(value) => updateImage(index, 'alt', value)}
              placeholder={t('fields.imageDescription', 'Image description')}
            />
            <div>
              <Label className="text-xs">{t('fields.link', 'Link')} ({t('fields.optional', 'optional')})</Label>
              <Input type="url" value={image.link || ''} onChange={(e) => updateImage(index, 'link', e.target.value)} placeholder="https://example.com" />
            </div>
          </div>
        ))}
      </div>

      <div className="flex items-center gap-2">
        <input type="checkbox" id="autoPlay" checked={data.autoPlay || false} onChange={(e) => handleChange({ ...data, autoPlay: e.target.checked })} className="h-4 w-4" />
        <Label htmlFor="autoPlay" className="cursor-pointer">{t('fields.autoPlay', 'Auto-play')}</Label>
      </div>

      {data.autoPlay && (
        <div>
          <Label>{t('fields.interval', 'Interval')} (ms)</Label>
          <Input type="number" value={data.interval || 3000} onChange={(e) => handleChange({ ...data, interval: parseInt(e.target.value) })} min="1000" step="500" />
        </div>
      )}
    </div>
  );
}

export const CarouselBlockEditor = withBlockEditor(CarouselBlockEditorComponent, {
  hint: 'Create an image gallery carousel with auto-play option',
  validate: validateCarouselBlock,
});

import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Button } from '@/components/ui/button';
import { Switch } from '@/components/ui/switch';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Card, CardContent } from '@/components/ui/card';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Plus, Trash2, GripVertical, ImageIcon, FolderOpen } from 'lucide-react';
import { MultilingualInput } from '@/components/form-fields/MultilingualInput';
import { CurrencySelect } from '@/components/form-fields/CurrencySelect';
import { MediaUpload } from '@/components/form-fields/MediaUpload';
import type { CatalogBlock, CatalogItem, CatalogCategory, Currency } from '@/types/page';
import { createMultilingualString, isMultilingualString, getI18nText } from '@/lib/i18n-helpers';
import { cn } from '@/lib/utils/utils';

import { withBlockEditor, type BaseBlockEditorProps } from './BlockEditorWrapper';
import { validateCatalogBlock } from '@/lib/blocks/block-validators';

function CatalogBlockEditorComponent({ formData, onChange }: BaseBlockEditorProps) {
  const { t, i18n } = useTranslation();
  const [expandedItem, setExpandedItem] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'items' | 'categories'>('items');

  const items = formData.items || [];
  const categories = formData.categories || [];
  const currentLang = i18n.language as 'ru' | 'en' | 'kk';

  // Category functions
  const addCategory = () => {
    const newCategory: CatalogCategory = {
      id: `cat-${Date.now()}`,
      name: createMultilingualString(''),
    };
    onChange({ categories: [...categories, newCategory] });
  };

  const updateCategory = (categoryId: string, updates: Partial<CatalogCategory>) => {
    onChange({
      categories: categories.map(cat =>
        cat.id === categoryId ? { ...cat, ...updates } : cat
      ),
    });
  };

  const removeCategory = (categoryId: string) => {
    // Remove category and unassign items from it
    onChange({
      categories: categories.filter(cat => cat.id !== categoryId),
      items: items.map(item =>
        item.categoryId === categoryId ? { ...item, categoryId: undefined } : item
      ),
    });
  };

  const getCategoryName = (category: CatalogCategory): string => {
    return getI18nText(category.name, currentLang) || t('blocks.catalog.newCategory', 'Новая категория');
  };

  // Item functions
  const addItem = () => {
    const newItem: CatalogItem = {
      id: `item-${Date.now()}`,
      name: createMultilingualString(''),
      description: createMultilingualString(''),
      price: 0,
      currency: formData.currency || 'KZT',
      image: '',
      categoryId: undefined,
    };
    onChange({ items: [...items, newItem] });
    setExpandedItem(newItem.id);
  };

  const updateItem = (itemId: string, updates: Partial<CatalogItem>) => {
    onChange({
      items: items.map(item =>
        item.id === itemId ? { ...item, ...updates } : item
      ),
    });
  };

  const removeItem = (itemId: string) => {
    onChange({ items: items.filter(item => item.id !== itemId) });
    if (expandedItem === itemId) {
      setExpandedItem(null);
    }
  };

  const getItemName = (item: CatalogItem): string => {
    return getI18nText(item.name, currentLang) || t('blocks.catalog.noName', 'Без названия');
  };

  const getItemCategoryName = (item: CatalogItem): string | null => {
    if (!item.categoryId) return null;
    const category = categories.find(c => c.id === item.categoryId);
    if (!category) return null;
    return getCategoryName(category);
  };

  return (
    <div className="space-y-4">
      {/* Title */}
      <MultilingualInput
        label={t('blocks.catalog.title', 'Заголовок каталога')}
        value={typeof formData.title === 'string' ? createMultilingualString(formData.title) : (formData.title || createMultilingualString(''))}
        onChange={(value) => onChange({ title: value })}
        placeholder={t('blocks.catalog.titlePlaceholder', 'Наше меню')}
      />

      {/* Layout */}
      <div className="space-y-2">
        <Label>{t('blocks.catalog.layout', 'Отображение')}</Label>
        <Select
          value={formData.layout || 'list'}
          onValueChange={(value: 'list' | 'grid') => onChange({ layout: value })}
        >
          <SelectTrigger>
            <SelectValue />
          </SelectTrigger>
          <SelectContent>
            <SelectItem value="list">{t('blocks.catalog.layoutList', 'Список')}</SelectItem>
            <SelectItem value="grid">{t('blocks.catalog.layoutGrid', 'Сетка')}</SelectItem>
          </SelectContent>
        </Select>
      </div>

      {/* Show Prices */}
      <div className="flex items-center justify-between">
        <Label>{t('blocks.catalog.showPrices', 'Показывать цены')}</Label>
        <Switch
          checked={formData.showPrices !== false}
          onCheckedChange={(checked) => onChange({ showPrices: checked })}
        />
      </div>

      {/* Default Currency */}
      {formData.showPrices !== false && (
        <div className="space-y-2">
          <Label>{t('blocks.catalog.defaultCurrency', 'Валюта по умолчанию')}</Label>
          <CurrencySelect
            value={formData.currency || 'KZT'}
            onValueChange={(value: string) => onChange({ currency: value as Currency })}
          />
        </div>
      )}

      {/* Tabs for Items and Categories */}
      <Tabs value={activeTab} onValueChange={(v: string) => setActiveTab(v as 'items' | 'categories')}>
        <TabsList className="grid w-full grid-cols-2">
          <TabsTrigger value="items">
            {t('blocks.catalog.items', 'Позиции')} ({items.length})
          </TabsTrigger>
          <TabsTrigger value="categories">
            {t('blocks.catalog.categories', 'Категории')} ({categories.length})
          </TabsTrigger>
        </TabsList>

        {/* Categories Tab */}
        <TabsContent value="categories" className="space-y-3">
          <div className="flex items-center justify-between">
            <p className="text-sm text-muted-foreground">
              {t('blocks.catalog.categoriesHint', 'Создайте категории для группировки позиций')}
            </p>
            <Button type="button" variant="outline" size="sm" onClick={addCategory}>
              <Plus className="h-4 w-4 mr-1" />
              {t('blocks.catalog.addCategory', 'Добавить')}
            </Button>
          </div>

          <div className="space-y-2 max-h-[300px] overflow-y-auto">
            {categories.map((category, index) => (
              <Card key={category.id}>
                <CardContent className="p-3">
                  <div className="flex items-center gap-2">
                    <FolderOpen className="h-4 w-4 text-muted-foreground flex-shrink-0" />
                    <div className="flex-1">
                      <MultilingualInput
                        label=""
                        value={typeof category.name === 'string' ? createMultilingualString(category.name) : category.name}
                        onChange={(value) => updateCategory(category.id, { name: value })}
                        placeholder={t('blocks.catalog.categoryNamePlaceholder', 'Название категории')}
                      />
                    </div>
                    <Button
                      type="button"
                      variant="ghost"
                      size="icon"
                      className="h-8 w-8 flex-shrink-0"
                      onClick={() => removeCategory(category.id)}
                    >
                      <Trash2 className="h-4 w-4 text-destructive" />
                    </Button>
                  </div>
                  <p className="text-xs text-muted-foreground mt-1 ml-6">
                    {items.filter(i => i.categoryId === category.id).length} {t('blocks.catalog.itemsCount', 'позиций')}
                  </p>
                </CardContent>
              </Card>
            ))}

            {categories.length === 0 && (
              <div className="text-center py-8 text-muted-foreground border-2 border-dashed rounded-lg">
                <FolderOpen className="h-8 w-8 mx-auto mb-2 opacity-50" />
                <p className="text-sm">{t('blocks.catalog.noCategoriesHint', 'Категории помогут организовать ваш каталог')}</p>
              </div>
            )}
          </div>
        </TabsContent>

        {/* Items Tab */}
        <TabsContent value="items" className="space-y-3">
          <div className="flex items-center justify-between">
            <p className="text-sm text-muted-foreground">
              {t('blocks.catalog.itemsHint', 'Добавьте позиции в каталог')}
            </p>
            <Button type="button" variant="outline" size="sm" onClick={addItem}>
              <Plus className="h-4 w-4 mr-1" />
              {t('blocks.catalog.addItem', 'Добавить')}
            </Button>
          </div>

          <div className="space-y-2 max-h-[400px] overflow-y-auto">
            {items.map((item, index) => {
              const categoryName = getItemCategoryName(item);

              return (
                <Card
                  key={item.id}
                  className={cn(
                    'transition-all',
                    expandedItem === item.id && 'ring-2 ring-primary'
                  )}
                >
                  <CardContent className="p-3">
                    {/* Collapsed view */}
                    <div
                      className="flex items-center gap-2 cursor-pointer"
                      onClick={() => setExpandedItem(expandedItem === item.id ? null : item.id)}
                    >
                      <GripVertical className="h-4 w-4 text-muted-foreground flex-shrink-0" />
                      {item.image ? (
                        <img
                          src={item.image}
                          alt=""
                          className="h-10 w-10 rounded object-cover flex-shrink-0"
                        />
                      ) : (
                        <div className="h-10 w-10 rounded bg-muted flex items-center justify-center flex-shrink-0">
                          <ImageIcon className="h-4 w-4 text-muted-foreground" />
                        </div>
                      )}
                      <div className="flex-1 min-w-0">
                        <p className="font-medium truncate text-sm">
                          {getItemName(item) || `${t('blocks.catalog.position', 'Позиция')} ${index + 1}`}
                        </p>
                        <div className="flex items-center gap-2 text-xs text-muted-foreground">
                          {categoryName && (
                            <span className="bg-secondary px-1.5 py-0.5 rounded">
                              {categoryName}
                            </span>
                          )}
                          {item.price !== undefined && item.price > 0 && (
                            <span>
                              {item.price.toLocaleString()} {item.currency || formData.currency || 'KZT'}
                            </span>
                          )}
                        </div>
                      </div>
                      <Button
                        type="button"
                        variant="ghost"
                        size="icon"
                        className="h-8 w-8 flex-shrink-0"
                        onClick={(e) => {
                          e.stopPropagation();
                          removeItem(item.id);
                        }}
                      >
                        <Trash2 className="h-4 w-4 text-destructive" />
                      </Button>
                    </div>

                    {/* Expanded view */}
                    {expandedItem === item.id && (
                      <div className="mt-4 space-y-3 border-t pt-4">
                        {/* Category */}
                        {categories.length > 0 && (
                          <div className="space-y-2">
                            <Label>{t('blocks.catalog.itemCategory', 'Категория')}</Label>
                            <Select
                              value={item.categoryId || 'none'}
                              onValueChange={(value: string) => updateItem(item.id, {
                                categoryId: value === 'none' ? undefined : value
                              })}
                            >
                              <SelectTrigger>
                                <SelectValue placeholder={t('blocks.catalog.selectCategory', 'Выберите категорию')} />
                              </SelectTrigger>
                              <SelectContent>
                                <SelectItem value="none">
                                  {t('blocks.catalog.noCategory', 'Без категории')}
                                </SelectItem>
                                {categories.map(cat => (
                                  <SelectItem key={cat.id} value={cat.id}>
                                    {getCategoryName(cat)}
                                  </SelectItem>
                                ))}
                              </SelectContent>
                            </Select>
                          </div>
                        )}

                        {/* Image */}
                        <div className="space-y-2">
                          <Label>{t('blocks.catalog.itemImage', 'Фото')}</Label>
                          <MediaUpload
                            value={item.image || ''}
                            onChange={(url) => updateItem(item.id, { image: url })}
                            accept="image/*"
                          />
                        </div>

                        {/* Name */}
                        <MultilingualInput
                          label={t('blocks.catalog.itemName', 'Название')}
                          value={typeof item.name === 'string' ? createMultilingualString(item.name) : item.name}
                          onChange={(value) => updateItem(item.id, { name: value })}
                          placeholder={t('blocks.catalog.itemNamePlaceholder', 'Название позиции')}
                        />

                        {/* Description */}
                        <MultilingualInput
                          label={t('blocks.catalog.itemDescription', 'Описание')}
                          value={typeof item.description === 'string' ? createMultilingualString(item.description) : (item.description || createMultilingualString(''))}
                          onChange={(value) => updateItem(item.id, { description: value })}
                          placeholder={t('blocks.catalog.itemDescriptionPlaceholder', 'Описание позиции')}
                          type="textarea"
                        />

                        {/* Price */}
                        {formData.showPrices !== false && (
                          <div className="grid grid-cols-2 gap-2">
                            <div className="space-y-2">
                              <Label>{t('blocks.catalog.itemPrice', 'Цена')}</Label>
                              <Input
                                type="number"
                                min="0"
                                value={item.price || ''}
                                onChange={(e) => updateItem(item.id, {
                                  price: e.target.value ? parseFloat(e.target.value) : undefined
                                })}
                                placeholder="0"
                              />
                            </div>
                            <div className="space-y-2">
                              <Label>{t('blocks.catalog.itemCurrency', 'Валюта')}</Label>
                              <CurrencySelect
                                value={item.currency || formData.currency || 'KZT'}
                                onValueChange={(value: string) => updateItem(item.id, { currency: value as Currency })}
                              />
                            </div>
                          </div>
                        )}
                      </div>
                    )}
                  </CardContent>
                </Card>
              );
            })}

            {items.length === 0 && (
              <div className="text-center py-8 text-muted-foreground border-2 border-dashed rounded-lg">
                <p className="text-sm">{t('blocks.catalog.emptyHint', 'Нажмите "Добавить" чтобы создать первую позицию')}</p>
              </div>
            )}
          </div>
        </TabsContent>
      </Tabs>
    </div>
  );
}

export const CatalogBlockEditor = withBlockEditor(CatalogBlockEditorComponent, {
