import React, { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Label } from '@/components/ui/label';
import { Button } from '@/components/ui/button';
import { Card, CardContent } from '@/components/ui/card';
import { Plus, Trash2, GripVertical, ChevronDown, ChevronUp } from 'lucide-react';
import { MultilingualInput } from '@/components/form-fields/MultilingualInput';
import type { FAQBlock, FAQItem } from '@/types/page';
import { createMultilingualString, getI18nText } from '@/lib/i18n-helpers';
import { cn } from '@/lib/utils/utils';

interface FAQBlockEditorProps {
  formData: Partial<FAQBlock>;
  onChange: (data: Partial<FAQBlock>) => void;
}

export function FAQBlockEditor({ formData, onChange }: FAQBlockEditorProps) {
  const { t, i18n } = useTranslation();
  const [expandedItem, setExpandedItem] = useState<string | null>(null);
  const currentLang = i18n.language as 'ru' | 'en' | 'kk';

  const items = formData.items || [];

  const addItem = () => {
    const newItem: FAQItem = {
      id: `faq-${Date.now()}`,
      question: createMultilingualString(''),
      answer: createMultilingualString(''),
    };
    onChange({ items: [...items, newItem] });
    setExpandedItem(newItem.id);
  };

  const updateItem = (itemId: string, updates: Partial<FAQItem>) => {
    onChange({
      items: items.map(item => 
        item.id === itemId ? { ...item, ...updates } : item
      ),
    });
  };

  const removeItem = (itemId: string) => {
    onChange({ items: items.filter(item => item.id !== itemId) });
    if (expandedItem === itemId) {
      setExpandedItem(null);
    }
  };

  const getQuestionPreview = (item: FAQItem): string => {
    return getI18nText(item.question, currentLang) || t('blocks.faq.newQuestion', 'Новый вопрос');
  };

  return (
    <div className="space-y-4">
      {/* Title */}
      <MultilingualInput
        label={t('blocks.faq.title', 'Заголовок')}
        value={typeof formData.title === 'string' ? createMultilingualString(formData.title) : (formData.title || createMultilingualString(''))}
        onChange={(value) => onChange({ title: value })}
        placeholder={t('blocks.faq.titlePlaceholder', 'Частые вопросы')}
      />

      {/* Items */}
      <div className="space-y-2">
        <div className="flex items-center justify-between">
          <Label>{t('blocks.faq.items', 'Вопросы и ответы')}</Label>
          <Button type="button" variant="outline" size="sm" onClick={addItem}>
            <Plus className="h-4 w-4 mr-1" />
            {t('blocks.faq.addItem', 'Добавить')}
          </Button>
        </div>

        <div className="space-y-2 max-h-[400px] overflow-y-auto">
          {items.map((item, index) => (
            <Card 
              key={item.id} 
              className={cn(
                'transition-all',
                expandedItem === item.id && 'ring-2 ring-primary'
              )}
            >
              <CardContent className="p-3">
                {/* Collapsed view */}
                <div 
                  className="flex items-center gap-2 cursor-pointer"
                  onClick={() => setExpandedItem(expandedItem === item.id ? null : item.id)}
                >
                  <GripVertical className="h-4 w-4 text-muted-foreground flex-shrink-0" />
                  <div className="flex-1 min-w-0">
                    <p className="font-medium truncate text-sm">
                      {getQuestionPreview(item)}
                    </p>
                  </div>
                  {expandedItem === item.id ? (
                    <ChevronUp className="h-4 w-4 text-muted-foreground" />
                  ) : (
                    <ChevronDown className="h-4 w-4 text-muted-foreground" />
                  )}
                  <Button
                    type="button"
                    variant="ghost"
                    size="icon"
                    className="h-8 w-8 flex-shrink-0"
                    onClick={(e) => {
                      e.stopPropagation();
                      removeItem(item.id);
                    }}
                  >
                    <Trash2 className="h-4 w-4 text-destructive" />
                  </Button>
                </div>

                {/* Expanded view */}
                {expandedItem === item.id && (
                  <div className="mt-4 space-y-3 border-t pt-4">
                    <MultilingualInput
                      label={t('blocks.faq.question', 'Вопрос')}
                      value={typeof item.question === 'string' ? createMultilingualString(item.question) : item.question}
                      onChange={(value) => updateItem(item.id, { question: value })}
                      placeholder={t('blocks.faq.questionPlaceholder', 'Введите вопрос')}
                    />

                    <MultilingualInput
                      label={t('blocks.faq.answer', 'Ответ')}
                      value={typeof item.answer === 'string' ? createMultilingualString(item.answer) : item.answer}
                      onChange={(value) => updateItem(item.id, { answer: value })}
                      placeholder={t('blocks.faq.answerPlaceholder', 'Введите ответ')}
                      type="textarea"
                    />
                  </div>
                )}
              </CardContent>
            </Card>
          ))}

          {items.length === 0 && (
            <div className="text-center py-8 text-muted-foreground border-2 border-dashed rounded-lg">
              <p className="text-sm">{t('blocks.faq.emptyHint', 'Добавьте вопросы и ответы')}</p>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { withBlockEditor, type BaseBlockEditorProps } from './BlockEditorWrapper';
import { validateFormBlock } from '@/lib/blocks/block-validators';
import { ArrayFieldList } from '@/components/form-fields/ArrayFieldList';
import { ArrayFieldItem } from '@/components/form-fields/ArrayFieldItem';
import { useTranslation } from 'react-i18next';
import { MultilingualInput } from '@/components/form-fields/MultilingualInput';
import { migrateToMultilingual } from '@/lib/i18n-helpers';

function FormBlockEditorComponent({ formData, onChange }: BaseBlockEditorProps) {
  const { t } = useTranslation();
  const fields = formData.fields || [];

  const addField = () => {
    const newField = {
      name: { ru: '', en: '', kk: '' },
      placeholder: { ru: '', en: '', kk: '' },
      type: 'text' as const,
      required: false
    };
    onChange({
      ...formData,
      fields: [...fields, newField],
    });
  };

  const removeField = (index: number) => {
    onChange({
      ...formData,
      fields: fields.filter((_: unknown, i: number) => i !== index),
    });
  };

  const updateField = (index: number, field: string, value: unknown) => {
    const updated = [...fields];
    updated[index] = { ...updated[index], [field]: value };
    onChange({ ...formData, fields: updated });
  };

  return (
    <div className="space-y-4">
      <MultilingualInput
        label={t('fields.formTitle', 'Form Title')}
        value={migrateToMultilingual(formData.title)}
        onChange={(value) => onChange({ ...formData, title: value })}
        placeholder={t('fields.contactForm', 'Contact Form')}
      />

      <MultilingualInput
        label={t('fields.buttonText', 'Button Text')}
        value={migrateToMultilingual(formData.buttonText)}
        onChange={(value) => onChange({ ...formData, buttonText: value })}
        placeholder={t('fields.send', 'Send')}
      />

      <ArrayFieldList label={t('fields.formFields', 'Form Fields')} items={fields} onAdd={addField}>
        {fields.map((field: any, index: number) => (
          <ArrayFieldItem
            key={index}
            index={index}
            label={t('fields.field', 'Field')}
            onRemove={() => removeField(index)}
          >
            <MultilingualInput
              label={t('fields.fieldName', 'Field Name')}
              value={migrateToMultilingual(field.name)}
              onChange={(value) => updateField(index, 'name', value)}
              placeholder={t('fields.fieldNamePlaceholder', 'Name')}
            />

            <MultilingualInput
              label={`${t('fields.placeholder', 'Placeholder')} (${t('fields.optional', 'optional')})`}
              value={migrateToMultilingual(field.placeholder)}
              onChange={(value) => updateField(index, 'placeholder', value)}
              placeholder={t('fields.enterText', 'Enter text...')}
            />

            <div>
              <Label className="text-xs">{t('fields.fieldType', 'Field Type')}</Label>
              <Select
                value={field.type}
                onValueChange={(value: string) => updateField(index, 'type', value)}
              >
                <SelectTrigger>
                  <SelectValue />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="text">{t('fields.text', 'Text')}</SelectItem>
                  <SelectItem value="email">{t('fields.email', 'Email')}</SelectItem>
                  <SelectItem value="phone">{t('fields.phone', 'Phone')}</SelectItem>
                  <SelectItem value="textarea">{t('fields.textarea', 'Textarea')}</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="flex items-center gap-2">
              <input
                type="checkbox"
                id={`required-${index}`}
                checked={field.required || false}
                onChange={(e) => updateField(index, 'required', e.target.checked)}
                className="h-4 w-4"
              />
              <Label htmlFor={`required-${index}`} className="cursor-pointer text-xs">
                {t('fields.requiredField', 'Required field')}
              </Label>
            </div>
          </ArrayFieldItem>
        ))}
      </ArrayFieldList>
    </div>
  );
}

export const FormBlockEditor = withBlockEditor(FormBlockEditorComponent, {
  hint: 'Create a contact form with custom fields',
  validate: validateFormBlock,
  isPremium: true,
  description: 'Collect user information with customizable form fields',
});

