/**
 * ProfileEditorWizard - Step-by-step wizard for editing profile block
 * Steps: Cover → Avatar → Name/Bio → Style
 */
import { memo, useState, useCallback, useRef } from 'react';
import { useTranslation } from 'react-i18next';
import { 
  Image, 
  User, 
  FileText, 
  Palette, 
  ChevronRight, 
  ChevronLeft,
  Check,
  Camera,
  Upload,
  Loader2,
  Sparkles,
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { cn } from '@/lib/utils/utils';
import { migrateToMultilingual, getI18nText, type SupportedLanguage } from '@/lib/i18n-helpers';
import { compressImage } from '@/lib/utils/image-compression';
import { supabase } from '@/platform/supabase/client';
import { useAuth } from '@/hooks/user/useAuth';
import { toast } from 'sonner';
import { ImageCropper } from '@/components/form-fields/ImageCropper';
import type { ProfileBlock } from '@/types/page';

interface ProfileEditorWizardProps {
  formData: Partial<ProfileBlock>;
  onChange: (data: Partial<ProfileBlock>) => void;
  onComplete?: () => void;
}

type WizardStep = 'cover' | 'avatar' | 'info' | 'style';

const STEPS: WizardStep[] = ['cover', 'avatar', 'info', 'style'];

const COVER_GRADIENTS = [
  { value: 'none', label: 'gradients.none', preview: 'bg-muted' },
  { value: 'dark', label: 'gradients.dark', preview: 'bg-gradient-to-b from-black/50 to-black/20' },
  { value: 'light', label: 'gradients.light', preview: 'bg-gradient-to-b from-white/50 to-white/20' },
  { value: 'primary', label: 'gradients.primary', preview: 'bg-gradient-to-b from-primary/60 to-primary/20' },
  { value: 'sunset', label: 'gradients.sunset', preview: 'bg-gradient-to-br from-orange-500/50 via-pink-500/50 to-purple-600/50' },
  { value: 'ocean', label: 'gradients.ocean', preview: 'bg-gradient-to-br from-blue-500/50 via-cyan-500/50 to-teal-500/50' },
];

const AVATAR_SIZES = [
  { value: 'small', label: 'avatarSizes.small', size: 'h-16 w-16' },
  { value: 'medium', label: 'avatarSizes.medium', size: 'h-24 w-24' },
  { value: 'large', label: 'avatarSizes.large', size: 'h-32 w-32' },
  { value: 'xlarge', label: 'avatarSizes.xlarge', size: 'h-40 w-40' },
];

export const ProfileEditorWizard = memo(function ProfileEditorWizard({
  formData,
  onChange,
  onComplete,
}: ProfileEditorWizardProps) {
  const { t, i18n } = useTranslation();
  const { user } = useAuth();
  const currentLang = i18n.language as SupportedLanguage;
  
  const [currentStep, setCurrentStep] = useState<WizardStep>('cover');
  const [isUploading, setIsUploading] = useState(false);
  const [cropperOpen, setCropperOpen] = useState(false);
  const [cropperImage, setCropperImage] = useState('');
  const [cropperType, setCropperType] = useState<'avatar' | 'cover'>('avatar');
  
  const avatarInputRef = useRef<HTMLInputElement>(null);
  const coverInputRef = useRef<HTMLInputElement>(null);

  const currentStepIndex = STEPS.indexOf(currentStep);
  const isFirstStep = currentStepIndex === 0;
  const isLastStep = currentStepIndex === STEPS.length - 1;

  // Get current name/bio for display
  const nameValue = typeof formData.name === 'object' 
    ? getI18nText(formData.name, currentLang)
    : formData.name || '';
  
  const bioValue = typeof formData.bio === 'object'
    ? getI18nText(formData.bio, currentLang)
    : formData.bio || '';

  const initials = nameValue
    .split(' ')
    .map(n => n[0])
    .join('')
    .toUpperCase()
    .slice(0, 2) || 'ME';

  const goNext = useCallback(() => {
    if (isLastStep) {
      onComplete?.();
    } else {
      setCurrentStep(STEPS[currentStepIndex + 1]);
    }
  }, [currentStepIndex, isLastStep, onComplete]);

  const goPrev = useCallback(() => {
    if (!isFirstStep) {
      setCurrentStep(STEPS[currentStepIndex - 1]);
    }
  }, [currentStepIndex, isFirstStep]);

  const goToStep = useCallback((step: WizardStep) => {
    setCurrentStep(step);
  }, []);

  // File upload handler
  const handleFileUpload = useCallback(async (file: File, type: 'avatar' | 'cover') => {
    if (!user) {
      toast.error(t('auth.required', 'Please sign in'));
      return;
    }

    if (file.size > 10 * 1024 * 1024) {
      toast.error(t('upload.fileTooLarge', 'File too large (max 10MB)'));
      return;
    }

    // For GIFs, upload directly
    if (file.type === 'image/gif') {
      await uploadFile(file, type);
      return;
    }

    // Open cropper for other images
    const reader = new FileReader();
    reader.onload = (e) => {
      setCropperImage(e.target?.result as string);
      setCropperType(type);
      setCropperOpen(true);
    };
    reader.readAsDataURL(file);
  }, [user, t]);

  const uploadFile = async (file: File | Blob, type: 'avatar' | 'cover') => {
    if (!user) return;
    
    setIsUploading(true);
    try {
      let processedFile = file;
      if (file instanceof File && file.type.startsWith('image/') && file.type !== 'image/gif') {
        processedFile = await compressImage(file);
      }

      const fileExt = file instanceof File ? file.name.split('.').pop() : 'jpg';
      const fileName = `${type}-${Date.now()}.${fileExt}`;
      const filePath = `${user.id}/${fileName}`;

      const { error } = await supabase.storage
        .from('user-media')
        .upload(filePath, processedFile);

      if (error) throw error;

      const { data: { publicUrl } } = supabase.storage
        .from('user-media')
        .getPublicUrl(filePath);

      if (type === 'avatar') {
        onChange({ ...formData, avatar: publicUrl });
      } else {
        onChange({ ...formData, coverImage: publicUrl });
      }
      toast.success(t('upload.success', 'Uploaded!'));
    } catch (err) {
      console.error('Upload error:', err);
      toast.error(t('upload.error', 'Upload failed'));
    } finally {
      setIsUploading(false);
    }
  };

  const handleCropperSave = async (croppedDataUrl: string) => {
    setCropperOpen(false);
    const { dataUrlToBlob } = await import('@/lib/utils/data-url-to-blob');
    const blob = dataUrlToBlob(croppedDataUrl);
    await uploadFile(blob, cropperType);
  };

  const handleInputChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const type = e.target === avatarInputRef.current ? 'avatar' : 'cover';
      handleFileUpload(file, type);
    }
    e.target.value = '';
  }, [handleFileUpload]);

  // Step content renderers
  const renderCoverStep = () => (
    <div className="space-y-6">
      <div className="text-center">
        <div className="h-14 w-14 rounded-2xl bg-primary/10 flex items-center justify-center mx-auto mb-4">
          <Image className="h-7 w-7 text-primary" />
        </div>
        <h2 className="text-xl font-black">{t('wizard.cover.title', 'Обложка профиля')}</h2>
        <p className="text-sm text-muted-foreground mt-1">
          {t('wizard.cover.description', 'Добавьте красивую обложку для вашего профиля')}
        </p>
      </div>

      {/* Cover preview */}
      <div 
        className={cn(
          "relative aspect-[3/1] rounded-2xl overflow-hidden border-2 border-dashed",
          formData.coverImage ? "border-transparent" : "border-border bg-muted/30"
        )}
      >
        {formData.coverImage ? (
          <>
            <img src={formData.coverImage} alt="" className="w-full h-full object-cover" />
            {formData.coverGradient && formData.coverGradient !== 'none' && (
              <div className={cn(
                "absolute inset-0",
                COVER_GRADIENTS.find(g => g.value === formData.coverGradient)?.preview
              )} />
            )}
          </>
        ) : (
          <div className="flex flex-col items-center justify-center h-full gap-2">
            <Camera className="h-8 w-8 text-muted-foreground" />
            <span className="text-sm text-muted-foreground">
              {t('wizard.cover.placeholder', 'Нажмите чтобы загрузить')}
            </span>
          </div>
        )}
        
        {/* Upload overlay */}
        <button
          type="button"
          onClick={() => coverInputRef.current?.click()}
          disabled={isUploading}
          className="absolute inset-0 flex items-center justify-center bg-black/0 hover:bg-black/40 transition-colors group"
        >
          {isUploading ? (
            <Loader2 className="h-10 w-10 text-white animate-spin" />
          ) : (
            <Upload className="h-10 w-10 text-white opacity-0 group-hover:opacity-100 transition-opacity" />
          )}
        </button>
        <input
          ref={coverInputRef}
          type="file"
          accept="image/*"
          onChange={handleInputChange}
          className="hidden"
        />
      </div>

      {/* Gradient selector */}
      {formData.coverImage && (
        <div className="space-y-3">
          <Label>{t('wizard.cover.gradient', 'Градиент')}</Label>
          <div className="grid grid-cols-3 gap-2">
            {COVER_GRADIENTS.map((gradient) => (
              <button
                key={gradient.value}
                type="button"
                onClick={() => onChange({ ...formData, coverGradient: gradient.value as any })}
                className={cn(
                  "aspect-[2/1] rounded-xl border-2 transition-all",
                  gradient.preview,
                  formData.coverGradient === gradient.value 
                    ? "border-primary ring-2 ring-primary/30" 
                    : "border-border/20 hover:border-border/50"
                )}
              />
            ))}
          </div>
        </div>
      )}

      {formData.coverImage && (
        <Button
          variant="outline"
          size="sm"
          onClick={() => onChange({ ...formData, coverImage: undefined })}
          className="w-full rounded-xl"
        >
          {t('wizard.cover.remove', 'Удалить обложку')}
        </Button>
      )}
    </div>
  );

  const renderAvatarStep = () => (
    <div className="space-y-6">
      <div className="text-center">
        <div className="h-14 w-14 rounded-2xl bg-primary/10 flex items-center justify-center mx-auto mb-4">
          <User className="h-7 w-7 text-primary" />
        </div>
        <h2 className="text-xl font-black">{t('wizard.avatar.title', 'Ваше фото')}</h2>
        <p className="text-sm text-muted-foreground mt-1">
          {t('wizard.avatar.description', 'Добавьте аватар - это поможет людям узнать вас')}
        </p>
      </div>

      {/* Avatar preview */}
      <div className="flex flex-col items-center gap-4">
        <button
          type="button"
          onClick={() => avatarInputRef.current?.click()}
          disabled={isUploading}
          className="relative group"
        >
          <Avatar className="h-32 w-32 ring-4 ring-primary/20 ring-offset-4 ring-offset-background">
            <AvatarImage src={formData.avatar} alt="" />
            <AvatarFallback className="bg-primary text-primary-foreground text-3xl font-black">
              {initials}
            </AvatarFallback>
          </Avatar>
          
          <div className="absolute inset-0 flex items-center justify-center bg-black/50 rounded-full opacity-0 group-hover:opacity-100 transition-opacity">
            {isUploading ? (
              <Loader2 className="h-8 w-8 text-white animate-spin" />
            ) : (
              <Camera className="h-8 w-8 text-white" />
            )}
          </div>
        </button>
        
        <input
          ref={avatarInputRef}
          type="file"
          accept="image/*"
          onChange={handleInputChange}
          className="hidden"
        />

        <p className="text-xs text-muted-foreground text-center">
          {t('wizard.avatar.hint', 'Рекомендуется: квадратное фото минимум 400×400px')}
        </p>
      </div>

      {/* Size selector */}
      <div className="space-y-3">
        <Label>{t('wizard.avatar.size', 'Размер аватара')}</Label>
        <div className="grid grid-cols-4 gap-2">
          {AVATAR_SIZES.map((size) => (
            <button
              key={size.value}
              type="button"
              onClick={() => onChange({ ...formData, avatarSize: size.value as any })}
              className={cn(
                "flex flex-col items-center gap-2 p-3 rounded-xl border-2 transition-all",
                formData.avatarSize === size.value 
                  ? "border-primary bg-primary/5" 
                  : "border-border/20 hover:border-border/50"
              )}
            >
              <div className={cn("rounded-full bg-muted", 
                size.value === 'small' && 'h-6 w-6',
                size.value === 'medium' && 'h-8 w-8',
                size.value === 'large' && 'h-10 w-10',
                size.value === 'xlarge' && 'h-12 w-12'
              )} />
              <span className="text-[10px] font-medium">{t(size.label)}</span>
            </button>
          ))}
        </div>
      </div>
    </div>
  );

  const renderInfoStep = () => (
    <div className="space-y-6">
      <div className="text-center">
        <div className="h-14 w-14 rounded-2xl bg-primary/10 flex items-center justify-center mx-auto mb-4">
          <FileText className="h-7 w-7 text-primary" />
        </div>
        <h2 className="text-xl font-black">{t('wizard.info.title', 'О вас')}</h2>
        <p className="text-sm text-muted-foreground mt-1">
          {t('wizard.info.description', 'Расскажите о себе - имя и краткое описание')}
        </p>
      </div>

      {/* Name input */}
      <div className="space-y-2">
        <Label>{t('fields.name', 'Имя')}</Label>
        <Input
          value={nameValue}
          onChange={(e) => {
            const newName = migrateToMultilingual(e.target.value);
            onChange({ ...formData, name: newName });
          }}
          placeholder={t('placeholders.yourName', 'Ваше имя')}
          className="h-14 text-lg rounded-2xl border-2 focus:border-primary"
        />
      </div>

      {/* Bio input */}
      <div className="space-y-2">
        <Label>{t('fields.bio', 'О себе')}</Label>
        <Textarea
          value={bioValue}
          onChange={(e) => {
            const newBio = migrateToMultilingual(e.target.value);
            onChange({ ...formData, bio: newBio });
          }}
          placeholder={t('placeholders.tellAboutYourself', 'Расскажите о себе...')}
          className="min-h-[120px] text-base rounded-2xl border-2 focus:border-primary resize-none"
          rows={4}
        />
        <p className="text-xs text-muted-foreground text-right">
          {bioValue.length}/200
        </p>
      </div>
    </div>
  );

  const renderStyleStep = () => (
    <div className="space-y-6">
      <div className="text-center">
        <div className="h-14 w-14 rounded-2xl bg-primary/10 flex items-center justify-center mx-auto mb-4">
          <Palette className="h-7 w-7 text-primary" />
        </div>
        <h2 className="text-xl font-black">{t('wizard.style.title', 'Финальные штрихи')}</h2>
        <p className="text-sm text-muted-foreground mt-1">
          {t('wizard.style.description', 'Настройте внешний вид профиля')}
        </p>
      </div>

      {/* Preview card */}
      <div className="border border-border/20 rounded-2xl overflow-hidden bg-card">
        {/* Mini cover */}
        <div className={cn(
          "h-20 w-full relative",
          formData.coverImage ? '' : 'bg-muted'
        )}>
          {formData.coverImage && (
            <img src={formData.coverImage} alt="" className="w-full h-full object-cover" />
          )}
        </div>
        
        {/* Avatar + info */}
        <div className="flex items-center gap-4 p-4 -mt-8">
          <Avatar className="h-16 w-16 ring-4 ring-background">
            <AvatarImage src={formData.avatar} alt="" />
            <AvatarFallback className="bg-primary text-primary-foreground text-lg font-black">
              {initials}
            </AvatarFallback>
          </Avatar>
          <div className="flex-1 min-w-0 pt-6">
            <h3 className="font-bold truncate">{nameValue || t('wizard.preview.name', 'Ваше имя')}</h3>
            <p className="text-sm text-muted-foreground truncate">{bioValue || t('wizard.preview.bio', 'О себе')}</p>
          </div>
        </div>
      </div>

      {/* Quick style options */}
      <div className="space-y-3">
        <Label>{t('wizard.style.position', 'Позиция аватара')}</Label>
        <div className="grid grid-cols-3 gap-2">
          {['left', 'center', 'right'].map((pos) => (
            <button
              key={pos}
              type="button"
              onClick={() => onChange({ ...formData, avatarPosition: pos as any })}
              className={cn(
                "py-3 rounded-xl border-2 text-sm font-medium transition-all",
                formData.avatarPosition === pos 
                  ? "border-primary bg-primary/5" 
                  : "border-border/20 hover:border-border/50"
              )}
            >
              {t(`fields.${pos}`, pos)}
            </button>
          ))}
        </div>
      </div>

      {/* Success message */}
      <div className="flex items-center gap-3 p-4 rounded-2xl bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800">
        <Sparkles className="h-5 w-5 text-green-600" />
        <p className="text-sm text-green-700 dark:text-green-400">
          {t('wizard.style.ready', 'Отлично! Ваш профиль готов к публикации')}
        </p>
      </div>
    </div>
  );

  return (
    <div className="flex flex-col h-full">
      {/* Progress steps */}
      <div className="flex items-center justify-center gap-2 px-4 py-3 border-b border-border/10">
        {STEPS.map((step, index) => {
          const isActive = step === currentStep;
          const isCompleted = index < currentStepIndex;
          
          return (
            <button
              key={step}
              type="button"
              onClick={() => goToStep(step)}
              className={cn(
                "flex items-center gap-1.5 px-3 py-1.5 rounded-full text-xs font-medium transition-all",
                isActive && "bg-primary text-primary-foreground",
                isCompleted && "bg-primary/20 text-primary",
                !isActive && !isCompleted && "bg-muted text-muted-foreground"
              )}
            >
              {isCompleted && <Check className="h-3 w-3" />}
              <span>{index + 1}</span>
            </button>
          );
        })}
      </div>

      {/* Content */}
      <div className="flex-1 overflow-y-auto px-5 py-6">
        {currentStep === 'cover' && renderCoverStep()}
        {currentStep === 'avatar' && renderAvatarStep()}
        {currentStep === 'info' && renderInfoStep()}
        {currentStep === 'style' && renderStyleStep()}
      </div>

      {/* Navigation */}
      <div className="flex gap-3 px-5 py-4 pb-safe border-t border-border/10 bg-background/98">
        {!isFirstStep && (
          <Button
            variant="outline"
            onClick={goPrev}
            className="flex-1 h-14 rounded-2xl text-base font-bold"
          >
            <ChevronLeft className="h-5 w-5 mr-1" />
            {t('wizard.back', 'Назад')}
          </Button>
        )}
        
        <Button
          onClick={goNext}
          className={cn(
            "h-14 rounded-2xl text-base font-bold shadow-lg shadow-primary/25",
            isFirstStep ? "flex-1" : "flex-[2]"
          )}
        >
          {isLastStep ? (
            <>
              <Check className="h-5 w-5 mr-2" />
              {t('wizard.finish', 'Готово')}
            </>
          ) : (
            <>
              {t('wizard.next', 'Далее')}
              <ChevronRight className="h-5 w-5 ml-1" />
            </>
          )}
        </Button>
      </div>

      {/* Image Cropper */}
      <ImageCropper
        imageUrl={cropperImage}
        open={cropperOpen}
        onClose={() => setCropperOpen(false)}
        onSave={handleCropperSave}
        aspectRatio={cropperType === 'avatar' ? 1 : 16 / 9}
        shape={cropperType === 'avatar' ? 'circle' : 'rectangle'}
      />
    </div>
  );
});

import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { withBlockEditor, type BaseBlockEditorProps } from './BlockEditorWrapper';
import { validateTestimonialBlock } from '@/lib/blocks/block-validators';
import { ArrayFieldList } from '@/components/form-fields/ArrayFieldList';
import { ArrayFieldItem } from '@/components/form-fields/ArrayFieldItem';
import { useTranslation } from 'react-i18next';
import { MultilingualInput } from '@/components/form-fields/MultilingualInput';
import { migrateToMultilingual } from '@/lib/i18n-helpers';

function TestimonialBlockEditorComponent({ formData, onChange }: BaseBlockEditorProps) {
  const { t } = useTranslation();
  const testimonials = formData.testimonials || [];

  const addTestimonial = () => {
    onChange({
      ...formData,
      testimonials: [...testimonials, { 
        name: { ru: '', en: '', kk: '' }, 
        role: { ru: '', en: '', kk: '' }, 
        avatar: '', 
        text: { ru: '', en: '', kk: '' }, 
        rating: 5 
      }],
    });
  };

  const removeTestimonial = (index: number) => {
    onChange({
      ...formData,
      testimonials: testimonials.filter((_: unknown, i: number) => i !== index),
    });
  };

  const updateTestimonial = (index: number, field: string, value: unknown) => {
    const updated = [...testimonials];
    updated[index] = { ...updated[index], [field]: value };
    onChange({ ...formData, testimonials: updated });
  };

  return (
    <div className="space-y-4">
      <MultilingualInput
        label={t('fields.title', 'Title')}
        value={migrateToMultilingual(formData.title)}
        onChange={(value) => onChange({ ...formData, title: value })}
        placeholder={t('fields.whatPeopleSay', 'What People Say')}
      />

      <ArrayFieldList label={t('fields.testimonials', 'Testimonials')} items={testimonials} onAdd={addTestimonial}>
        {testimonials.map((testimonial: any, index: number) => (
          <ArrayFieldItem
            key={index}
            index={index}
            label={t('fields.testimonial', 'Testimonial')}
            onRemove={() => removeTestimonial(index)}
          >
            <MultilingualInput
              label={t('fields.name', 'Name')}
              value={migrateToMultilingual(testimonial.name)}
              onChange={(value) => updateTestimonial(index, 'name', value)}
              placeholder="John Doe"
            />

            <MultilingualInput
              label={`${t('fields.role', 'Role')} (${t('fields.optional', 'optional')})`}
              value={migrateToMultilingual(testimonial.role)}
              onChange={(value) => updateTestimonial(index, 'role', value)}
              placeholder="CEO, Company"
            />

            <div>
              <Label className="text-xs">{t('fields.avatarUrl', 'Avatar URL')} ({t('fields.optional', 'optional')})</Label>
              <Input
                type="url"
                value={testimonial.avatar || ''}
                onChange={(e) => updateTestimonial(index, 'avatar', e.target.value)}
                placeholder="https://example.com/avatar.jpg"
              />
            </div>

            <MultilingualInput
              label={t('fields.testimonialText', 'Testimonial Text')}
              value={migrateToMultilingual(testimonial.text)}
              onChange={(value) => updateTestimonial(index, 'text', value)}
              type="textarea"
              placeholder={t('fields.testimonialPlaceholder', 'This is an amazing product!')}
            />

            <div>
              <Label className="text-xs">{t('fields.rating', 'Rating')} (1-5)</Label>
              <Input
                type="number"
                min="1"
                max="5"
                value={testimonial.rating || 5}
                onChange={(e) => updateTestimonial(index, 'rating', parseInt(e.target.value))}
              />
            </div>
          </ArrayFieldItem>
        ))}
      </ArrayFieldList>
    </div>
  );
}

export const TestimonialBlockEditor = withBlockEditor(TestimonialBlockEditorComponent, {
  hint: 'Display customer reviews and testimonials with ratings',
  validate: validateTestimonialBlock,
  isPremium: true,
  description: 'Showcase social proof with customer testimonials',
});

import { useTranslation } from 'react-i18next';
import type { AvatarBlock as AvatarBlockType, AvatarFrameStyle } from '@/types/page';
import { cn } from '@/lib/utils/utils';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { getAnimationClass, getAnimationStyle } from '@/lib/animation-utils';
import { getI18nText, type SupportedLanguage } from '@/lib/i18n-helpers';
import { getFrameStyles, getShadowStyles, FRAME_CSS, isAnimatedFrame } from '@/lib/avatar-frame-utils';

interface AvatarBlockProps {
  block: AvatarBlockType;
}

export function AvatarBlock({ block }: AvatarBlockProps) {
  const { i18n } = useTranslation();
  const name = getI18nText(block.name, i18n.language as SupportedLanguage);
  const subtitle = getI18nText(block.subtitle, i18n.language as SupportedLanguage);

  const sizeClasses = {
    small: 'h-16 w-16',
    medium: 'h-24 w-24',
    large: 'h-32 w-32',
    xlarge: 'h-48 w-48',
  };

  // Frame sizes (slightly larger than avatar)
  const frameSizeClasses = {
    small: 'h-[72px] w-[72px]',
    medium: 'h-[104px] w-[104px]',
    large: 'h-[136px] w-[136px]',
    xlarge: 'h-[200px] w-[200px]',
  };

  const shapeClasses = {
    circle: 'rounded-full',
    rounded: 'rounded-xl',
    square: 'rounded-none',
  };

  const initials = name
    .split(' ')
    .map(n => n[0])
    .join('')
    .toUpperCase()
    .slice(0, 2);

  const paddingMap = { none: '', sm: 'p-2', md: 'p-4', lg: 'p-6', xl: 'p-8' };
  const marginMap = { none: '', sm: 'my-2', md: 'my-4', lg: 'my-6', xl: 'my-8' };

  const alignmentClass = block.alignment === 'left' ? 'items-start text-left'
    : block.alignment === 'right' ? 'items-end text-right'
      : 'items-center text-center';

  const frameStyle = block.frameStyle || (block.border ? 'gradient' : 'none');
  const hasFrame = frameStyle !== 'none';

  return (
    <div
      className={cn(
        "flex flex-col gap-3",
        alignmentClass,
        block.blockStyle?.padding && paddingMap[block.blockStyle.padding],
        block.blockStyle?.margin && marginMap[block.blockStyle.margin],
      )}
    >
      {/* Outer wrapper for animation */}
      <div
        className={cn(
          "relative",
          getAnimationClass(block.blockStyle)
        )}
        style={getAnimationStyle(block.blockStyle)}
      >
        {/* Frame wrapper - shadow applies here */}
        <div
          className={cn(
            "flex items-center justify-center",
            frameSizeClasses[block.size || 'medium'],
            shapeClasses[block.shape || 'circle'],
          )}
          style={{
            ...getShadowStyles(block.shadow || 'none'),
            ...(hasFrame ? getFrameStyles(frameStyle) : {}),
          }}
        >
          {/* Avatar - NO animation, NO shadow */}
          <Avatar
            className={cn(
              sizeClasses[block.size || 'medium'],
              shapeClasses[block.shape || 'circle'],
              "bg-background"
            )}
          >
            <AvatarImage src={block.imageUrl} alt={name} className="object-cover" />
            <AvatarFallback className="text-lg font-semibold bg-primary/10">
              {initials}
            </AvatarFallback>
          </Avatar>
        </div>
      </div>

      <div className="space-y-1.5">
        <h3 className="text-xl font-bold text-gradient leading-tight">{name}</h3>
        {subtitle && (
          <p className="text-sm font-medium text-muted-foreground/80">{subtitle}</p>
        )}
      </div>

      {/* CSS for frame animations */}
      <style>{FRAME_CSS}</style>
    </div>
  );
}

import React, { useState, useRef, useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import type { BeforeAfterBlock as BeforeAfterBlockType } from '@/types/page';
import { Card, CardContent } from '@/components/ui/card';
import { getI18nText } from '@/lib/i18n-helpers';
import { cn } from '@/lib/utils/utils';

interface BeforeAfterBlockProps {
  block: BeforeAfterBlockType;
}

export const BeforeAfterBlock = React.memo(function BeforeAfterBlock({ block }: BeforeAfterBlockProps) {
  const { t, i18n } = useTranslation();
  const currentLang = i18n.language as 'ru' | 'en' | 'kk';
  const [sliderPosition, setSliderPosition] = useState(50);
  const containerRef = useRef<HTMLDivElement>(null);
  const isDragging = useRef(false);

  const title = block.title ? getI18nText(block.title, currentLang) : '';
  const beforeLabel = block.beforeLabel 
    ? getI18nText(block.beforeLabel, currentLang) 
    : t('blocks.beforeAfter.before', 'До');
  const afterLabel = block.afterLabel 
    ? getI18nText(block.afterLabel, currentLang) 
    : t('blocks.beforeAfter.after', 'После');

  const handleMove = useCallback((clientX: number) => {
    if (!containerRef.current) return;
    
    const rect = containerRef.current.getBoundingClientRect();
    const x = clientX - rect.left;
    const percentage = Math.max(0, Math.min(100, (x / rect.width) * 100));
    setSliderPosition(percentage);
  }, []);

  const handleMouseDown = useCallback(() => {
    isDragging.current = true;
  }, []);

  const handleMouseUp = useCallback(() => {
    isDragging.current = false;
  }, []);

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
    if (!isDragging.current) return;
    handleMove(e.clientX);
  }, [handleMove]);

  const handleTouchMove = useCallback((e: React.TouchEvent) => {
    handleMove(e.touches[0].clientX);
  }, [handleMove]);

  const handleClick = useCallback((e: React.MouseEvent) => {
    handleMove(e.clientX);
  }, [handleMove]);

  if (!block.beforeImage || !block.afterImage) {
    return (
      <Card className="w-full">
        <CardContent className="p-6 text-center text-muted-foreground">
          {t('blocks.beforeAfter.noImages', 'Добавьте изображения')}
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="w-full space-y-3">
      {title && (
        <h3 className="text-xl font-semibold text-center">{title}</h3>
      )}
      
      <div 
        ref={containerRef}
        className="relative w-full aspect-[4/3] rounded-xl overflow-hidden cursor-ew-resize select-none"
        onMouseDown={handleMouseDown}
        onMouseUp={handleMouseUp}
        onMouseLeave={handleMouseUp}
        onMouseMove={handleMouseMove}
        onTouchMove={handleTouchMove}
        onClick={handleClick}
      >
        {/* After Image (Background) */}
        <img
          src={block.afterImage}
          alt={afterLabel}
          className="absolute inset-0 w-full h-full object-cover"
          draggable={false}
        />
        
        {/* Before Image (Clipped) */}
        <div 
          className="absolute inset-0 overflow-hidden"
          style={{ width: `${sliderPosition}%` }}
        >
          <img
            src={block.beforeImage}
            alt={beforeLabel}
            className="absolute inset-0 w-full h-full object-cover"
            style={{ 
              width: containerRef.current ? `${containerRef.current.offsetWidth}px` : '100%',
              maxWidth: 'none'
            }}
            draggable={false}
          />
        </div>
        
        {/* Slider Line */}
        <div 
          className="absolute top-0 bottom-0 w-1 bg-background shadow-lg z-10"
          style={{ left: `${sliderPosition}%`, transform: 'translateX(-50%)' }}
        >
          {/* Handle */}
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-10 h-10 bg-background rounded-full shadow-lg flex items-center justify-center border border-border">
            <div className="flex gap-0.5">
              <div className="w-0.5 h-4 bg-muted-foreground rounded" />
              <div className="w-0.5 h-4 bg-muted-foreground rounded" />
            </div>
          </div>
        </div>
        
        {/* Labels */}
        <div className="absolute bottom-3 left-3 px-2 py-1 bg-background/80 backdrop-blur-sm text-foreground text-sm rounded border border-border">
          {beforeLabel}
        </div>
        <div className="absolute bottom-3 right-3 px-2 py-1 bg-background/80 backdrop-blur-sm text-foreground text-sm rounded border border-border">
          {afterLabel}
        </div>
      </div>
    </div>
  );
});

import { memo, useState, useEffect, useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { Calendar } from '@/components/ui/calendar';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Clock, CalendarDays, User, Phone, Mail, Check, Loader2, MessageCircle, CheckCircle2, XCircle, Info } from 'lucide-react';
import { supabase } from '@/platform/supabase/client';
import { fintechService } from '@/services/fintech';
import { useRobokassa } from '@/hooks/useRobokassa';
import { getCurrencySymbol } from '@/components/form-fields/CurrencySelect';
import { cn } from '@/lib/utils/utils';
import { toast } from 'sonner';
import { format, addDays, isBefore, startOfDay, isToday, isTomorrow } from 'date-fns';
import { ru, kk } from 'date-fns/locale';
import { getI18nText, type SupportedLanguage } from '@/lib/i18n-helpers';
import type { BookingBlock as BookingBlockType } from '@/types/page';

interface BookingBlockProps {
  block: BookingBlockType;
  pageOwnerId?: string;
  pageId?: string;
}

interface TimeSlot {
  time: string;
  endTime?: string;
  available: boolean;
  bookingId?: string;
}

interface BookingFormData {
  name: string;
  phone: string;
  email: string;
  notes: string;
}

export const BookingBlock = memo(function BookingBlockComponent({
  block,
  pageOwnerId,
  pageId
}: BookingBlockProps) {
  const { t, i18n } = useTranslation();
  const [selectedDate, setSelectedDate] = useState<Date | undefined>(undefined);
  const [selectedSlot, setSelectedSlot] = useState<TimeSlot | null>(null);
  const [slots, setSlots] = useState<TimeSlot[]>([]);
  const [loading, setLoading] = useState(false);
  const [submitting, setSubmitting] = useState(false);
  const [showForm, setShowForm] = useState(false);
  const [formData, setFormData] = useState<BookingFormData>({
    name: '',
    phone: '',
    email: '',
    notes: ''
  });

  const { initiatePayment } = useRobokassa();

  const locale = i18n.language === 'ru' ? ru : i18n.language === 'kk' ? kk : undefined;

  // Fetch available slots for selected date
  const fetchSlots = useCallback(async (date: Date) => {
    if (!pageId || !block.id) return;

    setLoading(true);
    try {
      const dayOfWeek = date.getDay();
      const dateStr = format(date, 'yyyy-MM-dd');

      // Fetch slot templates for this day
      const { data: slotTemplates } = await supabase
        .from('booking_slots')
        .select('*')
        .eq('page_id', pageId)
        .eq('block_id', block.id)
        .eq('is_available', true)
        .or(`day_of_week.eq.${dayOfWeek},specific_date.eq.${dateStr}`);

      // Fetch existing bookings for this date
      const { data: bookings } = await supabase
        .from('bookings')
        .select('*')
        .eq('page_id', pageId)
        .eq('block_id', block.id)
        .eq('slot_date', dateStr)
        .neq('status', 'cancelled');

      // Generate slots from templates
      const generatedSlots: TimeSlot[] = [];

      // Call Edge Function to check Google Calendar availability if enabled
      let gcalBlockedSlots: string[] = [];
      if (block.gcalSyncEnabled && pageOwnerId) {
        try {
          const { data, error } = await supabase.functions.invoke('google-calendar-sync', {
            body: {
              action: 'check_availability',
              owner_id: pageOwnerId,
              date: dateStr
            }
          });

          if (!error && data?.blocked_slots) {
            gcalBlockedSlots = data.blocked_slots;
          }
        } catch (err) {
          console.error('Failed to sync with Google Calendar:', err);
        }
      }

      // If block has custom slots defined
      if (block.slots && block.slots.length > 0) {
        block.slots.forEach(slot => {
          const isBookedLocally = bookings?.some(b => b.slot_time === slot.startTime);
          const isBookedGcal = gcalBlockedSlots.includes(slot.startTime);

          generatedSlots.push({
            time: slot.startTime,
            endTime: slot.endTime,
            available: !isBookedLocally && !isBookedGcal,
            bookingId: bookings?.find(b => b.slot_time === slot.startTime)?.id
          });
        });
      } else if (slotTemplates && slotTemplates.length > 0) {
        slotTemplates.forEach(template => {
          const isBookedLocally = bookings?.some(b => b.slot_time === template.start_time);
          const isBookedGcal = gcalBlockedSlots.includes(template.start_time);

          generatedSlots.push({
            time: template.start_time,
            endTime: template.end_time,
            available: !isBookedLocally && !isBookedGcal,
            bookingId: bookings?.find(b => b.slot_time === template.start_time)?.id
          });
        });
      } else {
        // Generate default slots from block settings
        const startHour = block.workingHoursStart ?? 9;
        const endHour = block.workingHoursEnd ?? 18;
        const duration = block.slotDuration || 60;

        // Calculate total minutes from start to end
        const startMinutes = startHour * 60;
        const endMinutes = endHour * 60;

        // Generate slots based on duration
        for (let slotStart = startMinutes; slotStart + duration <= endMinutes; slotStart += duration) {
          const slotEnd = slotStart + duration;

          const startHr = Math.floor(slotStart / 60);
          const startMin = slotStart % 60;
          const endHr = Math.floor(slotEnd / 60);
          const endMin = slotEnd % 60;

          const timeStr = `${startHr.toString().padStart(2, '0')}:${startMin.toString().padStart(2, '0')}:00`;
          const endTimeStr = `${endHr.toString().padStart(2, '0')}:${endMin.toString().padStart(2, '0')}:00`;

          const isBookedLocally = bookings?.some(b => b.slot_time === timeStr);
          const isBookedGcal = gcalBlockedSlots.includes(timeStr);

          generatedSlots.push({
            time: timeStr,
            endTime: endTimeStr,
            available: !isBookedLocally && !isBookedGcal,
            bookingId: bookings?.find(b => b.slot_time === timeStr)?.id
          });
        }
      }

      setSlots(generatedSlots.sort((a, b) => a.time.localeCompare(b.time)));
    } catch (error) {
      console.error('Error fetching slots:', error);
    } finally {
      setLoading(false);
    }
  }, [pageId, block.id, block.slots, block.workingHoursStart, block.workingHoursEnd, block.slotDuration]);

  useEffect(() => {
    if (selectedDate) {
      fetchSlots(selectedDate);
    }
  }, [selectedDate, fetchSlots]);

  const handleSelectSlot = (slot: TimeSlot) => {
    if (!slot.available) return;
    setSelectedSlot(slot);
    setShowForm(true);
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!selectedDate || !selectedSlot || !pageId || !pageOwnerId) return;

    setSubmitting(true);
    try {
      const { data: session } = await supabase.auth.getSession();

      const { error } = await supabase
        .from('bookings')
        .insert({
          page_id: pageId,
          block_id: block.id,
          owner_id: pageOwnerId,
          user_id: session?.session?.user?.id || null,
          slot_date: format(selectedDate, 'yyyy-MM-dd'),
          slot_time: selectedSlot.time,
          slot_end_time: selectedSlot.endTime || null,
          client_name: formData.name,
          client_phone: formData.phone || null,
          client_email: formData.email || null,
          client_notes: formData.notes || null,
        });

      if (error) throw error;

      // Record in Fintech Ledger (Phase 1)
      try {
        await fintechService.recordPendingIncome({
          userId: pageOwnerId,
          amount: block.prepaymentAmount || 0,
          description: `Бронирование: ${formData.name} (${format(selectedDate, 'dd.MM.yyyy')} ${selectedSlot.time.substring(0, 5)})`,
          relatedEntityId: block.id,
          relatedEntityType: 'booking',
          metadata: {
            client_name: formData.name,
            slot_date: format(selectedDate, 'yyyy-MM-dd'),
            slot_time: selectedSlot.time
          }
        });
      } catch (fintechErr) {
        console.error('Failed to record fintech transaction', fintechErr);
        // Don't block the main flow
      }

      // Send notification to owner
      try {
        await supabase.functions.invoke('send-booking-notification', {
          body: {
            ownerId: pageOwnerId,
            clientName: formData.name,
            clientPhone: formData.phone,
            clientEmail: formData.email,
            date: format(selectedDate, 'dd.MM.yyyy'),
            time: selectedSlot.time.substring(0, 5),
          }
        });
      } catch {
        // Notification failed but booking succeeded
      }

      // Add event to Google Calendar if sync is enabled
      if (block.gcalSyncEnabled && pageOwnerId) {
        try {
          await supabase.functions.invoke('google-calendar-sync', {
            body: {
              action: 'create_event',
              owner_id: pageOwnerId,
              date: format(selectedDate, 'yyyy-MM-dd'),
              start_time: selectedSlot.time,
              end_time: selectedSlot.endTime || null,
              client_name: formData.name,
              client_phone: formData.phone || '',
              client_email: formData.email || '',
              client_notes: formData.notes || '',
              block_title: blockTitle
            }
          });
        } catch (err) {
          console.error('Failed to create event in Google Calendar:', err);
        }
      }

      // If prepayment is required, redirect to Robokassa
      if (block.requirePrepayment && block.prepaymentAmount && block.prepaymentAmount > 0) {
        const amount = block.prepaymentAmount;
        const description = t('booking.payment_desc', 'Запись на {{date}} {{time}}', {
          date: format(selectedDate, 'dd.MM.yyyy'),
          time: selectedSlot.time.substring(0, 5)
        });

        // initiatePayment will redirect to Robokassa
        await initiatePayment(amount, description, block.id);
      } else {
        toast.success(t('booking.success', 'Вы успешно записались!'));
        setShowForm(false);
        setSelectedSlot(null);
        setFormData({ name: '', phone: '', email: '', notes: '' });
      }

      setFormData({ name: '', phone: '', email: '', notes: '' });

      // Refresh slots
      fetchSlots(selectedDate);
    } catch (error) {
      console.error('Booking error:', error);
      toast.error(t('booking.error', 'Ошибка при записи. Попробуйте снова.'));
    } finally {
      setSubmitting(false);
    }
  };

  const formatTime = (time: string) => {
    return time.substring(0, 5);
  };

  const disabledDays = (date: Date) => {
    // Disable past dates
    if (isBefore(startOfDay(date), startOfDay(new Date()))) return true;

    // Disable dates beyond max booking days
    const maxDays = block.maxBookingDays || 30;
    if (isBefore(addDays(new Date(), maxDays), date)) return true;

    // Disable specific weekdays if configured
    if (block.disabledWeekdays?.includes(date.getDay())) return true;

    return false;
  };

  const blockTitle = typeof block.title === 'object'
    ? getI18nText(block.title, i18n.language as SupportedLanguage)
    : block.title;

  const blockDescription = typeof block.description === 'object'
    ? getI18nText(block.description, i18n.language as SupportedLanguage)
    : block.description;

  // Calculate stats for the selected date
  const availableCount = slots.filter(s => s.available).length;
  const bookedCount = slots.filter(s => !s.available).length;
  const totalCount = slots.length;

  // Format date label
  const getDateLabel = (date: Date) => {
    if (isToday(date)) return t('booking.today', 'Сегодня');
    if (isTomorrow(date)) return t('booking.tomorrow', 'Завтра');
    return format(date, 'd MMMM, EEEE', { locale });
  };

  // Get working hours display
  const getWorkingHours = () => {
    const start = block.workingHoursStart || 9;
    const end = block.workingHoursEnd || 18;
    return `${start.toString().padStart(2, '0')}:00 — ${end.toString().padStart(2, '0')}:00`;
  };

  return (
    <div className="w-full rounded-2xl overflow-hidden glass-card backdrop-blur-md border-white/10 shadow-glass">
      {/* Header */}
      <div className="p-5 sm:p-6 pb-2">
        <div className="flex items-center gap-3">
          <div className="p-2 rounded-xl bg-primary/10 text-primary shadow-sm shadow-primary/20">
            <CalendarDays className="h-5 w-5" />
          </div>
          <h3 className="font-bold text-lg text-gradient">
            {blockTitle || t('booking.title', 'Записаться')}
          </h3>
        </div>
        {blockDescription && (
          <p className="text-sm text-muted-foreground/80 mt-2 line-clamp-2">{blockDescription}</p>
        )}
        {/* Working hours - premium style */}
        <div className="flex items-center gap-1.5 text-xs font-medium text-primary mt-3 bg-primary/5 w-fit px-2 py-1 rounded-lg">
          <Clock className="h-3 w-3" />
          <span>{getWorkingHours()}</span>
        </div>
      </div>

      <div className="p-5 sm:p-6 pt-2 space-y-6">
        {/* Step indicator - Premium */}
        <div className="flex items-center gap-2 text-xs font-semibold">
          <div className={cn(
            "flex items-center justify-center w-6 h-6 rounded-lg transition-all duration-300",
            selectedDate ? "bg-primary text-primary-foreground shadow-lg shadow-primary/20" : "bg-primary/5 text-primary/50"
          )}>
            1
          </div>
          <span className={selectedDate ? 'text-foreground' : 'text-muted-foreground'}>
            {t('booking.step1', 'Дата')}
          </span>
          {selectedDate && (
            <>
              <div className="h-0.5 flex-1 bg-primary/10 rounded-full mx-1" />
              <div className={cn(
                "flex items-center justify-center w-6 h-6 rounded-lg transition-all duration-300",
                selectedSlot ? "bg-primary text-primary-foreground shadow-lg shadow-primary/20" : "bg-primary/5 text-primary/50"
              )}>
                2
              </div>
              <span className={selectedSlot ? 'text-foreground' : 'text-muted-foreground'}>
                {t('booking.step2', 'Время')}
              </span>
            </>
          )}
        </div>

        {/* Calendar - optimized with glass feel */}
        <div className="flex justify-center -mx-2 bg-primary/5 rounded-2xl p-2 border border-white/5">
          <Calendar
            mode="single"
            selected={selectedDate}
            onSelect={setSelectedDate}
            disabled={disabledDays}
            locale={locale}
            className="rounded-xl border-0 w-full max-w-[320px]"
            classNames={{
              months: "w-full",
              month: "w-full space-y-2",
              caption: "flex justify-center pt-1 relative items-center mb-2",
              caption_label: "text-sm font-bold text-gradient",
              nav: "space-x-1 flex items-center",
              nav_button: "h-8 w-8 bg-white/5 p-0 opacity-50 hover:opacity-100 rounded-lg hover:bg-white/10 transition-colors",
              table: "w-full border-collapse",
              head_row: "flex w-full",
              head_cell: "text-primary/60 rounded-md w-full font-bold text-[0.7rem] uppercase tracking-wider",
              row: "flex w-full mt-1",
              cell: "relative p-0 text-center text-sm focus-within:relative focus-within:z-20 flex-1 aspect-square",
              day: "h-full w-full p-0 font-medium hover:bg-primary/10 rounded-xl transition-all text-sm flex items-center justify-center",
              day_selected: "bg-primary text-primary-foreground hover:bg-primary hover:text-primary-foreground focus:bg-primary focus:text-primary-foreground shadow-lg shadow-primary/30 scale-110 z-10",
              day_today: "bg-primary/10 text-primary font-bold",
              day_disabled: "text-muted-foreground/30 opacity-50",
              day_outside: "text-muted-foreground/20 opacity-50",
            }}
          />
        </div>

        {/* Time slots section - mobile optimized */}
        {selectedDate && (
          <div className="space-y-3">
            {/* Date header with stats - glass style */}
            <div className="flex items-center justify-between gap-3 p-3 rounded-xl bg-white/5 border border-white/10">
              <div className="flex items-center gap-2.5 min-w-0">
                <div className="p-1.5 rounded-lg bg-primary/10 text-primary">
                  <CalendarDays className="h-4 w-4" />
                </div>
                <span className="font-bold text-sm truncate">{getDateLabel(selectedDate)}</span>
              </div>
              {!loading && totalCount > 0 && (
                <div className="flex items-center gap-2.5 text-xs font-bold px-2 py-1 rounded-lg bg-black/20">
                  <span className="flex items-center gap-1 text-emerald-400">
                    <CheckCircle2 className="h-3 w-3" />
                    {availableCount}
                  </span>
                  {bookedCount > 0 && (
                    <span className="flex items-center gap-1 text-white/40">
                      <XCircle className="h-3 w-3" />
                      {bookedCount}
                    </span>
                  )}
                </div>
              )}
            </div>

            {loading ? (
              <div className="flex flex-col items-center justify-center py-10 gap-3">
                <Loader2 className="h-6 w-6 animate-spin text-primary" />
                <span className="text-xs font-medium text-muted-foreground animate-pulse">
                  {t('booking.loadingSlots', 'Загружаем...')}
                </span>
              </div>
            ) : slots.length === 0 ? (
              <div className="flex flex-col items-center justify-center py-10 gap-3 text-center bg-white/5 rounded-2xl border border-dashed border-white/10">
                <div className="p-3 rounded-full bg-white/5 text-muted-foreground/50">
                  <Info className="h-8 w-8" />
                </div>
                <div>
                  <p className="text-sm font-bold">
                    {t('booking.noSlotsTitle', 'Нет доступных окон')}
                  </p>
                  <p className="text-xs text-muted-foreground mt-1">
                    {t('booking.noSlotsHint', 'Попробуйте выбрать другую дату')}
                  </p>
                </div>
              </div>
            ) : (
              /* Time slots grid - premium glass buttons */
              <div className="grid grid-cols-3 gap-2 max-h-[220px] overflow-y-auto pr-2 custom-scrollbar">
                {slots.map((slot, idx) => (
                  <button
                    key={idx}
                    disabled={!slot.available}
                    onClick={() => handleSelectSlot(slot)}
                    className={cn(
                      "relative py-3 px-1 rounded-xl text-center transition-all duration-300",
                      slot.available
                        ? selectedSlot?.time === slot.time
                          ? "bg-primary text-primary-foreground shadow-lg shadow-primary/40 scale-105 z-10 border-transparent font-bold"
                          : "glass-card hover:border-primary/50 hover:bg-primary/5 active:scale-95 border-white/10"
                        : "bg-white/5 opacity-20 cursor-not-allowed border-transparent"
                    )}
                  >
                    <span className={cn(
                      "text-sm font-bold tracking-tight",
                      !slot.available && 'line-through opacity-50'
                    )}>
                      {formatTime(slot.time)}
                    </span>
                    {slot.endTime && (
                      <span className="block text-[10px] opacity-40 mt-1 font-medium">
                        – {formatTime(slot.endTime)}
                      </span>
                    )}
                  </button>
                ))}
              </div>
            )}

            {/* Selected slot confirmation - Premium Floating style */}
            {selectedSlot && (
              <div className="p-4 rounded-2xl bg-primary/10 border border-primary/20 shadow-lg shadow-primary/10 animate-in fade-in slide-in-from-bottom-2 duration-300">
                <div className="flex items-center justify-between gap-4">
                  <div className="flex items-center gap-3 min-w-0">
                    <div className="flex items-center justify-center w-10 h-10 rounded-xl bg-primary text-primary-foreground shadow-md">
                      <Check className="h-6 w-6" />
                    </div>
                    <div className="min-w-0">
                      <p className="text-[10px] font-bold text-primary uppercase tracking-wider">{t('booking.selectedTime', 'Выбрано время')}</p>
                      <p className="text-sm font-bold truncate">
                        {formatTime(selectedSlot.time)}
