              <Button type="submit" disabled={submitting} className="flex-[2] h-12 rounded-xl font-bold shadow-lg shadow-primary/30 hover:scale-[1.02] transition-transform">
                {submitting ? (
                  <Loader2 className="h-5 w-5 animate-spin mr-2" />
                ) : block.requirePrepayment ? (
                  <MessageCircle className="h-5 w-5 mr-2" />
                ) : (
                  <Check className="h-5 w-5 mr-2" />
                )}
                {block.requirePrepayment
                  ? (getI18nText(block.buttonText, i18n.language as SupportedLanguage) || t('booking.confirmAndPay', 'Записаться и оплатить'))
                  : (getI18nText(block.buttonText, i18n.language as SupportedLanguage) || t('booking.confirm', 'Записаться'))
                }
              </Button>
            </div>

            {block.requirePrepayment && block.prepaymentAmount && (
              <p className="text-[10px] font-bold text-muted-foreground/60 text-center uppercase tracking-widest px-4">
                {t('booking.prepaymentNote', 'После записи вы будете перенаправлены в WhatsApp для оплаты')}
                {' '}({block.prepaymentAmount} {getCurrencySymbol(block.prepaymentCurrency || 'KZT')})
              </p>
            )}
          </form>
        </DialogContent>
      </Dialog>
    </div>
  );
});

import { memo } from 'react';
import { useTranslation } from 'react-i18next';
import { getI18nText, type SupportedLanguage } from '@/lib/i18n-helpers';
import { createBlockClickHandler, getHoverClass, getBackgroundStyle } from '@/lib/blocks/block-utils';
import { getBlockStyles, hasCustomBlockStyle } from '@/lib/blocks/block-styling';
import type { ButtonBlock as ButtonBlockType } from '@/types/page';
import { cn } from '@/lib/utils/utils';

interface ButtonBlockProps {
  block: ButtonBlockType;
  onClick?: () => void;
}

export const ButtonBlock = memo(function ButtonBlockComponent({ block, onClick }: ButtonBlockProps) {
  const { i18n } = useTranslation();
  const handleClick = createBlockClickHandler(block.url, onClick);
  const title = getI18nText(block.title, i18n.language as SupportedLanguage);

  const alignmentClass = block.alignment === 'left' ? 'justify-start' 
    : block.alignment === 'right' ? 'justify-end' 
    : 'justify-center';

  // Legacy background system
  const hasLegacyBackground = block.background && block.background.value;
  const isImageBackground = block.background?.type === 'image';
  const legacyButtonStyle = hasLegacyBackground ? getBackgroundStyle(block.background) : {};

  // New block styling system
  const { style: blockStyleObj, textEffectClass } = getBlockStyles(block.blockStyle);
  const hasBlockStyle = hasCustomBlockStyle(block.blockStyle);

  // Combine styles - new blockStyle takes precedence
  const combinedStyle = { ...legacyButtonStyle, ...blockStyleObj };
  const hasAnyCustomStyle = hasLegacyBackground || hasBlockStyle;

  const widthClass = block.width === 'full' ? 'w-full' 
    : block.width === 'small' ? 'w-auto min-w-[120px]' 
    : 'w-full sm:w-auto sm:min-w-[280px] sm:max-w-md';

  return (
    <div className={cn("flex w-full", alignmentClass)}>
      <button
        onClick={handleClick}
        className={cn(
          widthClass,
          "relative overflow-hidden rounded-2xl px-6 sm:px-8 py-4 text-sm sm:text-base font-semibold",
          "shadow-glass-lg backdrop-blur-xl transition-all duration-300",
          "hover:shadow-glass-xl hover:scale-[1.02] active:scale-[0.98]",
          "break-words hyphens-auto",
          getHoverClass(block.hoverEffect),
          hasLegacyBackground 
            ? 'text-white drop-shadow-md' 
            : hasBlockStyle 
              ? '' 
              : 'bg-primary text-primary-foreground border border-primary/20'
        )}
        style={combinedStyle}
      >
        {/* Overlay for image backgrounds to ensure text readability */}
        {isImageBackground && (
          <div className="absolute inset-0 bg-black/30 pointer-events-none" />
        )}
        <span className={cn("relative z-10 line-clamp-2", textEffectClass)}>{title}</span>
        {/* Glass reflection overlay */}
        {!hasBlockStyle && (
          <div className="absolute inset-0 bg-gradient-to-b from-white/20 to-transparent pointer-events-none z-20" />
        )}
      </button>
    </div>
  );
});

import { memo } from 'react';
import { useTranslation } from 'react-i18next';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import {
  Carousel,
  CarouselContent,
  CarouselItem,
  CarouselNext,
  CarouselPrevious,
} from '@/components/ui/carousel';
import Autoplay from 'embla-carousel-autoplay';
import type { CarouselBlock as CarouselBlockType } from '@/types/page';
import { getI18nText, type SupportedLanguage } from '@/lib/i18n-helpers';

interface CarouselBlockProps {
  block: CarouselBlockType;
  onClick?: () => void;
}

export const CarouselBlock = memo(function CarouselBlockComponent({ block, onClick }: CarouselBlockProps) {
  const { i18n, t } = useTranslation();
  const title = getI18nText(block.title, i18n.language as SupportedLanguage);

  const autoplayPlugin = block.autoPlay
    ? Autoplay({ delay: block.interval || 3000, stopOnInteraction: true })
    : undefined;

  const handleImageClick = (link?: string) => {
    if (link) {
      onClick?.();
      // Delay to ensure tracking request is sent before navigation
      setTimeout(() => {
        window.open(link, '_blank', 'noopener,noreferrer');
      }, 15);
    }
  };

  if (!block.images || block.images.length === 0) {
    return (
      <Card className="bg-card border-border shadow-sm">
        <CardContent className="p-6">
          <p className="text-sm text-muted-foreground text-center">
            {t('blocks.carousel.empty', 'No images added to carousel')}
          </p>
        </CardContent>
      </Card>
    );
  }

  return (
    <div className="w-full overflow-hidden rounded-2xl glass-card backdrop-blur-md border-white/10 shadow-glass">
      {title && (
        <div className="p-4 sm:p-5 pb-0">
          <h3 className="font-bold text-base sm:text-lg text-gradient truncate">{title}</h3>
        </div>
      )}
      <Carousel
        opts={{
          align: 'start',
          loop: true,
        }}
        plugins={autoplayPlugin ? [autoplayPlugin] : undefined}
        className="w-full"
      >
        <CarouselContent className="-ml-0">
          {block.images.map((image, index) => {
            const alt = getI18nText(image.alt, i18n.language as SupportedLanguage) || `Slide ${index + 1}`;
            return (
              <CarouselItem key={index} className="pl-0">
                <div
                  className="aspect-[16/9] overflow-hidden bg-black/20 cursor-pointer"
                  onClick={() => handleImageClick(image.link)}
                >
                  <img
                    src={image.url}
                    alt={alt}
                    className="w-full h-full object-cover hover:scale-105 transition-transform duration-500"
                    loading="lazy"
                  />
                </div>
              </CarouselItem>
            );
          })}
        </CarouselContent>
        {block.images.length > 1 && (
          <>
            <CarouselPrevious className="left-4 h-10 w-10 glass-button shadow-glass border-white/10" />
            <CarouselNext className="right-4 h-10 w-10 glass-button shadow-glass border-white/10" />
          </>
        )}
      </Carousel>
      {/* Dots indicator for mobile */}
      {block.images.length > 1 && (
        <div className="flex justify-center gap-2 py-3">
          {block.images.map((_, idx) => (
            <div
              key={idx}
              className="w-2 h-2 rounded-full bg-primary/20 transition-all duration-300"
            />
          ))}
        </div>
      )}
    </div>
  );
});

import React, { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import type { CountdownBlock as CountdownBlockType } from '@/types/page';
import { Card, CardContent } from '@/components/ui/card';
import { getI18nText } from '@/lib/i18n-helpers';
import { cn } from '@/lib/utils/utils';

interface CountdownBlockProps {
  block: CountdownBlockType;
}

interface TimeLeft {
  days: number;
  hours: number;
  minutes: number;
  seconds: number;
}

export const CountdownBlock = React.memo(function CountdownBlock({ block }: CountdownBlockProps) {
  const { t, i18n } = useTranslation();
  const currentLang = i18n.language as 'ru' | 'en' | 'kk';
  const [timeLeft, setTimeLeft] = useState<TimeLeft | null>(null);
  const [isExpired, setIsExpired] = useState(false);

  const title = block.title ? getI18nText(block.title, currentLang) : '';
  const expiredText = block.expiredText 
    ? getI18nText(block.expiredText, currentLang) 
    : t('blocks.countdown.expired', 'Время вышло!');

  const showDays = block.showDays !== false;
  const showHours = block.showHours !== false;
  const showMinutes = block.showMinutes !== false;
  const showSeconds = block.showSeconds !== false;

  useEffect(() => {
    const calculateTimeLeft = () => {
      const targetDate = new Date(block.targetDate).getTime();
      const now = new Date().getTime();
      const difference = targetDate - now;

      if (difference <= 0) {
        setIsExpired(true);
        setTimeLeft(null);
        return;
      }

      setIsExpired(false);
      setTimeLeft({
        days: Math.floor(difference / (1000 * 60 * 60 * 24)),
        hours: Math.floor((difference % (1000 * 60 * 60 * 24)) / (1000 * 60 * 60)),
        minutes: Math.floor((difference % (1000 * 60 * 60)) / (1000 * 60)),
        seconds: Math.floor((difference % (1000 * 60)) / 1000),
      });
    };

    calculateTimeLeft();
    const timer = setInterval(calculateTimeLeft, 1000);

    return () => clearInterval(timer);
  }, [block.targetDate]);

  if (!block.targetDate) {
    return (
      <Card className="w-full bg-card border-border shadow-sm rounded-xl p-4 sm:p-5">
        <CardContent className="p-0 text-center text-muted-foreground text-sm">
          {t('blocks.countdown.noDate', 'Укажите дату')}
        </CardContent>
      </Card>
    );
  }

  const TimeUnit = ({ value, label }: { value: number; label: string }) => (
    <div className="flex flex-col items-center">
      <div className="bg-card border border-border shadow-sm rounded-lg p-2 sm:p-3 min-w-[48px] sm:min-w-[60px]">
        <span className="text-xl sm:text-2xl md:text-3xl font-bold text-primary">
          {value.toString().padStart(2, '0')}
        </span>
      </div>
      <span className="text-[10px] sm:text-xs md:text-sm text-muted-foreground mt-1">{label}</span>
    </div>
  );

  return (
    <div className="w-full space-y-2 sm:space-y-3">
      {title && (
        <h3 className="text-lg sm:text-xl font-semibold text-center truncate">{title}</h3>
      )}
      
      {isExpired ? (
        <div className="text-center py-4 sm:py-6">
          <p className="text-base sm:text-lg font-medium text-primary">{expiredText}</p>
        </div>
      ) : timeLeft ? (
        <div className="flex justify-center gap-1.5 sm:gap-2 md:gap-4">
          {showDays && (
            <TimeUnit 
              value={timeLeft.days} 
              label={t('blocks.countdown.days', 'дней')} 
            />
          )}
          {showHours && (
            <TimeUnit 
              value={timeLeft.hours} 
              label={t('blocks.countdown.hours', 'часов')} 
            />
          )}
          {showMinutes && (
            <TimeUnit 
              value={timeLeft.minutes} 
              label={t('blocks.countdown.minutes', 'минут')} 
            />
          )}
          {showSeconds && (
            <TimeUnit 
              value={timeLeft.seconds} 
              label={t('blocks.countdown.seconds', 'секунд')} 
            />
          )}
        </div>
      ) : null}
    </div>
  );
});

import { memo, useState } from 'react';
import { Crown, Send } from 'lucide-react';
import { useTranslation } from 'react-i18next';
import type { FormBlock as FormBlockType } from '@/types/page';
import { Card } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import { toast } from 'sonner';
import { getI18nText, type SupportedLanguage } from '@/lib/i18n-helpers';
import { supabase } from '@/platform/supabase/client';
import { fintechService } from '@/services/fintech';
import { TurnstileWidget } from '@/components/legal/TurnstileWidget';

import { trackLead } from '@/lib/analytics';

interface FormBlockProps {
  block: FormBlockType;
  pageOwnerId?: string;
  pageId?: string;
}

export const FormBlock = memo(function FormBlock({ block, pageOwnerId, pageId }: FormBlockProps) {
  const { t, i18n } = useTranslation();
  const [formData, setFormData] = useState<Record<string, string>>({});
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [turnstileToken, setTurnstileToken] = useState<string | null>(null);

  const title = getI18nText(block.title, i18n.language as SupportedLanguage);
  const buttonText = getI18nText(block.buttonText, i18n.language as SupportedLanguage) || t('actions.send', 'Send');

  const getFieldKey = (field: FormBlockType['fields'][0], index: number): string => {
    if (typeof field.name === 'object' && field.name) {
      return getI18nText(field.name, i18n.language as SupportedLanguage) || `Field ${index + 1}`;
    }
    return (field.name as string) || `Field ${index + 1}`;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    const missingFields = block.fields
      ?.filter((field, index) => field.required && !formData[getFieldKey(field, index)])
      .map((field, index) => getFieldKey(field, index));

    if (missingFields && missingFields.length > 0) {
      toast.error(t('form.fillRequired', 'Please fill required fields') + `: ${missingFields.join(', ')}`);
      return;
    }

    setIsSubmitting(true);

    try {
      // Create lead via edge function (bypasses RLS for anonymous visitors)
      if (pageOwnerId) {
        const name = formData['name'] || formData['Name'] || formData['Имя'] || formData['имя'] || 'Unknown';
        const email = formData['email'] || formData['Email'] || formData['Почта'] || formData['почта'] || null;
        const phone = formData['phone'] || formData['Phone'] || formData['Телефон'] || formData['телефон'] || null;

        const { error } = await supabase.functions.invoke('submit-lead', {
          body: {
            pageId,
            blockId: block.id,
            formData: formData,
          },
        });

        if (error) {
          console.error('Error creating lead:', error);
        } else {
          // Track lead event on success
          trackLead();

          // Record in Fintech Ledger if it's a lead form with potential value
          try {
            await fintechService.recordPendingIncome({
              userId: pageOwnerId,
              amount: 0, // Forms usually don't have fixed price in Phase 1
              description: `Лид из формы: ${name}`,
              relatedEntityId: block.id,
              relatedEntityType: 'lead',
              metadata: {
                form_data: formData
              }
            });
          } catch (fintechErr) {
            console.error('Failed to record fintech transaction for lead', fintechErr);
          }
        }
      }

      toast.success(t('form.success', 'Form submitted successfully!'));
      setFormData({});
    } catch (error) {
      console.error('Error submitting form:', error);
      toast.error(t('form.error', 'Error submitting form'));
    } finally {
      setIsSubmitting(false);
    }
  };

  const renderField = (field: FormBlockType['fields'][0], index: number) => {
    const fieldName = typeof field.name === 'object' && field.name
      ? getI18nText(field.name, i18n.language as SupportedLanguage) || `Field ${index + 1}`
      : (field.name as string) || `Field ${index + 1}`;

    const fieldPlaceholder = typeof field.placeholder === 'object' && field.placeholder
      ? getI18nText(field.placeholder, i18n.language as SupportedLanguage)
      : (field.placeholder as string);

    const commonProps = {
      id: `field-${index}`,
      name: fieldName,
      required: field.required,
      value: formData[fieldName] || '',
      onChange: (e: any) => setFormData({ ...formData, [fieldName]: e.target.value }),
    };

    switch (field.type) {
      case 'textarea':
        return <Textarea {...commonProps} placeholder={fieldPlaceholder || t('form.enterPlaceholder', 'Enter') + ` ${fieldName.toLowerCase()}`} />;
      case 'email':
        return <Input {...commonProps} type="email" placeholder={fieldPlaceholder || 'example@email.com'} />;
      case 'phone':
        return <Input {...commonProps} type="tel" placeholder={fieldPlaceholder || '+7 (___) ___-__-__'} />;
      default:
        return <Input {...commonProps} type="text" placeholder={fieldPlaceholder || t('form.enterPlaceholder', 'Enter') + ` ${fieldName.toLowerCase()}`} />;
    }
  };

  const getFieldDisplayName = (field: FormBlockType['fields'][0], index: number) => {
    if (typeof field.name === 'object' && field.name) {
      return getI18nText(field.name, i18n.language as SupportedLanguage) || `Field ${index + 1}`;
    }
    return (field.name as string) || `Field ${index + 1}`;
  };

  return (
    <Card className="p-5 sm:p-6 bg-card border-border shadow-sm rounded-xl">
      <div className="flex items-center gap-2 mb-3 sm:mb-4">
        <h3 className="font-semibold text-base sm:text-lg truncate">{title}</h3>
        <Crown className="h-4 w-4 text-primary flex-shrink-0" />
      </div>
      <form onSubmit={handleSubmit} className="space-y-3 sm:space-y-4">
        {block.fields?.map((field, index) => (
          <div key={index}>
            <Label htmlFor={`field-${index}`} className="text-sm">
              {getFieldDisplayName(field, index)} {field.required && <span className="text-destructive">*</span>}
            </Label>
            {renderField(field, index)}
          </div>
        ))}
        <Button
          type="submit"
          className="w-full h-12 sm:h-10 rounded-xl text-base sm:text-sm font-semibold"
          disabled={isSubmitting}
        >
          <Send className="h-4 w-4 mr-2" />
          {isSubmitting ? t('form.submitting', 'Submitting...') : buttonText}
        </Button>
        <TurnstileWidget onToken={setTurnstileToken} className="mt-2" />
      </form>
    </Card>
  );
});

'use client';

/**
 * FreePremiumBlockGate - Visual separation for Free vs Premium blocks
 * Shows lock overlay and upgrade prompts for premium-only blocks
 */
import { memo } from 'react';
import { useTranslation } from 'react-i18next';
import { useRouter } from 'next/navigation';
import { Crown, Lock, Sparkles, ArrowRight } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { cn } from '@/lib/utils/utils';
import {
  FREE_BLOCK_TYPES,
  PREMIUM_BLOCK_TYPES,
  isFreeBlock,
  isPremiumBlock,
  type FreeBlockType,
  type PremiumBlockType
} from '@/lib/blocks/block-registry';

// Re-export from registry for backward compatibility
export { FREE_BLOCK_TYPES, PREMIUM_BLOCK_TYPES, isFreeBlock, isPremiumBlock };
export type { FreeBlockType, PremiumBlockType };

// Backward compatibility alias
export const isFreeSlock = isFreeBlock;

interface PremiumBlockOverlayProps {
  blockType: string;
  className?: string;
}

export const PremiumBlockOverlay = memo(function PremiumBlockOverlay({
  blockType,
  className,
}: PremiumBlockOverlayProps) {
  const { t } = useTranslation();
  const router = useRouter();

  return (
    <div className={cn(
      "absolute inset-0 z-10 flex flex-col items-center justify-center p-6 text-center",
      "bg-gradient-to-t from-background/95 via-background/80 to-background/60",
      "backdrop-blur-sm rounded-2xl",
      className
    )}>
      <div className="h-16 w-16 rounded-2xl bg-gradient-to-br from-amber-400 to-orange-500 flex items-center justify-center mb-4 shadow-xl shadow-amber-500/30">
        <Crown className="h-8 w-8 text-white" />
      </div>
      <h3 className="text-lg font-bold mb-2">
        {t('premium.blockLocked', 'Блок Premium')}
      </h3>
      <p className="text-sm text-muted-foreground mb-4 max-w-xs">
        {t('premium.unlockWith', 'Разблокируйте этот блок с подпиской Pro')}
      </p>
      <Button
        size="sm"
        className="h-10 px-5 rounded-xl font-bold shadow-lg shadow-primary/25"
        onClick={() => router.push('/pricing')}
      >
        <Sparkles className="h-4 w-4 mr-2" />
        {t('premium.upgrade', 'Перейти на Pro')}
        <ArrowRight className="h-4 w-4 ml-2" />
      </Button>
    </div>
  );
});

interface TierBadgeProps {
  tier: 'free' | 'pro';
  className?: string;
  size?: 'sm' | 'md';
}

export const BlockTierBadge = memo(function BlockTierBadge({
  tier,
  className,
  size = 'sm',
}: TierBadgeProps) {
  const { t } = useTranslation();

  if (tier === 'free') {
    return (
      <Badge
        variant="secondary"
        className={cn(
          "font-bold",
          size === 'sm' ? "text-xs h-5 px-2" : "text-sm h-6 px-3",
          "bg-emerald-500/15 text-emerald-600 border-emerald-500/30",
          className
        )}
      >
        {t('tier.free', 'Free')}
      </Badge>
    );
  }

  return (
    <Badge
      className={cn(
        "font-bold",
        size === 'sm' ? "text-xs h-5 px-2" : "text-sm h-6 px-3",
        "bg-gradient-to-r from-amber-500 to-orange-500 text-white border-0",
        className
      )}
    >
      <Crown className={cn("mr-1", size === 'sm' ? "h-3 w-3" : "h-3.5 w-3.5")} />
      PRO
    </Badge>
  );
});

interface BlockCategoryHeaderProps {
  title: string;
  tier: 'free' | 'pro';
  blockCount?: number;
}

export const BlockCategoryHeader = memo(function BlockCategoryHeader({
  title,
  tier,
  blockCount,
}: BlockCategoryHeaderProps) {
  const { t } = useTranslation();
  return (
    <div className="flex items-center justify-between px-1 mb-3">
      <div className="flex items-center gap-2">
        <span className="text-sm font-bold text-foreground">{title}</span>
        <BlockTierBadge tier={tier} />
      </div>
      {blockCount !== undefined && (
        <span className="text-xs text-muted-foreground">{blockCount} {t('tier.blocksCount', 'блоков')}</span>
      )}
    </div>
  );
});

interface LockedBlockCardProps {
  blockType: string;
  label: string;
  icon: React.ReactNode;
  color: string;
  onClick?: () => void;
}

export const LockedBlockCard = memo(function LockedBlockCard({
  blockType,
  label,
  icon,
  color,
  onClick,
}: LockedBlockCardProps) {
  const { t } = useTranslation();
  const router = useRouter();

  return (
    <button
      onClick={onClick || (() => router.push('/pricing'))}
      className="relative flex flex-col items-center gap-3 p-4 rounded-3xl transition-all opacity-60 hover:opacity-80"
    >
      {/* Colorful icon with lock overlay */}
      <div className="relative">
        <div className={cn(
          "w-16 h-16 rounded-2xl flex items-center justify-center text-white shadow-lg",
          color
        )}>
          {icon}
        </div>
        <div className="absolute -top-1 -right-1 h-6 w-6 rounded-full bg-background border-2 border-border flex items-center justify-center">
          <Lock className="h-3 w-3 text-muted-foreground" />
        </div>
      </div>

      {/* Label */}
      <span className="text-sm font-bold text-center leading-tight text-muted-foreground">
        {label}
      </span>

      {/* PRO badge */}
      <div className="absolute top-2 right-2">
        <Crown className="h-4 w-4 text-amber-500" />
      </div>
    </button>
  );
});

'use client';

import { memo, useState, useEffect, useRef, useCallback, lazy, Suspense } from 'react';
import { useTranslation } from 'react-i18next';
import { useRouter } from 'next/navigation';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Badge } from '@/components/ui/badge';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { CheckCircle2, Check, X, Camera, Loader2, Settings2, Pencil, Palette } from 'lucide-react';
import { Button } from '@/components/ui/button';
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from '@/components/ui/popover';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { getI18nText, isI18nText, ensureI18nText, type SupportedLanguage, type I18nText } from '@/lib/i18n-helpers';
import { supabase } from '@/platform/supabase/client';
import { useAuth } from '@/hooks/user/useAuth';
import { useFreemiumLimits } from '@/hooks/user/useFreemiumLimits';
import { compressImage } from '@/lib/utils/image-compression';
import { toast } from 'sonner';
import { ImageCropper } from '@/components/form-fields/ImageCropper';
import { RichTextEditor } from '@/components/form-fields/RichTextEditor';
import { FrameSelector } from '@/components/profile/FrameSelector';
import { NameAnimationSelector } from '@/components/profile/NameAnimationSelector';
import { NAME_ANIMATION_CSS, getNameAnimationClass } from '@/lib/profile-frame-system';
import type { ProfileBlock as ProfileBlockType, NameAnimationType } from '@/types/page';
import { cn } from '@/lib/utils/utils';

// Lazy load full editor
const ProfileFullEditor = lazy(() => import('./ProfileFullEditor'));

interface InlineProfileEditorProps {
  block: ProfileBlockType;
  onUpdate: (updates: Partial<ProfileBlockType>) => void;
}

export const InlineProfileEditor = memo(function InlineProfileEditor({
  block,
  onUpdate
}: InlineProfileEditorProps) {
  const { t, i18n } = useTranslation();
  const { user } = useAuth();
  const router = useRouter();
  const { canUsePremiumFrames } = useFreemiumLimits();
  const currentLang = i18n.language as SupportedLanguage;

  const name = getI18nText(block.name, currentLang);
  const bio = getI18nText(block.bio, currentLang);

  const [isEditingName, setIsEditingName] = useState(false);
  const [isEditingBio, setIsEditingBio] = useState(false);
  const [editedName, setEditedName] = useState(name);
  const [editedBio, setEditedBio] = useState(bio);
  const [isUploadingAvatar, setIsUploadingAvatar] = useState(false);
  const [isUploadingCover, setIsUploadingCover] = useState(false);
  const [isFullEditorOpen, setIsFullEditorOpen] = useState(false);

  // Image cropper state
  const [cropperOpen, setCropperOpen] = useState(false);
  const [cropperImage, setCropperImage] = useState('');
  const [cropperType, setCropperType] = useState<'avatar' | 'cover'>('avatar');

  const nameInputRef = useRef<HTMLInputElement>(null);
  const bioTextareaRef = useRef<HTMLTextAreaElement>(null);
  const avatarInputRef = useRef<HTMLInputElement>(null);
  const coverInputRef = useRef<HTMLInputElement>(null);

  // Sync state when block changes
  useEffect(() => {
    setEditedName(name);
  }, [name]);

  useEffect(() => {
    setEditedBio(bio);
  }, [bio]);

  // Focus management with animation
  useEffect(() => {
    if (isEditingName && nameInputRef.current) {
      requestAnimationFrame(() => {
        nameInputRef.current?.focus();
        nameInputRef.current?.select();
      });
    }
  }, [isEditingName]);

  useEffect(() => {
    if (isEditingBio && bioTextareaRef.current) {
      requestAnimationFrame(() => {
        bioTextareaRef.current?.focus();
        // Move cursor to end
        const len = bioTextareaRef.current?.value.length || 0;
        bioTextareaRef.current?.setSelectionRange(len, len);
      });
    }
  }, [isEditingBio]);

  // Save handlers that preserve multilingual structure
  const handleSaveName = useCallback(() => {
    const trimmedName = editedName.trim();
    if (trimmedName && trimmedName !== name) {
      // Preserve multilingual structure, update only current language
      const existingName = ensureI18nText(block.name, currentLang);
      const updatedName: I18nText = { ...existingName, [currentLang]: trimmedName };
      onUpdate({ name: updatedName });
      toast.success(t('profile.nameSaved', 'Имя сохранено'));
    }
    setIsEditingName(false);
  }, [editedName, name, block.name, currentLang, onUpdate, t]);

  const handleSaveBio = useCallback(() => {
    const trimmedBio = editedBio.trim();
    if (trimmedBio !== bio) {
      // Preserve multilingual structure, update only current language
      const existingBio = ensureI18nText(block.bio, currentLang);
      const updatedBio: I18nText = { ...existingBio, [currentLang]: trimmedBio };
      onUpdate({ bio: updatedBio });
      toast.success(t('profile.bioSaved', 'Описание сохранено'));
    }
    setIsEditingBio(false);
  }, [editedBio, bio, block.bio, currentLang, onUpdate, t]);

  const handleCancelName = useCallback(() => {
    setEditedName(name);
    setIsEditingName(false);
  }, [name]);

  const handleCancelBio = useCallback(() => {
    setEditedBio(bio);
    setIsEditingBio(false);
  }, [bio]);

  const handleNameKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleSaveName();
    } else if (e.key === 'Escape') {
      handleCancelName();
    }
  };

  const handleBioKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Escape') {
      handleCancelBio();
    }
  };

  const handleAvatarClick = () => {
    avatarInputRef.current?.click();
  };

  const handleAvatarUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    if (!user) {
      toast.error(t('auth.required', 'Please sign in to upload'));
      return;
    }

    if (file.size > 10 * 1024 * 1024) {
      toast.error(t('upload.fileTooLarge', 'File size must be less than 10MB'));
      return;
    }

    // For GIFs, upload directly without cropping
    if (file.type === 'image/gif') {
      await uploadFile(file, 'avatar');
      return;
    }

    // Open cropper for other images
    const reader = new FileReader();
    reader.onload = (e) => {
      setCropperImage(e.target?.result as string);
      setCropperType('avatar');
      setCropperOpen(true);
    };
    reader.readAsDataURL(file);

    if (avatarInputRef.current) {
      avatarInputRef.current.value = '';
    }
  };

  const handleCoverUploadFile = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    if (!user) {
      toast.error(t('auth.required', 'Please sign in to upload'));
      return;
    }

    if (file.size > 10 * 1024 * 1024) {
      toast.error(t('upload.fileTooLarge', 'File size must be less than 10MB'));
      return;
    }

    // For GIFs, upload directly without cropping
    if (file.type === 'image/gif') {
      await uploadFile(file, 'cover');
      return;
    }

    // Open cropper for other images
    const reader = new FileReader();
    reader.onload = (e) => {
      setCropperImage(e.target?.result as string);
      setCropperType('cover');
      setCropperOpen(true);
    };
    reader.readAsDataURL(file);

    if (coverInputRef.current) {
      coverInputRef.current.value = '';
    }
  };

  const uploadFile = async (file: File | Blob, type: 'avatar' | 'cover') => {
    if (!user) return;

    const setUploading = type === 'avatar' ? setIsUploadingAvatar : setIsUploadingCover;
    setUploading(true);

    try {
      let processedFile = file;
      if (file instanceof File && file.type.startsWith('image/') && file.type !== 'image/gif') {
        processedFile = await compressImage(file);
      }

      const fileExt = file instanceof File ? file.name.split('.').pop() : 'jpg';
      const fileName = `${type}-${Date.now()}.${fileExt}`;
      const filePath = `${user.id}/${fileName}`;

      const { error: uploadError } = await supabase.storage
        .from('user-media')
        .upload(filePath, processedFile);

      if (uploadError) throw uploadError;

      const { data: { publicUrl } } = supabase.storage
        .from('user-media')
        .getPublicUrl(filePath);

      if (type === 'avatar') {
        onUpdate({ avatar: publicUrl });
      } else {
        onUpdate({ coverImage: publicUrl });
      }
      toast.success(t('upload.success', 'Image updated'));
    } catch (error) {
      console.error(`${type} upload error:`, error);
      toast.error(t('upload.error', 'Failed to upload image'));
    } finally {
      setUploading(false);
    }
  };

  const handleCropperSave = async (croppedDataUrl: string) => {
    setCropperOpen(false);

    // Convert data URL to blob without fetch (avoids CSP violations)
    const { dataUrlToBlob } = await import('@/lib/utils/data-url-to-blob');
    const blob = dataUrlToBlob(croppedDataUrl);

    await uploadFile(blob, cropperType);
  };

  const handleCoverClick = () => {
    coverInputRef.current?.click();
  };

  const handleCoverUpload = handleCoverUploadFile;

  const initials = name
    .split(' ')
    .map(n => n[0])
    .join('')
    .toUpperCase()
    .slice(0, 2);

  const getAvatarSize = () => {
    const size = block.avatarSize || 'large';
    switch (size) {
      case 'small': return 'h-20 w-20';
      case 'medium': return 'h-28 w-28';
      case 'large': return 'h-36 w-36';
      case 'xlarge': return 'h-44 w-44';
      default: return 'h-36 w-36';
    }
  };

  const getShadowClass = () => {
    const shadow = block.shadowStyle || 'soft';
    switch (shadow) {
      case 'none': return '';
      case 'soft': return 'shadow-md';
      case 'medium': return 'shadow-xl';
      case 'strong': return 'shadow-2xl';
      case 'glow': return 'shadow-[0_0_30px_hsl(var(--primary)/0.4)]';
      default: return 'shadow-md';
    }
  };

  const getCoverGradient = () => {
    const gradient = block.coverGradient || 'none';
    switch (gradient) {
      case 'none': return '';
      case 'dark': return 'bg-gradient-to-b from-black/50 to-black/20';
      case 'light': return 'bg-gradient-to-b from-white/50 to-white/20';
      case 'primary': return 'bg-gradient-to-b from-primary/60 to-primary/20';
      case 'sunset': return 'bg-gradient-to-br from-orange-500/50 via-pink-500/50 to-purple-600/50';
      case 'ocean': return 'bg-gradient-to-br from-blue-500/50 via-cyan-500/50 to-teal-500/50';
      case 'purple': return 'bg-gradient-to-br from-purple-600/50 via-pink-500/50 to-blue-500/50';
      default: return '';
    }
  };

  // Using the new frame utils
  const frameStyle = block.avatarFrame || 'default';
  const hasGradientFrame = ['gradient', 'gradient-sunset', 'gradient-ocean', 'gradient-purple', 'rainbow', 'rainbow-spin'].includes(frameStyle);

  const getPositionClass = () => {
    const position = block.avatarPosition || 'center';
    switch (position) {
      case 'left': return 'items-start';
      case 'right': return 'items-end';
      case 'center':
      default: return 'items-center';
    }
  };

  const getCoverHeight = () => {
    const height = block.coverHeight || 'medium';
    switch (height) {
      case 'small': return 'h-[140px]';
      case 'medium': return 'h-[240px]';
      case 'large': return 'h-[360px]';
      default: return 'h-[240px]';
    }
  };

  return (
    <div className={`relative flex flex-col ${getPositionClass()}`}>
      {/* Full Editor Button - Floating */}
      <Button
        size="icon"
        variant="secondary"
        onClick={() => setIsFullEditorOpen(true)}
        className="absolute top-2 left-2 z-20 h-10 w-10 rounded-xl shadow-lg bg-background/90 backdrop-blur-sm hover:bg-background"
        title={t('profileEditor.openEditor', 'Открыть редактор')}
      >
        <Pencil className="h-4 w-4" />
      </Button>

      {/* Hidden file input for cover upload */}
      <input
        ref={coverInputRef}
        type="file"
        accept="image/*"
        onChange={handleCoverUpload}
        className="hidden"
      />

      {/* Cover image area - clickable */}
      <div
        className={`relative w-full ${getCoverHeight()} overflow-hidden group/cover ${!block.coverImage ? 'bg-muted border-2 border-dashed border-border cursor-pointer' : ''}`}
        onClick={!block.coverImage ? handleCoverClick : undefined}
        title={!block.coverImage ? t('profile.clickToChangeCover', 'Click to add cover') : undefined}
      >
        {block.coverImage ? (
          <>
            <img
              src={block.coverImage}
              alt="Cover"
              className="w-full h-full object-cover cursor-pointer"
              onClick={handleCoverClick}
            />
            {block.coverGradient !== 'none' && (
              <div className={`absolute inset-0 ${getCoverGradient()} pointer-events-none`} />
            )}

            {/* Cover controls */}
            <div className="absolute top-2 right-2 flex gap-1 opacity-0 group-hover/cover:opacity-100 transition-opacity z-10">
              {/* Settings popover */}
              <Popover>
                <PopoverTrigger asChild>
                  <Button
                    size="icon"
                    variant="secondary"
                    className="h-8 w-8"
                    onClick={(e) => e.stopPropagation()}
                    title={t('profile.coverSettings', 'Cover settings')}
                  >
                    <Settings2 className="h-4 w-4" />
                  </Button>
                </PopoverTrigger>
                <PopoverContent className="w-56" align="end" onClick={(e) => e.stopPropagation()}>
                  <div className="space-y-4">
                    <div className="space-y-2">
                      <Label className="text-xs">{t('profile.coverHeight', 'Height')}</Label>
                      <Select
                        value={block.coverHeight || 'medium'}
                        onValueChange={(value: string) => onUpdate({ coverHeight: value as 'small' | 'medium' | 'large' })}
                      >
                        <SelectTrigger className="h-8">
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="small">{t('profile.small', 'Small')}</SelectItem>
                          <SelectItem value="medium">{t('profile.medium', 'Medium')}</SelectItem>
                          <SelectItem value="large">{t('profile.large', 'Large')}</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>

                    <div className="space-y-2">
                      <Label className="text-xs">{t('profile.coverGradient', 'Gradient overlay')}</Label>
                      <Select
                        value={block.coverGradient || 'none'}
                        onValueChange={(value: string) => onUpdate({ coverGradient: value as 'none' | 'dark' | 'light' | 'primary' | 'sunset' | 'ocean' | 'purple' })}
                      >
                        <SelectTrigger className="h-8">
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="none">{t('profile.none', 'None')}</SelectItem>
                          <SelectItem value="dark">{t('profile.dark', 'Dark')}</SelectItem>
                          <SelectItem value="light">{t('profile.light', 'Light')}</SelectItem>
                          <SelectItem value="primary">{t('profile.primary', 'Primary')}</SelectItem>
                          <SelectItem value="sunset">{t('profile.sunset', 'Sunset')}</SelectItem>
                          <SelectItem value="ocean">{t('profile.ocean', 'Ocean')}</SelectItem>
                          <SelectItem value="purple">{t('profile.purple', 'Purple')}</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>
                  </div>
                </PopoverContent>
              </Popover>

              {/* Delete button */}
              <Button
                size="icon"
                variant="destructive"
                className="h-8 w-8"
                onClick={(e) => {
                  e.stopPropagation();
                  onUpdate({ coverImage: '' });
                  toast.success(t('profile.coverRemoved', 'Cover removed'));
                }}
                title={t('profile.removeCover', 'Remove cover')}
              >
                <X className="h-4 w-4" />
              </Button>
            </div>
          </>
        ) : (
          <div className="flex items-center justify-center h-full">
            <div className="text-center text-muted-foreground">
              <Camera className="h-8 w-8 mx-auto mb-2" />
              <span className="text-sm">{t('profile.addCover', 'Add cover image')}</span>
            </div>
          </div>
        )}

        {/* Upload overlay */}
        <div className="absolute inset-0 flex items-center justify-center bg-black/50 opacity-0 group-hover/cover:opacity-100 transition-opacity pointer-events-none">
          {isUploadingCover ? (
            <Loader2 className="h-10 w-10 text-white animate-spin" />
          ) : (
            <div className="text-center text-white">
              <Camera className="h-10 w-10 mx-auto mb-2" />
              <span className="text-sm font-medium">{block.coverImage ? t('profile.changeCover', 'Change cover') : t('profile.addCover', 'Add cover')}</span>
            </div>
          )}
        </div>
      </div>

      <div className={`flex flex-col ${getPositionClass()} gap-5 p-8 ${block.coverImage ? '-mt-20' : ''}`}>
        {/* Hidden file input for avatar upload */}
        <input
          ref={avatarInputRef}
          type="file"
          accept="image/*"
          onChange={handleAvatarUpload}
          className="hidden"
        />

        {/* Avatar with settings */}
        <div className="relative group/avatar-container">
          {/* Clickable Avatar */}
          <div
            className={`${getShadowClass()} relative cursor-pointer group/avatar rounded-full`}
            onClick={handleAvatarClick}
            title={t('profile.clickToChangeAvatar', 'Click to change avatar')}
          >
            <Avatar className={`${getAvatarSize()} ring-4 ring-primary ring-offset-4 ring-offset-background`}>
              <AvatarImage src={block.avatar} alt={name} />
              <AvatarFallback className="bg-primary text-primary-foreground text-3xl font-black">
                {initials}
              </AvatarFallback>
            </Avatar>

            {/* Upload overlay */}
            <div className="absolute inset-0 flex items-center justify-center bg-black/50 rounded-full opacity-0 group-hover/avatar:opacity-100 transition-opacity">
              {isUploadingAvatar ? (
                <Loader2 className="h-8 w-8 text-white animate-spin" />
              ) : (
                <Camera className="h-8 w-8 text-white" />
              )}
            </div>
          </div>

          {/* Avatar settings button */}
          <Popover>
            <PopoverTrigger asChild>
              <Button
                size="icon"
                variant="secondary"
                className="absolute -bottom-1 -right-1 h-7 w-7 rounded-full opacity-0 group-hover/avatar-container:opacity-100 transition-opacity z-10 shadow-md"
                onClick={(e) => e.stopPropagation()}
                title={t('profile.avatarSettings', 'Avatar settings')}
              >
                <Palette className="h-3.5 w-3.5" />
              </Button>
            </PopoverTrigger>
            <PopoverContent className="w-80" align="center" onClick={(e) => e.stopPropagation()}>
              <Tabs defaultValue="frame" className="w-full">
                <TabsList className="grid grid-cols-3 w-full h-auto mb-3">
                  <TabsTrigger value="frame" className="text-xs py-2">
                    {t('profile.frame', 'Рамка')}
                  </TabsTrigger>
                  <TabsTrigger value="size" className="text-xs py-2">
                    {t('profile.size', 'Размер')}
                  </TabsTrigger>
                  <TabsTrigger value="animation" className="text-xs py-2">
                    {t('profile.nameAnim', 'Имя')}
                  </TabsTrigger>
                </TabsList>

                <TabsContent value="frame" className="mt-0">
                  <FrameSelector
                    value={block.avatarFrame || 'default'}
                    onChange={(value) => onUpdate({ avatarFrame: value })}
                    isPremium={canUsePremiumFrames()}
                    avatarUrl={block.avatar}
                    onUpgradeClick={() => router.push('/pricing')}
                  />
                </TabsContent>

                <TabsContent value="size" className="mt-0 space-y-4">
                  <div className="space-y-2">
                    <Label className="text-xs">{t('profile.avatarSize', 'Размер аватара')}</Label>
                    <Select
                      value={block.avatarSize || 'large'}
                      onValueChange={(value: string) => onUpdate({ avatarSize: value as 'small' | 'medium' | 'large' | 'xlarge' })}
                    >
                      <SelectTrigger className="h-9">
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="small">{t('profile.small', 'Маленький')}</SelectItem>
                        <SelectItem value="medium">{t('profile.medium', 'Средний')}</SelectItem>
                        <SelectItem value="large">{t('profile.large', 'Большой')}</SelectItem>
                        <SelectItem value="xlarge">{t('profile.xlarge', 'Очень большой')}</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>

                  <div className="space-y-2">
                    <Label className="text-xs">{t('profile.shadowStyle', 'Тень')}</Label>
                    <Select
                      value={block.shadowStyle || 'soft'}
                      onValueChange={(value: string) => onUpdate({ shadowStyle: value as 'none' | 'soft' | 'medium' | 'strong' | 'glow' })}
                    >
                      <SelectTrigger className="h-9">
                        <SelectValue />
                      </SelectTrigger>
                      <SelectContent>
                        <SelectItem value="none">{t('profile.none', 'Нет')}</SelectItem>
                        <SelectItem value="soft">{t('profile.soft', 'Мягкая')}</SelectItem>
                        <SelectItem value="medium">{t('profile.medium', 'Средняя')}</SelectItem>
                        <SelectItem value="strong">{t('profile.strong', 'Сильная')}</SelectItem>
                        <SelectItem value="glow">{t('profile.glow', 'Свечение')}</SelectItem>
                      </SelectContent>
                    </Select>
                  </div>
                </TabsContent>

                <TabsContent value="animation" className="mt-0">
                  <NameAnimationSelector
                    value={(block.nameAnimation as NameAnimationType) || 'none'}
                    onChange={(value) => onUpdate({ nameAnimation: value })}
                    isPremium={canUsePremiumFrames()}
                    previewName={name}
                    onUpgradeClick={() => router.push('/pricing')}
                  />
                </TabsContent>
              </Tabs>
            </PopoverContent>
          </Popover>
        </div>

        <div className="text-center space-y-3 w-full max-w-md">
          {/* CSS for name animations */}
          <style>{NAME_ANIMATION_CSS}</style>

          {/* Editable Name - Optimized with animations */}
          <div className="flex items-center justify-center gap-3">
            {isEditingName ? (
              <div className="flex items-center gap-2 animate-in fade-in zoom-in-95 duration-200">
                <Input
                  ref={nameInputRef}
                  value={editedName}
                  onChange={(e) => setEditedName(e.target.value)}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter') handleSaveName();
                    if (e.key === 'Escape') handleCancelName();
                  }}
                  onBlur={handleSaveName}
                  className="text-2xl sm:text-3xl font-black text-center h-14 w-full max-w-[280px] rounded-2xl border-2 border-primary/50 focus:border-primary transition-colors"
                  placeholder={t('profile.namePlaceholder', 'Ваше имя')}
                />
                <Button size="icon" variant="ghost" className="h-12 w-12 rounded-xl hover:bg-primary/10 active:scale-95 transition-all" onClick={handleSaveName}>
                  <Check className="h-5 w-5 text-primary" />
                </Button>
                <Button size="icon" variant="ghost" className="h-12 w-12 rounded-xl hover:bg-destructive/10 active:scale-95 transition-all" onClick={handleCancelName}>
                  <X className="h-5 w-5 text-muted-foreground" />
                </Button>
              </div>
            ) : (
              <h1
                className={cn(
                  "text-2xl sm:text-3xl font-black cursor-pointer transition-all duration-200",
                  "hover:text-primary border-b-2 border-transparent hover:border-primary/30",
                  "active:scale-[0.98] tracking-tight px-2 py-1 rounded-lg hover:bg-muted/50",
                  getNameAnimationClass((block.nameAnimation as NameAnimationType) || 'none')
                )}
                onClick={() => setIsEditingName(true)}
                title={t('profile.clickToEdit', 'Нажмите для редактирования')}
              >
                {name || t('profile.addName', 'Добавить имя')}
              </h1>
            )}
            {block.verified && !isEditingName && (
              <Badge variant="secondary" className="gap-1.5 text-sm px-3 py-1 rounded-xl font-bold animate-in fade-in duration-300">
                <CheckCircle2 className="h-4 w-4" />
                {t('profile.verified', 'Verified')}
              </Badge>
            )}
          </div>

          {/* Editable Bio - Optimized with animations */}
          {isEditingBio ? (
            <div className="space-y-3 w-full animate-in fade-in zoom-in-95 duration-200">
              <RichTextEditor
                value={editedBio}
                onChange={(val) => setEditedBio(val)}
                placeholder={t('profile.bioPlaceholder', 'Расскажите о себе...')}
                type="textarea"
                className="text-base rounded-2xl border-2 border-primary/50 focus:border-primary resize-none transition-colors"
              />
              <div className="flex items-center justify-center gap-3">
                <Button size="lg" onClick={handleSaveBio} className="rounded-2xl px-6 h-12 font-bold shadow-lg shadow-primary/20 active:scale-[0.98] transition-all">
                  <Check className="h-5 w-5 mr-2" />
                  {t('common.save', 'Сохранить')}
                </Button>
                <Button size="lg" variant="outline" onClick={handleCancelBio} className="rounded-2xl px-6 h-12 font-bold active:scale-[0.98] transition-all">
                  <X className="h-5 w-5 mr-2" />
                  {t('editor.cancel', 'Отмена')}
                </Button>
              </div>
            </div>
          ) : (
            <p
              className={cn(
                "text-base sm:text-lg text-muted-foreground cursor-pointer transition-all duration-200",
                "hover:text-foreground border-b-2 border-transparent hover:border-primary/30",
                "px-3 py-2 font-medium rounded-lg hover:bg-muted/50 active:scale-[0.98]"
              )}
              onClick={() => setIsEditingBio(true)}
              title={t('profile.clickToEdit', 'Нажмите для редактирования')}
            >
              {bio || t('profile.addBio', 'Добавить описание')}
            </p>
          )}
        </div>
      </div>

      {/* Image Cropper */}
      <ImageCropper
        imageUrl={cropperImage}
        open={cropperOpen}
        onClose={() => setCropperOpen(false)}
        onSave={handleCropperSave}
        aspectRatio={cropperType === 'avatar' ? 1 : 16 / 9}
        shape={cropperType === 'avatar' ? 'circle' : 'rectangle'}
      />

      {/* Full Profile Editor */}
      <Suspense fallback={null}>
        <ProfileFullEditor
          block={block}
          isOpen={isFullEditorOpen}
          onClose={() => setIsFullEditorOpen(false)}
          onSave={onUpdate}
        />
      </Suspense>
    </div>
  );
});

import { memo, useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { Button } from '@/components/ui/button';
import { ExternalLink, Instagram, Twitter, Youtube, Facebook, Linkedin, Globe, Link2 } from 'lucide-react';
import { getButtonClass, createBlockClickHandler, getBackgroundStyle } from '@/lib/blocks/block-utils';
import { getI18nText, type SupportedLanguage } from '@/lib/i18n-helpers';
import { extractDomain, getGoogleFaviconUrl, getDirectFaviconUrl } from '@/lib/favicon-utils';
import { getBlockStyles, hasCustomBlockStyle } from '@/lib/blocks/block-styling';
import { cn } from '@/lib/utils/utils';
import type { LinkBlock as LinkBlockType } from '@/types/page';

interface LinkBlockProps {
  block: LinkBlockType;
  onClick?: () => void;
}

const iconMap: Record<string, React.ComponentType<{ className?: string }>> = {
  instagram: Instagram,
  twitter: Twitter,
  youtube: Youtube,
  facebook: Facebook,
  linkedin: Linkedin,
  globe: Globe,
};

export const LinkBlock = memo(function LinkBlockComponent({ block, onClick }: LinkBlockProps) {
  const { i18n } = useTranslation();
  const [faviconError, setFaviconError] = useState(false);
  const [faviconLoaded, setFaviconLoaded] = useState(false);

  const iconMode = block.iconMode || 'auto';
  const isManualMode = iconMode === 'manual';
  const domain = extractDomain(block.url || '');

  const getFaviconSrc = (): string | null => {
    if (isManualMode) {
      return block.customIconUrl || null;
    }
    if (block.faviconUrl) return block.faviconUrl;
    if (domain) return getGoogleFaviconUrl(domain);
    return null;
  };

  const faviconSrc = getFaviconSrc();

  useEffect(() => {
    setFaviconError(false);
    setFaviconLoaded(false);
  }, [block.url, block.faviconUrl, block.customIconUrl]);

  const FallbackIcon = block.icon && iconMap[block.icon.toLowerCase()]
    ? iconMap[block.icon.toLowerCase()]
    : Link2;

  const handleClick = createBlockClickHandler(block.url, onClick);
  const title = getI18nText(block.title, i18n.language as SupportedLanguage);
  const shouldShowFavicon = faviconSrc && !faviconError;

  const handleFaviconError = () => {
    if (!faviconError && domain && faviconSrc === getGoogleFaviconUrl(domain)) {
      const directUrl = getDirectFaviconUrl(domain);
      const img = new Image();
      img.onload = () => setFaviconLoaded(true);
      img.onerror = () => setFaviconError(true);
      img.src = directUrl;
    } else {
      setFaviconError(true);
    }
  };

  // Check if we have a custom background from block.background
  const hasLegacyBackground = block.background && block.background.type && block.background.value;
  const legacyBackgroundStyle = hasLegacyBackground ? getBackgroundStyle(block.background) : {};
  const isImageBackground = block.background?.type === 'image';

  // Get custom block styles (new system)
  const { style: blockStyleObj, textEffectClass } = getBlockStyles(block.blockStyle);
  const hasBlockStyle = hasCustomBlockStyle(block.blockStyle);

  // Combine styles - new blockStyle takes precedence
  const combinedStyle = { ...legacyBackgroundStyle, ...blockStyleObj };
  const hasAnyCustomStyle = hasLegacyBackground || hasBlockStyle;

  return (
    <div className={cn(
      "flex w-full",
      block.alignment === 'left' ? 'justify-start' : block.alignment === 'right' ? 'justify-end' : 'justify-center'
    )}>
      <Button
        variant="ghost"
        className={cn(
          "w-full justify-between h-auto min-h-[56px] py-3 px-4 sm:px-6",
          "glass-button backdrop-blur-md",
          "hover:scale-[1.02] transition-all shadow-glass hover:shadow-glass-lg rounded-xl",
          "active:scale-[0.98]",
          getButtonClass(block.style),
          hasAnyCustomStyle ? 'border-transparent hover:bg-transparent' : 'border-white/10',
          isImageBackground && 'relative overflow-hidden'
        )}
        onClick={handleClick}
        style={combinedStyle}
      >
        {/* Overlay for image backgrounds */}
        {isImageBackground && (
          <div className="absolute inset-0 bg-black/30 pointer-events-none" />
        )}
        <div className={cn(
          "flex items-center gap-3 min-w-0 flex-1",
          isImageBackground && 'relative z-10'
        )}>
          {shouldShowFavicon ? (
            <img
              src={faviconSrc}
              alt=""
              className="h-6 w-6 flex-shrink-0 rounded-md object-contain"
              onError={handleFaviconError}
              onLoad={() => setFaviconLoaded(true)}
            />
          ) : (
            <FallbackIcon className={cn(
              "h-6 w-6 flex-shrink-0",
              hasAnyCustomStyle ? '' : 'text-primary'
            )} style={blockStyleObj.color ? { color: blockStyleObj.color } : undefined} />
          )}
          <span className={cn(
            "font-medium text-sm sm:text-base line-clamp-2 text-left",
            hasLegacyBackground ? 'text-white drop-shadow-md' : hasBlockStyle ? '' : 'text-foreground',
            textEffectClass
          )} style={blockStyleObj.color ? { color: blockStyleObj.color } : undefined}>
            {title}
          </span>
        </div>
        <ExternalLink className={cn(
          "h-4 w-4 flex-shrink-0 ml-2",
          isImageBackground && 'relative z-10',
          hasLegacyBackground ? 'text-white/80' : hasBlockStyle ? '' : 'text-muted-foreground'
        )} style={blockStyleObj.color ? { color: blockStyleObj.color, opacity: 0.8 } : undefined} />
      </Button>
    </div>
  );
});

import { memo } from 'react';
import { useTranslation } from 'react-i18next';
import { MessageCircle, Send, ExternalLink, Phone } from 'lucide-react';
import type { MessengerBlock as MessengerBlockType } from '@/types/page';
import { supabase } from '@/platform/supabase/client';
import { getI18nText, type SupportedLanguage } from '@/lib/i18n-helpers';
import { cn } from '@/lib/utils/utils';

interface MessengerBlockProps {
  block: MessengerBlockType;
  pageOwnerId?: string;
  onClick?: () => void;
}

export const MessengerBlock = memo(function MessengerBlock({ block, pageOwnerId, onClick }: MessengerBlockProps) {
  const { i18n } = useTranslation();
  const title = getI18nText(block.title, i18n.language as SupportedLanguage);

  const getMessengerIcon = (platform: string) => {
    const icons: Record<string, string> = {
      whatsapp: '🟢',
      telegram: '✈️',
      viber: '🟣',
      wechat: '💬',
    };
    return icons[platform] || '💬';
  };

  const getMessengerUrl = (platform: string, username: string, message?: string) => {
    const encodedMessage = message ? encodeURIComponent(message) : '';
    const urls: Record<string, string> = {
      whatsapp: `https://wa.me/${username}${message ? `?text=${encodedMessage}` : ''}`,
      telegram: `https://t.me/${username}`,
      viber: `viber://chat?number=${username}`,
      wechat: `weixin://dl/chat?${username}`,
    };
    return urls[platform] || '#';
  };

  const getPlatformName = (platform: string) => {
    const names: Record<string, string> = {
      whatsapp: 'WhatsApp',
      telegram: 'Telegram',
      viber: 'Viber',
      wechat: 'WeChat',
    };
    return names[platform] || platform;
  };

  const handleMessengerClick = async (platform: string, username: string, message?: string) => {
    // Track analytics click
    onClick?.();

    if (pageOwnerId) {
      try {
        await supabase.functions.invoke('create-lead', {
          body: {
            pageOwnerId,
            name: `${getPlatformName(platform)} Contact`,
            source: 'messenger',
            notes: `Clicked ${getPlatformName(platform)} link: @${username}`,
            metadata: { platform, username }
          }
        });
      } catch (error) {
        console.error('Failed to create lead from messenger click:', error);
      }
    }

    const url = getMessengerUrl(platform, username, message);
    // Delay to ensure tracking request is sent before navigation
    setTimeout(() => {
      window.open(url, '_blank', 'noopener,noreferrer');
    }, 15);
  };

  const messengers = block.messengers || [];

  // Compact horizontal layout for mobile
  const isSingleMessenger = messengers.length === 1;

  if (messengers.length === 0) {
    return null;
  }

  return (
    <div
      className="w-full rounded-[2rem] glass-card border border-white/10 shadow-glass p-5 relative overflow-hidden group"
      style={{
        backgroundColor: block.blockStyle?.backgroundColor,
        backgroundImage: block.blockStyle?.backgroundGradient,
      }}
    >
      {/* Background glow */}
      <div className="absolute -top-24 -left-24 w-48 h-48 bg-primary/10 blur-[80px] rounded-full group-hover:bg-primary/20 transition-colors duration-500" />

      <div className="relative z-10">
        {title && (
          <div className="flex items-center gap-3 mb-6 px-1">
            <div className="p-2 rounded-xl bg-primary/10 text-primary shadow-sm shadow-primary/20">
              <MessageCircle className="h-5 w-5" />
            </div>
            <h3 className="font-bold text-lg text-gradient leading-tight">{title}</h3>
          </div>
        )}

        <div className="flex flex-col gap-3">
          {messengers.map((messenger, index) => (
            <button
              key={index}
              onClick={() => handleMessengerClick(messenger.platform, messenger.username, messenger.message)}
              className={cn(
                "flex items-center gap-4 p-4 rounded-2xl",
                "glass-card backdrop-blur-md border-white/10 shadow-glass",
                "transition-all duration-300 hover:scale-[1.02] hover:shadow-glass-lg active:scale-[0.98]",
                "group/item overflow-hidden relative text-left w-full"
              )}
            >
              <div className="flex-shrink-0 relative z-10">
                {messenger.platform === 'whatsapp' && <MessageCircle className="h-6 w-6 text-[#25D366]" />}
                {messenger.platform === 'telegram' && <Send className="h-6 w-6 text-[#0088cc]" />}
                {messenger.platform === 'viber' && <Phone className="h-6 w-6 text-[#7360f2]" />}
              </div>
              <div className="flex-1 min-w-0 relative z-10">
                <div className="font-bold text-sm tracking-wide uppercase text-foreground/90">
                  {getPlatformName(messenger.platform)}
                </div>
                {messenger.username && (
                  <div className="text-xs text-muted-foreground/60 truncate font-medium mt-0.5">
                    {messenger.username}
                  </div>
                )}
              </div>
              <ExternalLink className="h-4 w-4 text-muted-foreground/30 group-hover/item:text-primary transition-colors duration-300 relative z-10" />
            </button>
          ))}
        </div>
      </div>
    </div>
  );
});

import { memo, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Mail, Crown, CheckCircle, Send, Loader2, Check } from 'lucide-react';
import type { NewsletterBlock as NewsletterBlockType } from '@/types/page';
import { Card } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { toast } from 'sonner';
import { getI18nText, type SupportedLanguage } from '@/lib/i18n-helpers';
import { cn } from '@/lib/utils/utils';
import { supabase } from '@/platform/supabase/client';

interface NewsletterBlockProps {
  block: NewsletterBlockType;
  pageOwnerId?: string;
  pageId?: string;
}

export const NewsletterBlock = memo(function NewsletterBlock({ block, pageOwnerId, pageId }: NewsletterBlockProps) {
  const { i18n, t } = useTranslation();
  const [email, setEmail] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);
  const [isSubscribed, setIsSubscribed] = useState(false);

  const title = getI18nText(block.title, i18n.language as SupportedLanguage);
  const description = getI18nText(block.description, i18n.language as SupportedLanguage);
  const buttonText = getI18nText(block.buttonText, i18n.language as SupportedLanguage) || t('actions.subscribe', 'Subscribe');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    const trimmedEmail = email.trim().toLowerCase();

    if (!trimmedEmail || !trimmedEmail.includes('@') || !trimmedEmail.includes('.')) {
      toast.error(t('errors.invalidEmail', 'Enter a valid email'));
      return;
    }

    if (!pageOwnerId || !pageId) {
      toast.error(t('errors.subscription', 'Subscription error'));
      return;
    }

    setIsSubmitting(true);

    try {
      // Save newsletter subscription using raw insert (types not yet generated)
      const { error: subscriptionError } = await supabase
        .from('newsletter_subscriptions' as any)
        .insert({
          email: trimmedEmail,
          page_id: pageId,
          block_id: block.id,
          owner_id: pageOwnerId,
          status: 'active',
        } as any);

      if (subscriptionError) {
        // Check if already subscribed (unique constraint violation)
        if (subscriptionError.code === '23505') {
          toast.info(t('newsletter.alreadySubscribed', 'You are already subscribed!'));
          setIsSubscribed(true);
          setEmail('');
          return;
        }
        throw subscriptionError;
      }

      // Also create a lead for CRM integration
      const { error: leadError } = await supabase
        .from('leads')
        .insert({
          name: trimmedEmail.split('@')[0], // Use email prefix as name
          email: trimmedEmail,
          user_id: pageOwnerId,
          source: 'form', // Using 'form' as newsletter source
          status: 'new',
          metadata: {
            block_id: block.id,
            page_id: pageId,
            subscribed_at: new Date().toISOString(),
            source_type: 'newsletter',
          },
        } as any);

      // Lead creation failure is not critical, just log it
      if (leadError) {
        console.warn('Failed to create lead for newsletter subscription:', leadError);
      }

      toast.success(t('success.subscribed', 'Successfully subscribed!'));
      setIsSubscribed(true);
      setEmail('');
    } catch (error) {
      console.error('Newsletter subscription error:', error);
      toast.error(t('errors.subscription', 'Subscription error'));
    } finally {
      setIsSubmitting(false);
    }
  };

  if (isSubscribed) {
    return (
      <Card className="p-5 sm:p-6 bg-card border-border shadow-sm rounded-xl">
        <div className="flex flex-col items-center gap-3 text-center py-4">
          <CheckCircle className="h-10 w-10 text-primary" />
          <h3 className="font-semibold text-lg">{t('newsletter.thankYou', 'Thank you!')}</h3>
          <p className="text-sm text-muted-foreground">
            {t('newsletter.subscriptionConfirmed', 'Your subscription has been confirmed.')}
          </p>
        </div>
      </Card>
    );
  }

  return (
    <div className="w-full p-6 sm:p-8 rounded-[2rem] glass-card backdrop-blur-xl border-white/10 shadow-glass-xl relative overflow-hidden group">
      {/* Background glow effect */}
      <div className="absolute -top-24 -right-24 w-48 h-48 bg-primary/10 blur-[80px] rounded-full group-hover:bg-primary/20 transition-colors duration-500" />

      <div className="relative z-10">
        <div className="flex items-center gap-3 mb-4">
          <div className="p-2 rounded-xl bg-primary/10 text-primary shadow-sm shadow-primary/20">
            <Mail className="h-6 w-6" />
          </div>
          <h3 className="text-xl font-bold tracking-tight text-gradient">
            {title || t('newsletter.title', 'Подпишитесь')}
          </h3>
        </div>

        {description && (
          <p className="text-sm text-foreground/70 mb-6 leading-relaxed font-medium">
            {description}
          </p>
        )}

        <form onSubmit={handleSubmit} className="space-y-3">
          <div className="relative group/input">
            <Input
              type="email"
              value={email}
              onChange={(e) => setEmail(e.target.value)}
              placeholder={t('newsletter.emailPlaceholder', 'Ваш email')}
              required
              disabled={status === 'loading'}
              className="h-14 rounded-2xl glass-input border-white/5 focus:border-primary/50 text-base font-medium transition-all"
            />
          </div>

          <Button
            type="submit"
            disabled={status === 'loading'}
            className="w-full h-14 rounded-2xl text-base font-bold shadow-lg shadow-primary/30 hover:scale-[1.02] active:scale-[0.98] transition-all gap-2"
          >
            {status === 'loading' ? (
              <Loader2 className="h-5 w-5 animate-spin" />
            ) : status === 'success' ? (
              <Check className="h-5 w-5" />
            ) : (
              <Send className="h-5 w-5" />
            )}
            {buttonText || t('newsletter.subscribe', 'Подписаться')}
          </Button>
        </form>

        {status === 'success' && (
          <p className="text-xs font-bold text-center text-emerald-400 mt-4 animate-in fade-in slide-in-from-top-2">
            {t('newsletter.success', 'Спасибо за подписку!')}
          </p>
        )}

        {status === 'error' && (
          <p className="text-xs font-bold text-center text-red-400 mt-4 animate-in fade-in slide-in-from-top-2">
            {t('newsletter.error', 'Ошибка. Попробуйте снова.')}
          </p>
        )}
      </div>
    </div>
  );
});

import { memo, useMemo, Suspense } from 'react';
import { useTranslation } from 'react-i18next';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { getI18nText, type SupportedLanguage } from '@/lib/i18n-helpers';
import { parseRichText } from '@/lib/rich-text-parser';
import { getFrameStyles, getShadowStyles, isGradientFrame, FRAME_CSS, getVerificationPositionClasses, getVerificationColor, VERIFICATION_ICON_OPTIONS } from '@/lib/avatar-frame-utils';
import { getLucideIcon, CheckCircle2 } from '@/lib/utils/icon-utils';
import { cn } from '@/lib/utils/utils';
import { VerifiedBadge } from './VerifiedBadge';
import { NAME_ANIMATION_CSS, getNameAnimationClass, type NameAnimationType } from '@/lib/profile-frame-system';
import type { ProfileBlock as ProfileBlockType, ProfileFrameStyle, VerificationIconType } from '@/types/page';
import type { PremiumTier } from '@/hooks/user/usePremiumStatus';

interface ProfileBlockProps {
  block: ProfileBlockType;
  isPreview?: boolean;
  isOwnerPremium?: boolean;
  ownerTier?: PremiumTier;
  isOwnerVerified?: boolean;
}

// Custom verification badge component for user-selected styling
const CustomVerificationBadge = memo(function CustomVerificationBadgeComponent({
  iconType,
  customIcon,
  color,
  position
}: {
  iconType?: VerificationIconType;
  customIcon?: string;
  color?: string;
  position?: string;
}) {
  // If custom icon is provided, use it instead of preset icon
  if (customIcon) {
    return (
      <div
        className={cn(
          "absolute rounded-full shadow-lg z-10 overflow-hidden flex-shrink-0",
          "w-6 h-6 sm:w-7 sm:h-7",
          getVerificationPositionClasses(position)
        )}
        style={{
          backgroundColor: getVerificationColor(color),
        }}
      >
        <img
          src={customIcon}
          alt="Verified"
          className="w-full h-full object-cover"
        />
      </div>
    );
  }

  const iconOption = VERIFICATION_ICON_OPTIONS.find(opt => opt.value === (iconType || 'check-circle'));
  const iconName = iconOption?.icon || 'CheckCircle2';
  const IconComponent = getLucideIcon(iconName, CheckCircle2);

  return (
    <div
      className={cn(
        "absolute rounded-full p-1 sm:p-1.5 shadow-lg z-10 flex-shrink-0",
        getVerificationPositionClasses(position)
      )}
      style={{ backgroundColor: getVerificationColor(color) }}
    >
      <Suspense fallback={<div className="h-3.5 w-3.5 sm:h-4 sm:w-4 bg-white/20 rounded-full" />}>
        <IconComponent className="h-3.5 w-3.5 sm:h-4 sm:w-4 text-white" fill="currentColor" />
      </Suspense>
    </div>
  );
});

export const ProfileBlock = memo(function ProfileBlockComponent({
  block,
  isPreview,
  isOwnerPremium,
  ownerTier,
  isOwnerVerified = false
}: ProfileBlockProps) {
  const { t, i18n } = useTranslation();
  const name = getI18nText(block.name, i18n.language as SupportedLanguage);
  const bio = getI18nText(block.bio, i18n.language as SupportedLanguage);

  // Pro tier users are considered premium
  const isPremiumUser = ownerTier === 'pro' || isOwnerPremium;

  // Use platform verification status + premium status for badge
  const showPlatformBadge = isOwnerVerified || isPremiumUser;

  const initials = name
    .split(' ')
    .map(n => n[0])
    .join('')
    .toUpperCase()
    .slice(0, 2);

  const getAvatarSize = () => {
    const size = block.avatarSize || 'large';
    switch (size) {
      case 'small': return 'h-16 w-16';
      case 'medium': return 'h-24 w-24';
      case 'large': return 'h-32 w-32';
      case 'xlarge': return 'h-40 w-40';
      default: return 'h-32 w-32';
    }
  };

  const getFrameSize = () => {
    const size = block.avatarSize || 'large';
    switch (size) {
      case 'small': return 'h-[72px] w-[72px]';
      case 'medium': return 'h-[104px] w-[104px]';
      case 'large': return 'h-[140px] w-[140px]';
      case 'xlarge': return 'h-[172px] w-[172px]';
      default: return 'h-[140px] w-[140px]';
    }
  };

  const getCoverGradient = () => {
    const gradient = block.coverGradient || 'none';
    switch (gradient) {
      case 'none': return '';
      case 'dark': return 'bg-gradient-to-b from-black/50 to-black/20';
      case 'light': return 'bg-gradient-to-b from-white/50 to-white/20';
      case 'primary': return 'bg-gradient-to-b from-primary/60 to-primary/20';
      case 'sunset': return 'bg-gradient-to-br from-orange-500/50 via-pink-500/50 to-purple-600/50';
      case 'ocean': return 'bg-gradient-to-br from-blue-500/50 via-cyan-500/50 to-teal-500/50';
      case 'purple': return 'bg-gradient-to-br from-purple-600/50 via-pink-500/50 to-blue-500/50';
      default: return '';
    }
  };

  const getPositionClass = () => {
    const position = block.avatarPosition || 'center';
    switch (position) {
      case 'left': return 'items-start';
      case 'right': return 'items-end';
      case 'center':
      default: return 'items-center';
    }
  };

  const getCoverHeight = () => {
    const height = block.coverHeight || 'medium';
    switch (height) {
      case 'small': return 'h-[120px]';
      case 'medium': return 'h-[200px]';
      case 'large': return 'h-[320px]';
      default: return 'h-[200px]';
    }
  };

  const frameStyle: ProfileFrameStyle = block.avatarFrame || 'default';
  const hasGradientFrame = isGradientFrame(frameStyle);

  // Get icon component dynamically
  const getIconComponent = () => {
    if (!block.avatarIcon) return null;
    const IconComp = getLucideIcon(block.avatarIcon);
    return IconComp !== CheckCircle2 ? IconComp : null;
  };

  const IconComponent = getIconComponent();

  return (
    <div className={`relative flex flex-col ${getPositionClass()}`}>
      {block.coverImage && (
        <div className={`relative w-full ${getCoverHeight()} overflow-hidden`}>
          <img
            src={block.coverImage}
            alt="Cover"
            className="w-full h-full object-cover"
          />
          {block.coverGradient !== 'none' && (
            <div className={`absolute inset-0 ${getCoverGradient()}`} />
          )}
        </div>
      )}

      <div className={`flex flex-col ${getPositionClass()} gap-4 p-6 ${block.coverImage ? '-mt-16' : ''}`}>
        {/* Outer container for positioning icon - no animation here */}
        <div className="relative">
          {/* Frame wrapper - animations and shadow apply here ONLY */}
          <div
            className={cn(
              "flex items-center justify-center rounded-full",
              getFrameSize(),
            )}
            style={{
              ...getShadowStyles(block.shadowStyle || 'glass'),
              ...getFrameStyles(frameStyle),
            }}
          >
            {/* Avatar - NO animation, NO shadow - completely static */}
            <Avatar className={cn(getAvatarSize(), "bg-background")}>
              <AvatarImage src={block.avatar} alt={name} className="object-cover" />
              <AvatarFallback className="bg-primary text-primary-foreground text-2xl font-semibold">
                {initials}
              </AvatarFallback>
            </Avatar>
          </div>

          {/* Icon badge */}
          {IconComponent && (
            <div className="absolute -top-1 -right-1 bg-primary text-primary-foreground rounded-full p-1.5 shadow-lg z-10">
              <Suspense fallback={<div className="h-4 w-4 bg-primary-foreground/20 rounded-full" />}>
                <IconComponent className="h-4 w-4" />
              </Suspense>
            </div>
          )}

          {/* Platform verification badge - shows based on actual verification + premium status */}
          {showPlatformBadge && (
            <div className={cn("absolute z-10", getVerificationPositionClasses(block.verifiedPosition || 'bottom-right'))}>
              <VerifiedBadge
                isVerified={isOwnerVerified}
                isPremium={isPremiumUser}
                size="md"
              />
            </div>
          )}

          {/* Custom user-defined badge (if manually set and different from platform badge) */}
          {block.verified && !showPlatformBadge && (
            <CustomVerificationBadge
              iconType={block.verifiedIcon}
              customIcon={block.verifiedCustomIcon}
              color={block.verifiedColor}
              position={block.verifiedPosition || 'bottom-right'}
            />
          )}
        </div>

        <div className="text-center space-y-2">
          <style>{NAME_ANIMATION_CSS}</style>
          <div className="flex items-center justify-center gap-2">
            <h1 className={cn(
              "text-2xl font-bold transition-all duration-300",
              block.nameAnimation === 'none' && "hover:text-primary",
              (isPremiumUser || block.nameAnimation !== 'none') && "text-gradient bg-[length:200%_auto] animate-gradient-x",
              getNameAnimationClass((block.nameAnimation as NameAnimationType) || 'none')
            )}>
              {name}
            </h1>
          </div>

          {bio && (
            <p className="text-muted-foreground max-w-md whitespace-pre-line">{parseRichText(bio)}</p>
          )}
        </div>

        {/* Proof of Human - Video/Audio Greeting */}
        {(block.introVideo || block.introAudio) && (
          <div className="w-full max-w-md mx-auto space-y-3 mt-4">
            {block.introVideo && (
              <div className="relative rounded-xl overflow-hidden bg-muted/50 border border-border/50">
                <video
                  src={block.introVideo}
                  controls
                  playsInline
                  className="w-full max-h-48 object-cover"
                  preload="metadata"
                >
                  Your browser does not support video.
                </video>
                <div className="absolute top-2 left-2 bg-background/80 backdrop-blur-sm rounded-full px-2 py-1 text-xs font-medium flex items-center gap-1">
                  <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse" />
                  Video Greeting
                </div>
              </div>
            )}

            {block.introAudio && !block.introVideo && (
              <div className="relative rounded-xl overflow-hidden bg-muted/50 border border-border/50 p-4">
                <div className="flex items-center gap-3">
                  <div className="w-10 h-10 bg-primary/10 rounded-full flex items-center justify-center flex-shrink-0">
                    <span className="w-3 h-3 bg-primary rounded-full animate-pulse" />
                  </div>
                  <audio
                    src={block.introAudio}
                    controls
                    className="flex-1 h-10"
                    preload="metadata"
                  >
                    Your browser does not support audio.
                  </audio>
                </div>
                <div className="mt-2 text-xs text-muted-foreground text-center">
                  🎙️ Voice Greeting
                </div>
              </div>
            )}
          </div>
        )}
      </div>

      <style>{FRAME_CSS}</style>
    </div>
  );
});

'use client';

import type { CoverHeight, CoverGradient, AvatarSize, ShadowStyle, AvatarPosition } from "@/types/profile-editor";
/**
 * ProfileFullEditor - Unified full-screen editor for the top profile section
 * Opens as a drawer on mobile, dialog on desktop
 */
import { memo, useState, useEffect, useRef, useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { useRouter } from 'next/navigation';
import {
  Drawer,
  DrawerContent,
  DrawerHeader,
  DrawerTitle,
  DrawerDescription,
} from '@/components/ui/drawer';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import {
  Image,
  User,
  Type,
  Palette,
  Camera,
  Upload,
  Loader2,
  Check,
  X,
  ChevronLeft,
  Trash2,
  Sparkles,
} from 'lucide-react';
import { cn } from '@/lib/utils/utils';
import { useIsMobile } from '@/hooks/ui/use-mobile';
import { useFreemiumLimits } from '@/hooks/user/useFreemiumLimits';
import { getI18nText, createMultilingualString, isMultilingualString, type SupportedLanguage, type MultilingualString } from '@/lib/i18n-helpers';
import { compressImage } from '@/lib/utils/image-compression';
import { supabase } from '@/platform/supabase/client';
import { useAuth } from '@/hooks/user/useAuth';
import { toast } from 'sonner';
import { ImageCropper } from '@/components/form-fields/ImageCropper';
import { MultilingualInput } from '@/components/form-fields/MultilingualInput';
import { FrameSelector } from '@/components/profile/FrameSelector';
import { NameAnimationSelector } from '@/components/profile/NameAnimationSelector';
import { NAME_ANIMATION_CSS, getNameAnimationClass } from '@/lib/profile-frame-system';
import type { ProfileBlock as ProfileBlockType, NameAnimationType } from '@/types/page';

interface ProfileFullEditorProps {
  block: ProfileBlockType;
  isOpen: boolean;
  onClose: () => void;
  onSave: (updates: Partial<ProfileBlockType>) => void;
}

const COVER_GRADIENTS = [
  { value: 'none', label: 'profile.none', preview: 'bg-muted' },
  { value: 'dark', label: 'profile.dark', preview: 'bg-gradient-to-b from-black/50 to-black/20' },
  { value: 'light', label: 'profile.light', preview: 'bg-gradient-to-b from-white/50 to-white/20' },
  { value: 'primary', label: 'profile.primary', preview: 'bg-gradient-to-b from-primary/60 to-primary/20' },
  { value: 'sunset', label: 'profile.sunset', preview: 'bg-gradient-to-br from-orange-500/50 via-pink-500/50 to-purple-600/50' },
  { value: 'ocean', label: 'profile.ocean', preview: 'bg-gradient-to-br from-blue-500/50 via-cyan-500/50 to-teal-500/50' },
  { value: 'purple', label: 'profile.purple', preview: 'bg-gradient-to-br from-purple-600/50 via-pink-500/50 to-blue-500/50' },
];

const COVER_HEIGHTS = [
  { value: 'small', label: 'profile.small' },
  { value: 'medium', label: 'profile.medium' },
  { value: 'large', label: 'profile.large' },
];

const AVATAR_SIZES = [
  { value: 'small', label: 'profile.small', size: 'h-12 w-12' },
  { value: 'medium', label: 'profile.medium', size: 'h-16 w-16' },
  { value: 'large', label: 'profile.large', size: 'h-20 w-20' },
  { value: 'xlarge', label: 'profile.xlarge', size: 'h-24 w-24' },
];

// Avatar frames are now handled by FrameSelector component with full options

const SHADOW_STYLES = [
  { value: 'none', label: 'profile.none' },
  { value: 'soft', label: 'profile.soft' },
  { value: 'medium', label: 'profile.medium' },
  { value: 'strong', label: 'profile.strong' },
  { value: 'glow', label: 'profile.glow' },
];

const AVATAR_POSITIONS = [
  { value: 'left', label: 'fields.left' },
  { value: 'center', label: 'fields.center' },
  { value: 'right', label: 'fields.right' },
];

export const ProfileFullEditor = memo(function ProfileFullEditor({
  block,
  isOpen,
  onClose,
  onSave,
}: ProfileFullEditorProps) {
  const { t, i18n } = useTranslation();
  const { user } = useAuth();
  const router = useRouter();
  const isMobile = useIsMobile();
  const { canUsePremiumFrames } = useFreemiumLimits();
  const currentLang = i18n.language as SupportedLanguage;

  const [formData, setFormData] = useState<Partial<ProfileBlockType>>(() => ({ ...block }));
  const [isUploading, setIsUploading] = useState(false);
  const [uploadType, setUploadType] = useState<'avatar' | 'cover'>('avatar');
  const [cropperOpen, setCropperOpen] = useState(false);
  const [cropperImage, setCropperImage] = useState('');
  const [activeTab, setActiveTab] = useState('cover');

  const avatarInputRef = useRef<HTMLInputElement>(null);
  const coverInputRef = useRef<HTMLInputElement>(null);

  // Sync formData when block changes
  useEffect(() => {
    if (block) {
      setFormData({ ...block });
    }
  }, [block]);

  const name = typeof formData.name === 'object'
    ? getI18nText(formData.name, currentLang)
    : formData.name || '';

  const bio = typeof formData.bio === 'object'
    ? getI18nText(formData.bio, currentLang)
    : formData.bio || '';

  const initials = name
    .split(' ')
    .map(n => n[0])
    .join('')
    .toUpperCase()
    .slice(0, 2) || 'ME';

  const handleFileUpload = useCallback(async (file: File, type: 'avatar' | 'cover') => {
    if (!user) {
      toast.error(t('auth.required', 'Please sign in'));
      return;
    }

    if (file.size > 10 * 1024 * 1024) {
      toast.error(t('upload.fileTooLarge', 'File too large (max 10MB)'));
      return;
    }

    if (file.type === 'image/gif') {
      await uploadFile(file, type);
      return;
    }

    const reader = new FileReader();
    reader.onload = (e) => {
      setCropperImage(e.target?.result as string);
      setUploadType(type);
      setCropperOpen(true);
    };
    reader.readAsDataURL(file);
  }, [user, t]);

  const uploadFile = async (file: File | Blob, type: 'avatar' | 'cover') => {
    if (!user) return;

    setIsUploading(true);
    try {
      let processedFile = file;
      if (file instanceof File && file.type.startsWith('image/') && file.type !== 'image/gif') {
        processedFile = await compressImage(file);
      }

      const fileExt = file instanceof File ? file.name.split('.').pop() : 'jpg';
      const fileName = `${type}-${Date.now()}.${fileExt}`;
      const filePath = `${user.id}/${fileName}`;

      const { error } = await supabase.storage
        .from('user-media')
        .upload(filePath, processedFile);

      if (error) throw error;

      const { data: { publicUrl } } = supabase.storage
        .from('user-media')
        .getPublicUrl(filePath);

      if (type === 'avatar') {
        setFormData(prev => ({ ...prev, avatar: publicUrl }));
      } else {
        setFormData(prev => ({ ...prev, coverImage: publicUrl }));
      }
      toast.success(t('upload.success', 'Uploaded!'));
    } catch (err) {
      console.error('Upload error:', err);
      toast.error(t('upload.error', 'Upload failed'));
    } finally {
      setIsUploading(false);
    }
  };

  const handleCropperSave = async (croppedDataUrl: string) => {
    setCropperOpen(false);
    const { dataUrlToBlob } = await import('@/lib/utils/data-url-to-blob');
    const blob = dataUrlToBlob(croppedDataUrl);
    await uploadFile(blob, uploadType);
  };

  const handleInputChange = useCallback((e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const type = e.target === avatarInputRef.current ? 'avatar' : 'cover';
      handleFileUpload(file, type);
    }
    e.target.value = '';
  }, [handleFileUpload]);

  const handleSave = () => {
    onSave(formData);
    onClose();
  };

  const renderContent = () => (
    <>
      {/* Hidden file inputs */}
      <input
        ref={avatarInputRef}
        type="file"
        accept="image/*"
        onChange={handleInputChange}
        className="hidden"
      />
      <input
        ref={coverInputRef}
        type="file"
        accept="image/*"
        onChange={handleInputChange}
        className="hidden"
      />

      <Tabs value={activeTab} onValueChange={setActiveTab} className="flex-1 flex flex-col min-h-0 overflow-hidden">
        <TabsList className="grid grid-cols-4 mx-4 mb-4 h-12 rounded-2xl bg-muted/50 p-1 shrink-0">
          <TabsTrigger value="cover" className="rounded-xl data-[state=active]:bg-background data-[state=active]:shadow-sm">
            <Image className="h-4 w-4" />
          </TabsTrigger>
          <TabsTrigger value="avatar" className="rounded-xl data-[state=active]:bg-background data-[state=active]:shadow-sm">
            <User className="h-4 w-4" />
          </TabsTrigger>
          <TabsTrigger value="info" className="rounded-xl data-[state=active]:bg-background data-[state=active]:shadow-sm">
            <Type className="h-4 w-4" />
          </TabsTrigger>
          <TabsTrigger value="style" className="rounded-xl data-[state=active]:bg-background data-[state=active]:shadow-sm">
            <Palette className="h-4 w-4" />
          </TabsTrigger>
        </TabsList>

        <div className="flex-1 overflow-y-auto min-h-0">
          <div className="px-5 pb-6 space-y-6">
            {/* Cover Tab */}
            <TabsContent value="cover" className="mt-0 space-y-5">
              <div className="text-center mb-4">
                <h3 className="text-lg font-bold">{t('profileEditor.cover', 'Обложка')}</h3>
                <p className="text-sm text-muted-foreground">{t('profileEditor.coverDesc', 'Добавьте красивую обложку')}</p>
              </div>

              {/* Cover Preview */}
              <div
                className={cn(
                  "relative aspect-[2.5/1] rounded-2xl overflow-hidden border-2 border-dashed cursor-pointer group",
                  formData.coverImage ? "border-transparent" : "border-border bg-muted/30"
                )}
                onClick={() => coverInputRef.current?.click()}
              >
                {formData.coverImage ? (
                  <>
                    <img src={formData.coverImage} alt="" className="w-full h-full object-cover" />
                    {formData.coverGradient && formData.coverGradient !== 'none' && (
                      <div className={cn(
                        "absolute inset-0",
                        COVER_GRADIENTS.find(g => g.value === formData.coverGradient)?.preview
                      )} />
                    )}
                  </>
                ) : (
                  <div className="flex flex-col items-center justify-center h-full gap-2">
                    <Camera className="h-8 w-8 text-muted-foreground" />
                    <span className="text-sm text-muted-foreground">{t('profileEditor.uploadCover', 'Загрузить обложку')}</span>
                  </div>
                )}

                <div className="absolute inset-0 flex items-center justify-center bg-black/0 group-hover:bg-black/40 transition-colors">
                  {isUploading && uploadType === 'cover' ? (
                    <Loader2 className="h-10 w-10 text-white animate-spin" />
                  ) : (
                    <Upload className="h-10 w-10 text-white opacity-0 group-hover:opacity-100 transition-opacity" />
                  )}
                </div>
              </div>

              {formData.coverImage && (
                <Button
                  variant="outline"
                  size="sm"
                  onClick={() => setFormData(prev => ({ ...prev, coverImage: undefined }))}
                  className="w-full rounded-xl"
                >
                  <Trash2 className="h-4 w-4 mr-2" />
                  {t('profileEditor.removeCover', 'Удалить обложку')}
                </Button>
              )}

              {/* Cover Height */}
              <div className="space-y-3">
                <Label className="text-sm font-medium">{t('profile.coverHeight', 'Высота')}</Label>
                <div className="grid grid-cols-3 gap-2">
                  {COVER_HEIGHTS.map((height) => (
                    <button
                      key={height.value}
                      type="button"
                      onClick={() => setFormData(prev => ({ ...prev, coverHeight: height.value as CoverHeight }))}
                      className={cn(
                        "py-3 rounded-xl border-2 text-sm font-medium transition-all",
                        formData.coverHeight === height.value
                          ? "border-primary bg-primary/5"
                          : "border-border/20 hover:border-border/50"
                      )}
                    >
                      {t(height.label)}
                    </button>
                  ))}
                </div>
              </div>

              {/* Cover Gradient */}
              {formData.coverImage && (
                <div className="space-y-3">
                  <Label className="text-sm font-medium">{t('profile.coverGradient', 'Градиент')}</Label>
                  <div className="grid grid-cols-4 gap-2">
                    {COVER_GRADIENTS.map((gradient) => (
                      <button
                        key={gradient.value}
                        type="button"
                        onClick={() => setFormData(prev => ({ ...prev, coverGradient: gradient.value as CoverGradient }))}
                        className={cn(
                          "aspect-[2/1] rounded-xl border-2 transition-all",
                          gradient.preview,
                          formData.coverGradient === gradient.value
                            ? "border-primary ring-2 ring-primary/30"
                            : "border-border/20 hover:border-border/50"
                        )}
                        title={t(gradient.label)}
                      />
                    ))}
                  </div>
                </div>
              )}
            </TabsContent>

            {/* Avatar Tab */}
