import { useState, useRef, useEffect } from 'react';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { MessageCircle, X, Send, Loader2 } from 'lucide-react';
import { cn } from '@/lib/utils/utils';

interface Message {
  role: 'user' | 'assistant';
  content: string;
}

interface ChatbotWidgetProps {
  pageSlug: string;
}

export function ChatbotWidget({ pageSlug }: ChatbotWidgetProps) {
  const [isOpen, setIsOpen] = useState(false);
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [messages]);

  const sendMessage = async () => {
    if (!input.trim() || isLoading) return;

    const userMessage: Message = { role: 'user', content: input };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    try {
      const response = await fetch(
        `${import.meta.env.VITE_SUPABASE_URL}/functions/v1/chatbot-stream`,
        {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY}`,
          },
          body: JSON.stringify({
            pageSlug,
            messages: [...messages, userMessage],
          }),
        }
      );

      if (!response.ok) {
        throw new Error('Failed to get response');
      }

      const reader = response.body?.getReader();
      const decoder = new TextDecoder();
      let assistantMessage = '';

      if (reader) {
        // Add empty assistant message
        setMessages(prev => [...prev, { role: 'assistant', content: '' }]);

        while (true) {
          const { done, value } = await reader.read();
          if (done) break;

          const chunk = decoder.decode(value);
          const lines = chunk.split('\n');

          for (const line of lines) {
            if (line.startsWith('data: ')) {
              const data = line.slice(6);
              if (data === '[DONE]') continue;

              try {
                const parsed = JSON.parse(data);
                const content = parsed.choices?.[0]?.delta?.content;

                if (content) {
                  assistantMessage += content;
                  setMessages(prev => {
                    const newMessages = [...prev];
                    newMessages[newMessages.length - 1] = {
                      role: 'assistant',
                      content: assistantMessage,
                    };
                    return newMessages;
                  });
                }
              } catch (e) {
                // Skip malformed JSON
              }
            }
          }
        }
      }
    } catch (error) {
      console.error('Chat error:', error);
      setMessages(prev => [
        ...prev,
        {
          role: 'assistant',
          content: 'Sorry, I encountered an error. Please try again.',
        },
      ]);
    } finally {
      setIsLoading(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  return (
    <>
      {/* Chat Button - Mobile Optimized */}
      {!isOpen && (
        <Button
          onClick={() => setIsOpen(true)}
          className="fixed bottom-4 right-4 sm:bottom-6 sm:right-6 h-12 w-12 sm:h-14 sm:w-14 rounded-full shadow-lg z-50"
          size="icon"
        >
          <MessageCircle className="h-5 w-5 sm:h-6 sm:w-6" />
        </Button>
      )}

      {/* Chat Window - Fullscreen on Mobile */}
      {isOpen && (
        <Card className="fixed inset-0 sm:inset-auto sm:bottom-6 sm:right-6 sm:w-[380px] sm:h-[600px] shadow-2xl z-50 flex flex-col sm:rounded-lg">
          {/* Header */}
          <div className="flex items-center justify-between p-3 sm:p-4 border-b bg-background">
            <div className="flex items-center gap-2">
              <MessageCircle className="h-4 w-4 sm:h-5 sm:w-5 text-primary" />
              <h3 className="font-semibold text-sm sm:text-base">Ask me anything</h3>
            </div>
            <Button
              variant="ghost"
              size="icon"
              onClick={() => setIsOpen(false)}
              className="h-8 w-8 sm:h-10 sm:w-10"
            >
              <X className="h-4 w-4" />
            </Button>
          </div>

          {/* Messages - Optimized Scroll */}
          <div className="flex-1 overflow-y-auto p-3 sm:p-4 space-y-3 sm:space-y-4">
            {messages.length === 0 && (
              <div className="text-center text-muted-foreground text-xs sm:text-sm py-8">
                <p>Hi! I'm here to help answer questions about this page.</p>
                <p className="mt-2">Ask me anything!</p>
              </div>
            )}

            {messages.map((message, index) => (
              <div
                key={index}
                className={cn(
                  'flex',
                  message.role === 'user' ? 'justify-end' : 'justify-start'
                )}
              >
                <div
                  className={cn(
                    'rounded-lg px-3 py-2 sm:px-4 max-w-[85%] sm:max-w-[80%]',
                    message.role === 'user'
                      ? 'bg-primary text-primary-foreground'
                      : 'bg-muted'
                  )}
                >
                  <p className="text-xs sm:text-sm whitespace-pre-wrap break-words">{message.content}</p>
                </div>
              </div>
            ))}

            {isLoading && (
              <div className="flex justify-start">
                <div className="bg-muted rounded-lg px-3 py-2 sm:px-4">
                  <Loader2 className="h-4 w-4 animate-spin" />
                </div>
              </div>
            )}

            <div ref={messagesEndRef} />
          </div>

          {/* Input - Touch Optimized */}
          <div className="p-3 sm:p-4 border-t bg-background">
            <div className="flex gap-2">
              <Input
                value={input}
                onChange={(e) => setInput(e.target.value)}
                onKeyPress={handleKeyPress}
                placeholder="Type your message..."
                disabled={isLoading}
                className="text-sm sm:text-base h-10 sm:h-10"
              />
              <Button
                onClick={sendMessage}
                disabled={!input.trim() || isLoading}
                size="icon"
                className="h-10 w-10 sm:h-10 sm:w-10 flex-shrink-0"
              >
                <Send className="h-4 w-4" />
              </Button>
            </div>
          </div>
        </Card>
      )}
    </>
  );
}

import { useState, useEffect } from 'react';
import { Checkbox } from '@/components/ui/checkbox';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Badge } from '@/components/ui/badge';
import { Loader2, Save, Eye, EyeOff } from 'lucide-react';
import { supabase } from '@/platform/supabase/client';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';

interface BlockSettings {
  requester_blocks: string[];
  target_blocks: string[];
  show_all: boolean;
}

interface CollabBlockManagerProps {
  collabId: string;
  requesterId: string;
  targetId: string;
  requesterPageId: string;
  targetPageId: string | null;
  currentSettings: BlockSettings;
  requesterProfile: {
    display_name: string | null;
    username: string | null;
    avatar_url: string | null;
  } | null;
  targetProfile: {
    display_name: string | null;
    username: string | null;
    avatar_url: string | null;
  } | null;
  onSettingsChange: (settings: BlockSettings) => void;
}

interface BlockData {
  id: string;
  type: string;
  owner: 'requester' | 'target';
  pageId: string;
}

export function CollabBlockManager({
  collabId,
  requesterPageId,
  targetPageId,
  currentSettings,
  requesterProfile,
  targetProfile,
  onSettingsChange,
}: CollabBlockManagerProps) {
  const { t } = useTranslation();
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [blocks, setBlocks] = useState<BlockData[]>([]);
  const [settings, setSettings] = useState<BlockSettings>(currentSettings);

  useEffect(() => {
    loadBlocks();
  }, [requesterPageId, targetPageId]);

  const loadBlocks = async () => {
    setLoading(true);
    try {
      const pageIds = [requesterPageId, targetPageId].filter(Boolean) as string[];
      
      const { data: blocksData } = await supabase
        .from('blocks')
        .select('id, type, page_id')
        .in('page_id', pageIds)
        .order('position');

      if (blocksData) {
        const blocksWithOwner: BlockData[] = blocksData.map(b => ({
          id: b.id,
          type: b.type,
          owner: b.page_id === requesterPageId ? 'requester' : 'target',
          pageId: b.page_id,
        }));
        
        setBlocks(blocksWithOwner);
      }
    } catch (error) {
      console.error('Error loading blocks:', error);
    } finally {
      setLoading(false);
    }
  };

  const isBlockSelected = (blockId: string, owner: 'requester' | 'target'): boolean => {
    if (settings.show_all) return true;
    return owner === 'requester' 
      ? settings.requester_blocks.includes(blockId)
      : settings.target_blocks.includes(blockId);
  };

  const toggleBlock = (blockId: string, owner: 'requester' | 'target') => {
    const key = owner === 'requester' ? 'requester_blocks' : 'target_blocks';
    const currentList = settings[key];
    
    const newList = currentList.includes(blockId)
      ? currentList.filter(id => id !== blockId)
      : [...currentList, blockId];
    
    setSettings(prev => ({
      ...prev,
      show_all: false,
      [key]: newList,
    }));
  };

  const toggleShowAll = () => {
    setSettings(prev => ({
      ...prev,
      show_all: !prev.show_all,
    }));
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      const settingsJson = JSON.parse(JSON.stringify(settings));
      const { error } = await supabase
        .from('collaborations')
        .update({ block_settings: settingsJson })
        .eq('id', collabId);

      if (error) throw error;
      onSettingsChange(settings);
      toast.success(t('collab.blocksSaved', 'Настройки блоков сохранены'));
    } catch (error) {
      console.error('Error saving block settings:', error);
      toast.error(t('collab.blocksSaveError', 'Ошибка сохранения'));
    } finally {
      setSaving(false);
    }
  };

  const getBlockLabel = (block: BlockData): string => {
    const typeKeys: Record<string, string> = {
      profile: 'blocks.profile',
      link: 'blocks.link',
      button: 'blocks.button',
      text: 'blocks.text',
      image: 'blocks.image',
      video: 'blocks.video',
      carousel: 'blocks.carousel',
      product: 'blocks.product',
      socials: 'blocks.socials',
      messenger: 'blocks.messenger',
      form: 'blocks.form',
      download: 'blocks.download',
      newsletter: 'blocks.newsletter',
      testimonial: 'blocks.testimonial',
      faq: 'blocks.faq',
      countdown: 'blocks.countdown',
      map: 'blocks.map',
      custom_code: 'blocks.customCode',
      scratch: 'blocks.scratch',
      search: 'blocks.search',
      avatar: 'blocks.avatar',
      shoutout: 'blocks.shoutout',
      separator: 'blocks.separator',
      catalog: 'blocks.catalog',
      pricing: 'blocks.pricing',
      before_after: 'blocks.beforeAfter',
    };
    const key = typeKeys[block.type];
    return key ? t(key, block.type) : block.type;
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center p-4">
        <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
      </div>
    );
  }

  const requesterBlocks = blocks.filter(b => b.owner === 'requester');
  const targetBlocks = blocks.filter(b => b.owner === 'target');

  return (
    <div className="space-y-4">
      <div className="flex items-center justify-between">
        <Button 
          variant={settings.show_all ? 'default' : 'outline'} 
          size="sm"
          onClick={toggleShowAll}
        >
          {settings.show_all ? <Eye className="h-4 w-4 mr-2" /> : <EyeOff className="h-4 w-4 mr-2" />}
          {settings.show_all ? t('collab.showAll', 'Показать все') : t('collab.selective', 'Выборочно')}
        </Button>
        <Button size="sm" onClick={handleSave} disabled={saving}>
          {saving ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <Save className="h-4 w-4 mr-2" />}
          {t('collab.save', 'Сохранить')}
        </Button>
      </div>

      {/* Requester blocks */}
      <Card className="bg-card/50">
        <CardHeader className="py-3">
          <CardTitle className="text-sm flex items-center gap-2">
            <Avatar className="h-6 w-6">
              <AvatarImage src={requesterProfile?.avatar_url || ''} />
              <AvatarFallback className="text-xs">
                {(requesterProfile?.display_name || 'U').charAt(0)}
              </AvatarFallback>
            </Avatar>
            {requesterProfile?.display_name || requesterProfile?.username || t('collab.initiator', 'Инициатор')}
          </CardTitle>
        </CardHeader>
        <CardContent className="pt-0">
          {requesterBlocks.length === 0 ? (
            <p className="text-xs text-muted-foreground">{t('collab.noBlocks', 'Нет блоков')}</p>
          ) : (
            <div className="space-y-2">
              {requesterBlocks.map(block => (
                <div 
                  key={block.id} 
                  className="flex items-center gap-3 p-2 bg-muted/50 rounded-lg"
                >
                  <Checkbox
                    checked={isBlockSelected(block.id, 'requester')}
                    onCheckedChange={() => toggleBlock(block.id, 'requester')}
                    disabled={settings.show_all}
                  />
                  <Badge variant="secondary" className="text-xs">
                    {getBlockLabel(block)}
                  </Badge>
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Target blocks */}
      {targetPageId && (
        <Card className="bg-card/50">
          <CardHeader className="py-3">
            <CardTitle className="text-sm flex items-center gap-2">
              <Avatar className="h-6 w-6">
                <AvatarImage src={targetProfile?.avatar_url || ''} />
              <AvatarFallback className="text-xs">
                {(targetProfile?.display_name || 'U').charAt(0)}
              </AvatarFallback>
            </Avatar>
            {targetProfile?.display_name || targetProfile?.username || t('collab.partner', 'Партнёр')}
          </CardTitle>
        </CardHeader>
        <CardContent className="pt-0">
          {targetBlocks.length === 0 ? (
            <p className="text-xs text-muted-foreground">{t('collab.noBlocks', 'Нет блоков')}</p>
          ) : (
              <div className="space-y-2">
                {targetBlocks.map(block => (
                  <div 
                    key={block.id} 
                    className="flex items-center gap-3 p-2 bg-muted/50 rounded-lg"
                  >
                    <Checkbox
                      checked={isBlockSelected(block.id, 'target')}
                      onCheckedChange={() => toggleBlock(block.id, 'target')}
                      disabled={settings.show_all}
                    />
                    <Badge variant="secondary" className="text-xs">
                      {getBlockLabel(block)}
                    </Badge>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      )}
    </div>
  );
}

'use client';

import { useState, useCallback } from 'react';
import Link from 'next/link';
import { useTranslation } from 'react-i18next';
import {
  ExternalLink, Settings, Loader2, Users, Copy,
  UserPlus, Crown, Check, Link2
} from 'lucide-react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Badge } from '@/components/ui/badge';
import { Dialog, DialogContent, DialogDescription, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { TeamEditor } from './TeamEditor';
import { TeamMembersList } from './TeamMembersList';
import { getTeamWithMembers, type Team, type TeamMember } from '@/services/collaboration';
import { toast } from 'sonner';

interface TeamsTabProps {
  userId: string;
  teams: Team[];
  onCreateTeam: (name: string, slug: string, description?: string) => Promise<{ success: boolean }>;
  onLeaveTeam: (teamId: string) => void;
  onJoinByCode?: (inviteCode: string) => Promise<{ success: boolean; team?: Team }>;
  onGetInviteCode?: (teamId: string) => Promise<string | null>;
  onRefresh: () => void;
}

export function TeamsTab({
  userId,
  teams,
  onCreateTeam,
  onLeaveTeam,
  onJoinByCode,
  onGetInviteCode,
  onRefresh
}: TeamsTabProps) {
  const { t } = useTranslation();
  const [newTeamName, setNewTeamName] = useState('');
  const [newTeamSlug, setNewTeamSlug] = useState('');
  const [newTeamDesc, setNewTeamDesc] = useState('');
  const [inviteCode, setInviteCode] = useState('');
  const [isJoining, setIsJoining] = useState(false);
  const [selectedTeam, setSelectedTeam] = useState<Team | null>(null);
  const [teamMembers, setTeamMembers] = useState<TeamMember[]>([]);
  const [loadingMembers, setLoadingMembers] = useState(false);
  const [copiedTeamId, setCopiedTeamId] = useState<string | null>(null);

  const loadTeamMembers = useCallback(async (teamId: string) => {
    setLoadingMembers(true);
    try {
      const teamWithMembers = await getTeamWithMembers(teamId);
      if (teamWithMembers?.members) {
        setTeamMembers(teamWithMembers.members);
      }
    } catch (error) {
      console.error('Error loading team members:', error);
    } finally {
      setLoadingMembers(false);
    }
  }, []);

  const handleOpenTeamSettings = useCallback(async (team: Team) => {
    setSelectedTeam(team);
    await loadTeamMembers(team.id);
  }, [loadTeamMembers]);

  const handleTeamUpdate = useCallback((updatedTeam: Team) => {
    setSelectedTeam(updatedTeam);
  }, []);

  const handleTeamDelete = useCallback(() => {
    setSelectedTeam(null);
    setTeamMembers([]);
    onRefresh();
  }, [onRefresh]);

  const handleMemberRemoved = useCallback(() => {
    if (selectedTeam) {
      loadTeamMembers(selectedTeam.id);
    }
  }, [selectedTeam, loadTeamMembers]);

  const handleCreateTeam = async () => {
    if (!newTeamName.trim() || !newTeamSlug.trim()) return;
    const result = await onCreateTeam(newTeamName, newTeamSlug, newTeamDesc);
    if (result.success) {
      setNewTeamName('');
      setNewTeamSlug('');
      setNewTeamDesc('');
    }
  };

  const handleJoinByCode = async () => {
    if (!inviteCode.trim() || !onJoinByCode) return;
    setIsJoining(true);
    const result = await onJoinByCode(inviteCode.trim());
    if (result.success) {
      setInviteCode('');
    }
    setIsJoining(false);
  };

  const handleCopyInviteLink = async (team: Team) => {
    if (!onGetInviteCode) return;

    let code = team.invite_code;
    if (!code) {
      code = await onGetInviteCode(team.id);
    }

    if (code) {
      const inviteUrl = `${window.location.origin}/join-team/${code}`;
      await navigator.clipboard.writeText(inviteUrl);
      setCopiedTeamId(team.id);
      toast.success(t('teams.linkCopied', 'Ссылка скопирована!'));
      setTimeout(() => setCopiedTeamId(null), 2000);
    }
  };

  const ownedTeams = teams.filter(t => t.owner_id === userId);
  const memberTeams = teams.filter(t => t.owner_id !== userId);

  return (
    <div className="space-y-4">
      {/* Teams stats */}
      {teams.length > 0 && (
        <div className="grid grid-cols-3 gap-2">
          <div className="bg-gradient-to-br from-blue-500/10 to-cyan-500/10 rounded-xl p-3 text-center">
            <Users className="h-4 w-4 mx-auto mb-1 text-blue-500" />
            <p className="text-lg font-bold">{teams.length}</p>
            <p className="text-[10px] text-muted-foreground">{t('teams.total', 'Команд')}</p>
          </div>
          <div className="bg-gradient-to-br from-amber-500/10 to-orange-500/10 rounded-xl p-3 text-center">
            <Crown className="h-4 w-4 mx-auto mb-1 text-amber-500" />
            <p className="text-lg font-bold">{ownedTeams.length}</p>
            <p className="text-[10px] text-muted-foreground">{t('teams.owned', 'Владею')}</p>
          </div>
          <div className="bg-gradient-to-br from-green-500/10 to-emerald-500/10 rounded-xl p-3 text-center">
            <UserPlus className="h-4 w-4 mx-auto mb-1 text-green-500" />
            <p className="text-lg font-bold">{memberTeams.length}</p>
            <p className="text-[10px] text-muted-foreground">{t('teams.member', 'Участник')}</p>
          </div>
        </div>
      )}

      {/* My teams */}
      <Card>
        <CardHeader className="pb-2">
          <CardTitle className="text-sm flex items-center gap-2">
            <Users className="h-4 w-4" />
            {t('teams.myTeams', 'Мои команды')}
          </CardTitle>
        </CardHeader>
        <CardContent>
          {teams.length === 0 ? (
            <div className="text-center py-6 space-y-2">
              <Users className="h-10 w-10 mx-auto text-muted-foreground/50" />
              <p className="text-sm text-muted-foreground">
                {t('teams.noTeams', 'Вы не состоите ни в одной команде')}
              </p>
              <p className="text-xs text-muted-foreground">
                {t('teams.noTeamsHint', 'Создайте команду или присоединитесь по коду приглашения')}
              </p>
            </div>
          ) : (
            <div className="space-y-2">
              {teams.map(team => (
                <div key={team.id} className="p-3 bg-muted/50 rounded-xl border border-border/30 space-y-2">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-3">
                      <Avatar className="h-10 w-10 rounded-xl">
                        <AvatarImage src={team.avatar_url || ''} />
                        <AvatarFallback className="rounded-xl bg-primary/10 text-primary font-bold">
                          {team.name[0]}
                        </AvatarFallback>
                      </Avatar>
                      <div>
                        <div className="flex items-center gap-2">
                          <p className="font-medium">{team.name}</p>
                          {team.owner_id === userId && (
                            <Badge variant="secondary" className="text-[10px] px-1.5 py-0">
                              <Crown className="h-3 w-3 mr-0.5" />
                              {t('teams.owner', 'Владелец')}
                            </Badge>
                          )}
                        </div>
                        <p className="text-xs text-muted-foreground">/{team.slug}</p>
                      </div>
                    </div>
                    <div className="flex gap-1">
                      <Link href={`/team/${team.slug}`}>
                        <Button size="sm" variant="ghost" className="h-8 w-8 p-0">
                          <ExternalLink className="h-4 w-4" />
                        </Button>
                      </Link>
                      {team.owner_id === userId && (
                        <Button
                          size="sm"
                          variant="ghost"
                          className="h-8 w-8 p-0"
                          onClick={() => handleCopyInviteLink(team)}
                        >
                          {copiedTeamId === team.id ? (
                            <Check className="h-4 w-4 text-green-500" />
                          ) : (
                            <Link2 className="h-4 w-4" />
                          )}
                        </Button>
                      )}
                      <Dialog>
                        <DialogTrigger asChild>
                          <Button
                            size="sm"
                            variant="ghost"
                            className="h-8 w-8 p-0"
                            onClick={() => handleOpenTeamSettings(team)}
                          >
                            <Settings className="h-4 w-4" />
                          </Button>
                        </DialogTrigger>
                        <DialogContent className="max-h-[80vh] overflow-y-auto">
                          <DialogHeader>
                            <DialogTitle>{t('teams.settings', 'Настройки команды')}</DialogTitle>
                            <DialogDescription className="sr-only">
                              {t('teams.settingsDesc', 'Manage team settings and members')}
                            </DialogDescription>
                          </DialogHeader>
                          {selectedTeam && selectedTeam.id === team.id && (
                            <div className="space-y-4">
                              <TeamEditor
                                team={selectedTeam}
                                isOwner={team.owner_id === userId}
                                onTeamUpdate={handleTeamUpdate}
                                onTeamDelete={handleTeamDelete}
                              />
                              {loadingMembers ? (
                                <div className="flex justify-center py-4">
                                  <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
                                </div>
                              ) : (
                                <TeamMembersList
                                  teamId={team.id}
                                  members={teamMembers}
                                  ownerId={team.owner_id}
                                  isOwner={team.owner_id === userId}
                                  onMemberRemoved={handleMemberRemoved}
                                />
                              )}
                            </div>
                          )}
                        </DialogContent>
                      </Dialog>
                      {team.owner_id !== userId && (
                        <Button
                          size="sm"
                          variant="ghost"
                          className="h-8 text-xs text-destructive hover:text-destructive"
                          onClick={() => onLeaveTeam(team.id)}
                        >
                          {t('teams.leave', 'Выйти')}
                        </Button>
                      )}
                    </div>
                  </div>
                  {team.description && (
                    <p className="text-xs text-muted-foreground line-clamp-2">{team.description}</p>
                  )}
                </div>
              ))}
            </div>
          )}
        </CardContent>
      </Card>

      {/* Create or Join */}
      <Tabs defaultValue="join" className="w-full">
        <TabsList className="grid w-full grid-cols-2">
          <TabsTrigger value="join" className="text-xs">
            <Link2 className="h-3 w-3 mr-1" />
            {t('teams.joinByCode', 'По коду')}
          </TabsTrigger>
          <TabsTrigger value="create" className="text-xs">
            <UserPlus className="h-3 w-3 mr-1" />
            {t('teams.createNew', 'Создать')}
          </TabsTrigger>
        </TabsList>

        <TabsContent value="join">
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm">{t('teams.joinTeam', 'Присоединиться к команде')}</CardTitle>
              <CardDescription className="text-xs">
                {t('teams.joinTeamDesc', 'Введите код приглашения от владельца команды')}
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-3">
              <Input
                placeholder={t('teams.inviteCodePlaceholder', 'Код приглашения (team-xxxxx)')}
                value={inviteCode}
                onChange={(e) => setInviteCode(e.target.value)}
                onKeyDown={(e) => e.key === 'Enter' && handleJoinByCode()}
              />
              <Button
                className="w-full"
                onClick={handleJoinByCode}
                disabled={!inviteCode.trim() || isJoining || !onJoinByCode}
              >
                {isJoining ? (
                  <Loader2 className="h-4 w-4 animate-spin mr-2" />
                ) : (
                  <UserPlus className="h-4 w-4 mr-2" />
                )}
                {t('teams.joinButton', 'Присоединиться')}
              </Button>
            </CardContent>
          </Card>
        </TabsContent>

        <TabsContent value="create">
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm">{t('teams.createTeam', 'Создать команду')}</CardTitle>
              <CardDescription className="text-xs">
                {t('teams.createTeamDesc', 'Соберите единомышленников для совместной работы')}
              </CardDescription>
            </CardHeader>
            <CardContent className="space-y-3">
              <Input
                placeholder={t('teams.teamNamePlaceholder', 'Название команды')}
                value={newTeamName}
                onChange={(e) => setNewTeamName(e.target.value)}
              />
              <Input
                placeholder={t('teams.teamSlugPlaceholder', 'URL команды (slug)')}
                value={newTeamSlug}
                onChange={(e) => setNewTeamSlug(e.target.value.toLowerCase().replace(/[^a-z0-9-]/g, ''))}
              />
              <Textarea
                placeholder={t('teams.teamDescriptionPlaceholder', 'Описание команды (необязательно)')}
                value={newTeamDesc}
                onChange={(e) => setNewTeamDesc(e.target.value)}
                className="min-h-[60px]"
              />
              <Button
                className="w-full"
                onClick={handleCreateTeam}
                disabled={!newTeamName || !newTeamSlug}
              >
                <Crown className="h-4 w-4 mr-2" />
                {t('teams.createTeamButton', 'Создать команду')}
              </Button>
            </CardContent>
          </Card>
        </TabsContent>
      </Tabs>
    </div>
  );
}

import { useTranslation } from 'react-i18next';
import { usePageAnalytics, TimePeriod } from '@/hooks/analytics/usePageAnalytics';
import { Card } from '@/components/ui/card';
import { Tabs, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { ScrollArea } from '@/components/ui/scroll-area';
import {
  Eye,
  MousePointerClick,
  Share2,
  Users,
  TrendingUp,
  TrendingDown,
  BarChart3,
  Calendar,
  Globe,
  Smartphone,
  Tablet,
  Monitor,
  RefreshCw
} from 'lucide-react';
import {
  AreaChart,
  Area,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  BarChart,
  Bar,
  PieChart,
  Pie,
  Cell,
  Legend
} from 'recharts';
import { Button } from '@/components/ui/button';

export function AnalyticsPanel() {
  const { t } = useTranslation();
  const { analytics, loading, period, setPeriod, refresh } = usePageAnalytics();

  if (loading) {
    return (
      <div className="p-8 text-center text-muted-foreground">
        <RefreshCw className="h-6 w-6 animate-spin mx-auto mb-2" />
        {t('messages.loading', 'Loading...')}
      </div>
    );
  }

  if (!analytics) {
    return (
      <div className="p-8 text-center text-muted-foreground">
        {t('analytics.noData', 'No analytics data available')}
      </div>
    );
  }

  const chartData = period === 'month' || period === 'all'
    ? analytics.monthlyData
    : period === 'week'
      ? analytics.weeklyData
      : analytics.dailyData;

  const DEVICE_COLORS = ['hsl(var(--chart-1))', 'hsl(var(--chart-2))', 'hsl(var(--chart-3))'];

  const deviceData = [
    { name: t('analytics.mobile', 'Mobile'), value: analytics.deviceBreakdown.mobile, icon: Smartphone },
    { name: t('analytics.tablet', 'Tablet'), value: analytics.deviceBreakdown.tablet, icon: Tablet },
    { name: t('analytics.desktop', 'Desktop'), value: analytics.deviceBreakdown.desktop, icon: Monitor },
  ].filter(d => d.value > 0);

  const total = analytics.deviceBreakdown.mobile + analytics.deviceBreakdown.tablet + analytics.deviceBreakdown.desktop;

  return (
    <ScrollArea className="h-[calc(100vh-200px)]">
      <div className="p-3 sm:p-4 space-y-3 sm:space-y-4 overflow-hidden">
        {/* Period Selector - Scrollable on mobile */}
        <div className="overflow-x-auto -mx-3 px-3 sm:mx-0 sm:px-0">
          <Tabs value={period} onValueChange={(v: string) => setPeriod(v as TimePeriod)}>
            <TabsList className="grid w-full min-w-[280px] grid-cols-4">
              <TabsTrigger value="day" className="text-[10px] sm:text-xs px-2">
                {t('analytics.today', 'Today')}
              </TabsTrigger>
              <TabsTrigger value="week" className="text-[10px] sm:text-xs px-2">
                {t('analytics.week', 'Week')}
              </TabsTrigger>
              <TabsTrigger value="month" className="text-[10px] sm:text-xs px-2">
                {t('analytics.month', 'Month')}
              </TabsTrigger>
              <TabsTrigger value="all" className="text-[10px] sm:text-xs px-2">
                {t('analytics.all', 'All')}
              </TabsTrigger>
            </TabsList>
          </Tabs>
        </div>

        {/* Summary Cards - 2x2 grid, responsive */}
        <div className="grid grid-cols-2 gap-2 sm:gap-3">
          <StatCard
            icon={Eye}
            label={t('analytics.views', 'Views')}
            value={analytics.totalViews}
            change={analytics.viewsChange}
          />
          <StatCard
            icon={MousePointerClick}
            label={t('analytics.clicks', 'Clicks')}
            value={analytics.totalClicks}
            change={analytics.clicksChange}
          />
          <StatCard
            icon={Share2}
            label={t('analytics.shares', 'Shares')}
            value={analytics.totalShares}
          />
          <StatCard
            icon={Users}
            label={t('analytics.visitors', 'Visitors')}
            value={analytics.uniqueVisitors}
          />
        </div>

        {/* Average Stats - Compact */}
        <Card className="p-3 sm:p-4">
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-2 text-xs sm:text-sm text-muted-foreground">
              <Calendar className="h-3.5 w-3.5 sm:h-4 sm:w-4" />
              {t('analytics.avgPerDay', 'Average per day')}
            </div>
            <div className="text-right">
              <div className="text-lg sm:text-2xl font-bold">{analytics.avgViewsPerDay}</div>
              <div className="text-[10px] sm:text-xs text-muted-foreground">
                {t('analytics.viewsPerDay', 'views / day')}
              </div>
            </div>
          </div>
        </Card>

        {/* Activity Chart - Responsive height */}
        <Card className="p-3 sm:p-4 overflow-hidden">
          <h3 className="text-xs sm:text-sm font-medium mb-3 sm:mb-4 flex items-center gap-2">
            <BarChart3 className="h-3.5 w-3.5 sm:h-4 sm:w-4" />
            {t('analytics.activityChart', 'Activity')}
          </h3>
          <div className="h-36 sm:h-48 -mx-2 sm:mx-0">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={chartData} margin={{ left: -25, right: 5, top: 5, bottom: 5 }}>
                <defs>
                  <linearGradient id="colorViews" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="hsl(var(--primary))" stopOpacity={0.3} />
                    <stop offset="95%" stopColor="hsl(var(--primary))" stopOpacity={0} />
                  </linearGradient>
                  <linearGradient id="colorClicks" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="hsl(var(--chart-2))" stopOpacity={0.3} />
                    <stop offset="95%" stopColor="hsl(var(--chart-2))" stopOpacity={0} />
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" className="stroke-muted" vertical={false} />
                <XAxis
                  dataKey="date"
                  tick={{ fontSize: 9 }}
                  tickLine={false}
                  axisLine={false}
                  className="text-muted-foreground"
                  interval="preserveStartEnd"
                />
                <YAxis
                  tick={{ fontSize: 9 }}
                  tickLine={false}
                  axisLine={false}
                  className="text-muted-foreground"
                  width={30}
                />
                <Tooltip
                  contentStyle={{
                    backgroundColor: 'hsl(var(--popover))',
                    border: '1px solid hsl(var(--border))',
                    borderRadius: '8px',
                    fontSize: '11px',
                    padding: '8px'
                  }}
                />
                <Area
                  type="monotone"
                  dataKey="views"
                  stroke="hsl(var(--primary))"
                  strokeWidth={2}
                  fillOpacity={1}
                  fill="url(#colorViews)"
                  name={t('analytics.views', 'Views')}
                />
                <Area
                  type="monotone"
                  dataKey="clicks"
                  stroke="hsl(var(--chart-2))"
                  strokeWidth={2}
                  fillOpacity={1}
                  fill="url(#colorClicks)"
                  name={t('analytics.clicks', 'Clicks')}
                />
              </AreaChart>
            </ResponsiveContainer>
          </div>
          {/* Legend */}
          <div className="flex justify-center gap-4 mt-2 text-[10px] sm:text-xs">
            <div className="flex items-center gap-1.5">
              <div className="w-2.5 h-2.5 rounded-full bg-primary" />
              <span className="text-muted-foreground">{t('analytics.views', 'Views')}</span>
            </div>
            <div className="flex items-center gap-1.5">
              <div className="w-2.5 h-2.5 rounded-full" style={{ backgroundColor: 'hsl(var(--chart-2))' }} />
              <span className="text-muted-foreground">{t('analytics.clicks', 'Clicks')}</span>
            </div>
          </div>
        </Card>

        {/* Top Blocks - Compact list */}
        {analytics.topBlocks.length > 0 && (
          <Card className="p-3 sm:p-4">
            <h3 className="text-xs sm:text-sm font-medium mb-3">
              {t('analytics.topBlocks', 'Top Content')}
            </h3>
            <div className="space-y-2">
              {analytics.topBlocks.slice(0, 5).map((block, index) => (
                <div key={block.blockId} className="flex items-center gap-2 sm:gap-3">
                  <div className="w-5 h-5 sm:w-6 sm:h-6 rounded-full bg-primary/10 text-primary text-[10px] sm:text-xs flex items-center justify-center font-medium shrink-0">
                    {index + 1}
                  </div>
                  <div className="flex-1 min-w-0">
                    <div className="text-xs sm:text-sm font-medium truncate">
                      {block.blockTitle}
                    </div>
                    <div className="text-[10px] sm:text-xs text-muted-foreground">
                      {block.blockType}
                    </div>
                  </div>
                  <div className="text-right shrink-0">
                    <div className="text-xs sm:text-sm font-medium">{block.clicks}</div>
                    <div className="text-[10px] sm:text-xs text-muted-foreground">
                      {block.ctr.toFixed(1)}%
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </Card>
        )}

        {/* Clicks by Block Chart - Horizontal bar, mobile optimized */}
        {analytics.topBlocks.length > 0 && (
          <Card className="p-3 sm:p-4 overflow-hidden">
            <h3 className="text-xs sm:text-sm font-medium mb-3">
              {t('analytics.clicksByBlock', 'Clicks by Block')}
            </h3>
            <div className="h-40 sm:h-48 -mx-1 sm:mx-0">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart
                  data={analytics.topBlocks.slice(0, 5)}
                  layout="vertical"
                  margin={{ left: 0, right: 10, top: 0, bottom: 0 }}
                >
                  <CartesianGrid strokeDasharray="3 3" className="stroke-muted" horizontal={false} />
                  <XAxis type="number" tick={{ fontSize: 9 }} tickLine={false} axisLine={false} />
                  <YAxis
                    type="category"
                    dataKey="blockTitle"
                    tick={{ fontSize: 9 }}
                    width={70}
                    tickLine={false}
                    axisLine={false}
                    tickFormatter={(value) => value.length > 10 ? value.slice(0, 10) + '...' : value}
                  />
                  <Tooltip
                    contentStyle={{
                      backgroundColor: 'hsl(var(--popover))',
                      border: '1px solid hsl(var(--border))',
                      borderRadius: '8px',
                      fontSize: '11px'
                    }}
                  />
                  <Bar
                    dataKey="clicks"
                    fill="hsl(var(--primary))"
                    radius={[0, 4, 4, 0]}
                  />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </Card>
        )}

        {/* Traffic Sources - Simplified progress bars */}
        {analytics.trafficSources.length > 0 && (
          <Card className="p-3 sm:p-4">
            <h3 className="text-xs sm:text-sm font-medium mb-3 flex items-center gap-2">
              <Globe className="h-3.5 w-3.5 sm:h-4 sm:w-4" />
              {t('analytics.trafficSources', 'Traffic Sources')}
            </h3>
            <div className="space-y-2.5">
              {analytics.trafficSources.slice(0, 5).map((source) => (
                <div key={source.source} className="space-y-1">
                  <div className="flex items-center justify-between text-xs">
                    <span className="capitalize truncate">{source.source}</span>
                    <span className="text-muted-foreground shrink-0 ml-2">
                      {source.count} ({source.percentage.toFixed(0)}%)
                    </span>
                  </div>
                  <div className="w-full bg-muted rounded-full h-1.5">
                    <div
                      className="bg-primary h-1.5 rounded-full transition-all"
                      style={{ width: `${Math.min(source.percentage, 100)}%` }}
                    />
                  </div>
                </div>
              ))}
            </div>
          </Card>
        )}

        {/* Device Breakdown - Horizontal layout for mobile */}
        {deviceData.length > 0 && (
          <Card className="p-3 sm:p-4 overflow-hidden">
            <h3 className="text-xs sm:text-sm font-medium mb-3 flex items-center gap-2">
              <Monitor className="h-3.5 w-3.5 sm:h-4 sm:w-4" />
              {t('analytics.devices', 'Devices')}
            </h3>
            <div className="flex flex-col sm:flex-row items-center gap-3 sm:gap-4">
              {/* Pie chart - smaller on mobile */}
              <div className="w-20 h-20 sm:w-24 sm:h-24 shrink-0">
                <ResponsiveContainer width="100%" height="100%">
                  <PieChart>
                    <Pie
                      data={deviceData}
                      cx="50%"
                      cy="50%"
                      innerRadius={20}
                      outerRadius={35}
                      paddingAngle={3}
                      dataKey="value"
                    >
                      {deviceData.map((_, index) => (
                        <Cell key={`cell-${index}`} fill={DEVICE_COLORS[index % DEVICE_COLORS.length]} />
                      ))}
                    </Pie>
                  </PieChart>
                </ResponsiveContainer>
              </div>
              {/* Legend - horizontal on mobile */}
              <div className="flex flex-row sm:flex-col flex-wrap justify-center gap-2 sm:gap-1.5 flex-1">
                {deviceData.map((device, index) => {
                  const Icon = device.icon;
                  const percentage = total > 0 ? (device.value / total) * 100 : 0;
                  return (
                    <div key={device.name} className="flex items-center gap-1.5 text-xs sm:text-sm">
                      <div
                        className="w-2.5 h-2.5 rounded-full shrink-0"
                        style={{ backgroundColor: DEVICE_COLORS[index] }}
                      />
                      <Icon className="h-3.5 w-3.5 text-muted-foreground shrink-0" />
                      <span className="truncate">{device.name}</span>
                      <span className="font-medium shrink-0">{percentage.toFixed(0)}%</span>
                    </div>
                  );
                })}
              </div>
            </div>
          </Card>
        )}

        {/* Refresh Button */}
        <Button
          variant="outline"
          size="sm"
          className="w-full"
          onClick={refresh}
        >
          <RefreshCw className="h-4 w-4 mr-2" />
          {t('analytics.refresh', 'Refresh')}
        </Button>
      </div>
    </ScrollArea>
  );
}

interface StatCardProps {
  icon: React.ElementType;
  label: string;
  value: number;
  change?: number;
}

function StatCard({ icon: Icon, label, value, change }: StatCardProps) {
  const showChange = change !== undefined && change !== 0;
  const isPositive = change && change > 0;

  return (
    <Card className="p-2.5 sm:p-3">
      <div className="flex items-center gap-1.5 text-muted-foreground mb-0.5 sm:mb-1">
        <Icon className="h-3.5 w-3.5 sm:h-4 sm:w-4" />
        <span className="text-[10px] sm:text-xs truncate">{label}</span>
      </div>
      <div className="flex items-baseline gap-1.5">
        <span className="text-lg sm:text-2xl font-bold">{value.toLocaleString()}</span>
        {showChange && (
          <span className={`text-[10px] sm:text-xs flex items-center gap-0.5 ${isPositive ? 'text-green-500' : 'text-red-500'
            }`}>
            {isPositive ? <TrendingUp className="h-2.5 w-2.5 sm:h-3 sm:w-3" /> : <TrendingDown className="h-2.5 w-2.5 sm:h-3 sm:w-3" />}
            {Math.abs(change).toFixed(0)}%
          </span>
        )}
      </div>
    </Card>
  );
}

import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Switch } from '@/components/ui/switch';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Collapsible, CollapsibleContent, CollapsibleTrigger } from '@/components/ui/collapsible';
import { Bot, ChevronDown, Clock, MessageSquare, Star, Bell, Loader2, Save, Info } from 'lucide-react';
import { supabase } from '@/platform/supabase/client';
import { toast } from 'sonner';

interface Automation {
  id?: string;
  user_id: string;
  automation_type: 'follow_up' | 'time_clarification' | 'review_request';
  is_enabled: boolean;
  trigger_hours: number;
  template_message: string;
}

interface AutomationsPanelProps {
  userId: string;
  isPremium: boolean;
}

const DEFAULT_TEMPLATES = {
  follow_up: {
    ru: 'Здравствуйте, {lead_name}! Это {owner_name}. Хотела уточнить — вы всё ещё рассматриваете запись? Буду рада помочь!',
    en: 'Hi {lead_name}! This is {owner_name}. Just checking in — are you still interested in booking? Happy to help!',
    kk: 'Сәлеметсіз бе, {lead_name}! Бұл {owner_name}. Сіз әлі де жазылуды қарастырасыз ба? Көмектесуге қуаныштымын!'
  },
  time_clarification: {
    ru: 'Здравствуйте, {lead_name}! Подскажите удобное время для записи? У меня есть свободные окна на этой неделе.',
    en: 'Hi {lead_name}! What time works best for you? I have some openings this week.',
    kk: 'Сәлеметсіз бе, {lead_name}! Сізге қай уақыт ыңғайлы? Осы аптада бос орындар бар.'
  },
  review_request: {
    ru: 'Здравствуйте, {lead_name}! Спасибо, что были у меня! Буду благодарна за короткий отзыв — это очень помогает! ⭐',
    en: 'Hi {lead_name}! Thanks for visiting! A quick review would mean a lot to me! ⭐',
    kk: 'Сәлеметсіз бе, {lead_name}! Маған келгеніңізге рахмет! Қысқа пікір қалдырсаңыз өте ризамын! ⭐'
  }
};

export function AutomationsPanel({ userId, isPremium }: AutomationsPanelProps) {
  const { t, i18n } = useTranslation();
  const [automations, setAutomations] = useState<Automation[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState<string | null>(null);
  const [expandedType, setExpandedType] = useState<string | null>(null);

  const lang = i18n.language as 'ru' | 'en' | 'kk';

  useEffect(() => {
    loadAutomations();
  }, [userId]);

  const loadAutomations = async () => {
    try {
      const { data, error } = await supabase
        .from('crm_automations')
        .select('*')
        .eq('user_id', userId);

      if (error) throw error;

      // Initialize with defaults if not exists
      const types: Automation['automation_type'][] = ['follow_up', 'time_clarification', 'review_request'];
      const existingTypes = new Set((data || []).map(a => a.automation_type));

      const allAutomations: Automation[] = (data || []).map(a => ({
        id: a.id,
        user_id: a.user_id,
        automation_type: a.automation_type as Automation['automation_type'],
        is_enabled: a.is_enabled,
        trigger_hours: a.trigger_hours,
        template_message: a.template_message
      }));

      for (const type of types) {
        if (!existingTypes.has(type)) {
          allAutomations.push({
            user_id: userId,
            automation_type: type,
            is_enabled: false,
            trigger_hours: type === 'follow_up' ? 24 : type === 'time_clarification' ? 12 : 48,
            template_message: DEFAULT_TEMPLATES[type][lang] || DEFAULT_TEMPLATES[type].ru
          });
        }
      }

      setAutomations(allAutomations);
    } catch (error) {
      console.error('Error loading automations:', error);
    } finally {
      setLoading(false);
    }
  };

  const saveAutomation = async (automation: Automation) => {
    setSaving(automation.automation_type);
    try {
      if (automation.id) {
        const { error } = await supabase
          .from('crm_automations')
          .update({
            is_enabled: automation.is_enabled,
            trigger_hours: automation.trigger_hours,
            template_message: automation.template_message
          })
          .eq('id', automation.id);

        if (error) throw error;
      } else {
        const { data, error } = await supabase
          .from('crm_automations')
          .insert({
            user_id: userId,
            automation_type: automation.automation_type,
            is_enabled: automation.is_enabled,
            trigger_hours: automation.trigger_hours,
            template_message: automation.template_message
          })
          .select()
          .single();

        if (error) throw error;

        setAutomations(prev => prev.map(a =>
          a.automation_type === automation.automation_type ? { ...a, id: data.id } : a
        ));
      }

      toast.success(t('automations.saved', 'Automation saved'));
    } catch (error) {
      console.error('Error saving automation:', error);
      toast.error(t('automations.saveError', 'Failed to save automation'));
    } finally {
      setSaving(null);
    }
  };

  const updateAutomation = (type: string, updates: Partial<Automation>) => {
    setAutomations(prev => prev.map(a =>
      a.automation_type === type ? { ...a, ...updates } : a
    ));
  };

  const getAutomationConfig = (type: Automation['automation_type']) => {
    switch (type) {
      case 'follow_up':
        return {
          icon: Bell,
          title: t('automations.followUp.title', 'Follow-up Reminder'),
          description: t('automations.followUp.description', 'Send reminder if lead is inactive'),
          color: 'text-blue-500',
          bgColor: 'bg-blue-500/10'
        };
      case 'time_clarification':
        return {
          icon: Clock,
          title: t('automations.timeClarification.title', 'Time Clarification'),
          description: t('automations.timeClarification.description', 'Ask to choose a time slot'),
          color: 'text-amber-500',
          bgColor: 'bg-amber-500/10'
        };
      case 'review_request':
        return {
          icon: Star,
          title: t('automations.reviewRequest.title', 'Review Request'),
          description: t('automations.reviewRequest.description', 'Ask for feedback after completion'),
          color: 'text-green-500',
          bgColor: 'bg-green-500/10'
        };
    }
  };

  if (!isPremium) {
    return (
      <Card className="p-4 bg-card/60 backdrop-blur-xl border-border/30">
        <div className="flex items-center gap-2 mb-3">
          <div className="p-1.5 rounded-lg bg-primary/10">
            <Bot className="h-4 w-4 text-primary" />
          </div>
          <h3 className="font-semibold">{t('automations.title', 'Smart Automations')}</h3>
        </div>
        <p className="text-sm text-muted-foreground mb-3">
          {t('automations.premiumRequired', 'Upgrade to Pro to use smart automations')}
        </p>
        <Button variant="outline" size="sm" className="w-full" disabled>
          {t('automations.unlockPremium', 'Available in Pro')}
        </Button>
      </Card>
    );
  }

  if (loading) {
    return (
      <Card className="p-4 bg-card/60 backdrop-blur-xl border-border/30">
        <div className="flex items-center justify-center py-6">
          <Loader2 className="h-5 w-5 animate-spin text-muted-foreground" />
        </div>
      </Card>
    );
  }

  return (
    <Card className="p-4 bg-card/60 backdrop-blur-xl border-border/30">
      <div className="flex items-center gap-2 mb-4">
        <div className="p-1.5 rounded-lg bg-primary/10">
          <Bot className="h-4 w-4 text-primary" />
        </div>
        <div>
          <h3 className="font-semibold">{t('automations.title', 'Smart Automations')}</h3>
          <p className="text-xs text-muted-foreground">{t('automations.subtitle', 'Auto-reminders via Telegram')}</p>
        </div>
      </div>

      <div className="space-y-3">
        {automations.map((automation) => {
          const config = getAutomationConfig(automation.automation_type);
          const Icon = config.icon;
          const isExpanded = expandedType === automation.automation_type;

          return (
            <Collapsible
              key={automation.automation_type}
              open={isExpanded}
              onOpenChange={(open) => setExpandedType(open ? automation.automation_type : null)}
            >
              <div className="rounded-xl bg-background/30 border border-border/20 overflow-hidden">
                <div className="p-3">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center gap-2">
                      <div className={`p-1.5 rounded-lg ${config.bgColor}`}>
                        <Icon className={`h-4 w-4 ${config.color}`} />
                      </div>
                      <div>
                        <Label className="text-sm font-medium">{config.title}</Label>
                        <p className="text-xs text-muted-foreground">{config.description}</p>
                      </div>
                    </div>
                    <div className="flex items-center gap-2">
                      <Switch
                        checked={automation.is_enabled}
                        onCheckedChange={(enabled) => {
                          updateAutomation(automation.automation_type, { is_enabled: enabled });
                          saveAutomation({ ...automation, is_enabled: enabled });
                        }}
                      />
                      <CollapsibleTrigger asChild>
                        <Button variant="ghost" size="icon" className="h-8 w-8">
                          <ChevronDown className={`h-4 w-4 transition-transform ${isExpanded ? 'rotate-180' : ''}`} />
                        </Button>
                      </CollapsibleTrigger>
                    </div>
                  </div>
                </div>

                <CollapsibleContent>
                  <div className="px-3 pb-3 space-y-3 border-t border-border/20 pt-3">
                    {/* Trigger time */}
                    <div>
                      <Label className="text-xs text-muted-foreground">
                        {t('automations.triggerAfter', 'Trigger after')}
                      </Label>
                      <Select
                        value={String(automation.trigger_hours)}
                        onValueChange={(val: string) => updateAutomation(automation.automation_type, { trigger_hours: parseInt(val) })}
                      >
                        <SelectTrigger className="bg-background/50 mt-1">
                          <SelectValue />
                        </SelectTrigger>
                        <SelectContent>
                          <SelectItem value="6">6 {t('automations.hours', 'hours')}</SelectItem>
                          <SelectItem value="12">12 {t('automations.hours', 'hours')}</SelectItem>
                          <SelectItem value="24">24 {t('automations.hours', 'hours')}</SelectItem>
                          <SelectItem value="48">48 {t('automations.hours', 'hours')}</SelectItem>
                          <SelectItem value="72">72 {t('automations.hours', 'hours')}</SelectItem>
                        </SelectContent>
                      </Select>
                    </div>

                    {/* Template */}
                    <div>
                      <Label className="text-xs text-muted-foreground">
                        {t('automations.messageTemplate', 'Message template')}
                      </Label>
                      <Textarea
                        value={automation.template_message}
                        onChange={(e) => updateAutomation(automation.automation_type, { template_message: e.target.value })}
                        className="mt-1 bg-background/50 text-sm"
                        rows={3}
                      />
                      <div className="flex items-start gap-1.5 mt-1.5">
                        <Info className="h-3 w-3 text-muted-foreground mt-0.5 shrink-0" />
                        <p className="text-xs text-muted-foreground">
                          {t('automations.variables', 'Use {lead_name}, {owner_name} for personalization')}
                        </p>
                      </div>
                    </div>

                    {/* Save button */}
                    <Button
                      size="sm"
                      onClick={() => saveAutomation(automation)}
                      disabled={saving === automation.automation_type}
                      className="w-full"
                    >
                      {saving === automation.automation_type ? (
                        <Loader2 className="h-4 w-4 animate-spin mr-2" />
                      ) : (
                        <Save className="h-4 w-4 mr-2" />
                      )}
                      {t('automations.saveSettings', 'Save settings')}
                    </Button>
                  </div>
                </CollapsibleContent>
              </div>
            </Collapsible>
          );
        })}
      </div>

      <div className="mt-3 p-2 rounded-lg bg-muted/50">
        <p className="text-xs text-muted-foreground flex items-center gap-1.5">
          <MessageSquare className="h-3 w-3" />
          {t('automations.telegramNote', 'Reminders are sent to your Telegram')}
        </p>
      </div>
    </Card>
  );
}

import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { supabase } from '@/platform/supabase/client';
import { useAuth } from '@/hooks/user/useAuth';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/components/ui/tabs';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
} from '@/components/ui/alert-dialog';
import {
  Calendar,
  Clock,
  User,
  Phone,
  Mail,
  MessageSquare,
  Check,
  X,
  RefreshCw,
  CalendarDays,
  Download,
  CalendarPlus,
} from 'lucide-react';
import { toast } from 'sonner';
import { format, isToday, isTomorrow, isPast, parseISO } from 'date-fns';
import { ru, kk, enUS } from 'date-fns/locale';

interface Booking {
  id: string;
  client_name: string;
  client_phone: string | null;
  client_email: string | null;
  client_notes: string | null;
  slot_date: string;
  slot_time: string;
  slot_end_time: string | null;
  status: string;
  created_at: string;
  block_id: string;
}

const statusColors: Record<string, string> = {
  confirmed: 'bg-green-500/20 text-green-500 border-green-500/30',
  pending: 'bg-yellow-500/20 text-yellow-500 border-yellow-500/30',
  cancelled: 'bg-red-500/20 text-red-500 border-red-500/30',
  completed: 'bg-blue-500/20 text-blue-500 border-blue-500/30',
};

export function BookingsPanel() {
  const { t, i18n } = useTranslation();
  const { user } = useAuth();
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [loading, setLoading] = useState(true);
  const [statusFilter, setStatusFilter] = useState<'all' | 'upcoming' | 'past'>('upcoming');
  const [cancelDialogOpen, setCancelDialogOpen] = useState(false);
  const [selectedBooking, setSelectedBooking] = useState<Booking | null>(null);

  const locale = i18n.language === 'ru' ? ru : i18n.language === 'kk' ? kk : enUS;

  const fetchBookings = async () => {
    if (!user) return;
    setLoading(true);

    const { data, error } = await supabase
      .from('bookings')
      .select('*')
      .eq('owner_id', user.id)
      .order('slot_date', { ascending: true })
      .order('slot_time', { ascending: true });

    if (error) {
      console.error('Error fetching bookings:', error);
      toast.error(t('bookings.fetchError', 'Failed to load bookings'));
    } else {
      setBookings(data || []);
    }
    setLoading(false);
  };

  useEffect(() => {
    fetchBookings();
  }, [user]);

  const handleCancelBooking = async () => {
    if (!selectedBooking) return;

    const { error } = await supabase
      .from('bookings')
      .update({ status: 'cancelled', cancelled_by: 'owner' })
      .eq('id', selectedBooking.id);

    if (error) {
      toast.error(t('bookings.cancelError', 'Failed to cancel booking'));
    } else {
      toast.success(t('bookings.cancelSuccess', 'Booking cancelled'));
      fetchBookings();
    }

    setCancelDialogOpen(false);
    setSelectedBooking(null);
  };

  const handleConfirmBooking = async (booking: Booking) => {
    const { error } = await supabase
      .from('bookings')
      .update({ status: 'confirmed' })
      .eq('id', booking.id);

    if (error) {
      toast.error(t('bookings.confirmError', 'Failed to confirm booking'));
    } else {
      toast.success(t('bookings.confirmSuccess', 'Booking confirmed'));
      fetchBookings();
    }
  };

  const handleCompleteBooking = async (booking: Booking) => {
    const { error } = await supabase
      .from('bookings')
      .update({ status: 'completed' })
      .eq('id', booking.id);

    if (error) {
      toast.error(t('bookings.completeError', 'Failed to complete booking'));
    } else {
      toast.success(t('bookings.completeSuccess', 'Booking marked as completed'));
      fetchBookings();
    }
  };

  const filteredBookings = bookings.filter((booking) => {
    const bookingDate = parseISO(booking.slot_date);
    const isBookingPast = isPast(bookingDate) && !isToday(bookingDate);

    if (statusFilter === 'upcoming') {
      return !isBookingPast && booking.status !== 'cancelled' && booking.status !== 'completed';
    }
    if (statusFilter === 'past') {
      return isBookingPast || booking.status === 'cancelled' || booking.status === 'completed';
    }
    return true;
  });

  const stats = {
    total: bookings.length,
    upcoming: bookings.filter(b => {
      const d = parseISO(b.slot_date);
      return (!isPast(d) || isToday(d)) && b.status !== 'cancelled' && b.status !== 'completed';
    }).length,
    today: bookings.filter(b => isToday(parseISO(b.slot_date)) && b.status !== 'cancelled').length,
    confirmed: bookings.filter(b => b.status === 'confirmed').length,
  };

  const formatBookingDate = (dateStr: string) => {
    const date = parseISO(dateStr);
    if (isToday(date)) return t('bookings.today', 'Today');
    if (isTomorrow(date)) return t('bookings.tomorrow', 'Tomorrow');
    return format(date, 'd MMMM', { locale });
  };

  const formatTime = (time: string, endTime?: string | null) => {
    const formatted = time.slice(0, 5);
    if (endTime) {
      return `${formatted} - ${endTime.slice(0, 5)}`;
    }
    return formatted;
  };

  // Export bookings to CSV
  const exportToCSV = () => {
    if (filteredBookings.length === 0) {
      toast.error(t('bookings.noBookingsToExport', 'No bookings to export'));
      return;
    }

    const headers = ['Date', 'Time', 'Name', 'Phone', 'Email', 'Notes', 'Status', 'Created'];
    const rows = filteredBookings.map(booking => [
      booking.slot_date,
      booking.slot_time.slice(0, 5),
      booking.client_name,
      booking.client_phone || '',
      booking.client_email || '',
      booking.client_notes || '',
      booking.status,
      new Date(booking.created_at).toISOString().split('T')[0],
    ]);

    const csvContent = [
      headers.join(','),
      ...rows.map(row => row.map(cell => `"${String(cell).replace(/"/g, '""')}"`).join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `bookings-${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
    URL.revokeObjectURL(link.href);

    toast.success(t('bookings.exportSuccess', 'Bookings exported successfully'));
  };

  // Generate ICS file for calendar
  const generateICS = (booking: Booking) => {
    const startDate = parseISO(booking.slot_date);
    const [hours, minutes] = booking.slot_time.split(':').map(Number);
    startDate.setHours(hours, minutes, 0, 0);

    const endDate = new Date(startDate);
    if (booking.slot_end_time) {
      const [endHours, endMinutes] = booking.slot_end_time.split(':').map(Number);
      endDate.setHours(endHours, endMinutes, 0, 0);
    } else {
      endDate.setHours(hours + 1, minutes, 0, 0);
    }

    const formatICSDate = (date: Date) => {
      return date.toISOString().replace(/[-:]/g, '').split('.')[0] + 'Z';
    };

    const icsContent = `BEGIN:VCALENDAR
VERSION:2.0
PRODID:-//lnkmx.my//Booking//EN
BEGIN:VEVENT
UID:${booking.id}@linkmax
DTSTAMP:${formatICSDate(new Date())}
DTSTART:${formatICSDate(startDate)}
DTEND:${formatICSDate(endDate)}
SUMMARY:${t('bookings.appointmentWith', 'Appointment with')} ${booking.client_name}
DESCRIPTION:${booking.client_notes ? booking.client_notes.replace(/\n/g, '\\n') : ''}\\n${booking.client_phone ? `Tel: ${booking.client_phone}` : ''}\\n${booking.client_email ? `Email: ${booking.client_email}` : ''}
END:VEVENT
END:VCALENDAR`;

    const blob = new Blob([icsContent], { type: 'text/calendar;charset=utf-8' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `booking-${booking.client_name.replace(/\s+/g, '-')}-${booking.slot_date}.ics`;
    link.click();
    URL.revokeObjectURL(link.href);

    toast.success(t('bookings.calendarExported', 'Added to calendar'));
  };

  if (loading) {
    return (
      <div className="p-8 text-center text-muted-foreground">
        <RefreshCw className="h-6 w-6 animate-spin mx-auto mb-2" />
        {t('messages.loading', 'Loading...')}
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col">
      {/* Stats */}
      <div className="grid grid-cols-4 gap-2 p-3 border-b">
        <div className="text-center p-2 rounded-lg bg-primary/10">
          <div className="text-lg font-bold text-primary">{stats.total}</div>
          <div className="text-[10px] text-muted-foreground">{t('bookings.total', 'Total')}</div>
        </div>
        <div className="text-center p-2 rounded-lg bg-green-500/10">
          <div className="text-lg font-bold text-green-500">{stats.upcoming}</div>
          <div className="text-[10px] text-muted-foreground">{t('bookings.upcoming', 'Upcoming')}</div>
        </div>
        <div className="text-center p-2 rounded-lg bg-yellow-500/10">
          <div className="text-lg font-bold text-yellow-500">{stats.today}</div>
          <div className="text-[10px] text-muted-foreground">{t('bookings.today', 'Today')}</div>
        </div>
        <div className="text-center p-2 rounded-lg bg-blue-500/10">
          <div className="text-lg font-bold text-blue-500">{stats.confirmed}</div>
          <div className="text-[10px] text-muted-foreground">{t('bookings.confirmed', 'Confirmed')}</div>
        </div>
      </div>

      {/* Filter Tabs */}
      <Tabs value={statusFilter} onValueChange={(v: string) => setStatusFilter(v as any)} className="w-full">
        <TabsList className="grid w-full grid-cols-3 mx-0 rounded-none border-b bg-transparent h-10">
          <TabsTrigger value="upcoming" className="rounded-none data-[state=active]:border-b-2 data-[state=active]:border-primary text-xs">
            {t('bookings.upcoming', 'Upcoming')}
          </TabsTrigger>
          <TabsTrigger value="past" className="rounded-none data-[state=active]:border-b-2 data-[state=active]:border-primary text-xs">
            {t('bookings.past', 'Past')}
          </TabsTrigger>
          <TabsTrigger value="all" className="rounded-none data-[state=active]:border-b-2 data-[state=active]:border-primary text-xs">
            {t('bookings.all', 'All')}
          </TabsTrigger>
        </TabsList>
      </Tabs>

      {/* Bookings List */}
      <ScrollArea className="flex-1">
        {filteredBookings.length === 0 ? (
          <div className="p-8 text-center text-muted-foreground">
            <CalendarDays className="h-12 w-12 mx-auto mb-3 opacity-50" />
            <p className="text-sm">{t('bookings.noBookings', 'No bookings yet')}</p>
          </div>
        ) : (
          <div className="divide-y">
            {filteredBookings.map((booking) => (
              <Card key={booking.id} className="m-3 p-3 border rounded-lg">
                <div className="flex items-start justify-between gap-2">
                  <div className="flex-1 min-w-0">
                    {/* Date & Time */}
                    <div className="flex items-center gap-2 mb-2">
                      <Badge variant="outline" className="text-xs">
                        <Calendar className="h-3 w-3 mr-1" />
                        {formatBookingDate(booking.slot_date)}
                      </Badge>
                      <Badge variant="outline" className="text-xs">
                        <Clock className="h-3 w-3 mr-1" />
                        {formatTime(booking.slot_time, booking.slot_end_time)}
                      </Badge>
                    </div>

                    {/* Client Info */}
                    <div className="space-y-1">
                      <div className="flex items-center gap-2 text-sm font-medium">
                        <User className="h-3.5 w-3.5 text-muted-foreground" />
                        {booking.client_name}
                      </div>
                      {booking.client_phone && (
                        <div className="flex items-center gap-2 text-xs text-muted-foreground">
                          <Phone className="h-3 w-3" />
                          <a href={`tel:${booking.client_phone}`} className="hover:text-primary">
                            {booking.client_phone}
                          </a>
                        </div>
                      )}
                      {booking.client_email && (
                        <div className="flex items-center gap-2 text-xs text-muted-foreground">
                          <Mail className="h-3 w-3" />
                          <a href={`mailto:${booking.client_email}`} className="hover:text-primary truncate">
                            {booking.client_email}
                          </a>
                        </div>
                      )}
                      {booking.client_notes && (
                        <div className="flex items-start gap-2 text-xs text-muted-foreground mt-2">
                          <MessageSquare className="h-3 w-3 mt-0.5 shrink-0" />
                          <span className="line-clamp-2">{booking.client_notes}</span>
                        </div>
                      )}
                    </div>
                  </div>

                  {/* Status & Actions */}
                  <div className="flex flex-col items-end gap-2">
                    <Badge variant="outline" className={`${statusColors[booking.status]} text-[10px]`}>
                      {t(`bookings.status.${booking.status}`, booking.status)}
                    </Badge>

                    {booking.status !== 'cancelled' && booking.status !== 'completed' && (
                      <div className="flex gap-1">
                        {/* Add to Calendar */}
                        <Button
                          size="sm"
                          variant="ghost"
                          className="h-7 w-7 p-0 text-primary hover:text-primary/80 hover:bg-primary/10"
                          onClick={() => generateICS(booking)}
                          title={t('bookings.addToCalendar', 'Add to Calendar')}
                        >
                          <CalendarPlus className="h-4 w-4" />
                        </Button>
                        {booking.status === 'pending' && (
                          <Button
                            size="sm"
                            variant="ghost"
                            className="h-7 w-7 p-0 text-green-500 hover:text-green-600 hover:bg-green-500/10"
                            onClick={() => handleConfirmBooking(booking)}
                          >
                            <Check className="h-4 w-4" />
                          </Button>
                        )}
                        {booking.status === 'confirmed' && (
                          <Button
                            size="sm"
                            variant="ghost"
                            className="h-7 w-7 p-0 text-blue-500 hover:text-blue-600 hover:bg-blue-500/10"
                            onClick={() => handleCompleteBooking(booking)}
                          >
                            <Check className="h-4 w-4" />
                          </Button>
                        )}
                        <Button
                          size="sm"
                          variant="ghost"
                          className="h-7 w-7 p-0 text-red-500 hover:text-red-600 hover:bg-red-500/10"
                          onClick={() => {
                            setSelectedBooking(booking);
                            setCancelDialogOpen(true);
                          }}
                        >
                          <X className="h-4 w-4" />
                        </Button>
                      </div>
                    )}
                  </div>
                </div>
              </Card>
            ))}
          </div>
        )}
      </ScrollArea>

      {/* Actions Row */}
      <div className="p-3 border-t flex gap-2">
        <Button variant="outline" size="sm" className="flex-1" onClick={exportToCSV}>
          <Download className="h-4 w-4 mr-2" />
          {t('bookings.exportCSV', 'CSV')}
        </Button>
        <Button variant="outline" size="sm" className="flex-1" onClick={fetchBookings}>
          <RefreshCw className="h-4 w-4 mr-2" />
          {t('bookings.refresh', 'Refresh')}
        </Button>
      </div>

      {/* Cancel Confirmation Dialog */}
      <AlertDialog open={cancelDialogOpen} onOpenChange={setCancelDialogOpen}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>{t('bookings.cancelTitle', 'Cancel Booking?')}</AlertDialogTitle>
            <AlertDialogDescription>
              {t('bookings.cancelDescription', 'Are you sure you want to cancel this booking? The client will be notified.')}
            </AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel>{t('common.cancel', 'Cancel')}</AlertDialogCancel>
            <AlertDialogAction onClick={handleCancelBooking} className="bg-destructive text-destructive-foreground">
              {t('bookings.confirmCancel', 'Yes, Cancel Booking')}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

/**
 * EventRegistrationsList - List of registrations for a specific event
 * Features: Status management, ticket view, check-in
 */
import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { supabase } from '@/platform/supabase/client';
import { useAuth } from '@/hooks/user/useAuth';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Input } from '@/components/ui/input';
import {
  ArrowLeft,
  Search,
  Download,
  QrCode,
  User,
  Mail,
  Phone,
  Ticket,
  Check,
  X,
  Clock,
  Loader2,
  CheckCircle2,
  XCircle,
  AlertCircle,
} from 'lucide-react';
import { toast } from 'sonner';
import { format } from 'date-fns';
import { ru, kk, enUS } from 'date-fns/locale';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { QRCodeSVG } from 'qrcode.react';

interface Registration {
  id: string;
  attendee_name: string;
  attendee_email: string;
  attendee_phone: string | null;
  answers_json: unknown;
  status: string;
  payment_status: string;
  created_at: string;
  utm_json?: Record<string, string>;
  event_tickets: Array<{
    id: string;
    ticket_code: string;
    status: string;
    checked_in_at: string | null;
  }> | null;
}

interface EventRegistrationsListProps {
  eventId: string;
  eventTitle: string;
  isPremium: boolean;
  onBack: () => void;
  onExport: () => void;
  onOpenScanner: () => void;
}

const STATUS_CONFIG = {
  pending: { bg: 'bg-yellow-500/20', text: 'text-yellow-500', icon: AlertCircle, label: 'Ожидает' },
  confirmed: { bg: 'bg-green-500/20', text: 'text-green-500', icon: CheckCircle2, label: 'Подтвержден' },
  rejected: { bg: 'bg-red-500/20', text: 'text-red-500', icon: XCircle, label: 'Отклонен' },
  cancelled: { bg: 'bg-gray-500/20', text: 'text-gray-500', icon: X, label: 'Отменен' },
};

const TICKET_STATUS_CONFIG = {
  valid: { bg: 'bg-green-500/20', text: 'text-green-500', label: 'Активен' },
  used: { bg: 'bg-blue-500/20', text: 'text-blue-500', label: 'Использован' },
  cancelled: { bg: 'bg-gray-500/20', text: 'text-gray-500', label: 'Отменен' },
};

export function EventRegistrationsList({
  eventId,
  eventTitle,
  isPremium,
  onBack,
  onExport,
  onOpenScanner,
}: EventRegistrationsListProps) {
  const { t, i18n } = useTranslation();
  const { user } = useAuth();
  const [registrations, setRegistrations] = useState<Registration[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedRegistration, setSelectedRegistration] = useState<Registration | null>(null);

  const locale = i18n.language === 'ru' ? ru : i18n.language === 'kk' ? kk : enUS;

  const fetchRegistrations = async () => {
    if (!user) return;
    setLoading(true);

    try {
      const { data, error } = await supabase
        .from('event_registrations')
        .select('id, attendee_name, attendee_email, attendee_phone, answers_json, status, payment_status, created_at, utm_json, event_tickets(id, ticket_code, status, checked_in_at)')
        .eq('event_id', eventId)
        .eq('owner_id', user.id)
        .order('created_at', { ascending: false });

      if (error) throw error;
      // Use unknown cast to bypass strict typing since types may be out of sync
      setRegistrations((data as unknown as Registration[]) || []);
    } catch (error) {
      console.error('Error fetching registrations:', error);
      toast.error(t('events.fetchError', 'Не удалось загрузить регистрации'));
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchRegistrations();
  }, [eventId, user]);

  const updateStatus = async (registrationId: string, newStatus: 'confirmed' | 'rejected') => {
    try {
      const { error } = await supabase
        .from('event_registrations')
        .update({ status: newStatus, updated_at: new Date().toISOString() })
        .eq('id', registrationId);

      if (error) throw error;
      toast.success(t(`events.status${newStatus}`, newStatus === 'confirmed' ? 'Подтверждено' : 'Отклонено'));
      fetchRegistrations();
    } catch (error) {
      console.error('Status update error:', error);
      toast.error(t('events.updateError', 'Ошибка обновления'));
    }
  };

  const filteredRegistrations = registrations.filter(reg => {
    if (!searchQuery) return true;
    const query = searchQuery.toLowerCase();
    return (
      reg.attendee_name.toLowerCase().includes(query) ||
      reg.attendee_email.toLowerCase().includes(query) ||
      reg.attendee_phone?.includes(query) ||
      reg.event_tickets?.[0]?.ticket_code?.toLowerCase().includes(query)
    );
  });

  const stats = {
    total: registrations.length,
    confirmed: registrations.filter(r => r.status === 'confirmed').length,
    pending: registrations.filter(r => r.status === 'pending').length,
    checkedIn: registrations.filter(r => (r.event_tickets as Array<{ status: string }>)?.[0]?.status === 'used').length,
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-16">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  return (
    <div className="h-full flex flex-col">
      {/* Header */}
      <div className="p-3 border-b flex items-center gap-3">
        <Button variant="ghost" size="icon" onClick={onBack}>
          <ArrowLeft className="h-5 w-5" />
        </Button>
        <div className="flex-1 min-w-0">
          <h2 className="font-semibold truncate">{eventTitle}</h2>
          <p className="text-xs text-muted-foreground">{stats.total} {t('events.registrations', 'регистраций')}</p>
        </div>
      </div>

      {/* Stats */}
      <div className="grid grid-cols-4 gap-2 p-3 border-b">
        <div className="text-center p-2 rounded-lg bg-primary/10">
          <div className="text-lg font-bold text-primary">{stats.total}</div>
          <div className="text-[10px] text-muted-foreground">{t('events.total', 'Всего')}</div>
        </div>
        <div className="text-center p-2 rounded-lg bg-green-500/10">
          <div className="text-lg font-bold text-green-500">{stats.confirmed}</div>
          <div className="text-[10px] text-muted-foreground">{t('events.confirmed', 'Подтв.')}</div>
        </div>
        <div className="text-center p-2 rounded-lg bg-yellow-500/10">
          <div className="text-lg font-bold text-yellow-500">{stats.pending}</div>
          <div className="text-[10px] text-muted-foreground">{t('events.pending', 'Ожидают')}</div>
        </div>
        <div className="text-center p-2 rounded-lg bg-blue-500/10">
          <div className="text-lg font-bold text-blue-500">{stats.checkedIn}</div>
          <div className="text-[10px] text-muted-foreground">{t('events.checkedIn', 'Отмечены')}</div>
        </div>
      </div>

      {/* Search & Actions */}
      <div className="p-3 border-b flex gap-2">
        <div className="relative flex-1">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder={t('events.searchRegistrations', 'Поиск по имени, email, билету...')}
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="h-9 pl-10 rounded-lg bg-muted/50 border-0"
          />
        </div>
        <Button variant="outline" size="icon" onClick={onExport} title={t('events.export', 'Экспорт')}>
          <Download className="h-4 w-4" />
        </Button>
        <Button
          variant={isPremium ? 'default' : 'outline'}
          size="icon"
          onClick={onOpenScanner}
          title={t('events.scanner', 'QR-сканер')}
        >
          <QrCode className="h-4 w-4" />
        </Button>
      </div>

      {/* Registrations List */}
      <ScrollArea className="flex-1">
        {filteredRegistrations.length === 0 ? (
          <div className="p-8 text-center text-muted-foreground">
            <User className="h-12 w-12 mx-auto mb-3 opacity-50" />
            <p className="text-sm">{t('events.noRegistrations', 'Нет регистраций')}</p>
          </div>
        ) : (
          <div className="divide-y">
            {filteredRegistrations.map((reg) => {
              const statusConfig = STATUS_CONFIG[reg.status as keyof typeof STATUS_CONFIG];
              const StatusIcon = statusConfig.icon;
              const ticket = reg.event_tickets?.[0];
              const ticketStatusConfig = ticket ? TICKET_STATUS_CONFIG[ticket.status as keyof typeof TICKET_STATUS_CONFIG] : null;

              return (
                <Card
                  key={reg.id}
                  className="m-3 p-3 border rounded-lg cursor-pointer hover:border-primary/50 transition-colors"
                  onClick={() => setSelectedRegistration(reg)}
                >
                  <div className="flex items-start gap-3">
                    {/* Avatar */}
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center ${statusConfig.bg}`}>
                      <StatusIcon className={`h-5 w-5 ${statusConfig.text}`} />
                    </div>

                    {/* Content */}
                    <div className="flex-1 min-w-0">
                      <div className="flex items-center justify-between gap-2 mb-1">
                        <span className="font-medium text-sm truncate">{reg.attendee_name}</span>
                        <Badge variant="outline" className={`${statusConfig.bg} ${statusConfig.text} text-[10px]`}>
                          {t(`events.status.${reg.status}`, statusConfig.label)}
                        </Badge>
                      </div>

                      <div className="space-y-0.5 text-xs text-muted-foreground">
                        <div className="flex items-center gap-1">
                          <Mail className="h-3 w-3" />
                          <span className="truncate">{reg.attendee_email}</span>
                        </div>
                        {reg.attendee_phone && (
                          <div className="flex items-center gap-1">
                            <Phone className="h-3 w-3" />
                            {reg.attendee_phone}
                          </div>
                        )}
                      </div>

                      {/* Ticket info */}
                      {ticket && (
                        <div className="flex items-center gap-2 mt-2">
                          <Badge variant="outline" className="text-[10px] font-mono">
                            <Ticket className="h-3 w-3 mr-1" />
                            {ticket.ticket_code}
                          </Badge>
                          {ticketStatusConfig && (
                            <Badge variant="outline" className={`${ticketStatusConfig.bg} ${ticketStatusConfig.text} text-[10px]`}>
                              {ticketStatusConfig.label}
                            </Badge>
                          )}
                        </div>
                      )}
                    </div>

                    {/* Quick actions for pending */}
                    {reg.status === 'pending' && (
                      <div className="flex gap-1">
                        <Button
                          size="icon"
                          variant="ghost"
                          className="h-8 w-8 text-green-500 hover:bg-green-500/10"
                          onClick={(e) => {
                            e.stopPropagation();
                            updateStatus(reg.id, 'confirmed');
                          }}
                        >
                          <Check className="h-4 w-4" />
                        </Button>
                        <Button
                          size="icon"
                          variant="ghost"
                          className="h-8 w-8 text-red-500 hover:bg-red-500/10"
                          onClick={(e) => {
                            e.stopPropagation();
                            updateStatus(reg.id, 'rejected');
                          }}
                        >
                          <X className="h-4 w-4" />
                        </Button>
                      </div>
                    )}
                  </div>
                </Card>
              );
            })}
          </div>
        )}
      </ScrollArea>

      {/* Registration Detail Dialog */}
      <Dialog open={!!selectedRegistration} onOpenChange={() => setSelectedRegistration(null)}>
        <DialogContent className="max-w-md">
          <DialogHeader>
            <DialogTitle>{t('events.registrationDetails', 'Детали регистрации')}</DialogTitle>
          </DialogHeader>
          {selectedRegistration && (
            <div className="space-y-4">
              <div className="space-y-2">
                <div className="flex items-center gap-2">
                  <User className="h-4 w-4 text-muted-foreground" />
                  <span className="font-medium">{selectedRegistration.attendee_name}</span>
                </div>
                <div className="flex items-center gap-2">
                  <Mail className="h-4 w-4 text-muted-foreground" />
                  <a href={`mailto:${selectedRegistration.attendee_email}`} className="text-primary hover:underline">
                    {selectedRegistration.attendee_email}
                  </a>
                </div>
                {selectedRegistration.attendee_phone && (
                  <div className="flex items-center gap-2">
                    <Phone className="h-4 w-4 text-muted-foreground" />
                    <a href={`tel:${selectedRegistration.attendee_phone}`} className="text-primary hover:underline">
                      {selectedRegistration.attendee_phone}
                    </a>
                  </div>
                )}
                <div className="flex items-center gap-2">
                  <Clock className="h-4 w-4 text-muted-foreground" />
                  <span className="text-sm text-muted-foreground">
                    {format(new Date(selectedRegistration.created_at), 'd MMM yyyy, HH:mm', { locale })}
                  </span>
                </div>
              </div>

              {/* QR Code */}
              {selectedRegistration.event_tickets?.[0] && isPremium && (
                <div className="flex flex-col items-center p-4 bg-muted rounded-lg">
                  <QRCodeSVG
                    value={selectedRegistration.event_tickets[0].ticket_code}
                    size={160}
                    level="H"
                  />
                  <p className="mt-2 font-mono text-sm">{selectedRegistration.event_tickets[0].ticket_code}</p>
                  {selectedRegistration.event_tickets[0].checked_in_at && (
                    <Badge className="mt-2 bg-blue-500/20 text-blue-500">
                      <Check className="h-3 w-3 mr-1" />
                      {t('events.checkedInAt', 'Отмечен')}: {format(new Date(selectedRegistration.event_tickets[0].checked_in_at), 'HH:mm', { locale })}
                    </Badge>
                  )}
                </div>
              )}

              {/* UTM Attribution (Pro) */}
              {isPremium && selectedRegistration.utm_json && Object.keys(selectedRegistration.utm_json).length > 0 && (
                <div className="rounded-lg border border-border/60 p-3 space-y-2">
                  <p className="text-xs font-medium text-muted-foreground">{t('events.utmAttribution', 'Источник трафика')}</p>
                  <div className="grid grid-cols-2 gap-2 text-xs">
                    {selectedRegistration.utm_json.utm_source && (
                      <div>
                        <span className="text-muted-foreground">Source: </span>
                        <span className="font-medium">{selectedRegistration.utm_json.utm_source}</span>
                      </div>
                    )}
                    {selectedRegistration.utm_json.utm_medium && (
                      <div>
                        <span className="text-muted-foreground">Medium: </span>
                        <span className="font-medium">{selectedRegistration.utm_json.utm_medium}</span>
                      </div>
                    )}
                    {selectedRegistration.utm_json.utm_campaign && (
                      <div className="col-span-2">
                        <span className="text-muted-foreground">Campaign: </span>
                        <span className="font-medium">{selectedRegistration.utm_json.utm_campaign}</span>
                      </div>
                    )}
                  </div>
                </div>
              )}

              {/* Actions */}
              {selectedRegistration.status === 'pending' && (
                <div className="flex gap-2">
                  <Button
                    className="flex-1"
                    variant="outline"
                    onClick={() => {
                      updateStatus(selectedRegistration.id, 'confirmed');
                      setSelectedRegistration(null);
                    }}
                  >
                    <Check className="h-4 w-4 mr-2" />
                    {t('events.confirm', 'Подтвердить')}
                  </Button>
                  <Button
                    className="flex-1"
                    variant="destructive"
                    onClick={() => {
                      updateStatus(selectedRegistration.id, 'rejected');
                      setSelectedRegistration(null);
                    }}
                  >
                    <X className="h-4 w-4 mr-2" />
                    {t('events.reject', 'Отклонить')}
                  </Button>
                </div>
              )}
            </div>
          )}
        </DialogContent>
      </Dialog>
    </div>
  );
}

'use client';

/**
 * EventsPanel - CRM tab for managing events and registrations
 * Features: Event list, registration management, QR scanner access, Excel/CSV export
 */
import { useState, useEffect, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { useRouter } from 'next/navigation';
import { supabase } from '@/platform/supabase/client';
import { useAuth } from '@/hooks/user/useAuth';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Tabs, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Input } from '@/components/ui/input';
import { DropdownMenu, DropdownMenuContent, DropdownMenuItem, DropdownMenuTrigger } from '@/components/ui/dropdown-menu';
import {
  CalendarDays,
  Users,
  QrCode,
  Download,
  RefreshCw,
  Search,
  ChevronRight,
  Clock,
  MapPin,
  Loader2,
  FileSpreadsheet,
  FileText,
} from 'lucide-react';
import { toast } from 'sonner';
import { format, isPast } from 'date-fns';
import { ru, kk, enUS } from 'date-fns/locale';
import { getI18nText, type SupportedLanguage } from '@/lib/i18n-helpers';
import { EventRegistrationsList } from './EventRegistrationsList';
import { exportToExcel, exportToCSV } from '@/lib/export/excel-export';
import type { EventFormField } from '@/types/page';

interface Event {
  id: string;
  title_i18n_json: unknown;
  description_i18n_json: unknown;
  cover_url: string | null;
  start_at: string | null;
  end_at: string | null;
  capacity: number | null;
  status: string;
  is_paid: boolean;
  price_amount: number | null;
  currency: string | null;
  location_value: string | null;
  created_at: string;
  registration_count?: number;
  form_schema_json?: unknown;
}

interface EventsPanelProps {
  isPremium: boolean;
}

export function EventsPanel({ isPremium }: EventsPanelProps) {
  const { t, i18n } = useTranslation();
  const { user } = useAuth();
  const router = useRouter();
  const [events, setEvents] = useState<Event[]>([]);
  const [loading, setLoading] = useState(true);
  const [statusFilter, setStatusFilter] = useState<'all' | 'published' | 'draft' | 'closed'>('all');
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedEventId, setSelectedEventId] = useState<string | null>(null);

  const language = i18n.language as SupportedLanguage;
  const locale = i18n.language === 'ru' ? ru : i18n.language === 'kk' ? kk : enUS;

  const fetchEvents = async () => {
    if (!user) return;
    setLoading(true);

    try {
      // Fetch events
      const { data: eventsData, error: eventsError } = await supabase
        .from('events')
        .select('*')
        .eq('owner_id', user.id)
        .order('created_at', { ascending: false });

      if (eventsError) throw eventsError;

      // Fetch registration counts
      const eventIds = (eventsData || []).map(e => e.id);
      if (eventIds.length > 0) {
        const { data: regCounts } = await supabase
          .from('event_registrations')
          .select('event_id')
          .in('event_id', eventIds)
          .in('status', ['confirmed', 'pending']);

        const countMap: Record<string, number> = {};
        (regCounts || []).forEach(r => {
          countMap[r.event_id] = (countMap[r.event_id] || 0) + 1;
        });

        const eventsWithCounts = (eventsData || []).map(event => ({
          ...event,
          registration_count: countMap[event.id] || 0,
        })) as Event[];
        setEvents(eventsWithCounts);
      } else {
        setEvents([]);
      }
    } catch (error) {
      console.error('Error fetching events:', error);
      toast.error(t('events.fetchError', 'Не удалось загрузить события'));
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchEvents();
  }, [user]);

  const filteredEvents = useMemo(() => {
    return events.filter(event => {
      const matchesStatus = statusFilter === 'all' || event.status === statusFilter;
      const titleJson = (event.title_i18n_json || {}) as Record<string, string>;
      const title = getI18nText(titleJson, language);
      const matchesSearch = !searchQuery ||
        title.toLowerCase().includes(searchQuery.toLowerCase());
      return matchesStatus && matchesSearch;
    });
  }, [events, statusFilter, searchQuery, language]);

  const stats = useMemo(() => ({
    total: events.length,
    published: events.filter(e => e.status === 'published').length,
    draft: events.filter(e => e.status === 'draft').length,
    totalRegistrations: events.reduce((sum, e) => sum + (e.registration_count || 0), 0),
  }), [events]);

  const handleExport = async (eventId: string, formatType: 'xlsx' | 'csv' = 'csv') => {
    try {
      // Fetch event details for form fields
      const event = events.find(e => e.id === eventId);
      const eventTitle = event
        ? getI18nText((event.title_i18n_json || {}) as Record<string, string>, language)
        : 'Event';
      const formFields = (event?.form_schema_json as EventFormField[]) || [];

      // Fetch registrations
      const { data: registrations, error } = await supabase
        .from('event_registrations')
        .select('id, attendee_name, attendee_email, attendee_phone, answers_json, status, payment_status, created_at, event_tickets(ticket_code, status, checked_in_at)')
        .eq('event_id', eventId)
        .order('created_at', { ascending: false });

      if (error) throw error;
      if (!registrations || registrations.length === 0) {
        toast.error(t('events.noRegistrations', 'Нет регистраций для экспорта'));
        return;
      }

      // Transform data for export
      const transformedRegistrations = (registrations as unknown as Array<{
        id: string;
        attendee_name: string;
        attendee_email: string;
        attendee_phone: string | null;
        answers_json: Record<string, unknown> | null;
        status: string;
        payment_status: string;
        created_at: string;
        event_tickets: Array<{
          ticket_code: string;
          status: string;
          checked_in_at: string | null;
        }> | null;
      }>);

      const exportData = {
        eventTitle,
        registrations: transformedRegistrations,
        formFields,
        language,
        includeAnswers: true,
      };

      if (formatType === 'xlsx' && isPremium) {
        await exportToExcel(exportData);
        toast.success(t('events.exportSuccess', 'Экспорт в Excel завершен'));
      } else {
        exportToCSV(exportData);
        toast.success(t('events.exportSuccess', 'Экспорт в CSV завершен'));
      }
    } catch (error) {
      console.error('Export error:', error);
      toast.error(t('events.exportError', 'Ошибка экспорта'));
    }
  };

  const openScanner = (eventId: string) => {
    if (!isPremium) {
      toast.error(t('events.scannerProOnly', 'QR-сканер доступен в Pro'));
      return;
    }
    router.push(`/dashboard/events/${eventId}/scanner`);
  };

  const getStatusBadge = (status: string) => {
    switch (status) {
      case 'published':
        return <Badge className="bg-green-500/20 text-green-500 border-green-500/30">{t('events.published', 'Опубликован')}</Badge>;
      case 'draft':
        return <Badge className="bg-yellow-500/20 text-yellow-500 border-yellow-500/30">{t('events.draft', 'Черновик')}</Badge>;
      case 'closed':
        return <Badge className="bg-gray-500/20 text-gray-500 border-gray-500/30">{t('events.closed', 'Закрыт')}</Badge>;
      default:
        return null;
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center py-16">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  // If viewing a specific event's registrations
  if (selectedEventId) {
    const selectedEvent = events.find(e => e.id === selectedEventId);
    const selectedTitle = selectedEvent
      ? getI18nText((selectedEvent.title_i18n_json || {}) as Record<string, string>, language)
      : '';
    return (
      <EventRegistrationsList
        eventId={selectedEventId}
        eventTitle={selectedTitle}
        isPremium={isPremium}
        onBack={() => setSelectedEventId(null)}
        onExport={() => handleExport(selectedEventId, 'csv')}
        onOpenScanner={() => openScanner(selectedEventId)}
      />
    );
  }

  return (
    <div className="h-full flex flex-col">
      {/* Stats */}
      <div className="grid grid-cols-4 gap-2 p-3 border-b">
        <div className="text-center p-2 rounded-lg bg-primary/10">
          <div className="text-lg font-bold text-primary">{stats.total}</div>
          <div className="text-[10px] text-muted-foreground">{t('events.total', 'Всего')}</div>
        </div>
        <div className="text-center p-2 rounded-lg bg-green-500/10">
          <div className="text-lg font-bold text-green-500">{stats.published}</div>
          <div className="text-[10px] text-muted-foreground">{t('events.active', 'Активных')}</div>
        </div>
        <div className="text-center p-2 rounded-lg bg-yellow-500/10">
          <div className="text-lg font-bold text-yellow-500">{stats.draft}</div>
          <div className="text-[10px] text-muted-foreground">{t('events.drafts', 'Черновики')}</div>
        </div>
        <div className="text-center p-2 rounded-lg bg-blue-500/10">
          <div className="text-lg font-bold text-blue-500">{stats.totalRegistrations}</div>
          <div className="text-[10px] text-muted-foreground">{t('events.registrations', 'Заявок')}</div>
        </div>
      </div>

      {/* Filter Tabs */}
      <Tabs value={statusFilter} onValueChange={(v: string) => setStatusFilter(v as typeof statusFilter)} className="w-full">
        <TabsList className="grid w-full grid-cols-4 mx-0 rounded-none border-b bg-transparent h-10">
          <TabsTrigger value="all" className="rounded-none data-[state=active]:border-b-2 data-[state=active]:border-primary text-xs">
            {t('events.all', 'Все')}
          </TabsTrigger>
          <TabsTrigger value="published" className="rounded-none data-[state=active]:border-b-2 data-[state=active]:border-primary text-xs">
            {t('events.published', 'Активные')}
          </TabsTrigger>
          <TabsTrigger value="draft" className="rounded-none data-[state=active]:border-b-2 data-[state=active]:border-primary text-xs">
            {t('events.draft', 'Черновики')}
          </TabsTrigger>
          <TabsTrigger value="closed" className="rounded-none data-[state=active]:border-b-2 data-[state=active]:border-primary text-xs">
            {t('events.closed', 'Закрытые')}
          </TabsTrigger>
        </TabsList>
      </Tabs>

      {/* Search */}
      <div className="p-3 border-b">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            placeholder={t('events.searchPlaceholder', 'Поиск по названию...')}
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            className="h-9 pl-10 rounded-lg bg-muted/50 border-0"
          />
        </div>
      </div>

      {/* Events List */}
      <ScrollArea className="flex-1">
        {filteredEvents.length === 0 ? (
          <div className="p-8 text-center text-muted-foreground">
            <CalendarDays className="h-12 w-12 mx-auto mb-3 opacity-50" />
            <p className="text-sm mb-4">{t('events.noEvents', 'У вас пока нет событий')}</p>
            <p className="text-xs text-muted-foreground">
              {t('events.createHint', 'Создайте событие через редактор страницы')}
            </p>
          </div>
        ) : (
          <div className="divide-y">
            {filteredEvents.map((event) => {
              const titleJson = (event.title_i18n_json || {}) as Record<string, string>;
              const title = getI18nText(titleJson, language);
              const isEventPast = event.end_at ? isPast(new Date(event.end_at)) : false;

              return (
                <Card
                  key={event.id}
                  className="m-3 p-3 border rounded-lg cursor-pointer hover:border-primary/50 transition-colors"
                  onClick={() => setSelectedEventId(event.id)}
                >
                  <div className="flex items-start gap-3">
                    {/* Cover */}
                    <div className="w-16 h-16 rounded-lg overflow-hidden bg-muted shrink-0">
                      {event.cover_url ? (
                        <img src={event.cover_url} alt={title} className="w-full h-full object-cover" />
                      ) : (
                        <div className="w-full h-full flex items-center justify-center bg-gradient-to-br from-primary/20 to-primary/5">
                          <CalendarDays className="h-6 w-6 text-primary/50" />
                        </div>
                      )}
                    </div>

                    {/* Content */}
                    <div className="flex-1 min-w-0">
                      <div className="flex items-start justify-between gap-2 mb-1">
                        <h3 className="font-semibold text-sm truncate">{title}</h3>
                        {getStatusBadge(event.status)}
                      </div>

                      <div className="space-y-1 text-xs text-muted-foreground">
                        {event.start_at && (
                          <div className="flex items-center gap-1">
                            <Clock className="h-3 w-3" />
                            {format(new Date(event.start_at), 'd MMM yyyy, HH:mm', { locale })}
                            {isEventPast && (
                              <Badge variant="outline" className="ml-1 text-[10px] h-4">
                                {t('events.past', 'Прошел')}
                              </Badge>
                            )}
                          </div>
                        )}
                        {event.location_value && (
                          <div className="flex items-center gap-1">
                            <MapPin className="h-3 w-3" />
                            <span className="truncate">{event.location_value}</span>
                          </div>
                        )}
                      </div>

                      {/* Stats row */}
                      <div className="flex items-center gap-3 mt-2">
                        <div className="flex items-center gap-1 text-xs">
                          <Users className="h-3 w-3 text-primary" />
                          <span className="font-medium">{event.registration_count || 0}</span>
                          {event.capacity && (
                            <span className="text-muted-foreground">/ {event.capacity}</span>
                          )}
                        </div>
                        {event.is_paid && event.price_amount && (
                          <Badge variant="secondary" className="text-[10px] h-5">
                            {event.price_amount} {event.currency || 'KZT'}
                          </Badge>
                        )}
                      </div>
                    </div>

                    <ChevronRight className="h-5 w-5 text-muted-foreground shrink-0" />
                  </div>
                </Card>
              );
            })}
          </div>
        )}
      </ScrollArea>

      {/* Actions Row */}
      <div className="p-3 border-t flex gap-2">
        <Button variant="outline" size="sm" className="flex-1" onClick={fetchEvents}>
          <RefreshCw className="h-4 w-4 mr-2" />
          {t('events.refresh', 'Обновить')}
        </Button>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { formatDateTime } from '@/lib/utils/format';
import { useLeads, useLeadInteractions, LeadStatus, InteractionType } from '@/hooks/crm/useLeads';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Badge } from '@/components/ui/badge';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Card } from '@/components/ui/card';
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
} from '@/components/ui/sheet';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogFooter,
  AlertDialogHeader,
  AlertDialogTitle,
  AlertDialogTrigger,
} from '@/components/ui/alert-dialog';
import {
  User,
  Mail,
  Phone,
  Calendar,
  Trash2,
  MessageSquare,
  PhoneCall,
  Video,
  FileText,
  Send,
  Tag
} from 'lucide-react';
import type { Lead } from '@/hooks/crm/useLeads';

interface LeadDetailsProps {
  lead: Lead;
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

const statusColors: Record<LeadStatus, string> = {
  new: 'bg-blue-500/20 text-blue-500 border-blue-500/30',
  contacted: 'bg-yellow-500/20 text-yellow-500 border-yellow-500/30',
  qualified: 'bg-purple-500/20 text-purple-500 border-purple-500/30',
  converted: 'bg-green-500/20 text-green-500 border-green-500/30',
  lost: 'bg-red-500/20 text-red-500 border-red-500/30',
};

const interactionIcons: Record<InteractionType, React.ReactNode> = {
  note: <FileText className="h-3.5 w-3.5 sm:h-4 sm:w-4" />,
  call: <PhoneCall className="h-3.5 w-3.5 sm:h-4 sm:w-4" />,
  email: <Mail className="h-3.5 w-3.5 sm:h-4 sm:w-4" />,
  message: <MessageSquare className="h-3.5 w-3.5 sm:h-4 sm:w-4" />,
  meeting: <Video className="h-3.5 w-3.5 sm:h-4 sm:w-4" />,
};

const sourceColors: Record<string, string> = {
  form: 'bg-emerald-500/20 text-emerald-500 border-emerald-500/30',
  messenger: 'bg-indigo-500/20 text-indigo-500 border-indigo-500/30',
  manual: 'bg-slate-500/20 text-slate-500 border-slate-500/30',
  page_view: 'bg-cyan-500/20 text-cyan-500 border-cyan-500/30',
  other: 'bg-gray-500/20 text-gray-500 border-gray-500/30',
};

const sourceIcons: Record<string, string> = {
  form: '📝',
  messenger: '💬',
  manual: '✏️',
  page_view: '👁️',
  other: '📌',
};

export function LeadDetails({ lead, open, onOpenChange }: LeadDetailsProps) {
  const { t, i18n } = useTranslation();
  const { updateLead, deleteLead, saving } = useLeads();
  const { interactions, loading: interactionsLoading, addInteraction } = useLeadInteractions(lead.id);

  const [status, setStatus] = useState<LeadStatus>(lead.status);
  const [notes, setNotes] = useState(lead.notes || '');
  const [newInteractionType, setNewInteractionType] = useState<InteractionType>('note');
  const [newInteractionContent, setNewInteractionContent] = useState('');
  const [hasChanges, setHasChanges] = useState(false);

  const handleStatusChange = async (newStatus: LeadStatus) => {
    setStatus(newStatus);
    await updateLead(lead.id, { status: newStatus });
  };

  const handleSaveNotes = async () => {
    await updateLead(lead.id, { notes });
    setHasChanges(false);
  };

  const handleAddInteraction = async () => {
    if (!newInteractionContent.trim()) return;

    await addInteraction(newInteractionType, newInteractionContent);
    setNewInteractionContent('');
  };

  const handleDelete = async () => {
    await deleteLead(lead.id);
    onOpenChange(false);
  };

  const formatDate = (dateStr: string) => formatDateTime(dateStr, i18n.language);

  const formatShortDate = (dateStr: string) => formatDateTime(dateStr, i18n.language);

  const statuses: LeadStatus[] = ['new', 'contacted', 'qualified', 'converted', 'lost'];
  const interactionTypes: InteractionType[] = ['note', 'call', 'email', 'message', 'meeting'];

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent className="w-full sm:max-w-lg p-0 flex flex-col">
        <SheetHeader className="p-3 sm:p-4 border-b">
          <SheetTitle className="flex items-center gap-2 text-base sm:text-lg">
            <User className="h-4 w-4 sm:h-5 sm:w-5" />
            <span className="truncate">{lead.name}</span>
          </SheetTitle>
        </SheetHeader>

        <ScrollArea className="flex-1">
          <div className="p-3 sm:p-4 space-y-4 sm:space-y-6">
            {/* Contact Info - Compact card */}
            <Card className="p-3 sm:p-4 space-y-2 sm:space-y-3">
              <h4 className="font-medium text-xs sm:text-sm text-muted-foreground">
                {t('crm.contactInfo', 'Contact Information')}
              </h4>
              {lead.email && (
                <a
                  href={`mailto:${lead.email}`}
                  className="flex items-center gap-2 text-xs sm:text-sm hover:text-primary transition-colors"
                >
                  <Mail className="h-3.5 w-3.5 sm:h-4 sm:w-4 shrink-0" />
                  <span className="truncate">{lead.email}</span>
                </a>
              )}
              {lead.phone && (
                <a
                  href={`tel:${lead.phone}`}
                  className="flex items-center gap-2 text-xs sm:text-sm hover:text-primary transition-colors"
                >
                  <Phone className="h-3.5 w-3.5 sm:h-4 sm:w-4" />
                  {lead.phone}
                </a>
              )}
              <div className="flex items-center gap-2 text-xs sm:text-sm text-muted-foreground">
                <Calendar className="h-3.5 w-3.5 sm:h-4 sm:w-4" />
                {formatShortDate(lead.created_at)}
              </div>
              <div className="flex items-center gap-2">
                <Badge variant="outline" className={`${sourceColors[lead.source]} text-[10px] sm:text-xs`}>
                  {sourceIcons[lead.source]} {t(`crm.source.${lead.source}`, lead.source)}
                </Badge>
              </div>
            </Card>

            {/* Form Data / Metadata - Compact */}
            {lead.metadata && Object.keys(lead.metadata).length > 0 && (
              <Card className="p-3 sm:p-4">
                <h4 className="font-medium text-xs sm:text-sm text-muted-foreground mb-2 sm:mb-3 flex items-center gap-2">
                  <Tag className="h-3.5 w-3.5 sm:h-4 sm:w-4" />
                  {t('crm.formData', 'Form Data')}
                </h4>
                <div className="space-y-1.5 sm:space-y-2">
                  {Object.entries(lead.metadata).map(([key, value]) => (
                    <div key={key} className="flex flex-col gap-0.5 p-2 bg-accent/50 rounded-lg">
                      <span className="text-[10px] sm:text-xs font-medium text-muted-foreground uppercase">{key}</span>
                      <span className="text-xs sm:text-sm break-words">{String(value)}</span>
                    </div>
                  ))}
                </div>
              </Card>
            )}

            {/* Status - Full width select */}
            <div>
              <Label className="text-xs sm:text-sm">{t('crm.status.label', 'Status')}</Label>
              <Select value={status} onValueChange={handleStatusChange}>
                <SelectTrigger className="mt-1 h-9 sm:h-10">
                  <SelectValue>
                    <Badge variant="outline" className={`${statusColors[status]} text-[10px] sm:text-xs`}>
                      {t(`crm.status.${status}`, status)}
                    </Badge>
                  </SelectValue>
                </SelectTrigger>
                <SelectContent>
                  {statuses.map(s => (
                    <SelectItem key={s} value={s}>
                      <Badge variant="outline" className={`${statusColors[s]} text-[10px] sm:text-xs`}>
                        {t(`crm.status.${s}`, s)}
                      </Badge>
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>
            </div>

            {/* Notes - Compact textarea */}
            <div>
              <div className="flex items-center justify-between mb-1">
                <Label className="text-xs sm:text-sm">{t('crm.notes', 'Notes')}</Label>
                {hasChanges && (
                  <Button size="sm" variant="ghost" onClick={handleSaveNotes} disabled={saving} className="h-7 text-xs">
                    {t('editor.save', 'Save')}
                  </Button>
                )}
              </div>
              <Textarea
                value={notes}
                onChange={(e) => {
                  setNotes(e.target.value);
                  setHasChanges(true);
                }}
                placeholder={t('crm.notesPlaceholder', 'Add notes...')}
                rows={2}
                className="text-sm resize-none"
              />
            </div>

            {/* Add Interaction - Compact */}
            <Card className="p-3 sm:p-4">
              <h4 className="font-medium text-xs sm:text-sm text-muted-foreground mb-2 sm:mb-3">
                {t('crm.addInteraction', 'Add Interaction')}
              </h4>
              <div className="space-y-2 sm:space-y-3">
                {/* Interaction type buttons - Compact grid */}
                <div className="grid grid-cols-5 gap-1.5 sm:gap-2">
                  {interactionTypes.map(type => (
                    <Button
                      key={type}
                      size="sm"
                      variant={newInteractionType === type ? 'default' : 'outline'}
                      onClick={() => setNewInteractionType(type)}
                      className="h-8 sm:h-9 p-0"
                    >
                      {interactionIcons[type]}
                    </Button>
                  ))}
                </div>
                <div className="flex gap-2">
                  <Input
                    value={newInteractionContent}
                    onChange={(e) => setNewInteractionContent(e.target.value)}
                    placeholder={t('crm.interactionPlaceholder', 'What happened?')}
                    onKeyDown={(e) => e.key === 'Enter' && handleAddInteraction()}
                    className="h-9 sm:h-10 text-sm"
                  />
                  <Button onClick={handleAddInteraction} disabled={!newInteractionContent.trim()} size="icon" className="h-9 w-9 sm:h-10 sm:w-10 shrink-0">
                    <Send className="h-3.5 w-3.5 sm:h-4 sm:w-4" />
                  </Button>
                </div>
              </div>
            </Card>

            {/* Interactions History - Compact list */}
            <div>
              <h4 className="font-medium text-xs sm:text-sm text-muted-foreground mb-2 sm:mb-3">
                {t('crm.history', 'History')} ({interactions.length})
              </h4>
              {interactionsLoading ? (
                <p className="text-xs sm:text-sm text-muted-foreground">{t('messages.loading', 'Loading...')}</p>
              ) : interactions.length === 0 ? (
                <p className="text-xs sm:text-sm text-muted-foreground">
                  {t('crm.noInteractions', 'No interactions yet')}
                </p>
              ) : (
                <div className="space-y-1.5 sm:space-y-2">
                  {interactions.map(interaction => (
                    <Card key={interaction.id} className="p-2.5 sm:p-3">
                      <div className="flex items-start gap-2">
                        <div className="p-1 sm:p-1.5 rounded-full bg-accent shrink-0">
                          {interactionIcons[interaction.type]}
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-1.5 sm:gap-2 flex-wrap">
                            <span className="text-[10px] sm:text-xs font-medium text-muted-foreground">
                              {t(`crm.interactionTypes.${interaction.type}`, interaction.type)}
                            </span>
                            <span className="text-[10px] sm:text-xs text-muted-foreground">
                              {formatShortDate(interaction.created_at)}
                            </span>
                          </div>
                          <p className="text-xs sm:text-sm mt-0.5 break-words">{interaction.content}</p>
                        </div>
                      </div>
                    </Card>
                  ))}
                </div>
              )}
            </div>

            {/* Delete - Full width */}
            <AlertDialog>
              <AlertDialogTrigger asChild>
                <Button variant="destructive" className="w-full h-9 sm:h-10 text-sm">
                  <Trash2 className="h-3.5 w-3.5 sm:h-4 sm:w-4 mr-2" />
                  {t('crm.deleteLead', 'Delete Lead')}
                </Button>
              </AlertDialogTrigger>
              <AlertDialogContent className="max-w-[calc(100vw-2rem)] sm:max-w-lg">
                <AlertDialogHeader>
                  <AlertDialogTitle className="text-base sm:text-lg">{t('crm.confirmDelete', 'Delete this lead?')}</AlertDialogTitle>
                  <AlertDialogDescription className="text-xs sm:text-sm">
                    {t('crm.deleteWarning', 'This action cannot be undone. All interactions will also be deleted.')}
                  </AlertDialogDescription>
                </AlertDialogHeader>
                <AlertDialogFooter className="gap-2 sm:gap-0">
                  <AlertDialogCancel className="h-9 sm:h-10 text-sm">{t('editor.cancel', 'Cancel')}</AlertDialogCancel>
                  <AlertDialogAction onClick={handleDelete} className="bg-destructive text-destructive-foreground h-9 sm:h-10 text-sm">
                    {t('editor.delete', 'Delete')}
                  </AlertDialogAction>
                </AlertDialogFooter>
              </AlertDialogContent>
            </AlertDialog>
          </div>
        </ScrollArea>
      </SheetContent>
    </Sheet>
  );
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { formatDateShort } from '@/lib/utils/format';
import { useLeads, LeadStatus } from '@/hooks/crm/useLeads';
import { usePremiumStatus } from '@/hooks/user/usePremiumStatus';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription
} from '@/components/ui/sheet';
import {
  Users,
  Plus,
  Search,
  Phone,
  Mail,
  Calendar,
  Crown,
  Download,
  BarChart3,
  CalendarDays
} from 'lucide-react';
import { toast } from 'sonner';
import { AddLeadDialog } from './AddLeadDialog';
import { LeadDetails } from './LeadDetails';
import { AnalyticsPanel } from './AnalyticsPanel';
import { BookingsPanel } from './BookingsPanel';
import { FunnelAnalysis } from './FunnelAnalysis';
import { HeatmapVisualization } from './HeatmapVisualization';
import { openPremiumPurchase } from '@/lib/utils/upgrade-utils';
import type { Lead } from '@/hooks/crm/useLeads';

interface LeadsPanelProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
}

const statusColors: Record<LeadStatus, string> = {
  new: 'bg-blue-500/20 text-blue-500 border-blue-500/30',
  contacted: 'bg-yellow-500/20 text-yellow-500 border-yellow-500/30',
  qualified: 'bg-purple-500/20 text-purple-500 border-purple-500/30',
  converted: 'bg-green-500/20 text-green-500 border-green-500/30',
  lost: 'bg-red-500/20 text-red-500 border-red-500/30',
};

const sourceColors: Record<string, string> = {
  form: 'bg-emerald-500/20 text-emerald-500 border-emerald-500/30',
  messenger: 'bg-indigo-500/20 text-indigo-500 border-indigo-500/30',
  manual: 'bg-slate-500/20 text-slate-500 border-slate-500/30',
  page_view: 'bg-cyan-500/20 text-cyan-500 border-cyan-500/30',
  other: 'bg-gray-500/20 text-gray-500 border-gray-500/30',
};

const sourceIcons: Record<string, string> = {
  form: '📝',
  messenger: '💬',
  manual: '✏️',
  page_view: '👁️',
  other: '📌',
};

export function LeadsPanel({ open, onOpenChange }: LeadsPanelProps) {
  const { t, i18n } = useTranslation();
  const { isPremium } = usePremiumStatus();
  const { leads, loading, getLeadStats, refreshLeads } = useLeads();
  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<LeadStatus | 'all'>('all');
  const [addDialogOpen, setAddDialogOpen] = useState(false);
  const [selectedLead, setSelectedLead] = useState<Lead | null>(null);
  const [activeTab, setActiveTab] = useState<'leads' | 'bookings' | 'analytics' | 'funnel' | 'heatmap'>('leads');
  const [sourceFilter, setSourceFilter] = useState<string>('all');

  const stats = getLeadStats();

  // Refresh leads when panel opens
  const handleOpenChange = (isOpen: boolean) => {
    if (isOpen) {
      refreshLeads();
    }
    onOpenChange(isOpen);
  };

  // Refresh leads when lead details closes
  const handleLeadDetailsClose = (isOpen: boolean) => {
    if (!isOpen) {
      setSelectedLead(null);
      refreshLeads();
    }
  };

  const filteredLeads = leads.filter(lead => {
    const matchesSearch = lead.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      (lead.email?.toLowerCase().includes(searchQuery.toLowerCase())) ||
      (lead.phone?.includes(searchQuery)) ||
      (lead.notes?.toLowerCase().includes(searchQuery.toLowerCase()));

    const matchesStatus = statusFilter === 'all' || lead.status === statusFilter;
    const matchesSource = sourceFilter === 'all' || lead.source === sourceFilter;

    return matchesSearch && matchesStatus && matchesSource;
  });

  const sourceStats = {
    form: leads.filter(l => l.source === 'form').length,
    messenger: leads.filter(l => l.source === 'messenger').length,
    manual: leads.filter(l => l.source === 'manual').length,
    page_view: leads.filter(l => l.source === 'page_view').length,
    other: leads.filter(l => l.source === 'other').length,
  };

  const formatDate = (dateStr: string) => {
    return formatDateShort(dateStr, i18n.language);
  };

  const exportToCSV = () => {
    if (filteredLeads.length === 0) {
      toast.error(t('crm.noLeadsToExport', 'No leads to export'));
      return;
    }

    const headers = ['Name', 'Email', 'Phone', 'Status', 'Source', 'Notes', 'Created'];
    const rows = filteredLeads.map(lead => [
      lead.name,
      lead.email || '',
      lead.phone || '',
      lead.status,
      lead.source,
      lead.notes || '',
      new Date(lead.created_at).toISOString().split('T')[0],
    ]);

    const csvContent = [
      headers.join(','),
      ...rows.map(row => row.map(cell => `"${String(cell).replace(/"/g, '""')}"`).join(','))
    ].join('\n');

    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const link = document.createElement('a');
    link.href = URL.createObjectURL(blob);
    link.download = `leads-${new Date().toISOString().split('T')[0]}.csv`;
    link.click();
    URL.revokeObjectURL(link.href);

    toast.success(t('crm.exportSuccess', 'Leads exported successfully'));
  };

  if (!isPremium) {
    return (
      <Sheet open={open} onOpenChange={handleOpenChange}>
        <SheetContent className="w-full sm:max-w-lg">
          <SheetHeader>
            <SheetTitle className="flex items-center gap-2">
              <Users className="h-5 w-5" />
              {t('crm.title', 'CRM')}
            </SheetTitle>
          </SheetHeader>
          <div className="flex flex-col items-center justify-center h-[60vh] text-center p-6">
            <Crown className="h-16 w-16 text-primary mb-4" />
            <h3 className="text-xl font-semibold mb-2">{t('crm.premiumRequired', 'Premium Feature')}</h3>
            <p className="text-muted-foreground mb-4">
              {t('crm.premiumDescription', 'Upgrade to Premium to access CRM and track your leads')}
            </p>
            <Button onClick={openPremiumPurchase}>
              <Crown className="h-4 w-4 mr-2" />
              {t('freemium.upgradeToPremium', 'Upgrade to Premium')}
            </Button>
          </div>
        </SheetContent>
      </Sheet>
    );
  }

  return (
    <>
      <Sheet open={open} onOpenChange={handleOpenChange}>
        <SheetContent className="w-full sm:max-w-lg p-0">
          <SheetHeader className="p-3 sm:p-4 border-b">
            <SheetTitle className="flex items-center gap-2 text-base sm:text-lg">
              {activeTab === 'leads' ? <Users className="h-4 w-4 sm:h-5 sm:w-5" /> : <BarChart3 className="h-4 w-4 sm:h-5 sm:w-5" />}
              {activeTab === 'leads' ? t('crm.title', 'CRM') : t('analytics.title', 'Analytics')}
            </SheetTitle>
            <SheetDescription className="text-xs sm:text-sm">
              {activeTab === 'leads'
                ? t('crm.description', 'Manage your leads and interactions')
                : t('analytics.description', 'Track your page performance')
              }
            </SheetDescription>
          </SheetHeader>

          {/* Tabs for Leads / Analytics */}
          <Tabs value={activeTab} onValueChange={(v: string) => setActiveTab(v as typeof activeTab)} className="w-full">
            <TabsList className="grid w-full grid-cols-5 mx-0 rounded-none border-b bg-transparent h-10 sm:h-11">
              <TabsTrigger value="leads" className="rounded-none data-[state=active]:border-b-2 data-[state=active]:border-primary text-[10px] sm:text-xs px-0.5">
                <Users className="h-3 w-3 sm:h-4 sm:w-4" />
                <span className="hidden sm:inline ml-1">{t('crm.leads', 'Leads')}</span>
              </TabsTrigger>
              <TabsTrigger value="bookings" className="rounded-none data-[state=active]:border-b-2 data-[state=active]:border-primary text-[10px] sm:text-xs px-0.5">
                <CalendarDays className="h-3 w-3 sm:h-4 sm:w-4" />
                <span className="hidden sm:inline ml-1">{t('crm.bookings', 'Bookings')}</span>
              </TabsTrigger>
              <TabsTrigger value="analytics" className="rounded-none data-[state=active]:border-b-2 data-[state=active]:border-primary text-[10px] sm:text-xs px-0.5">
                <BarChart3 className="h-3 w-3 sm:h-4 sm:w-4" />
                <span className="hidden sm:inline ml-1">{t('analytics.title', 'Stats')}</span>
              </TabsTrigger>
              <TabsTrigger value="funnel" className="rounded-none data-[state=active]:border-b-2 data-[state=active]:border-primary text-[10px] sm:text-xs px-0.5">
                <svg className="h-3 w-3 sm:h-4 sm:w-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <path d="M22 3H2l8 9.46V19l4 2v-8.54L22 3z" />
                </svg>
                <span className="hidden sm:inline ml-1">{t('funnel.short', 'Funnel')}</span>
              </TabsTrigger>
              <TabsTrigger value="heatmap" className="rounded-none data-[state=active]:border-b-2 data-[state=active]:border-primary text-[10px] sm:text-xs px-0.5">
                <svg className="h-3 w-3 sm:h-4 sm:w-4" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                  <circle cx="12" cy="12" r="10" />
                  <circle cx="12" cy="12" r="6" />
                  <circle cx="12" cy="12" r="2" />
                </svg>
                <span className="hidden sm:inline ml-1">{t('heatmap.short', 'Heat')}</span>
              </TabsTrigger>
            </TabsList>

            <TabsContent value="bookings" className="mt-0 h-[calc(100vh-150px)]">
              <BookingsPanel />
            </TabsContent>

            <TabsContent value="analytics" className="mt-0">
              <AnalyticsPanel />
            </TabsContent>

            <TabsContent value="funnel" className="mt-0">
              <FunnelAnalysis />
            </TabsContent>

            <TabsContent value="heatmap" className="mt-0">
              <HeatmapVisualization />
            </TabsContent>

            <TabsContent value="leads" className="mt-0">
              {/* Status Stats - Scrollable on mobile */}
              <div className="overflow-x-auto -mx-0">
                <div className="grid grid-cols-5 gap-1.5 sm:gap-2 p-3 sm:p-4 border-b min-w-[320px]">
                  {(['new', 'contacted', 'qualified', 'converted', 'lost'] as LeadStatus[]).map(status => (
                    <button
                      key={status}
                      onClick={() => setStatusFilter(statusFilter === status ? 'all' : status)}
                      className={`p-1.5 sm:p-2 rounded-lg text-center transition-all ${statusFilter === status ? 'ring-2 ring-primary ring-offset-1' : ''
                        } ${statusColors[status]}`}
                    >
                      <div className="text-base sm:text-lg font-bold">{stats[status]}</div>
                      <div className="text-[8px] sm:text-[10px] uppercase opacity-70 truncate">
                        {t(`crm.status.${status}`, status)}
                      </div>
                    </button>
                  ))}
                </div>
              </div>

              {/* Source Filter - Scrollable */}
              <div className="flex gap-1.5 sm:gap-2 p-3 sm:p-4 border-b overflow-x-auto scrollbar-hide">
                <button
                  onClick={() => setSourceFilter('all')}
                  className={`px-2.5 sm:px-3 py-1 sm:py-1.5 rounded-full text-[10px] sm:text-xs font-medium transition-all whitespace-nowrap shrink-0 ${sourceFilter === 'all' ? 'bg-primary text-primary-foreground' : 'bg-accent text-accent-foreground'
                    }`}
                >
                  {t('crm.allSources', 'All')} ({stats.total})
                </button>
                {(['form', 'messenger', 'manual', 'page_view', 'other'] as const).map(source => (
                  sourceStats[source] > 0 && (
                    <button
                      key={source}
                      onClick={() => setSourceFilter(sourceFilter === source ? 'all' : source)}
                      className={`px-2.5 sm:px-3 py-1 sm:py-1.5 rounded-full text-[10px] sm:text-xs font-medium transition-all whitespace-nowrap flex items-center gap-1 shrink-0 ${sourceFilter === source ? 'ring-2 ring-primary ring-offset-1' : ''
                        } ${sourceColors[source]}`}
                    >
                      <span>{sourceIcons[source]}</span>
                      <span className="hidden sm:inline">{t(`crm.source.${source}`, source)}</span>
                      ({sourceStats[source]})
                    </button>
                  )
                ))}
              </div>

              {/* Search, Export & Add */}
              <div className="p-3 sm:p-4 border-b flex gap-2">
                <div className="relative flex-1">
                  <Search className="absolute left-2.5 sm:left-3 top-1/2 -translate-y-1/2 h-3.5 w-3.5 sm:h-4 sm:w-4 text-muted-foreground" />
                  <Input
                    placeholder={t('crm.searchPlaceholder', 'Search...')}
                    value={searchQuery}
                    onChange={(e) => setSearchQuery(e.target.value)}
                    className="pl-8 sm:pl-9 h-9 sm:h-10 text-sm"
                  />
                </div>
                <Button variant="outline" size="icon" onClick={exportToCSV} title={t('crm.export', 'Export CSV')} className="h-9 w-9 sm:h-10 sm:w-10">
                  <Download className="h-3.5 w-3.5 sm:h-4 sm:w-4" />
                </Button>
                <Button size="icon" onClick={() => setAddDialogOpen(true)} className="h-9 w-9 sm:h-10 sm:w-10">
                  <Plus className="h-3.5 w-3.5 sm:h-4 sm:w-4" />
                </Button>
              </div>

              {/* Leads List */}
              <ScrollArea className="h-[calc(100vh-320px)] sm:h-[calc(100vh-300px)]">
                {loading ? (
                  <div className="p-8 text-center text-muted-foreground text-sm">
                    {t('messages.loading', 'Loading...')}
                  </div>
                ) : filteredLeads.length === 0 ? (
                  <div className="p-8 text-center text-muted-foreground text-sm">
                    {searchQuery || statusFilter !== 'all'
                      ? t('crm.noResults', 'No leads found')
                      : t('crm.noLeads', 'No leads yet. Add your first lead!')
                    }
                  </div>
                ) : (
                  <div className="divide-y">
                    {filteredLeads.map(lead => (
                      <button
                        key={lead.id}
                        onClick={() => setSelectedLead(lead)}
                        className="w-full p-3 sm:p-4 text-left hover:bg-accent/50 transition-colors active:bg-accent/70"
                      >
                        <div className="flex items-start justify-between gap-2">
                          <div className="min-w-0 flex-1">
                            <div className="flex items-center gap-1.5 sm:gap-2">
                              <span className="text-xs sm:text-sm">{sourceIcons[lead.source]}</span>
                              <span className="font-medium text-sm sm:text-base truncate">{lead.name}</span>
                            </div>
                            <div className="flex items-center gap-2 sm:gap-3 mt-1 text-xs sm:text-sm text-muted-foreground">
                              {lead.email && (
                                <span className="flex items-center gap-1 truncate max-w-[120px] sm:max-w-none">
                                  <Mail className="h-3 w-3 shrink-0" />
                                  <span className="truncate">{lead.email}</span>
                                </span>
                              )}
                              {lead.phone && (
                                <span className="flex items-center gap-1 shrink-0">
                                  <Phone className="h-3 w-3" />
                                  <span className="hidden sm:inline">{lead.phone}</span>
                                  <span className="sm:hidden">{lead.phone.slice(-4)}</span>
                                </span>
                              )}
                            </div>
                            {lead.notes && (
                              <div className="text-[10px] sm:text-xs text-muted-foreground mt-1 truncate max-w-[200px]">
                                {lead.notes}
                              </div>
                            )}
                          </div>
                          <div className="flex flex-col items-end gap-0.5 sm:gap-1 shrink-0">
                            <Badge variant="outline" className={`${statusColors[lead.status]} text-[10px] sm:text-xs px-1.5 sm:px-2`}>
                              {t(`crm.status.${lead.status}`, lead.status)}
                            </Badge>
                            <span className="text-[10px] sm:text-xs text-muted-foreground flex items-center gap-1">
                              <Calendar className="h-2.5 w-2.5 sm:h-3 sm:w-3" />
                              {formatDate(lead.created_at)}
                            </span>
                          </div>
                        </div>
                      </button>
                    ))}
                  </div>
                )}
              </ScrollArea>
            </TabsContent>
          </Tabs>
        </SheetContent>
      </Sheet>

      <AddLeadDialog
        open={addDialogOpen}
        onOpenChange={(isOpen) => {
          setAddDialogOpen(isOpen);
          if (!isOpen) refreshLeads();
        }}
      />

      {selectedLead && (
        <LeadDetails
          lead={selectedLead}
          open={!!selectedLead}
          onOpenChange={handleLeadDetailsClose}
        />
      )}
    </>
  );
}

import { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { ScrollArea } from '@/components/ui/scroll-area';
import {
    Wallet, TrendingUp, Clock, ArrowUpRight, ArrowDownLeft,
    AlertCircle, ChevronRight, Loader2, DollarSign, Banknote
} from 'lucide-react';
import { useAuth } from '@/hooks/user/useAuth';
import { fintechService } from '@/services/fintech';
import { format } from 'date-fns';
import { cn } from '@/lib/utils/utils';
import { useTranslation } from 'react-i18next';
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
    DialogFooter
} from '@/components/ui/dialog';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { toast } from 'sonner';

export const WalletWidget = () => {
    const { user } = useAuth();
    const { t } = useTranslation();
    const [data, setData] = useState<any>(null);
    const [loading, setLoading] = useState(true);
    const [isPayoutOpen, setIsPayoutOpen] = useState(false);
    const [payoutAmount, setPayoutAmount] = useState('');
    const [payoutMethod, setPayoutMethod] = useState('');
    const [submittingPayout, setSubmittingPayout] = useState(false);

    const loadData = async () => {
        if (!user) return;
        try {
            setLoading(true);
            const overview = await fintechService.getWalletOverview(user.id);
            setData(overview);
        } catch (err) {
            console.error('Failed to load wallet data', err);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadData();
    }, [user]);

    const handlePayoutRequest = async () => {
        if (!user || !payoutAmount || isNaN(Number(payoutAmount))) return;

        const amount = Number(payoutAmount);
        if (amount > (data?.wallet?.balance || 0)) {
            toast.error("Недостаточно средств на балансе");
            return;
        }

        try {
            setSubmittingPayout(true);
            await fintechService.requestPayout({
                userId: user.id,
                amount,
                method: { type: 'card', value: payoutMethod },
                notes: `Запрос выплаты из CRM`
            });
            toast.success("Запрос на выплату успешно отправлен");
            setIsPayoutOpen(false);
            setPayoutAmount('');
            setPayoutMethod('');
            loadData();
        } catch (err: any) {
            toast.error("Ошибка при создании запроса: " + err.message);
        } finally {
            setSubmittingPayout(false);
        }
    };

    if (loading) {
        return (
            <Card className="glass-card border-white/10 overflow-hidden">
                <CardContent className="p-10 flex flex-col items-center justify-center gap-3">
                    <Loader2 className="h-8 w-8 animate-spin text-primary" />
                    <p className="text-sm text-muted-foreground animate-pulse">Загружаем финансы...</p>
                </CardContent>
            </Card>
        );
    }

    const balance = data?.wallet?.balance || 0;
    const pendingGMV = data?.pendingGMV || 0;
    const transactions = data?.transactions || [];

    return (
        <Card className="glass-card border-white/10 overflow-hidden shadow-glass h-full flex flex-col">
            <CardHeader className="p-5 pb-2">
                <div className="flex items-center justify-between gap-4">
                    <div className="flex items-center gap-3">
                        <div className="p-2 rounded-xl bg-primary/10 text-primary">
                            <Wallet className="h-5 w-5" />
                        </div>
                        <div>
                            <CardTitle className="text-lg">Мой кошелек</CardTitle>
                            <CardDescription className="text-xs">Управление доходами и GMV</CardDescription>
                        </div>
                    </div>
                    <Button variant="ghost" size="icon" onClick={loadData} className="h-8 w-8">
                        <TrendingUp className="h-4 w-4" />
                    </Button>
                </div>
            </CardHeader>
            <CardContent className="p-5 flex-1 flex flex-col gap-6">
                {/* Balance Cards */}
                <div className="grid grid-cols-2 gap-4">
                    <div className="p-4 rounded-2xl bg-primary/5 border border-primary/10">
                        <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-wider mb-1">Доступно</p>
                        <p className="text-2xl font-bold text-gradient">{balance.toLocaleString()} ₸</p>
                    </div>
                    <div className="p-4 rounded-2xl bg-emerald-500/5 border border-emerald-500/10">
                        <p className="text-[10px] font-bold text-muted-foreground uppercase tracking-wider mb-1">В ожидании (GMV)</p>
                        <p className="text-2xl font-bold text-emerald-400">+{pendingGMV.toLocaleString()} ₸</p>
                    </div>
                </div>

                {/* Transactions List */}
                <div className="flex-1">
                    <div className="flex items-center justify-between mb-3 px-1">
                        <h4 className="text-xs font-bold uppercase tracking-widest text-muted-foreground/60">Последние операции</h4>
                        <Button variant="link" className="h-auto p-0 text-xs font-bold text-primary">Все</Button>
                    </div>
                    <ScrollArea className="h-[200px] -mx-1 pr-2">
                        <div className="space-y-3 px-1">
                            {transactions.length === 0 ? (
                                <div className="py-10 text-center space-y-2 opacity-50">
                                    <Clock className="h-8 w-8 mx-auto text-muted-foreground" />
                                    <p className="text-xs font-medium">Транзакций пока нет</p>
                                </div>
                            ) : (
                                transactions.map((tx: any) => (
                                    <div key={tx.id} className="flex items-center justify-between gap-3 p-3 rounded-xl bg-white/5 border border-white/10 group hover:border-primary/30 transition-all cursor-default">
                                        <div className="flex items-center gap-3">
                                            <div className={cn(
                                                "p-2 rounded-lg",
                                                tx.type === 'income' ? "bg-emerald-500/10 text-emerald-500" :
                                                    tx.type === 'fee' ? "bg-amber-500/10 text-amber-500" : "bg-red-500/10 text-red-500"
                                            )}>
                                                {tx.type === 'income' ? <ArrowDownLeft className="h-4 w-4" /> : <ArrowUpRight className="h-4 w-4" />}
                                            </div>
                                            <div className="min-w-0">
                                                <p className="text-sm font-bold truncate">{tx.description}</p>
                                                <p className="text-[10px] text-muted-foreground uppercase font-medium">
                                                    {format(new Date(tx.created_at), 'dd MMM, HH:mm')}
                                                </p>
                                            </div>
                                        </div>
                                        <div className="text-right">
                                            <p className={cn(
                                                "text-sm font-bold",
                                                tx.amount > 0 ? "text-emerald-400" : "text-muted-foreground"
                                            )}>
                                                {tx.amount > 0 ? '+' : ''}{tx.amount.toLocaleString()} ₸
                                            </p>
                                            <Badge variant="outline" className={cn(
                                                "text-[8px] py-0 h-4 border-none bg-black/40",
                                                tx.status === 'completed' ? "text-emerald-400" : "text-amber-400"
                                            )}>
                                                {tx.status === 'completed' ? 'Успешно' : 'Ожидает'}
                                            </Badge>
                                        </div>
                                    </div>
                                ))
                            )}
                        </div>
                    </ScrollArea>
                </div>

                <Dialog open={isPayoutOpen} onOpenChange={setIsPayoutOpen}>
                    <DialogTrigger asChild>
                        <Button className="w-full h-12 rounded-xl font-bold shadow-lg shadow-primary/20 hover:scale-[1.02] transition-transform">
                            Вывести средства
                        </Button>
                    </DialogTrigger>
                    <DialogContent className="glass-card border-white/10 sm:max-w-[425px]">
                        <DialogHeader>
                            <DialogTitle className="text-xl">Запрос выплаты</DialogTitle>
                            <DialogDescription>
                                Укажите сумму и реквизиты для вывода. Мы обработаем запрос в течение 24 часов.
                            </DialogDescription>
                        </DialogHeader>
                        <div className="grid gap-4 py-4">
                            <div className="grid gap-2">
                                <Label htmlFor="amount">Сумма (₸)</Label>
                                <Input
                                    id="amount"
                                    type="number"
                                    value={payoutAmount}
                                    onChange={(e) => setPayoutAmount(e.target.value)}
                                    placeholder="Например: 5000"
                                    className="bg-white/5 border-white/10"
                                />
                                <p className="text-[10px] text-muted-foreground">
                                    Доступно: <span className="text-primary font-bold">{(data?.wallet?.balance || 0).toLocaleString()} ₸</span>
                                </p>
                            </div>
                            <div className="grid gap-2">
                                <Label htmlFor="method">Реквизиты (Номер карты / Kaspi)</Label>
                                <Input
                                    id="method"
                                    value={payoutMethod}
                                    onChange={(e) => setPayoutMethod(e.target.value)}
                                    placeholder="4400 ...."
                                    className="bg-white/5 border-white/10"
                                />
                            </div>
                        </div>
                        <DialogFooter>
                            <Button
                                onClick={handlePayoutRequest}
                                disabled={submittingPayout || !payoutAmount || !payoutMethod}
                                className="w-full"
                            >
                                {submittingPayout ? <Loader2 className="h-4 w-4 animate-spin mr-2" /> : <Banknote className="h-4 w-4 mr-2" />}
                                Отправить запрос
                            </Button>
                        </DialogFooter>
                    </DialogContent>
                </Dialog>
            </CardContent>
        </Card>
    );
};

/**
 * AnalyticsChart - Time series chart for views/clicks/shares
 */
import { memo, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import {
  LineChart,
  Line,
  XAxis,
  YAxis,
  CartesianGrid,
  Tooltip,
  ResponsiveContainer,
  Area,
  AreaChart,
} from 'recharts';
import { Card } from '@/components/ui/card';
import type { TimeSeriesData } from '@/hooks/analytics/usePageAnalytics';

interface AnalyticsChartProps {
  data: TimeSeriesData[];
  title?: string;
  type?: 'line' | 'area';
  showClicks?: boolean;
  showShares?: boolean;
}

export const AnalyticsChart = memo(function AnalyticsChart({
  data,
  title,
  type = 'area',
  showClicks = true,
  showShares = false,
}: AnalyticsChartProps) {
  const { t } = useTranslation();

  const chartData = useMemo(() => {
    return data.map(item => ({
      ...item,
      date: item.date,
    }));
  }, [data]);

  if (!data.length) return null;

  const ChartComponent = type === 'area' ? AreaChart : LineChart;

  return (
    <Card className="p-4">
      {title && (
        <h3 className="font-bold mb-4 text-sm">{title}</h3>
      )}
      <div className="h-48">
        <ResponsiveContainer width="100%" height="100%">
          <ChartComponent data={chartData} margin={{ top: 5, right: 5, left: -20, bottom: 5 }}>
            <defs>
              <linearGradient id="viewsGradient" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="hsl(var(--primary))" stopOpacity={0.3} />
                <stop offset="95%" stopColor="hsl(var(--primary))" stopOpacity={0} />
              </linearGradient>
              <linearGradient id="clicksGradient" x1="0" y1="0" x2="0" y2="1">
                <stop offset="5%" stopColor="hsl(142 76% 36%)" stopOpacity={0.3} />
                <stop offset="95%" stopColor="hsl(142 76% 36%)" stopOpacity={0} />
              </linearGradient>
            </defs>
            <CartesianGrid strokeDasharray="3 3" stroke="hsl(var(--border))" opacity={0.5} />
            <XAxis
              dataKey="date"
              tick={{ fontSize: 10, fill: 'hsl(var(--muted-foreground))' }}
              tickLine={false}
              axisLine={false}
            />
            <YAxis
              tick={{ fontSize: 10, fill: 'hsl(var(--muted-foreground))' }}
              tickLine={false}
              axisLine={false}
            />
            <Tooltip
              contentStyle={{
                backgroundColor: 'hsl(var(--popover))',
                border: '1px solid hsl(var(--border))',
                borderRadius: '8px',
                fontSize: '12px',
              }}
              labelStyle={{ color: 'hsl(var(--popover-foreground))' }}
            />
            {type === 'area' ? (
              <>
                <Area
                  type="monotone"
                  dataKey="views"
                  stroke="hsl(var(--primary))"
                  strokeWidth={2}
                  fill="url(#viewsGradient)"
                  name={t('analytics.views', 'Просмотры')}
                />
                {showClicks && (
                  <Area
                    type="monotone"
                    dataKey="clicks"
                    stroke="hsl(142 76% 36%)"
                    strokeWidth={2}
                    fill="url(#clicksGradient)"
                    name={t('analytics.clicks', 'Клики')}
                  />
                )}
              </>
            ) : (
              <>
                <Line
                  type="monotone"
                  dataKey="views"
                  stroke="hsl(var(--primary))"
                  strokeWidth={2}
                  dot={false}
                  name={t('analytics.views', 'Просмотры')}
                />
                {showClicks && (
                  <Line
                    type="monotone"
                    dataKey="clicks"
                    stroke="hsl(142 76% 36%)"
                    strokeWidth={2}
                    dot={false}
                    name={t('analytics.clicks', 'Клики')}
                  />
                )}
              </>
            )}
          </ChartComponent>
        </ResponsiveContainer>
      </div>
    </Card>
  );
});

/**
 * AnalyticsExport - Export analytics data to CSV/PDF
 */
import { memo, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Button } from '@/components/ui/button';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from '@/components/ui/dropdown-menu';
import { Download, Table } from 'lucide-react';
import { toast } from 'sonner';
import type { AnalyticsSummary } from '@/hooks/analytics/usePageAnalytics';
import { exportAnalyticsToExcel } from '@/lib/export/excel-export-analytics';

interface AnalyticsExportProps {
  analytics: AnalyticsSummary | null;
  pageTitle?: string;
  period: string;
}

export const AnalyticsExport = memo(function AnalyticsExport({
  analytics,
  pageTitle = 'Page',
  period,
}: AnalyticsExportProps) {
  const { t } = useTranslation();
  const [exporting, setExporting] = useState(false);

  const exportToExcel = async () => {
    if (!analytics) return;
    setExporting(true);

    try {
      const pageViews = analytics.dailyData.map(d => ({
        date: d.date,
        views: d.views,
      }));

      await exportAnalyticsToExcel({
        pageViews,
        blockStats: analytics.topBlocks,
        dateRange: period,
      });

      toast.success(t('analytics.export.success', 'Данные успешно экспортированы'));
    } catch (error) {
      console.error(error);
      toast.error(t('analytics.export.error', 'Ошибка экспорта данных'));
    } finally {
      setExporting(false);
    }
  };

  if (!analytics) return null;

  return (
    <Button
      variant="outline"
      size="sm"
      disabled={exporting}
      onClick={exportToExcel}
      className="gap-2"
    >
      <Table className="h-4 w-4" />
      <span className="hidden sm:inline">{t('analytics.export.excel', 'Export Excel')}</span>
    </Button>
  );
});

/**
 * BlockPerformance - Detailed block-level analytics
 */
import { memo } from 'react';
import { useTranslation } from 'react-i18next';
import { Card } from '@/components/ui/card';
import { Progress } from '@/components/ui/progress';
import { Badge } from '@/components/ui/badge';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer } from 'recharts';
import { TrendingUp, TrendingDown, Minus, ExternalLink, Target } from 'lucide-react';
import { cn } from '@/lib/utils/utils';
import type { BlockStats } from '@/hooks/analytics/usePageAnalytics';

interface BlockPerformanceProps {
  blocks: BlockStats[];
  totalViews: number;
  showChart?: boolean;
}

const blockTypeLabels: Record<string, string> = {
  link: 'Ссылка',
  social: 'Соцсети',
  button: 'Кнопка',
  booking: 'Бронирование',
  contact_form: 'Форма',
  pricing: 'Цены',
  product: 'Товар',
  gallery: 'Галерея',
  video: 'Видео',
  event: 'Событие',
  messenger: 'Мессенджер',
};

export const BlockPerformance = memo(function BlockPerformance({
  blocks,
  totalViews,
  showChart = true,
}: BlockPerformanceProps) {
  const { t } = useTranslation();

  const chartData = blocks.slice(0, 8).map(block => ({
    name: block.blockTitle.length > 12
      ? block.blockTitle.substring(0, 12) + '...'
      : block.blockTitle,
    clicks: block.clicks,
    ctr: block.ctr,
  }));

  const getPerformanceLevel = (ctr: number): 'high' | 'medium' | 'low' => {
    if (ctr >= 15) return 'high';
    if (ctr >= 5) return 'medium';
    return 'low';
  };

  const getPerformanceColor = (level: 'high' | 'medium' | 'low') => {
    switch (level) {
      case 'high': return 'text-emerald-500 bg-emerald-500/10';
      case 'medium': return 'text-amber-500 bg-amber-500/10';
      case 'low': return 'text-red-500 bg-red-500/10';
    }
  };

  if (!blocks.length) {
    return (
      <Card className="p-4">
        <h3 className="font-bold mb-4">{t('analytics.blocks.title', 'Эффективность блоков')}</h3>
        <p className="text-center text-muted-foreground py-4 text-sm">
          {t('analytics.blocks.noData', 'Нет данных о кликах')}
        </p>
      </Card>
    );
  }

  return (
    <Card className="p-4">
      <div className="flex items-center justify-between mb-4">
        <h3 className="font-bold">{t('analytics.blocks.title', 'Эффективность блоков')}</h3>
        <Badge variant="outline" className="text-xs">
          <Target className="h-3 w-3 mr-1" />
          {t('analytics.blocks.avgCtr', 'Ср. CTR')}: {(blocks.reduce((sum, b) => sum + b.ctr, 0) / blocks.length).toFixed(1)}%
        </Badge>
      </div>

      {/* Chart */}
      {showChart && blocks.length > 2 && (
        <div className="h-32 mb-4">
          <ResponsiveContainer width="100%" height="100%">
            <BarChart data={chartData} margin={{ top: 5, right: 5, left: -20, bottom: 5 }}>
              <XAxis
                dataKey="name"
                tick={{ fontSize: 9, fill: 'hsl(var(--muted-foreground))' }}
                tickLine={false}
                axisLine={false}
              />
              <YAxis
                tick={{ fontSize: 9, fill: 'hsl(var(--muted-foreground))' }}
                tickLine={false}
                axisLine={false}
              />
              <Tooltip
                contentStyle={{
                  backgroundColor: 'hsl(var(--popover))',
                  border: '1px solid hsl(var(--border))',
                  borderRadius: '8px',
                  fontSize: '12px',
                }}
                formatter={(value?: number | string | Array<number | string>, name?: string | number) => [
                  name === 'clicks' ? `${value ?? 0} кликов` : `${Number(value ?? 0).toFixed(1)}%`,
                  name === 'clicks' ? 'Клики' : 'CTR',
                ]}
              />
              <Bar
                dataKey="clicks"
                fill="hsl(var(--primary))"
                radius={[4, 4, 0, 0]}
              />
            </BarChart>
          </ResponsiveContainer>
        </div>
      )}

      {/* Block list */}
      <div className="space-y-2">
        {blocks.slice(0, 5).map((block, index) => {
          const level = getPerformanceLevel(block.ctr);
          const colorClass = getPerformanceColor(level);

          return (
            <div
              key={block.blockId}
              className="flex items-center gap-3 p-2 rounded-lg bg-muted/30"
            >
              <div className="h-7 w-7 rounded-lg bg-muted flex items-center justify-center text-xs font-bold text-muted-foreground">
                {index + 1}
              </div>

              <div className="flex-1 min-w-0">
                <div className="flex items-center gap-2">
                  <span className="text-sm font-medium truncate">{block.blockTitle}</span>
                  <Badge variant="outline" className="text-[10px] px-1.5">
                    {blockTypeLabels[block.blockType] || block.blockType}
                  </Badge>
                </div>
                <div className="flex items-center gap-3 mt-0.5">
                  <span className="text-xs text-muted-foreground">
                    {block.clicks} {t('analytics.blocks.clicks', 'кликов')}
                  </span>
                  <Progress value={Math.min(100, block.ctr * 3)} className="h-1 w-16" />
                </div>
              </div>

              <div className={cn("px-2 py-1 rounded-md text-xs font-bold", colorClass)}>
                {block.ctr.toFixed(1)}%
              </div>
            </div>
          );
        })}
      </div>

      {blocks.length > 5 && (
        <div className="mt-3 text-center">
          <span className="text-xs text-muted-foreground">
            {t('analytics.blocks.andMore', 'и ещё {{count}} блоков', { count: blocks.length - 5 })}
          </span>
        </div>
      )}
    </Card>
  );
});

/**
 * GeographyChart - Geographic distribution of visitors
 */
import { memo } from 'react';
import { useTranslation } from 'react-i18next';
import { Card } from '@/components/ui/card';
import { Progress } from '@/components/ui/progress';
import { MapPin, Globe } from 'lucide-react';

interface GeoData {
  country: string;
  countryCode: string;
  count: number;
  percentage: number;
}

interface GeographyChartProps {
  data: GeoData[];
  totalVisitors: number;
}

// Country code to flag emoji
const getFlagEmoji = (countryCode: string) => {
  if (!countryCode || countryCode.length !== 2) return '🌍';
  const codePoints = countryCode
    .toUpperCase()
    .split('')
    .map(char => 127397 + char.charCodeAt(0));
  return String.fromCodePoint(...codePoints);
};

// Country name translations for common codes
const countryNames: Record<string, Record<string, string>> = {
  RU: { ru: 'Россия', en: 'Russia' },
  KZ: { ru: 'Казахстан', en: 'Kazakhstan' },
  UA: { ru: 'Украина', en: 'Ukraine' },
  BY: { ru: 'Беларусь', en: 'Belarus' },
  US: { ru: 'США', en: 'USA' },
  DE: { ru: 'Германия', en: 'Germany' },
  GB: { ru: 'Великобритания', en: 'United Kingdom' },
  FR: { ru: 'Франция', en: 'France' },
  UZ: { ru: 'Узбекистан', en: 'Uzbekistan' },
  KG: { ru: 'Кыргызстан', en: 'Kyrgyzstan' },
  TJ: { ru: 'Таджикистан', en: 'Tajikistan' },
  AZ: { ru: 'Азербайджан', en: 'Azerbaijan' },
  GE: { ru: 'Грузия', en: 'Georgia' },
  AM: { ru: 'Армения', en: 'Armenia' },
  TR: { ru: 'Турция', en: 'Turkey' },
  AE: { ru: 'ОАЭ', en: 'UAE' },
  unknown: { ru: 'Другие', en: 'Other' },
};

export const GeographyChart = memo(function GeographyChart({
  data,
  totalVisitors,
}: GeographyChartProps) {
  const { t, i18n } = useTranslation();
  const lang = i18n.language.startsWith('ru') ? 'ru' : 'en';

  const getCountryName = (code: string, fallback: string) => {
    return countryNames[code]?.[lang] || fallback;
  };

  if (!data.length) {
    return (
      <Card className="p-4">
        <div className="flex items-center gap-2 mb-4">
          <Globe className="h-5 w-5 text-primary" />
          <h3 className="font-bold">{t('analytics.geography.title', 'География')}</h3>
        </div>
        <div className="text-center py-8 text-muted-foreground">
          <MapPin className="h-10 w-10 mx-auto mb-2 opacity-50" />
          <p className="text-sm">{t('analytics.geography.noData', 'Нет данных о географии')}</p>
        </div>
      </Card>
    );
  }

  return (
    <Card className="p-4">
      <div className="flex items-center gap-2 mb-4">
        <Globe className="h-5 w-5 text-primary" />
        <h3 className="font-bold">{t('analytics.geography.title', 'География')}</h3>
      </div>

      <div className="space-y-3">
        {data.slice(0, 6).map((geo, index) => (
          <div key={geo.countryCode || index} className="space-y-1">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <span className="text-lg">{getFlagEmoji(geo.countryCode)}</span>
                <span className="text-sm font-medium">
                  {getCountryName(geo.countryCode, geo.country)}
                </span>
              </div>
              <div className="flex items-center gap-2">
                <span className="text-sm text-muted-foreground">{geo.count}</span>
                <span className="text-sm font-bold">{geo.percentage.toFixed(0)}%</span>
              </div>
            </div>
            <Progress value={geo.percentage} className="h-1.5" />
          </div>
        ))}
      </div>

      {data.length > 6 && (
        <div className="mt-3 pt-3 border-t border-border/50 text-center">
          <span className="text-xs text-muted-foreground">
            {t('analytics.geography.andMore', 'и ещё {{count}} стран', { count: data.length - 6 })}
          </span>
        </div>
      )}
    </Card>
  );
});

/**
 * TrafficSourcesChart - Visual breakdown of traffic sources
 */
import { memo } from 'react';
import { useTranslation } from 'react-i18next';
import { Card } from '@/components/ui/card';
import { Progress } from '@/components/ui/progress';
import { PieChart, Pie, Cell, ResponsiveContainer, Legend, Tooltip } from 'recharts';
import type { TrafficSource } from '@/hooks/analytics/usePageAnalytics';

interface TrafficSourcesChartProps {
  sources: TrafficSource[];
  variant?: 'pie' | 'bar';
}

// Source icons/colors
const sourceConfig: Record<string, { label: string; color: string; icon: string }> = {
  instagram: { label: 'Instagram', color: '#E1306C', icon: '📸' },
  facebook: { label: 'Facebook', color: '#4267B2', icon: '📘' },
  twitter: { label: 'Twitter/X', color: '#1DA1F2', icon: '🐦' },
  tiktok: { label: 'TikTok', color: '#000000', icon: '🎵' },
  youtube: { label: 'YouTube', color: '#FF0000', icon: '📺' },
  telegram: { label: 'Telegram', color: '#0088cc', icon: '✈️' },
  whatsapp: { label: 'WhatsApp', color: '#25D366', icon: '💬' },
  vkontakte: { label: 'ВКонтакте', color: '#4A76A8', icon: '🔵' },
  linkedin: { label: 'LinkedIn', color: '#0077B5', icon: '💼' },
  google: { label: 'Google', color: '#4285F4', icon: '🔍' },
  yandex: { label: 'Яндекс', color: '#FF0000', icon: '🔎' },
  bing: { label: 'Bing', color: '#00809D', icon: '🔍' },
  direct: { label: 'Прямой', color: 'hsl(var(--primary))', icon: '🔗' },
  referral: { label: 'Реферал', color: '#9333EA', icon: '🔗' },
  unknown: { label: 'Другое', color: '#6B7280', icon: '❓' },
};

export const TrafficSourcesChart = memo(function TrafficSourcesChart({
  sources,
  variant = 'bar',
}: TrafficSourcesChartProps) {
  const { t } = useTranslation();

  const chartData = sources.map(source => {
    const config = sourceConfig[source.source] || sourceConfig.unknown;
    return {
      name: config.label,
      value: source.count,
      percentage: source.percentage,
      color: config.color,
      icon: config.icon,
    };
  });

  if (!sources.length) {
    return (
      <Card className="p-4">
        <h3 className="font-bold mb-4">{t('analytics.sources.title', 'Источники трафика')}</h3>
        <p className="text-center text-muted-foreground py-4 text-sm">
          {t('analytics.sources.noData', 'Нет данных об источниках')}
        </p>
      </Card>
    );
  }

  if (variant === 'pie') {
    return (
      <Card className="p-4">
        <h3 className="font-bold mb-4">{t('analytics.sources.title', 'Источники трафика')}</h3>
        <div className="h-48">
          <ResponsiveContainer width="100%" height="100%">
            <PieChart>
              <Pie
                data={chartData}
                cx="50%"
                cy="50%"
                innerRadius={40}
                outerRadius={70}
                paddingAngle={2}
                dataKey="value"
              >
                {chartData.map((entry, index) => (
                  <Cell key={`cell-${index}`} fill={entry.color} />
                ))}
              </Pie>
              <Tooltip
                contentStyle={{
                  backgroundColor: 'hsl(var(--popover))',
                  border: '1px solid hsl(var(--border))',
                  borderRadius: '8px',
                  fontSize: '12px',
                }}
                formatter={(value?: number | string | Array<number | string>, name?: string | number) => [
                  `${value ?? 0} (${chartData.find(d => d.name === name)?.percentage.toFixed(0) ?? 0}%)`,
                  String(name ?? ''),
                ]}
              />
              <Legend
                formatter={(value) => (
                  <span style={{ color: 'hsl(var(--foreground))', fontSize: '12px' }}>{value}</span>
                )}
              />
            </PieChart>
          </ResponsiveContainer>
        </div>
      </Card>
    );
  }

  return (
    <Card className="p-4">
      <h3 className="font-bold mb-4">{t('analytics.sources.title', 'Источники трафика')}</h3>
      <div className="space-y-3">
        {chartData.slice(0, 6).map((source, index) => (
          <div key={index} className="space-y-1">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <span>{source.icon}</span>
                <span className="text-sm font-medium">{source.name}</span>
              </div>
              <div className="flex items-center gap-2">
                <span className="text-sm text-muted-foreground">{source.value}</span>
                <span className="text-sm font-bold">{source.percentage.toFixed(0)}%</span>
