          >
            <Coins className="h-6 w-6 text-primary mb-2" />
            <div className="font-bold">{t('dashboard.accountSettings.tokens', 'Tokens')}</div>
            <div className="text-xs text-muted-foreground">{t('dashboard.accountSettings.tokensDesc', 'Balance & history')}</div>
          </button>

          <button
            onClick={props.onOpenAchievements}
            className="p-4 rounded-2xl bg-gradient-to-br from-amber-500/10 to-orange-500/10 border border-amber-500/20 text-left transition-all active:scale-[0.98]"
          >
            <Trophy className="h-6 w-6 text-amber-500 mb-2" />
            <div className="font-bold">{t('dashboard.accountSettings.achievements', 'Achievements')}</div>
            <div className="text-xs text-muted-foreground">{t('dashboard.accountSettings.achievementsDesc', 'Your progress')}</div>
          </button>
        </motion.div>

        {/* Account Section */}
        <motion.div variants={itemVariants} className="space-y-2">
          <h3 className="text-sm font-bold text-muted-foreground uppercase tracking-wider px-1">
            {t('dashboard.accountSettings.account', 'Account')}
          </h3>
          <Card className="divide-y divide-border/50 overflow-hidden">
            <SettingsItem
              icon={Users}
              iconBg="bg-pink-500/15"
              iconColor="text-pink-500"
              label={t('dashboard.accountSettings.friends', 'Friends')}
              onClick={props.onOpenFriends}
            />
            <SettingsItem
              icon={LayoutTemplate}
              iconBg="bg-emerald-500/15"
              iconColor="text-emerald-500"
              label={t('dashboard.accountSettings.myTemplates', 'My Templates')}
              onClick={props.onOpenMyTemplates}
            />
            <SettingsItem
              icon={Save}
              iconBg="bg-blue-500/15"
              iconColor="text-blue-500"
              label={t('dashboard.accountSettings.saveTemplate', 'Save as Template')}
              onClick={props.onOpenSaveTemplate}
            />
            <SettingsItem
              icon={Shield}
              iconBg="bg-violet-500/15"
              iconColor="text-violet-500"
              label={t('dashboard.accountSettings.verification', 'Verification')}
              onClick={() => setShowVerification(true)}
            />
          </Card>
        </motion.div>

        {/* Notifications Section */}
        <motion.div variants={itemVariants} className="space-y-2">
          <h3 className="text-sm font-bold text-muted-foreground uppercase tracking-wider px-1">
            {t('dashboard.accountSettings.notifications', 'Notifications')}
          </h3>
          <Card className="divide-y divide-border/50 overflow-hidden">
            <SettingsItem
              icon={Mail}
              iconBg="bg-blue-500/15"
              iconColor="text-blue-500"
              label={t('dashboard.accountSettings.emailNotifications', 'Email Notifications')}
              description={t('dashboard.accountSettings.emailNotificationsDesc', 'About new leads')}
              rightElement={
                <Switch
                  checked={props.emailNotificationsEnabled}
                  onCheckedChange={props.onEmailNotificationsChange}
                />
              }
            />
            <div className="p-4 space-y-3">
              <div className="flex items-center gap-3">
                <div className="h-11 w-11 rounded-2xl bg-blue-500/15 flex items-center justify-center">
                  <MessageCircle className="h-5 w-5 text-blue-500" />
                </div>
                <div className="flex-1">
                  <div className="font-medium">{t('dashboard.accountSettings.telegram', 'Telegram')}</div>
                  <p className="text-sm text-muted-foreground">
                    {props.telegramEnabled
                      ? t('dashboard.accountSettings.connected', 'Connected')
                      : t('dashboard.accountSettings.notConnected', 'Not connected')}
                  </p>
                </div>
                <Switch checked={props.telegramEnabled} onCheckedChange={(checked) => props.onTelegramChange(checked)} />
              </div>
              {props.telegramEnabled && showTelegramVerification && (
                <TelegramVerification
                  onVerified={(chatId) => {
                    props.onTelegramChange(true, chatId);
                    setShowTelegramVerification(false);
                  }}
                  onBack={() => setShowTelegramVerification(false)}
                />
              )}
              {props.telegramEnabled && !showTelegramVerification && !props.telegramChatId && (
                <Button variant="outline" className="w-full mt-2" onClick={() => setShowTelegramVerification(true)}>
                  {t('dashboard.accountSettings.connectTelegram', 'Connect Telegram')}
                </Button>
              )}
            </div>
          </Card>
        </motion.div>

        {/* Appearance Section */}
        <motion.div variants={itemVariants} className="space-y-2">
          <h3 className="text-sm font-bold text-muted-foreground uppercase tracking-wider px-1">
            {t('dashboard.accountSettings.appearance', 'Appearance')}
          </h3>
          <Card className="divide-y divide-border/50 overflow-hidden">
            <SettingsItem
              icon={Globe}
              iconBg="bg-emerald-500/15"
              iconColor="text-emerald-500"
              label={t('dashboard.accountSettings.language', 'Language')}
              rightElement={<LanguageSwitcher />}
            />
          </Card>
        </motion.div>

        {/* Plan & Billing */}
        <motion.div variants={itemVariants} className="space-y-2">
          <h3 className="text-sm font-bold text-muted-foreground uppercase tracking-wider px-1">
            {t('dashboard.accountSettings.planBilling', 'Plan & Billing')}
          </h3>
          <Card className="divide-y divide-border/50 overflow-hidden">
            <SettingsItem
              icon={Crown}
              iconBg={props.isPremium ? "bg-amber-500/15" : "bg-muted"}
              iconColor={props.isPremium ? "text-amber-500" : "text-muted-foreground"}
              label={props.isPremium ? t('dashboard.accountSettings.proPlan', 'Pro Plan') : t('dashboard.accountSettings.freePlan', 'Free Plan')}
              description={props.isPremium ? t('dashboard.accountSettings.manageSubscription', 'Manage subscription') : t('dashboard.accountSettings.upgradeForMore', 'Upgrade for more features')}
              onClick={() => router.push('/pricing')}
            />
            {props.isPremium && (
              <SettingsItem
                icon={CreditCard}
                iconBg="bg-slate-500/15"
                iconColor="text-slate-500"
                label={t('dashboard.accountSettings.billingHistory', 'Billing History')}
                onClick={() => {/* TODO: Open billing history */ }}
              />
            )}
          </Card>
        </motion.div>

        {/* Linked Accounts Section */}
        <motion.div variants={itemVariants}>
          <LinkedAccountsSection userEmail={props.displayName} />
        </motion.div>

        {/* Security */}
        <motion.div variants={itemVariants} className="space-y-2">
          <h3 className="text-sm font-bold text-muted-foreground uppercase tracking-wider px-1">
            {t('dashboard.accountSettings.security', 'Security')}
          </h3>
          <Card className="divide-y divide-border/50 overflow-hidden">
            <SettingsItem
              icon={Lock}
              iconBg="bg-destructive/15"
              iconColor="text-destructive"
              label={t('dashboard.accountSettings.changePassword', 'Change Password')}
              onClick={() => {/* TODO: Open password change */ }}
            />
          </Card>
        </motion.div>

        {/* Logout */}
        <motion.div variants={itemVariants}>
          <Button
            variant="outline"
            className="w-full h-14 rounded-2xl text-destructive hover:text-destructive hover:bg-destructive/10 border-destructive/30"
            onClick={props.onSignOut}
          >
            <LogOut className="h-5 w-5 mr-2" />
            {t('dashboard.accountSettings.signOut', 'Sign Out')}
          </Button>
        </motion.div>
      </motion.div>

      {/* Verification Panel */}
      {showVerification && (
        <div className="fixed inset-0 z-50 bg-background/95 backdrop-blur-sm overflow-auto p-4">
          <div className="max-w-lg mx-auto">
            <div className="flex items-center justify-between mb-4">
              <h2 className="text-xl font-bold">{t('dashboard.accountSettings.verification', 'Verification')}</h2>
              <Button variant="ghost" onClick={() => setShowVerification(false)}>
                ✕
              </Button>
            </div>
            <VerificationPanel />
          </div>
        </div>
      )}
    </div>
  );
});

/**
 * ActivityScreen - Unified inbox for leads, bookings, messages
 */
import { memo, useState, useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { useLeads, LeadStatus } from '@/hooks/crm/useLeads';
import { formatDateShort, getLocale } from '@/lib/utils/format';
import { toast } from 'sonner';
import {
  Search,
  Plus,
  MessageCircle,
  Phone,
  Mail,
  Calendar,
  Crown,
  ChevronRight,
  Loader2,
  Send,
  CheckCheck,
  X,
  Sparkles,
  Inbox,
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Avatar, AvatarFallback } from '@/components/ui/avatar';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Tabs, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { DashboardHeader } from '../layout/DashboardHeader';
import { EmptyState } from '../common/EmptyState';
// ErrorState removed - useLeads doesn't expose error
import { LoadingSkeleton } from '../common/LoadingSkeleton';
import { AddLeadDialog } from '@/components/crm/AddLeadDialog';
import { LeadDetails } from '@/components/crm/LeadDetails';
import { BookingsPanel } from '@/components/crm/BookingsPanel';
import { WalletWidget } from '@/components/crm/WalletWidget';
import { cn } from '@/lib/utils/utils';
import { openPremiumPurchase } from '@/lib/utils/upgrade-utils';
import { exportLeadsToExcel } from '@/lib/export/excel-export-leads';
import type { Lead } from '@/hooks/crm/useLeads';
import { motion, AnimatePresence } from 'framer-motion';

interface ActivityScreenProps {
  isPremium: boolean;
}

const STATUS_CONFIG: Record<LeadStatus, {
  bg: string;
  text: string;
  label: string;
  icon: React.ComponentType<{ className?: string }>;
}> = {
  new: { bg: 'bg-blue-500', text: 'text-white', label: 'Новый', icon: Sparkles },
  contacted: { bg: 'bg-amber-500', text: 'text-white', label: 'В работе', icon: Send },
  qualified: { bg: 'bg-purple-500', text: 'text-white', label: 'Квалиф.', icon: CheckCheck },
  converted: { bg: 'bg-emerald-500', text: 'text-white', label: 'Сделка', icon: CheckCheck },
  lost: { bg: 'bg-gray-400', text: 'text-white', label: 'Потерян', icon: X },
};

const SOURCE_ICONS: Record<string, { emoji: string; label: string }> = {
  form: { emoji: '📝', label: 'Форма' },
  messenger: { emoji: '💬', label: 'Мессенджер' },
  manual: { emoji: '✏️', label: 'Вручную' },
  page_view: { emoji: '👁️', label: 'Просмотр' },
  other: { emoji: '📌', label: 'Другое' },
};

const containerVariants = {
  hidden: { opacity: 0 },
  show: {
    opacity: 1,
    transition: {
      staggerChildren: 0.05
    }
  }
};

const itemVariants = {
  hidden: { opacity: 0, y: 10 },
  show: { opacity: 1, y: 0 }
};

export const ActivityScreen = memo(function ActivityScreen({ isPremium }: ActivityScreenProps) {
  const { t, i18n } = useTranslation();
  const { leads, loading, getLeadStats, refreshLeads } = useLeads();

  const [searchQuery, setSearchQuery] = useState('');
  const [statusFilter, setStatusFilter] = useState<LeadStatus | 'all'>('all');
  const [showAddDialog, setShowAddDialog] = useState(false);
  const [selectedLead, setSelectedLead] = useState<Lead | null>(null);
  const [activeTab, setActiveTab] = useState<'leads' | 'bookings'>('leads');

  const stats = getLeadStats();

  // Premium gate
  <div className="min-h-screen flex items-center justify-center p-6 safe-area-top bg-liquid-mesh">
    <div className="text-center max-w-sm glass-card p-8 border-white/20 shadow-glass-xl relative overflow-hidden">
      <div className="absolute inset-0 bg-gradient-to-br from-amber-500/10 to-transparent -z-1" />
      <div className="h-24 w-24 rounded-[32px] bg-gradient-to-br from-amber-400 to-orange-500 flex items-center justify-center mx-auto mb-6 shadow-2xl shadow-amber-500/30 animate-float">
        <Crown className="h-12 w-12 text-white" />
      </div>
      <h2 className="text-2xl font-black mb-3 text-gradient-amber">{t('dashboard.activity.premiumRequired', 'Для Premium')}</h2>
      <p className="text-sm text-muted-foreground mb-6 leading-relaxed">
        {t('dashboard.activity.premiumDescription', 'Управляйте заявками как в мессенджере. Telegram-уведомления, статусы и история.')}
      </p>
      <Button
        size="lg"
        className="w-full h-14 px-8 rounded-2xl text-base font-bold shadow-xl shadow-amber-500/25 bg-gradient-to-r from-amber-500 to-orange-500 hover:scale-[1.02] active:scale-[0.98] transition-all"
        onClick={openPremiumPurchase}
      >
        <Crown className="h-5 w-5 mr-2" />
        {t('dashboard.activity.upgradeToPremium', 'Получить Premium')}
      </Button>
    </div>
  </div>

  const filteredLeads = leads.filter((lead) => {
    const matchesSearch =
      lead.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
      lead.email?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      lead.phone?.includes(searchQuery);
    const matchesStatus = statusFilter === 'all' || lead.status === statusFilter;
    return matchesSearch && matchesStatus;
  });

  // Group leads by date
  const groupedLeads = filteredLeads.reduce((groups, lead) => {
    const date = new Date(lead.created_at);
    const today = new Date();
    const yesterday = new Date(today);
    yesterday.setDate(yesterday.getDate() - 1);

    let key: string;
    if (date.toDateString() === today.toDateString()) {
      key = t('dashboard.activity.today', 'Сегодня');
    } else if (date.toDateString() === yesterday.toDateString()) {
      key = t('dashboard.activity.yesterday', 'Вчера');
    } else {
      key = formatDateShort(date, i18n.language);
    }

    if (!groups[key]) groups[key] = [];
    groups[key].push(lead);
    return groups;
  }, {} as Record<string, Lead[]>);

  return (
    <div className="h-[calc(100vh-64px)] md:h-screen safe-area-top flex flex-col">
      <DashboardHeader
        title={t('dashboard.activity.title', 'Входящие')}
        subtitle={`${stats.total} ${t('dashboard.activity.totalLeads', 'заявок')}`}
        actions={
          <div className="flex items-center gap-2">
            {isPremium && leads.length > 0 && activeTab === 'leads' && (
              <Button
                variant="outline"
                size="sm"
                className="h-12 w-12 rounded-2xl md:h-9 md:w-auto md:px-4 md:rounded-xl"
                onClick={() => {
                  toast.promise(
                    exportLeadsToExcel({ leads }),
                    {
                      loading: t('dashboard.activity.exporting', 'Экспорт лидов...'),
                      success: t('dashboard.activity.exportSuccess', 'Экспорт завершен'),
                      error: t('dashboard.activity.exportError', 'Ошибка экспорта')
                    }
                  );
                }}
              >
                <span className="hidden md:inline">{t('dashboard.activity.export', 'Экспорт')}</span>
                <span className="md:hidden font-bold">EX</span>
              </Button>
            )}
            <Button
              size="icon"
              className="h-12 w-12 rounded-2xl md:h-9 md:w-9 md:rounded-xl shadow-lg shadow-primary/25"
              onClick={() => setShowAddDialog(true)}
            >
              <Plus className="h-6 w-6 md:h-5 md:w-5" />
            </Button>
          </div>
        }
      />

      {/* Fintech Ledger Widget - Foundation for Fintech Pivot */}
      <div className="px-5 pb-6">
        <WalletWidget />
      </div>

      {/* Tabs */}
      <div className="px-5 pb-3">
        <div className="bg-muted/50 rounded-2xl p-1">
          <Tabs value={activeTab} onValueChange={(v: string) => setActiveTab(v as 'leads' | 'bookings')}>
            <TabsList className="grid grid-cols-2 h-11 bg-transparent p-0 gap-1">
              <TabsTrigger
                value="leads"
                className="rounded-xl h-full data-[state=active]:bg-background data-[state=active]:shadow-sm font-bold text-sm"
              >
                <MessageCircle className="h-4 w-4 mr-2" />
                {t('dashboard.activity.tabs.leads', 'Заявки')}
                {stats.new > 0 && (
                  <Badge className="ml-2 h-5 px-1.5 bg-blue-500 text-white text-xs">
                    {stats.new}
                  </Badge>
                )}
              </TabsTrigger>
              <TabsTrigger
                value="bookings"
                className="rounded-xl h-full data-[state=active]:bg-background data-[state=active]:shadow-sm font-bold text-sm"
              >
                <Calendar className="h-4 w-4 mr-2" />
                {t('dashboard.activity.tabs.bookings', 'Записи')}
              </TabsTrigger>
            </TabsList>
          </Tabs>
        </div>
      </div>

      <AnimatePresence mode='wait'>
        {activeTab === 'leads' && (
          <motion.div
            key="leads-tab"
            initial={{ opacity: 0, x: -20 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: 20 }}
            transition={{ duration: 0.2 }}
          >
            {/* Status Pills */}
            <div className="px-5 py-3 overflow-x-auto scrollbar-hide">
              <div className="flex gap-2 min-w-max">
                <button
                  onClick={() => setStatusFilter('all')}
                  className={cn(
                    "h-9 px-4 rounded-full text-sm font-bold whitespace-nowrap transition-all flex items-center gap-2",
                    statusFilter === 'all'
                      ? "bg-foreground text-background shadow-lg scale-105"
                      : "bg-muted/60 text-muted-foreground hover:bg-muted"
                  )}
                >
                  {t('dashboard.activity.all', 'Все')}
                  <span className="text-xs opacity-70">({stats.total})</span>
                </button>
                {Object.entries(STATUS_CONFIG).map(([status, config]) => {
                  const count = stats[status as LeadStatus];
                  if (count === 0) return null;
                  const StatusIcon = config.icon;
                  return (
                    <button
                      key={status}
                      onClick={() => setStatusFilter(status as LeadStatus)}
                      className={cn(
                        "h-9 px-4 rounded-full text-sm font-bold whitespace-nowrap transition-all flex items-center gap-2",
                        statusFilter === status
                          ? `${config.bg} ${config.text} shadow-lg scale-105`
                          : "bg-muted/60 text-muted-foreground hover:bg-muted"
                      )}
                    >
                      <StatusIcon className="h-3.5 w-3.5" />
                      {config.label}
                      <span className="text-xs opacity-70">({count})</span>
                    </button>
                  );
                })}
              </div>
            </div>

            {/* Search */}
            <div className="px-5 pb-3">
              <div className="relative">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-5 w-5 text-muted-foreground" />
                <Input
                  placeholder={t('dashboard.activity.searchPlaceholder', 'Поиск по имени, телефону...')}
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="h-11 pl-12 rounded-xl bg-muted/50 border-0 text-base"
                />
              </div>
            </div>

            {/* Leads List - Flex Layout for Scroll */}
            <div className="flex-1 min-h-0 overflow-y-auto">
              {loading ? (
                <div className="px-5 pt-2">
                  <LoadingSkeleton variant="list" />
                </div>
              ) : filteredLeads.length === 0 ? (
                <EmptyState
                  icon={Inbox}
                  title={searchQuery ? t('dashboard.activity.noResults', 'Ничего не найдено') : t('dashboard.activity.noLeads', 'Пока нет заявок')}
                  description={t('dashboard.activity.noLeadsHint', 'Заявки появятся здесь, когда посетители заполнят формы на вашей странице')}
                />
              ) : (
                <div className="px-5 pb-24 pt-2">
                  <motion.div
                    variants={containerVariants}
                    initial="hidden"
                    animate="show"
                  >
                    {Object.entries(groupedLeads).map(([date, dateLeads]) => (
                      <div key={date} className="mb-6">
                        <div className="text-xs font-bold text-muted-foreground uppercase tracking-wider mb-3 px-1 sticky top-0 bg-background/95 backdrop-blur-sm py-2 z-10 shadow-sm">
                          {date}
                        </div>
                        <div className="space-y-2">
                          {dateLeads.map((lead) => (
                            <motion.div key={lead.id} variants={itemVariants}>
                              <LeadCard lead={lead} onClick={() => setSelectedLead(lead)} />
                            </motion.div>
                          ))}
                        </div>
                      </div>
                    ))}
                  </motion.div>
                </div>
              )}
            </div>
          </motion.div>
        )}

        {activeTab === 'bookings' && (
          <motion.div
            key="bookings-tab"
            initial={{ opacity: 0, x: 20 }}
            animate={{ opacity: 1, x: 0 }}
            exit={{ opacity: 0, x: -20 }}
            transition={{ duration: 0.2 }}
          >
            <BookingsPanel />
          </motion.div>
        )}
      </AnimatePresence>

      {/* Dialogs */}
      <AddLeadDialog
        open={showAddDialog}
        onOpenChange={(isOpen) => {
          setShowAddDialog(isOpen);
          if (!isOpen) refreshLeads();
        }}
      />

      {selectedLead && (
        <LeadDetails
          lead={selectedLead}
          open={!!selectedLead}
          onOpenChange={(isOpen) => {
            if (!isOpen) {
              setSelectedLead(null);
              refreshLeads();
            }
          }}
        />
      )}
    </div>
  );
});

// Lead Card Component
interface LeadCardProps {
  lead: Lead;
  onClick: () => void;
}

function LeadCard({ lead, onClick }: LeadCardProps) {
  const { i18n } = useTranslation();
  const statusConfig = STATUS_CONFIG[lead.status];
  const sourceInfo = SOURCE_ICONS[lead.source] || SOURCE_ICONS.other;

  const formatTime = (dateStr: string) => {
    const date = new Date(dateStr);
    return date.toLocaleTimeString(getLocale(i18n.language), { hour: '2-digit', minute: '2-digit' });
  };

  return (
    <button
      onClick={onClick}
      className={cn(
        "w-full p-4 rounded-2xl glass-card transition-all duration-300 relative overflow-hidden group",
        "hover:bg-primary/5 hover:translate-x-1 active:scale-[0.98] border-white/10",
        lead.status === 'new' && "border-blue-500/30 ring-1 ring-blue-500/20"
      )}
    >
      <div className={cn(
        "absolute inset-0 opacity-0 group-hover:opacity-100 transition-opacity bg-gradient-to-r from-primary/5 to-transparent -z-1",
        lead.status === 'new' && "opacity-10"
      )} />
      <div className="flex items-start gap-3">
        <Avatar className="h-12 w-12 rounded-xl shrink-0">
          <AvatarFallback className={cn("rounded-xl text-base font-bold", statusConfig.bg, statusConfig.text)}>
            {lead.name.charAt(0).toUpperCase()}
          </AvatarFallback>
        </Avatar>

        <div className="flex-1 min-w-0 text-left">
          <div className="flex items-center justify-between gap-2 mb-1">
            <div className="flex items-center gap-2 min-w-0">
              <span className="font-bold truncate">{lead.name}</span>
              {lead.status === 'new' && (
                <span className="h-2 w-2 rounded-full bg-blue-500 shrink-0 animate-pulse" />
              )}
            </div>
            <span className="text-xs text-muted-foreground shrink-0">{formatTime(lead.created_at)}</span>
          </div>

          <div className="flex items-center gap-3 text-sm text-muted-foreground mb-2">
            {lead.phone && (
              <span className="flex items-center gap-1">
                <Phone className="h-3 w-3" />
                {lead.phone}
              </span>
            )}
            {lead.email && (
              <span className="flex items-center gap-1 truncate">
                <Mail className="h-3 w-3" />
                {lead.email}
              </span>
            )}
          </div>

          <div className="flex items-center justify-between">
            <span className="text-xs text-muted-foreground flex items-center gap-1">
              <span>{sourceInfo.emoji}</span>
              {sourceInfo.label}
            </span>
            <Badge className={cn("text-xs font-bold h-6 px-2", statusConfig.bg, statusConfig.text, "border-0")}>
              {statusConfig.label}
            </Badge>
          </div>
        </div>

        <ChevronRight className="h-5 w-5 text-muted-foreground shrink-0 self-center" />
      </div>
    </button>
  );
}

/**
 * EditorScreen - Page editor with block management
 * Mobile-first design with GridEditor and block editing capabilities
 */
import { memo, useCallback, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Eye, Share2, Sparkles, LayoutTemplate, Undo2, Redo2, History } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { DashboardHeader } from '../layout/DashboardHeader';
import { LoadingSkeleton } from '../common/LoadingSkeleton';
import { GridEditor } from '@/components/editor/GridEditor';
import { cn } from '@/lib/utils/utils';
import type { PageData, Block, ProfileBlock } from '@/types/page';
import type { FreeTier } from '@/hooks/user/useFreemiumLimits';
import type { PremiumTier } from '@/hooks/user/usePremiumStatus';

interface EditorScreenProps {
  pageData: PageData | null;
  loading: boolean;
  isPremium: boolean;
  currentTier?: FreeTier;
  premiumTier?: PremiumTier;
  onInsertBlock: (blockType: string, position: number) => { success: boolean; blockId?: string; error?: string };
  onEditBlock: (block: Block) => void;
  onDeleteBlock: (blockId: string) => void;
  onUpdateBlock: (id: string, updates: Partial<Block>) => void;
  onReorderBlocks: (blocks: Block[]) => void;
  onPreview: () => void;
  onShare: () => void;
  onOpenTemplates: () => void;
  onOpenAI: () => void;
  // Undo/Redo
  canUndo?: boolean;
  canRedo?: boolean;
  onUndo?: () => void;
  onRedo?: () => void;
  // Versions
  onOpenVersions?: () => void;
}

export const EditorScreen = memo(function EditorScreen({
  pageData,
  loading,
  isPremium,
  currentTier = 'free',
  premiumTier,
  onInsertBlock,
  onEditBlock,
  onDeleteBlock,
  onUpdateBlock,
  onReorderBlocks,
  onPreview,
  onShare,
  onOpenTemplates,
  onOpenAI,
  canUndo = false,
  canRedo = false,
  onUndo,
  onRedo,
  onOpenVersions,
}: EditorScreenProps) {
  const { t } = useTranslation();

  if (loading || !pageData) {
    return <LoadingSkeleton />;
  }

  const isPublished = pageData.isPublished || false;
  const blockCount = pageData.blocks.length;

  // Count non-profile blocks to determine if user is experienced
  const contentBlockCount = pageData.blocks.filter(b => b.type !== 'profile').length;

  // Page has content if it has more than just a profile block
  const hasContent = pageData.blocks.length > 1 ||
    (pageData.blocks.length === 1 && pageData.blocks[0].type !== 'profile');

  // Show AI builder only for new users (less than 2 content blocks)
  const showAIBuilder = contentBlockCount < 2;

  return (
    <div className="min-h-screen safe-area-top">
      {/* Header with actions */}
      <div className="sticky top-0 z-40 glass-nav border-b border-white/10">
        <div className="px-4 py-3">
          <div className="flex items-center justify-between gap-3">
            {/* Left: Title */}
            <div className="flex-1 min-w-0">
              <h1 className="text-xl font-black text-gradient truncate">
                {t('dashboard.editor.title', 'Редактор')}
              </h1>
              <div className="flex items-center gap-1.5 mt-0.5">
                <div className="h-1.5 w-1.5 rounded-full bg-emerald-500 animate-pulse" />
                <p className="text-[10px] text-muted-foreground font-bold uppercase tracking-widest">
                  {blockCount} {t('dashboard.editor.blocks', 'блоков')}
                </p>
              </div>
            </div>

            {/* Center: Undo/Redo */}
            <div className="flex items-center gap-1">
              <Button
                variant="ghost"
                size="sm"
                className="h-9 w-9 p-0 rounded-xl"
                onClick={onUndo}
                disabled={!canUndo}
              >
                <Undo2 className="h-4 w-4" />
              </Button>
              <Button
                variant="ghost"
                size="sm"
                className="h-9 w-9 p-0 rounded-xl"
                onClick={onRedo}
                disabled={!canRedo}
              >
                <Redo2 className="h-4 w-4" />
              </Button>
            </div>

            {/* Right: Actions */}
            <div className="flex items-center gap-2">
              <Button
                variant="ghost"
                size="sm"
                className="h-9 w-9 p-0 rounded-xl"
                onClick={onPreview}
              >
                <Eye className="h-4 w-4" />
              </Button>
              <Button
                size="sm"
                className={cn(
                  "h-9 rounded-xl font-semibold px-4",
                  !isPublished && "bg-primary hover:bg-primary/90 text-primary-foreground"
                )}
                onClick={onShare}
              >
                <Share2 className="h-4 w-4 mr-1.5" />
                {isPublished ? t('editor.share', 'Поделиться') : t('editor.publish', 'Опубликовать')}
              </Button>
            </div>
          </div>
        </div>

        {/* Quick tools bar */}
        <div className="px-4 py-2 flex gap-2 overflow-x-auto scrollbar-hide border-t border-border/5">
          {/* Show templates only for pages without content */}
          {!hasContent && (
            <Button
              variant="outline"
              size="sm"
              className="h-8 rounded-xl shrink-0 gap-1.5"
              onClick={onOpenTemplates}
            >
              <LayoutTemplate className="h-3.5 w-3.5" />
              {t('editor.templates', 'Шаблоны')}
            </Button>
          )}

          {/* Show version history for pages with content */}
          {hasContent && onOpenVersions && (
            <Button
              variant="outline"
              size="sm"
              className="h-8 rounded-xl shrink-0 gap-1.5"
              onClick={onOpenVersions}
            >
              <History className="h-3.5 w-3.5" />
              {t('editor.versions', 'История')}
            </Button>
          )}

        </div>
      </div>

      {/* Grid Editor */}
      <div className="pt-4">
        <GridEditor
          blocks={pageData.blocks}
          isPremium={isPremium}
          currentTier={currentTier}
          premiumTier={premiumTier}
          gridConfig={pageData.gridConfig}
          onInsertBlock={onInsertBlock}
          onEditBlock={onEditBlock}
          onDeleteBlock={onDeleteBlock}
          onUpdateBlock={onUpdateBlock}
          onReorderBlocks={onReorderBlocks}
        />
      </div>
    </div>
  );
});

'use client';

/**
 * EventDetailScreen - Detailed event view with registrations management
 * Shows all registrations, allows check-in, export, and management
 */
import { memo, useState, useEffect, useCallback } from 'react';
import { useRouter, useParams } from 'next/navigation';
import { useTranslation } from 'react-i18next';
import { format } from 'date-fns';
import { ru, kk, enUS } from 'date-fns/locale';
import { supabase } from '@/platform/supabase/client';
import { useAuth } from '@/hooks/user/useAuth';
import { usePremiumStatus } from '@/hooks/user/usePremiumStatus';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Skeleton } from '@/components/ui/skeleton';
import { Input } from '@/components/ui/input';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
  DropdownMenuSeparator,
} from '@/components/ui/dropdown-menu';
import {
  ArrowLeft,
  Users,
  QrCode,
  Download,
  MapPin,
  Clock,
  Search,
  ExternalLink,
  CalendarDays,
  UserCheck,
  UserX,
  Crown,
  Loader2,
  Mail,
  Phone,
  MoreVertical,
  Check,
  X,
  RefreshCw,
  Ticket,
  FileSpreadsheet,
  FileText,
  BarChart3,
} from 'lucide-react';
import { toast } from 'sonner';
import { openPremiumPurchase } from '@/lib/utils/upgrade-utils';
import { cn } from '@/lib/utils/utils';
import { exportToExcel, exportToCSV } from '@/lib/export/excel-export';
import { exportEventToPDF, calculateEventAnalytics } from '@/lib/export/pdf-export';
import type { SupportedLanguage } from '@/lib/i18n-helpers';
import type { EventFormField } from '@/types/page';

interface Registration {
  id: string;
  attendeeName: string;
  attendeeEmail: string;
  attendeePhone: string | null;
  status: 'confirmed' | 'pending' | 'cancelled';
  createdAt: string;
  ticketCode: string | null;
  ticketStatus: 'valid' | 'used' | 'cancelled' | null;
  checkedInAt: string | null;
  answersJson: Record<string, unknown> | null;
  paymentStatus: string;
}

interface FullRegistration {
  id: string;
  attendee_name: string;
  attendee_email: string;
  attendee_phone: string | null;
  answers_json: Record<string, unknown> | null;
  status: string;
  payment_status: string;
  created_at: string;
  event_tickets?: Array<{
    ticket_code: string;
    status: string;
    checked_in_at: string | null;
  }> | null;
}

interface EventDetail {
  id: string;
  title: string;
  description: string | null;
  startAt: string | null;
  endAt: string | null;
  locationType: string;
  locationValue: string | null;
  status: string;
  capacity: number | null;
  isPaid: boolean;
  price: number | null;
  currency: string | null;
  coverUrl: string | null;
  pageSlug: string;
  formSchema: EventFormField[];
}

export const EventDetailScreen = memo(function EventDetailScreen() {
  const params = useParams();
  const eventId = params?.eventId as string;
  const router = useRouter();
  const { t, i18n } = useTranslation();
  const { user } = useAuth();
  const { isPremium } = usePremiumStatus();

  const [event, setEvent] = useState<EventDetail | null>(null);
  const [registrations, setRegistrations] = useState<Registration[]>([]);
  const [fullRegistrations, setFullRegistrations] = useState<FullRegistration[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');
  const [activeTab, setActiveTab] = useState<'all' | 'confirmed' | 'pending' | 'checked'>('all');
  const [refreshing, setRefreshing] = useState(false);
  const [exporting, setExporting] = useState(false);

  const locale = i18n.language === 'ru' ? ru : i18n.language === 'kk' ? kk : enUS;

  const fetchData = useCallback(async () => {
    if (!user || !eventId) return;

    try {
      // Fetch event details with form schema
      const { data: eventData, error: eventError } = await supabase
        .from('events')
        .select(`
          id,
          title_i18n_json,
          description_i18n_json,
          start_at,
          end_at,
          location_type,
          location_value,
          status,
          capacity,
          is_paid,
          price_amount,
          currency,
          cover_url,
          form_schema_json,
          pages!inner(slug)
        `)
        .eq('id', eventId)
        .eq('owner_id', user.id)
        .single();

      if (eventError || !eventData) {
        toast.error(t('events.notFound', 'Событие не найдено'));
        router.push('/dashboard/events');
        return;
      }

      const formSchema = ((eventData.form_schema_json as { fields?: EventFormField[] })?.fields || []) as EventFormField[];

      setEvent({
        id: eventData.id,
        title: (eventData.title_i18n_json as Record<string, string>)?.[i18n.language] ||
          (eventData.title_i18n_json as Record<string, string>)?.ru || '',
        description: (eventData.description_i18n_json as Record<string, string>)?.[i18n.language] ||
          (eventData.description_i18n_json as Record<string, string>)?.ru || null,
        startAt: eventData.start_at,
        endAt: eventData.end_at,
        locationType: eventData.location_type || 'online',
        locationValue: eventData.location_value,
        status: eventData.status || 'draft',
        capacity: eventData.capacity,
        isPaid: eventData.is_paid || false,
        price: eventData.price_amount,
        currency: eventData.currency,
        coverUrl: eventData.cover_url,
        pageSlug: (eventData.pages as { slug: string })?.slug || '',
        formSchema,
      });

      // Fetch registrations with answers
      const { data: regsData, error: regsError } = await supabase
        .from('event_registrations')
        .select('id, attendee_name, attendee_email, attendee_phone, status, payment_status, answers_json, created_at')
        .eq('event_id', eventId)
        .order('created_at', { ascending: false });

      if (regsError) throw regsError;

      // Fetch tickets for these registrations
      const regIds = (regsData || []).map(r => r.id);
      let ticketsData: Array<{ registration_id: string; ticket_code: string; status: string; checked_in_at: string | null }> = [];

      if (regIds.length > 0) {
        const { data } = await supabase
          .from('event_tickets')
          .select('registration_id, ticket_code, status, checked_in_at')
          .in('registration_id', regIds);
        ticketsData = (data as unknown) as typeof ticketsData;
      }

      const ticketMap = new Map(ticketsData.map(t => [t.registration_id, t]));

      // Set full registrations for export
      setFullRegistrations((regsData || []).map(r => {
        const ticket = ticketMap.get(r.id);
        return {
          id: r.id,
          attendee_name: r.attendee_name,
          attendee_email: r.attendee_email,
          attendee_phone: r.attendee_phone,
          answers_json: r.answers_json as Record<string, unknown> | null,
          status: r.status,
          payment_status: r.payment_status,
          created_at: r.created_at,
          event_tickets: ticket ? [{
            ticket_code: ticket.ticket_code,
            status: ticket.status,
            checked_in_at: ticket.checked_in_at,
          }] : null,
        };
      }));

      setRegistrations((regsData || []).map(r => {
        const ticket = ticketMap.get(r.id);
        return {
          id: r.id,
          attendeeName: r.attendee_name,
          attendeeEmail: r.attendee_email,
          attendeePhone: r.attendee_phone,
          status: r.status as Registration['status'],
          createdAt: r.created_at,
          ticketCode: ticket?.ticket_code || null,
          ticketStatus: ticket?.status as Registration['ticketStatus'] || null,
          checkedInAt: ticket?.checked_in_at || null,
          answersJson: r.answers_json as Record<string, unknown> | null,
          paymentStatus: r.payment_status,
        };
      }));
    } catch (error) {
      console.error('Error fetching event:', error);
      toast.error(t('events.fetchError', 'Ошибка загрузки'));
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, [user, eventId, i18n.language, t, router]);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  const handleRefresh = async () => {
    setRefreshing(true);
    await fetchData();
  };

  // Filter registrations
  const filteredRegistrations = registrations.filter(reg => {
    const matchesSearch =
      reg.attendeeName.toLowerCase().includes(searchQuery.toLowerCase()) ||
      reg.attendeeEmail.toLowerCase().includes(searchQuery.toLowerCase()) ||
      reg.ticketCode?.toLowerCase().includes(searchQuery.toLowerCase());

    if (!matchesSearch) return false;

    switch (activeTab) {
      case 'confirmed':
        return reg.status === 'confirmed';
      case 'pending':
        return reg.status === 'pending';
      case 'checked':
        return reg.ticketStatus === 'used';
      default:
        return true;
    }
  });

  // Stats
  const stats = {
    total: registrations.length,
    confirmed: registrations.filter(r => r.status === 'confirmed').length,
    pending: registrations.filter(r => r.status === 'pending').length,
    checkedIn: registrations.filter(r => r.ticketStatus === 'used').length,
  };

  const handleApprove = async (regId: string) => {
    try {
      const { error } = await supabase
        .from('event_registrations')
        .update({ status: 'confirmed' })
        .eq('id', regId);

      if (error) throw error;

      setRegistrations(prev => prev.map(r =>
        r.id === regId ? { ...r, status: 'confirmed' as const } : r
      ));
      toast.success(t('events.approved', 'Регистрация подтверждена'));
    } catch (error) {
      toast.error(t('events.approveError', 'Ошибка подтверждения'));
    }
  };

  const handleReject = async (regId: string) => {
    try {
      const { error } = await supabase
        .from('event_registrations')
        .update({ status: 'cancelled' })
        .eq('id', regId);

      if (error) throw error;

      setRegistrations(prev => prev.map(r =>
        r.id === regId ? { ...r, status: 'cancelled' as const } : r
      ));
      toast.success(t('events.rejected', 'Регистрация отклонена'));
    } catch (error) {
      toast.error(t('events.rejectError', 'Ошибка отклонения'));
    }
  };

  const handleManualCheckIn = async (regId: string, ticketCode: string | null) => {
    if (!ticketCode) return;

    try {
      const { error } = await supabase
        .from('event_tickets')
        .update({ status: 'used', checked_in_at: new Date().toISOString() })
        .eq('ticket_code', ticketCode);

      if (error) throw error;

      setRegistrations(prev => prev.map(r =>
        r.id === regId ? { ...r, ticketStatus: 'used' as const, checkedInAt: new Date().toISOString() } : r
      ));
      toast.success(t('events.checkedIn', 'Гость отмечен!'));
    } catch (error) {
      toast.error(t('events.checkInError', 'Ошибка отметки'));
    }
  };

  // Export handlers
  const handleExportExcel = async () => {
    if (!event || fullRegistrations.length === 0) {
      toast.error(t('events.noDataToExport', 'Нет данных для экспорта'));
      return;
    }

    if (!isPremium) {
      openPremiumPurchase();
      return;
    }

    setExporting(true);
    try {
      await exportToExcel({
        eventTitle: event.title,
        registrations: fullRegistrations,
        formFields: event.formSchema,
        language: i18n.language as SupportedLanguage,
        includeAnswers: true,
      });
      toast.success(t('events.exportSuccess', 'Экспорт в Excel завершён'));
    } catch (error) {
      console.error('Export error:', error);
      toast.error(t('events.exportError', 'Ошибка экспорта'));
    } finally {
      setExporting(false);
    }
  };

  const handleExportCSV = async () => {
    if (!event || fullRegistrations.length === 0) {
      toast.error(t('events.noDataToExport', 'Нет данных для экспорта'));
      return;
    }

    setExporting(true);
    try {
      exportToCSV({
        eventTitle: event.title,
        registrations: fullRegistrations,
        formFields: event.formSchema,
        language: i18n.language as SupportedLanguage,
        includeAnswers: true,
      });
      toast.success(t('events.exportSuccess', 'Экспорт в CSV завершён'));
    } catch (error) {
      console.error('Export error:', error);
      toast.error(t('events.exportError', 'Ошибка экспорта'));
    } finally {
      setExporting(false);
    }
  };

  const handleExportPDF = async () => {
    if (!event || fullRegistrations.length === 0) {
      toast.error(t('events.noDataToExport', 'Нет данных для экспорта'));
      return;
    }

    if (!isPremium) {
      openPremiumPurchase();
      return;
    }

    setExporting(true);
    try {
      const analytics = calculateEventAnalytics(
        fullRegistrations,
        event.formSchema,
        i18n.language as SupportedLanguage
      );

      const eventDate = event.startAt
        ? format(new Date(event.startAt), 'dd MMMM yyyy, HH:mm', { locale })
        : undefined;

      const eventLocation = event.locationType === 'online'
        ? t('events.online', 'Онлайн')
        : event.locationValue || t('events.offline', 'Офлайн');

      await exportEventToPDF({
        eventTitle: event.title,
        eventDate,
        eventLocation,
        registrations: fullRegistrations,
        analytics,
        formFields: event.formSchema,
        language: i18n.language as SupportedLanguage,
        includeAnalytics: true,
        includeRegistrationsList: true,
      });
      toast.success(t('events.exportSuccess', 'Экспорт в PDF завершён'));
    } catch (error) {
      console.error('PDF Export error:', error);
      toast.error(t('events.exportError', 'Ошибка экспорта'));
    } finally {
      setExporting(false);
    }
  };

  const renderRegistrationCard = (reg: Registration) => (
    <Card key={reg.id} className="p-4">
      <div className="flex items-start justify-between gap-3">
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-2 mb-1">
            <h4 className="font-medium truncate">{reg.attendeeName}</h4>
            {reg.status === 'pending' && (
              <Badge variant="outline" className="text-[10px] text-amber-600 border-amber-300">
                {t('events.pendingApproval', 'Ожидает')}
              </Badge>
            )}
            {reg.status === 'cancelled' && (
              <Badge variant="outline" className="text-[10px] text-destructive border-destructive/30">
                {t('events.cancelled', 'Отменён')}
              </Badge>
            )}
            {reg.ticketStatus === 'used' && (
              <Badge className="text-[10px] bg-emerald-500/10 text-emerald-600">
                <UserCheck className="h-3 w-3 mr-1" />
                {t('events.checkedInLabel', 'Отмечен')}
              </Badge>
            )}
          </div>

          <div className="flex flex-wrap items-center gap-3 text-xs text-muted-foreground">
            <span className="flex items-center gap-1">
              <Mail className="h-3 w-3" />
              {reg.attendeeEmail}
            </span>
            {reg.attendeePhone && (
              <span className="flex items-center gap-1">
                <Phone className="h-3 w-3" />
                {reg.attendeePhone}
              </span>
            )}
          </div>

          <div className="flex items-center gap-3 mt-2 text-xs text-muted-foreground">
            <span className="flex items-center gap-1">
              <Clock className="h-3 w-3" />
              {format(new Date(reg.createdAt), 'd MMM, HH:mm', { locale })}
            </span>
            {reg.ticketCode && (
              <span className="flex items-center gap-1 font-mono">
                <Ticket className="h-3 w-3" />
                {reg.ticketCode}
              </span>
            )}
          </div>
        </div>

        <DropdownMenu>
          <DropdownMenuTrigger asChild>
            <Button variant="ghost" size="icon" className="h-8 w-8">
              <MoreVertical className="h-4 w-4" />
            </Button>
          </DropdownMenuTrigger>
          <DropdownMenuContent align="end">
            {reg.status === 'pending' && (
              <>
                <DropdownMenuItem onClick={() => handleApprove(reg.id)}>
                  <Check className="h-4 w-4 mr-2 text-emerald-600" />
                  {t('events.approve', 'Подтвердить')}
                </DropdownMenuItem>
                <DropdownMenuItem onClick={() => handleReject(reg.id)}>
                  <X className="h-4 w-4 mr-2 text-destructive" />
                  {t('events.reject', 'Отклонить')}
                </DropdownMenuItem>
              </>
            )}
            {reg.status === 'confirmed' && reg.ticketStatus !== 'used' && (
              <DropdownMenuItem onClick={() => handleManualCheckIn(reg.id, reg.ticketCode)}>
                <UserCheck className="h-4 w-4 mr-2" />
                {t('events.manualCheckIn', 'Отметить вручную')}
              </DropdownMenuItem>
            )}
            <DropdownMenuItem
              onClick={() => {
                navigator.clipboard.writeText(reg.attendeeEmail);
                toast.success(t('common.copied', 'Скопировано'));
              }}
            >
              <Mail className="h-4 w-4 mr-2" />
              {t('events.copyEmail', 'Копировать email')}
            </DropdownMenuItem>
          </DropdownMenuContent>
        </DropdownMenu>
      </div>
    </Card>
  );

  if (loading) {
    return (
      <div className="p-4 space-y-4">
        <Skeleton className="h-10 w-full" />
        <Skeleton className="h-32 w-full" />
        <Skeleton className="h-24 w-full" />
        <Skeleton className="h-24 w-full" />
      </div>
    );
  }

  if (!event) {
    return null;
  }

  return (
    <div className="min-h-screen safe-area-top">
      {/* Header */}
      <div className="sticky top-0 z-40 bg-background/95 backdrop-blur-xl border-b border-border/10">
        <div className="px-4 py-3">
          <div className="flex items-center gap-3 mb-3">
            <Button variant="ghost" size="icon" onClick={() => router.push('/dashboard/events')}>
              <ArrowLeft className="h-5 w-5" />
            </Button>
            <div className="flex-1 min-w-0">
              <h1 className="text-lg font-bold truncate">{event.title}</h1>
              <div className="flex items-center gap-2 text-xs text-muted-foreground">
                {event.startAt && (
                  <span className="flex items-center gap-1">
                    <CalendarDays className="h-3 w-3" />
                    {format(new Date(event.startAt), 'd MMM yyyy', { locale })}
                  </span>
                )}
                <span className="flex items-center gap-1">
                  <MapPin className="h-3 w-3" />
                  {event.locationType === 'online' ? t('events.online', 'Онлайн') : t('events.offline', 'Офлайн')}
                </span>
              </div>
            </div>
            <Button
              variant="ghost"
              size="icon"
              onClick={handleRefresh}
              disabled={refreshing}
            >
              <RefreshCw className={cn('h-4 w-4', refreshing && 'animate-spin')} />
            </Button>
          </div>

          {/* Stats */}
          <div className="grid grid-cols-4 gap-2 mb-3">
            <Card className="p-2 text-center">
              <div className="text-lg font-bold">{stats.total}</div>
              <div className="text-[10px] text-muted-foreground">{t('events.total', 'Всего')}</div>
            </Card>
            <Card className="p-2 text-center">
              <div className="text-lg font-bold text-emerald-600">{stats.confirmed}</div>
              <div className="text-[10px] text-muted-foreground">{t('events.confirmed', 'Подтв.')}</div>
            </Card>
            <Card className="p-2 text-center">
              <div className="text-lg font-bold text-amber-600">{stats.pending}</div>
              <div className="text-[10px] text-muted-foreground">{t('events.pendingShort', 'Ожид.')}</div>
            </Card>
            <Card className="p-2 text-center">
              <div className="text-lg font-bold text-primary">{stats.checkedIn}</div>
              <div className="text-[10px] text-muted-foreground">{t('events.checkedInShort', 'Чекин')}</div>
            </Card>
          </div>

          {/* Actions */}
          <div className="flex gap-2">
            <Button
              variant="outline"
              size="sm"
              className="flex-1 h-9 text-xs"
              onClick={() => {
                if (!isPremium) {
                  openPremiumPurchase();
                  return;
                }
                router.push(`/dashboard/events/${eventId}/scanner`);
              }}
            >
              <QrCode className="h-4 w-4 mr-1.5" />
              {t('events.scanner', 'Сканер')}
              {!isPremium && <Crown className="h-3 w-3 ml-1 text-amber-500" />}
            </Button>

            {/* Export Dropdown */}
            <DropdownMenu>
              <DropdownMenuTrigger asChild>
                <Button
                  variant="outline"
                  size="sm"
                  className="flex-1 h-9 text-xs"
                  disabled={exporting || registrations.length === 0}
                >
                  {exporting ? (
                    <Loader2 className="h-4 w-4 mr-1.5 animate-spin" />
                  ) : (
                    <Download className="h-4 w-4 mr-1.5" />
                  )}
                  {t('events.export', 'Экспорт')}
                </Button>
              </DropdownMenuTrigger>
              <DropdownMenuContent align="end" className="w-48">
                <DropdownMenuItem onClick={handleExportExcel}>
                  <FileSpreadsheet className="h-4 w-4 mr-2 text-emerald-600" />
                  Excel (.xlsx)
                  {!isPremium && <Crown className="h-3 w-3 ml-auto text-amber-500" />}
                </DropdownMenuItem>
                <DropdownMenuItem onClick={handleExportCSV}>
                  <FileText className="h-4 w-4 mr-2 text-muted-foreground" />
                  CSV
                </DropdownMenuItem>
                <DropdownMenuSeparator />
                <DropdownMenuItem onClick={handleExportPDF}>
                  <BarChart3 className="h-4 w-4 mr-2 text-primary" />
                  {t('events.exportPdfWithCharts', 'PDF + Аналитика')}
                  {!isPremium && <Crown className="h-3 w-3 ml-auto text-amber-500" />}
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>

            <Button
              variant="outline"
              size="sm"
              className="h-9 w-9 p-0"
              onClick={() => window.open(`https://lnkmx.my/${event.pageSlug}`, '_blank')}
            >
              <ExternalLink className="h-4 w-4" />
            </Button>
          </div>
        </div>

        {/* Tabs */}
        <Tabs value={activeTab} onValueChange={(v: string) => setActiveTab(v as typeof activeTab)}>
          <TabsList className="w-full justify-start px-4 h-10 bg-transparent border-b rounded-none">
            <TabsTrigger value="all" className="text-xs">
              {t('events.all', 'Все')} ({stats.total})
            </TabsTrigger>
            <TabsTrigger value="confirmed" className="text-xs">
              {t('events.confirmedTab', 'Подтв.')} ({stats.confirmed})
            </TabsTrigger>
            <TabsTrigger value="pending" className="text-xs">
              {t('events.pendingTab', 'Ожид.')} ({stats.pending})
            </TabsTrigger>
            <TabsTrigger value="checked" className="text-xs">
              {t('events.checkedTab', 'Чекин')} ({stats.checkedIn})
            </TabsTrigger>
          </TabsList>
        </Tabs>
      </div>

      {/* Search */}
      <div className="p-4 pb-2">
        <div className="relative">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input
            value={searchQuery}
            onChange={(e) => setSearchQuery(e.target.value)}
            placeholder={t('events.searchRegistrations', 'Поиск по имени, email, коду...')}
            className="pl-9 h-10 rounded-xl"
          />
        </div>
      </div>

      {/* Registrations List */}
      <ScrollArea className="flex-1">
        <div className="p-4 pt-2 space-y-3">
          {filteredRegistrations.length === 0 ? (
            <Card className="p-6 text-center">
              <Users className="h-8 w-8 mx-auto mb-3 text-muted-foreground" />
              <p className="text-sm text-muted-foreground">
                {searchQuery
                  ? t('events.noSearchResults', 'Ничего не найдено')
                  : t('events.noRegistrations', 'Пока нет регистраций')}
              </p>
            </Card>
          ) : (
            filteredRegistrations.map(renderRegistrationCard)
          )}
        </div>
      </ScrollArea>
    </div>
  );
});

'use client';

/**
 * EventsScreen - Events management dashboard
 * Shows all user events with stats, registrations access, and quick actions
 */
import { memo, useState, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useTranslation } from 'react-i18next';
import { format } from 'date-fns';
import { ru, kk, enUS } from 'date-fns/locale';
import { supabase } from '@/platform/supabase/client';
import { useAuth } from '@/hooks/user/useAuth';
import { usePremiumStatus } from '@/hooks/user/usePremiumStatus';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Skeleton } from '@/components/ui/skeleton';
import { Input } from '@/components/ui/input';
import {
  Calendar,
  Users,
  QrCode,
  Download,
  MapPin,
  Clock,
  Search,
  Plus,
  ExternalLink,
  ChevronRight,
  CalendarDays,
  UserCheck,
  Crown,
  Loader2,
} from 'lucide-react';
import { toast } from 'sonner';
import { openPremiumPurchase } from '@/lib/utils/upgrade-utils';
import { cn } from '@/lib/utils/utils';

interface EventData {
  id: string;
  blockId: string;
  pageId: string;
  pageSlug: string;
  title: string;
  startAt: string | null;
  endAt: string | null;
  locationType: string;
  locationValue: string | null;
  status: string;
  capacity: number | null;
  isPaid: boolean;
  price: number | null;
  currency: string | null;
  totalRegistrations: number;
  checkedIn: number;
  pendingApproval: number;
}

interface EventsScreenProps {
  className?: string;
}

export const EventsScreen = memo(function EventsScreen({ className }: EventsScreenProps) {
  const { t, i18n } = useTranslation();
  const router = useRouter();
  const { user } = useAuth();
  const { isPremium, isLoading: premiumLoading } = usePremiumStatus();

  const [events, setEvents] = useState<EventData[]>([]);
  const [loading, setLoading] = useState(true);
  const [searchQuery, setSearchQuery] = useState('');

  const locale = i18n.language === 'ru' ? ru : i18n.language === 'kk' ? kk : enUS;

  // Fetch events
  useEffect(() => {
    const fetchEvents = async () => {
      if (!user) return;

      try {
        // Fetch events with page info
        const { data: eventsData, error } = await supabase
          .from('events')
          .select(`
            id,
            block_id,
            page_id,
            title_i18n_json,
            start_at,
            end_at,
            location_type,
            location_value,
            status,
            capacity,
            is_paid,
            price_amount,
            currency,
            pages!inner(slug)
          `)
          .eq('owner_id', user.id)
          .order('created_at', { ascending: false });

        if (error) throw error;

        // Get registration counts for each event
        const eventsWithStats: EventData[] = await Promise.all(
          (eventsData || []).map(async (event) => {
            const { data: regs } = await supabase
              .from('event_registrations')
              .select('id, status, event_tickets(status)')
              .eq('event_id', event.id);

            const total = regs?.filter(r => r.status !== 'cancelled').length || 0;
            const checkedIn = regs?.filter(r =>
              r.event_tickets?.some((t: { status: string }) => t.status === 'used')
            ).length || 0;
            const pending = regs?.filter(r => r.status === 'pending').length || 0;

            return {
              id: event.id,
              blockId: event.block_id,
              pageId: event.page_id,
              pageSlug: (event.pages as { slug: string })?.slug || '',
              title: (event.title_i18n_json as Record<string, string>)?.[i18n.language] ||
                (event.title_i18n_json as Record<string, string>)?.ru ||
                t('events.untitled', 'Без названия'),
              startAt: event.start_at,
              endAt: event.end_at,
              locationType: event.location_type || 'online',
              locationValue: event.location_value,
              status: event.status || 'draft',
              capacity: event.capacity,
              isPaid: event.is_paid || false,
              price: event.price_amount,
              currency: event.currency,
              totalRegistrations: total,
              checkedIn,
              pendingApproval: pending,
            };
          })
        );

        setEvents(eventsWithStats);
      } catch (error) {
        console.error('Error fetching events:', error);
        toast.error(t('events.fetchError', 'Ошибка загрузки событий'));
      } finally {
        setLoading(false);
      }
    };

    fetchEvents();
  }, [user, i18n.language, t]);

  // Filter events by search
  const filteredEvents = events.filter(event =>
    event.title.toLowerCase().includes(searchQuery.toLowerCase())
  );

  // Group events by status
  const upcomingEvents = filteredEvents.filter(e =>
    e.status === 'published' && (!e.startAt || new Date(e.startAt) >= new Date())
  );
  const pastEvents = filteredEvents.filter(e =>
    e.startAt && new Date(e.startAt) < new Date()
  );
  const draftEvents = filteredEvents.filter(e => e.status === 'draft');

  const handleOpenScanner = (eventId: string) => {
    if (!isPremium) {
      openPremiumPurchase();
      return;
    }
    router.push(`/dashboard/events/${eventId}/scanner`);
  };

  const handleExportRegistrations = async (eventId: string, eventTitle: string) => {
    if (!isPremium) {
      openPremiumPurchase();
      return;
    }

    try {
      const { data, error } = await supabase
        .from('event_registrations')
        .select('attendee_name, attendee_email, attendee_phone, status, created_at, answers_json')
        .eq('event_id', eventId)
        .order('created_at', { ascending: false });

      if (error) throw error;

      // Get tickets separately
      const { data: ticketsData } = await supabase
        .from('event_tickets')
        .select('registration_id, ticket_code, status, checked_in_at')
        .in('registration_id', (data || []).map(r => r.attendee_email)); // We'll match by registration later

      // Create CSV
      const headers = ['Имя', 'Email', 'Телефон', 'Статус', 'Дата регистрации'];
      const rows = (data || []).map(r => [
        r.attendee_name,
        r.attendee_email,
        r.attendee_phone || '',
        r.status,
        format(new Date(r.created_at), 'dd.MM.yyyy HH:mm'),
      ]);

      const csv = [headers, ...rows].map(row => row.join(',')).join('\n');
      const blob = new Blob(['\ufeff' + csv], { type: 'text/csv;charset=utf-8;' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `${eventTitle.replace(/\s+/g, '_')}_registrations.csv`;
      a.click();
      URL.revokeObjectURL(url);

      toast.success(t('events.exportSuccess', 'Экспорт завершён'));
    } catch (error) {
      console.error('Export error:', error);
      toast.error(t('events.exportError', 'Ошибка экспорта'));
    }
  };

  const renderEventCard = (event: EventData) => {
    const isUpcoming = event.startAt && new Date(event.startAt) > new Date();
    const statusColors: Record<string, string> = {
      draft: 'bg-muted text-muted-foreground',
      published: 'bg-emerald-500/10 text-emerald-600',
      closed: 'bg-red-500/10 text-red-600',
    };

    return (
      <Card
        key={event.id}
        className="p-4 hover:shadow-md transition-shadow cursor-pointer"
        onClick={() => router.push(`/dashboard/events/${event.id}`)}
      >
        <div className="flex items-start justify-between gap-3">
          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-2 mb-1">
              <h3 className="font-semibold truncate">{event.title}</h3>
              <Badge className={cn('text-[10px]', statusColors[event.status])}>
                {t(`events.status.${event.status}`, event.status)}
              </Badge>
              {event.isPaid && (
                <Badge variant="outline" className="text-[10px]">
                  {event.price} {event.currency}
                </Badge>
              )}
            </div>

            <div className="flex flex-wrap items-center gap-3 text-xs text-muted-foreground mb-3">
              {event.startAt && (
                <span className="flex items-center gap-1">
                  <CalendarDays className="h-3 w-3" />
                  {format(new Date(event.startAt), 'd MMM yyyy, HH:mm', { locale })}
                </span>
              )}
              <span className="flex items-center gap-1">
                <MapPin className="h-3 w-3" />
                {event.locationType === 'online'
                  ? t('events.online', 'Онлайн')
                  : t('events.offline', 'Офлайн')}
              </span>
            </div>

            {/* Stats */}
            <div className="flex items-center gap-4">
              <div className="flex items-center gap-1.5 text-sm">
                <Users className="h-4 w-4 text-primary" />
                <span className="font-medium">{event.totalRegistrations}</span>
                {event.capacity && (
                  <span className="text-muted-foreground">/ {event.capacity}</span>
                )}
              </div>
              <div className="flex items-center gap-1.5 text-sm">
                <UserCheck className="h-4 w-4 text-emerald-500" />
                <span>{event.checkedIn}</span>
              </div>
              {event.pendingApproval > 0 && (
                <Badge variant="secondary" className="text-xs">
                  {event.pendingApproval} {t('events.pending', 'ожидают')}
                </Badge>
              )}
            </div>
          </div>

          <ChevronRight className="h-5 w-5 text-muted-foreground shrink-0" />
        </div>

        {/* Quick Actions */}
        <div className="flex items-center gap-2 mt-3 pt-3 border-t">
          <Button
            variant="outline"
            size="sm"
            className="h-8 text-xs gap-1.5"
            onClick={(e) => {
              e.stopPropagation();
              handleOpenScanner(event.id);
            }}
          >
            <QrCode className="h-3.5 w-3.5" />
            {t('events.scanner', 'Сканер')}
            {!isPremium && <Crown className="h-3 w-3 text-amber-500" />}
          </Button>
          <Button
            variant="outline"
            size="sm"
            className="h-8 text-xs gap-1.5"
            onClick={(e) => {
              e.stopPropagation();
              handleExportRegistrations(event.id, event.title);
            }}
          >
            <Download className="h-3.5 w-3.5" />
            {t('events.export', 'Экспорт')}
            {!isPremium && <Crown className="h-3 w-3 text-amber-500" />}
          </Button>
          <Button
            variant="ghost"
            size="sm"
            className="h-8 text-xs gap-1.5 ml-auto"
            onClick={(e) => {
              e.stopPropagation();
              window.open(`https://lnkmx.my/${event.pageSlug}`, '_blank');
            }}
          >
            <ExternalLink className="h-3.5 w-3.5" />
          </Button>
        </div>
      </Card>
    );
  };

  if (loading || premiumLoading) {
    return (
      <div className={cn('p-4 space-y-4', className)}>
        <Skeleton className="h-10 w-full" />
        <Skeleton className="h-32 w-full" />
        <Skeleton className="h-32 w-full" />
        <Skeleton className="h-32 w-full" />
      </div>
    );
  }

  return (
    <div className={cn('min-h-screen safe-area-top', className)}>
      {/* Header */}
      <div className="sticky top-0 z-40 bg-background/95 backdrop-blur-xl border-b border-border/10">
        <div className="px-4 py-3">
          <div className="flex items-center justify-between gap-3 mb-3">
            <div>
              <h1 className="text-lg font-bold">
                {t('events.title', 'События')}
              </h1>
              <p className="text-xs text-muted-foreground">
                {events.length} {t('events.eventsCount', 'событий')}
              </p>
            </div>
          </div>

          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              placeholder={t('events.search', 'Поиск событий...')}
              className="pl-9 h-10 rounded-xl"
            />
          </div>
        </div>
      </div>

      <ScrollArea className="flex-1">
        <div className="p-4 space-y-6">
          {events.length === 0 ? (
            <Card className="p-8 text-center">
              <Calendar className="h-12 w-12 mx-auto mb-4 text-muted-foreground" />
              <h3 className="font-semibold mb-2">
                {t('events.noEvents', 'Нет событий')}
              </h3>
              <p className="text-sm text-muted-foreground mb-4">
                {t('events.noEventsDesc', 'Добавьте блок "Событие" на свою страницу, чтобы начать собирать регистрации')}
              </p>
              <Button onClick={() => router.push('/dashboard/home?tab=editor')}>
                <Plus className="h-4 w-4 mr-2" />
                {t('events.addEventBlock', 'Добавить блок')}
              </Button>
            </Card>
          ) : filteredEvents.length === 0 ? (
            <Card className="p-6 text-center">
              <Search className="h-8 w-8 mx-auto mb-3 text-muted-foreground" />
              <p className="text-sm text-muted-foreground">
                {t('events.noSearchResults', 'Ничего не найдено')}
              </p>
            </Card>
          ) : (
            <>
              {/* Upcoming Events */}
              {upcomingEvents.length > 0 && (
                <section>
                  <h2 className="text-sm font-semibold text-muted-foreground mb-3 flex items-center gap-2">
                    <Clock className="h-4 w-4" />
                    {t('events.upcoming', 'Предстоящие')}
                    <Badge variant="secondary" className="ml-auto">{upcomingEvents.length}</Badge>
                  </h2>
                  <div className="space-y-3">
                    {upcomingEvents.map(renderEventCard)}
                  </div>
                </section>
              )}

              {/* Draft Events */}
              {draftEvents.length > 0 && (
                <section>
                  <h2 className="text-sm font-semibold text-muted-foreground mb-3 flex items-center gap-2">
                    {t('events.drafts', 'Черновики')}
                    <Badge variant="outline" className="ml-auto">{draftEvents.length}</Badge>
                  </h2>
                  <div className="space-y-3">
                    {draftEvents.map(renderEventCard)}
                  </div>
                </section>
              )}

              {/* Past Events */}
              {pastEvents.length > 0 && (
                <section>
                  <h2 className="text-sm font-semibold text-muted-foreground mb-3 flex items-center gap-2">
                    {t('events.past', 'Прошедшие')}
                    <Badge variant="outline" className="ml-auto">{pastEvents.length}</Badge>
                  </h2>
                  <div className="space-y-3">
                    {pastEvents.map(renderEventCard)}
                  </div>
                </section>
              )}
            </>
          )}
        </div>
      </ScrollArea>
    </div>
  );
});

/**
 * InsightsScreen - Comprehensive analytics dashboard with charts and AI recommendations
 */
import { memo, useState, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import { usePageAnalytics } from '@/hooks/analytics/usePageAnalytics';
import {
  Eye,
  MousePointerClick,
  Users,
  Sparkles,
  ArrowRight,
  Smartphone,
  Monitor,
  Globe,
  TrendingUp,
  ChartBar,
  Target,
  RefreshCw,
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Progress } from '@/components/ui/progress';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { DashboardHeader } from '../layout/DashboardHeader';
import { StatCard } from '../common/StatCard';
import { LoadingSkeleton } from '../common/LoadingSkeleton';
import { EmptyState } from '../common/EmptyState';
import {
  AnalyticsChart,
  ConversionFunnel,
  EngagementMetrics,
  GeographyChart,
  TrafficSourcesChart,
  BlockPerformance,
  AnalyticsExport,
} from '../analytics';
import { cn } from '@/lib/utils/utils';
import type { Block } from '@/types/page';
import { motion } from 'framer-motion';

interface InsightsScreenProps {
  pageId: string;
  blocks: Block[];
  isPremium: boolean;
  onApplyInsight: (action: { type: string; blockId?: string; data?: Record<string, unknown> }) => void;
}

type Period = '7d' | '14d' | '30d';
type Tab = 'overview' | 'traffic' | 'blocks' | 'funnel';

const containerVariants = {
  hidden: { opacity: 0 },
  show: {
    opacity: 1,
    transition: {
      staggerChildren: 0.1
    }
  }
};

const itemVariants = {
  hidden: { opacity: 0, y: 20 },
  show: { opacity: 1, y: 0 }
};

export const InsightsScreen = memo(function InsightsScreen({
  pageId,
  blocks,
  isPremium,
  onApplyInsight,
}: InsightsScreenProps) {
  const { t } = useTranslation();
  const [period, setPeriod] = useState<Period>('7d');
  const [activeTab, setActiveTab] = useState<Tab>('overview');
  const { analytics, loading, setPeriod: setAnalyticsPeriod, refresh } = usePageAnalytics();

  const handlePeriodChange = (p: Period) => {
    setPeriod(p);
    if (p === '7d') setAnalyticsPeriod('week');
    else if (p === '14d') setAnalyticsPeriod('two_weeks');
    else if (p === '30d') setAnalyticsPeriod('month');
  };

  // Use real analytics data with fallbacks
  const stats = useMemo(() => ({
    views: analytics?.totalViews ?? 0,
    viewsChange: analytics?.viewsChange ?? 0,
    clicks: analytics?.totalClicks ?? 0,
    clicksChange: analytics?.clicksChange ?? 0,
    shares: analytics?.totalShares ?? 0,
    uniqueVisitors: analytics?.uniqueVisitors ?? 0,
    visitorsChange: analytics?.viewsChange ?? 0,
    avgViewsPerDay: analytics?.avgViewsPerDay ?? 0,
    ctr: analytics && analytics.totalViews > 0
      ? ((analytics.totalClicks / analytics.totalViews) * 100)
      : 0,
    topBlocks: analytics?.topBlocks ?? [],
    devices: {
      mobile: analytics?.deviceBreakdown?.mobile ?? 0,
      desktop: analytics?.deviceBreakdown?.desktop ?? 0,
      tablet: analytics?.deviceBreakdown?.tablet ?? 0,
    },
    sources: analytics?.trafficSources ?? [],
    dailyData: analytics?.dailyData ?? [],
    geoData: analytics?.geoData ?? [],
    avgSessionDuration: analytics?.avgSessionDuration ?? 0,
    bounceRate: analytics?.bounceRate ?? 0,
    returningVisitors: analytics?.returningVisitors ?? 0,
    conversions: analytics?.totalConversions ?? 0,
  }), [analytics]);

  // Calculate device percentages
  const totalDevices = stats.devices.mobile + stats.devices.desktop + stats.devices.tablet;
  const devicePercentages = useMemo(() =>
    totalDevices > 0
      ? {
        mobile: Math.round((stats.devices.mobile / totalDevices) * 100),
        desktop: Math.round((stats.devices.desktop / totalDevices) * 100),
        tablet: Math.round((stats.devices.tablet / totalDevices) * 100),
      }
      : { mobile: 0, desktop: 0, tablet: 0 },
    [totalDevices, stats.devices]
  );

  // AI Insights
  const insights = useMemo(() => {
    const hasPricing = blocks.some((b) => b.type === 'pricing');
    const hasTestimonials = blocks.some((b) => b.type === 'testimonial');
    const hasContactForm = blocks.some((b) => b.type === 'form');

    const suggestions = [];

    // CTR-based insights
    if (stats.ctr < 5 && stats.views > 10) {
      suggestions.push({
        id: 'low-ctr',
        type: 'warning',
        title: t('dashboard.insights.lowCtr', 'Низкий CTR'),
        description: t('dashboard.insights.lowCtrDesc', `CTR всего ${stats.ctr.toFixed(1)}%. Добавьте яркие CTA-кнопки`),
        action: () => onApplyInsight({ type: 'add', data: { blockType: 'button' } }),
        impact: 'high' as const,
      });
    }

    // Bounce rate insights
    if (stats.bounceRate > 70 && stats.views > 10) {
      suggestions.push({
        id: 'high-bounce',
        type: 'warning',
        title: t('dashboard.insights.highBounce', 'Высокий показатель отказов'),
        description: t('dashboard.insights.highBounceDesc', `${stats.bounceRate.toFixed(0)}% посетителей уходят без действий`),
        action: () => onApplyInsight({ type: 'optimize', data: { action: 'improve_engagement' } }),
        impact: 'high' as const,
      });
    }

    if (!hasPricing && blocks.length > 3) {
      suggestions.push({
        id: 'add-pricing',
        type: 'add',
        title: t('dashboard.insights.addPricing', 'Добавьте блок с ценами'),
        description: t('dashboard.insights.addPricingDesc', 'Страницы с прайсом получают на 40% больше заявок'),
        action: () => onApplyInsight({ type: 'add', data: { blockType: 'pricing' } }),
        impact: 'high' as const,
      });
    }

    if (!hasTestimonials && blocks.length > 5) {
      suggestions.push({
        id: 'add-testimonials',
        type: 'add',
        title: t('dashboard.insights.addTestimonials', 'Добавьте отзывы'),
        description: t('dashboard.insights.addTestimonialsDesc', 'Отзывы увеличивают доверие и конверсию на 25%'),
        action: () => onApplyInsight({ type: 'add', data: { blockType: 'testimonial' } }),
        impact: 'medium' as const,
      });
    }

    if (!hasContactForm && stats.views > 50 && stats.conversions === 0) {
      suggestions.push({
        id: 'add-form',
        type: 'add',
        title: t('dashboard.insights.addForm', 'Добавьте форму захвата'),
        description: t('dashboard.insights.addFormDesc', 'Есть трафик, но нет конверсий. Добавьте форму обратной связи'),
        action: () => onApplyInsight({ type: 'add', data: { blockType: 'contact_form' } }),
        impact: 'high' as const,
      });
    }

    if (stats.topBlocks[0]?.ctr > 15) {
      suggestions.push({
        id: 'duplicate-top',
        type: 'optimize',
        title: t('dashboard.insights.duplicateTop', 'Продублируйте популярную ссылку'),
        description: t(
          'dashboard.insights.duplicateTopDesc',
          `"${stats.topBlocks[0].blockTitle}" получает ${stats.topBlocks[0].ctr.toFixed(0)}% кликов`
        ),
        action: () => onApplyInsight({ type: 'duplicate', blockId: stats.topBlocks[0].blockId }),
        impact: 'medium' as const,
      });
    }

    // Mobile optimization
    if (devicePercentages.mobile > 80) {
      suggestions.push({
        id: 'mobile-first',
        type: 'info',
        title: t('dashboard.insights.mobileFirst', 'Mobile-first аудитория'),
        description: t('dashboard.insights.mobileFirstDesc', `${devicePercentages.mobile}% с мобильных. Оптимизируйте под телефоны`),
        action: null,
        impact: 'low' as const,
      });
    }

    return suggestions.slice(0, 4);
  }, [blocks, onApplyInsight, stats, devicePercentages, t]);

  if (loading) {
    return (
      <div className="min-h-screen safe-area-top">
        <DashboardHeader title={t('dashboard.insights.title', 'Аналитика')} />
        <div className="px-5 py-6">
          <LoadingSkeleton variant="stats" />
        </div>
      </div>
    );
  }

  const hasData = stats.views > 0 || stats.clicks > 0;

  return (
    <div className="min-h-screen safe-area-top">
      <DashboardHeader
        title={t('dashboard.insights.title', 'Аналитика')}
        subtitle={t('dashboard.insights.subtitle', 'Статистика страницы')}
        actions={
          <div className="flex items-center gap-2">
            <Button variant="ghost" size="icon" onClick={refresh} className="h-8 w-8">
              <RefreshCw className="h-4 w-4" />
            </Button>
            {isPremium && <AnalyticsExport analytics={analytics} period={period} />}
          </div>
        }
      />

      {/* Period Selector */}
      <div className="px-5 pb-4">
        <div className="flex gap-2">
          {(['7d', '14d', '30d'] as Period[]).map((p) => (
            <button
              key={p}
              onClick={() => handlePeriodChange(p)}
              className={cn(
                "flex-1 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest transition-all",
                period === p
                  ? "bg-primary text-primary-foreground shadow-lg shadow-primary/25 scale-[1.05]"
                  : "glass-subtle text-muted-foreground/60 hover:bg-muted"
              )}
            >
              {t(`dashboard.insights.period.${p}`, p === '7d' ? '7 дней' : p === '14d' ? '14 дней' : '30 дней')}
            </button>
          ))}
        </div>
      </div>

      <div className="px-5 pb-24 space-y-6">
        {!hasData ? (
          <EmptyState
            icon={Eye}
            title={t('dashboard.insights.noData', 'Нет данных')}
            description={t('dashboard.insights.noDataDesc', 'Опубликуйте страницу, чтобы начать собирать статистику')}
          />
        ) : (
          <>
            {/* Tab Navigation */}
            <Tabs value={activeTab} onValueChange={(v: string) => setActiveTab(v as Tab)} className="w-full">
              <TabsList className="grid w-full grid-cols-4 h-10">
                <TabsTrigger value="overview" className="text-xs">
                  <ChartBar className="h-3.5 w-3.5 mr-1" />
                  {t('analytics.tabs.overview', 'Обзор')}
                </TabsTrigger>
                <TabsTrigger value="traffic" className="text-xs">
                  <Globe className="h-3.5 w-3.5 mr-1" />
                  {t('analytics.tabs.traffic', 'Трафик')}
                </TabsTrigger>
                <TabsTrigger value="blocks" className="text-xs">
                  <Target className="h-3.5 w-3.5 mr-1" />
                  {t('analytics.tabs.blocks', 'Блоки')}
                </TabsTrigger>
                <TabsTrigger value="funnel" className="text-xs">
                  <TrendingUp className="h-3.5 w-3.5 mr-1" />
                  {t('analytics.tabs.funnel', 'Воронка')}
                </TabsTrigger>
              </TabsList>

              {/* Overview Tab */}
              <TabsContent value="overview" className="mt-4">
                <motion.div
                  className="space-y-4"
                  variants={containerVariants}
                  initial="hidden"
                  animate="show"
                >
                  {/* Main Stats */}
                  <div className="grid grid-cols-2 gap-3">
                    <motion.div variants={itemVariants}>
                      <StatCard
                        icon={Eye}
                        iconBg="bg-blue-500/15"
                        iconColor="text-blue-500"
                        value={stats.views}
                        label={t('dashboard.insights.views', 'Просмотры')}
                        change={stats.viewsChange}
                      />
                    </motion.div>
                    <motion.div variants={itemVariants}>
                      <StatCard
                        icon={MousePointerClick}
                        iconBg="bg-emerald-500/15"
                        iconColor="text-emerald-500"
                        value={stats.clicks}
                        label={t('dashboard.insights.clicks', 'Клики')}
                        change={stats.clicksChange}
                      />
                    </motion.div>
                  </div>

                  <div className="grid grid-cols-2 gap-3">
                    <motion.div variants={itemVariants}>
                      <StatCard
                        icon={Users}
                        iconBg="bg-violet-500/15"
                        iconColor="text-violet-500"
                        value={stats.uniqueVisitors}
                        label={t('dashboard.insights.uniqueVisitors', 'Уникальные')}
                        change={stats.visitorsChange}
                      />
                    </motion.div>
                    <motion.div variants={itemVariants}>
                      <StatCard
                        icon={Target}
                        iconBg="bg-amber-500/15"
                        iconColor="text-amber-500"
                        value={`${stats.ctr.toFixed(1)}%`}
                        label={t('dashboard.insights.ctr', 'CTR')}
                      />
                    </motion.div>
                  </div>

                  {/* Chart */}
                  {stats.dailyData.length > 0 && (
                    <motion.div variants={itemVariants}>
                      <AnalyticsChart
                        data={stats.dailyData}
                        title={t('analytics.chart.title', 'Динамика за период')}
                        showClicks={true}
                      />
                    </motion.div>
                  )}

                  {/* AI Insights */}
                  {insights.length > 0 && (
                    <motion.div variants={itemVariants} className="space-y-3">
                      <div className="flex items-center gap-2 px-1">
                        <Sparkles className="h-5 w-5 text-primary" />
                        <h2 className="font-bold">{t('dashboard.insights.aiInsights', 'AI Рекомендации')}</h2>
                      </div>

                      {insights.map((insight, i) => (
                        <motion.div key={insight.id} variants={itemVariants} custom={i}>
                          <Card
                            className={cn(
                              "p-4 border-l-4 transition-all hover:scale-[1.01]",
                              insight.impact === 'high'
                                ? "border-l-emerald-500 bg-emerald-500/5"
                                : insight.impact === 'medium'
                                  ? "border-l-amber-500 bg-amber-500/5"
                                  : "border-l-blue-500 bg-blue-500/5"
                            )}
                          >
                            <div className="flex items-start gap-3">
                              <div
                                className={cn(
                                  "h-9 w-9 rounded-xl flex items-center justify-center shrink-0",
                                  insight.impact === 'high'
                                    ? "bg-emerald-500/20"
                                    : insight.impact === 'medium'
                                      ? "bg-amber-500/20"
                                      : "bg-blue-500/20"
                                )}
                              >
                                <Sparkles
                                  className={cn(
                                    "h-4 w-4",
                                    insight.impact === 'high'
                                      ? "text-emerald-600"
                                      : insight.impact === 'medium'
                                        ? "text-amber-600"
                                        : "text-blue-600"
                                  )}
                                />
                              </div>

                              <div className="flex-1 min-w-0">
                                <h3 className="font-bold text-sm mb-0.5">{insight.title}</h3>
                                <p className="text-xs text-muted-foreground mb-2">{insight.description}</p>
                                {insight.action && (
                                  <Button size="sm" variant="outline" className="h-7 text-xs rounded-lg" onClick={insight.action}>
                                    {t('dashboard.insights.apply', 'Применить')}
                                    <ArrowRight className="h-3 w-3 ml-1" />
                                  </Button>
                                )}
                              </div>
                            </div>
                          </Card>
                        </motion.div>
                      ))}
                    </motion.div>
                  )}

                  {/* Devices */}
                  <motion.div variants={itemVariants} className="space-y-3">
                    <h2 className="font-bold px-1">{t('dashboard.insights.devices', 'Устройства')}</h2>
                    <div className="grid grid-cols-3 gap-3">
                      <Card className="p-3 text-center">
                        <Smartphone className="h-5 w-5 mx-auto mb-1.5 text-blue-500" />
                        <div className="text-xl font-black">{devicePercentages.mobile}%</div>
                        <div className="text-[10px] text-muted-foreground">{t('dashboard.insights.mobile', 'Телефон')}</div>
                      </Card>
                      <Card className="p-3 text-center">
                        <Monitor className="h-5 w-5 mx-auto mb-1.5 text-emerald-500" />
                        <div className="text-xl font-black">{devicePercentages.desktop}%</div>
                        <div className="text-[10px] text-muted-foreground">{t('dashboard.insights.desktop', 'Компьютер')}</div>
                      </Card>
                      <Card className="p-3 text-center">
                        <Globe className="h-5 w-5 mx-auto mb-1.5 text-violet-500" />
                        <div className="text-xl font-black">{devicePercentages.tablet}%</div>
                        <div className="text-[10px] text-muted-foreground">{t('dashboard.insights.tablet', 'Планшет')}</div>
                      </Card>
                    </div>
                  </motion.div>
                </motion.div>
              </TabsContent>

              {/* Traffic Tab */}
              <TabsContent value="traffic" className="mt-4">
                <motion.div
                  className="space-y-4"
                  initial={{ opacity: 0, y: 20 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ duration: 0.3 }}
                >
                  <EngagementMetrics
                    avgSessionDuration={stats.avgSessionDuration}
                    bounceRate={stats.bounceRate}
                    returningVisitors={stats.returningVisitors}
                    ctr={stats.ctr}
                    totalViews={stats.views}
                    uniqueVisitors={stats.uniqueVisitors}
                  />

                  <TrafficSourcesChart sources={stats.sources} variant="bar" />

                  <GeographyChart data={stats.geoData} totalVisitors={stats.uniqueVisitors} />
                </motion.div>
              </TabsContent>

              {/* Blocks Tab */}
              <TabsContent value="blocks" className="mt-4">
                <motion.div
                  className="space-y-4"
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ duration: 0.3 }}
                >
                  <BlockPerformance
                    blocks={stats.topBlocks}
                    totalViews={stats.views}
                    showChart={true}
                  />

                  {/* Top Blocks List */}
                  {stats.topBlocks.length > 0 && (
                    <div className="space-y-3">
                      <h2 className="font-bold px-1">{t('dashboard.insights.topBlocks', 'Детали по блокам')}</h2>
                      <Card className="divide-y divide-border/50">
                        {stats.topBlocks.slice(0, 5).map((block, index) => (
                          <motion.div
                            key={block.blockId}
                            className="p-4 flex items-center gap-4"
                            initial={{ opacity: 0 }}
                            animate={{ opacity: 1 }}
                            transition={{ delay: index * 0.05 }}
                          >
                            <div className="h-10 w-10 rounded-xl bg-muted flex items-center justify-center font-bold text-muted-foreground">
                              {index + 1}
                            </div>
                            <div className="flex-1 min-w-0">
                              <div className="font-medium truncate">{block.blockTitle}</div>
                              <div className="text-sm text-muted-foreground">
                                {block.clicks} {t('dashboard.insights.clicksCount', 'кликов')} • CTR: {block.ctr.toFixed(1)}%
                              </div>
                            </div>
                            <div className="w-20">
                              <Progress value={Math.min(100, block.ctr * 5)} className="h-2" />
                            </div>
                          </motion.div>
                        ))}
                      </Card>
                    </div>
                  )}
                </motion.div>
              </TabsContent>

              {/* Funnel Tab */}
              <TabsContent value="funnel" className="mt-4">
                <motion.div
                  className="space-y-4"
                  initial={{ opacity: 0, scale: 0.95 }}
                  animate={{ opacity: 1, scale: 1 }}
                  transition={{ duration: 0.3 }}
                >
                  <ConversionFunnel
                    views={stats.views}
                    clicks={stats.clicks}
                    shares={stats.shares}
                    conversions={stats.conversions}
                  />

                  {/* Conversion insights */}
                  <Card className="p-4">
