              {isPremium && (
                <p className="text-xs text-muted-foreground mt-1">
                  {t('dashboard.monetize.paidPages', 'Paid Pages')}: {defaultLimits.paidPages} • {t('dashboard.monetize.freePages', 'Free Pages')}: {defaultLimits.freePages}
