interface BlockEditorV2Props {
    block: Block | null;
    isOpen: boolean;
    onClose: () => void;
    onSave: (updates: Partial<Block>) => void;
    /** Enable autosave (optional, default: true) */
    enableAutosave?: boolean;
    /** Autosave delay in ms (default: 2000) */
    autosaveDelay?: number;
    /** Delete handler */
    onDelete?: (id: string) => void;
}

// Loading fallback
const EditorFallback = () => (
    <div className="space-y-5 p-5 outline-none" tabIndex={-1} autoFocus>
        <Skeleton className="h-14 w-full rounded-2xl" />
        <Skeleton className="h-14 w-full rounded-2xl" />
        <Skeleton className="h-32 w-full rounded-2xl" />
    </div>
);

export function BlockEditorV2({
    block,
    isOpen,
    onClose,
    onSave,
    enableAutosave = true,
    autosaveDelay = 2000,
    onDelete,
}: BlockEditorV2Props) {
    const { t } = useTranslation();
    const isMobile = useIsMobile();
    const [formData, setFormData] = useState<any>(() => block ? { ...block } : {});
    const [isSaving, setIsSaving] = useState(false);
    const [lastSaved, setLastSaved] = useState<Date | null>(null);
    const [hasUnsavedChanges, setHasUnsavedChanges] = useState(false);
    const autosaveTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
    const deferredFormData = useDeferredValue(formData);
    const currentBlockIdRef = useRef<string | null>(block ? block.id : null);

    // Update formData when block changes (only if it's a completely new block)
    useEffect(() => {
        if (block && block.id !== currentBlockIdRef.current) {
            setFormData({ ...block });
            currentBlockIdRef.current = block.id;
            setHasUnsavedChanges(false);
            setLastSaved(null);
        }
    }, [block]);

    // Check for unsaved changes
    const handleFormChange = useCallback((updates: any) => {
        setFormData(updates);
        setHasUnsavedChanges(true);

        // Autosave if enabled
        if (enableAutosave) {
            if (autosaveTimerRef.current) {
                clearTimeout(autosaveTimerRef.current);
            }
            autosaveTimerRef.current = setTimeout(() => {
                performSave(updates, false);
            }, autosaveDelay);
        }
    }, [enableAutosave, autosaveDelay]);

    // Perform save
    const performSave = useCallback(async (data: any, closeAfter: boolean = true) => {
        setIsSaving(true);
        try {
            await onSave(data);
            setLastSaved(new Date());
            setHasUnsavedChanges(false);
            if (closeAfter) {
                onClose();
            }
        } finally {
            setIsSaving(false);
        }
    }, [onSave, onClose]);

    // Manual save
    const handleSave = useCallback(() => {
        if (autosaveTimerRef.current) {
            clearTimeout(autosaveTimerRef.current);
        }
        performSave(formData, true);
    }, [formData, performSave]);

    // Cleanup autosave timer
    useEffect(() => {
        return () => {
            if (autosaveTimerRef.current) {
                clearTimeout(autosaveTimerRef.current);
            }
        };
    }, []);

    // Intercept close attempt
    const [showUnsavedDialog, setShowUnsavedDialog] = useState(false);

    const handleCloseAttempt = useCallback(() => {
        if (isSaving) return; // Prevent closing while a save is in progress

        if (hasUnsavedChanges && enableAutosave) {
            if (autosaveTimerRef.current) {
                clearTimeout(autosaveTimerRef.current);
            }
            performSave(formData, true);
        } else if (hasUnsavedChanges) {
            setShowUnsavedDialog(true);
        } else {
            onClose();
        }
    }, [hasUnsavedChanges, enableAutosave, performSave, formData, onClose, isSaving]);

    const handleDiscard = useCallback(() => {
        setShowUnsavedDialog(false);
        onClose();
    }, [onClose]);

    const handleSaveAndClose = useCallback(() => {
        if (autosaveTimerRef.current) {
            clearTimeout(autosaveTimerRef.current);
        }
        performSave(formData, true);
        setShowUnsavedDialog(false);
    }, [performSave, formData]);

    if (!block) return null;

    const commonProps = {
        formData,
        onChange: handleFormChange,
    };

    const BlockIcon = useMemo(() => getLucideIcon(BLOCK_ICONS[block.type] || 'Box'), [block.type]);
    const blockTypeName = t(`blockEditor.${block.type}`, block.type);

    const renderEditor = () => {
        switch (block.type) {
            case 'profile':
                return <Suspense fallback={<EditorFallback />}><ProfileEditorWizard {...commonProps} onComplete={() => performSave(formData, true)} /></Suspense>;
            case 'text':
                return <Suspense fallback={<EditorFallback />}><TextBlockEditor {...commonProps} /></Suspense>;
            case 'link':
                return <Suspense fallback={<EditorFallback />}><LinkBlockEditor {...commonProps} /></Suspense>;
            case 'product':
