            case 'testimonial':
                return <Suspense fallback={<EditorFallback />}><TestimonialBlockEditor {...commonProps} /></Suspense>;
            case 'scratch':
                return <Suspense fallback={<EditorFallback />}><ScratchBlockEditor {...commonProps} /></Suspense>;
