}

type BlockTier = 'free' | 'pro';

interface BlockConfig {
  type: string;
  label: string;
  Icon: React.ComponentType<{ className?: string }>;
  color: string;
  tier: BlockTier;
}

// Blocks with colorful icons like competitors - labels are translation keys
const ALL_BLOCKS: BlockConfig[] = [
  // Basic
