                  </TooltipTrigger>
                  <TooltipContent>
                    <p className="text-xs">{t('freemium.upgradeToEdit', 'Обновите до {{tier}} для редактирования', { tier: requiredTier.toUpperCase() })}</p>
                  </TooltipContent>
                </Tooltip>
              ) : (
                <Button
                  variant="ghost"
                  size="sm"
                  className="h-7 sm:h-8 text-xs"
                  onClick={() => onEdit(block.id)}
                >
                  {t('common.edit', 'Edit')}
                </Button>
              )
            )}
            {block.type !== 'profile' && (
              <Button
                variant="ghost"
                size="sm"
                className="h-7 sm:h-8 w-7 sm:w-8 p-0"
                onClick={() => onDelete(block.id)}
              >
                <Trash2 className="h-4 w-4 text-destructive" />
              </Button>
            )}
          </div>
        </div>
      </Card>
    </TooltipProvider>
  );
}

export function DraggableBlockList({
  blocks,
  onReorder,
  onDelete,
  onEdit,
}: DraggableBlockListProps) {
  const { isBlockViewOnly, getRequiredTier } = useFreemiumLimits();

  const sensors = useSensors(
    useSensor(PointerSensor),
    useSensor(KeyboardSensor, {
      coordinateGetter: sortableKeyboardCoordinates,
    })
  );

  const handleDragEnd = (event: DragEndEvent) => {
    const { active, over } = event;

    if (over && active.id !== over.id) {
      const oldIndex = blocks.findIndex((block) => block.id === active.id);
      const newIndex = blocks.findIndex((block) => block.id === over.id);

      const reorderedBlocks = arrayMove(blocks, oldIndex, newIndex);
      onReorder(reorderedBlocks);
    }
  };

  const handleMoveUp = (id: string) => {
    const index = blocks.findIndex((block) => block.id === id);
    if (index > 0) {
      const reorderedBlocks = arrayMove(blocks, index, index - 1);
      onReorder(reorderedBlocks);
    }
  };

  const handleMoveDown = (id: string) => {
    const index = blocks.findIndex((block) => block.id === id);
    if (index < blocks.length - 1) {
      const reorderedBlocks = arrayMove(blocks, index, index + 1);
      onReorder(reorderedBlocks);
    }
  };

  const sortableBlocks = blocks.filter(b => b.type !== 'profile');

  if (sortableBlocks.length === 0) {
    return (
      <div className="text-center py-12 text-muted-foreground">
        <div className="max-w-md mx-auto space-y-2">
          <p className="text-lg font-medium">Блоки отсутствуют</p>
          <p className="text-sm">Добавьте блоки для начала работы</p>
        </div>
      </div>
    );
  }

  return (
    <DndContext
      sensors={sensors}
      collisionDetection={closestCenter}
      onDragEnd={handleDragEnd}
    >
      <SortableContext
        items={sortableBlocks.map(b => b.id)}
        strategy={verticalListSortingStrategy}
      >
        <div className="space-y-3 p-1">
          <div className="text-xs text-muted-foreground mb-3 px-1">
            Всего блоков: {sortableBlocks.length}
          </div>
          {sortableBlocks.map((block, index) => (
            <SortableBlockItem
              key={block.id}
              block={block}
              index={index}
              totalCount={sortableBlocks.length}
              onDelete={onDelete}
              onEdit={onEdit}
              onMoveUp={handleMoveUp}
              onMoveDown={handleMoveDown}
              isViewOnly={isBlockViewOnly(block.type)}
              requiredTier={getRequiredTier(block.type)}
            />
          ))}
        </div>
      </SortableContext>
    </DndContext>
  );
}

