interface SortableGridBlockItemProps {
  block: Block;
  onEdit: (block: Block) => void;
  onDelete: (id: string) => void;
  isPremium?: boolean;
  premiumTier?: PremiumTier;
  isDragging?: boolean;
  isMobile?: boolean;
}

function SortableGridBlockItem({
  block,
  onEdit,
  onDelete,
  isPremium,
  premiumTier,
  isMobile = false,
}: SortableGridBlockItemProps) {
  const {
    attributes,
    listeners,
    setNodeRef,
    transform,
    transition,
    isDragging,
  } = useSortable({ id: block.id });

  const style = {
    transform: CSS.Transform.toString(transform),
    transition,
  };

  // Determine grid span based on block size
  const blockSize = block.blockSize || 'small';
  const dimensions = BLOCK_SIZE_DIMENSIONS[blockSize] || BLOCK_SIZE_DIMENSIONS['small'];

  // Map dimensions to Tailwind classes
  const colSpanClass = dimensions.gridCols === 2 ? 'col-span-2' : 'col-span-1';
  const rowSpanClass = dimensions.gridRows === 2 ? 'row-span-2' : 'row-span-1';

  // Blocks that render without card frame
  const isFrameless = block.type === 'separator' || block.type === 'socials';

  return (
    <div
      ref={setNodeRef}
      style={style}
      className={cn(
        'relative group overflow-hidden transition-all duration-300',
        isFrameless
          ? 'rounded-xl'
          : 'glass-card rounded-2xl border-white/10 shadow-glass hover:shadow-glass-lg hover:border-white/20 hover:scale-[1.01]',
        colSpanClass,
        rowSpanClass,
        isDragging && 'opacity-50 ring-4 ring-primary/30 scale-95 z-50',
        !isFrameless && 'min-h-[140px]',
        !isFrameless && dimensions.gridRows === 2 && 'min-h-[296px]'
      )}
    >
      {/* Drag Handle - top-left on mobile, visible; top-left on desktop, hover */}
      <div
        className={cn(
          "absolute top-2 left-2 z-40 touch-none",
          isMobile
            ? "opacity-100"
            : "cursor-grab active:cursor-grabbing opacity-0 group-hover:opacity-100 transition-opacity",
          isDragging && "opacity-0"
        )}
        {...attributes}
        {...listeners}
      >
        <div className="bg-background/80 backdrop-blur-md p-2 rounded-xl border border-border/10 shadow-sm active:scale-95 transition-transform">
          <GripVertical className="h-5 w-5 text-muted-foreground" />
        </div>
      </div>

      {/* Block Content */}
      <div className="w-full h-full relative z-0">
        <div className="pointer-events-none w-full h-full">
          <BlockRenderer block={block} isPreview isOwnerPremium={isPremium} ownerTier={premiumTier} />
        </div>

        {/* Click Overlay - captures taps/clicks to open editor */}
        <div
          className="absolute inset-0 z-20 cursor-pointer rounded-2xl ring-offset-background transition-colors hover:bg-black/5 active:bg-black/10"
          onClick={(e) => {
            e.preventDefault();
            e.stopPropagation();
            onEdit(block);
          }}
          onTouchEnd={(e) => {
            // Ensure tap works on mobile even with DnD sensors
            e.stopPropagation();
          }}
          role="button"
          tabIndex={0}
          aria-label={`Edit ${block.type} block`}
        />
      </div>

      {/* Edit/Delete Controls - top-right, visible on mobile too */}
      <div className={cn(
        "absolute top-2 right-2 flex gap-1.5 z-30 transition-opacity",
        isMobile ? "opacity-100" : "opacity-0 group-hover:opacity-100"
      )}>
        <Button
          size="sm"
          variant="secondary"
          className="h-8 w-8 p-0 rounded-lg shadow-sm"
          onClick={(e) => {
            e.stopPropagation();
            e.preventDefault();
            onEdit(block);
          }}
          onTouchEnd={(e) => {
            e.stopPropagation();
          }}
        >
          <Edit2 className="h-4 w-4" />
        </Button>
        <Button
          size="sm"
          variant="destructive"
          className="h-8 w-8 p-0 rounded-lg shadow-sm"
          onClick={(e) => {
            e.stopPropagation();
            e.preventDefault();
            onDelete(block.id);
          }}
          onTouchEnd={(e) => {
            e.stopPropagation();
          }}
        >
          <Trash2 className="h-4 w-4" />
        </Button>
      </div>
    </div>
  );
}

// Drag overlay component
function DragOverlayBlockItem({ block, isPremium, premiumTier }: { block: Block; isPremium?: boolean; premiumTier?: PremiumTier }) {
  const blockSize = block.blockSize || 'small';
  const dimensions = BLOCK_SIZE_DIMENSIONS[blockSize] || BLOCK_SIZE_DIMENSIONS['small'];
  const widthClass = dimensions.gridCols === 2 ? 'w-full md:w-[600px]' : 'w-full md:w-[300px]';

  return (
    <div
      className={cn(
        'relative bg-card rounded-2xl border-2 border-primary shadow-xl overflow-hidden cursor-grabbing',
        widthClass,
        dimensions.gridRows === 2 ? 'h-[296px]' : 'h-[140px]'
      )}
    >
      <div className="w-full h-full overflow-hidden opacity-80">
        <BlockRenderer block={block} isPreview isOwnerPremium={isPremium} ownerTier={premiumTier} />
      </div>
      {/* Show handle in overlay to indicate dragging state */}
      <div className="absolute top-0 right-0 z-40 p-3 pt-3 pr-3">
        <div className="bg-primary/20 backdrop-blur-md p-2 rounded-xl">
          <GripVertical className="h-5 w-5 text-primary" />
        </div>
      </div>
    </div>
  );
}

export const GridEditor = memo(function GridEditor({
  blocks,
  isPremium,
  currentTier = 'free',
  premiumTier,
  gridConfig,
  onInsertBlock,
  onEditBlock,
  onDeleteBlock,
  onUpdateBlock,
  onReorderBlocks,
}: GridEditorProps) {
  const { t } = useTranslation();
  const isMobile = useIsMobile();
  const [activeId, setActiveId] = useState<string | null>(null);

  const dndContextId = useId();

  const profileBlock = blocks.find(b => b.type === 'profile') as ProfileBlock | undefined;
  const contentBlocks = blocks.filter(b => b.type !== 'profile');

  // Note: blockIdsKey removed from DndContext key to prevent full remounts on block changes
  // SortableContext items prop handles reconciliation naturally

  const sensors = useSensors(
    useSensor(PointerSensor, {
      activationConstraint: {
        distance: 5 // Minimal distance to detect drag vs click on the handle
      }
    }),
    useSensor(TouchSensor, {
      activationConstraint: {
        delay: 200, // Give onClick time to fire before drag activates
        tolerance: 8
      }
    }),
    useSensor(KeyboardSensor, { coordinateGetter: sortableKeyboardCoordinates })
  );

  const activeBlock = activeId ? contentBlocks.find(b => b.id === activeId) : null;

  const handleDragStart = useCallback((event: DragStartEvent) => {
    setActiveId(event.active.id as string);
  }, []);

  const handleDragEnd = useCallback((event: DragEndEvent) => {
    const { active, over } = event;
    setActiveId(null);

    if (over && active.id !== over.id) {
      const oldIndex = contentBlocks.findIndex(b => b.id === active.id);
      const newIndex = contentBlocks.findIndex(b => b.id === over.id);

      if (oldIndex !== -1 && newIndex !== -1) {
        const reorderedContent = arrayMove(contentBlocks, oldIndex, newIndex);
        const newBlocks = profileBlock ? [profileBlock, ...reorderedContent] : reorderedContent;
        onReorderBlocks?.(newBlocks);
      }
    }
  }, [contentBlocks, profileBlock, onReorderBlocks]);

  const handleInsertBlock = useCallback((blockType: string, position?: number) => {
    const pos = typeof position === 'number' ? position : blocks.length;
    onInsertBlock(blockType, pos);
  }, [onInsertBlock, blocks.length]);

  return (
    <div className="max-w-2xl mx-auto px-4 py-4 space-y-2 pb-32 md:pb-24">
      {/* Profile block */}
      {profileBlock && (
        <div className="relative" data-onboarding="profile-block">
          <InlineProfileEditor
            block={profileBlock}
            onUpdate={(updates) => onUpdateBlock(profileBlock.id, updates)}
          />
        </div>
      )}

      {/* Insert after profile / before first content block */}
      {contentBlocks.length > 0 && (
        <InsertBetweenDivider
          position={0}
          onInsert={handleInsertBlock}
          isPremium={isPremium}
          currentTier={currentTier}
          currentBlockCount={blocks.length}
          isMobile={isMobile}
        />
      )}

      {/* Grid container with interleaved insert dividers */}
      <DndContext
        key={dndContextId}
        sensors={sensors}
        collisionDetection={closestCenter}
        onDragStart={handleDragStart}
        onDragEnd={handleDragEnd}
      >
        <SortableContext
          items={contentBlocks.map(b => b.id)}
          strategy={verticalListSortingStrategy}
        >
          <div className="space-y-2">
            {contentBlocks.map((block, index) => (
              <div key={block.id}>
                <SortableGridBlockItem
                  block={block}
                  onEdit={onEditBlock}
                  onDelete={onDeleteBlock}
                  isPremium={isPremium}
                  premiumTier={premiumTier}
                  isMobile={isMobile}
                />

                {/* Insert divider after each block */}
                {index < contentBlocks.length - 1 && (
                  <InsertBetweenDivider
                    position={index + 1}
                    onInsert={handleInsertBlock}
                    isPremium={isPremium}
                    currentTier={currentTier}
                    currentBlockCount={blocks.length}
                    isMobile={isMobile}
                  />
                )}
              </div>
            ))}
          </div>
        </SortableContext>

        <DragOverlay adjustScale={true}>
          {activeBlock && (
            <DragOverlayBlockItem block={activeBlock} isPremium={isPremium} premiumTier={premiumTier} />
          )}
        </DragOverlay>
      </DndContext>

      {/* Bottom Add Button */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mt-4">
        <motion.div
          className="col-span-1 md:col-span-2 border-2 border-dashed border-border rounded-2xl flex items-center justify-center bg-muted/20 hover:bg-muted/40 transition-colors py-8"
          initial={{ opacity: 0, y: 20 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ delay: 0.2 }}
        >
          <BlockInsertButton
            onInsert={(blockType) => handleInsertBlock(blockType)}
            isPremium={isPremium}
            currentTier={currentTier}
            currentBlockCount={blocks.length}
          />
        </motion.div>
      </div>

      {/* Empty state */}
      {contentBlocks.length === 0 && (
        <div className="text-center py-12 border-2 border-dashed border-border rounded-2xl mx-2 bg-card">
          <p className="text-base text-muted-foreground mb-4 px-6">
            {t('dashboard.addFirstBlock', 'Нажмите + чтобы добавить первый блок')}
          </p>
          <BlockInsertButton
            onInsert={(blockType) => handleInsertBlock(blockType)}
            isPremium={isPremium}
            currentTier={currentTier}
            currentBlockCount={blocks.length}
          />
        </div>
      )}

      {/* Fixed FAB on mobile */}
      {isMobile && (
        <motion.div
          className="fixed bottom-24 right-4 z-40"
          initial={{ scale: 0 }}
          animate={{ scale: 1 }}
          transition={{ type: "spring", stiffness: 260, damping: 20 }}
        >
          <BlockInsertButton
            onInsert={(blockType) => handleInsertBlock(blockType)}
            isPremium={isPremium}
            currentTier={currentTier}
            currentBlockCount={blocks.length}
          />
        </motion.div>
      )}
    </div>
  );
});

import { memo, useState, useRef, useCallback, TouchEvent } from 'react';
import { Pencil, Trash2, GripVertical, ChevronUp, ChevronDown, MoreVertical } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { BlockRenderer } from '@/components/editor/BlockRenderer';
import { MobileBlockActions } from './MobileBlockActions';
import { cn } from '@/lib/utils/utils';
import { useIsMobile } from '@/hooks/ui/use-mobile';
import { useHapticFeedback } from '@/hooks/ui/useHapticFeedback';
import type { Block } from '@/types/page';

interface InlineEditableBlockProps {
  block: Block;
  onEdit: (block: Block) => void;
  onDelete: (id: string) => void;
  onMoveUp?: (id: string) => void;
  onMoveDown?: (id: string) => void;
  onDuplicate?: (block: Block) => void;
  isDragging?: boolean;
  dragHandleProps?: any;
  isFirst?: boolean;
  isLast?: boolean;
  isOwnerPremium?: boolean;
}

export const InlineEditableBlock = memo(function InlineEditableBlock({
  block,
  onEdit,
  onDelete,
  onMoveUp,
  onMoveDown,
  onDuplicate,
  isDragging,
  dragHandleProps,
  isFirst = false,
  isLast = false,
  isOwnerPremium = false,
}: InlineEditableBlockProps) {
  const isMobile = useIsMobile();
  const haptic = useHapticFeedback();
  const [isHovered, setIsHovered] = useState(false);
  const [isTouched, setIsTouched] = useState(false);
  const [showActionsSheet, setShowActionsSheet] = useState(false);
  const isProfileBlock = block.type === 'profile';

  // Swipe state
  const [offsetX, setOffsetX] = useState(0);
  const [isTransitioning, setIsTransitioning] = useState(false);
  const [hasTriggeredHaptic, setHasTriggeredHaptic] = useState(false);
  const startXRef = useRef(0);
  const startYRef = useRef(0);
  const startTimeRef = useRef(0);
  const isSwipingRef = useRef(false);
  const isVerticalScrollRef = useRef(false);
  const longPressTimerRef = useRef<NodeJS.Timeout | null>(null);

  const threshold = 80;
  const maxSwipe = 120;
  const longPressDelay = 350;

  const handleTouchStart = useCallback((e: TouchEvent) => {
    if (isProfileBlock) {
      setIsTouched(true);
      return;
    }

    startXRef.current = e.touches[0].clientX;
    startYRef.current = e.touches[0].clientY;
    startTimeRef.current = Date.now();
    isSwipingRef.current = false;
    isVerticalScrollRef.current = false;
    setIsTransitioning(false);
    setHasTriggeredHaptic(false);

    // Long press detection
    longPressTimerRef.current = setTimeout(() => {
      if (!isSwipingRef.current && !isVerticalScrollRef.current) {
        haptic.heavyTap();
        setShowActionsSheet(true);
      }
    }, longPressDelay);
  }, [isProfileBlock, haptic]);

  const handleTouchMove = useCallback((e: TouchEvent) => {
    if (isProfileBlock) return;

    // Cancel long press on move
    if (longPressTimerRef.current) {
      clearTimeout(longPressTimerRef.current);
      longPressTimerRef.current = null;
    }

    const diffX = e.touches[0].clientX - startXRef.current;
    const diffY = e.touches[0].clientY - startYRef.current;

    // Determine if this is a vertical scroll or horizontal swipe
    if (!isSwipingRef.current && !isVerticalScrollRef.current) {
      if (Math.abs(diffY) > Math.abs(diffX) && Math.abs(diffY) > 10) {
        isVerticalScrollRef.current = true;
        return;
      }
      if (Math.abs(diffX) > 15) {
        isSwipingRef.current = true;
        haptic.lightTap();
      }
    }

    if (isVerticalScrollRef.current) return;

    if (isSwipingRef.current && isMobile) {
      const resistance = Math.abs(diffX) > threshold ? 0.5 : 1;
      const clampedDiff = Math.max(-maxSwipe, Math.min(maxSwipe, diffX * resistance));
      setOffsetX(clampedDiff);

      if (!hasTriggeredHaptic && Math.abs(clampedDiff) >= threshold) {
        haptic.mediumTap();
        setHasTriggeredHaptic(true);
      } else if (hasTriggeredHaptic && Math.abs(clampedDiff) < threshold - 10) {
        setHasTriggeredHaptic(false);
      }
    }
  }, [isProfileBlock, isMobile, hasTriggeredHaptic, haptic, threshold]);

  const handleTouchEnd = useCallback(() => {
    if (longPressTimerRef.current) {
      clearTimeout(longPressTimerRef.current);
      longPressTimerRef.current = null;
    }

    if (isProfileBlock) {
      setTimeout(() => setIsTouched(false), 3000);
      return;
    }

    const touchDuration = Date.now() - startTimeRef.current;
    if (!isSwipingRef.current && !isVerticalScrollRef.current && touchDuration < 200) {
      setIsTouched(true);
      setTimeout(() => setIsTouched(false), 3000);
      return;
    }

    if (!isSwipingRef.current || !isMobile) {
      setOffsetX(0);
      return;
    }

    setIsTransitioning(true);

    if (offsetX < -threshold) {
      haptic.warning();
      setOffsetX(-maxSwipe - 20);
      setTimeout(() => {
        onDelete(block.id);
        setOffsetX(0);
        setIsTransitioning(false);
      }, 250);
    } else if (offsetX > threshold) {
      haptic.success();
      setOffsetX(maxSwipe + 20);
      setTimeout(() => {
        onEdit(block);
        setOffsetX(0);
        setIsTransitioning(false);
      }, 250);
    } else {
      setOffsetX(0);
      setTimeout(() => setIsTransitioning(false), 300);
    }

    isSwipingRef.current = false;
  }, [isProfileBlock, isMobile, offsetX, threshold, maxSwipe, block, onDelete, onEdit, haptic]);

  const showControls = isHovered || isTouched;

  const showDeleteAction = offsetX < -30 && isMobile && !isProfileBlock;
  const showEditAction = offsetX > 30 && isMobile && !isProfileBlock;
  const actionOpacity = Math.min(1, Math.abs(offsetX) / threshold);
  const isAtThreshold = Math.abs(offsetX) >= threshold;
  const actionScale = isAtThreshold ? 1.2 : 0.85 + (Math.abs(offsetX) / threshold) * 0.35;

  return (
    <>
      <div className="relative overflow-visible rounded-3xl">
        {/* Delete action background (swipe left) */}
        {isMobile && !isProfileBlock && (
          <div
            className={cn(
              "absolute inset-y-0 right-0 flex items-center justify-end px-6 transition-all duration-200 rounded-3xl",
              showDeleteAction ? "opacity-100" : "opacity-0 pointer-events-none",
              isAtThreshold && offsetX < 0 ? "bg-destructive" : "bg-destructive/75"
            )}
            style={{
              opacity: showDeleteAction ? actionOpacity : 0,
              width: maxSwipe + 40,
            }}
          >
            <div
              className="flex flex-col items-center gap-2 text-destructive-foreground transition-all duration-200"
              style={{ transform: `scale(${offsetX < 0 ? actionScale : 0.85})` }}
            >
              <div className={cn(
                "h-14 w-14 rounded-2xl bg-white/25 flex items-center justify-center backdrop-blur-sm",
                isAtThreshold && "animate-pulse"
              )}>
                <Trash2 className="h-7 w-7" />
              </div>
              <span className="text-sm font-bold">Удалить</span>
            </div>
          </div>
        )}

        {/* Edit action background (swipe right) */}
        {isMobile && !isProfileBlock && (
          <div
            className={cn(
              "absolute inset-y-0 left-0 flex items-center justify-start px-6 transition-all duration-200 rounded-3xl",
              showEditAction ? "opacity-100" : "opacity-0 pointer-events-none",
              isAtThreshold && offsetX > 0 ? "bg-primary" : "bg-primary/75"
            )}
            style={{
              opacity: showEditAction ? actionOpacity : 0,
              width: maxSwipe + 40,
            }}
          >
            <div
              className="flex flex-col items-center gap-2 text-primary-foreground transition-all duration-200"
              style={{ transform: `scale(${offsetX > 0 ? actionScale : 0.85})` }}
            >
              <div className={cn(
                "h-14 w-14 rounded-2xl bg-white/25 flex items-center justify-center backdrop-blur-sm",
                isAtThreshold && "animate-pulse"
              )}>
                <Pencil className="h-7 w-7" />
              </div>
              <span className="text-sm font-bold">Изменить</span>
            </div>
          </div>
        )}

        {/* Main content wrapper */}
        <div
          className={cn(
            "relative group",
            block.type !== 'separator' && block.type !== 'socials' && "bg-card/70 backdrop-blur-xl rounded-3xl border border-border/20 shadow-glass",
            isDragging && "opacity-50 scale-95 shadow-glass-lg",
            isTransitioning && "transition-transform duration-300 ease-out"
          )}
          style={{
            transform: isMobile && !isProfileBlock ? `translateX(${offsetX}px)` : undefined,
          }}
          onMouseEnter={() => setIsHovered(true)}
          onMouseLeave={() => setIsHovered(false)}
          onTouchStart={handleTouchStart}
          onTouchMove={handleTouchMove}
          onTouchEnd={handleTouchEnd}
          data-onboarding={isProfileBlock ? 'profile-block' : 'block-edit'}
        >
          {/* Hover/Touch overlay with controls */}
          {showControls && !isDragging && (
            <div className="absolute inset-0 bg-primary/10 border-2 border-primary/40 rounded-3xl pointer-events-none z-10 backdrop-blur-sm" />
          )}

          {/* Control buttons - Desktop */}
          {showControls && !isDragging && !isMobile && (
            <div className="absolute -top-3 right-2 flex gap-2 z-20">
              {!isProfileBlock && onMoveUp && onMoveDown && (
                <div className="flex gap-1 bg-card/90 backdrop-blur-xl rounded-2xl shadow-glass border border-border/20 p-1">
                  <Button
                    variant="ghost"
                    size="sm"
                    className="h-9 w-9 p-0 hover:bg-primary/20 rounded-xl"
                    onClick={() => {
                      haptic.lightTap();
                      onMoveUp(block.id);
                    }}
                    disabled={isFirst}
                  >
                    <ChevronUp className="h-5 w-5" />
                  </Button>
                  <Button
                    variant="ghost"
                    size="sm"
                    className="h-9 w-9 p-0 hover:bg-primary/20 rounded-xl"
                    onClick={() => {
                      haptic.lightTap();
                      onMoveDown(block.id);
                    }}
                    disabled={isLast}
                  >
                    <ChevronDown className="h-5 w-5" />
                  </Button>
                </div>
              )}

              {!isProfileBlock && (
                <Button
                  variant="glass"
                  size="sm"
                  className="h-9 w-9 p-0 shadow-glass rounded-xl"
                  {...dragHandleProps}
                >
                  <GripVertical className="h-5 w-5" />
                </Button>
              )}

              <Button
                variant="glass"
                size="sm"
                className="h-9 w-9 p-0 shadow-glass hover:bg-primary/20 rounded-xl"
                onClick={(e) => {
                  e.preventDefault();
                  e.stopPropagation();
                  haptic.lightTap();
                  onEdit(block);
                }}
              >
                <Pencil className="h-4 w-4" />
              </Button>

              {!isProfileBlock && (
                <Button
                  variant="destructive"
                  size="sm"
                  className="h-9 w-9 p-0 shadow-glass backdrop-blur-xl rounded-xl"
                  onClick={() => {
                    haptic.warning();
                    onDelete(block.id);
                  }}
                >
                  <Trash2 className="h-4 w-4" />
                </Button>
              )}
            </div>
          )}

          {/* Mobile: Quick action buttons - MUCH LARGER for easy tapping */}
          {isMobile && showControls && !isDragging && !isProfileBlock && (
            <div className="absolute -top-4 right-3 z-20 flex gap-2">
              <Button
                variant="default"
                size="lg"
                className="h-14 w-14 p-0 rounded-2xl shadow-xl shadow-primary/30"
                onClick={(e) => {
                  e.preventDefault();
                  e.stopPropagation();
                  haptic.mediumTap();
                  onEdit(block);
                }}
                onTouchEnd={(e) => {
                  e.stopPropagation();
                }}
              >
                <Pencil className="h-6 w-6" />
              </Button>
              <Button
                variant="glass"
                size="lg"
                className="h-14 w-14 p-0 rounded-2xl shadow-glass-lg"
                onClick={() => {
                  haptic.mediumTap();
                  setShowActionsSheet(true);
                }}
              >
                <MoreVertical className="h-6 w-6" />
              </Button>
            </div>
          )}

          {/* The actual block */}
          <BlockRenderer block={block} isPreview={false} isOwnerPremium={isOwnerPremium} />

          {/* Mobile swipe hint */}
          {isMobile && !isProfileBlock && isTouched && offsetX === 0 && (
            <div className="absolute bottom-4 left-1/2 -translate-x-1/2 px-5 py-2.5 bg-card/95 backdrop-blur-xl rounded-full text-sm text-muted-foreground shadow-glass border border-border/30 flex items-center gap-3 animate-fade-in font-medium">
              <span className="text-primary text-lg">←</span>
              <span>Свайп для действий</span>
              <span className="text-primary text-lg">→</span>
            </div>
          )}
        </div>
      </div>

      {/* Mobile Actions Sheet */}
      <MobileBlockActions
        block={block}
        open={showActionsSheet}
        onOpenChange={setShowActionsSheet}
        onEdit={onEdit}
        onDelete={onDelete}
        onMoveUp={onMoveUp}
        onMoveDown={onMoveDown}
        onDuplicate={onDuplicate}
        isFirst={isFirst}
        isLast={isLast}
      />
    </>
  );
});

