                  >
                    <LogOut className="h-4 w-4 mr-2" />
                    {t('auth.signOut', 'Выйти')}
                  </Button>
                </Card>
              </TabsContent>
            </Tabs>
          </div>
        </SheetContent>
      </Sheet>

      {/* CRM Leads Panel */}
      <LeadsPanel open={leadsPanelOpen} onOpenChange={setLeadsPanelOpen} />
    </>
  );
});

'use client';

import { memo, useState } from 'react';
import { useTranslation } from 'react-i18next';
import { useRouter } from 'next/navigation';
import {
  Save,
  Eye,
  Upload,
  Settings,
  Wand2,
  LayoutTemplate,
  Trophy,
  Users,
  Globe,
  MoreHorizontal,
  X,
  Store,
  Coins,
  ImageIcon,
  Crown,
  Flame,
  Check,
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
  SheetDescription,
} from '@/components/ui/sheet';
import { LanguageSwitcher } from '@/components/translation/LanguageSwitcher';
import { AutoSaveIndicator, type SaveStatus } from './AutoSaveIndicator';
import { StreakDisplay } from '@/components/streak/StreakDisplay';
import { TokenBalanceDisplay } from '@/components/tokens/TokenBalanceDisplay';
import { cn } from '@/lib/utils/utils';

interface MobileToolbarProps {
  saving: boolean;
  saveStatus: SaveStatus;
  onSave: () => void;
  onPreview: () => void;
  onShare: () => void;
  onOpenSettings: () => void;
  onOpenAIBuilder: () => void;
  onOpenTemplates: () => void;
  onOpenMarketplace: () => void;
  onOpenAchievements: () => void;
  onOpenCRM: () => void;
  onOpenTokens: () => void;
  onOpenGallery: () => void;
  achievementCount: number;
  userId?: string;
}

export const MobileToolbar = memo(function MobileToolbar({
  saving,
  saveStatus,
  onSave,
  onPreview,
  onShare,
  onOpenSettings,
  onOpenAIBuilder,
  onOpenTemplates,
  onOpenMarketplace,
  onOpenAchievements,
  onOpenCRM,
  onOpenTokens,
  onOpenGallery,
  achievementCount,
  userId,
}: MobileToolbarProps) {
  const { t } = useTranslation();
  const router = useRouter();
  const [moreOpen, setMoreOpen] = useState(false);

  // Helper to handle actions that close the sheet and open another dialog
  // Uses a timeout to prevent aria-hidden focus issues (Radix UI race condition)
  const handleAction = (action: () => void) => {
    setMoreOpen(false);
    setTimeout(() => {
      action();
    }, 100);
  };

  // Main actions for bottom bar - simplified to 4 main actions
  const mainActions = [
    {
      icon: Eye,
      label: t('mobileToolbar.preview', 'Смотреть'),
      onClick: onPreview,
      variant: 'ghost' as const,
      color: 'text-blue-500',
