    {
      icon: Upload,
      label: t('mobileToolbar.share', 'Опубликовать'),
      onClick: onShare,
      variant: 'default' as const,
      primary: true,
    },
    {
      icon: Settings,
      label: t('mobileToolbar.settings', 'Настройки'),
      onClick: onOpenSettings,
      variant: 'ghost' as const,
      color: 'text-muted-foreground',
    },
    {
      icon: MoreHorizontal,
