      { type: 'link', overrides: { title: { ru: '🎬 YouTube', en: '🎬 YouTube', kk: '🎬 YouTube' }, url: 'https://youtube.com/', icon: 'youtube', style: 'rounded' } },
      { type: 'link', overrides: { title: { ru: '🔗 Ваша ссылка', en: '🔗 Your link', kk: '🔗 Сіздің сілтемеңіз' }, url: 'https://example.com', icon: 'link', style: 'rounded' } },
      { type: 'socials', overrides: { platforms: [{ platform: 'instagram', url: 'https://instagram.com/' }, { platform: 'telegram', url: 'https://t.me/' }, { platform: 'tiktok', url: 'https://tiktok.com/' }] } },
    ],
  },
  {
    id: 'blank',
    name: 'Пустой шаблон',
    description: 'Начните с чистого листа — полная свобода',
    category: 'other',
    preview: '📄',
    blocks: [],
  },
];

const CATEGORIES: TemplateCategoryKey[] = [...TEMPLATE_CATEGORY_KEYS];

interface TemplateGalleryProps {
  open: boolean;
  onClose: () => void;
  onSelect: (blocks: Block[]) => void;
}

export const TemplateGallery = memo(function TemplateGallery({
  open,
  onClose,
  onSelect,
}: TemplateGalleryProps) {
  const { t } = useTranslation();
  const [selectedCategory, setSelectedCategory] = useState<TemplateCategoryKey>('all');
  const [copiedId, setCopiedId] = useState<string | null>(null);
  const [personalizationOpen, setPersonalizationOpen] = useState(false);
  const [selectedTemplate, setSelectedTemplate] = useState<Template | null>(null);
  const [marketplaceOpen, setMarketplaceOpen] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [smartPrompt, setSmartPrompt] = useState('');

  const handleSmartMatch = async () => {
    if (!smartPrompt.trim()) return;

    setIsGenerating(true);
    try {
      // 1. Find best template
      const words = smartPrompt.toLowerCase().split(/\s+/);
      let bestTemplateId = 'personal';

      for (const word of words) {
        if (MATCH_KEYWORDS[word]) {
          bestTemplateId = MATCH_KEYWORDS[word];
          break;
        }
      }

      // Default to business/agency if description implies business but no specific keyword matches
      if (bestTemplateId === 'personal' && (smartPrompt.toLowerCase().includes('business') || smartPrompt.toLowerCase().includes('company'))) {
        bestTemplateId = 'agency';
      }

      const template = templates.find(t => t.id === bestTemplateId) || templates[0];

      // 2. Call AI to fill content
      const { data, error } = await supabase.functions.invoke('ai-content-generator', {
        body: {
          type: 'template-filler',
          input: {
            prompt: smartPrompt,
            templateBlocks: template.blocks
          }
        }
      });

      if (error) throw error;

      // 3. Apply overrides
      const aiBlocks = data.result.blocks || data.result;
      const finalBlocks = aiBlocks.map((b: any) => createTemplateBlock(b.type, b.overrides));

      onSelect(finalBlocks);
      onClose();
      toast.success(t('templates.generated', 'Template generated successfully!'));

    } catch (error) {
      console.error(error);
      toast.error(t('templates.error', 'Generation failed'));
    } finally {
      setIsGenerating(false);
    }
  };

  const handleSelect = (template: Template) => {
    // Generate blocks with full structure from block-factory + overrides
    const fullBlocks = template.blocks.map((blockDef) =>
      createTemplateBlock(blockDef.type, blockDef.overrides || {})
    );
    onSelect(fullBlocks);
    setCopiedId(template.id);
    setTimeout(() => {
      setCopiedId(null);
      onClose();
    }, 500);
  };

  // Fetch templates from DB
  const { data: dbTemplates, isLoading } = useTemplates();

  // Use DB templates if available, otherwise fallback to hardcoded
  // This ensures the gallery is never empty during migration
  const templates = (dbTemplates && dbTemplates.length > 0) ? dbTemplates : HARDCODED_TEMPLATES;

  const filteredTemplates = selectedCategory === 'all'
    ? templates
    : templates.filter(t => normalizeTemplateCategory(t.category) === selectedCategory);

  return (
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="max-w-[95vw] sm:max-w-4xl max-h-[85vh] p-0 overflow-hidden">
        <DialogHeader className="p-3 sm:p-6 pb-0">
          <div className="flex items-center justify-between gap-2">
            <DialogTitle className="text-base sm:text-xl flex items-center gap-2">
              <Sparkles className="h-4 w-4 sm:h-5 sm:w-5 text-primary flex-shrink-0" />
              <span className="truncate">{t('templates.title', 'Галерея шаблонов')}</span>
            </DialogTitle>
            <DialogDescription className="sr-only">
              {t('templates.description', 'Выберите шаблон для вашей страницы')}
            </DialogDescription>
            <Button
              variant="outline"
              size="sm"
              onClick={() => setMarketplaceOpen(true)}
              className="gap-1 flex-shrink-0 text-xs sm:text-sm px-2 sm:px-3"
            >
              <Store className="h-3 w-3 sm:h-4 sm:w-4" />
              <span className="hidden xs:inline">{t('templates.marketplace', 'Маркетплейс')}</span>
            </Button>
          </div>
          <DialogDescription className="text-xs sm:text-sm">
            {t('templates.description', 'Выберите готовый шаблон — AI персонализирует под ваш бизнес')}
          </DialogDescription>
        </DialogHeader>

        {/* Smart Match Input */}
        <div className="px-3 sm:px-6 py-4 bg-muted/20 border-b space-y-3">
          <div className="space-y-1.5">
            <Label htmlFor="smart-prompt" className="text-sm font-medium flex items-center gap-1.5">
              <Wand2 className="h-3.5 w-3.5 text-primary" />
              {t('templates.smartMatch.title', 'AI Smart Auto-Fill')}
            </Label>
            <div className="flex gap-2">
              <Input
                id="smart-prompt"
                placeholder={t('templates.smartMatch.placeholder', 'Example: I am a fitness coach in Almaty...')}
                value={smartPrompt}
                onChange={(e) => setSmartPrompt(e.target.value)}
                className="flex-1 bg-background text-sm h-9"
                onKeyDown={(e) => e.key === 'Enter' && handleSmartMatch()}
              />
              <Button
                onClick={handleSmartMatch}
                disabled={isGenerating || !smartPrompt.trim()}
                size="sm"
                className="h-9 px-4 shrink-0"
              >
                {isGenerating ? (
                  <Loader2 className="h-4 w-4 animate-spin" />
                ) : (
                  <>
                    <Sparkles className="h-4 w-4 mr-1.5" />
                    {t('templates.smartMatch.button', 'Generate')}
                  </>
                )}
              </Button>
            </div>
            <p className="text-[10px] sm:text-xs text-muted-foreground">
              {t('templates.smartMatch.hint', 'Describe your business and we will select & fill the best template for you.')}
            </p>
          </div>
        </div>

        {/* Category Filter - Horizontal scroll on mobile */}
        <div className="px-3 sm:px-6 py-2 sm:py-3 border-b overflow-hidden">
          <div className="flex gap-1.5 sm:gap-2 overflow-x-auto pb-1 scrollbar-hide -mx-1 px-1">
            {CATEGORIES.map((category) => (
              <Button
                key={category}
                variant={selectedCategory === category ? 'default' : 'outline'}
                size="sm"
                onClick={() => setSelectedCategory(category)}
                className="whitespace-nowrap text-[11px] sm:text-sm px-2.5 sm:px-3 h-7 sm:h-9 flex-shrink-0"
              >
                {getTemplateCategoryLabel(t, category)}
              </Button>
            ))}
          </div>
        </div>

        <ScrollArea className="h-[55vh] sm:h-[55vh]">
          <div className="p-3 sm:p-6 pt-3 sm:pt-4">
            <div className="grid grid-cols-2 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-2 sm:gap-4">
              {filteredTemplates.map((template) => (
                <Card
                  key={template.id}
                  className={`relative p-2.5 sm:p-4 hover:border-primary cursor-pointer transition-all hover:shadow-lg group active:scale-[0.98] ${copiedId === template.id ? 'border-green-500 bg-green-500/10' : ''
                    }`}
                  onClick={() => handleSelect(template)}
                >
                  {template.isPremium && (
                    <Badge className="absolute -top-1.5 -right-1.5 sm:-top-2 sm:-right-2 bg-gradient-to-r from-amber-500 to-orange-500 text-white text-[9px] sm:text-[10px] px-1.5">
                      PRO
                    </Badge>
                  )}

                  <div className="text-2xl sm:text-4xl mb-1.5 sm:mb-2 text-center group-hover:scale-110 transition-transform">
                    {copiedId === template.id ? (
                      <Check className="h-6 w-6 sm:h-8 sm:w-8 mx-auto text-green-500" />
                    ) : (
                      template.preview
                    )}
                  </div>

                  <h4 className="font-semibold text-[11px] sm:text-sm text-center mb-0.5 sm:mb-1 truncate">
                    {template.name}
                  </h4>

                  <p className="text-[9px] sm:text-xs text-muted-foreground text-center line-clamp-2 min-h-[2em] sm:min-h-[2.5em]">
                    {template.description}
                  </p>

                  <div className="mt-1.5 sm:mt-3 text-center">
                    <Badge variant="secondary" className="text-[9px] sm:text-xs px-1.5 sm:px-2">
                      {template.blocks.length} {t('templates.blocks', 'блоков')}
                    </Badge>
                  </div>
                </Card>
              ))}
            </div>
          </div>
        </ScrollArea>

        <div className="flex justify-end gap-2 p-3 sm:p-4 border-t bg-muted/30">
          <Button variant="outline" onClick={onClose} className="w-full sm:w-auto text-sm">
            {t('common.cancel', 'Отмена')}
          </Button>
        </div>
      </DialogContent>

      {/* Personalization Dialog */}
      {selectedTemplate && (
        <TemplatePersonalization
          open={personalizationOpen}
          onClose={() => setPersonalizationOpen(false)}
          templateBlocks={selectedTemplate.blocks}
          templateName={selectedTemplate.name}
          onApply={(blocks, profile) => {
            onSelect(blocks);
            setPersonalizationOpen(false);
            onClose();
          }}
        />
      )}

      {/* Marketplace Dialog */}
      <TemplateMarketplace
        open={marketplaceOpen}
        onClose={() => setMarketplaceOpen(false)}
        onApplyTemplate={(blocks) => {
          onSelect(blocks);
          setMarketplaceOpen(false);
          onClose();
        }}
      />
    </Dialog>
  );
});

import { memo, useState, useEffect, useCallback, useMemo } from 'react';
import {
  Dialog,
  DialogContent,
  DialogDescription,
  DialogHeader,
  DialogTitle,
} from '@/components/ui/dialog';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { ScrollArea } from '@/components/ui/scroll-area';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Input } from '@/components/ui/input';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import {
  Heart,
  Download,
  ShoppingCart,
  Search,
  TrendingUp,
  Clock,
  Star,
  Loader2,
  Eye,
  User,
  Filter,
  X,
  Layers
} from 'lucide-react';
import { useTranslation } from 'react-i18next';
import { supabase } from '@/platform/supabase/client';
import { toast } from 'sonner';
import { useAuth } from '@/hooks/user/useAuth';
import { useTokens } from '@/hooks/user/useTokens';
import { redirectToTokenPurchase } from '@/lib/token-purchase-helper';
import type { Block } from '@/types/page';
import { createBlock as createBaseBlock } from '@/lib/blocks/block-factory';
import { TemplatePreviewCard } from '@/components/templates/TemplatePreviewCard';
import {
  TEMPLATE_CATEGORY_KEYS,
  type TemplateCategoryKey,
  getTemplateCategoryLabel,
  normalizeTemplateCategory,
} from '@/lib/templateCategories';

interface Author {
  username: string | null;
  display_name: string | null;
  avatar_url: string | null;
}

interface UserTemplate {
  id: string;
  user_id: string;
  name: string;
  description: string | null;
  category: string;
  preview_url: string | null;
  blocks: unknown;
  is_public: boolean;
  is_for_sale: boolean;
  price: number;
  currency: string;
  downloads_count: number;
  likes_count: number;
  created_at: string;
  author?: Author;
}

interface TemplateMarketplaceProps {
  open: boolean;
  onClose: () => void;
  onApplyTemplate: (blocks: Block[]) => void;
}

const CATEGORIES: TemplateCategoryKey[] = [...TEMPLATE_CATEGORY_KEYS];

export const TemplateMarketplace = memo(function TemplateMarketplace({
  open,
  onClose,
  onApplyTemplate,
}: TemplateMarketplaceProps) {
  const { t } = useTranslation();
  const { user } = useAuth();
  const { balance, purchaseMarketplaceItem, refresh: refreshBalance } = useTokens();
  const [templates, setTemplates] = useState<UserTemplate[]>([]);
  const [loading, setLoading] = useState(true);
  const [purchasing, setPurchasing] = useState<string | null>(null);
  const [searchQuery, setSearchQuery] = useState('');
  const [authorQuery, setAuthorQuery] = useState('');
  const [selectedCategory, setSelectedCategory] = useState<TemplateCategoryKey>('all');
  const [activeTab, setActiveTab] = useState('popular');
  const [purchasedTemplates, setPurchasedTemplates] = useState<string[]>([]);

  const fetchTemplates = useCallback(async () => {
    setLoading(true);
    try {
      let query = supabase
        .from('user_templates')
        .select('*')
        .eq('is_public', true);

      if (activeTab === 'popular') {
        query = query.order('likes_count', { ascending: false });
      } else if (activeTab === 'new') {
        query = query.order('created_at', { ascending: false });
      } else if (activeTab === 'free') {
        query = query.eq('is_for_sale', false);
      } else if (activeTab === 'premium') {
        query = query.eq('is_for_sale', true);
      }

      const { data, error } = await query.limit(100);
      if (error) throw error;

      const templatesData = (data || []) as unknown as UserTemplate[];

      // Fetch author profiles for all templates
      const userIds = Array.from(new Set(templatesData.map(t => t.user_id).filter(Boolean)));
      if (userIds.length > 0) {
        const { data: profiles } = await supabase
          .from('public_user_profiles')
          .select('id, username, display_name, avatar_url')
          .in('id', userIds);

        const profilesMap = new Map(
          (profiles || []).map(p => [p.id, p])
        );

        templatesData.forEach(template => {
          const profile = profilesMap.get(template.user_id);
          if (profile) {
            template.author = {
              username: profile.username,
              display_name: profile.display_name,
              avatar_url: profile.avatar_url,
            };
          }
        });
      }

      setTemplates(templatesData);

      // Fetch purchased templates
      if (user) {
        const { data: purchases } = await supabase
          .from('template_purchases')
          .select('template_id')
          .eq('buyer_id', user.id);

        setPurchasedTemplates(purchases?.map(p => p.template_id) || []);
      }
    } catch (error) {
      console.error('Error fetching templates:', error);
    } finally {
      setLoading(false);
    }
  }, [activeTab, user]);

  useEffect(() => {
    if (open) {
      fetchTemplates();
    }
  }, [open, fetchTemplates]);

  const handleLike = async (templateId: string) => {
    if (!user) {
      toast.error(t('auth.loginRequired', 'Войдите в аккаунт'));
      return;
    }

    try {
      await supabase.rpc('like_template', { p_template_id: templateId });
      setTemplates(prev =>
        prev.map(t => t.id === templateId ? { ...t, likes_count: t.likes_count + 1 } : t)
      );
    } catch (error) {
      console.error('Like error:', error);
    }
  };

  const handlePurchase = async (template: UserTemplate) => {
    if (!user) {
      toast.error(t('auth.loginRequired', 'Войдите в аккаунт'));
      return;
    }

    const price = template.price || 0;
    const currentBalance = balance?.balance || 0;

    // Check if user has enough tokens
    if (currentBalance < price) {
      const deficit = price - currentBalance;
      toast.info(t('templates.notEnoughTokens', 'Недостаточно токенов. Нужно еще {{amount}} Linkkon.', { amount: deficit.toFixed(0) }));
      redirectToTokenPurchase(deficit, template.name);
      return;
    }

    setPurchasing(template.id);
    try {
      const success = await purchaseMarketplaceItem(
        template.user_id,
        'template',
        template.id,
        price,
        t('templates.purchaseTemplate', 'Покупка шаблона: {{name}}', { name: template.name })
      );

      if (success) {
        setPurchasedTemplates(prev => [...prev, template.id]);
        refreshBalance();
        applyTemplate(template);
      }
    } finally {
      setPurchasing(null);
    }
  };

  const applyTemplate = (template: UserTemplate) => {
    const blocksArray = Array.isArray(template.blocks) ? template.blocks : [];
    const blocks: Block[] = blocksArray.map((blockData: any, index: number) => {
      const baseBlock = createBaseBlock(blockData.type);
      return {
        ...baseBlock,
        ...blockData,
        id: `${blockData.type}-${Date.now()}-${index}`,
      } as Block;
    });

    onApplyTemplate(blocks);
    toast.success(t('templates.applied', 'Шаблон применён!'));
    onClose();
  };

  const handleApply = (template: UserTemplate) => {
    if (template.is_for_sale && !purchasedTemplates.includes(template.id)) {
      handlePurchase(template);
    } else {
      applyTemplate(template);
    }
  };

  const filteredTemplates = useMemo(() => {
    return templates.filter(t => {
      // Search by name/description
      const matchesSearch = searchQuery === '' ||
        t.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
        t.description?.toLowerCase().includes(searchQuery.toLowerCase());

      // Filter by category
      const matchesCategory = selectedCategory === 'all' ||
        normalizeTemplateCategory(t.category) === selectedCategory;

      // Search by author
      const matchesAuthor = authorQuery === '' ||
        t.author?.username?.toLowerCase().includes(authorQuery.toLowerCase()) ||
        t.author?.display_name?.toLowerCase().includes(authorQuery.toLowerCase());

      return matchesSearch && matchesCategory && matchesAuthor;
    });
  }, [templates, searchQuery, selectedCategory, authorQuery]);

  const formatPrice = (price: number, currency: string) => {
    return new Intl.NumberFormat('ru-KZ', {
      style: 'currency',
      currency,
      minimumFractionDigits: 0,
    }).format(price);
  };

  const hasActiveFilters = selectedCategory !== 'all' || authorQuery !== '';

  const clearFilters = () => {
    setSelectedCategory('all');
    setAuthorQuery('');
    setSearchQuery('');
  };

  const getAuthorDisplayName = (author?: Author) => {
    if (!author) return t('templates.unknownAuthor', 'Неизвестный автор');
    return author.display_name || author.username || t('templates.unknownAuthor', 'Неизвестный автор');
  };

  return (
    <Dialog open={open} onOpenChange={(v: boolean) => !v && onClose()}>
      <DialogContent className="max-w-[95vw] sm:max-w-4xl max-h-[90vh] p-0 overflow-hidden">
        <DialogHeader className="p-3 sm:p-6 pb-2 sm:pb-4">
          <div className="flex items-center justify-between">
            <DialogTitle className="flex items-center gap-2 text-base sm:text-xl">
              <ShoppingCart className="h-4 w-4 sm:h-5 sm:w-5" />
              {t('templates.marketplace', 'Маркетплейс шаблонов')}
            </DialogTitle>
            {balance && (
              <Badge variant="secondary" className="bg-amber-500/10 text-amber-600 text-xs sm:text-sm">
                {balance.balance.toFixed(0)} Linkkon
              </Badge>
            )}
          </div>
          <DialogDescription className="text-xs sm:text-sm">
            {t('templates.marketplaceDesc', 'Шаблоны от сообщества — готовые к использованию')}
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-3 sm:space-y-4 px-3 sm:px-6">
          {/* Search and Filters */}
          <div className="space-y-2 sm:space-y-3">
            {/* Main search */}
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
              <Input
                placeholder={t('templates.search', 'Поиск шаблонов...')}
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="pl-9 h-9 sm:h-10 text-sm"
              />
            </div>

            {/* Filters row */}
            <div className="flex flex-wrap gap-1.5 sm:gap-2">
              {/* Category filter */}
              <Select value={selectedCategory} onValueChange={(value: string) => setSelectedCategory(value as TemplateCategoryKey)}>
                <SelectTrigger className="w-[130px] sm:w-[160px] h-9 sm:h-10 text-xs sm:text-sm">
                  <Filter className="h-3 w-3 sm:h-4 sm:w-4 mr-1 sm:mr-2" />
                  <SelectValue placeholder={t('templates.category', 'Категория')} />
                </SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">
                    {getTemplateCategoryLabel(t, 'all')}
                  </SelectItem>
                  {CATEGORIES.filter(c => c !== 'all').map((category) => (
                    <SelectItem key={category} value={category}>
                      {getTemplateCategoryLabel(t, category)}
                    </SelectItem>
                  ))}
                </SelectContent>
              </Select>

              {/* Author search */}
              <div className="relative flex-1 min-w-[140px] sm:min-w-[180px]">
                <User className="absolute left-3 top-1/2 -translate-y-1/2 h-3 w-3 sm:h-4 sm:w-4 text-muted-foreground" />
                <Input
                  placeholder={t('templates.searchAuthor', 'По автору...')}
                  value={authorQuery}
                  onChange={(e) => setAuthorQuery(e.target.value)}
                  className="pl-8 sm:pl-9 h-9 sm:h-10 text-xs sm:text-sm"
                />
              </div>

              {/* Clear filters button */}
              {hasActiveFilters && (
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={clearFilters}
                  className="h-9 sm:h-10 px-2 sm:px-3 text-xs sm:text-sm"
                >
                  <X className="h-3 w-3 sm:h-4 sm:w-4 mr-0.5 sm:mr-1" />
                  <span className="hidden sm:inline">{t('templates.clearFilters', 'Сбросить')}</span>
                  <span className="sm:hidden">×</span>
                </Button>
              )}
            </div>
          </div>

          <Tabs value={activeTab} onValueChange={(v: string) => setActiveTab(v)}>
            <TabsList className="grid w-full grid-cols-4 h-8 sm:h-10">
              <TabsTrigger value="popular" className="text-[10px] sm:text-sm px-1 sm:px-3">
                <TrendingUp className="h-3 w-3 mr-0.5 sm:mr-1" />
                <span className="hidden xs:inline">{t('templates.popular', 'Популярные')}</span>
                <span className="xs:hidden">🔥</span>
              </TabsTrigger>
              <TabsTrigger value="new" className="text-[10px] sm:text-sm px-1 sm:px-3">
                <Clock className="h-3 w-3 mr-0.5 sm:mr-1" />
                <span className="hidden xs:inline">{t('templates.new', 'Новые')}</span>
                <span className="xs:hidden">🆕</span>
              </TabsTrigger>
              <TabsTrigger value="free" className="text-[10px] sm:text-sm px-1 sm:px-3">
                <Star className="h-3 w-3 mr-0.5 sm:mr-1" />
                <span className="hidden xs:inline">{t('templates.free', 'Бесплатные')}</span>
                <span className="xs:hidden">✨</span>
              </TabsTrigger>
