  lt: { name: 'Lietuvių', flag: '🇱🇹' },
};

// Default languages to show - English is primary
const DEFAULT_LANGUAGES: LocaleCode[] = ['en', 'ru', 'kk'];

interface FlexibleMultilingualInputProps {
  label: string;
  value: I18nText;
  onChange: (value: I18nText) => void;
  type?: 'input' | 'textarea';
  placeholder?: string;
  required?: boolean;
  enableRichText?: boolean;
  /** Languages to show by default */
  defaultLanguages?: LocaleCode[];
  /** Allow adding more languages */
  allowAddLanguages?: boolean;
  /** Primary/required language - English by default */
  primaryLanguage?: LocaleCode;
}

export function FlexibleMultilingualInput({
  label,
  value,
  onChange,
  type = 'input',
  placeholder,
  required = false,
  enableRichText = false,
  defaultLanguages = DEFAULT_LANGUAGES,
  allowAddLanguages = true,
  primaryLanguage = 'en',
}: FlexibleMultilingualInputProps) {
  const { t } = useTranslation();
  
  // Active languages - includes defaults + any languages that have content
  const [activeLanguages, setActiveLanguages] = useState<LocaleCode[]>(() => {
    const existing = Object.keys(value || {}).filter(k => value[k]?.trim());
    const combined = new Set([...defaultLanguages, ...existing]);
    return Array.from(combined);
  });
  
  const [activeTab, setActiveTab] = useState<LocaleCode>(primaryLanguage);
  const [isTranslating, setIsTranslating] = useState(false);
  const [languagePickerOpen, setLanguagePickerOpen] = useState(false);

  // Available languages to add
  const availableLanguages = useMemo(() => {
    return Object.entries(ALL_LANGUAGES)
      .filter(([code]) => !activeLanguages.includes(code))
      .map(([code, info]) => ({ code, ...info }));
  }, [activeLanguages]);

  const handleChange = (lang: LocaleCode, text: string) => {
    onChange({
      ...value,
      [lang]: text,
    });
  };

  const handleAddLanguage = (langCode: LocaleCode) => {
    setActiveLanguages(prev => [...prev, langCode]);
    setActiveTab(langCode);
    setLanguagePickerOpen(false);
  };

  const handleRemoveLanguage = (langCode: LocaleCode) => {
    // Can't remove primary language
    if (langCode === primaryLanguage) return;
    
    setActiveLanguages(prev => prev.filter(l => l !== langCode));
    
    // Clear the content for this language
    const newValue = { ...value };
    delete newValue[langCode];
    onChange(newValue);
    
    // Switch tab if needed
    if (activeTab === langCode) {
      setActiveTab(primaryLanguage);
    }
  };

  const handleTranslate = async () => {
    const sourceText = value[activeTab];
    if (!sourceText?.trim()) {
      toast.error(t('ai.noTextToTranslate', 'Введите текст для перевода'));
      return;
    }

    setIsTranslating(true);
    try {
      const targetLanguages = activeLanguages.filter(l => l !== activeTab);
      
      const { data, error } = await supabase.functions.invoke('translate-content', {
        body: {
          text: sourceText,
          sourceLanguage: activeTab,
          targetLanguages,
        },
      });

      if (error) throw error;

      onChange({
        ...value,
        ...data.translations,
      });

      toast.success(t('ai.translationSuccess', 'Перевод выполнен'));
    } catch (error) {
      console.error('Translation error:', error);
      toast.error(t('ai.translationError', 'Ошибка перевода'));
    } finally {
      setIsTranslating(false);
    }
  };

  const InputComponent = type === 'textarea' ? Textarea : Input;

  const getLanguageInfo = (code: LocaleCode) => 
    ALL_LANGUAGES[code] || { name: code.toUpperCase(), flag: '🏳️' };

  // Determine grid columns based on number of languages
  const getGridCols = () => {
    const count = activeLanguages.length;
    if (count <= 3) return 'grid-cols-3';
    if (count <= 4) return 'grid-cols-4';
    if (count <= 5) return 'grid-cols-5';
    return 'grid-cols-6';
  };

  return (
    <div className="space-y-2">
      <div className="flex items-center justify-between gap-2">
        <Label>
          {label}
          {required && <span className="text-destructive ml-1">*</span>}
        </Label>
        <div className="flex items-center gap-1">
          <Button
            type="button"
            variant="ghost"
            size="sm"
            onClick={handleTranslate}
            disabled={isTranslating || !value[activeTab]?.trim()}
            className="h-7 px-2 text-xs gap-1.5"
            title={t('ai.translateToOthers', 'Перевести на другие языки')}
          >
            {isTranslating ? (
              <Loader2 className="h-3.5 w-3.5 animate-spin" />
            ) : (
              <Languages className="h-3.5 w-3.5" />
            )}
            <span className="hidden sm:inline">{t('ai.translate', 'Перевести')}</span>
          </Button>
          
          {allowAddLanguages && availableLanguages.length > 0 && (
            <Popover open={languagePickerOpen} onOpenChange={setLanguagePickerOpen}>
              <PopoverTrigger asChild>
                <Button
                  type="button"
                  variant="ghost"
                  size="sm"
                  className="h-7 px-2"
                  title={t('language.addLanguage', 'Добавить язык')}
                >
                  <Plus className="h-3.5 w-3.5" />
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-60 p-0" align="end">
                <Command>
                  <CommandInput placeholder={t('language.searchLanguage', 'Поиск языка...')} />
                  <CommandList>
                    <CommandEmpty>{t('language.noLanguageFound', 'Язык не найден')}</CommandEmpty>
                    <CommandGroup>
                      {availableLanguages.map((lang) => (
                        <CommandItem
                          key={lang.code}
                          value={`${lang.code} ${lang.name}`}
                          onSelect={() => handleAddLanguage(lang.code)}
                          className="gap-2"
                        >
                          <span>{lang.flag}</span>
                          <span>{lang.name}</span>
                          <span className="text-muted-foreground text-xs ml-auto">
                            {lang.code.toUpperCase()}
                          </span>
                        </CommandItem>
                      ))}
                    </CommandGroup>
                  </CommandList>
                </Command>
              </PopoverContent>
            </Popover>
          )}
        </div>
      </div>

      <Tabs value={activeTab} onValueChange={(val) => setActiveTab(val as LocaleCode)}>
        <TabsList className={`grid w-full ${getGridCols()}`}>
          {activeLanguages.map((langCode) => {
            const lang = getLanguageInfo(langCode);
            const hasContent = !!value[langCode]?.trim();
            
            return (
              <TabsTrigger 
                key={langCode} 
                value={langCode} 
                className="gap-1 relative group"
              >
                <span>{lang.flag}</span>
                <span className="hidden sm:inline text-xs">{lang.name}</span>
                {hasContent && (
                  <span className="absolute -top-1 -right-1 w-1.5 h-1.5 bg-primary rounded-full" />
                )}
                {langCode !== primaryLanguage && activeLanguages.length > 1 && (
                  <button
                    type="button"
                    onClick={(e) => {
                      e.stopPropagation();
                      handleRemoveLanguage(langCode);
                    }}
                    className="absolute -top-1.5 -right-1.5 w-4 h-4 bg-destructive text-destructive-foreground rounded-full opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center"
                  >
                    <X className="h-2.5 w-2.5" />
                  </button>
                )}
              </TabsTrigger>
            );
          })}
        </TabsList>

        {activeLanguages.map((langCode) => {
          const lang = getLanguageInfo(langCode);
          
          return (
            <TabsContent key={langCode} value={langCode} className="mt-2">
              {enableRichText ? (
                <RichTextEditor
                  value={value[langCode] || ''}
                  onChange={(text) => handleChange(langCode, text)}
                  placeholder={placeholder ? `${placeholder} (${lang.name})` : undefined}
                  type={type}
                />
              ) : (
                <InputComponent
                  value={value[langCode] || ''}
                  onChange={(e) => handleChange(langCode, e.target.value)}
                  placeholder={placeholder ? `${placeholder} (${lang.name})` : undefined}
                  className={type === 'textarea' ? 'min-h-[100px]' : ''}
                />
              )}
              {langCode === primaryLanguage && required && (
                <p className="text-xs text-muted-foreground mt-1">
                  {t('fields.requiredEnglish', 'Required field (English is mandatory)')}
                </p>
              )}
            </TabsContent>
          );
        })}
      </Tabs>

      {activeLanguages.length > defaultLanguages.length && (
        <div className="flex flex-wrap gap-1">
          <span className="text-xs text-muted-foreground">
            {t('language.additionalLanguages', 'Дополнительные языки:')}
          </span>
          {activeLanguages
            .filter(l => !defaultLanguages.includes(l))
            .map(langCode => {
              const lang = getLanguageInfo(langCode);
              return (
                <Badge key={langCode} variant="secondary" className="text-xs gap-1">
                  {lang.flag} {langCode.toUpperCase()}
                </Badge>
              );
            })}
        </div>
      )}

      {enableRichText && (
        <p className="text-xs text-muted-foreground">
          {t('hints.richTextVisual', 'Используйте кнопку 🔗 для добавления ссылок. Переносы строк сохраняются.')}
        </p>
      )}
    </div>
  );
}

// Re-export for backward compatibility
export { FlexibleMultilingualInput as I18nInput };

import { useState, useRef, useCallback } from 'react';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription, DialogFooter } from '@/components/ui/dialog';
import { VisuallyHidden } from '@radix-ui/react-visually-hidden';
import { Button } from '@/components/ui/button';
import { Slider } from '@/components/ui/slider';
import { Label } from '@/components/ui/label';
import { ZoomIn, ZoomOut, Move, RotateCcw, Check, X } from 'lucide-react';
import { useTranslation } from 'react-i18next';

interface ImageCropperProps {
  imageUrl: string;
  open: boolean;
  onClose: () => void;
  onSave: (croppedDataUrl: string) => void;
  aspectRatio?: number; // 1 for square (avatar), 16/9 for cover
  shape?: 'circle' | 'rectangle';
}

export function ImageCropper({
  imageUrl,
  open,
  onClose,
  onSave,
  aspectRatio = 1,
  shape = 'circle',
}: ImageCropperProps) {
  const { t } = useTranslation();
  const [zoom, setZoom] = useState(1);
  const [position, setPosition] = useState({ x: 50, y: 50 });
  const [isDragging, setIsDragging] = useState(false);
  const dragStartRef = useRef({ x: 0, y: 0, posX: 50, posY: 50 });
  const containerRef = useRef<HTMLDivElement>(null);

  const handleMouseDown = (e: React.MouseEvent) => {
    e.preventDefault();
    setIsDragging(true);
    dragStartRef.current = {
      x: e.clientX,
      y: e.clientY,
      posX: position.x,
      posY: position.y,
    };
  };

  const handleMouseMove = useCallback((e: React.MouseEvent) => {
    if (!isDragging) return;
    
    const deltaX = (e.clientX - dragStartRef.current.x) / 2;
    const deltaY = (e.clientY - dragStartRef.current.y) / 2;
    
    setPosition({
      x: Math.max(0, Math.min(100, dragStartRef.current.posX - deltaX / zoom)),
      y: Math.max(0, Math.min(100, dragStartRef.current.posY - deltaY / zoom)),
    });
  }, [isDragging, zoom]);

  const handleMouseUp = () => {
    setIsDragging(false);
  };

  const handleTouchStart = (e: React.TouchEvent) => {
    const touch = e.touches[0];
    setIsDragging(true);
    dragStartRef.current = {
      x: touch.clientX,
      y: touch.clientY,
      posX: position.x,
      posY: position.y,
    };
  };

  const handleTouchMove = useCallback((e: React.TouchEvent) => {
    if (!isDragging) return;
    
    const touch = e.touches[0];
    const deltaX = (touch.clientX - dragStartRef.current.x) / 2;
    const deltaY = (touch.clientY - dragStartRef.current.y) / 2;
    
    setPosition({
      x: Math.max(0, Math.min(100, dragStartRef.current.posX - deltaX / zoom)),
      y: Math.max(0, Math.min(100, dragStartRef.current.posY - deltaY / zoom)),
    });
  }, [isDragging, zoom]);

  const handleReset = () => {
    setZoom(1);
    setPosition({ x: 50, y: 50 });
  };

  const handleSave = () => {
    const canvas = document.createElement('canvas');
    const img = new Image();
    img.crossOrigin = 'anonymous';
    
    img.onload = () => {
      // Fixed output dimensions
      const outputWidth = shape === 'circle' ? 512 : 1200;
      const outputHeight = shape === 'circle' ? 512 : 400; // 3:1 aspect for cover
      
      canvas.width = outputWidth;
      canvas.height = outputHeight;
      
      const ctx = canvas.getContext('2d');
      if (!ctx) return;

      // Calculate crop area maintaining image proportions (object-fit: cover logic)
      const outputAspect = outputWidth / outputHeight;
      const imgAspect = img.width / img.height;
      
      let cropWidth: number;
      let cropHeight: number;
      
      if (imgAspect > outputAspect) {
        // Image is wider - crop sides
        cropHeight = img.height / zoom;
        cropWidth = cropHeight * outputAspect;
      } else {
        // Image is taller - crop top/bottom
        cropWidth = img.width / zoom;
        cropHeight = cropWidth / outputAspect;
      }
      
      // Position the crop area based on user pan
      const maxOffsetX = Math.max(0, img.width - cropWidth);
      const maxOffsetY = Math.max(0, img.height - cropHeight);
      const cropX = maxOffsetX * (position.x / 100);
      const cropY = maxOffsetY * (position.y / 100);

      // Draw cropped image (no stretching)
      ctx.drawImage(
        img,
        cropX,
        cropY,
        cropWidth,
        cropHeight,
        0,
        0,
        outputWidth,
        outputHeight
      );

      const dataUrl = canvas.toDataURL('image/jpeg', 0.9);
      onSave(dataUrl);
    };
    
    img.src = imageUrl;
  };

  const previewStyle: React.CSSProperties = {
    width: '100%',
    height: '100%',
    objectFit: 'cover',
    objectPosition: `${position.x}% ${position.y}%`,
    transform: `scale(${zoom})`,
    transformOrigin: `${position.x}% ${position.y}%`,
    cursor: isDragging ? 'grabbing' : 'grab',
  };

  return (
    <Dialog open={open} onOpenChange={(open) => !open && onClose()}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Move className="h-4 w-4" />
            {t('imageCropper.title', 'Настройка изображения')}
          </DialogTitle>
          <VisuallyHidden>
            <DialogDescription>
              {t('imageCropper.description', 'Перетащите и масштабируйте изображение')}
            </DialogDescription>
          </VisuallyHidden>
        </DialogHeader>

        <div className="space-y-4">
          {/* Preview area */}
          <div
            ref={containerRef}
            className={`relative mx-auto overflow-hidden bg-muted border-2 border-dashed border-border ${
              shape === 'circle' ? 'rounded-full w-48 h-48' : 'rounded-xl w-full aspect-[3/1]'
            }`}
            onMouseDown={handleMouseDown}
            onMouseMove={handleMouseMove}
            onMouseUp={handleMouseUp}
            onMouseLeave={handleMouseUp}
            onTouchStart={handleTouchStart}
            onTouchMove={handleTouchMove}
            onTouchEnd={handleMouseUp}
          >
            <img
              src={imageUrl}
              alt="Preview"
              style={previewStyle}
              draggable={false}
            />
          </div>

          {/* Zoom control */}
          <div className="space-y-2">
            <div className="flex items-center justify-between">
              <Label className="text-sm flex items-center gap-2">
                <ZoomIn className="h-4 w-4" />
                {t('imageCropper.zoom', 'Масштаб')}
              </Label>
              <span className="text-sm text-muted-foreground">{Math.round(zoom * 100)}%</span>
            </div>
            <div className="flex items-center gap-3">
              <ZoomOut className="h-4 w-4 text-muted-foreground" />
              <Slider
                value={[zoom]}
                onValueChange={([value]) => setZoom(value)}
                min={1}
                max={3}
                step={0.1}
                className="flex-1"
              />
              <ZoomIn className="h-4 w-4 text-muted-foreground" />
            </div>
          </div>

          {/* Hint */}
          <p className="text-xs text-muted-foreground text-center">
            {t('imageCropper.hint', 'Перетащите изображение для позиционирования')}
          </p>
        </div>

        <DialogFooter className="flex-row gap-2 sm:gap-2">
          <Button variant="outline" onClick={handleReset} className="flex-1">
            <RotateCcw className="h-4 w-4 mr-2" />
            {t('imageCropper.reset', 'Сбросить')}
          </Button>
          <Button variant="ghost" onClick={onClose}>
            <X className="h-4 w-4 mr-2" />
            {t('actions.cancel', 'Отмена')}
          </Button>
          <Button onClick={handleSave} className="flex-1">
            <Check className="h-4 w-4 mr-2" />
            {t('actions.save', 'Сохранить')}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

import { useState, useRef } from 'react';
import { Upload, X, Loader2, CheckCircle, Crown, Sparkles } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { Badge } from '@/components/ui/badge';
import { supabase } from '@/platform/supabase/client';
import { useAuth } from '@/hooks/user/useAuth';
import { usePremiumStatus } from '@/hooks/user/usePremiumStatus';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';
import { compressImage, getCompressionStats } from '@/lib/utils/image-compression';

interface MediaUploadProps {
  value: string;
  onChange: (url: string) => void;
  accept?: string;
  label?: string;
  placeholder?: string;
  allowGif?: boolean; // Enable GIF support for this field
}

export function MediaUpload({ 
  value, 
  onChange, 
  accept = 'image/*',
  label,
  placeholder = 'https://example.com/image.jpg',
  allowGif = false
}: MediaUploadProps) {
  const { t } = useTranslation();
  const { user } = useAuth();
  const { isPremium } = usePremiumStatus();
  const [uploading, setUploading] = useState(false);
  const [compressing, setCompressing] = useState(false);
  const [compressionInfo, setCompressionInfo] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<string>(value ? 'url' : 'upload');
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Determine accepted file types based on GIF support and premium status
  const getAcceptedTypes = () => {
    if (allowGif && isPremium) {
      return accept.includes('image') ? 'image/*,.gif' : accept;
    }
    return accept;
  };

  const isGifFile = (file: File) => file.type === 'image/gif';
  const isGifUrl = (url: string) => url.toLowerCase().endsWith('.gif');

  const handleFileSelect = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    if (!user) {
      toast.error(t('auth.required', 'Please sign in to upload files'));
      return;
    }

    // Validate file size (15MB limit before compression)
    if (file.size > 15 * 1024 * 1024) {
      toast.error(t('upload.fileTooLarge', 'File size must be less than 15MB'));
      return;
    }

    // Check if GIF is allowed for non-premium users
    if (isGifFile(file) && allowGif && !isPremium) {
      toast.error(t('upload.gifPremiumOnly', 'GIF uploads are available for Premium users only'));
      return;
    }

    setCompressing(true);
    setCompressionInfo(null);

    try {
      // Compress image if it's an image file (skip GIFs to preserve animation)
      let processedFile = file;
      if (file.type.startsWith('image/') && !isGifFile(file)) {
        const originalSize = file.size;
        processedFile = await compressImage(file);
        
        if (processedFile.size < originalSize) {
          const stats = getCompressionStats(originalSize, processedFile.size);
          setCompressionInfo(`${stats.percentage}% ${t('upload.compressed', 'compressed')}`);
        }
      } else if (isGifFile(file)) {
        setCompressionInfo(t('upload.gifPreserved', 'GIF animation preserved'));
      }

      setCompressing(false);
      setUploading(true);

      const fileExt = processedFile.name.split('.').pop();
      const fileName = `${Date.now()}-${Math.random().toString(36).substring(2)}.${fileExt}`;
      const filePath = `${user.id}/${fileName}`;

      const { error: uploadError } = await supabase.storage
        .from('user-media')
        .upload(filePath, processedFile);

      if (uploadError) {
        throw uploadError;
      }

      const { data: { publicUrl } } = supabase.storage
        .from('user-media')
        .getPublicUrl(filePath);

      onChange(publicUrl);
      toast.success(t('upload.success', 'File uploaded successfully'));
    } catch (error: any) {
      console.error('Upload error:', error);
      toast.error(t('upload.error', 'Failed to upload file'));
      setCompressionInfo(null);
    } finally {
      setCompressing(false);
      setUploading(false);
      if (fileInputRef.current) {
        fileInputRef.current.value = '';
      }
    }
  };

  const handleRemove = () => {
    onChange('');
    setCompressionInfo(null);
  };

  const isProcessing = uploading || compressing;

  return (
    <div className="space-y-2">
      {label && <Label>{label}</Label>}
      
      <Tabs value={activeTab} onValueChange={setActiveTab} className="w-full">
        <TabsList className="grid w-full grid-cols-2">
          <TabsTrigger value="upload">{t('upload.tab', 'Upload')}</TabsTrigger>
          <TabsTrigger value="url">{t('url.tab', 'URL')}</TabsTrigger>
        </TabsList>

        <TabsContent value="upload" className="space-y-3">
          <input
            ref={fileInputRef}
            type="file"
            accept={getAcceptedTypes()}
            onChange={handleFileSelect}
            className="hidden"
          />
          
          {value ? (
            <div className="relative">
              {accept.includes('image') ? (
                <img 
                  src={value} 
                  alt="Preview" 
                  className="w-full h-32 object-cover rounded-lg border"
                />
              ) : (
                <div className="w-full h-32 flex items-center justify-center bg-muted rounded-lg border">
                  <span className="text-sm text-muted-foreground truncate px-4">
                    {value.split('/').pop()}
                  </span>
                </div>
              )}
              <Button
                type="button"
                variant="destructive"
                size="icon"
                className="absolute top-2 right-2 h-6 w-6"
                onClick={handleRemove}
              >
                <X className="h-4 w-4" />
              </Button>
              {compressionInfo && (
                <div className="absolute bottom-2 left-2 flex items-center gap-1 bg-primary/90 text-primary-foreground text-xs px-2 py-1 rounded">
                  <CheckCircle className="h-3 w-3" />
                  {compressionInfo}
                </div>
              )}
            </div>
          ) : (
            <Button
              type="button"
              variant="outline"
              className="w-full h-32 flex flex-col gap-2"
              onClick={() => fileInputRef.current?.click()}
              disabled={isProcessing || !user}
            >
              {compressing ? (
                <>
                  <Loader2 className="h-6 w-6 animate-spin" />
                  <span>{t('upload.compressing', 'Compressing...')}</span>
                </>
              ) : uploading ? (
                <>
                  <Loader2 className="h-6 w-6 animate-spin" />
                  <span>{t('upload.uploading', 'Uploading...')}</span>
                </>
              ) : (
                <>
                  <Upload className="h-6 w-6" />
                  <span>{t('upload.click', 'Click to upload')}</span>
                  <div className="flex items-center gap-2 text-xs text-muted-foreground">
                    <span>{t('upload.autoCompress', 'Auto-compressed, max 15MB')}</span>
                    {allowGif && isPremium && (
                      <Badge variant="secondary" className="gap-1 text-xs">
                        <Sparkles className="h-3 w-3" />
                        GIF
                      </Badge>
                    )}
                  </div>
                  {allowGif && !isPremium && (
                    <div className="flex items-center gap-1 text-xs text-muted-foreground">
                      <Crown className="h-3 w-3 text-primary" />
                      <span>{t('upload.gifPremium', 'GIF available with Premium')}</span>
                    </div>
                  )}
                </>
              )}
            </Button>
          )}
          
          {!user && (
            <p className="text-xs text-muted-foreground text-center">
              {t('upload.signInRequired', 'Sign in to upload files')}
            </p>
          )}
        </TabsContent>

        <TabsContent value="url" className="space-y-3">
          <Input
            type="url"
            value={value}
            onChange={(e) => onChange(e.target.value)}
            placeholder={placeholder}
          />
          
          {value && accept.includes('image') && (
            <div className="relative">
              <img 
                src={value} 
                alt="Preview" 
                className="w-full h-32 object-cover rounded-lg border"
                onError={(e) => {
                  (e.target as HTMLImageElement).style.display = 'none';
                }}
              />
            </div>
          )}
        </TabsContent>
      </Tabs>
    </div>
  );
}

/**
 * MultilingualInput - supports flexible languages
 * Updated to use the new I18nText system while maintaining backward compatibility
 */
import { useState, useMemo } from 'react';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { Tabs, TabsList, TabsTrigger, TabsContent } from '@/components/ui/tabs';
import { Button } from '@/components/ui/button';
import { Languages, Loader2, Plus, X } from 'lucide-react';
import {
  LANGUAGES,
  LANGUAGE_DEFINITIONS,
  type MultilingualString,
  type I18nText,
  type LocaleCode,
} from '@/lib/i18n-helpers';
import { supabase } from '@/platform/supabase/client';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';
import { RichTextEditor } from './RichTextEditor';
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from '@/components/ui/popover';
import {
  Command,
  CommandEmpty,
  CommandGroup,
  CommandInput,
  CommandItem,
  CommandList,
} from '@/components/ui/command';

// Extended language definitions
const ALL_LANGUAGES: Record<LocaleCode, { name: string; flag: string }> = {
  ...LANGUAGE_DEFINITIONS,
  tr: { name: 'Türkçe', flag: '🇹🇷' },
  de: { name: 'Deutsch', flag: '🇩🇪' },
  fr: { name: 'Français', flag: '🇫🇷' },
  es: { name: 'Español', flag: '🇪🇸' },
  it: { name: 'Italiano', flag: '🇮🇹' },
  pt: { name: 'Português', flag: '🇵🇹' },
  zh: { name: '中文', flag: '🇨🇳' },
  ja: { name: '日本語', flag: '🇯🇵' },
  ko: { name: '한국어', flag: '🇰🇷' },
  ar: { name: 'العربية', flag: '🇸🇦' },
  uz: { name: "O'zbekcha", flag: '🇺🇿' },
  uk: { name: 'Українська', flag: '🇺🇦' },
  az: { name: 'Azərbaycan', flag: '🇦🇿' },
  ky: { name: 'Кыргызча', flag: '🇰🇬' },
  tg: { name: 'Тоҷикӣ', flag: '🇹🇯' },
  pl: { name: 'Polski', flag: '🇵🇱' },
  vi: { name: 'Tiếng Việt', flag: '🇻🇳' },
};

// Default languages - English is mandatory, others are optional
const DEFAULT_LANGUAGE_CODES: LocaleCode[] = ['en', 'ru', 'kk'];

// Recommended languages for quick add (most popular)
const RECOMMENDED_LANGUAGES: LocaleCode[] = ['de', 'fr', 'es', 'tr', 'uz', 'uk', 'zh', 'ar'];

interface MultilingualInputProps {
  label: string;
  value: MultilingualString | I18nText;
  onChange: (value: MultilingualString | I18nText) => void;
  type?: 'input' | 'textarea';
  placeholder?: string;
  required?: boolean;
  enableRichText?: boolean;
  /** Allow adding more languages beyond the default - now true by default */
  allowAddLanguages?: boolean;
  /** Primary language (required field) - English is default */
  primaryLanguage?: LocaleCode;
  /** Show compact mode with fewer default tabs */
  compact?: boolean;
}

export function MultilingualInput({
  label,
  value,
  onChange,
  type = 'input',
  placeholder,
  required = false,
  enableRichText = false,
  allowAddLanguages = true,
  primaryLanguage = 'en',
  compact = false,
}: MultilingualInputProps) {
  const { t } = useTranslation();

  // Determine active languages from value + defaults
  // In compact mode, only show languages that have content + primary
  const [activeLanguages, setActiveLanguages] = useState<LocaleCode[]>(() => {
    const existingLangs = Object.keys(value || {}).filter(k =>
      (value as I18nText)[k]?.trim()
    );
    // Always include primary language (English)
    const defaultsToShow = compact
      ? [primaryLanguage]
      : DEFAULT_LANGUAGE_CODES;
    const combined = new Set([...defaultsToShow, ...existingLangs]);
    return Array.from(combined);
  });

  const [activeTab, setActiveTab] = useState<LocaleCode>(primaryLanguage);
  const [isTranslating, setIsTranslating] = useState(false);
  const [languagePickerOpen, setLanguagePickerOpen] = useState(false);

  // Available languages to add
  const availableLanguages = useMemo(() => {
    return Object.entries(ALL_LANGUAGES)
      .filter(([code]) => !activeLanguages.includes(code))
      .map(([code, info]) => ({ code, ...info }));
  }, [activeLanguages]);

  const handleChange = (lang: LocaleCode, text: string) => {
    onChange({
      ...value,
      [lang]: text,
    });
  };

  const handleAddLanguage = (langCode: LocaleCode) => {
    setActiveLanguages(prev => [...prev, langCode]);
    setActiveTab(langCode);
    setLanguagePickerOpen(false);
  };

  const handleRemoveLanguage = (langCode: LocaleCode) => {
    // Can't remove primary language (English is mandatory)
    if (langCode === primaryLanguage) return;

    setActiveLanguages(prev => prev.filter(l => l !== langCode));

    const newValue = { ...value } as I18nText;
    delete newValue[langCode];
    onChange(newValue);

    if (activeTab === langCode) {
      setActiveTab(primaryLanguage);
    }
  };

  const handleTranslate = async () => {
    const sourceText = (value as I18nText)[activeTab];
    if (!sourceText?.trim()) {
      toast.error(t('ai.noTextToTranslate', 'Введите текст для перевода'));
      return;
    }

    setIsTranslating(true);
    try {
      const targetLanguages = activeLanguages.filter(l => l !== activeTab);

      const { data, error } = await supabase.functions.invoke('translate-content', {
        body: {
          text: sourceText,
          sourceLanguage: activeTab,
          targetLanguages,
        },
      });

      if (error) throw error;

      onChange({
        ...value,
        ...data.translations,
      });

      toast.success(t('ai.translationSuccess', 'Перевод выполнен'));
    } catch (error) {
      console.error('Translation error:', error);
      toast.error(t('ai.translationError', 'Ошибка перевода'));
    } finally {
      setIsTranslating(false);
    }
  };

  const InputComponent = type === 'textarea' ? Textarea : Input;

  const getLanguageInfo = (code: LocaleCode) =>
    ALL_LANGUAGES[code] || { name: code.toUpperCase(), flag: '🏳️' };

  // Grid columns based on language count
  const getGridCols = () => {
    const count = activeLanguages.length;
    if (count <= 3) return 'grid-cols-3';
    if (count <= 4) return 'grid-cols-4';
    if (count <= 5) return 'grid-cols-5';
    return 'grid-cols-6';
  };

  return (
    <div className="space-y-2">
      <div className="flex items-center justify-between gap-2">
        <Label>
          {label}
          {required && <span className="text-destructive ml-1">*</span>}
        </Label>
        <div className="flex items-center gap-1">
          <Button
            type="button"
            variant="ghost"
            size="sm"
            onClick={handleTranslate}
            disabled={isTranslating || !(value as I18nText)[activeTab]?.trim()}
            className="h-7 px-2 text-xs gap-1.5"
            title={t('ai.translateToOthers', 'Перевести на другие языки')}
          >
            {isTranslating ? (
              <Loader2 className="h-3.5 w-3.5 animate-spin" />
            ) : (
              <Languages className="h-3.5 w-3.5" />
            )}
            <span className="hidden sm:inline">{t('ai.translate', 'Перевести')}</span>
          </Button>

          {allowAddLanguages && availableLanguages.length > 0 && (
            <Popover open={languagePickerOpen} onOpenChange={setLanguagePickerOpen}>
              <PopoverTrigger asChild>
                <Button
                  type="button"
                  variant="ghost"
                  size="sm"
                  className="h-7 px-2"
                  title={t('language.addLanguage', 'Добавить язык')}
                >
                  <Plus className="h-3.5 w-3.5" />
                </Button>
              </PopoverTrigger>
              <PopoverContent className="w-60 p-0" align="end">
                <Command>
                  <CommandInput placeholder={t('language.searchLanguage', 'Поиск языка...')} />
                  <CommandList>
                    <CommandEmpty>{t('language.noLanguageFound', 'Язык не найден')}</CommandEmpty>
                    <CommandGroup>
                      {availableLanguages.map((lang) => (
                        <CommandItem
                          key={lang.code}
                          value={`${lang.code} ${lang.name}`}
                          onSelect={() => handleAddLanguage(lang.code)}
                          className="gap-2"
                        >
                          <span>{lang.flag}</span>
                          <span>{lang.name}</span>
                          <span className="text-muted-foreground text-xs ml-auto">
                            {lang.code.toUpperCase()}
                          </span>
                        </CommandItem>
                      ))}
                    </CommandGroup>
                  </CommandList>
                </Command>
              </PopoverContent>
            </Popover>
          )}
        </div>
      </div>

      <Tabs value={activeTab} onValueChange={(val) => setActiveTab(val as LocaleCode)}>
        <TabsList className={`grid w-full ${getGridCols()} glass-card backdrop-blur-md bg-muted/20 border-white/5`}>
          {activeLanguages.map((langCode) => {
            const lang = getLanguageInfo(langCode);
            const hasContent = !!(value as I18nText)[langCode]?.trim();
            const isPrimary = langCode === primaryLanguage;

            return (
              <TabsTrigger
                key={langCode}
                value={langCode}
                className="gap-1 relative group"
              >
                <span>{lang.flag}</span>
                <span className="hidden sm:inline text-xs">{lang.name}</span>
                {hasContent && !isPrimary && (
                  <span className="absolute -top-1 -right-1 w-1.5 h-1.5 bg-primary rounded-full" />
                )}
                {isPrimary && (
                  <span className="absolute -top-1 -right-1 w-1.5 h-1.5 bg-accent-foreground rounded-full" title="Required" />
                )}
                {!isPrimary && allowAddLanguages && (
                  <button
                    type="button"
                    onClick={(e) => {
                      e.stopPropagation();
                      handleRemoveLanguage(langCode);
                    }}
                    className="absolute -top-1.5 -right-1.5 w-4 h-4 bg-destructive text-destructive-foreground rounded-full opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center"
                  >
                    <X className="h-2.5 w-2.5" />
                  </button>
                )}
              </TabsTrigger>
            );
          })}
        </TabsList>

        {activeLanguages.map((langCode) => {
          const lang = getLanguageInfo(langCode);

          return (
            <TabsContent key={langCode} value={langCode} className="mt-2">
              {enableRichText ? (
                <RichTextEditor
                  value={(value as I18nText)[langCode] || ''}
                  onChange={(text) => handleChange(langCode, text)}
                  placeholder={placeholder ? `${placeholder} (${lang.name})` : undefined}
                  type={type}
                  variant="glass"
                />
              ) : (
                <InputComponent
                  value={(value as I18nText)[langCode] || ''}
                  onChange={(e) => handleChange(langCode, e.target.value)}
                  placeholder={placeholder ? `${placeholder} (${lang.name})` : undefined}
                  className={type === 'textarea' ? 'min-h-[100px]' : ''}
                  variant="glass"
                />
              )}
              {langCode === primaryLanguage && required && (
                <p className="text-xs text-muted-foreground mt-1">
                  {t('fields.requiredEnglish', 'Required field (English is mandatory)')}
                </p>
              )}
            </TabsContent>
          );
        })}
      </Tabs>

      {enableRichText && (
        <p className="text-xs text-muted-foreground">
          {t('hints.richTextVisual', 'Используйте кнопку 🔗 для добавления ссылок. Переносы строк сохраняются.')}
        </p>
      )}
    </div>
  );
}

import { useState, useRef, useCallback } from 'react';
import { Link, Unlink } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Popover, PopoverContent, PopoverTrigger } from '@/components/ui/popover';
import { Label } from '@/components/ui/label';
import { useTranslation } from 'react-i18next';

interface RichTextEditorProps {
  value: string;
  onChange: (value: string) => void;
  placeholder?: string;
  type?: 'input' | 'textarea';
  className?: string;
  variant?: 'default' | 'glass' | 'minimal';
}

export function RichTextEditor({
  value,
  onChange,
  placeholder,
  type = 'textarea',
  className,
  variant = 'default',
}: RichTextEditorProps) {
  const { t } = useTranslation();
  const [isLinkPopoverOpen, setIsLinkPopoverOpen] = useState(false);
  const [linkText, setLinkText] = useState('');
  const [linkUrl, setLinkUrl] = useState('');
  const [selectionStart, setSelectionStart] = useState(0);
  const [selectionEnd, setSelectionEnd] = useState(0);
  const inputRef = useRef<HTMLTextAreaElement | HTMLInputElement>(null);

  const handleSelect = useCallback(() => {
    if (inputRef.current) {
      const start = inputRef.current.selectionStart || 0;
      const end = inputRef.current.selectionEnd || 0;
      setSelectionStart(start);
      setSelectionEnd(end);

      // If text is selected, prefill the link text
      if (start !== end) {
        setLinkText(value.substring(start, end));
      }
    }
  }, [value]);

  const handleInsertLink = () => {
    if (!linkUrl.trim()) return;

    const text = linkText.trim() || linkUrl;
    const markdownLink = `[${text}](${linkUrl})`;

    let newValue: string;
    if (selectionStart !== selectionEnd) {
      // Replace selected text with link
      newValue = value.substring(0, selectionStart) + markdownLink + value.substring(selectionEnd);
    } else {
      // Insert link at cursor position
      newValue = value.substring(0, selectionStart) + markdownLink + value.substring(selectionStart);
    }

    onChange(newValue);
    setIsLinkPopoverOpen(false);
    setLinkText('');
    setLinkUrl('');

    // Focus back on input
    setTimeout(() => {
      if (inputRef.current) {
        inputRef.current.focus();
        const newCursorPos = selectionStart + markdownLink.length;
        inputRef.current.setSelectionRange(newCursorPos, newCursorPos);
      }
    }, 0);
  };

  const handleRemoveLink = () => {
    // Simple regex to find and remove markdown links
    const linkRegex = /\[([^\]]+)\]\([^)]+\)/g;
    const newValue = value.replace(linkRegex, '$1');
    onChange(newValue);
  };

  const hasLinks = /\[([^\]]+)\]\([^)]+\)/.test(value);

  const InputComponent = type === 'textarea' ? Textarea : Input;

  return (
    <div className="space-y-2">
      <div className="flex items-center gap-1">
        <Popover open={isLinkPopoverOpen} onOpenChange={setIsLinkPopoverOpen}>
          <PopoverTrigger asChild>
            <Button
              type="button"
              variant="ghost"
              size="sm"
              className="h-7 px-2"
              title={t('richText.insertLink', 'Вставить ссылку')}
            >
              <Link className="h-3.5 w-3.5" />
            </Button>
          </PopoverTrigger>
          <PopoverContent className="w-72 p-3" align="start">
            <div className="space-y-3">
              <div className="space-y-1.5">
                <Label className="text-xs">{t('richText.linkText', 'Текст ссылки')}</Label>
                <Input
                  value={linkText}
                  onChange={(e) => setLinkText(e.target.value)}
                  placeholder={t('richText.linkTextPlaceholder', 'Например: нажмите сюда')}
                  className="h-8 text-sm"
                />
              </div>
              <div className="space-y-1.5">
                <Label className="text-xs">{t('richText.linkUrl', 'URL')}</Label>
                <Input
                  value={linkUrl}
                  onChange={(e) => setLinkUrl(e.target.value)}
                  placeholder="https://..."
                  className="h-8 text-sm"
                />
              </div>
              <Button
                type="button"
                size="sm"
                className="w-full"
                onClick={handleInsertLink}
                disabled={!linkUrl.trim()}
              >
                {t('richText.insert', 'Вставить')}
              </Button>
            </div>
          </PopoverContent>
        </Popover>

        {hasLinks && (
          <Button
            type="button"
            variant="ghost"
            size="sm"
            className="h-7 px-2"
            onClick={handleRemoveLink}
            title={t('richText.removeLinks', 'Удалить все ссылки')}
          >
            <Unlink className="h-3.5 w-3.5" />
          </Button>
        )}
      </div>

      <InputComponent
        ref={inputRef as any}
        value={value}
        onChange={(e) => onChange(e.target.value)}
        onSelect={handleSelect}
        placeholder={placeholder}
        variant={variant}
        className={type === 'textarea' ? `min-h-[100px] ${className || ''}` : className}
      />
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Badge } from '@/components/ui/badge';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import {
  X, Users, UserPlus, Search, Check,
  X as XIcon, UserMinus, Trophy,
  Sparkles, Clock, ExternalLink, Heart, Gift, Activity
} from 'lucide-react';
import { useFriends } from '@/hooks/user/useFriends';
import { getUserPageSlug } from '@/services/friends';
import { getPageByUserId, likeGalleryPage, unlikeGalleryPage } from '@/services/gallery';
import { toast } from 'sonner';
import { GiftPremiumDialog } from '@/components/social/GiftPremiumDialog';
import { FriendActivityFeed } from '@/components/social/FriendActivityFeed';
import { storage } from '@/lib/storage';

interface FriendsPanelProps {
  onClose: () => void;
}

export function FriendsPanel({ onClose }: FriendsPanelProps) {
  const { t } = useTranslation();
  const {
    friends,
    pendingRequests,
    sentRequests,
    loading,
    sendRequest,
    acceptRequest,
    rejectRequest,
    removeFriend,
    searchUsers,
    pendingCount
  } = useFriends();

  const [searchQuery, setSearchQuery] = useState('');
  const [searchResults, setSearchResults] = useState<Array<{
    id: string;
    username: string | null;
    display_name: string | null;
    avatar_url: string | null;
  }>>([]);
  const [isSearching, setIsSearching] = useState(false);
  const [activeTab, setActiveTab] = useState('friends');
  const [likedPages, setLikedPages] = useState<Set<string>>(() => {
    const storedLikes = storage.get<string[]>('linkmax_liked_pages');
    return new Set(storedLikes || []);
  });
  const [giftRecipient, setGiftRecipient] = useState<{
    id: string;
    username: string | null;
    display_name: string | null;
    avatar_url: string | null;
  } | null>(null);

  const handleToggleLike = async (pageId: string) => {
    const isCurrentlyLiked = likedPages.has(pageId);

    if (isCurrentlyLiked) {
      const newLikedPages = new Set(likedPages);
      newLikedPages.delete(pageId);
      setLikedPages(newLikedPages);
      storage.set('linkmax_liked_pages', Array.from(newLikedPages));
      await unlikeGalleryPage(pageId);
      toast.success(t('friends.likeRemoved', 'Like removed'));
    } else {
      const newLikedPages = new Set(likedPages).add(pageId);
      setLikedPages(newLikedPages);
      storage.set('linkmax_liked_pages', Array.from(newLikedPages));
      await likeGalleryPage(pageId);
      toast.success(t('friends.pageLiked', 'Page liked!'));
    }
  };

  const handleSearch = async (query: string) => {
    setSearchQuery(query);
    if (query.length < 2) {
      setSearchResults([]);
      return;
    }

    setIsSearching(true);
    const results = await searchUsers(query);
    setSearchResults(results);
    setIsSearching(false);
  };

  const handleSendRequest = async (userId: string) => {
    await sendRequest(userId);
    setSearchResults(prev => prev.filter(u => u.id !== userId));
  };

  return (
    <div className="fixed inset-0 bg-background/95 backdrop-blur-md z-50 flex flex-col">
      {/* Header */}
      <div className="flex-shrink-0 border-b border-border/50 bg-background/80 backdrop-blur-sm">
        <div className="flex items-center justify-between p-4">
          <div className="flex items-center gap-3">
            <div className="h-10 w-10 rounded-2xl bg-gradient-to-br from-blue-400 to-purple-500 flex items-center justify-center shadow-lg shadow-purple-500/25">
              <Users className="h-5 w-5 text-white" />
            </div>
            <div>
              <h2 className="text-lg font-bold">{t('friends.title', 'Friends')}</h2>
              <p className="text-xs text-muted-foreground">
                {friends.length} {t('friends.count', 'friends')}
              </p>
            </div>
          </div>
          <Button
            variant="ghost"
            size="icon"
            onClick={onClose}
            className="h-10 w-10 rounded-xl"
          >
            <X className="h-5 w-5" />
          </Button>
        </div>

        {/* Search */}
        <div className="px-4 pb-4">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
            <Input
              value={searchQuery}
              onChange={(e) => handleSearch(e.target.value)}
              placeholder={t('friends.search', 'Search users...')}
              className="pl-10 h-11 rounded-xl bg-card/40 backdrop-blur-xl border-border/30"
            />
          </div>
        </div>

        {/* Tabs */}
        <Tabs value={activeTab} onValueChange={setActiveTab} className="px-4 pb-3">
          <TabsList className="grid w-full grid-cols-4 h-10 rounded-xl bg-muted/50">
            <TabsTrigger value="friends" className="rounded-lg text-xs px-2">
              {t('friends.title', 'Friends')}
            </TabsTrigger>
            <TabsTrigger value="activity" className="rounded-lg text-xs px-2">
              <Activity className="h-3 w-3 mr-1" />
              {t('friends.activity', 'Feed')}
            </TabsTrigger>
            <TabsTrigger value="requests" className="rounded-lg text-xs px-2 relative">
              {t('friends.requests', 'Requests')}
              {pendingCount > 0 && (
                <Badge className="absolute -top-1 -right-1 h-5 w-5 p-0 flex items-center justify-center text-[10px]">
                  {pendingCount}
                </Badge>
              )}
            </TabsTrigger>
            <TabsTrigger value="sent" className="rounded-lg text-xs px-2">
              {t('friends.sent', 'Sent')}
            </TabsTrigger>
          </TabsList>
        </Tabs>
      </div>

      {/* Content */}
      <div className="flex-1 overflow-y-auto p-4">
        {/* Search Results */}
        {searchQuery.length >= 2 && (
          <div className="space-y-3 mb-6">
            <h3 className="text-sm font-semibold text-muted-foreground flex items-center gap-2">
              <Search className="h-4 w-4" />
              {t('friends.searchResults', 'Search results')}
            </h3>
            {isSearching ? (
              <div className="flex items-center justify-center py-8">
                <div className="h-6 w-6 animate-spin rounded-full border-2 border-primary border-t-transparent" />
              </div>
            ) : searchResults.length > 0 ? (
              <div className="space-y-2">
                {searchResults.map(user => (
                  <UserCard
                    key={user.id}
                    user={user}
                    action={
                      <Button
                        size="sm"
                        onClick={() => handleSendRequest(user.id)}
                        className="h-8 rounded-lg gap-1"
                      >
                        <UserPlus className="h-4 w-4" />
                        {t('friends.add', 'Add')}
                      </Button>
                    }
                  />
                ))}
              </div>
            ) : (
              <p className="text-center text-sm text-muted-foreground py-4">
                {t('friends.noResults', 'Users not found')}
              </p>
            )}
          </div>
        )}

        {/* Friends List */}
        {activeTab === 'friends' && (
          <div className="space-y-3">
            {loading ? (
              <LoadingSkeleton />
            ) : friends.length > 0 ? (
              <>
                {/* Friends Stats */}
                <div className="grid grid-cols-3 gap-3 mb-4">
                  <div className="bg-gradient-to-br from-blue-500/10 to-purple-500/10 rounded-2xl p-3 text-center">
                    <Users className="h-5 w-5 mx-auto mb-1 text-blue-500" />
                    <p className="text-lg font-bold">{friends.length}</p>
                    <p className="text-[10px] text-muted-foreground">{t('friends.title', 'Friends')}</p>
                  </div>
                  <div className="bg-gradient-to-br from-amber-500/10 to-orange-500/10 rounded-2xl p-3 text-center">
                    <Trophy className="h-5 w-5 mx-auto mb-1 text-amber-500" />
                    <p className="text-lg font-bold">{Math.floor(friends.length / 5)}</p>
                    <p className="text-[10px] text-muted-foreground">{t('friends.rewards', 'Rewards')}</p>
                  </div>
                  <div className="bg-gradient-to-br from-green-500/10 to-emerald-500/10 rounded-2xl p-3 text-center">
                    <Sparkles className="h-5 w-5 mx-auto mb-1 text-green-500" />
                    <p className="text-lg font-bold">+{friends.length * 2}h</p>
                    <p className="text-[10px] text-muted-foreground">{t('friends.bonuses', 'Bonuses')}</p>
                  </div>
                </div>

                {friends.map(friendship => (
                  <UserCard
                    key={friendship.id}
                    user={friendship.friend_profile}
                    showViewPage
                    onToggleLike={handleToggleLike}
                    likedPages={likedPages}
                    onGift={setGiftRecipient}
                    action={
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => removeFriend(friendship.id)}
                        className="h-8 w-8 p-0 rounded-lg text-destructive hover:text-destructive"
                      >
                        <UserMinus className="h-4 w-4" />
                      </Button>
                    }
                  />
                ))}
              </>
            ) : (
              <EmptyState
                icon={<Users className="h-8 w-8" />}
                title={t('friends.noFriends', 'No friends yet')}
                description={t('friends.findFriends', 'Find friends through search above')}
              />
            )}
          </div>
        )}

        {/* Activity Feed */}
        {activeTab === 'activity' && (
          <FriendActivityFeed maxHeight="calc(100vh - 280px)" />
        )}

        {/* Pending Requests */}
        {activeTab === 'requests' && (
          <div className="space-y-3">
            {pendingRequests.length > 0 ? (
              pendingRequests.map(request => (
                <UserCard
                  key={request.id}
                  user={request.user_profile}
                  action={
                    <div className="flex gap-2">
                      <Button
                        size="sm"
                        onClick={() => acceptRequest(request.id)}
                        className="h-8 rounded-lg gap-1"
                      >
                        <Check className="h-4 w-4" />
                      </Button>
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => rejectRequest(request.id)}
                        className="h-8 rounded-lg"
                      >
                        <XIcon className="h-4 w-4" />
                      </Button>
                    </div>
                  }
                />
              ))
            ) : (
              <EmptyState
                icon={<Clock className="h-8 w-8" />}
                title={t('friends.noRequests', 'No incoming requests')}
                description={t('friends.noRequestsDesc', 'When someone wants to add you as a friend, the request will appear here')}
              />
            )}
          </div>
        )}

        {/* Sent Requests */}
        {activeTab === 'sent' && (
          <div className="space-y-3">
            {sentRequests.length > 0 ? (
              sentRequests.map(request => (
                <UserCard
                  key={request.id}
                  user={request.friend_profile}
                  badge={<Badge variant="secondary" className="text-[10px]">{t('friends.pending', 'Pending')}</Badge>}
                  action={
                    <Button
                      variant="ghost"
                      size="sm"
                      onClick={() => rejectRequest(request.id)}
                      className="h-8 rounded-lg"
                    >
                      <XIcon className="h-4 w-4" />
                    </Button>
                  }
                />
              ))
            ) : (
              <EmptyState
                icon={<UserPlus className="h-8 w-8" />}
                title={t('friends.noSentRequests', 'No sent requests')}
                description={t('friends.noSentRequestsDesc', 'Find friends through search')}
              />
            )}
          </div>
        )}
      </div>

      {/* Gamification Banner */}
      <div className="flex-shrink-0 p-4 border-t border-border/50">
        <div className="bg-gradient-to-r from-primary/10 via-purple-500/10 to-pink-500/10 rounded-2xl p-4">
          <div className="flex items-center gap-3">
            <div className="h-10 w-10 rounded-xl bg-primary/20 flex items-center justify-center">
              <Trophy className="h-5 w-5 text-primary" />
            </div>
            <div className="flex-1">
              <p className="text-sm font-semibold">{t('friends.inviteFriends', 'Invite friends!')}</p>
              <p className="text-xs text-muted-foreground">
                {t('friends.inviteReward', '+2 hours Premium per friend')}
              </p>
            </div>
            <Badge variant="secondary" className="bg-primary/20 text-primary">
              +{friends.length * 2}h
            </Badge>
          </div>
        </div>
      </div>

      {/* Gift Premium Dialog */}
      {giftRecipient && (
        <GiftPremiumDialog
          open={!!giftRecipient}
          onOpenChange={(open) => !open && setGiftRecipient(null)}
          recipient={giftRecipient}
        />
      )}
    </div>
  );
}

interface UserCardProps {
  user?: {
    id: string;
    username: string | null;
    display_name: string | null;
    avatar_url: string | null;
  };
  badge?: React.ReactNode;
  action: React.ReactNode;
  showViewPage?: boolean;
  onGift?: (user: { id: string; username: string | null; display_name: string | null; avatar_url: string | null }) => void;
  onToggleLike?: (pageId: string) => Promise<void>;
  likedPages?: Set<string>;
}

function UserCard({ user, badge, action, showViewPage, onToggleLike, likedPages, onGift }: UserCardProps) {
  const { t } = useTranslation();
  const [pageId, setPageId] = useState<string | null>(null);
  const [isLiking, setIsLiking] = useState(false);

  useEffect(() => {
    if (user && showViewPage) {
      getPageByUserId(user.id).then(page => {
        if (page) setPageId(page.id);
      });
    }
  }, [user, showViewPage]);

  if (!user) return null;

  const handleViewPage = async () => {
    const slug = await getUserPageSlug(user.id);
    if (slug) {
      window.open(`/${slug}`, '_blank');
    } else {
      toast.error(t('friends.pageNotPublished', 'Page not published'));
    }
  };

  const handleLike = async () => {
    if (!pageId || !onToggleLike || isLiking) return;
    setIsLiking(true);
    try {
      await onToggleLike(pageId);
    } finally {
      setIsLiking(false);
    }
  };

  const isLiked = pageId ? likedPages?.has(pageId) : false;

  return (
    <div className="flex items-center gap-3 p-3 rounded-2xl bg-card/50 border border-border/30">
      <Avatar className="h-11 w-11 rounded-xl">
        <AvatarImage src={user.avatar_url || undefined} />
        <AvatarFallback className="rounded-xl bg-primary/10 text-primary">
          {(user.display_name || user.username || 'U')[0].toUpperCase()}
        </AvatarFallback>
      </Avatar>
      <div className="flex-1 min-w-0">
        <div className="flex items-center gap-2">
          <p className="text-sm font-medium truncate">
            {user.display_name || user.username || t('friends.user', 'User')}
          </p>
          {badge}
        </div>
        {user.username && (
          <p className="text-xs text-muted-foreground truncate">@{user.username}</p>
        )}
      </div>
      <div className="flex items-center gap-1">
        {showViewPage && onGift && (
          <Button
            variant="ghost"
            size="sm"
            onClick={() => onGift(user)}
            className="h-8 w-8 p-0 rounded-lg text-pink-500 hover:text-pink-600 hover:bg-pink-500/10"
            title={t('friends.giftPremium', 'Gift Premium')}
          >
            <Gift className="h-4 w-4" />
          </Button>
        )}
        {showViewPage && pageId && onToggleLike && (
          <Button
            variant="ghost"
            size="sm"
            onClick={handleLike}
            disabled={isLiking}
            className="h-8 w-8 p-0 rounded-lg"
            title={isLiked ? t('friends.removeLike', 'Убрать лайк') : t('friends.addLike', 'Поставить лайк')}
          >
            <Heart className={`h-4 w-4 transition-all ${isLiked ? 'fill-red-500 text-red-500' : ''}`} />
          </Button>
        )}
        {showViewPage && (
          <Button
            variant="ghost"
            size="sm"
            onClick={handleViewPage}
            className="h-8 w-8 p-0 rounded-lg"
            title={t('friends.viewPage', 'Открыть страницу')}
          >
            <ExternalLink className="h-4 w-4" />
          </Button>
        )}
        {action}
      </div>
    </div>
  );
}

function EmptyState({ icon, title, description }: { icon: React.ReactNode; title: string; description: string }) {
  return (
    <div className="flex flex-col items-center justify-center py-12 text-center">
      <div className="h-16 w-16 rounded-full bg-muted flex items-center justify-center mb-4 text-muted-foreground">
        {icon}
      </div>
      <h3 className="font-semibold text-lg mb-1">{title}</h3>
      <p className="text-sm text-muted-foreground max-w-[240px]">{description}</p>
    </div>
  );
}

function LoadingSkeleton() {
  return (
    <div className="space-y-3">
      {[1, 2, 3].map(i => (
        <div key={i} className="flex items-center gap-3 p-3 rounded-2xl bg-card/50 animate-pulse">
          <div className="h-11 w-11 rounded-xl bg-muted" />
          <div className="flex-1 space-y-2">
            <div className="h-4 w-24 rounded bg-muted" />
            <div className="h-3 w-16 rounded bg-muted" />
          </div>
        </div>
      ))}
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { Users, Loader2, Trophy } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { useGallery } from '@/hooks/social/useGallery';
import { useGalleryFilters } from '@/hooks/social/useGalleryFilters';
import { GalleryFilters } from './GalleryFilters';
import { GalleryPageCard } from './GalleryPageCard';
import { FeaturedPages } from './FeaturedPages';
import { NicheFilter } from './NicheFilter';
import { storage } from '@/lib/storage';


interface CommunityGalleryProps {
  compact?: boolean;
  maxItems?: number;
  showFilters?: boolean;
  showFeatured?: boolean;
}

export function CommunityGallery({
  compact = false,
  maxItems,
  showFilters = true,
  showFeatured = true,
}: CommunityGalleryProps) {
  const { t } = useTranslation();
  const { pages, loading, likePage, unlikePage, selectedNiche, setSelectedNiche, nicheCounts } = useGallery();
  const [likedPages, setLikedPages] = useState<Set<string>>(() => {
    const storedLikes = storage.get<string[]>('linkmax_liked_pages');
    return new Set(storedLikes || []);
  });

  const {
    search,
    setSearch,
    sortBy,
    setSortBy,
    filteredPages,
    featuredPages,
    totalCount,
  } = useGalleryFilters(pages);

  const displayPages = maxItems ? filteredPages.slice(0, maxItems) : filteredPages;

  const handleToggleLike = useCallback(async (pageId: string) => {
    const isCurrentlyLiked = likedPages.has(pageId);

    if (isCurrentlyLiked) {
      // Unlike
      const newLikedPages = new Set(likedPages);
      newLikedPages.delete(pageId);
      setLikedPages(newLikedPages);
      storage.set('linkmax_liked_pages', Array.from(newLikedPages));
      await unlikePage(pageId);
    } else {
      // Like
      const newLikedPages = new Set(likedPages).add(pageId);
      setLikedPages(newLikedPages);
      storage.set('linkmax_liked_pages', Array.from(newLikedPages));
      await likePage(pageId);
    }
  }, [likedPages, likePage, unlikePage]);

  if (loading) {
    return (
      <div className="flex items-center justify-center py-12">
        <Loader2 className="h-8 w-8 animate-spin text-primary" />
      </div>
    );
  }

  if (pages.length === 0 && !selectedNiche) {
    return (
      <div className="text-center py-12">
        <Users className="h-12 w-12 mx-auto text-muted-foreground mb-4" />
        <h3 className="text-lg font-medium mb-2">{t('gallery.empty', 'No pages yet')}</h3>
        <p className="text-muted-foreground">
          {t('gallery.emptyDescription', 'Be the first to share your page!')}
        </p>
      </div>
    );
  }

  return (
    <div className="space-y-6">
      {/* Niche filter */}
      {showFilters && !compact && (
        <NicheFilter
          selectedNiche={selectedNiche}
          onNicheChange={setSelectedNiche}
          nicheCounts={nicheCounts}
        />
      )}

      {/* Featured carousel (only on full view and no niche selected) */}
      {showFeatured && !compact && !selectedNiche && featuredPages.length > 0 && (
        <FeaturedPages
          pages={featuredPages}
          onLike={handleToggleLike}
          likedPages={likedPages}
        />
      )}

      {/* Search and sort filters */}
      {showFilters && !compact && (
        <GalleryFilters
          search={search}
          onSearchChange={setSearch}
          sortBy={sortBy}
          onSortChange={setSortBy}
          totalCount={totalCount}
        />
      )}

      {/* Grid */}
      {filteredPages.length === 0 ? (
        <div className="text-center py-20 px-4 border-2 border-dashed border-muted rounded-3xl bg-muted/30">
          <div className="w-16 h-16 bg-primary/10 rounded-full flex items-center justify-center mx-auto mb-4">
            <Trophy className="h-8 w-8 text-primary" />
          </div>
          <h3 className="text-xl font-bold mb-2">{t('gallery.empty', 'Be the first here!')}</h3>
          <p className="text-muted-foreground mb-6 max-w-md mx-auto">
            {t('gallery.emptyDescription', 'This niche is waiting for a star. Create your page and get featured.')}
          </p>
          <Button onClick={() => window.location.href = '/auth'} size="lg" className="rounded-full shadow-lg hover:shadow-primary/20">
            {t('gallery.createPage', 'Create Page')}
          </Button>
        </div>
      ) : (
        <div className={
          compact
            ? 'space-y-3'
            : 'grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 md:gap-6'
        }>
          {displayPages.map((page) => (
            <GalleryPageCard
              key={page.id}
              page={page}
              onLike={handleToggleLike}
              isLiked={likedPages.has(page.id)}
            />
          ))}
        </div>
      )}
    </div>
  );
}

import { useTranslation } from 'react-i18next';
import { Heart, Copy, Crown, Eye } from 'lucide-react';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Tooltip, TooltipContent, TooltipTrigger } from '@/components/ui/tooltip';
import { Badge } from '@/components/ui/badge';
import type { GalleryPage } from '@/services/gallery';
import { PagePreview } from './PagePreview';
import { NICHE_ICONS, type Niche } from '@/lib/niches';
import { useState } from 'react';

// Unified interface supporting both old and new usage
interface GalleryPageCardProps {
  page: GalleryPage;
  // New props (simplified)
  onCopy?: () => void;
  onView?: () => void;
  onLike?: (pageId: string) => Promise<void> | void;

  // Legacy props (compat)
  isLiked?: boolean;
  featured?: boolean;
}

export function GalleryPageCard({
  page,
  onCopy,
  onView,
  onLike,
  isLiked = false,
  featured = false
}: GalleryPageCardProps) {
  const { t } = useTranslation();
  const [internalLikeState, setInternalLikeState] = useState(isLiked);
  const [isLiking, setIsLiking] = useState(false);

  // Sync internal state with prop if provided
  if (isLiked !== internalLikeState && !isLiking) {
    setInternalLikeState(isLiked);
  }

  const handleLike = async (e: React.MouseEvent) => {
    e.stopPropagation();
    if (isLiking || !onLike) return;

    setIsLiking(true);
    try {
      // Optimistic update
      setInternalLikeState(!internalLikeState);

      const result = onLike(page.id);
      if (result instanceof Promise) {
        await result;
      }
    } catch {
      // Revert on error
      setInternalLikeState(!internalLikeState);
    } finally {
      setIsLiking(false);
    }
  };

  const handleCopy = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (onCopy) {
      onCopy();
    } else {
      // Fallback copy logic if no handler provided
      navigator.clipboard.writeText(`${window.location.origin}/${page.slug}`);
    }
  };

  const handleView = (e?: React.MouseEvent) => {
    e?.stopPropagation();
    if (onView) {
      onView();
    } else {
      window.open(`/${page.slug}`, '_blank', 'noopener,noreferrer');
    }
  };

  return (
    <Card
      className={`
        group overflow-hidden transition-all duration-300 hover:shadow-lg hover:-translate-y-1 cursor-pointer active:scale-[0.98]
        ${featured
          ? 'bg-gradient-to-br from-primary/10 via-card/80 to-card border-primary/30'
          : 'bg-card/50 backdrop-blur-lg border-border/30 hover:border-border/50'
        }
      `}
      onClick={(e) => handleView()}
    >
      {/* Page Preview Screenshot */}
      <div className="aspect-[9/16] w-full relative overflow-hidden bg-gradient-to-br from-primary/10 to-violet-500/10 transition-transform duration-500 group-hover:scale-[1.02]">
        <PagePreview
          slug={page.slug}
          title={page.title}
          avatarUrl={page.avatar_url}
          previewUrl={page.preview_url}
          className="w-full h-full object-cover"
        />

        {page.is_premium && (
          <div className="absolute top-2 right-2 z-10">
            <Crown className="h-4 w-4 text-amber-500 drop-shadow-md" />
          </div>
        )}

        {/* Hover overlay for desktop */}
        <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity hidden md:flex items-center justify-center gap-2">
          <Button
            size="sm"
            variant="secondary"
            className="h-8"
            onClick={(e) => { e.stopPropagation(); handleView(e); }}
          >
            <Eye className="w-4 h-4 mr-1.5" />
            {t('common.view', 'View')}
          </Button>
        </div>
      </div>

      <CardContent className="p-3">
        {/* Header with title and badges */}
        <div className="flex items-center gap-2 mb-2">
          <Avatar className="h-6 w-6 rounded-md ring-1 ring-border/50">
            <AvatarImage src={page.avatar_url || undefined} />
            <AvatarFallback className="rounded-md text-xs font-bold bg-primary/10 text-primary">
              {page.title?.charAt(0) || 'L'}
            </AvatarFallback>
          </Avatar>
          <div className="flex-1 min-w-0">
            <div className="flex items-center gap-1.5">
              <span className="font-bold text-sm truncate">{page.title || t('gallery.untitled', 'Untitled')}</span>
              {featured && (
                <Badge variant="default" className="bg-primary/90 text-[10px] h-4 px-1">
                  ⭐
                </Badge>
              )}
            </div>
          </div>
        </div>

        {/* Stats & Actions */}
        <div className="flex items-center justify-between mt-2">
          <div className="flex items-center gap-3 text-xs text-muted-foreground">
            <Tooltip>
              <TooltipTrigger asChild>
                <button
                  onClick={handleLike}
                  className="flex items-center gap-1 hover:text-red-500 transition-colors group/like"
                  disabled={isLiking}
                >
                  <Heart className={`h-3.5 w-3.5 transition-colors ${internalLikeState ? 'fill-red-500 text-red-500' : 'group-hover/like:text-red-500'}`} />
                  <span className={internalLikeState ? 'text-red-500 font-medium' : ''}>{page.gallery_likes || 0}</span>
                </button>
              </TooltipTrigger>
              <TooltipContent>
                {internalLikeState ? t('gallery.unlike', 'Unlike') : t('gallery.like', 'Like')}
              </TooltipContent>
            </Tooltip>

            <div className="flex items-center gap-1">
              <Eye className="h-3.5 w-3.5" />
              {page.view_count || 0}
            </div>
          </div>

          <Tooltip>
            <TooltipTrigger asChild>
              <Button
                variant="ghost"
                size="sm"
                className="h-7 w-7 p-0 rounded-lg hover:bg-primary/10 hover:text-primary ml-auto"
                onClick={handleCopy}
              >
                <Copy className="h-3.5 w-3.5" />
                <span className="sr-only">{t('common.copy', 'Copy')}</span>
              </Button>
            </TooltipTrigger>
            <TooltipContent>
              {t('common.copy', 'Copy Link')}
            </TooltipContent>
          </Tooltip>
        </div>
      </CardContent>
    </Card>
  );
}

// Helper component for layout compatibility if needed
function CardContent({ className, children }: { className?: string; children: React.ReactNode }) {
  return <div className={className}>{children}</div>;
}

