          <CardTitle className="flex items-center gap-2 text-lg">
            <Trophy className="h-5 w-5 text-amber-500" />
            {t('leaderboard.title', 'Top Pages')}
          </CardTitle>

          <Tabs value={period} onValueChange={(v: string) => setPeriod(v as LeaderboardPeriod)}>
