                  {/* Rank */}
                  <div className="flex-shrink-0 w-8 text-center">
                    {isTopThree ? (
                      <span className="text-xl">{rankStyle?.icon}</span>
                    ) : (
                      <span className="text-sm font-bold text-muted-foreground">#{index + 1}</span>
                    )}
