'use client';

import { useState, useCallback, useEffect } from 'react';
import { useRouter } from 'next/navigation';
import { useTranslation } from 'react-i18next';
import { Users, ArrowRight, Crown, Eye, Heart, Loader2, Filter } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Avatar, AvatarImage, AvatarFallback } from '@/components/ui/avatar';
import { useGallery } from '@/hooks/social/useGallery';
import { NICHES, NICHE_ICONS, type Niche } from '@/lib/niches';
import { toast } from 'sonner';
import { storage } from '@/lib/storage';

export function LandingGallerySection() {
  const { t } = useTranslation();
  const router = useRouter();
  const { pages, loading, likePage, selectedNiche, setSelectedNiche, nicheCounts } = useGallery();
  const [likedPages, setLikedPages] = useState<Set<string>>(new Set());
  const [showFilters, setShowFilters] = useState(false);

  // Get top 8 pages for display
  const displayPages = pages.slice(0, 8);

  const handleLike = useCallback(async (e: React.MouseEvent, pageId: string) => {
    e.stopPropagation();

    // Check storage for liked pages
    const likedSet = new Set<string>(storage.get<string[]>('linkmax_liked_pages') || []);

    if (likedSet.has(pageId)) {
      toast.info(t('gallery.alreadyLiked'));
      return;
    }

    await likePage(pageId);
    likedSet.add(pageId);
    setLikedPages(new Set(likedSet));
    storage.set('linkmax_liked_pages', Array.from(likedSet));
    toast.success(t('gallery.liked'));
  }, [likePage, t]);

  // Load liked pages from storage on mount
  useEffect(() => {
    const storedLikes = storage.get<string[]>('linkmax_liked_pages');
    if (storedLikes) {
      setLikedPages(new Set(storedLikes));
    }
  }, []);

  // Top 5 niches by count
  const topNiches = Object.entries(nicheCounts)
    .sort(([, a], [, b]) => b - a)
    .slice(0, 5)
    .map(([niche]) => niche as Niche);

  return (
    <section className="py-12 sm:py-20 px-4 bg-gradient-to-b from-background to-muted/30">
      <div className="container mx-auto max-w-6xl">
        {/* Header */}
        <div className="text-center mb-8 sm:mb-12">
          <div className="inline-flex items-center gap-2 px-4 py-2 rounded-full bg-primary/10 border border-primary/20 text-sm font-medium mb-4">
            <Users className="h-4 w-4 text-primary" />
            <span className="text-primary">{t('landing.gallery.badge')}</span>
          </div>
          <h2 className="text-2xl sm:text-4xl lg:text-5xl font-bold tracking-tight mb-3 sm:mb-4">
            {t('landing.gallery.title')}
          </h2>
          <p className="text-base sm:text-lg text-muted-foreground max-w-2xl mx-auto">
            {t('landing.gallery.subtitle')}
          </p>
        </div>

        {/* Niche Filters - Always visible */}
        <div className="mb-6 sm:mb-8">
          <div className="flex items-center justify-center gap-2 mb-3">
            <Button
              variant="ghost"
              size="sm"
              onClick={() => setShowFilters(!showFilters)}
              className="sm:hidden text-muted-foreground"
            >
              <Filter className="h-4 w-4 mr-1" />
              {t('gallery.filter')}
            </Button>
          </div>

          <div className={`flex flex-wrap justify-center gap-2 ${showFilters ? '' : 'hidden sm:flex'}`}>
            <Button
              variant={selectedNiche === null ? 'default' : 'outline'}
              size="sm"
              onClick={() => setSelectedNiche(null)}
              className="rounded-full text-xs sm:text-sm"
            >
              {t('gallery.all')}
              <Badge variant="secondary" className="ml-1.5 text-[10px] px-1.5">
                {Object.values(nicheCounts).reduce((a, b) => a + b, 0)}
              </Badge>
            </Button>

            {topNiches.map((niche) => (
              <Button
                key={niche}
                variant={selectedNiche === niche ? 'default' : 'outline'}
                size="sm"
                onClick={() => setSelectedNiche(niche)}
                className="rounded-full text-xs sm:text-sm"
              >
                <span className="mr-1">{NICHE_ICONS[niche]}</span>
                {t(`niches.${niche}`, niche)}
                <Badge variant="secondary" className="ml-1.5 text-[10px] px-1.5">
                  {nicheCounts[niche] || 0}
                </Badge>
              </Button>
            ))}
          </div>
        </div>

        {/* Loading State */}
        {loading && (
          <div className="flex justify-center py-12">
            <Loader2 className="h-8 w-8 animate-spin text-primary" />
          </div>
        )}

        {/* Empty State */}
        {!loading && displayPages.length === 0 && (
          <div className="text-center py-12">
            <p className="text-muted-foreground">{t('gallery.empty')}</p>
          </div>
        )}

        {/* Gallery grid */}
        {!loading && displayPages.length > 0 && (
          <div className="grid grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 gap-3 sm:gap-4 mb-8">
            {displayPages.map((page) => (
              <Card
                key={page.id}
                className="group cursor-pointer bg-card/50 backdrop-blur-xl border-border/30 hover:border-primary/30 transition-all duration-300 hover:shadow-lg hover:-translate-y-1 overflow-hidden"
                onClick={() => router.push(`/${page.slug}`)}
              >
                {/* Avatar Section */}
                <div className="relative p-3 sm:p-4 pb-2 flex flex-col items-center">
                  {/* Premium Badge */}
                  {page.is_premium && (
                    <div className="absolute top-2 right-2 z-10">
                      <div className="flex items-center gap-0.5 px-1.5 py-0.5 rounded-full bg-gradient-to-r from-amber-500 to-yellow-500 text-white text-[10px] font-semibold shadow-sm">
                        <Crown className="h-2.5 w-2.5" />
                      </div>
                    </div>
                  )}

                  <Avatar className="h-14 w-14 sm:h-16 sm:w-16 border-2 border-primary/20 shadow-md group-hover:scale-105 transition-transform">
                    <AvatarImage
                      src={page.avatar_url || ''}
                      alt={page.title || ''}
                      loading="lazy"
                      decoding="async"
                    />
                    <AvatarFallback className="bg-primary/10 text-primary text-lg font-bold">
                      {(page.title || 'U')[0].toUpperCase()}
                    </AvatarFallback>
                  </Avatar>
                </div>

                {/* Page Info */}
                <div className="px-2.5 sm:px-3 pb-2.5 sm:pb-3">
                  <h3 className="font-semibold text-xs sm:text-sm text-center truncate mb-1.5">
                    {page.title || page.slug}
                  </h3>

                  {page.niche && (
                    <div className="flex justify-center mb-2">
                      <Badge variant="secondary" className="text-[9px] sm:text-[10px] px-1.5 py-0">
                        {NICHE_ICONS[page.niche as Niche]} {t(`niches.${page.niche}`, page.niche)}
                      </Badge>
                    </div>
                  )}

                  {/* Stats */}
                  <div className="flex items-center justify-center gap-3 text-[10px] sm:text-xs text-muted-foreground">
                    <span className="flex items-center gap-0.5">
                      <Eye className="h-3 w-3" />
                      {page.view_count || 0}
                    </span>
                    <button
                      onClick={(e) => handleLike(e, page.id)}
                      className={`flex items-center gap-0.5 transition-colors hover:text-red-500 ${likedPages.has(page.id) ? 'text-red-500' : ''
                        }`}
                    >
                      <Heart className={`h-3 w-3 ${likedPages.has(page.id) ? 'fill-current' : ''}`} />
                      {page.gallery_likes || 0}
                    </button>
                  </div>
                </div>
              </Card>
            ))}
          </div>
        )}

        {/* CTA button */}
        <div className="text-center">
          <Button
            size="lg"
            variant="outline"
            onClick={() => router.push('/gallery')}
            className="rounded-2xl px-6 sm:px-8 py-5 sm:py-6 text-sm sm:text-base font-semibold bg-background/60 backdrop-blur-xl hover:bg-accent border-border/50 hover:border-primary/30 transition-all group"
          >
            {t('landing.gallery.viewAll')}
            <ArrowRight className="ml-2 h-4 w-4 sm:h-5 sm:w-5 transition-transform group-hover:translate-x-1" />
          </Button>
        </div>
      </div>
    </section>
  );
}

import { useQuery } from '@tanstack/react-query';
import { useTranslation } from 'react-i18next';
import { supabase } from '@/platform/supabase/client';
import { cn } from '@/lib/utils/utils';

interface Partner {
    id: string;
    name: string;
    logo_url: string;
    website_url: string | null;
}

// Placeholder partners for when database is empty or loading
const placeholderPartners: Partner[] = Array.from({ length: 10 }, (_, i) => ({
    id: `placeholder-${i + 1}`,
    name: `Partner ${i + 1}`,
    logo_url: `https://via.placeholder.com/200x80/${['1a1a2e', '16213e', '0f3460', '533483', 'e94560'][i % 5]}/ffffff?text=Partner+${i + 1}`,
    website_url: null,
}));

export function PartnersSection() {
    const { t } = useTranslation();

    const { data: partners } = useQuery({
        queryKey: ['landing-partners'],
        queryFn: async () => {
            const { data, error } = await (supabase as any)
                .from('partners')
                .select('id, name, logo_url, website_url')
                .eq('is_active', true)
                .order('sort_order', { ascending: true });

            if (error) throw error;
            return (data || []) as Partner[];
        },
        staleTime: 1000 * 60 * 5, // 5 minutes
    });

    // Use fetched partners or placeholders
    const displayPartners = partners?.length ? partners : placeholderPartners;

    // Double the partners for seamless loop
    const loopedPartners = [...displayPartners, ...displayPartners];

    return (
        <section className="py-8 px-5 overflow-hidden">
            <div className="max-w-xl mx-auto">
                <p className="text-center text-sm font-medium text-muted-foreground mb-6">
                    {t('landing.partners.title', 'Нам доверяют')}
                </p>
            </div>

            {/* Marquee Container */}
            <div className="relative">
                {/* Gradient fades on edges */}
                <div className="absolute left-0 top-0 bottom-0 w-12 bg-gradient-to-r from-background to-transparent z-10 pointer-events-none" />
                <div className="absolute right-0 top-0 bottom-0 w-12 bg-gradient-to-l from-background to-transparent z-10 pointer-events-none" />

                {/* Marquee track */}
                <div
                    className="flex items-center gap-8 animate-marquee hover:[animation-play-state:paused]"
                    style={{
                        width: 'max-content',
                    }}
                >
                    {loopedPartners.map((partner, index) => (
                        <PartnerLogo key={`${partner.id}-${index}`} partner={partner} />
                    ))}
                </div>
            </div>

            {/* CSS for marquee animation */}
            <style>{`
        @keyframes marquee {
          0% {
            transform: translateX(0);
          }
          100% {
            transform: translateX(-50%);
          }
        }
        .animate-marquee {
          animation: marquee 30s linear infinite;
        }
      `}</style>
        </section>
    );
}

function PartnerLogo({ partner }: { partner: Partner }) {
    const Wrapper = partner.website_url ? 'a' : 'div';
    const wrapperProps = partner.website_url
        ? {
            href: partner.website_url,
            target: '_blank',
            rel: 'noopener noreferrer',
        }
        : {};

    return (
        <Wrapper
            {...wrapperProps}
            className={cn(
                "flex-shrink-0 h-12 px-4 flex items-center justify-center",
                "bg-card/50 rounded-xl border border-border/30",
                "transition-all duration-300 hover:border-border/60 hover:bg-card",
                partner.website_url && "cursor-pointer"
            )}
        >
            <img
                src={partner.logo_url}
                alt={partner.name}
                className="h-6 w-auto max-w-[120px] object-contain opacity-70 hover:opacity-100 transition-opacity grayscale hover:grayscale-0"
                loading="lazy"
                onError={(e) => {
                    (e.target as HTMLImageElement).src = 'https://via.placeholder.com/120x24?text=Logo';
                }}
            />
        </Wrapper>
    );
}

