  onComplete: (data: {
    profile: { name: string; bio: string };
    blocks: Block[];
    niche: Niche;
  }) => void;
}

type Step = 'intro' | 'niche' | 'details' | 'generating' | 'complete';

// Niche gradient colors for visual appeal
const NICHE_GRADIENTS: Record<Niche, string> = {
  beauty: 'from-pink-500/20 to-rose-500/20',
  fitness: 'from-green-500/20 to-emerald-500/20',
  food: 'from-amber-500/20 to-yellow-500/20',
  education: 'from-yellow-500/20 to-amber-500/20',
  art: 'from-indigo-500/20 to-violet-500/20',
  music: 'from-red-500/20 to-rose-500/20',
  tech: 'from-blue-500/20 to-cyan-500/20',
  business: 'from-teal-500/20 to-green-500/20',
  health: 'from-purple-500/20 to-pink-500/20',
  fashion: 'from-pink-400/20 to-fuchsia-500/20',
  travel: 'from-sky-500/20 to-blue-500/20',
  realestate: 'from-orange-500/20 to-red-500/20',
  events: 'from-violet-500/20 to-purple-500/20',
  services: 'from-gray-500/20 to-slate-500/20',
  other: 'from-gray-400/20 to-gray-500/20',
};

export const QuickStartFlow = memo(function QuickStartFlow({
  open,
  onClose,
  onComplete,
}: QuickStartFlowProps) {
  const { t } = useTranslation();
  const [step, setStep] = useState<Step>('intro');
  const [selectedNiche, setSelectedNiche] = useState<Niche | null>(null);
  const [name, setName] = useState('');
  const [description, setDescription] = useState('');
  const [generating, setGenerating] = useState(false);

  const progress =
    step === 'intro' ? 0 :
      step === 'niche' ? 33 :
        step === 'details' ? 66 : 100;

  const handleSelectNiche = (niche: Niche) => {
    setSelectedNiche(niche);
    setStep('details');
  };

  const handleBack = () => {
    if (step === 'details') setStep('niche');
    if (step === 'niche') setStep('intro');
  };

  const handleGenerate = useCallback(async () => {
    if (!selectedNiche || !name.trim()) {
      toast.error(t('onboarding.enterName', 'Введите ваше имя'));
      return;
    }

    setStep('generating');
    setGenerating(true);

    try {
      const { data, error } = await supabase.functions.invoke('ai-content-generator', {
        body: {
          type: 'niche-builder',
          input: {
            niche: selectedNiche,
            name: name.trim(),
            details: description.trim(),
          },
        },
      });

      if (error) throw error;

      const { profile, blocks } = data.result;

      const formattedBlocks: Block[] = blocks.map((block: any, index: number) => ({
        id: `${block.type}-${Date.now()}-${index}`,
        ...block,
      }));

      setStep('complete');

      setTimeout(() => {
        toast.success(t('onboarding.pageGenerated', 'Страница создана! 🎉'));
        onComplete({ profile, blocks: formattedBlocks, niche: selectedNiche });
        storage.set('linkmax_onboarding_completed', 'true');
        onClose();
      }, 1500);

    } catch (error) {
      console.error('Generation error:', error);
      toast.error(t('onboarding.generationFailed', 'Ошибка генерации. Попробуйте ещё раз'));
      setStep('details');
    } finally {
      setGenerating(false);
    }
  }, [selectedNiche, name, description, t, onComplete, onClose]);

  const handleSkip = () => {
    storage.set('linkmax_onboarding_completed', 'true');
    onClose();
  };

  return (
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="max-w-[95vw] sm:max-w-xl max-h-[90vh] overflow-hidden p-0 gap-0 rounded-[28px] border-0 bg-card/98 backdrop-blur-3xl [&>button]:hidden">
        {/* Accessible but visually hidden title for screen readers */}
        <VisuallyHidden.Root>
          <DialogTitle>{t('quickStart.title', 'Quick Start')}</DialogTitle>
          <DialogDescription>{t('quickStart.description', 'Create your page quickly with AI assistance')}</DialogDescription>
        </VisuallyHidden.Root>
        {/* Progress bar */}
        {step !== 'intro' && (
          <div className="px-6 pt-5">
            <Progress value={progress} className="h-1 rounded-full" />
          </div>
        )}

        {/* Step: Intro */}
        {step === 'intro' && (
          <div className="p-6 pt-10 pb-8 animate-fade-in text-center">
            <div className="inline-flex items-center justify-center h-20 w-20 rounded-[24px] bg-gradient-to-br from-primary/20 to-violet-500/20 mb-6">
              <Zap className="h-10 w-10 text-primary" />
            </div>

            <h2 className="text-2xl font-black mb-3">
              {t('quickStart.welcomeTitle', 'Создайте страницу за 60 секунд')}
            </h2>
            <p className="text-muted-foreground mb-8 max-w-sm mx-auto">
              {t('quickStart.welcomeDescription', 'AI сгенерирует персональную страницу на основе вашей ниши и описания')}
            </p>

            <div className="space-y-3">
              <Button
                size="lg"
                className="w-full h-14 rounded-2xl text-base font-bold shadow-xl shadow-primary/25"
                onClick={() => setStep('niche')}
              >
                <Wand2 className="h-5 w-5 mr-2" />
                {t('quickStart.startWithAI', 'Создать с AI')}
                <ArrowRight className="h-5 w-5 ml-2" />
              </Button>

              <Button
                variant="ghost"
                className="w-full h-12 rounded-2xl text-muted-foreground"
                onClick={handleSkip}
              >
                {t('quickStart.skipToEditor', 'Пропустить и создать вручную')}
              </Button>
            </div>
          </div>
        )}

        {/* Step: Niche Selection */}
        {step === 'niche' && (
          <div className="p-5 pt-6 animate-fade-in">
            <div className="flex items-center gap-3 mb-6">
              <Button
                variant="ghost"
                size="icon"
                onClick={handleBack}
                className="h-11 w-11 rounded-xl shrink-0"
              >
                <ArrowLeft className="h-5 w-5" />
              </Button>
              <div>
                <h2 className="text-xl font-black">
                  {t('quickStart.nicheTitle', 'Выберите нишу')}
                </h2>
                <p className="text-sm text-muted-foreground">
                  {t('quickStart.nicheDescription', 'AI подберёт дизайн и блоки')}
                </p>
              </div>
            </div>

            <div className="grid grid-cols-3 gap-2.5 max-h-[50vh] overflow-y-auto pb-4 scrollbar-hide">
              {NICHES.map((niche) => (
                <button
                  key={niche}
                  onClick={() => handleSelectNiche(niche)}
                  className={cn(
                    "p-4 rounded-2xl border-2 border-transparent transition-all duration-200",
                    `bg-gradient-to-br ${NICHE_GRADIENTS[niche]}`,
                    "hover:scale-[1.02] active:scale-[0.98]",
                    selectedNiche === niche && "ring-2 ring-primary ring-offset-2"
                  )}
                >
                  <div className="text-2xl mb-2">{NICHE_ICONS[niche]}</div>
                  <p className="font-bold text-xs text-center leading-tight">
                    {t(`niches.${niche}`, niche)}
                  </p>
                </button>
              ))}
            </div>
          </div>
        )}

        {/* Step: Details Input */}
        {step === 'details' && selectedNiche && (
          <div className="p-5 pt-6 animate-fade-in">
            <div className="flex items-center gap-3 mb-6">
              <Button
                variant="ghost"
                size="icon"
                onClick={handleBack}
                className="h-11 w-11 rounded-xl shrink-0"
              >
                <ArrowLeft className="h-5 w-5" />
              </Button>
              <div>
                <h2 className="text-xl font-black">
                  {t('quickStart.detailsTitle', 'Расскажите о себе')}
                </h2>
                <p className="text-sm text-muted-foreground">
                  {t('quickStart.detailsDescription', 'AI персонализирует страницу')}
                </p>
              </div>
            </div>

            <div className="space-y-5">
              <div className="space-y-2">
                <label className="text-sm font-bold flex items-center gap-2">
                  <User className="h-4 w-4 text-primary" />
                  {t('quickStart.yourName', 'Ваше имя')} *
                </label>
                <Input
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  placeholder={t('quickStart.namePlaceholder', 'Как вас зовут?')}
                  className="h-13 rounded-xl text-base px-4"
                  autoFocus
                />
              </div>

              <div className="space-y-2">
                <label className="text-sm font-bold flex items-center gap-2">
                  <Sparkles className="h-4 w-4 text-violet-500" />
                  {t('quickStart.additionalDetails', 'Описание (опционально)')}
                </label>
                <Textarea
                  value={description}
                  onChange={(e) => setDescription(e.target.value)}
                  placeholder={t('quickStart.detailsPlaceholder', 'Чем занимаетесь? Какие услуги предоставляете?')}
                  className="min-h-[100px] rounded-xl text-base p-4 resize-none"
                />
                <p className="text-xs text-muted-foreground">
                  {t('quickStart.detailsHint', 'Чем подробнее - тем лучше результат')}
                </p>
              </div>
            </div>

            <div className="pt-6 flex gap-3">
              <Button
                variant="outline"
                onClick={handleSkip}
                className="flex-1 h-13 rounded-xl font-bold"
              >
                {t('common.skip', 'Пропустить')}
              </Button>
              <Button
                onClick={handleGenerate}
                disabled={!name.trim()}
                className="flex-[2] h-13 rounded-xl font-bold shadow-lg shadow-primary/25"
              >
                <Wand2 className="h-5 w-5 mr-2" />
                {t('quickStart.generate', 'Создать')}
                <ArrowRight className="h-5 w-5 ml-2" />
              </Button>
            </div>
          </div>
        )}

        {/* Step: Generating */}
        {step === 'generating' && (
          <div className="p-6 py-16 text-center animate-fade-in">
            <div className="relative mx-auto w-24 h-24 mb-8">
              <div className="absolute inset-0 rounded-full bg-gradient-to-r from-primary via-violet-500 to-pink-500 animate-spin" style={{ animationDuration: '2s' }} />
              <div className="absolute inset-2 rounded-full bg-background flex items-center justify-center">
                <Wand2 className="h-8 w-8 text-primary animate-pulse" />
              </div>
            </div>
            <h3 className="text-xl font-black mb-2">
              {t('quickStart.generatingTitle', 'AI создаёт страницу')}
            </h3>
            <p className="text-muted-foreground mb-6">
              {t('quickStart.generatingDescription', 'Подбираем блоки и контент специально для вас')}
            </p>
            <div className="flex items-center justify-center gap-2 text-sm text-muted-foreground">
              <Loader2 className="h-4 w-4 animate-spin" />
              {t('common.pleaseWait', 'Пожалуйста, подождите...')}
            </div>
          </div>
        )}

        {/* Step: Complete */}
        {step === 'complete' && (
          <div className="p-6 py-16 text-center animate-scale-in">
            <div className="mx-auto w-20 h-20 rounded-full bg-emerald-500/20 flex items-center justify-center mb-6">
              <Check className="h-10 w-10 text-emerald-500" />
            </div>
            <h3 className="text-xl font-black mb-2">
              {t('quickStart.completeTitle', 'Готово! 🎉')}
            </h3>
            <p className="text-muted-foreground">
              {t('quickStart.completeDescription', 'Страница создана и готова к редактированию')}
            </p>
          </div>
        )}
      </DialogContent>
    </Dialog>
  );
});

import { memo } from 'react';
import { useTranslation } from 'react-i18next';
import { Crown, Lock } from 'lucide-react';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Badge } from '@/components/ui/badge';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { ScrollArea } from '@/components/ui/scroll-area';
import { cn } from '@/lib/utils/utils';
import { 
  FRAME_OPTIONS, 
  type FrameOption,
  getFramesByCategory,
} from '@/lib/profile-frame-system';
import { getFrameStyles, isGradientFrame, FRAME_CSS } from '@/lib/avatar-frame-utils';
import type { ProfileFrameStyle } from '@/types/page';

interface FrameSelectorProps {
  value: ProfileFrameStyle;
  onChange: (value: ProfileFrameStyle) => void;
  isPremium: boolean;
  avatarUrl?: string;
  onUpgradeClick?: () => void;
}

const DEMO_AVATAR = 'https://api.dicebear.com/7.x/avataaars/svg?seed=demo&backgroundColor=b6e3f4';

const FramePreviewItem = memo(function FramePreviewItem({
  option,
  selected,
  onClick,
  avatarUrl,
  isPremium,
  locked,
}: {
  option: FrameOption;
  selected: boolean;
  onClick: () => void;
  avatarUrl?: string;
  isPremium: boolean;
  locked: boolean;
}) {
  const { t } = useTranslation();
  const frameStyles = getFrameStyles(option.value);
  const isGradient = isGradientFrame(option.value);

  return (
    <div
      onClick={onClick}
      className={cn(
        'flex flex-col items-center gap-2 p-2 rounded-xl cursor-pointer transition-all duration-200',
        'hover:bg-muted/50',
        selected && 'bg-primary/10 ring-2 ring-primary',
        locked && !isPremium && 'opacity-60'
      )}
    >
      <div className="relative">
        <style>{FRAME_CSS}</style>
        <div
          className={cn(
            'w-14 h-14 rounded-full flex items-center justify-center transition-transform duration-200 hover:scale-105',
            option.isAnimated && 'animate-pulse-slow'
          )}
          style={frameStyles}
        >
          <Avatar className={cn('w-12 h-12', isGradient && 'p-0')}>
            <AvatarImage 
              src={avatarUrl || DEMO_AVATAR} 
              alt="Frame preview" 
              className="object-cover"
            />
            <AvatarFallback className="bg-gradient-to-br from-primary/20 to-primary/40 text-primary text-xs font-medium">
              AB
            </AvatarFallback>
          </Avatar>
        </div>
        
        {/* Pro/Lock indicator */}
        {locked && !isPremium && (
          <div className="absolute -top-1 -right-1 w-5 h-5 bg-warning rounded-full flex items-center justify-center shadow-sm">
            <Lock className="w-3 h-3 text-warning-foreground" />
          </div>
        )}
        
        {option.isPro && isPremium && (
          <div className="absolute -top-1 -right-1 w-5 h-5 bg-warning rounded-full flex items-center justify-center shadow-sm">
            <Crown className="w-3 h-3 text-warning-foreground" />
          </div>
        )}
      </div>
      
      <span className="text-[10px] text-muted-foreground text-center leading-tight max-w-[56px] truncate">
        {option.emoji ? `${option.emoji} ` : ''}{t(option.labelKey, option.label)}
      </span>
    </div>
  );
});

export const FrameSelector = memo(function FrameSelector({
  value,
  onChange,
  isPremium,
  avatarUrl,
  onUpgradeClick,
}: FrameSelectorProps) {
  const { t } = useTranslation();

  const handleSelect = (option: FrameOption) => {
    if (option.isPro && !isPremium) {
      onUpgradeClick?.();
      return;
    }
    onChange(option.value);
  };

  const basicFrames = getFramesByCategory('basic');
  const gradientFrames = getFramesByCategory('gradient');
  const neonFrames = getFramesByCategory('neon');
  const animatedFrames = [...getFramesByCategory('animated'), ...getFramesByCategory('special')];

  const renderFrameGrid = (frames: FrameOption[]) => (
    <div className="grid grid-cols-4 gap-2 p-2">
      {frames.map((option) => (
        <FramePreviewItem
          key={option.value}
          option={option}
          selected={value === option.value}
          onClick={() => handleSelect(option)}
          avatarUrl={avatarUrl}
          isPremium={isPremium}
          locked={option.isPro}
        />
      ))}
    </div>
  );

  return (
    <div className="space-y-3">
      {!isPremium && (
        <div 
          onClick={onUpgradeClick}
          className="flex items-center gap-2 p-3 bg-warning/10 border border-warning/20 rounded-xl cursor-pointer hover:bg-warning/20 transition-colors"
        >
          <Crown className="w-4 h-4 text-warning flex-shrink-0" />
          <span className="text-xs text-warning">
            {t('frames.unlockProFrames', 'Разблокируйте все рамки с PRO подпиской')}
          </span>
        </div>
      )}
      
      <Tabs defaultValue="basic" className="w-full">
        <TabsList className="grid grid-cols-4 w-full h-auto p-1">
          <TabsTrigger value="basic" className="text-xs py-2 px-1">
            {t('frames.categories.basic', 'Базовые')}
          </TabsTrigger>
          <TabsTrigger value="gradient" className="text-xs py-2 px-1">
            {t('frames.categories.gradient', 'Градиент')}
          </TabsTrigger>
          <TabsTrigger value="neon" className="text-xs py-2 px-1">
            {t('frames.categories.neon', 'Неон')}
          </TabsTrigger>
          <TabsTrigger value="animated" className="text-xs py-2 px-1 relative">
            {t('frames.categories.animated', 'Анимация')}
            {!isPremium && <Lock className="w-3 h-3 ml-1 inline-block" />}
          </TabsTrigger>
        </TabsList>
        
        <ScrollArea className="h-[200px] mt-2">
          <TabsContent value="basic" className="mt-0">
            {renderFrameGrid(basicFrames)}
          </TabsContent>
          
          <TabsContent value="gradient" className="mt-0">
            {renderFrameGrid(gradientFrames)}
            {!isPremium && (
              <Badge variant="outline" className="mx-2 mb-2 text-warning">
                <Crown className="w-3 h-3 mr-1" />
                PRO
              </Badge>
            )}
          </TabsContent>
          
          <TabsContent value="neon" className="mt-0">
            {renderFrameGrid(neonFrames)}
            {!isPremium && (
              <Badge variant="outline" className="mx-2 mb-2 text-warning">
                <Crown className="w-3 h-3 mr-1" />
                PRO
              </Badge>
            )}
          </TabsContent>
          
          <TabsContent value="animated" className="mt-0">
            {renderFrameGrid(animatedFrames)}
            {!isPremium && (
              <Badge variant="outline" className="mx-2 mb-2 text-warning">
                <Crown className="w-3 h-3 mr-1" />
                PRO
              </Badge>
            )}
          </TabsContent>
        </ScrollArea>
      </Tabs>
    </div>
  );
});

import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { X, Download, Smartphone, Monitor, Apple } from 'lucide-react';
import { Button } from '@/components/ui/button';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from '@/components/ui/dialog';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';

interface InstallPromptProps {
  open: boolean;
  onClose: () => void;
  pageUrl: string;
}

type DeviceType = 'desktop' | 'android' | 'ios';

function detectDevice(): DeviceType {
  const userAgent = navigator.userAgent.toLowerCase();

  if (/iphone|ipad|ipod/.test(userAgent)) {
    return 'ios';
  }
  if (/android/.test(userAgent)) {
    return 'android';
  }
  return 'desktop';
}

export function InstallPromptDialog({ open, onClose, pageUrl }: InstallPromptProps) {
  const { t } = useTranslation();
  const [activeTab, setActiveTab] = useState<DeviceType>(detectDevice());
  const [deferredPrompt, setDeferredPrompt] = useState<any>(null);

  useEffect(() => {
    const handler = (e: Event) => {
      e.preventDefault();
      setDeferredPrompt(e);
    };

    window.addEventListener('beforeinstallprompt', handler);
    return () => window.removeEventListener('beforeinstallprompt', handler);
  }, []);

  const handleInstallPWA = async () => {
    if (deferredPrompt) {
      deferredPrompt.prompt();
      const { outcome } = await deferredPrompt.userChoice;
      if (outcome === 'accepted') {
        onClose();
      }
      setDeferredPrompt(null);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onClose}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Download className="h-5 w-5 text-primary" />
            {t('install.title', 'Install lnkmx.my')}
          </DialogTitle>
          <DialogDescription className="sr-only">
            {t('install.description', 'Install lnkmx.my on your device for quick access')}
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-4">
          <p className="text-sm text-muted-foreground">
            {t('install.subtitle', 'Your page is published! Install lnkmx.my for quick access and offline editing.')}
          </p>

          <div className="p-3 bg-muted rounded-lg">
            <p className="text-xs text-muted-foreground mb-1">{t('install.yourLink', 'Your link:')}</p>
            <p className="font-medium text-primary break-all">{pageUrl}</p>
          </div>

          <Tabs value={activeTab} onValueChange={(v: string) => setActiveTab(v as DeviceType)}>
            <TabsList className="grid w-full grid-cols-3">
              <TabsTrigger value="ios" className="flex items-center gap-1">
                <Apple className="h-4 w-4" />
                <span className="hidden sm:inline">iPhone</span>
              </TabsTrigger>
              <TabsTrigger value="android" className="flex items-center gap-1">
                <Smartphone className="h-4 w-4" />
                <span className="hidden sm:inline">Android</span>
              </TabsTrigger>
              <TabsTrigger value="desktop" className="flex items-center gap-1">
                <Monitor className="h-4 w-4" />
                <span className="hidden sm:inline">{t('install.desktop.title', 'Desktop')}</span>
              </TabsTrigger>
            </TabsList>

            <TabsContent value="ios" className="space-y-4 mt-4">
              <div className="space-y-3">
                <div className="flex items-start gap-3">
                  <div className="flex-shrink-0 w-6 h-6 rounded-full bg-primary text-primary-foreground flex items-center justify-center text-sm font-bold">
                    1
                  </div>
                  <div>
                    <p className="font-medium">{t('install.ios.step1', 'Open in Safari')}</p>
                    <p className="text-sm text-muted-foreground">
                      {t('install.ios.step1desc', 'Make sure you\'re using Safari browser')}
                    </p>
                  </div>
                </div>
                <div className="flex items-start gap-3">
                  <div className="flex-shrink-0 w-6 h-6 rounded-full bg-primary text-primary-foreground flex items-center justify-center text-sm font-bold">
                    2
                  </div>
                  <div>
                    <p className="font-medium">{t('install.ios.step2', 'Tap Share button')}</p>
                    <p className="text-sm text-muted-foreground">
                      {t('install.ios.step2desc', 'Find the Share icon at the bottom of Safari')}
                    </p>
                  </div>
                </div>
                <div className="flex items-start gap-3">
                  <div className="flex-shrink-0 w-6 h-6 rounded-full bg-primary text-primary-foreground flex items-center justify-center text-sm font-bold">
                    3
                  </div>
                  <div>
                    <p className="font-medium">{t('install.ios.step3', '"Add to Home Screen"')}</p>
                    <p className="text-sm text-muted-foreground">
                      {t('install.ios.step3desc', 'Scroll down and tap "Add to Home Screen"')}
                    </p>
                  </div>
                </div>
              </div>
            </TabsContent>

            <TabsContent value="android" className="space-y-4 mt-4">
              <div className="space-y-3">
                <div className="flex items-start gap-3">
                  <div className="flex-shrink-0 w-6 h-6 rounded-full bg-primary text-primary-foreground flex items-center justify-center text-sm font-bold">
                    1
                  </div>
                  <div>
                    <p className="font-medium">{t('install.android.step1', 'Open browser menu')}</p>
                    <p className="text-sm text-muted-foreground">
                      {t('install.android.step1desc', 'Tap the three dots in the top right corner')}
                    </p>
                  </div>
                </div>
                <div className="flex items-start gap-3">
                  <div className="flex-shrink-0 w-6 h-6 rounded-full bg-primary text-primary-foreground flex items-center justify-center text-sm font-bold">
                    2
                  </div>
                  <div>
                    <p className="font-medium">{t('install.android.step2', '"Install app" or "Add to Home screen"')}</p>
                    <p className="text-sm text-muted-foreground">
                      {t('install.android.step2desc', 'Select the install option from the menu')}
                    </p>
                  </div>
                </div>
                <div className="flex items-start gap-3">
                  <div className="flex-shrink-0 w-6 h-6 rounded-full bg-primary text-primary-foreground flex items-center justify-center text-sm font-bold">
                    3
                  </div>
                  <div>
                    <p className="font-medium">{t('install.android.step3', 'Confirm installation')}</p>
                    <p className="text-sm text-muted-foreground">
                      {t('install.android.step3desc', 'Tap "Install" to add lnkmx.my to your home screen')}
                    </p>
                  </div>
                </div>
              </div>
            </TabsContent>

            <TabsContent value="desktop" className="space-y-4 mt-4">
              {deferredPrompt ? (
                <div className="text-center space-y-4">
                  <p className="text-sm text-muted-foreground">
                    {t('install.desktop.ready', 'lnkmx.my is ready to be installed!')}
                  </p>
                  <Button onClick={handleInstallPWA} className="w-full">
                    <Download className="h-4 w-4 mr-2" />
                    {t('install.desktop.installNow', 'Install Now')}
                  </Button>
                </div>
              ) : (
                <div className="space-y-3">
                  <div className="flex items-start gap-3">
                    <div className="flex-shrink-0 w-6 h-6 rounded-full bg-primary text-primary-foreground flex items-center justify-center text-sm font-bold">
                      1
                    </div>
                    <div>
                      <p className="font-medium">{t('install.desktop.step1', 'Look for install icon')}</p>
                      <p className="text-sm text-muted-foreground">
                        {t('install.desktop.step1desc', 'Find the install icon in the address bar (Chrome, Edge)')}
                      </p>
                    </div>
                  </div>
                  <div className="flex items-start gap-3">
                    <div className="flex-shrink-0 w-6 h-6 rounded-full bg-primary text-primary-foreground flex items-center justify-center text-sm font-bold">
                      2
                    </div>
                    <div>
                      <p className="font-medium">{t('install.desktop.step2', 'Click "Install"')}</p>
                      <p className="text-sm text-muted-foreground">
                        {t('install.desktop.step2desc', 'Confirm the installation to add lnkmx.my to your desktop')}
                      </p>
                    </div>
                  </div>
                </div>
              )}
            </TabsContent>
          </Tabs>

          <div className="flex gap-2 pt-2">
            <Button variant="outline" className="flex-1" onClick={onClose}>
              {t('install.later', 'Maybe Later')}
            </Button>
            <Button
              className="flex-1"
              onClick={() => {
                navigator.clipboard.writeText(pageUrl);
                onClose();
              }}
            >
              {t('install.copyLink', 'Copy Link')}
            </Button>
          </div>
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { useEffect } from 'react';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { RefreshCw } from 'lucide-react';

declare global {
  interface Window {
    workbox?: any;
  }
}

export function PWAUpdatePrompt() {
  useEffect(() => {
    if ('serviceWorker' in navigator) {
      navigator.serviceWorker.ready.then((registration) => {
        registration.addEventListener('updatefound', () => {
          const newWorker = registration.installing;
          if (newWorker) {
            newWorker.addEventListener('statechange', () => {
              if (newWorker.state === 'installed' && navigator.serviceWorker.controller) {
                // New service worker available
                console.log('New content is available; please refresh.');
              }
            });
          }
        });
      });
    }
  }, []);

  return null;
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Gift, Copy, Share2, Users, Check, X } from 'lucide-react';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { useReferral } from '@/hooks/user/useReferral';
import { toast } from 'sonner';

interface ShareAfterPublishDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  userId: string | undefined;
  publishedUrl: string;
}

export function ShareAfterPublishDialog({
  open,
  onOpenChange,
  userId,
  publishedUrl,
}: ShareAfterPublishDialogProps) {
  const { t } = useTranslation();
  const { stats, shareLink, copyCode } = useReferral(userId);
  const [copiedPage, setCopiedPage] = useState(false);
  const [copiedReferral, setCopiedReferral] = useState(false);

  const handleCopyPageLink = async () => {
    await navigator.clipboard.writeText(publishedUrl);
    setCopiedPage(true);
    toast.success(t('share.linkCopied', 'Link copied!'));
    setTimeout(() => setCopiedPage(false), 2000);
  };

  const handleCopyReferralLink = () => {
    shareLink();
    setCopiedReferral(true);
    setTimeout(() => setCopiedReferral(false), 2000);
  };

  const handleShare = async () => {
    if (navigator.share) {
      try {
        await navigator.share({
          title: t('share.title', 'Check out my lnkmx.my page!'),
          url: publishedUrl,
        });
      } catch (e) {
        // User cancelled
      }
    } else {
      handleCopyPageLink();
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md bg-card/95 backdrop-blur-2xl border-border/40">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2 text-xl">
            <div className="h-10 w-10 rounded-full bg-primary/10 flex items-center justify-center">
              <Share2 className="h-5 w-5 text-primary" />
            </div>
            {t('share.published', 'Page Published!')}
          </DialogTitle>
          <DialogDescription className="sr-only">
            {t('share.publishedDesc', 'Share your published page with others')}
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-6 py-4">
          {/* Share page link */}
          <div className="space-y-2">
            <label className="text-sm font-medium text-muted-foreground">
              {t('share.yourPageLink', 'Your page link')}
            </label>
            <div className="flex gap-2">
              <Input 
                value={publishedUrl} 
                readOnly 
                className="bg-muted/50 border-border/50"
              />
              <Button 
                variant="outline" 
                size="icon"
                onClick={handleCopyPageLink}
                className="flex-shrink-0"
              >
                {copiedPage ? <Check className="h-4 w-4 text-green-500" /> : <Copy className="h-4 w-4" />}
              </Button>
            </div>
            <Button 
              className="w-full mt-2 rounded-xl" 
              onClick={handleShare}
            >
              <Share2 className="h-4 w-4 mr-2" />
              {t('share.shareNow', 'Share Now')}
            </Button>
          </div>

          {/* Referral section */}
          {stats?.code && (
            <div className="pt-4 border-t border-border/50">
              <div className="flex items-center gap-3 mb-4">
                <div className="h-10 w-10 rounded-full bg-gradient-to-br from-amber-500 to-orange-500 flex items-center justify-center">
                  <Gift className="h-5 w-5 text-white" />
                </div>
                <div>
                  <h4 className="font-semibold">
                    {t('referral.inviteFriend', 'Invite a friend')}
                  </h4>
                  <p className="text-sm text-muted-foreground">
                    {t('referral.bothGetBonus', 'You both get +3 days Premium!')}
                  </p>
                </div>
              </div>

              <div className="space-y-2">
                <div className="flex gap-2">
                  <Input 
                    value={`${window.location.origin}/auth?ref=${stats.code}`}
                    readOnly 
                    className="bg-muted/50 border-border/50 text-sm"
                  />
                  <Button 
                    variant="outline" 
                    size="icon"
                    onClick={handleCopyReferralLink}
                    className="flex-shrink-0"
                  >
                    {copiedReferral ? <Check className="h-4 w-4 text-green-500" /> : <Copy className="h-4 w-4" />}
                  </Button>
                </div>
                <Button 
                  variant="secondary"
                  className="w-full rounded-xl"
                  onClick={handleCopyReferralLink}
                >
                  <Users className="h-4 w-4 mr-2" />
                  {t('referral.shareReferralLink', 'Share Referral Link')}
                </Button>
              </div>

              {stats.referralsCount > 0 && (
                <div className="mt-3 p-3 rounded-xl bg-primary/5 border border-primary/20">
                  <div className="flex items-center justify-between text-sm">
                    <span className="text-muted-foreground">
                      {t('referral.friendsInvited', 'Friends invited')}
                    </span>
                    <span className="font-semibold text-primary">{stats.referralsCount}</span>
                  </div>
                  <div className="flex items-center justify-between text-sm mt-1">
                    <span className="text-muted-foreground">
                      {t('referral.bonusEarned', 'Bonus days earned')}
                    </span>
                    <span className="font-semibold text-primary">+{stats.bonusDaysEarned}</span>
                  </div>
                </div>
              )}
            </div>
          )}
        </div>

        <Button 
          variant="ghost" 
          className="absolute top-4 right-4" 
          size="icon"
          onClick={() => onOpenChange(false)}
        >
          <X className="h-4 w-4" />
        </Button>
      </DialogContent>
    </Dialog>
  );
}

'use client';

import { useState, useEffect } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { toast } from 'sonner';
import { useAuth } from '@/hooks/user/useAuth';
import { useSoundEffects } from '@/hooks/ui/useSoundEffects';
import { Gift, Mail, Check } from 'lucide-react';
import { z } from 'zod';
import { LanguageSwitcher } from '@/components/translation/LanguageSwitcher';
import { applyReferralCode } from '@/services/referral';
import { supabase } from '@/platform/supabase/client';
import { logger } from '@/lib/utils/logger';
import { TermsLink } from '@/components/legal/TermsOfServiceModal';
import { PrivacyLink } from '@/components/legal/PrivacyPolicyModal';
import { Checkbox } from '@/components/ui/checkbox';
import { StaticSEOHead } from '@/components/seo/StaticSEOHead';

const authSchema = z.object({
  email: z
    .string()
    .trim()
    .email('Please enter a valid email address')
    .max(255, 'Email must be less than 255 characters'),
  password: z
    .string()
    .min(8, 'Password must be at least 8 characters')
    .regex(/[A-Z]/, 'Password must contain at least one uppercase letter')
    .regex(/[a-z]/, 'Password must contain at least one lowercase letter')
    .regex(/[0-9]/, 'Password must contain at least one number'),
});

type AuthMode = 'signin' | 'signup' | 'reset' | 'reset-telegram' | 'update-password';
type TelegramResetStep = 'request' | 'verify';

export default function Auth() {
  const navigate = useNavigate();
  const [searchParams] = useSearchParams();
  const { t, i18n } = useTranslation();
  const canonical = 'https://lnkmx.my/auth';
  const seoTitle = t('auth.seo.title', 'Sign in to lnkmx');
  const seoDescription = t(
    'auth.seo.description',
    'Access your lnkmx dashboard to build and publish your link in bio page.'
  );
  const { user, signUp, signIn, signInWithGoogle, signInWithApple } = useAuth();
  const { playSuccess, playError } = useSoundEffects();
  const [isLoading, setIsLoading] = useState(false);
  const [isOAuthLoading, setIsOAuthLoading] = useState<'google' | 'apple' | null>(null);
  const [authMode, setAuthMode] = useState<AuthMode>('signin');
  const [resetEmailSent, setResetEmailSent] = useState(false);
  const [signupEmailSent, setSignupEmailSent] = useState(false);
  const [passwordUpdated, setPasswordUpdated] = useState(false);

  // Telegram password reset state
  const [telegramResetStep, setTelegramResetStep] = useState<TelegramResetStep>('request');
  const [telegramChatId, setTelegramChatId] = useState('');
  const [resetToken, setResetToken] = useState('');

  // Get referral code and mode from URL
  const refCode = searchParams.get('ref');
  const urlMode = searchParams.get('mode');
  const returnTo = searchParams.get('returnTo');
  const safeReturnTo = returnTo && returnTo.startsWith('/') && !returnTo.startsWith('//') ? returnTo : undefined;

  // Check for auth errors returned from OAuth redirect
  const authError = searchParams.get('auth_error');
  const authErrorDescription = searchParams.get('auth_error_description');

  useEffect(() => {
    if (authError) {
      toast.error(t('auth.oauthError', 'Authentication Error: {{error}}', { error: authErrorDescription || authError }));
      // Clean up URL without triggering re-renders
      const newUrl = new URL(window.location.href);
      newUrl.searchParams.delete('auth_error');
      newUrl.searchParams.delete('auth_error_description');
      window.history.replaceState(null, '', newUrl.toString());
    }
  }, [authError, authErrorDescription, t]);

  // Check for password update mode from URL or hash params (from email link)
  useEffect(() => {
    if (urlMode === 'update-password') {
      setAuthMode('update-password');
      return;
    }

    // Check hash params for recovery token (from Supabase email link)
    const hashParams = new URL(window.location.href).hash.substring(1);
    const searchParams = new URLSearchParams(hashParams);
    const accessToken = searchParams.get('access_token');
    const type = searchParams.get('type');

    if (accessToken && type === 'recovery') {
      logger.debug('Recovery token detected, setting up password update mode');
      // Supabase will automatically set the session from hash params
      // We just need to set the mode
      setAuthMode('update-password');

      // Clean up the URL hash for better UX
      window.history.replaceState(null, '', `${window.location.pathname}?mode=update-password`);
    }
  }, [urlMode]);

  // Redirect if already logged in (but not during password update)
  useEffect(() => {
    if (user && authMode !== 'update-password') {
      // Apply referral code if present
      if (refCode) {
        applyReferralCode(refCode, user.id).then((result) => {
          if (result.success) {
            toast.success(t('auth.referral.success', '🎉 +{{days}} days Premium for referral code!', { days: result.bonusDays }));
          }
        });
      }
      navigate(safeReturnTo || '/dashboard');
    }
  }, [user, navigate, refCode, authMode, safeReturnTo]);

  // Simplified signup - no Telegram required for free users
  const handleSignUp = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setIsLoading(true);

    const formData = new FormData(e.currentTarget);
    const email = formData.get('signup-email') as string;
    const password = formData.get('signup-password') as string;

    // Validate with zod schema
    const validation = authSchema.safeParse({ email, password });

    if (!validation.success) {
      const firstError = validation.error.errors[0];
      toast.error(firstError.message);
      playError();
      setIsLoading(false);
      return;
    }

    const { data, error } = await signUp(validation.data.email, validation.data.password);

    if (error) {
      logger.error('Signup error:', error, { context: 'Auth' });
      toast.error(error.message || t('messages.failedToSignUp'));
      playError();
      setIsLoading(false);
      return;
    }

    if (data?.user && !data.session) {
      setSignupEmailSent(true);
      playSuccess();
      setIsLoading(false);
      return;
    }

    playSuccess();
    toast.success(t('messages.accountCreated'));
    // Auth state change will trigger redirect
    setIsLoading(false);
  };

  const handleSignIn = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setIsLoading(true);

    const formData = new FormData(e.currentTarget);
    const email = formData.get('signin-email') as string;
    const password = formData.get('signin-password') as string;

    // Validate with zod schema
    const validation = authSchema.safeParse({ email, password });

    if (!validation.success) {
      const firstError = validation.error.errors[0];
      toast.error(firstError.message);
      playError();
      setIsLoading(false);
      return;
    }

    const { error } = await signIn(validation.data.email, validation.data.password);

    if (error) {
      logger.error('Signin error:', error, { context: 'Auth' });
      toast.error(error.message || t('messages.failedToSignIn'));
      playError();
      setIsLoading(false);
      return;
    }

    playSuccess();
    toast.success(t('auth.welcomeBack', 'Welcome back!'));
    // Auth state change will trigger redirect
  };

  const handlePasswordReset = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setIsLoading(true);

    const formData = new FormData(e.currentTarget);
    const email = formData.get('reset-email') as string;

    const emailValidation = z.string().trim().email().safeParse(email);
    if (!emailValidation.success) {
      toast.error(t('auth.invalidEmail', 'Please enter a valid email address'));
      playError();
      setIsLoading(false);
      return;
    }

    const { error } = await supabase.auth.resetPasswordForEmail(emailValidation.data, {
      redirectTo: `${window.location.origin}/auth?mode=update-password`,
    });

    if (error) {
      logger.error('Password reset error:', error, { context: 'Auth' });
      toast.error(error.message || t('auth.resetFailed', 'Failed to send reset email'));
      playError();
      setIsLoading(false);
      return;
    }

    playSuccess();
    setResetEmailSent(true);
    setIsLoading(false);
  };

  const handleTelegramResetRequest = async () => {
    if (!telegramChatId || !/^\d+$/.test(telegramChatId)) {
      toast.error(t('auth.telegram.invalidChatId', 'Enter a valid Telegram Chat ID'));
      playError();
      return;
    }

    setIsLoading(true);
    try {
      const { data, error } = await supabase.functions.invoke('telegram-password-reset', {
        body: { telegram_chat_id: telegramChatId, action: 'request' }
      });

      if (error || !data?.success) {
        const errorMessages: Record<string, string> = {
          telegram_not_found: t('auth.telegram.notFound', 'Account with this Telegram not found'),
          telegram_send_failed: t('auth.telegram.sendFailed', 'Failed to send message')
        };
        toast.error(errorMessages[data?.error] || t('auth.telegram.codeSendError', 'Error sending code'));
        playError();
      } else {
        playSuccess();
        setTelegramResetStep('verify');
        toast.success(t('auth.telegram.codeSent', 'Code sent to Telegram!'));
      }
    } catch (e) {
      toast.error(t('auth.telegram.connectionError', 'Connection error'));
      playError();
    }
    setIsLoading(false);
  };

  const handleTelegramResetVerify = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    const formData = new FormData(e.currentTarget);
    const newPassword = formData.get('new-password') as string;

    const passwordValidation = authSchema.shape.password.safeParse(newPassword);
    if (!passwordValidation.success) {
      toast.error(passwordValidation.error.errors[0].message);
      playError();
      return;
    }

    setIsLoading(true);
    try {
      const { data, error } = await supabase.functions.invoke('telegram-password-reset', {
        body: { telegram_chat_id: telegramChatId, action: 'verify', token: resetToken, new_password: newPassword }
      });

      if (error || !data?.success) {
        toast.error(data?.error === 'invalid_token' ? t('auth.telegram.invalidToken', 'Invalid or expired code') : t('auth.telegram.resetError', 'Password reset error'));
        playError();
      } else {
        playSuccess();
        toast.success(t('auth.telegram.passwordChanged', 'Password successfully changed!'));
        setAuthMode('signin');
        setTelegramResetStep('request');
        setTelegramChatId('');
        setResetToken('');
      }
    } catch (e) {
      toast.error(t('auth.telegram.connectionError', 'Connection error'));
      playError();
    }
    setIsLoading(false);
  };

  const handleUpdatePassword = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setIsLoading(true);

    const formData = new FormData(e.currentTarget);
    const newPassword = formData.get('new-password') as string;
    const confirmPassword = formData.get('confirm-password') as string;

    if (newPassword !== confirmPassword) {
      toast.error(t('auth.passwordsDoNotMatch', 'Passwords do not match'));
      playError();
      setIsLoading(false);
      return;
    }

    const passwordValidation = authSchema.shape.password.safeParse(newPassword);
    if (!passwordValidation.success) {
      toast.error(passwordValidation.error.errors[0].message);
      playError();
      setIsLoading(false);
      return;
    }

    const { error } = await supabase.auth.updateUser({
      password: newPassword,
    });

    if (error) {
      logger.error('Password update error:', error, { context: 'Auth' });
      toast.error(error.message || t('auth.updateFailed', 'Failed to update password'));
      playError();
      setIsLoading(false);
      return;
    }

    playSuccess();
    setPasswordUpdated(true);
    setIsLoading(false);
  };

  const handleGoogleSignIn = async () => {
    setIsOAuthLoading('google');
    const { error } = await signInWithGoogle(safeReturnTo);
    if (error) {
      toast.error(error.message || t('messages.failedToSignIn'));
      playError();
    }
    setIsOAuthLoading(null);
  };

  const handleAppleSignIn = async () => {
    setIsOAuthLoading('apple');
    const { error } = await signInWithApple(safeReturnTo);
    if (error) {
      toast.error(error.message || t('messages.failedToSignIn'));
      playError();
    }
    setIsOAuthLoading(null);
  };

  return (
    <>
      <StaticSEOHead
        title={seoTitle}
        description={seoDescription}
        canonical={canonical}
        currentLanguage={i18n.language}
        indexable={false}
        alternates={[
          { hreflang: 'ru', href: `${canonical}?lang=ru` },
          { hreflang: 'en', href: `${canonical}?lang=en` },
          { hreflang: 'kk', href: `${canonical}?lang=kk` },
          { hreflang: 'x-default', href: canonical },
        ]}
      />
      <div className="min-h-screen bg-gradient-to-b from-background to-background/80 flex items-center justify-center p-4 relative overflow-x-hidden pb-safe">
        {/* Background Effects */}
        <div className="fixed inset-0 pointer-events-none overflow-hidden -z-10">
          <div className="absolute -top-40 -right-40 w-[600px] h-[600px] bg-gradient-to-bl from-primary/20 via-violet-500/10 to-transparent rounded-full blur-[150px] animate-morph will-change-transform" />
          <div className="absolute bottom-0 left-0 w-[500px] h-[500px] bg-gradient-to-tr from-blue-500/15 via-cyan-500/10 to-transparent rounded-full blur-[120px] animate-morph will-change-transform" style={{ animationDelay: '-7s' }} />
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[400px] h-[400px] bg-gradient-to-r from-purple-500/10 via-pink-500/5 to-transparent rounded-full blur-[100px] animate-float-slow will-change-transform" />
        </div>

        <div className="w-full max-w-md space-y-6">
          {/* Referral Banner */}
          {refCode && (
            <Card className="bg-gradient-to-r from-violet-500/20 to-purple-500/20 backdrop-blur-xl border-violet-500/30 rounded-2xl p-4 animate-fade-in">
              <div className="flex items-center gap-3">
                <div className="h-10 w-10 rounded-xl bg-violet-500/30 flex items-center justify-center">
                  <Gift className="h-5 w-5 text-violet-400" />
                </div>
                <div>
                  <p className="font-medium text-sm">{t('auth.referral.invited', 'You have been invited!')}</p>
                  <p className="text-xs text-muted-foreground">
                    {t('auth.referral.bonus', 'Sign up and get +3 days Premium')}
                  </p>
                </div>
              </div>
            </Card>
          )}

          {/* Logo */}
          <div className="text-center">
            <div className="flex items-center justify-center gap-2 mb-3 animate-fade-in">
              <div className="h-16 w-16 rounded-2xl bg-card/60 backdrop-blur-2xl border border-border/30 shadow-glass-lg flex items-center justify-center animate-scale-in">
                <img src="/favicon.png" alt="lnkmx" className="h-10 w-10 object-contain" />
              </div>
            </div>
            <h1 className="text-3xl font-bold bg-gradient-to-r from-primary via-primary to-violet-500 bg-clip-text text-transparent animate-fade-in" style={{ animationDelay: '0.1s' }}>
              {t('auth.title')}
            </h1>
            <p className="text-muted-foreground mt-2 animate-fade-in" style={{ animationDelay: '0.2s' }}>
              {t('auth.subtitle')}
            </p>
            <div className="mt-4 flex justify-center animate-fade-in" style={{ animationDelay: '0.3s' }}>
              <LanguageSwitcher />
            </div>
          </div>

          {/* Password Update Card */}
          {authMode === 'update-password' ? (
            <Card className="bg-card/60 backdrop-blur-2xl border border-border/30 rounded-3xl shadow-glass-xl animate-fade-in" style={{ animationDelay: '0.2s' }}>
              <CardHeader className="pb-4">
                <CardTitle className="text-xl">{t('auth.newPassword', 'New Password')}</CardTitle>
                <CardDescription>
                  {t('auth.enterNewPassword', 'Enter your new password')}
                </CardDescription>
              </CardHeader>
              <CardContent className="space-y-4">
                {passwordUpdated ? (
                  <div className="space-y-4 text-center">
                    <div className="h-16 w-16 mx-auto rounded-full bg-green-500/20 flex items-center justify-center">
                      <Check className="h-8 w-8 text-green-500" />
                    </div>
                    <h3 className="text-lg font-semibold">{t('auth.passwordUpdated', 'Password Updated')}</h3>
                    <p className="text-sm text-muted-foreground">
                      {t('auth.passwordUpdatedDesc', 'Your password has been successfully updated')}
                    </p>
                    <Button
                      className="w-full h-12 rounded-xl"
                      onClick={() => navigate('/dashboard')}
                    >
                      {t('auth.goToDashboard', 'Go to Dashboard')}
                    </Button>
                  </div>
                ) : (
                  <form onSubmit={handleUpdatePassword} className="space-y-4">
                    <div className="space-y-2">
                      <Label htmlFor="new-password" className="text-sm text-muted-foreground">
                        {t('auth.newPassword', 'New Password')}
                      </Label>
                      <Input
                        id="new-password"
                        name="new-password"
                        type="password"
                        placeholder="••••••••"
                        required
                        className="h-12 rounded-xl bg-card/40 backdrop-blur-xl border-border/30 focus:border-primary/50"
                      />
                    </div>
                    <div className="space-y-2">
                      <Label htmlFor="confirm-password" className="text-sm text-muted-foreground">
                        {t('auth.confirmPassword', 'Confirm Password')}
                      </Label>
                      <Input
                        id="confirm-password"
                        name="confirm-password"
                        type="password"
                        placeholder="••••••••"
                        required
                        className="h-12 rounded-xl bg-card/40 backdrop-blur-xl border-border/30 focus:border-primary/50"
                      />
                      <p className="text-xs text-muted-foreground mt-2 bg-muted/20 backdrop-blur-xl p-2 rounded-lg">
                        {t('auth.passwordHint')}
                      </p>
