                    ) : (
                      <form onSubmit={handleSignIn} className="space-y-4 pt-4">
                        <div className="space-y-2">
                          <Label htmlFor="signin-email" className="text-sm text-muted-foreground">{t('auth.email')}</Label>
                          <Input
                            id="signin-email"
