                          />
                        </div>
                        <Button type="submit" className="w-full h-12 rounded-xl shadow-glass-lg transition-all duration-300 hover:scale-[1.02]" disabled={isLoading || isOAuthLoading !== null}>
                          {isLoading ? t('auth.signingIn') : t('auth.signIn')}
