                      </div>
                    ) : (
                      <form onSubmit={handleSignUp} className="space-y-4 pt-4">
                        <div className="space-y-2">
                          <Label htmlFor="signup-email" className="text-sm text-muted-foreground">{t('auth.email')}</Label>
                          <Input
                            id="signup-email"
                            name="signup-email"
                            type="email"
                            placeholder="your@email.com"
                            required
                            className="h-12 rounded-xl bg-card/40 backdrop-blur-xl border-border/30 focus:border-primary/50"
                          />
                        </div>
                        <div className="space-y-2">
                          <Label htmlFor="signup-password" className="text-sm text-muted-foreground">{t('auth.password')}</Label>
                          <Input
                            id="signup-password"
                            name="signup-password"
                            type="password"
                            placeholder="••••••••"
                            required
                            className="h-12 rounded-xl bg-card/40 backdrop-blur-xl border-border/30 focus:border-primary/50"
                          />
                          <p className="text-xs text-muted-foreground mt-2 bg-muted/20 backdrop-blur-xl p-2 rounded-lg">
                            {t('auth.passwordHint')}
                          </p>
                        </div>
                        <div className="flex items-start space-x-2">
                          <Checkbox id="terms" required className="mt-0.5" />
                          <label htmlFor="terms" className="text-sm text-muted-foreground leading-tight">
                            {t('legal.agreeToTerms')}{' '}
                            <TermsLink className="text-primary hover:underline">
                              {t('legal.termsLink')}
                            </TermsLink>
                            {' '}{t('legal.andThe')}{' '}
                            <PrivacyLink className="text-primary hover:underline">
                              {t('legal.privacyLink')}
                            </PrivacyLink>
                          </label>
                        </div>
                        <Button type="submit" className="w-full h-12 rounded-xl shadow-glass-lg transition-all duration-300 hover:scale-[1.02]" disabled={isLoading || isOAuthLoading !== null}>
                          {isLoading ? t('messages.loading', 'Loading...') : t('auth.signUp')}
                        </Button>
                      </form>
                    )}
                  </TabsContent>
                </Tabs>
              </CardContent>
            </Card>
          )}

          {/* Back to home */}
          <div className="text-center animate-fade-in" style={{ animationDelay: '0.4s' }}>
            <Button variant="ghost" onClick={() => navigate('/')} className="rounded-xl hover:bg-card/40 backdrop-blur-xl">
              {t('auth.backToHome')}
            </Button>
          </div>
        </div>
      </div>
    </>
  );
}

'use client';

import { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { supabase } from "@/platform/supabase/client";
import { Loader2 } from "lucide-react";

export default function AuthCallback() {
    const navigate = useNavigate();

    useEffect(() => {
        // The Supabase client automatically handles the hash fragment parsing
        // and session restoration on initialization.

        // 1. Check for errors in hash or query params first
        const hashParams = new URLSearchParams(window.location.hash.substring(1));
        const searchParams = new URLSearchParams(window.location.search);

        const error = hashParams.get("error") || searchParams.get("error");
        const errorDescription = hashParams.get("error_description") || searchParams.get("error_description");

        if (error) {
            // If there's an error, check if we have an active session
            // This tells us if it was a login attempt or a link account attempt
            supabase.auth.getSession().then(({ data: { session } }) => {
                const encode = encodeURIComponent;
                if (session) {
                    // They were logged in, so they probably tried to link an account
                    navigate(`/dashboard/settings?auth_error=${encode(error)}&auth_error_description=${encode(errorDescription || '')}`, { replace: true });
                } else {
                    // Regular login error
                    navigate(`/auth?auth_error=${encode(error)}&auth_error_description=${encode(errorDescription || '')}`, { replace: true });
                }
            });
            return;
        }

        // 2. Listen for auth state changes for successful auth
        const { data: { subscription } } = supabase.auth.onAuthStateChange((event, session) => {
            if (event === "SIGNED_IN") {
                const returnTo = hashParams.get('returnTo') || searchParams.get('returnTo');
                navigate(returnTo || "/dashboard/settings", { replace: true });
            }
        });

        // 3. Fallback timeout in case onAuthStateChange doesn't fire (e.g. already signed in)
        const timeout = setTimeout(async () => {
            const { data: { session } } = await supabase.auth.getSession();
            if (session) {
                const returnTo = searchParams.get('returnTo') || hashParams.get('returnTo');
                navigate(returnTo || "/dashboard/settings", { replace: true });
            } else {
                if (!window.location.hash) {
                    navigate("/auth", { replace: true });
                }
            }
        }, 2000);

        return () => {
            subscription.unsubscribe();
            clearTimeout(timeout);
        };
    }, [navigate]);

    return (
        <div className="min-h-screen flex items-center justify-center bg-background">
            <div className="flex flex-col items-center gap-4">
                <Loader2 className="h-8 w-8 animate-spin text-primary" />
                <p className="text-muted-foreground">Completing authentication...</p>
            </div>
        </div>
    );
}

/**
 * Experts Directory Page
 * /experts - Main directory of all public profiles
 * /experts/{tag} - Filtered by niche/skill
 * 
 * SEO: CollectionPage schema, ItemList, internal linking
 */

'use client';

import { useEffect, useMemo } from 'react';
import { useParams, useSearchParams } from 'next/navigation';
import Link from 'next/link';
import { useTranslation } from 'react-i18next';
import { useQuery } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { StaticSEOHead } from '@/components/seo/StaticSEOHead';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Badge } from '@/components/ui/badge';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Skeleton } from '@/components/ui/skeleton';
import { Users, Search, ArrowRight, ExternalLink } from 'lucide-react';
import { cn } from '@/lib/utils/utils';

// Normalized niche tags with i18n
const NICHE_TAGS = [
  { slug: 'beauty', label: { ru: 'Красота', en: 'Beauty', kk: 'Сұлулық' } },
  { slug: 'coaching', label: { ru: 'Коучинг', en: 'Coaching', kk: 'Коучинг' } },
  { slug: 'consulting', label: { ru: 'Консалтинг', en: 'Consulting', kk: 'Кеңес беру' } },
  { slug: 'design', label: { ru: 'Дизайн', en: 'Design', kk: 'Дизайн' } },
  { slug: 'education', label: { ru: 'Образование', en: 'Education', kk: 'Білім' } },
  { slug: 'fitness', label: { ru: 'Фитнес', en: 'Fitness', kk: 'Фитнес' } },
  { slug: 'health', label: { ru: 'Здоровье', en: 'Health', kk: 'Денсаулық' } },
  { slug: 'marketing', label: { ru: 'Маркетинг', en: 'Marketing', kk: 'Маркетинг' } },
  { slug: 'music', label: { ru: 'Музыка', en: 'Music', kk: 'Музыка' } },
  { slug: 'photo', label: { ru: 'Фотография', en: 'Photography', kk: 'Фотография' } },
  { slug: 'tech', label: { ru: 'Технологии', en: 'Technology', kk: 'Технология' } },
  { slug: 'other', label: { ru: 'Другое', en: 'Other', kk: 'Басқа' } },
];

interface ExpertProfile {
  id: string;
  slug: string;
  title: string | null;
  description: string | null;
  avatar_url: string | null;
  niche: string | null;
  view_count: number | null;
}

export default function Experts() {
  const params = useParams();
  const tag = params?.tag as string;
  const searchParams = useSearchParams();
  const { t, i18n } = useTranslation();
  const language = i18n.language as 'ru' | 'en' | 'kk';

  // Fetch experts from database
  const { data: experts, isLoading } = useQuery({
    queryKey: ['experts', tag],
    queryFn: async () => {
      let query = (supabase as any)
        .from('pages')
        .select('id, slug, title, description, avatar_url, niche, view_count')
        .eq('is_published', true)
        .eq('is_indexable', true)
        .order('view_count', { ascending: false })
        .limit(100);

      if (tag) {
        query = query.eq('niche', tag);
      }

      const { data, error } = await query;
      if (error) throw error;
      return data as ExpertProfile[];
    },
    staleTime: 5 * 60 * 1000, // 5 minutes
  });

  // Page meta
  const currentTag = NICHE_TAGS.find(t => t.slug === tag);
  const pageTitle = tag
    ? `${currentTag?.label[language] || tag} ${t('experts.title', 'эксперты')} | lnkmx`
    : t('experts.directoryTitle', 'Каталог экспертов | lnkmx');

  const pageDescription = tag
    ? t('experts.tagDescription', { tag: currentTag?.label[language] || tag })
    : t('experts.directoryDescription', 'Найдите экспертов и специалистов на lnkmx');

  const canonical = tag
    ? `https://lnkmx.my/experts/${tag}`
    : 'https://lnkmx.my/experts';

  // JSON-LD Schema
  useEffect(() => {
    const schema = {
      '@context': 'https://schema.org',
      '@type': 'CollectionPage',
      name: pageTitle.replace(' | lnkmx', ''),
      description: pageDescription,
      url: canonical,
      mainEntity: {
        '@type': 'ItemList',
        itemListElement: (experts || []).slice(0, 20).map((expert, index) => ({
          '@type': 'ListItem',
          position: index + 1,
          item: {
            '@type': 'Person',
            name: expert.title || expert.slug,
            url: `https://lnkmx.my/${expert.slug}`,
            image: expert.avatar_url,
          },
        })),
      },
      isPartOf: {
        '@type': 'WebSite',
        name: 'lnkmx',
        url: 'https://lnkmx.my',
      },
    };

    let script = document.querySelector('script#experts-schema') as HTMLScriptElement;
    if (!script) {
      script = document.createElement('script');
      script.type = 'application/ld+json';
      script.id = 'experts-schema';
      document.head.appendChild(script);
    }
    script.textContent = JSON.stringify(schema);

    return () => {
      script?.remove();
    };
  }, [experts, canonical, pageTitle, pageDescription]);

  return (
    <>
      <StaticSEOHead
        title={pageTitle}
        description={pageDescription}
        canonical={canonical}
        currentLanguage={language}
        ogType="website"
        alternates={[
          { hreflang: 'ru', href: `${canonical}?lang=ru` },
          { hreflang: 'en', href: `${canonical}?lang=en` },
          { hreflang: 'kk', href: `${canonical}?lang=kk` },
          { hreflang: 'x-default', href: canonical },
        ]}
      />

      <div className="min-h-screen bg-background">
        {/* Header */}
        <header className="border-b bg-card/50 backdrop-blur-sm sticky top-0 z-40">
          <div className="container max-w-6xl mx-auto px-4 py-4">
            <div className="flex items-center justify-between">
              <Link href="/" className="text-xl font-bold text-primary">
                lnkmx
              </Link>
              <Link href="/auth">
                <Button variant="outline" size="sm">
                  {t('auth.signIn', 'Войти')}
                </Button>
              </Link>
            </div>
          </div>
        </header>

        {/* Hero */}
        <section className="py-12 bg-gradient-to-b from-primary/5 to-background">
          <div className="container max-w-6xl mx-auto px-4 text-center">
            <div className="inline-flex items-center gap-2 px-4 py-2 bg-primary/10 rounded-full mb-4">
              <Users className="h-4 w-4 text-primary" />
              <span className="text-sm text-primary font-medium">
                {experts?.length || 0}+ {t('experts.profiles', 'профилей')}
              </span>
            </div>

            <h1 className="text-3xl md:text-4xl font-bold mb-4">
              {tag ? (
                <>
                  {currentTag?.label[language] || tag}
                  <span className="text-muted-foreground"> {t('experts.onLnkmx', 'на lnkmx')}</span>
                </>
              ) : (
                t('experts.findExperts', 'Найти экспертов')
              )}
            </h1>

            <p className="text-muted-foreground max-w-xl mx-auto mb-8">
              {t('experts.subtitle', 'Мини-сайты экспертов, фрилансеров и малого бизнеса')}
            </p>

            {/* Search (placeholder for future) */}
            <div className="max-w-md mx-auto">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder={t('experts.searchPlaceholder', 'Поиск по имени или нише...')}
                  className="pl-10"
                  disabled
                />
              </div>
            </div>
          </div>
        </section>

        {/* Tags Filter */}
        <section className="py-6 border-b">
          <div className="container max-w-6xl mx-auto px-4">
            <div className="flex flex-wrap gap-2 justify-center">
              <Link href="/experts">
                <Badge
                  variant={!tag ? 'default' : 'outline'}
                  className="cursor-pointer hover:bg-primary/80"
                >
                  {t('experts.all', 'Все')}
                </Badge>
              </Link>
              {NICHE_TAGS.map(niche => (
                <Link key={niche.slug} href={`/experts/${niche.slug}`}>
                  <Badge
                    variant={tag === niche.slug ? 'default' : 'outline'}
                    className="cursor-pointer hover:bg-primary/80"
                  >
                    {niche.label[language]}
                  </Badge>
                </Link>
              ))}
            </div>
          </div>
        </section>

        {/* Experts Grid */}
        <section className="py-12">
          <div className="container max-w-6xl mx-auto px-4">
            {isLoading ? (
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                {[...Array(9)].map((_, i) => (
                  <Skeleton key={i} className="h-48 rounded-xl" />
                ))}
              </div>
            ) : experts?.length === 0 ? (
              <div className="text-center py-12">
                <p className="text-muted-foreground mb-4">
                  {t('experts.noResults', 'Пока нет профилей в этой категории')}
                </p>
                <Link href="/auth">
                  <Button>
                    {t('experts.beFirst', 'Стать первым')}
                    <ArrowRight className="h-4 w-4 ml-2" />
                  </Button>
                </Link>
              </div>
            ) : (
              <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6">
                {experts?.map(expert => (
                  <Link
                    key={expert.id}
                    href={`/${expert.slug}`}
                    className="group block"
                  >
                    <article
                      className={cn(
                        "p-6 rounded-xl border bg-card hover:border-primary/50 transition-all",
                        "hover:shadow-lg hover:-translate-y-1"
                      )}
                      itemScope
                      itemType="https://schema.org/Person"
                    >
                      <div className="flex items-start gap-4">
                        <Avatar className="h-14 w-14 ring-2 ring-background">
                          <AvatarImage src={expert.avatar_url || undefined} itemProp="image" />
                          <AvatarFallback>
                            {(expert.title || expert.slug).slice(0, 2).toUpperCase()}
                          </AvatarFallback>
                        </Avatar>
                        <div className="flex-1 min-w-0">
                          <h3
                            className="font-semibold truncate group-hover:text-primary transition-colors"
                            itemProp="name"
                          >
                            {expert.title || expert.slug}
                          </h3>
                          <p
                            className="text-sm text-muted-foreground line-clamp-2 mt-1"
                            itemProp="description"
                          >
                            {expert.description || t('experts.noDescription', 'Нет описания')}
                          </p>
                          <meta itemProp="url" content={`https://lnkmx.my/${expert.slug}`} />
                        </div>
                        <ExternalLink className="h-4 w-4 text-muted-foreground opacity-0 group-hover:opacity-100 transition-opacity" />
                      </div>

                      {expert.niche && (
                        <div className="mt-4 flex items-center gap-2">
                          <Badge variant="secondary" className="text-xs">
                            {NICHE_TAGS.find(n => n.slug === expert.niche)?.label[language] || expert.niche}
                          </Badge>
                          {expert.view_count && expert.view_count > 100 && (
                            <span className="text-xs text-muted-foreground">
                              {expert.view_count.toLocaleString()} {t('experts.views', 'просмотров')}
                            </span>
                          )}
                        </div>
                      )}
                    </article>
                  </Link>
                ))}
              </div>
            )}
          </div>
        </section>

        {/* CTA */}
        <section className="py-16 bg-primary/5">
          <div className="container max-w-4xl mx-auto px-4 text-center">
            <h2 className="text-2xl font-bold mb-4">
              {t('experts.ctaTitle', 'Создайте свою страницу бесплатно')}
            </h2>
            <p className="text-muted-foreground mb-6">
              {t('experts.ctaSubtitle', 'Присоединяйтесь к сообществу экспертов на lnkmx')}
            </p>
            <Link href="/auth">
              <Button size="lg" className="font-semibold">
                {t('experts.ctaButton', 'Создать страницу')}
                <ArrowRight className="h-4 w-4 ml-2" />
              </Button>
            </Link>
          </div>
        </section>

        {/* Footer */}
        <footer className="border-t py-8">
          <div className="container max-w-6xl mx-auto px-4 text-center text-sm text-muted-foreground">
            <p>© {new Date().getFullYear()} lnkmx. {t('footer.rights', 'Все права защищены.')}</p>
          </div>
        </footer>
      </div>
    </>
  );
}

/**
 * Gallery v1.3 - Mobile-first community gallery with performance optimizations
 * iOS-style design with filters, skeleton loading, and one-tap copy
 */
'use client';

import { useState, useMemo, useCallback, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import Link from 'next/link';
import { useRouter, useSearchParams } from 'next/navigation';
import {
  ArrowLeft,
  Users,
  Sparkles,
  TrendingUp,
  Heart,
  Search,
  Filter,
  Copy,
  ExternalLink,
  Crown,
  Eye,
  Star,
} from 'lucide-react';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Card } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { ScrollArea, ScrollBar } from '@/components/ui/scroll-area';
import { SkeletonCard, SkeletonGalleryGrid, SkeletonStats } from '@/components/ui/skeleton-card';
import { CommunityGallery } from '@/components/gallery/CommunityGallery';
import { Leaderboard } from '@/components/gallery/Leaderboard';
import { TopReferrers } from '@/components/gallery/TopReferrers';
import { LanguageSwitcher } from '@/components/translation/LanguageSwitcher';
import { useGallery } from '@/hooks/social/useGallery';
import { FeaturedPageCard } from '@/components/gallery/FeaturedPageCard';
import { GalleryPageCard } from '@/components/gallery/GalleryPageCard';
import { NICHES, NICHE_ICONS } from '@/lib/niches';
import { cn } from '@/lib/utils/utils';
import { toast } from 'sonner';
import { StaticSEOHead } from '@/components/seo/StaticSEOHead';
import { StructuredData } from '@/components/seo/StructuredData';
import { SEOMetaEnhancer } from '@/components/seo/SEOMetaEnhancer';
import { GEOTagging } from '@/components/seo/GEOTagging';
import { AISearchOptimizer } from '@/components/seo/AISearchOptimizer';

export default function Gallery() {
  const { t, i18n } = useTranslation();
  const router = useRouter();
  const searchParams = useSearchParams();
  const { pages, loading, likePage } = useGallery();
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedNiche, setSelectedNiche] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<'gallery' | 'leaderboard'>('gallery');
  const nicheLabel = selectedNiche ? t(`niches.${selectedNiche}`, selectedNiche) : null;
  const canonical = selectedNiche
    ? `https://lnkmx.my/gallery?niche=${selectedNiche}`
    : 'https://lnkmx.my/gallery';
  const seoTitle = selectedNiche
    ? t('gallery.seo.nicheTitle', { niche: nicheLabel, defaultValue: `lnkmx Gallery — ${nicheLabel}` })
    : t('gallery.seo.title', 'lnkmx Gallery — Link in Bio Examples & Templates');
  const seoDescription = selectedNiche
    ? t('gallery.seo.nicheDescription', { niche: nicheLabel, defaultValue: `Explore ${nicheLabel} pages on lnkmx.` })
    : t(
      'gallery.seo.description',
      'Explore real lnkmx link in bio pages by creators and businesses. Find templates, niches, and inspiration for your mini-site.'
    );
  const seoHighlights = t('gallery.seoIntro.highlights', { returnObjects: true }) as string[];

  // Quick stats - memoized for performance
  const totalLikes = useMemo(() =>
    pages.reduce((sum, p) => sum + (p.gallery_likes || 0), 0), [pages]);
  const totalViews = useMemo(() =>
    pages.reduce((sum, p) => sum + (p.view_count || 0), 0), [pages]);

  // Filter pages - memoized
  const filteredPages = useMemo(() => pages.filter(page => {
    const matchesSearch = !searchQuery ||
      page.title?.toLowerCase().includes(searchQuery.toLowerCase()) ||
      page.description?.toLowerCase().includes(searchQuery.toLowerCase());
    const matchesNiche = !selectedNiche || page.niche === selectedNiche;
    return matchesSearch && matchesNiche;
  }), [pages, searchQuery, selectedNiche]);

  // Featured pages (top 5 by likes) - memoized
  const featuredPages = useMemo(() => [...pages]
    .sort((a, b) => (b.gallery_likes || 0) - (a.gallery_likes || 0))
    .slice(0, 5), [pages]);

  const gallerySchema = useMemo(() => ({
    '@context': 'https://schema.org',
    '@graph': [
      {
        '@type': 'CollectionPage',
        name: seoTitle,
        description: seoDescription,
        url: canonical,
        inLanguage: i18n.language,
      },
      {
        '@type': 'ItemList',
        itemListElement: featuredPages.map((page, index) => ({
          '@type': 'ListItem',
          position: index + 1,
          url: `https://lnkmx.my/${page.slug}`,
          name: page.title || page.slug,
        })),
      },
    ],
  }), [seoTitle, seoDescription, canonical, featuredPages, i18n.language]);

  useEffect(() => {
    const nicheParam = searchParams.get('niche');
    if (nicheParam && NICHES.includes(nicheParam as (typeof NICHES)[number])) {
      setSelectedNiche(nicheParam);
      return;
    }
    if (!nicheParam) {
      setSelectedNiche(null);
    }
  }, [searchParams]);

  const updateNiche = useCallback((niche: string | null) => {
    setSelectedNiche(niche);
    const nextParams = new URLSearchParams(searchParams.toString());
    if (niche) {
      nextParams.set('niche', niche);
    } else {
      nextParams.delete('niche');
    }
    router.replace(`/gallery?${nextParams.toString()}`);
  }, [searchParams, router]);

  // Handlers - memoized
  const handleCopyTemplate = useCallback((pageSlug: string) => {
    toast.success(t('gallery.templateCopied', 'Шаблон скопирован!'), {
      description: t('gallery.goToEditor', 'Откройте редактор чтобы настроить'),
      action: {
        label: t('gallery.openEditor', 'Открыть'),
        onClick: () => router.push('/dashboard?tab=editor'),
      },
    });
  }, [t, router]);

  return (
    <>
      <StaticSEOHead
        title={seoTitle}
        description={seoDescription}
        canonical={canonical}
        currentLanguage={i18n.language}
        alternates={[
          { hreflang: 'ru', href: `${canonical}${canonical.includes('?') ? '&' : '?'}lang=ru` },
          { hreflang: 'en', href: `${canonical}${canonical.includes('?') ? '&' : '?'}lang=en` },
          { hreflang: 'kk', href: `${canonical}${canonical.includes('?') ? '&' : '?'}lang=kk` },
          { hreflang: 'x-default', href: canonical },
        ]}
      />
      <SEOMetaEnhancer
        pageUrl={canonical}
        pageTitle={seoTitle}
        pageDescription={seoDescription}
        imageUrl="https://lnkmx.my/og-gallery.png"
        imageAlt={t('gallery.seo.imageAlt', 'lnkmx Gallery - Link in Bio Examples')}
        type="website"
      />
      <GEOTagging includeOrganization={false} />
      <AISearchOptimizer
        pageType="gallery"
        primaryQuestion={t('gallery.seo.opt.question', 'Where can I see examples of lnkmx pages?')}
        primaryAnswer={t('gallery.seo.opt.answer', 'The lnkmx Gallery showcases real examples of pages created by users across different industries including freelancers, businesses, beauty professionals, fitness coaches, and content creators.')}
        entityName="lnkmx Gallery"
        entityCategory="Page Examples, Templates, Portfolio, Showcase"
        useCases={[
          t('gallery.seo.opt.uses.1', 'Browse professional page examples'),
          t('gallery.seo.opt.uses.2', 'Find inspiration for your industry'),
          t('gallery.seo.opt.uses.3', 'See real user implementations'),
          t('gallery.seo.opt.uses.4', 'Discover design ideas'),
          t('gallery.seo.opt.uses.5', 'Learn from successful pages'),
        ]}
        targetAudience={[
          t('gallery.seo.opt.audience.1', 'New users seeking inspiration'),
          t('gallery.seo.opt.audience.2', 'Businesses looking for examples'),
          t('gallery.seo.opt.audience.3', 'Designers researching layouts'),
          t('gallery.seo.opt.audience.4', 'Marketers studying conversions'),
        ]}
        problemStatement={t('gallery.seo.opt.problem', 'Users need inspiration and examples to understand how to build effective pages')}
        solutionStatement={t('gallery.seo.opt.solution', 'The Gallery provides real-world examples across multiple industries showing successful page implementations')}
      />
      <StructuredData id="gallery-schema" data={gallerySchema} />
      <div className="min-h-screen bg-background pb-20">
        {/* Header - Sticky glass effect */}
        <header className="sticky top-0 z-40 bg-background/80 backdrop-blur-2xl border-b border-border/10">
          <div className="px-5 pt-4 pb-3">
            <div className="flex items-center gap-4 mb-4">
              <Button variant="ghost" size="icon" className="h-10 w-10 rounded-xl" asChild>
                <Link href="/">
                  <ArrowLeft className="h-5 w-5" />
                </Link>
              </Button>
              <div className="flex-1">
                <h1 className="text-xl font-black flex items-center gap-2">
                  <Users className="h-5 w-5 text-primary" />
                  {t('gallery.title', 'Галерея')}
                </h1>
                <p className="text-sm text-muted-foreground">
                  {pages.length} {t('gallery.pages', 'страниц')}
                </p>
              </div>
              <LanguageSwitcher />
              <Button
                size="sm"
                className="h-10 rounded-xl font-bold"
                onClick={() => router.push('/auth')}
              >
                <Sparkles className="h-4 w-4 mr-1.5" />
                {t('gallery.create', 'Создать')}
              </Button>
            </div>

            {/* Stats row - with skeleton loading */}
            {loading ? (
              <SkeletonStats />
            ) : (
              <div className="grid grid-cols-3 gap-2 mb-4">
                <div className="p-3 rounded-xl bg-muted/50 text-center">
                  <Sparkles className="h-4 w-4 mx-auto text-primary mb-1" />
                  <p className="text-lg font-black">{pages.length}</p>
                  <p className="text-xs text-muted-foreground">{t('gallery.statsPages', 'Страниц')}</p>
                </div>
                <div className="p-3 rounded-xl bg-muted/50 text-center">
                  <Heart className="h-4 w-4 mx-auto text-red-500 mb-1" />
                  <p className="text-lg font-black">{totalLikes}</p>
                  <p className="text-xs text-muted-foreground">{t('gallery.statsLikes', 'Лайков')}</p>
                </div>
                <div className="p-3 rounded-xl bg-muted/50 text-center">
                  <Eye className="h-4 w-4 mx-auto text-emerald-500 mb-1" />
                  <p className="text-lg font-black">{totalViews}</p>
                  <p className="text-xs text-muted-foreground">{t('gallery.statsViews', 'Просмотров')}</p>
                </div>
              </div>
            )}

            {/* Tabs */}
            <div className="bg-muted/50 rounded-xl p-1 flex gap-1">
              <button
                onClick={() => setActiveTab('gallery')}
                className={cn(
                  "flex-1 h-10 rounded-lg text-sm font-bold transition-all",
                  activeTab === 'gallery'
                    ? "bg-background shadow-sm text-foreground"
                    : "text-muted-foreground"
                )}
              >
                {t('gallery.tabGallery', 'Галерея')}
              </button>
              <button
                onClick={() => setActiveTab('leaderboard')}
                className={cn(
                  "flex-1 h-10 rounded-lg text-sm font-bold transition-all",
                  activeTab === 'leaderboard'
                    ? "bg-background shadow-sm text-foreground"
                    : "text-muted-foreground"
                )}
              >
                {t('gallery.tabLeaderboard', 'Рейтинг')}
              </button>
            </div>
          </div>
        </header>

        {activeTab === 'gallery' && (
          <>
            {/* SEO intro */}
            <section className="px-5 pt-4">
              <div className="rounded-2xl border border-border/40 bg-card/60 p-5 space-y-3">
                <h2 className="text-base font-semibold">{t('gallery.seoIntro.title')}</h2>
                <p className="text-sm text-muted-foreground">{t('gallery.seoIntro.subtitle')}</p>
                <ul className="text-sm text-muted-foreground list-disc list-inside space-y-1">
                  {seoHighlights.map((item) => (
                    <li key={item}>{item}</li>
                  ))}
                </ul>
                <div className="pt-2">
                  <h3 className="text-sm font-semibold">{t('gallery.seoIntro.locationTitle')}</h3>
                  <p className="text-sm text-muted-foreground">{t('gallery.seoIntro.locationBody')}</p>
                </div>
              </div>
            </section>

            {/* Search */}
            <div className="px-5 py-3">
              <div className="relative">
                <Search className="absolute left-4 top-1/2 -translate-y-1/2 h-5 w-5 text-muted-foreground" />
                <Input
                  placeholder={t('gallery.searchPlaceholder', 'Поиск страниц...')}
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="h-11 pl-12 rounded-xl bg-muted/50 border-0 text-base"
                />
              </div>
            </div>

            {/* Niche filters - Horizontal scroll */}
            <div className="px-5 pb-3 overflow-x-auto scrollbar-hide">
              <div className="flex gap-2 min-w-max">
                <button
                  onClick={() => updateNiche(null)}
                  className={cn(
                    "h-9 px-4 rounded-full text-sm font-bold whitespace-nowrap transition-all",
                    !selectedNiche
                      ? "bg-foreground text-background"
                      : "bg-muted/60 text-muted-foreground"
                  )}
                >
                  {t('gallery.allNiches', 'Все')}
                </button>
                {NICHES.slice(0, 10).map((niche) => (
                  <button
                    key={niche}
                    onClick={() => updateNiche(niche)}
                    className={cn(
                      "h-9 px-4 rounded-full text-sm font-bold whitespace-nowrap transition-all flex items-center gap-1.5",
                      selectedNiche === niche
                        ? "bg-primary text-primary-foreground"
                        : "bg-muted/60 text-muted-foreground"
                    )}
                  >
                    <span>{NICHE_ICONS[niche]}</span>
                    {t(`niches.${niche}`, niche)}
                  </button>
                ))}
              </div>
            </div>

            {/* Featured carousel */}
            {!searchQuery && !selectedNiche && featuredPages.length > 0 && (
              <div className="px-5 pb-4">
                <h2 className="text-sm font-bold text-muted-foreground uppercase tracking-wider mb-3">
                  {t('gallery.featured', 'Популярные')}
                </h2>
                <ScrollArea className="w-full">
                  <div className="flex gap-3 pb-2">
                    {featuredPages.map((page) => (
                      <FeaturedPageCard
                        key={page.id}
                        page={page}
                        onCopy={() => handleCopyTemplate(page.slug)}
                        onView={() => router.push(`/${page.slug}`)}
                      />
                    ))}
                  </div>
                  <ScrollBar orientation="horizontal" />
                </ScrollArea>
              </div>
            )}

            {/* Pages grid */}
            <div className="px-5">
              <h2 className="text-sm font-bold text-muted-foreground uppercase tracking-wider mb-3">
                {selectedNiche
                  ? t(`niches.${selectedNiche}`, selectedNiche)
                  : t('gallery.allPages', 'Все страницы')}
                <span className="ml-2 text-xs font-normal">({filteredPages.length})</span>
              </h2>

              {loading ? (
                <SkeletonGalleryGrid />
              ) : filteredPages.length === 0 ? (
                <div className="text-center py-12">
                  <Users className="h-12 w-12 mx-auto text-muted-foreground/30 mb-4" />
                  <h3 className="font-bold mb-2">{t('gallery.noPages', 'Страниц не найдено')}</h3>
                  <p className="text-sm text-muted-foreground">
                    {t('gallery.tryAnotherFilter', 'Попробуйте другой фильтр')}
                  </p>
                </div>
              ) : (
                <div className="grid grid-cols-2 gap-3">
                  {filteredPages.map((page) => (
                    <GalleryPageCard
                      key={page.id}
                      page={page}
                      onCopy={() => handleCopyTemplate(page.slug)}
                      onView={() => router.push(`/${page.slug}`)}
                      onLike={() => likePage(page.id)}
                    />
                  ))}
                </div>
              )}
            </div>
          </>
        )}

        {activeTab === 'leaderboard' && (
          <div className="px-5 py-4 space-y-6">
            <Leaderboard />
            <TopReferrers />
          </div>
        )}
      </div>
    </>
  );
}

'use client';

import { useState } from 'react';
import { useRouter } from 'next/navigation';
import { useTranslation } from 'react-i18next';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardDescription, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { ArrowLeft, Check, Crown, Sparkles, Zap, Star, Clock, Shield, Coins, MessageCircle } from 'lucide-react';
import { LanguageSwitcher } from '@/components/translation/LanguageSwitcher';
import { usePremiumStatus } from '@/hooks/user/usePremiumStatus';
import { useTokens } from '@/hooks/user/useTokens';
import { redirectToTokenPurchase } from '@/lib/token-purchase-helper';
import { toast } from 'sonner';
import { useRobokassa } from '@/hooks/useRobokassa';
import { StaticSEOHead } from '@/components/seo/StaticSEOHead';
import { SEOMetaEnhancer } from '@/components/seo/SEOMetaEnhancer';
import { GEOTagging } from '@/components/seo/GEOTagging';
import { AISearchOptimizer } from '@/components/seo/AISearchOptimizer';
import { cn } from '@/lib/utils/utils';
type BillingPeriod = 3 | 6 | 12;

export default function Pricing() {
  const router = useRouter();
  const {
    t,
    i18n
  } = useTranslation();
  const {
    isPremium,
    tier,
    isLoading
  } = usePremiumStatus();
  const {
    balance,
    canAffordPremium,
    premiumCost,
    buyPremiumDay,
    converting
