import type { Block, FAQBlock, EventBlock, PricingBlock, SocialsBlock, TextBlock } from '@/types/page';
import { getI18nText } from '@/lib/i18n-helpers';
import { extractProfileFromBlocks, generateSourceContext } from '@/lib/seo-utils';
import { generateSectionAnchors, SECTION_LABELS } from '@/lib/seo/anchors';
import { extractEntityLinks } from '@/lib/seo/entity-linking';
import { generateAnswerBlock } from '@/lib/seo/answer-block';
import { generateKeyFacts as generateEnhancedKeyFacts } from '@/lib/seo/key-facts';
import { generateAutoFAQ, extractFAQContext, hasUserFAQ } from '@/lib/seo/auto-faq';

interface CrawlerFriendlyContentProps {
  blocks: Block[];
  slug: string;
  updatedAt?: string;
}

export function CrawlerFriendlyContent({ blocks, slug, updatedAt }: CrawlerFriendlyContentProps) {
  const { i18n } = useTranslation();
  const language = i18n.language as 'ru' | 'en' | 'kk';

  // Guard against undefined/null blocks
  const validBlocks = (blocks || []).filter((b): b is Block => b != null && typeof b === 'object' && 'type' in b);

  // Wrap all SEO processing in try-catch to prevent render crashes
  let profile: ReturnType<typeof extractProfileFromBlocks> = { type: 'Person', sameAs: [] };
  let sourceContext = '';
  let entityLinks: ReturnType<typeof extractEntityLinks> = { sameAs: [], knowsAbout: [] };
  let answerBlock: ReturnType<typeof generateAnswerBlock> = { summary: '', entityType: 'Person', services: [] };
  let keyFacts: ReturnType<typeof generateEnhancedKeyFacts> = [];
  let autoFAQItems: Array<{ question: string; answer: string }> = [];
  let faqBlock: FAQBlock | undefined;
  let eventBlocks: EventBlock[] = [];
  let pricingBlock: PricingBlock | undefined;

  try {
    profile = extractProfileFromBlocks(validBlocks, language);
    sourceContext = generateSourceContext(slug, updatedAt || new Date().toISOString());
    entityLinks = extractEntityLinks(validBlocks, language);
    answerBlock = generateAnswerBlock(validBlocks, slug, language);
    keyFacts = generateEnhancedKeyFacts(validBlocks, answerBlock, profile.name, language);
    
    const shouldGenerateAutoFAQ = !hasUserFAQ(validBlocks);
    const faqContext = extractFAQContext(validBlocks, profile.name, answerBlock.niche, answerBlock.location, language);
    autoFAQItems = shouldGenerateAutoFAQ ? generateAutoFAQ(faqContext, language, 5) : [];

    faqBlock = validBlocks.find(b => b.type === 'faq') as FAQBlock | undefined;
    eventBlocks = validBlocks.filter(b => b.type === 'event') as EventBlock[];
    pricingBlock = validBlocks.find(b => b.type === 'pricing') as PricingBlock | undefined;
  } catch (err) {
    console.warn('Crawler content processing error:', err);
  }

  // Extract links
  const linkBlocks = validBlocks.filter(b => b.type === 'link' || b.type === 'button') as any[];

  // Extract text blocks for content
  const textBlocks = validBlocks.filter(b => b.type === 'text') as TextBlock[];

  // Extract socials
  const socialsBlock = validBlocks.find(b => b.type === 'socials') as SocialsBlock | undefined;

  return (
    <noscript>
      {/* 
        This content is only visible to crawlers and users with JS disabled.
        It provides a semantic HTML fallback for the SPA content with:
        - Stable anchors (#about, #services, #faq, etc.)
        - Key facts for AI extraction
        - Proper schema.org microdata
      */}
      <article 
        className="crawler-content" 
        itemScope 
        itemType={`https://schema.org/${answerBlock.entityType}`}
      >
        {/* Main heading - H1 */}
        <header id="about">
          <h1 itemProp="name">{profile.name || `Page @${slug}`}</h1>
          {answerBlock.niche && (
            <p itemProp="jobTitle" className="role">{answerBlock.niche}</p>
          )}
          {profile.avatar && (
            <img 
              src={profile.avatar} 
              alt={profile.name || 'Profile'} 
              itemProp="image"
              width="96"
              height="96"
              loading="eager"
            />
          )}
          {/* Canonical URL */}
          <link itemProp="url" href={`https://lnkmx.my/${slug}`} />
          
          {/* sameAs links for entity linking */}
          {entityLinks.sameAs.map((url, i) => (
            <link key={i} itemProp="sameAs" href={url} />
          ))}
        </header>

        {/* Answer Block - PRIMARY for AI extraction */}
        <section id="answer" aria-label="Summary">
          <h2>{language === 'ru' ? 'О специалисте' : language === 'kk' ? 'Маман туралы' : 'About'}</h2>
          <p itemProp="description" className="answer-summary">
            {answerBlock.summary}
          </p>
        </section>

        {/* Key Facts - Atomic facts for AI citation */}
        {keyFacts.length > 0 && (
          <section id="key-facts" aria-label="Key Facts">
            <h2>{language === 'ru' ? 'Ключевые факты' : language === 'kk' ? 'Негізгі фактілер' : 'Key Facts'}</h2>
            <ul>
              {keyFacts.map((fact, i) => (
                <li key={i}>
                  <strong>{fact.label}:</strong> <span itemProp={fact.schemaProperty}>{fact.value}</span>
                </li>
              ))}
            </ul>
          </section>
        )}

        {/* Additional text content */}
        {textBlocks.length > 0 && (
          <section aria-label="Details">
            <h2>{SECTION_LABELS.about[language]}</h2>
            {textBlocks.map(block => (
              <p key={block.id}>{getI18nText(block.content, language)}</p>
            ))}
          </section>
        )}

        {/* Expertise/Skills (knowsAbout) */}
        {entityLinks.knowsAbout.length > 0 && (
          <section id="expertise" aria-label="Expertise">
            <h2>{SECTION_LABELS.expertise[language]}</h2>
            <ul>
              {entityLinks.knowsAbout.map((skill, i) => (
                <li key={i} itemProp="knowsAbout">{skill}</li>
              ))}
            </ul>
          </section>
        )}

        {/* Services/Pricing section */}
        {pricingBlock && pricingBlock.items?.length > 0 && (
          <section id="services" aria-label="Services">
            <h2>{SECTION_LABELS.services[language]}</h2>
            <ul>
              {(pricingBlock.items || []).filter(item => item && typeof item === 'object' && item.name).map(item => (
                <li 
                  key={item.id}
                  itemScope 
                  itemType="https://schema.org/Service"
                >
                  <h3 itemProp="name">{getI18nText(item.name, language)}</h3>
                  {item.description && (
                    <p itemProp="description">{getI18nText(item.description, language)}</p>
                  )}
                  <span 
                    itemProp="offers" 
                    itemScope 
                    itemType="https://schema.org/Offer"
                  >
                    <span itemProp="price">{item.price}</span>
                    <meta itemProp="priceCurrency" content={item.currency || pricingBlock.currency || 'KZT'} />
                  </span>
                </li>
              ))}
            </ul>
          </section>
        )}

        {/* Events section */}
        {eventBlocks.length > 0 && (
          <section id="events" aria-label="Events">
            <h2>{SECTION_LABELS.events[language]}</h2>
            {eventBlocks.map(event => (
              <article 
                key={event.id}
                itemScope 
                itemType="https://schema.org/Event"
              >
                <h3 itemProp="name">{getI18nText(event.title, language)}</h3>
                {event.description && (
                  <p itemProp="description">{getI18nText(event.description, language)}</p>
                )}
                {event.startAt && (
                  <time itemProp="startDate" dateTime={event.startAt}>
                    {new Date(event.startAt).toLocaleDateString(language)}
                  </time>
                )}
                {event.locationValue && (
                  <address itemProp="location">{event.locationValue}</address>
                )}
              </article>
            ))}
          </section>
        )}

        {/* FAQ section - User-created or Auto-generated */}
        {(faqBlock?.items?.length || autoFAQItems.length > 0) && (
          <section 
            id="faq"
            aria-label="FAQ"
            itemScope 
            itemType="https://schema.org/FAQPage"
          >
            <h2>{SECTION_LABELS.faq[language]}</h2>
            <dl>
              {/* User-created FAQ items */}
              {faqBlock?.items?.map(item => (
                <div 
                  key={item.id}
                  itemScope 
                  itemType="https://schema.org/Question"
                  itemProp="mainEntity"
                >
                  <dt itemProp="name">{getI18nText(item.question, language)}</dt>
                  <dd 
                    itemScope 
                    itemType="https://schema.org/Answer"
                    itemProp="acceptedAnswer"
                  >
                    <span itemProp="text">{getI18nText(item.answer, language)}</span>
                  </dd>
                </div>
              ))}
              {/* Auto-generated FAQ items (if user has no FAQ) */}
              {autoFAQItems.map((item, i) => (
                <div 
                  key={`auto-faq-${i}`}
                  itemScope 
                  itemType="https://schema.org/Question"
                  itemProp="mainEntity"
                >
                  <dt itemProp="name">{item.question}</dt>
                  <dd 
                    itemScope 
                    itemType="https://schema.org/Answer"
                    itemProp="acceptedAnswer"
                  >
                    <span itemProp="text">{item.answer}</span>
                  </dd>
                </div>
              ))}
            </dl>
          </section>
        )}

        {/* Links section */}
        {linkBlocks.length > 0 && (
          <section id="contacts" aria-label="Links">
            <h2>{SECTION_LABELS.contacts[language]}</h2>
            <ul>
              {linkBlocks.map(block => (
                <li key={block.id}>
                  <a href={block.url} rel="noopener noreferrer">
                    {getI18nText(block.title, language)}
                  </a>
                </li>
              ))}
            </ul>
          </section>
        )}

        {/* Social Links section */}
        {socialsBlock?.platforms && socialsBlock.platforms.length > 0 && (
          <section aria-label="Social Media">
            <h2>{language === 'ru' ? 'Соцсети' : language === 'kk' ? 'Әлеуметтік желілер' : 'Social Media'}</h2>
            <ul>
              {(socialsBlock.platforms || []).filter(p => p && p.url).map((platform, i) => (
                <li key={i}>
                  <a href={platform.url} rel="noopener noreferrer me" itemProp="sameAs">
                    {platform.name || platform.url}
                  </a>
                </li>
              ))}
            </ul>
          </section>
        )}

        {/* Source context footer */}
        <footer>
          <small>{sourceContext}</small>
          <p>
            <a href={`https://lnkmx.my/${slug}`} itemProp="url">
              lnkmx.my/{slug}
            </a>
          </p>
          <p>
            <small>
              {language === 'ru' 
                ? 'Эта страница создана на платформе lnkmx.my'
                : language === 'kk'
                ? 'Бұл бет lnkmx.my платформасында жасалған'
                : 'This page is created on lnkmx.my platform'}
            </small>
          </p>
        </footer>
      </article>
    </noscript>
  );
}

export default CrawlerFriendlyContent;

/**
 * EnhancedSEOHead - Comprehensive Auto-SEO for User Pages
 * 
 * AEO/GEO Features:
 * - Answer Block for AI extraction
 * - Auto meta tags generation
 * - Schema.org JSON-LD (Person/Organization, FAQ, Event, Service, HowTo)
 * - Quality gate for indexation
 * - Source context for AI citability
 * - Version tracking for stable URLs
 */

import { useEffect, useMemo } from 'react';
import { useTranslation } from 'react-i18next';
import type { PageData } from '@/types/page';
import {
  evaluateQualityGate,
  extractProfileFromBlocks,
  generatePageMeta,
} from '@/lib/seo-utils';
import { extractEntityLinks } from '@/lib/seo/entity-linking';
import { generateSectionAnchors } from '@/lib/seo/anchors';
import { generateAnswerBlock } from '@/lib/seo/answer-block';
import { generateEnhancedKeyFacts } from '@/lib/seo';
import { generateGEOSchemas, generateJsonLdGraph } from '@/lib/seo/geo-schemas';
import { generateAutoFAQ, extractFAQContext, hasUserFAQ } from '@/lib/seo/auto-faq';

interface EnhancedSEOHeadProps {
  pageData: PageData;
  pageUrl: string;
  updatedAt?: string;
  isNewAccount?: boolean;
}

// Helper to set/update meta tag
const setMetaTag = (name: string, content: string, property = false) => {
  const attr = property ? 'property' : 'name';
  let meta = document.querySelector(`meta[${attr}="${name}"]`) as HTMLMetaElement;
  if (!meta) {
    meta = document.createElement('meta');
    meta.setAttribute(attr, name);
    document.head.appendChild(meta);
  }
  meta.content = content;
};

// Helper to set/update link tag
const setLinkTag = (rel: string, href: string, hreflang?: string) => {
  const selector = hreflang
    ? `link[rel="${rel}"][hreflang="${hreflang}"]`
    : `link[rel="${rel}"]:not([hreflang])`;
  let link = document.querySelector(selector) as HTMLLinkElement;
  if (!link) {
    link = document.createElement('link');
    link.rel = rel;
    if (hreflang) link.hreflang = hreflang;
    document.head.appendChild(link);
  }
  link.href = href;
};

// Helper to add JSON-LD schema
const addJsonLd = (id: string, data: object | string) => {
  let script = document.querySelector(`script#${id}`) as HTMLScriptElement;
  if (!script) {
    script = document.createElement('script');
    script.type = 'application/ld+json';
    script.id = id;
    document.head.appendChild(script);
  }
  script.textContent = typeof data === 'string' ? data : JSON.stringify(data);
};

export function EnhancedSEOHead({ 
  pageData, 
  pageUrl,
  updatedAt,
  isNewAccount = false,
}: EnhancedSEOHeadProps) {
  const { i18n } = useTranslation();
  const language = i18n.language as 'ru' | 'en' | 'kk';
  const slug = pageData.slug || '';

  // Memoize all SEO computations - wrapped in try-catch for safety
  const seoData = useMemo(() => {
    try {
      const safeBlocks = (pageData.blocks || []).filter((b): b is NonNullable<typeof b> => b != null && typeof b === 'object' && 'type' in b);
      const profile = extractProfileFromBlocks(safeBlocks, language);
      const qualityGate = evaluateQualityGate(
        safeBlocks,
        profile.name,
        profile.bio,
        isNewAccount
      );
      const meta = generatePageMeta(profile, safeBlocks, slug, qualityGate, language);
      
      // Generate Answer Block for AEO
      const answerBlock = generateAnswerBlock(safeBlocks, slug, language);
      
      // Generate enhanced Key Facts
      const keyFacts = generateEnhancedKeyFacts(safeBlocks, answerBlock, profile.name, language);
      
      // Generate GEO Schemas with combined graph
      const geoSchemas = generateGEOSchemas(safeBlocks, {
        slug,
        name: profile.name || '',
        bio: profile.bio,
        avatar: profile.avatar,
        answerBlock,
        sameAs: profile.sameAs,
        language,
      });
      
      // Generate auto FAQ if needed
      const shouldGenerateAutoFAQ = !hasUserFAQ(safeBlocks);
      const faqContext = extractFAQContext(safeBlocks, profile.name, answerBlock.niche, answerBlock.location, language);
      const autoFAQ = shouldGenerateAutoFAQ ? generateAutoFAQ(faqContext, language, 5) : [];
      
      // Entity links for structured data
      const entityLinks = extractEntityLinks(safeBlocks, language);

      return {
        profile,
        qualityGate,
        meta,
        answerBlock,
        keyFacts,
        geoSchemas,
        autoFAQ,
        entityLinks,
      };
    } catch (err) {
      console.warn('SEO computation error, using fallback:', err);
      const fallbackProfile = { type: 'Person' as const, sameAs: [] };
      return {
        profile: fallbackProfile as ReturnType<typeof extractProfileFromBlocks>,
        qualityGate: { score: 0, shouldIndex: false, reasons: [] },
        meta: { title: slug || 'Profile', description: '', canonical: pageUrl, robots: 'noindex', ogImage: '' },
        answerBlock: { summary: '', entityType: 'Person' as const, services: [] },
        keyFacts: [],
        geoSchemas: { mainEntity: {}, webPage: {}, breadcrumb: {}, graph: [] },
        autoFAQ: [],
        entityLinks: { sameAs: [], knowsAbout: [] },
      };
    }
  }, [pageData.blocks, slug, language, updatedAt, isNewAccount, pageUrl]);

  useEffect(() => {
    const { meta, geoSchemas, qualityGate, answerBlock } = seoData;

    // Set document title
    document.title = meta.title;

    // Set lang attribute
    document.documentElement.lang = language;

    // Basic meta tags
    setMetaTag('description', meta.description);
    setMetaTag('robots', meta.robots);
    setMetaTag('googlebot', meta.robots);

    // Open Graph tags
    setMetaTag('og:type', 'profile', true);
    setMetaTag('og:title', meta.title, true);
    setMetaTag('og:description', meta.description, true);
    setMetaTag('og:url', meta.canonical, true);
    setMetaTag('og:site_name', 'lnkmx', true);
    
    if (meta.ogImage) {
      setMetaTag('og:image', meta.ogImage, true);
      setMetaTag('og:image:alt', `${seoData.profile.name || 'User'} profile`, true);
    }

    // Twitter Card tags
    setMetaTag('twitter:card', 'summary_large_image');
    setMetaTag('twitter:title', meta.title);
    setMetaTag('twitter:description', meta.description);
    if (meta.ogImage) {
      setMetaTag('twitter:image', meta.ogImage);
    }
    setMetaTag('twitter:site', '@lnkmx_app');

    // Canonical URL
    setLinkTag('canonical', meta.canonical);

    // Hreflang tags
    setLinkTag('alternate', `${meta.canonical}?lang=ru`, 'ru');
    setLinkTag('alternate', `${meta.canonical}?lang=en`, 'en');
    setLinkTag('alternate', `${meta.canonical}?lang=kk`, 'kk');
    setLinkTag('alternate', meta.canonical, 'x-default');

    // Add combined JSON-LD graph (all schemas in one)
    addJsonLd('schema-graph', generateJsonLdGraph(geoSchemas));

    // Page quality indicator (for internal use)
    setMetaTag('page-quality-score', String(qualityGate.score));
    
    // Answer block summary for AI crawlers
    setMetaTag('ai-summary', answerBlock.summary);

    // Cleanup on unmount
    return () => {
      document.title = 'lnkmx - AI Bio Page Builder';
      
      // Remove page-specific tags
      const tagsToRemove = [
        'meta[property="og:type"]',
        'meta[property="og:url"]',
        'meta[property="og:site_name"]',
        'meta[property="og:image:alt"]',
        'meta[name="page-quality-score"]',
        'meta[name="ai-summary"]',
        'link[rel="canonical"]',
        'link[rel="alternate"]',
        'script#schema-graph',
      ];

      tagsToRemove.forEach(selector => {
        const elements = document.querySelectorAll(selector);
        elements.forEach(el => el.remove());
      });
    };
  }, [seoData, language]);

  return null;
}

export default EnhancedSEOHead;

/**
 * LinkedAccountsSection - Manage linked OAuth accounts
 * Allows users to link/unlink Google and Apple accounts
 */
import { useState, useEffect } from 'react';
import { useTranslation } from 'react-i18next';
import { Card } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { toast } from 'sonner';
import { Mail, Link2, Unlink, Loader2, CalendarSync } from 'lucide-react';
import { supabase } from '@/platform/supabase/client';


import { cn } from '@/lib/utils/utils';

interface LinkedAccount {
  provider: 'email' | 'google' | 'apple';
  email?: string;
  linked: boolean;
}

interface LinkedAccountsSectionProps {
  userEmail?: string;
}

export function LinkedAccountsSection({ userEmail }: LinkedAccountsSectionProps) {
  const { t } = useTranslation();
  const [linkedAccounts, setLinkedAccounts] = useState<LinkedAccount[]>([]);
  const [isLoading, setIsLoading] = useState(true);
  const [linkingProvider, setLinkingProvider] = useState<string | null>(null);

  // Google Calendar Integration State
  const [gcalIsLoading, setGcalIsLoading] = useState(true);
  const [gcalIsConnected, setGcalIsConnected] = useState(false);
  const [gcalLastSync, setGcalLastSync] = useState<string | null>(null);

  useEffect(() => {
    loadLinkedAccounts();
    checkGcalIntegration();
  }, []);

  useEffect(() => {
    const searchParams = new URL(window.location.href).searchParams;
    const authError = searchParams.get('auth_error');
    const authErrorDescription = searchParams.get('auth_error_description');

    if (authError) {
      toast.error(t('settings.linkedAccounts.linkFailedReason', 'Failed to link account: {{reason}}', {
        reason: authErrorDescription || authError
      }));
      // Clean up URL
      const newUrl = new URL(window.location.href);
      newUrl.searchParams.delete('auth_error');
      newUrl.searchParams.delete('auth_error_description');
      window.history.replaceState(null, '', newUrl.toString());
    }
  }, [t]);

  const loadLinkedAccounts = async () => {
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      const identities = user.identities || [];

      const accounts: LinkedAccount[] = [
        {
          provider: 'email',
          email: user.email,
          linked: identities.some(i => i.provider === 'email') || !!user.email,
        },
        {
          provider: 'google',
          email: identities.find(i => i.provider === 'google')?.identity_data?.email,
          linked: identities.some(i => i.provider === 'google'),
        },
        {
          provider: 'apple',
          email: identities.find(i => i.provider === 'apple')?.identity_data?.email,
          linked: identities.some(i => i.provider === 'apple'),
        },
      ];

      setLinkedAccounts(accounts);
    } catch (error) {
      console.error('Failed to load linked accounts:', error);
    } finally {
      setIsLoading(false);
    }
  };

  const handleLinkAccount = async (provider: 'google' | 'apple') => {
    setLinkingProvider(provider);
    try {
      const { data, error } = await supabase.auth.linkIdentity({
        provider: provider,
        options: {
          redirectTo: `${window.location.origin}/auth/callback`,
          ...(provider === 'google' ? {
            queryParams: {
              access_type: 'offline',
              prompt: 'consent',
            },
          } : {}),
        },
      });

      if (error) {
        console.error('Link identity error:', error);
        toast.error(error.message || t('settings.linkedAccounts.linkFailed', 'Failed to link account'));
        setLinkingProvider(null);
        return;
      }

      // If successful, the browser will redirect to the OAuth provider
    } catch (error) {
      console.error('Link identity exception:', error);
      toast.error(t('settings.linkedAccounts.linkFailed', 'Failed to link account'));
      setLinkingProvider(null);
    }
  };

  const handleUnlinkAccount = async (provider: 'google' | 'apple') => {
    const linkedCount = linkedAccounts.filter(a => a.linked).length;
    if (linkedCount <= 1) {
      toast.error(t('settings.linkedAccounts.cannotUnlinkLast', 'You must have at least one login method'));
      return;
    }

    setLinkingProvider(provider);
    try {
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      const identity = user.identities?.find(i => i.provider === provider);
      if (!identity) return;

      const { error } = await supabase.auth.unlinkIdentity(identity);

      if (error) {
        toast.error(error.message || t('settings.linkedAccounts.unlinkFailed', 'Failed to unlink account'));
      } else {
        toast.success(t('settings.linkedAccounts.unlinkSuccess', 'Account unlinked'));
        await loadLinkedAccounts();
      }
    } catch (error) {
      toast.error(t('settings.linkedAccounts.unlinkFailed', 'Failed to unlink account'));
    } finally {
      setLinkingProvider(null);
    }
  };

  // Google Calendar Integration Functions
  const checkGcalIntegration = async () => {
    try {
      setGcalIsLoading(true);
      const { data: { user } } = await supabase.auth.getUser();
      if (!user) return;

      const { data, error } = await supabase
        .from('user_integrations_status' as any)
        .select('is_connected, updated_at')
        .eq('user_id', user.id)
        .eq('provider', 'google_calendar')
        .maybeSingle() as any;

      if (error && error.code !== 'PGRST116') {
        throw error;
      }

      setGcalIsConnected(!!data?.is_connected);
      if (data?.updated_at) {
        setGcalLastSync(data.updated_at);
      }
    } catch (error) {
      console.error('Error checking gcal integration:', error);
    } finally {
      setGcalIsLoading(false);
    }
  };

  const handleConnectGcal = async () => {
    setLinkingProvider('google_calendar');
    try {
      const { data: { session } } = await supabase.auth.getSession();
      if (!session) throw new Error('No active session');

      const redirectUri = `${window.location.origin}/dashboard/settings`;

      // Google OAuth URL (Requires setup in Google Cloud Console)
      // For now, we simulate the flow pointing to our Edge Function or a redirect
      toast.info(t('settings.integrations.gcalRedirecting', 'Перенаправление в Google...'));

      // In a real implementation we might redirect directly to Google OAuth Consent here
      // and pass state to our Edge Function.

      // const GOOGLE_CLIENT_ID = process.env.VITE_GOOGLE_CLIENT_ID;
      // const url = `https://accounts.google.com/o/oauth2/v2/auth?client_id=${GOOGLE_CLIENT_ID}&redirect_uri=${redirectUri}&response_type=code&scope=https://www.googleapis.com/auth/calendar.events&access_type=offline&prompt=consent`;
      // window.location.href = url;

      // Simulate success for now as we don't have the Google Client ID configured
      setTimeout(async () => {
        toast.success(t('settings.integrations.gcalConnected', 'Успешно подключено (Режим MOCK)'));
        setGcalIsConnected(true);
        setGcalLastSync(new Date().toISOString());
        setLinkingProvider(null);
      }, 1500);

    } catch (err) {
      console.error(err);
      toast.error(t('settings.integrations.gcalFailed', 'Ошибка подключения Google Calendar'));
      setLinkingProvider(null);
    }
  };

  const handleDisconnectGcal = async () => {
    // In production we would delete the row from user_integrations
    toast.success(t('settings.integrations.gcalDisconnected', 'Google Calendar отключен'));
    setGcalIsConnected(false);
    setGcalLastSync(null);
  };

  const getProviderIcon = (provider: string) => {
    switch (provider) {
      case 'google':
        return (
          <svg className="h-5 w-5" viewBox="0 0 24 24">
            <path fill="#4285F4" d="M22.56 12.25c0-.78-.07-1.53-.2-2.25H12v4.26h5.92c-.26 1.37-1.04 2.53-2.21 3.31v2.77h3.57c2.08-1.92 3.28-4.74 3.28-8.09z" />
            <path fill="#34A853" d="M12 23c2.97 0 5.46-.98 7.28-2.66l-3.57-2.77c-.98.66-2.23 1.06-3.71 1.06-2.86 0-5.29-1.93-6.16-4.53H2.18v2.84C3.99 20.53 7.7 23 12 23z" />
            <path fill="#FBBC05" d="M5.84 14.09c-.22-.66-.35-1.36-.35-2.09s.13-1.43.35-2.09V7.07H2.18C1.43 8.55 1 10.22 1 12s.43 3.45 1.18 4.93l2.85-2.22.81-.62z" />
            <path fill="#EA4335" d="M12 5.38c1.62 0 3.06.56 4.21 1.64l3.15-3.15C17.45 2.09 14.97 1 12 1 7.7 1 3.99 3.47 2.18 7.07l3.66 2.84c.87-2.6 3.3-4.53 6.16-4.53z" />
          </svg>
        );
      case 'apple':
        return (
          <svg className="h-5 w-5" viewBox="0 0 24 24" fill="currentColor">
            <path d="M17.05 20.28c-.98.95-2.05.8-3.08.35-1.09-.46-2.09-.48-3.24 0-1.44.62-2.2.44-3.06-.35C2.79 15.25 3.51 7.59 9.05 7.31c1.35.07 2.29.74 3.08.8 1.18-.24 2.31-.93 3.57-.84 1.51.12 2.65.72 3.4 1.8-3.12 1.87-2.38 5.98.48 7.13-.57 1.5-1.31 2.99-2.54 4.09l.01-.01zM12.03 7.25c-.15-2.23 1.66-4.07 3.74-4.25.29 2.58-2.34 4.5-3.74 4.25z" />
          </svg>
        );
      default:
        return <Mail className="h-5 w-5" />;
    }
  };

  const getProviderName = (provider: string) => {
    switch (provider) {
      case 'google':
        return 'Google';
      case 'apple':
        return 'Apple';
      default:
        return t('settings.linkedAccounts.email', 'Email');
    }
  };

  const getProviderBgColor = (provider: string) => {
    switch (provider) {
      case 'google':
        return 'bg-destructive/15';
      case 'apple':
        return 'bg-muted';
      default:
        return 'bg-primary/15';
    }
  };

  const getProviderIconColor = (provider: string) => {
    switch (provider) {
      case 'google':
        return 'text-destructive';
      case 'apple':
        return 'text-foreground';
      default:
        return 'text-primary';
    }
  };

  if (isLoading) {
    return (
      <Card className="p-6">
        <div className="flex items-center justify-center">
          <Loader2 className="h-6 w-6 animate-spin text-muted-foreground" />
        </div>
      </Card>
    );
  }

  return (
    <div className="space-y-2">
      <h3 className="text-sm font-bold text-muted-foreground uppercase tracking-wider px-1">
        {t('settings.linkedAccounts.title', 'Login Methods')}
      </h3>
      <Card className="divide-y divide-border/50 overflow-hidden">
        {linkedAccounts.map((account) => (
          <div key={account.provider} className="flex items-center gap-4 p-4">
            <div className={cn(
              "h-11 w-11 rounded-2xl flex items-center justify-center shrink-0",
              getProviderBgColor(account.provider)
            )}>
              <div className={getProviderIconColor(account.provider)}>
                {getProviderIcon(account.provider)}
              </div>
            </div>
            <div className="flex-1 min-w-0">
              <div className="flex items-center gap-2">
                <span className="font-medium">{getProviderName(account.provider)}</span>
                {account.linked && (
                  <Badge variant="outline" className="text-xs bg-primary/10 text-primary border-primary/30">
                    {t('settings.linkedAccounts.connected', 'Connected')}
                  </Badge>
                )}
              </div>
              {account.email && (
                <p className="text-sm text-muted-foreground truncate">{account.email}</p>
