              </>
            ) : (
              <>
                <Link2 className="h-4 w-4 mr-1" />
                {t('settings.linkedAccounts.link', 'Link')}
              </>
            )}
          </Button>
        </div>
      </Card>
    </div>
  );
}

import { useState } from 'react';
import { useTranslation } from 'react-i18next';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Textarea } from '@/components/ui/textarea';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Badge } from '@/components/ui/badge';
import {
  Dialog,
  DialogContent,
  DialogHeader,
  DialogTitle,
  DialogDescription,
} from '@/components/ui/dialog';
import { Gift, Crown, Sparkles, Send, Heart } from 'lucide-react';
import { sendPremiumGift } from '@/services/social';
import { toast } from 'sonner';
import { cn } from '@/lib/utils/utils';

interface GiftPremiumDialogProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  recipient: {
    id: string;
    username: string | null;
    display_name: string | null;
    avatar_url: string | null;
  };
}

export function GiftPremiumDialog({ open, onOpenChange, recipient }: GiftPremiumDialogProps) {
  const { t } = useTranslation();
  const [selectedDays, setSelectedDays] = useState(7);
  const [message, setMessage] = useState('');
  const [sending, setSending] = useState(false);

  const GIFT_OPTIONS = [
    { days: 3, label: t('gift.days3', '3 дня'), popular: false },
    { days: 7, label: t('gift.week1', '1 неделя'), popular: true },
    { days: 14, label: t('gift.weeks2', '2 недели'), popular: false },
    { days: 30, label: t('gift.month1', '1 месяц'), popular: false },
  ];

  const handleSend = async () => {
    setSending(true);
    try {
      const result = await sendPremiumGift(recipient.id, selectedDays, message);
      if (result.success) {
        toast.success(t('gift.sent', 'Подарок отправлен!'), {
          description: `${recipient.display_name || recipient.username} ${t('gift.sentDesc', 'получит дней Premium')}: +${selectedDays}`
        });
        onOpenChange(false);
        setMessage('');
        setSelectedDays(7);
      } else {
        toast.error(t('gift.sendError', 'Не удалось отправить подарок'));
      }
    } finally {
      setSending(false);
    }
  };

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <DialogContent className="sm:max-w-md">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2">
            <Gift className="h-5 w-5 text-primary" />
            {t('gift.title', 'Подарить Premium')}
          </DialogTitle>
          <DialogDescription>
            {t('gift.description', 'Порадуйте друга подарком Premium-подписки')}
          </DialogDescription>
        </DialogHeader>

        <div className="space-y-6 py-4">
          {/* Recipient */}
          <div className="flex items-center gap-3 p-3 rounded-xl bg-gradient-to-r from-primary/10 to-purple-500/10 border border-primary/20">
            <Avatar className="h-12 w-12 rounded-xl">
              <AvatarImage src={recipient.avatar_url || undefined} />
              <AvatarFallback className="rounded-xl bg-primary/10 text-primary">
                {(recipient.display_name || recipient.username || 'U')[0].toUpperCase()}
              </AvatarFallback>
            </Avatar>
            <div className="flex-1">
              <p className="font-semibold">
                {recipient.display_name || recipient.username || t('friends.user', 'Пользователь')}
              </p>
              {recipient.username && (
                <p className="text-sm text-muted-foreground">@{recipient.username}</p>
              )}
            </div>
            <Heart className="h-5 w-5 text-pink-500" />
          </div>

          <div className="space-y-2">
            <label className="text-sm font-medium">{t('gift.duration', 'Длительность подписки')}</label>
            <div className="grid grid-cols-2 gap-2">
              {GIFT_OPTIONS.map((option) => (
                <button
                  key={option.days}
                  onClick={() => setSelectedDays(option.days)}
                  className={cn(
                    "relative flex flex-col items-center gap-1 p-3 rounded-xl border-2 transition-all",
                    selectedDays === option.days
                      ? "border-primary bg-primary/10"
                      : "border-border hover:border-primary/50"
                  )}
                >
                  {option.popular && (
                    <Badge className="absolute -top-2 -right-2 text-[10px] bg-gradient-to-r from-amber-500 to-orange-500">
                      <Sparkles className="h-3 w-3 mr-1" />
                      {t('gift.popular', 'Популярно')}
                    </Badge>
                  )}
                  <Crown className={cn(
                    "h-5 w-5",
                    selectedDays === option.days ? "text-primary" : "text-muted-foreground"
                  )} />
                  <span className="font-semibold">{option.label}</span>
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-2">
            <label className="text-sm font-medium">{t('gift.message', 'Сообщение (необязательно)')}</label>
            <Textarea
              value={message}
              onChange={(e) => setMessage(e.target.value)}
              placeholder={t('gift.messagePlaceholder', 'Напишите тёплые слова...')}
              className="min-h-[80px] resize-none rounded-xl"
              maxLength={200}
            />
            <p className="text-xs text-muted-foreground text-right">
              {message.length}/200
            </p>
          </div>

          <Button
            onClick={handleSend}
            disabled={sending}
            className="w-full h-12 rounded-xl gap-2 bg-gradient-to-r from-primary to-purple-500 hover:opacity-90"
          >
            {sending ? (
              <div className="h-5 w-5 animate-spin rounded-full border-2 border-white border-t-transparent" />
            ) : (
              <>
                <Send className="h-5 w-5" />
                {t('gift.send', 'Отправить подарок')}
              </>
            )}
          </Button>
        </div>
      </DialogContent>
    </Dialog>
  );
}

import { useTranslation } from 'react-i18next';
import { Flame, Trophy, Gift, Calendar, TrendingUp, X } from 'lucide-react';
import { Card, CardContent } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Progress } from '@/components/ui/progress';
import { Badge } from '@/components/ui/badge';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogDescription } from '@/components/ui/dialog';
import { useStreak } from '@/hooks/user/useStreak';
import { getNextMilestone, STREAK_MILESTONES } from '@/services/streak';

interface StreakDisplayProps {
  userId: string | undefined;
  compact?: boolean;
}

export function StreakDisplay({ userId, compact = false }: StreakDisplayProps) {
  const { t } = useTranslation();
  const { streakData, loading, milestoneReached, dismissMilestone } = useStreak(userId);

  if (loading || !streakData) {
    return null;
  }

  const nextMilestone = getNextMilestone(streakData.currentStreak);
  const progress = nextMilestone
    ? (streakData.currentStreak / nextMilestone.days) * 100
    : 100;

  if (compact) {
    return (
      <div className="flex items-center gap-2 px-3 py-1.5 rounded-full bg-gradient-to-r from-orange-500/10 to-red-500/10 border border-orange-500/20">
        <Flame className="h-4 w-4 text-orange-500" />
        <span className="text-sm font-bold text-orange-500">{streakData.currentStreak}</span>
      </div>
    );
  }

  return (
    <>
      <Card className="bg-gradient-to-br from-orange-500/10 via-red-500/5 to-amber-500/10 backdrop-blur-xl border-orange-500/20">
        <CardContent className="p-4">
          <div className="flex items-start justify-between mb-3">
            <div className="flex items-center gap-2">
              <div className="p-2 rounded-xl bg-gradient-to-br from-orange-500 to-red-500 shadow-lg shadow-orange-500/25">
                <Flame className="h-5 w-5 text-white" />
              </div>
              <div>
                <h3 className="font-semibold text-sm">{t('streak.title', 'Daily Streak')}</h3>
                <p className="text-xs text-muted-foreground">{t('streak.keepGoing', 'Keep it going!')}</p>
              </div>
            </div>
            <div className="text-right">
              <div className="text-2xl font-bold text-orange-500">{streakData.currentStreak}</div>
              <div className="text-xs text-muted-foreground">{t('streak.days', 'days')}</div>
            </div>
          </div>

          {/* Progress to next milestone */}
          {nextMilestone && (
            <div className="space-y-2">
              <div className="flex justify-between text-xs">
                <span className="text-muted-foreground">{t('streak.nextMilestone', 'Next milestone')}</span>
                <span className="font-medium">
                  {nextMilestone.days} {t('streak.days', 'days')}
                  <Badge variant="secondary" className="ml-1.5 text-[10px] px-1.5 py-0">
                    +{nextMilestone.bonus} {t('streak.bonusDays', 'bonus days')}
                  </Badge>
                </span>
              </div>
              <Progress value={progress} className="h-2 bg-orange-500/20" />
            </div>
          )}

          {/* Stats */}
          <div className="flex justify-between mt-4 pt-3 border-t border-border/30">
            <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
              <Trophy className="h-3.5 w-3.5 text-amber-500" />
              <span>{t('streak.best', 'Best')}: {streakData.longestStreak}</span>
            </div>
            <div className="flex items-center gap-1.5 text-xs text-muted-foreground">
              <Gift className="h-3.5 w-3.5 text-green-500" />
              <span>{t('streak.earned', 'Earned')}: +{streakData.bonusDaysEarned} {t('streak.days', 'days')}</span>
            </div>
          </div>
        </CardContent>
      </Card>

      {/* Milestone Dialog */}
      <Dialog open={!!milestoneReached} onOpenChange={() => dismissMilestone()}>
        <DialogContent className="sm:max-w-md text-center">
          <DialogHeader>
            <DialogTitle className="text-center text-2xl">🎉 {t('streak.milestoneReached', 'Milestone Reached!')}</DialogTitle>
            <DialogDescription className="sr-only">
              {t('streak.milestoneDescription', 'Congratulations on reaching a new streak milestone!')}
            </DialogDescription>
          </DialogHeader>
          <div className="py-6 space-y-4">
            <div className="relative mx-auto w-24 h-24 rounded-full bg-gradient-to-br from-orange-500 to-red-500 flex items-center justify-center shadow-2xl shadow-orange-500/50 animate-bounce">
              <Flame className="h-12 w-12 text-white" />
            </div>
            <div className="text-4xl font-bold text-orange-500">
              {milestoneReached?.currentStreak} {t('streak.days', 'days')}
            </div>
            <p className="text-muted-foreground">
              {t('streak.bonusEarned', "You've earned")} <span className="font-bold text-green-500">+{milestoneReached?.bonusDays}</span> {t('streak.bonusTrialDays', 'bonus trial days!')}
            </p>
          </div>
          <Button onClick={dismissMilestone} className="w-full">
            {t('streak.awesome', 'Awesome!')}
          </Button>
        </DialogContent>
      </Dialog>
    </>
  );
}

export function StreakMilestones() {
  const { t } = useTranslation();

  return (
    <div className="space-y-2">
      <h4 className="text-sm font-medium flex items-center gap-2">
        <TrendingUp className="h-4 w-4 text-primary" />
        {t('streak.milestones', 'Streak Milestones')}
      </h4>
      <div className="grid grid-cols-5 gap-2">
        {STREAK_MILESTONES.map((milestone) => (
          <div
            key={milestone.days}
            className="text-center p-2 rounded-lg bg-background/50 border border-border/30"
          >
            <div className="text-sm font-bold">{milestone.days}</div>
            <div className="text-[10px] text-muted-foreground">{t('streak.days', 'days')}</div>
            <Badge variant="secondary" className="mt-1 text-[9px] px-1">
              +{milestone.bonus}
            </Badge>
          </div>
        ))}
      </div>
    </div>
  );
}

import { useState, useEffect, memo } from 'react';
import { useTranslation } from 'react-i18next';
import { useAuth } from '@/hooks/user/useAuth';
import { supabase } from '@/platform/supabase/client';
import { toast } from 'sonner';
import {
  Sheet,
  SheetContent,
  SheetHeader,
  SheetTitle,
} from '@/components/ui/sheet';
import { Button } from '@/components/ui/button';
import { Card } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs';
import { ScrollArea } from '@/components/ui/scroll-area';
import {
  Loader2,
  Package,
  ShoppingBag,
  Trash2,
  Download,
  DollarSign,
  Heart,
  Globe,
  Lock,
  Layers,
  Pencil,
} from 'lucide-react';
import type { Block } from '@/types/page';
import { TemplatePreviewCard } from './TemplatePreviewCard';
import { EditTemplateDialog } from './EditTemplateDialog';
import { getTemplateCategoryLabel } from '@/lib/templateCategories';

interface UserTemplate {
  id: string;
  name: string;
  description: string | null;
  category: string;
  preview_url: string | null;
  blocks: Block[];
  is_public: boolean;
  is_for_sale: boolean;
  price: number | null;
  currency: string | null;
  downloads_count: number;
  likes_count: number;
  created_at: string;
}

interface PurchasedTemplate {
  id: string;
  template_id: string;
  purchased_at: string;
  price: number;
  template: UserTemplate;
}

interface MyTemplatesPanelProps {
  open: boolean;
  onOpenChange: (open: boolean) => void;
  onApplyTemplate: (blocks: Block[]) => void;
  currentBlocks?: Block[];
}

export const MyTemplatesPanel = memo(function MyTemplatesPanel({
  open,
  onOpenChange,
  onApplyTemplate,
  currentBlocks,
}: MyTemplatesPanelProps) {
  const { t } = useTranslation();
  const { user } = useAuth();
  const [activeTab, setActiveTab] = useState('my');
  const [myTemplates, setMyTemplates] = useState<UserTemplate[]>([]);
  const [purchasedTemplates, setPurchasedTemplates] = useState<PurchasedTemplate[]>([]);
  const [loading, setLoading] = useState(true);
  const [deleting, setDeleting] = useState<string | null>(null);
  const [editingTemplate, setEditingTemplate] = useState<UserTemplate | null>(null);

  useEffect(() => {
    if (open && user) {
      loadTemplates();
    }
  }, [open, user]);

  const loadTemplates = async () => {
    if (!user) return;
    
    setLoading(true);
    try {
      // Load my templates
      const { data: myData, error: myError } = await supabase
        .from('user_templates')
        .select('*')
        .eq('user_id', user.id)
        .order('created_at', { ascending: false });

      if (myError) throw myError;
      setMyTemplates((myData || []).map(t => ({
        ...t,
        blocks: (t.blocks as unknown as Block[]) || [],
      })));

      // Load purchased templates
      const { data: purchasedData, error: purchasedError } = await supabase
        .from('template_purchases')
        .select(`
          id,
          template_id,
          purchased_at,
          price,
          user_templates!template_purchases_template_id_fkey (
            id,
            name,
            description,
            category,
            preview_url,
            blocks,
            is_public,
            is_for_sale,
            price,
            currency,
            downloads_count,
            likes_count,
            created_at
          )
        `)
        .eq('buyer_id', user.id)
        .order('purchased_at', { ascending: false });

      if (purchasedError) throw purchasedError;
      
      setPurchasedTemplates((purchasedData || []).map(p => ({
        id: p.id,
        template_id: p.template_id,
        purchased_at: p.purchased_at,
        price: p.price,
        template: {
          ...(p.user_templates as any),
          blocks: ((p.user_templates as any)?.blocks as Block[]) || [],
        },
      })));
    } catch (error) {
      console.error('Error loading templates:', error);
      toast.error(t('templates.loadError', 'Ошибка загрузки шаблонов'));
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (templateId: string) => {
    if (!confirm(t('templates.confirmDelete', 'Удалить этот шаблон?'))) return;
    
    setDeleting(templateId);
    try {
      const { error } = await supabase
        .from('user_templates')
        .delete()
        .eq('id', templateId);

      if (error) throw error;
      
      setMyTemplates(prev => prev.filter(t => t.id !== templateId));
      toast.success(t('templates.deleted', 'Шаблон удалён'));
    } catch (error) {
      console.error('Delete error:', error);
      toast.error(t('templates.deleteError', 'Ошибка удаления'));
    } finally {
      setDeleting(null);
    }
  };

  const handleApply = (templateBlocks: Block[]) => {
    // Generate new unique IDs for all blocks to avoid conflicts with existing blocks
    const blocksWithNewIds = templateBlocks.map((block, index) => ({
      ...block,
      id: `${block.type}-${Date.now()}-${index}`,
    }));
    onApplyTemplate(blocksWithNewIds);
    onOpenChange(false);
    toast.success(t('templates.applied', 'Шаблон применён!'));
  };

  const renderTemplateCard = (template: UserTemplate, isPurchased = false) => (
    <Card key={template.id} className="overflow-hidden group">
      {/* Preview - Use TemplatePreviewCard for visual block layout */}
      <div className="aspect-[4/5] relative">
        {template.preview_url ? (
          <img
            src={template.preview_url}
            alt={template.name}
            className="w-full h-full object-cover"
          />
        ) : (
          <TemplatePreviewCard 
            blocks={template.blocks}
            className="w-full h-full"
            showBlockCount
          />
        )}
        
        {/* Overlay with actions */}
        <div className="absolute inset-0 bg-background/80 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center gap-2 flex-wrap p-2">
          <Button size="sm" onClick={() => handleApply(template.blocks)}>
            <Download className="h-4 w-4 mr-1" />
            {t('templates.apply', 'Применить')}
          </Button>
          {!isPurchased && (
            <>
              <Button
                size="sm"
                variant="secondary"
                onClick={(e) => {
                  e.stopPropagation();
                  setEditingTemplate(template);
                }}
              >
                <Pencil className="h-4 w-4" />
              </Button>
              <Button
                size="sm"
                variant="destructive"
                onClick={() => handleDelete(template.id)}
                disabled={deleting === template.id}
              >
                {deleting === template.id ? (
                  <Loader2 className="h-4 w-4 animate-spin" />
                ) : (
                  <Trash2 className="h-4 w-4" />
                )}
              </Button>
            </>
          )}
        </div>
      </div>

      {/* Info */}
      <div className="p-3 space-y-2">
        <div className="flex items-start justify-between gap-2">
          <div>
            <h4 className="font-medium text-sm line-clamp-1">{template.name}</h4>
            <p className="text-xs text-muted-foreground">{getTemplateCategoryLabel(t, template.category)}</p>
          </div>
          {template.is_public ? (
            <Globe className="h-4 w-4 text-green-500 shrink-0" />
          ) : (
            <Lock className="h-4 w-4 text-muted-foreground shrink-0" />
          )}
        </div>

        {/* Stats */}
        <div className="flex items-center gap-3 text-xs text-muted-foreground">
          <span className="flex items-center gap-1">
            <Heart className="h-3 w-3" />
            {template.likes_count}
          </span>
          <span className="flex items-center gap-1">
            <Download className="h-3 w-3" />
            {template.downloads_count}
          </span>
          {template.is_for_sale && template.price && (
            <Badge variant="secondary" className="text-xs">
              <DollarSign className="h-3 w-3" />
              {template.price} {template.currency}
            </Badge>
          )}
        </div>
      </div>
    </Card>
  );

  return (
    <Sheet open={open} onOpenChange={onOpenChange}>
      <SheetContent side="right" className="w-full sm:max-w-lg">
        <SheetHeader>
          <SheetTitle className="flex items-center gap-2">
            <Package className="h-5 w-5" />
            {t('templates.myTemplates', 'Мои шаблоны')}
          </SheetTitle>
        </SheetHeader>

        <Tabs value={activeTab} onValueChange={setActiveTab} className="mt-4">
          <TabsList className="grid w-full grid-cols-2">
            <TabsTrigger value="my" className="flex items-center gap-1">
              <Package className="h-4 w-4" />
              {t('templates.created', 'Созданные')}
            </TabsTrigger>
            <TabsTrigger value="purchased" className="flex items-center gap-1">
              <ShoppingBag className="h-4 w-4" />
              {t('templates.purchased', 'Купленные')}
            </TabsTrigger>
          </TabsList>

          <TabsContent value="my" className="mt-4">
            {loading ? (
              <div className="flex items-center justify-center py-12">
                <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
              </div>
            ) : myTemplates.length === 0 ? (
              <div className="text-center py-12 text-muted-foreground">
                <Package className="h-12 w-12 mx-auto mb-3 opacity-50" />
                <p>{t('templates.noTemplates', 'У вас пока нет шаблонов')}</p>
                <p className="text-sm mt-1">
                  {t('templates.saveFirst', 'Сохраните страницу как шаблон в настройках')}
                </p>
              </div>
            ) : (
              <ScrollArea className="h-[calc(100vh-200px)]">
                <div className="grid grid-cols-2 gap-3 pr-4">
                  {myTemplates.map(template => renderTemplateCard(template))}
                </div>
              </ScrollArea>
            )}
          </TabsContent>

          <TabsContent value="purchased" className="mt-4">
            {loading ? (
              <div className="flex items-center justify-center py-12">
                <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
              </div>
            ) : purchasedTemplates.length === 0 ? (
              <div className="text-center py-12 text-muted-foreground">
                <ShoppingBag className="h-12 w-12 mx-auto mb-3 opacity-50" />
                <p>{t('templates.noPurchased', 'Нет купленных шаблонов')}</p>
                <p className="text-sm mt-1">
                  {t('templates.browseMk', 'Загляните в маркетплейс шаблонов')}
                </p>
              </div>
            ) : (
              <ScrollArea className="h-[calc(100vh-200px)]">
                <div className="grid grid-cols-2 gap-3 pr-4">
                  {purchasedTemplates.map(p => renderTemplateCard(p.template, true))}
                </div>
              </ScrollArea>
            )}
          </TabsContent>
        </Tabs>

        {/* Edit Template Dialog */}
        <EditTemplateDialog
          open={!!editingTemplate}
          onClose={() => setEditingTemplate(null)}
          template={editingTemplate}
          onUpdated={loadTemplates}
          currentBlocks={currentBlocks}
        />
      </SheetContent>
    </Sheet>
  );
});

import { memo, useMemo } from 'react';
import { cn } from '@/lib/utils/utils';
import type { Block } from '@/types/page';
import { 
  Link2, 
  Image, 
  Type, 
  Video, 
  ShoppingBag, 
  MessageCircle,
  User,
  Layers,
  FormInput,
  Star,
  MapPin,
  HelpCircle,
  Clock,
  DollarSign,
  File,
  Mail,
  ListOrdered,
  Gift,
  Megaphone,
  CalendarDays,
} from 'lucide-react';

interface TemplatePreviewCardProps {
  blocks: Block[] | unknown;
  className?: string;
  showBlockCount?: boolean;
}

// Map block types to icons and colors
const BLOCK_ICONS: Record<string, { icon: React.ElementType; color: string }> = {
  profile: { icon: User, color: 'bg-blue-500' },
  link: { icon: Link2, color: 'bg-sky-500' },
  button: { icon: () => <span className="text-[10px] font-bold">▶</span>, color: 'bg-red-500' },
  text: { icon: Type, color: 'bg-slate-500' },
  image: { icon: Image, color: 'bg-emerald-500' },
  video: { icon: Video, color: 'bg-rose-500' },
  product: { icon: ShoppingBag, color: 'bg-amber-500' },
  messenger: { icon: MessageCircle, color: 'bg-green-500' },
  socials: { icon: () => <span className="text-[10px]">@</span>, color: 'bg-pink-500' },
  carousel: { icon: Layers, color: 'bg-violet-500' },
  form: { icon: FormInput, color: 'bg-purple-500' },
  testimonial: { icon: Star, color: 'bg-yellow-500' },
  map: { icon: MapPin, color: 'bg-green-600' },
  faq: { icon: HelpCircle, color: 'bg-blue-400' },
  countdown: { icon: Clock, color: 'bg-orange-400' },
  pricing: { icon: DollarSign, color: 'bg-lime-500' },
  download: { icon: File, color: 'bg-indigo-500' },
  newsletter: { icon: Mail, color: 'bg-sky-500' },
  catalog: { icon: ListOrdered, color: 'bg-teal-500' },
  scratch: { icon: Gift, color: 'bg-red-400' },
  shoutout: { icon: Megaphone, color: 'bg-orange-500' },
  event: { icon: CalendarDays, color: 'bg-emerald-600' },
  avatar: { icon: User, color: 'bg-cyan-500' },
  separator: { icon: () => <span className="text-[10px]">—</span>, color: 'bg-gray-400' },
};

/**
 * Visual preview card showing template blocks in a mini-layout format
 */
export const TemplatePreviewCard = memo(function TemplatePreviewCard({
  blocks,
  className,
  showBlockCount = true,
}: TemplatePreviewCardProps) {
  const blocksArray = useMemo(() => {
    if (!blocks) return [];
    return Array.isArray(blocks) ? blocks : [];
  }, [blocks]);

  const profileBlock = blocksArray.find((b: any) => b?.type === 'profile');
  const contentBlocks = blocksArray.filter((b: any) => b?.type !== 'profile').slice(0, 8);
  
  // Group blocks into rows (max 2 per row for half-width, 1 for full-width)
  const rows = useMemo(() => {
    const result: Array<Array<any>> = [];
    let currentRow: any[] = [];
    let currentCols = 0;
    
    for (const block of contentBlocks) {
      const isFullWidth = !block.blockSize?.includes('half');
      const cols = isFullWidth ? 2 : 1;
      
      if (currentCols + cols > 2) {
        if (currentRow.length > 0) result.push(currentRow);
        currentRow = [block];
        currentCols = cols;
      } else {
        currentRow.push(block);
        currentCols += cols;
      }
      
      if (currentCols === 2) {
        result.push(currentRow);
        currentRow = [];
        currentCols = 0;
      }
    }
    
    if (currentRow.length > 0) result.push(currentRow);
    return result.slice(0, 4); // Max 4 rows in preview
  }, [contentBlocks]);

  const getBlockVisual = (block: any) => {
    const config = BLOCK_ICONS[block?.type] || BLOCK_ICONS.link;
    const IconComponent = config.icon;
    
    return (
      <div 
        className={cn(
          'rounded-sm flex items-center justify-center text-white',
          config.color
        )}
        style={{ width: '100%', height: '100%', minHeight: '12px' }}
      >
        <IconComponent className="h-2 w-2 sm:h-2.5 sm:w-2.5" />
      </div>
    );
  };

  return (
    <div className={cn(
      'relative w-full h-full rounded-lg overflow-hidden',
      'bg-gradient-to-br from-muted/50 to-muted',
      className
    )}>
      {/* Mini phone frame */}
      <div className="absolute inset-2 sm:inset-3 bg-background rounded-lg shadow-inner overflow-hidden flex flex-col">
        {/* Profile area */}
        {profileBlock && (
          <div className="flex flex-col items-center pt-2 pb-1 sm:pt-3 sm:pb-2 border-b border-border/30">
            {/* Mini avatar */}
            <div className="w-5 h-5 sm:w-6 sm:h-6 rounded-full bg-gradient-to-br from-primary/40 to-primary/20 flex items-center justify-center">
              <User className="h-2.5 w-2.5 sm:h-3 sm:w-3 text-primary" />
            </div>
            {/* Name placeholder */}
            <div className="w-12 sm:w-16 h-1.5 sm:h-2 bg-foreground/20 rounded-full mt-1" />
            {/* Bio placeholder */}
            <div className="w-16 sm:w-20 h-1 sm:h-1.5 bg-foreground/10 rounded-full mt-0.5" />
          </div>
        )}
        
        {/* Blocks grid */}
        <div className="flex-1 p-1.5 sm:p-2 space-y-1 sm:space-y-1.5 overflow-hidden">
          {rows.map((row, rowIndex) => (
            <div key={rowIndex} className="flex gap-1 sm:gap-1.5">
              {row.map((block: any, blockIndex: number) => {
                const isFullWidth = !block.blockSize?.includes('half');
                return (
                  <div 
                    key={blockIndex}
                    className={cn(
                      'h-3 sm:h-4 rounded-sm overflow-hidden',
                      isFullWidth ? 'w-full' : 'w-1/2'
                    )}
                  >
                    {getBlockVisual(block)}
                  </div>
                );
              })}
            </div>
          ))}
          
          {/* More blocks indicator */}
          {blocksArray.length > 9 && (
            <div className="text-center py-0.5">
              <span className="text-[8px] sm:text-[9px] text-muted-foreground">
                +{blocksArray.length - 9}
              </span>
            </div>
          )}
        </div>
      </div>
      
      {/* Block count badge */}
      {showBlockCount && blocksArray.length > 0 && (
        <div className="absolute bottom-1 right-1 sm:bottom-2 sm:right-2">
          <div className="bg-background/90 backdrop-blur-sm rounded-full px-1.5 py-0.5 text-[8px] sm:text-[9px] font-medium text-muted-foreground border border-border/50">
            {blocksArray.length} блоков
          </div>
        </div>
      )}
    </div>
  );
});

