import { useMemo } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import { supabase } from '@/integrations/supabase/client';
import { upsertToDB } from '@/lib/i18n-db-backend';
import { toast } from 'sonner';
import { logger } from '@/lib/utils/logger';

// Static fallbacks
import ru from '@/i18n/locales/ru.json';
import en from '@/i18n/locales/en.json';
import kk from '@/i18n/locales/kk.json';

type TranslationData = Record<string, unknown>;

const TRANSLATIONS_QUERY_KEY = ['admin_translations'];

// Flatten nested JSON object to dot notation keys
export function flattenObject(obj: TranslationData, prefix = ''): Record<string, string> {
    const result: Record<string, string> = {};
    if (!obj) return result;

    for (const [key, value] of Object.entries(obj)) {
        const newKey = prefix ? `${prefix}.${key}` : key;
        if (typeof value === 'object' && value !== null && !Array.isArray(value)) {
            Object.assign(result, flattenObject(value as TranslationData, newKey));
        } else {
            result[newKey] = String(value ?? '');
        }
    }
    return result;
}

// Set nested value by dot notation key
export function setNestedValue(obj: TranslationData, key: string, value: string): void {
    const parts = key.split('.');
    let current: TranslationData = obj;
    for (let i = 0; i < parts.length - 1; i++) {
        if (!current[parts[i]]) current[parts[i]] = {};
        current = current[parts[i]] as TranslationData;
    }
    current[parts[parts.length - 1]] = value;
}

export function useAdminTranslations(isAdmin: boolean) {
    const queryClient = useQueryClient();

    const { data: dbTranslations, isLoading: loading } = useQuery({
        queryKey: TRANSLATIONS_QUERY_KEY,
        queryFn: async () => {
            // Use explicit casting as any to bypass lint errors for custom table not yet in generated types
            const { data, error } = await (supabase.from('i18n_translations' as any) as any)
                .select('lang_code, data');

            if (error) throw error;

            const result: Record<string, TranslationData> = {};
            (data as any[])?.forEach(item => {
                result[item.lang_code] = item.data;
            });
            return result;
        },
        enabled: isAdmin,
        staleTime: 1000 * 60 * 5, // 5 minutes
    });

    const translations = useMemo(() => {
        return {
            ru: JSON.parse(JSON.stringify(ru)),
            en: JSON.parse(JSON.stringify(en)),
            kk: JSON.parse(JSON.stringify(kk)),
            ...(dbTranslations || {})
        } as Record<string, TranslationData>;
    }, [dbTranslations]);

    const activeLanguages = useMemo(() => {
        const baseLangs = ['en', 'ru', 'kk'];
        const dbLangs = dbTranslations ? Object.keys(dbTranslations) : [];
        return Array.from(new Set([...baseLangs, ...dbLangs]));
    }, [dbTranslations]);

    const updateMutation = useMutation({
        mutationFn: async ({ lang, key, value }: { lang: string; key: string; value: string }) => {
            const updatedLangData = JSON.parse(JSON.stringify(translations[lang] || {}));
            setNestedValue(updatedLangData, key, value);
            await upsertToDB(lang, updatedLangData);
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: TRANSLATIONS_QUERY_KEY });
            toast.success('Сохранено в БД');
        },
        onError: (error) => {
            logger.error('Failed to update translation', error);
            toast.error('Ошибка сохранения');
        }
    });

    const multiUpsertMutation = useMutation({
        mutationFn: async (payload: { lang: string; data: TranslationData }[]) => {
            for (const item of payload) {
                await upsertToDB(item.lang, item.data);
            }
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: TRANSLATIONS_QUERY_KEY });
            toast.success('Данные успешно синхронизированы');
        },
        onError: (error) => {
            logger.error('Failed multi upsert', error);
            toast.error('Ошибка синхронизации');
        }
    });

    const deleteKeyMutation = useMutation({
        mutationFn: async (key: string) => {
            const parts = key.split('.');
            for (const lang of activeLanguages) {
                const langObj = JSON.parse(JSON.stringify(translations[lang] || {}));
                let current: any = langObj;
                let found = true;
                for (let i = 0; i < parts.length - 1; i++) {
                    if (!current[parts[i]]) {
                        found = false;
                        break;
                    }
                    current = current[parts[i]];
                }
                if (found && current[parts[parts.length - 1]] !== undefined) {
                    delete current[parts[parts.length - 1]];
                    await upsertToDB(lang, langObj);
                }
            }
        },
        onSuccess: () => {
            queryClient.invalidateQueries({ queryKey: TRANSLATIONS_QUERY_KEY });
            toast.success('Ключ удалён отовсюду');
        },
        onError: (error) => {
            logger.error('Failed to delete key', error);
            toast.error('Ошибка при удалении ключа');
        }
    });

    const allKeys = useMemo(() => {
        const keySet = new Set<string>();
        activeLanguages.forEach(lang => {
            if (translations[lang]) {
                Object.keys(flattenObject(translations[lang])).forEach(k => keySet.add(k));
            }
        });

        const sortedKeys = Array.from(keySet).sort();
        const missingKeys: string[] = [];
        const fullKeys: string[] = [];

        sortedKeys.forEach(key => {
            const isMissingSomewhere = activeLanguages.some(lang => {
                const flat = flattenObject(translations[lang] || {});
                return !flat[key]?.trim();
            });
            if (isMissingSomewhere) missingKeys.push(key);
            else fullKeys.push(key);
        });

        return { all: [...missingKeys, ...fullKeys], missingCount: missingKeys.length };
    }, [translations, activeLanguages]);

    return {
        translations,
        activeLanguages,
        allKeys,
        loading,
        saving: updateMutation.isPending || multiUpsertMutation.isPending || deleteKeyMutation.isPending,
        updateTranslation: updateMutation.mutateAsync,
        upsertFullTranslations: multiUpsertMutation.mutateAsync,
        deleteKey: deleteKeyMutation.mutateAsync,
        addLanguage: async (langCode: string, initialData: TranslationData) => {
            await multiUpsertMutation.mutateAsync([{ lang: langCode, data: initialData }]);
        }
    };
}

/**
 * Hook for tracking analytics on public pages
 * Automatically tracks page views and provides methods for click/share tracking
 * Sends events to both internal DB and marketing pixels
 */

import { useEffect, useCallback, useRef } from 'react';
import {
  trackPageView,
  trackBlockClick,
  trackShare
} from '@/services/analytics';
import { trackClickLink, trackViewContent } from '@/lib/analytics';

interface UseAnalyticsTrackingOptions {
  pageId: string | undefined;
  enabled?: boolean;
}

export function useAnalyticsTracking({ pageId, enabled = true }: UseAnalyticsTrackingOptions) {
  const hasTrackedView = useRef(false);

  // Track page view on mount (only once per session per page)
  useEffect(() => {
    if (!pageId || !enabled || hasTrackedView.current) return;

    // Check if we've already tracked this page in this session
    const sessionKey = `linkmax_viewed_${pageId}`;
    const alreadyViewed = sessionStorage.getItem(sessionKey);

    if (!alreadyViewed) {
      trackPageView(pageId);
      sessionStorage.setItem(sessionKey, 'true');
      hasTrackedView.current = true;
    }
  }, [pageId, enabled]);

  // Track block click — sends to internal DB + marketing pixels
  const onBlockClick = useCallback(
    (blockId: string, blockType?: string, blockTitle?: string) => {
      if (!pageId || !enabled) return;
      // Internal analytics (DB)
      trackBlockClick(pageId, blockId, blockType, blockTitle);
      // Marketing pixels (FB, TikTok, GA4)
      trackClickLink(blockTitle, undefined);
    },
    [pageId, enabled]
  );

  // Track share
  const onShare = useCallback(
    (method?: string) => {
      if (!pageId || !enabled) return;
      trackShare(pageId, method);
    },
    [pageId, enabled]
  );

  return {
    onBlockClick,
    onShare,
  };
}

/**
 * Context for passing analytics tracking down the component tree
 */
import { createContext, useContext, type ReactNode } from 'react';

interface AnalyticsContextValue {
  pageId: string | undefined;
  onBlockClick: (blockId: string, blockType?: string, blockTitle?: string) => void;
  onShare: (method?: string) => void;
}

const AnalyticsContext = createContext<AnalyticsContextValue | null>(null);

interface AnalyticsProviderProps {
  pageId: string | undefined;
  enabled?: boolean;
  children: ReactNode;
}

export function AnalyticsProvider({ pageId, enabled = true, children }: AnalyticsProviderProps) {
  const { onBlockClick, onShare } = useAnalyticsTracking({ pageId, enabled });

  return (
    <AnalyticsContext.Provider value={{ pageId, onBlockClick, onShare }}>
      {children}
    </AnalyticsContext.Provider>
  );
}

export function useAnalytics() {
  const context = useContext(AnalyticsContext);
  if (!context) {
    // Return no-op functions if not in provider
    return {
      pageId: undefined,
      onBlockClick: () => { },
      onShare: () => { },
    };
  }
  return context;
}

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/platform/supabase/client';
import { useAuth } from '@/hooks/user/useAuth';
import { subDays, startOfYear, endOfYear, eachDayOfInterval, format, parseISO, isSameDay } from 'date-fns';
import { logger } from '@/lib/utils/logger';

export interface ClickPoint {
  x: number;
  y: number;
  relX: number;
  relY: number;
  count: number;
}

export interface ScrollDepthData {
  depth: number;
  count: number;
  percentage: number;
}

export interface HeatmapData {
  clicks: ClickPoint[];
  scrollDepths: ScrollDepthData[];
  totalSessions: number;
  avgScrollDepth: number;
  maxScrollDepth: number;
}

export function useHeatmapData(days: number = 30) {
  const { user } = useAuth();
  const [pageId, setPageId] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [data, setData] = useState<HeatmapData | null>(null);

  // Fetch user's page ID
  useEffect(() => {
    async function fetchPageId() {
      if (!user) return;

      const { data } = await supabase
        .from('pages')
        .select('id')
        .eq('user_id', user.id)
        .maybeSingle();

      if (data) {
        setPageId(data.id);
      }
    }

    fetchPageId();
  }, [user]);

  const fetchHeatmapData = useCallback(async () => {
    if (!user || !pageId) return;

    try {
      setLoading(true);
      const startDate = subDays(new Date(), days);

      // Fetch heatmap click events
      const { data: clickEvents } = await supabase
        .from('analytics')
        .select('metadata')
        .eq('page_id', pageId)
        .eq('event_type', 'heatmap_clicks')
        .gte('created_at', startDate.toISOString());

      // Fetch scroll depth events
      const { data: scrollEvents } = await supabase
        .from('analytics')
        .select('metadata')
        .eq('page_id', pageId)
        .eq('event_type', 'heatmap_scroll')
        .gte('created_at', startDate.toISOString());

      // Process click data - aggregate by grid cells
      const clickGrid = new Map<string, ClickPoint>();
      const gridSize = 50; // 50px grid cells

      (clickEvents || []).forEach(event => {
        const meta = event.metadata as Record<string, unknown>;
        const clicks = meta?.clicks as Array<{
          x: number;
          y: number;
          relX: number;
          relY: number;
        }> | undefined;

        clicks?.forEach(click => {
          // Normalize to grid cell
          const gridX = Math.floor((click.relX * 100) / (100 / 20)); // 20 columns
          const gridY = Math.floor((click.relY * 100) / (100 / 50)); // 50 rows
          const key = `${gridX},${gridY} `;

          const existing = clickGrid.get(key);
          if (existing) {
            existing.count++;
          } else {
            clickGrid.set(key, {
              x: gridX * 5, // Convert back to percentage (20 cols = 5% each)
              y: gridY * 2, // Convert back to percentage (50 rows = 2% each)
              relX: click.relX,
              relY: click.relY,
              count: 1,
            });
          }
        });
      });

      // Process scroll depth data - create histogram
      const scrollDepthCounts = new Map<number, number>();
      let totalScrollDepth = 0;
      let maxScrollDepth = 0;

      (scrollEvents || []).forEach(event => {
        const meta = event.metadata as Record<string, unknown>;
        const depth = (meta?.maxDepth as number) || 0;

        // Round to nearest 10%
        const bucket = Math.floor(depth / 10) * 10;
        scrollDepthCounts.set(bucket, (scrollDepthCounts.get(bucket) || 0) + 1);

        totalScrollDepth += depth;
        maxScrollDepth = Math.max(maxScrollDepth, depth);
      });

      const totalScrollSessions = scrollEvents?.length || 1;
      const scrollDepths: ScrollDepthData[] = [];

      // Build cumulative scroll depth data
      for (let depth = 0; depth <= 100; depth += 10) {
        // Count sessions that reached at least this depth
        let reachedCount = 0;
        scrollDepthCounts.forEach((count, d) => {
          if (d >= depth) reachedCount += count;
        });

        scrollDepths.push({
          depth,
          count: reachedCount,
          percentage: totalScrollSessions > 0
            ? Math.round((reachedCount / totalScrollSessions) * 100)
            : 0,
        });
      }

      setData({
        clicks: Array.from(clickGrid.values()).sort((a, b) => b.count - a.count),
        scrollDepths,
        totalSessions: totalScrollSessions,
        avgScrollDepth: totalScrollSessions > 0
          ? Math.round(totalScrollDepth / totalScrollSessions)
          : 0,
        maxScrollDepth,
      });
    } catch (error) {
      logger.error('Error fetching heatmap data:', error, { context: 'useHeatmapData' });
    } finally {
      setLoading(false);
    }
  }, [user, pageId, days]);

  useEffect(() => {
    if (pageId) {
      fetchHeatmapData();
    }
  }, [fetchHeatmapData, pageId]);

  return {
    data,
    loading,
    refresh: fetchHeatmapData,
  };
}

/**
 * Landing Page Analytics Hook
 * Tracks scroll depth, CTA clicks, section visibility, and drop-off
 */

import { useEffect, useCallback, useRef } from 'react';
import { supabase } from '@/platform/supabase/client';
import type { Json } from '@/platform/supabase/types';
import { logger } from '@/lib/utils/logger';

// Filter out bots and dev traffic
function isBot(): boolean {
  const ua = navigator.userAgent.toLowerCase();
  const botPatterns = [
    'bot', 'crawl', 'spider', 'scrape', 'lighthouse',
    'pagespeed', 'headless', 'phantomjs', 'selenium'
  ];
  return botPatterns.some(pattern => ua.includes(pattern));
}

function isDevTraffic(): boolean {
  return (
    window.location.hostname === 'localhost' ||
    window.location.hostname.includes('preview') ||
    window.location.hostname.includes('lovable')
  );
}

// Session tracking
const SESSION_KEY = 'lnkmx_landing_session';

interface LandingSession {
  id: string;
  startedAt: number;
  maxScrollDepth: number;
  sectionsViewed: string[];
  ctaClicks: string[];
}

function getOrCreateSession(): LandingSession {
  try {
    const stored = sessionStorage.getItem(SESSION_KEY);
    if (stored) {
      return JSON.parse(stored);
    }
  } catch {
    // Ignore
  }

  const session: LandingSession = {
    id: crypto.randomUUID?.() || Math.random().toString(36).substring(2),
    startedAt: Date.now(),
    maxScrollDepth: 0,
    sectionsViewed: [],
    ctaClicks: [],
  };

  try {
    sessionStorage.setItem(SESSION_KEY, JSON.stringify(session));
  } catch {
    // Ignore
  }

  return session;
}

function updateSession(updates: Partial<LandingSession>) {
  try {
    const session = getOrCreateSession();
    const updated = { ...session, ...updates };
    sessionStorage.setItem(SESSION_KEY, JSON.stringify(updated));
    return updated;
  } catch {
    return null;
  }
}

// Event types for landing page
type LandingEventType =
  | 'landing_view'
  | 'landing_scroll'
  | 'landing_section_view'
  | 'cta_create_click'
  | 'cta_gallery_click'
  | 'cta_pricing_click'
  | 'pricing_toggle'
  | 'signup_start'
  | 'landing_exit';

interface TrackLandingEventOptions {
  eventType: LandingEventType;
  metadata?: Record<string, unknown>;
}

async function trackLandingEvent({ eventType, metadata = {} }: TrackLandingEventOptions): Promise<void> {
  // Filter bots and dev traffic
  if (isBot() || isDevTraffic()) return;

  try {
    const session = getOrCreateSession();

    const enrichedMetadata = {
      ...metadata,
      sessionId: session.id,
      sessionDuration: Date.now() - session.startedAt,
      device: /mobile|android|iphone/i.test(navigator.userAgent) ? 'mobile' : 'desktop',
      source: document.referrer ? new URL(document.referrer).hostname : 'direct',
      userAgent: navigator.userAgent,
      language: navigator.language,
      screenWidth: screen.width,
      screenHeight: screen.height,
      timestamp: new Date().toISOString(),
    };

    await supabase.from('analytics').insert({
      page_id: null, // Landing page doesn't have a page_id
      block_id: null,
      event_type: eventType,
      metadata: enrichedMetadata as Json,
    });
  } catch (error) {
    // Silently fail for analytics
    logger.debug('Landing analytics failed:', { context: 'useLandingAnalytics', data: { error } });
  }
}

export function useLandingAnalytics() {
  const hasTrackedView = useRef(false);
  const scrollDepths = useRef<Set<number>>(new Set());
  const sectionsInViewport = useRef<Set<string>>(new Set());

  // Track initial page view
  useEffect(() => {
    if (hasTrackedView.current || isBot() || isDevTraffic()) return;

    const sessionKey = 'lnkmx_landing_viewed';
    const alreadyViewed = sessionStorage.getItem(sessionKey);

    if (!alreadyViewed) {
      trackLandingEvent({
        eventType: 'landing_view',
        metadata: {
          referrer: document.referrer,
          utmSource: new URLSearchParams(window.location.search).get('utm_source'),
          utmMedium: new URLSearchParams(window.location.search).get('utm_medium'),
          utmCampaign: new URLSearchParams(window.location.search).get('utm_campaign'),
        }
      });
      sessionStorage.setItem(sessionKey, 'true');
      hasTrackedView.current = true;
    }
  }, []);

  // Track scroll depth
  useEffect(() => {
    if (isBot() || isDevTraffic()) return;

    const handleScroll = () => {
      const scrollTop = window.scrollY;
      const docHeight = document.documentElement.scrollHeight - window.innerHeight;
      const scrollPercent = Math.round((scrollTop / docHeight) * 100);

      // Track at 25%, 50%, 75%, 90%, 100% thresholds
      const thresholds = [25, 50, 75, 90, 100];
      for (const threshold of thresholds) {
        if (scrollPercent >= threshold && !scrollDepths.current.has(threshold)) {
          scrollDepths.current.add(threshold);
          trackLandingEvent({
            eventType: 'landing_scroll',
            metadata: { depth: threshold }
          });

          // Update session max scroll depth
          const session = getOrCreateSession();
          if (threshold > session.maxScrollDepth) {
            updateSession({ maxScrollDepth: threshold });
          }
        }
      }
    };

    window.addEventListener('scroll', handleScroll, { passive: true });
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  // Track section visibility
  const trackSectionView = useCallback((sectionId: string) => {
    if (isBot() || isDevTraffic()) return;
    if (sectionsInViewport.current.has(sectionId)) return;

    sectionsInViewport.current.add(sectionId);

    trackLandingEvent({
      eventType: 'landing_section_view',
      metadata: { section: sectionId }
    });

    // Update session
    const session = getOrCreateSession();
    if (!session.sectionsViewed.includes(sectionId)) {
      updateSession({ sectionsViewed: [...session.sectionsViewed, sectionId] });
    }
  }, []);

  // Track CTA clicks
  const trackCtaClick = useCallback((ctaType: 'create' | 'gallery' | 'pricing' | 'signup', location?: string) => {
    if (isBot() || isDevTraffic()) return;

    const eventTypeMap: Record<string, LandingEventType> = {
      create: 'cta_create_click',
      gallery: 'cta_gallery_click',
      pricing: 'cta_pricing_click',
      signup: 'signup_start',
    };

    trackLandingEvent({
      eventType: eventTypeMap[ctaType],
      metadata: {
        ctaType,
        location: location || 'unknown',
        scrollDepth: Math.round((window.scrollY / (document.documentElement.scrollHeight - window.innerHeight)) * 100),
      }
    });

    // Update session
    const session = getOrCreateSession();
    updateSession({ ctaClicks: [...session.ctaClicks, `${ctaType}_${location || 'unknown'}`] });
  }, []);

  // Track pricing toggle
  const trackPricingToggle = useCallback((plan: string) => {
    if (isBot() || isDevTraffic()) return;

    trackLandingEvent({
      eventType: 'pricing_toggle',
      metadata: { selectedPlan: plan }
    });
  }, []);

  // Track exit (before unload)
  useEffect(() => {
    if (isBot() || isDevTraffic()) return;

    const handleBeforeUnload = () => {
      const session = getOrCreateSession();
      // Use sendBeacon for reliable exit tracking
      const data = {
        eventType: 'landing_exit',
        metadata: {
          sessionId: session.id,
          duration: Date.now() - session.startedAt,
          maxScrollDepth: session.maxScrollDepth,
          sectionsViewed: session.sectionsViewed,
          ctaClicks: session.ctaClicks,
        }
      };

      const blob = new Blob([JSON.stringify({
        page_id: null,
        block_id: null,
        event_type: 'landing_exit',
        metadata: data.metadata,
      })], { type: 'application/json' });

      navigator.sendBeacon?.(
        `${import.meta.env.VITE_SUPABASE_URL}/rest/v1/analytics?apikey=${import.meta.env.VITE_SUPABASE_PUBLISHABLE_KEY}`,
        blob
      );
    };

    window.addEventListener('beforeunload', handleBeforeUnload);
    return () => window.removeEventListener('beforeunload', handleBeforeUnload);
  }, []);

  return {
    trackSectionView,
    trackCtaClick,
    trackPricingToggle,
  };
}

// Intersection Observer hook for section tracking
export function useSectionObserver(sectionId: string, trackSectionView: (id: string) => void) {
  const sectionRef = useRef<HTMLElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      (entries) => {
        entries.forEach(entry => {
          if (entry.isIntersecting) {
            trackSectionView(sectionId);
          }
        });
      },
      { threshold: 0.3 } // 30% visibility triggers tracking
    );

    if (sectionRef.current) {
      observer.observe(sectionRef.current);
    }

    return () => observer.disconnect();
  }, [sectionId, trackSectionView]);

  return sectionRef;
}

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/platform/supabase/client';
import { logger } from '@/lib/utils/logger';
import { useAuth } from '@/hooks/user/useAuth';
import { startOfDay, startOfWeek, startOfMonth, subDays, subWeeks, subMonths, format, eachDayOfInterval, eachWeekOfInterval, eachMonthOfInterval } from 'date-fns';
import { getI18nText, type SupportedLanguage } from '@/lib/i18n-helpers';
import { useTranslation } from 'react-i18next';

export interface AnalyticsEvent {
  id: string;
  page_id: string;
  block_id: string | null;
  event_type: string;
  metadata: Record<string, any>;
  created_at: string;
}

export interface BlockStats {
  blockId: string;
  blockType: string;
  blockTitle: string;
  clicks: number;
  views: number;
  ctr: number; // Click-through rate
}

export interface TimeSeriesData {
  date: string;
  views: number;
  clicks: number;
  shares: number;
}

export interface GeoData {
  country: string;
  countryCode: string;
  count: number;
  percentage: number;
}

export interface AnalyticsSummary {
  totalViews: number;
  totalClicks: number;
  totalShares: number;
  uniqueVisitors: number;
  avgViewsPerDay: number;
  topBlocks: BlockStats[];
  dailyData: TimeSeriesData[];
  weeklyData: TimeSeriesData[];
  monthlyData: TimeSeriesData[];
  viewsChange: number; // % change from previous period
  clicksChange: number;
  trafficSources: TrafficSource[];
  deviceBreakdown: DeviceBreakdown;
  geoData: GeoData[];
  avgSessionDuration: number; // in seconds
  bounceRate: number; // percentage
  returningVisitors: number; // percentage
  totalConversions: number;
}

export interface TrafficSource {
  source: string;
  count: number;
  percentage: number;
}

export interface DeviceBreakdown {
  mobile: number;
  tablet: number;
  desktop: number;
}

export type TimePeriod = 'day' | 'week' | 'two_weeks' | 'month' | 'all';

export function usePageAnalytics() {
  const { user } = useAuth();
  const { i18n } = useTranslation();
  const [pageId, setPageId] = useState<string | null>(null);
  const [loading, setLoading] = useState(true);
  const [analytics, setAnalytics] = useState<AnalyticsSummary | null>(null);
  const [period, setPeriod] = useState<TimePeriod>('week');

  // Fetch user's page ID
  useEffect(() => {
    async function fetchPageId() {
      if (!user) return;

      const { data } = await supabase
        .from('pages')
        .select('id')
        .eq('user_id', user.id)
        .maybeSingle();

      if (data) {
        setPageId(data.id);
      }
    }

    fetchPageId();
  }, [user]);

  const fetchAnalytics = useCallback(async () => {
    if (!user || !pageId) return;

    try {
      setLoading(true);

      const now = new Date();
      let startDate: Date;
      let previousStartDate: Date;

      switch (period) {
        case 'day':
          startDate = startOfDay(now);
          previousStartDate = subDays(startDate, 1);
          break;
        case 'week':
          startDate = subDays(now, 7);
          previousStartDate = subDays(startDate, 7);
          break;
        case 'two_weeks':
          startDate = subDays(now, 14);
          previousStartDate = subDays(startDate, 14);
          break;
        case 'month':
          startDate = subDays(now, 30);
          previousStartDate = subDays(startDate, 30);
          break;
        default:
          startDate = subMonths(now, 12); // Last 12 months for "all"
          previousStartDate = subMonths(startDate, 12);
      }

      // Fetch all analytics for current period
      const { data: currentEvents, error } = await supabase
        .from('analytics')
        .select('*')
        .eq('page_id', pageId)
        .gte('created_at', startDate.toISOString())
        .order('created_at', { ascending: true });

      if (error) throw error;

      // Fetch previous period for comparison
      const { data: previousEvents } = await supabase
        .from('analytics')
        .select('*')
        .eq('page_id', pageId)
        .gte('created_at', previousStartDate.toISOString())
        .lt('created_at', startDate.toISOString());

      // Fetch blocks for the page to get block info
      const { data: blocks } = await supabase
        .from('blocks')
        .select('id, type, title, content, click_count')
        .eq('page_id', pageId);

      const events = (currentEvents as AnalyticsEvent[]) || [];
      const prevEvents = (previousEvents as AnalyticsEvent[]) || [];

      // Calculate totals
      const totalViews = events.filter(e => e.event_type === 'view').length;
      const totalClicks = events.filter(e => e.event_type === 'click').length;
      const totalShares = events.filter(e => e.event_type === 'share').length;

      // Previous period totals
      const prevViews = prevEvents.filter(e => e.event_type === 'view').length;
      const prevClicks = prevEvents.filter(e => e.event_type === 'click').length;

      // Calculate changes
      const viewsChange = prevViews > 0 ? ((totalViews - prevViews) / prevViews) * 100 : 0;
      const clicksChange = prevClicks > 0 ? ((totalClicks - prevClicks) / prevClicks) * 100 : 0;

      // Unique visitors (by IP in metadata or session)
      const uniqueIPs = new Set(events
        .filter(e => e.event_type === 'view' && e.metadata?.ip)
        .map(e => e.metadata.ip));
      const uniqueVisitors = uniqueIPs.size || Math.ceil(totalViews * 0.7); // Estimate if no IP data

      // Days in period for average
      const daysInPeriod = Math.max(1, Math.ceil((now.getTime() - startDate.getTime()) / (1000 * 60 * 60 * 24)));
      const avgViewsPerDay = Math.round(totalViews / daysInPeriod);

      // Block statistics
      const blockStatsMap = new Map<string, BlockStats>();

      if (blocks) {
        const currentLang = i18n.language as SupportedLanguage;
        blocks.forEach(block => {
          const content = block.content as any;
          // Use getI18nText to handle MultilingualString objects
          const rawTitle = block.title || content?.title || content?.name || block.type;
          const blockTitle = typeof rawTitle === 'object'
            ? getI18nText(rawTitle, currentLang)
            : rawTitle;

          blockStatsMap.set(block.id, {
            blockId: block.id,
            blockType: block.type,
            blockTitle,
            clicks: 0, // Initialize to 0 to only count clicks from the selected period
            views: 0,
            ctr: 0,
          });
        });
      }

      // Count clicks per block from events
      events.filter(e => e.event_type === 'click' && e.block_id).forEach(e => {
        const stats = blockStatsMap.get(e.block_id!);
        if (stats) {
          stats.clicks++;
        }
      });

      // Calculate CTR (clicks / total page views)
      blockStatsMap.forEach(stats => {
        stats.views = totalViews || 0;
        stats.ctr = totalViews > 0 ? (stats.clicks / totalViews) * 100 : 0;
        if (isNaN(stats.ctr)) stats.ctr = 0;
      });

      const topBlocks = Array.from(blockStatsMap.values())
        .sort((a, b) => b.clicks - a.clicks)
        .slice(0, 10);

      // Generate time series data
      const dailyData = generateDailyData(events, startDate, now);
      const weeklyData = generateWeeklyData(events, subMonths(now, 3), now);
      const monthlyData = generateMonthlyData(events, subMonths(now, 12), now);

      // Calculate traffic sources
      const sourceMap = new Map<string, number>();
      events.filter(e => e.event_type === 'view').forEach(e => {
        const source = e.metadata?.source || 'direct';
        sourceMap.set(source, (sourceMap.get(source) || 0) + 1);
      });
      const trafficSources: TrafficSource[] = Array.from(sourceMap.entries())
        .map(([source, count]) => ({
          source,
          count,
          percentage: totalViews > 0 ? (count / totalViews) * 100 : 0,
        }))
        .sort((a, b) => b.count - a.count)
        .slice(0, 10);

      // Calculate device breakdown
      const deviceCounts = { mobile: 0, tablet: 0, desktop: 0 };
      events.filter(e => e.event_type === 'view').forEach(e => {
        const device = e.metadata?.device as 'mobile' | 'tablet' | 'desktop' | undefined;
        if (device && device in deviceCounts) {
          deviceCounts[device]++;
        } else {
          deviceCounts.desktop++; // Default to desktop if unknown
        }
      });
      const deviceBreakdown: DeviceBreakdown = deviceCounts;

      // Calculate geography breakdown
      const geoMap = new Map<string, { country: string; countryCode: string; count: number }>();
      events.filter(e => e.event_type === 'view').forEach(e => {
        const countryCode = (e.metadata?.country as string) || 'unknown';
        const country = (e.metadata?.countryName as string) || countryCode;
        const existing = geoMap.get(countryCode);
        if (existing) {
          existing.count++;
        } else {
          geoMap.set(countryCode, { country, countryCode, count: 1 });
        }
      });
      const geoData: GeoData[] = Array.from(geoMap.values())
        .map(g => ({
          ...g,
          percentage: totalViews > 0 ? (g.count / totalViews) * 100 : 0,
        }))
        .sort((a, b) => b.count - a.count);

      // Calculate session metrics (estimates based on available data)
      const sessionsWithClicks = events.filter(e => e.event_type === 'click').length;
      const bounceRate = totalViews > 0
        ? Math.max(0, Math.min(100, ((totalViews - sessionsWithClicks) / totalViews) * 100))
        : 0;

      // Estimate average session duration from metadata if available
      const durations = events
        .filter(e => e.metadata?.sessionDuration && typeof e.metadata.sessionDuration === 'number')
        .map(e => e.metadata.sessionDuration as number);
      const avgSessionDuration = durations.length > 0
        ? durations.reduce((sum, d) => sum + d, 0) / durations.length
        : 45; // Default estimate

      // Calculate returning visitors
      const visitorCounts = new Map<string, number>();
      events.filter(e => e.event_type === 'view').forEach(e => {
        const visitorId = (e.metadata?.visitorId as string) || e.id;
        visitorCounts.set(visitorId, (visitorCounts.get(visitorId) || 0) + 1);
      });
      const returningCount = Array.from(visitorCounts.values()).filter(c => c > 1).length;
      const returningVisitorsPercent = uniqueVisitors > 0 ? (returningCount / uniqueVisitors) * 100 : 0;

      // Fetch conversions (leads + bookings + event_registrations)
      const { data: leads } = await supabase
        .from('leads')
        .select('id')
        .eq('user_id', user.id)
        .gte('created_at', startDate.toISOString());

      const { data: bookings } = await supabase
        .from('bookings')
        .select('id')
        .eq('owner_id', user.id)
        .gte('created_at', startDate.toISOString());

      const { data: eventRegistrations } = await supabase
        .from('event_registrations')
        .select('id')
        .eq('owner_id', user.id)
        .gte('created_at', startDate.toISOString());

      const totalConversions = (leads?.length || 0) + (bookings?.length || 0) + (eventRegistrations?.length || 0);

      setAnalytics({
        totalViews,
        totalClicks,
        totalShares,
        uniqueVisitors,
        avgViewsPerDay,
        topBlocks,
        dailyData,
        weeklyData,
        monthlyData,
        viewsChange,
        clicksChange,
        trafficSources,
        deviceBreakdown,
        geoData,
        avgSessionDuration,
        bounceRate,
        returningVisitors: returningVisitorsPercent,
        totalConversions,
      });
    } catch (error) {
      logger.error('Error fetching analytics:', error, { context: 'usePageAnalytics' });
    } finally {
      setLoading(false);
    }
  }, [user, pageId, period, i18n.language]);

  useEffect(() => {
    if (pageId) {
      fetchAnalytics();
    }
  }, [fetchAnalytics, pageId]);

  return {
    analytics,
    loading,
    period,
    setPeriod,
    refresh: fetchAnalytics,
  };
}

function generateDailyData(events: AnalyticsEvent[], start: Date, end: Date): TimeSeriesData[] {
  const days = eachDayOfInterval({ start, end });

  return days.map(day => {
    const dayStr = format(day, 'yyyy-MM-dd');
    const dayEvents = events.filter(e => {
      if (!e.created_at) return false;
      return format(new Date(e.created_at), 'yyyy-MM-dd') === dayStr;
    });

    return {
      date: format(day, 'dd MMM'),
      views: dayEvents.filter(e => e.event_type === 'view').length,
      clicks: dayEvents.filter(e => e.event_type === 'click').length,
      shares: dayEvents.filter(e => e.event_type === 'share').length,
    };
  });
}

function generateWeeklyData(events: AnalyticsEvent[], start: Date, end: Date): TimeSeriesData[] {
  const weeks = eachWeekOfInterval({ start, end }, { weekStartsOn: 1 });

  return weeks.map(weekStart => {
    const weekEnd = new Date(weekStart);
    weekEnd.setDate(weekEnd.getDate() + 6);

    const weekEvents = events.filter(e => {
      if (!e.created_at) return false;
      const eventDate = new Date(e.created_at);
      return eventDate >= weekStart && eventDate <= weekEnd;
    });

    return {
      date: format(weekStart, 'dd MMM'),
      views: weekEvents.filter(e => e.event_type === 'view').length,
      clicks: weekEvents.filter(e => e.event_type === 'click').length,
      shares: weekEvents.filter(e => e.event_type === 'share').length,
    };
  });
}

function generateMonthlyData(events: AnalyticsEvent[], start: Date, end: Date): TimeSeriesData[] {
  const months = eachMonthOfInterval({ start, end });

  return months.map(monthStart => {
    const monthEnd = new Date(monthStart);
    monthEnd.setMonth(monthEnd.getMonth() + 1);
    monthEnd.setDate(0);

    const monthEvents = events.filter(e => {
      if (!e.created_at) return false;
      const eventDate = new Date(e.created_at);
      return eventDate >= monthStart && eventDate <= monthEnd;
    });

    return {
      date: format(monthStart, 'MMM yyyy'),
      views: monthEvents.filter(e => e.event_type === 'view').length,
      clicks: monthEvents.filter(e => e.event_type === 'click').length,
      shares: monthEvents.filter(e => e.event_type === 'share').length,
    };
  });
}

import { describe, it, expect, vi, beforeEach } from 'vitest';
import { renderHook, act, waitFor } from '@testing-library/react';
import { useLeads } from '../useLeads';
import { supabase } from '@/platform/supabase/client';
