            order: vi.fn().mockResolvedValue({ data: mockLeads, error: null })
        } as any);

        const { result } = renderHook(() => useLeads());

        expect(result.current.loading).toBe(true);

        await waitFor(() => {
            expect(result.current.loading).toBe(false);
