});

import { useState, useEffect, useCallback } from 'react';
import { supabase } from '@/platform/supabase/client';
import { logger } from '@/lib/utils/logger';
import { useAuth } from '@/hooks/user/useAuth';
import { useTranslation } from 'react-i18next';
import { toast } from 'sonner';

export type LeadStatus = 'new' | 'contacted' | 'qualified' | 'converted' | 'lost';
export type LeadSource = 'page_view' | 'form' | 'messenger' | 'manual' | 'other';
export type InteractionType = 'note' | 'call' | 'email' | 'message' | 'meeting';

export interface Lead {
  id: string;
  user_id: string;
  name: string;
  email: string | null;
  phone: string | null;
  source: LeadSource;
  status: LeadStatus;
  notes: string | null;
  metadata: Record<string, any>;
  created_at: string;
  updated_at: string;
}

export interface LeadInteraction {
  id: string;
  lead_id: string;
  user_id: string;
  type: InteractionType;
  content: string;
  created_at: string;
}

export function useLeads() {
  const { user } = useAuth();
  const { t } = useTranslation();
  const [leads, setLeads] = useState<Lead[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  const fetchLeads = useCallback(async () => {
    if (!user) return;

    try {
      setLoading(true);
      const { data, error } = await supabase
        .from('leads')
        .select('*')
        .eq('user_id', user.id)
        .order('created_at', { ascending: false });

      if (error) throw error;
      setLeads((data as Lead[]) || []);
    } catch (error) {
      logger.error('Error fetching leads', error, { context: 'useLeads' });
      toast.error(t('toasts.leads.loadError'));
    } finally {
      setLoading(false);
    }
  }, [user, t]);

  useEffect(() => {
    fetchLeads();
  }, [fetchLeads]);

  const createLead = async (leadData: Partial<Lead>) => {
    if (!user) return null;

    try {
      setSaving(true);
      const { data, error } = await supabase
        .from('leads')
        .insert({
          user_id: user.id,
          name: leadData.name || '',
          email: leadData.email || null,
          phone: leadData.phone || null,
          source: leadData.source || 'manual',
          status: leadData.status || 'new',
          notes: leadData.notes || null,
          metadata: leadData.metadata || {},
        })
        .select()
        .single();

      if (error) throw error;

      setLeads(prev => [data as Lead, ...prev]);
      toast.success(t('toasts.leads.created'));
      return data as Lead;
    } catch (error) {
      logger.error('Error creating lead', error, { context: 'useLeads' });
      toast.error(t('toasts.leads.createError'));
      return null;
    } finally {
      setSaving(false);
    }
  };

  const updateLead = async (id: string, updates: Partial<Lead>) => {
    if (!user) return false;

    try {
      setSaving(true);
      const { error } = await supabase
        .from('leads')
        .update(updates)
        .eq('id', id)
        .eq('user_id', user.id);

      if (error) throw error;

      setLeads(prev => prev.map(lead =>
        lead.id === id ? { ...lead, ...updates } : lead
      ));
      toast.success(t('toasts.leads.updated'));
      return true;
    } catch (error) {
      logger.error('Error updating lead', error, { context: 'useLeads', data: { leadId: id } });
      toast.error(t('toasts.leads.updateError'));
      return false;
    } finally {
      setSaving(false);
    }
  };

  const deleteLead = async (id: string) => {
    if (!user) return false;

    try {
      setSaving(true);
      const { error } = await supabase
        .from('leads')
        .delete()
        .eq('id', id)
        .eq('user_id', user.id);

      if (error) throw error;

      setLeads(prev => prev.filter(lead => lead.id !== id));
      toast.success(t('toasts.leads.deleted'));
      return true;
    } catch (error) {
      logger.error('Error deleting lead', error, { context: 'useLeads', data: { leadId: id } });
      toast.error(t('toasts.leads.deleteError'));
      return false;
    } finally {
      setSaving(false);
    }
  };

  const getLeadStats = () => {
    const stats = {
      total: leads.length,
      new: leads.filter(l => l.status === 'new').length,
      contacted: leads.filter(l => l.status === 'contacted').length,
      qualified: leads.filter(l => l.status === 'qualified').length,
      converted: leads.filter(l => l.status === 'converted').length,
      lost: leads.filter(l => l.status === 'lost').length,
    };
    return stats;
  };

  return {
    leads,
    loading,
    saving,
    createLead,
    updateLead,
    deleteLead,
    refreshLeads: fetchLeads,
    getLeadStats,
  };
}

export function useLeadInteractions(leadId: string | null) {
  const { user } = useAuth();
  const { t } = useTranslation();
  const [interactions, setInteractions] = useState<LeadInteraction[]>([]);
  const [loading, setLoading] = useState(false);

  const fetchInteractions = useCallback(async () => {
    if (!user || !leadId) return;

    try {
      setLoading(true);
      const { data, error } = await supabase
        .from('lead_interactions')
        .select('*')
        .eq('lead_id', leadId)
        .order('created_at', { ascending: false });

      if (error) throw error;
      setInteractions((data as LeadInteraction[]) || []);
    } catch (error) {
      logger.error('Error fetching interactions', error, { context: 'useLeads', data: { leadId } });
    } finally {
      setLoading(false);
    }
  }, [user, leadId]);

  useEffect(() => {
    fetchInteractions();
  }, [fetchInteractions]);

  const addInteraction = async (type: InteractionType, content: string) => {
    if (!user || !leadId) return null;

    try {
      const { data, error } = await supabase
        .from('lead_interactions')
        .insert({
          lead_id: leadId,
          user_id: user.id,
          type,
          content,
        })
        .select()
        .single();

      if (error) throw error;

      setInteractions(prev => [data as LeadInteraction, ...prev]);
      return data as LeadInteraction;
    } catch (error) {
      logger.error('Error adding interaction', error, { context: 'useLeads', data: { leadId } });
      toast.error(t('toasts.leads.interactionError'));
      return null;
    }
  };

  return {
    interactions,
    loading,
    addInteraction,
    refreshInteractions: fetchInteractions,
  };
}

import { useCallback, useEffect, useRef, useMemo } from 'react';
import { useRouter } from 'next/navigation';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';

import { useAuth } from '@/hooks/user/useAuth';
import { useCloudPageState } from '@/hooks/page/useCloudPageState';
import { usePremiumStatus } from '@/hooks/user/usePremiumStatus';
import { useUserProfile } from '@/hooks/user/useUserProfile';
import { useBlockEditor } from '@/hooks/editor/useBlockEditor';
import { useDashboardSharing } from '@/hooks/dashboard/useDashboardSharing';
import { useDashboardAI } from '@/hooks/dashboard/useDashboardAI';
import { useDashboardOnboarding } from '@/hooks/dashboard/useDashboardOnboarding';
import { useDashboardUsername } from '@/hooks/dashboard/useDashboardUsername';
import { useDashboardAuthGuard } from '@/hooks/dashboard/useDashboardAuthGuard';
import { useAchievements } from '@/hooks/user/useAchievements';
import { useSoundEffects } from '@/hooks/ui/useSoundEffects';
import { useHapticFeedback } from '@/hooks/ui/useHapticFeedback';


import type { Block, PageData } from '@/types/page';
import type { Niche } from '@/lib/niches';

interface UseDashboardOptions {
  onPublish?: (pageData: PageData) => void;
}

export function useDashboard(options?: UseDashboardOptions) {
  const { t } = useTranslation();
  const router = useRouter();
  const { user } = useAuth();
  const sounds = useSoundEffects();
  const haptics = useHapticFeedback();

  // Premium status
  const { isPremium, tier, isLoading: premiumLoading } = usePremiumStatus();

  // Cloud page state (data, save, publish, block CRUD)
  const cloudState = useCloudPageState({ onPublish: options?.onPublish });

  // Auth guard
  useDashboardAuthGuard({ isLoading: cloudState.loading });

  // User profile
  const userProfile = useUserProfile(user?.id);

  // Achievements
  const achievements = useAchievements();

  // Profile block helper
  const profileBlock = useMemo(() => {
    return cloudState.pageData?.blocks.find(b => b.type === 'profile') || null;
  }, [cloudState.pageData?.blocks]);

  // Handle update profile (name/bio on profile block)
  const handleUpdateProfile = useCallback((updates: { name: string; bio: string }) => {
    if (!cloudState.pageData) return;
    const profileIdx = cloudState.pageData.blocks.findIndex(b => b.type === 'profile');
    if (profileIdx === -1) return;

    const profileBlk = cloudState.pageData.blocks[profileIdx];
    cloudState.updateBlock(profileBlk.id, {
      ...updates,
    } as Partial<Block>);
  }, [cloudState]);

  // Block editor
  const blockEditor = useBlockEditor({
    isPremium,
    addBlock: cloudState.addBlock,
    updateBlock: cloudState.updateBlock,
    deleteBlock: cloudState.deleteBlock,
    blocks: cloudState.pageData?.blocks || [],
    playAdd: sounds.playAdd,
    playDelete: sounds.playDelete,
    playError: sounds.playError,
    hapticSuccess: haptics.success,
  });

  // Sharing state
  const sharingState = useDashboardSharing({
    onPublish: cloudState.publish,
    onSave: cloudState.save,
  });

  // AI state
  const aiState = useDashboardAI({
    onUpdateProfile: handleUpdateProfile,
    onAddBlock: cloudState.addBlock,
    onReplaceBlocks: cloudState.replaceBlocks,
  });

  // Username state
  const usernameState = useDashboardUsername({
    userId: user?.id,
    initialUsername: userProfile.profile?.username,
    onSaveSuccess: async () => {
      await userProfile.refresh();
    },
  });

  // Onboarding state
  const handleNicheComplete = useCallback(
    (profile: { name: string; bio: string }, blocks: Block[], niche: Niche) => {
      handleUpdateProfile(profile);
      // APPEND new blocks to existing ones (don't replace)
      blocks.forEach((block) => {
        cloudState.addBlock(block);
      });
      cloudState.updateNiche(niche);
    },
    [handleUpdateProfile, cloudState]
  );

  const onboardingState = useDashboardOnboarding({
    isUserReady: !!user,
    isPageReady: !!cloudState.pageData,
    blockCount: cloudState.pageData?.blocks.length || 0,
    onNicheComplete: handleNicheComplete,
  });

  // Handle apply template
  const handleApplyTemplate = useCallback((blocks: Block[]) => {
    cloudState.replaceBlocks(blocks);
    toast.success(t('dashboard.templateApplied', 'Template applied!'));
  }, [cloudState, t]);

  // Handle sign out
  const handleSignOut = useCallback(async () => {
    const { supabase } = await import('@/platform/supabase/client');
    await supabase.auth.signOut();
    router.push('/');
  }, [router]);

  // Current tier string
  const currentTier = isPremium ? (tier || 'pro') : 'free';

  return useMemo(() => ({
    // Auth
    user,
    handleSignOut,

    // Page data
    pageData: cloudState.pageData,
    loading: cloudState.loading,
    saving: cloudState.saving,
    saveStatus: cloudState.saveStatus,

    // Profile
    profileBlock,
    handleUpdateProfile,
    userProfile,

    // Premium
    isPremium,
    currentTier,
    premiumLoading,

    // Block operations
    updateBlock: cloudState.updateBlock,
    reorderBlocks: cloudState.reorderBlocks,
    updatePageDataPartial: cloudState.updatePageDataPartial,
    updateNiche: cloudState.updateNiche,

    // Sub-state hooks
    blockEditor,
    sharingState,
    aiState,
    usernameState,
    onboardingState,
    achievements,

    // Template
    handleApplyTemplate,
  }), [
    user,
    handleSignOut,
    cloudState.pageData,
    cloudState.loading,
    cloudState.saving,
    cloudState.saveStatus,
    cloudState.updateBlock,
    cloudState.reorderBlocks,
    cloudState.updatePageDataPartial,
    cloudState.updateNiche,
    profileBlock,
    handleUpdateProfile,
    userProfile,
    isPremium,
    currentTier,
    premiumLoading,
    blockEditor,
    sharingState,
    aiState,
    usernameState,
    onboardingState,
    achievements,
    handleApplyTemplate,
  ]);
}

import { useState, useEffect, useCallback } from 'react';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';
import type { Block } from '@/types/page';
import type { Niche } from '@/lib/niches';

import { storage } from '@/lib/storage';

const STORAGE_KEYS = {
  AI_BUILDER_USED: 'ai_builder_used',
  NICHE_COMPLETED: 'niche_onboarding_completed',
  ONBOARDING_COMPLETED: 'onboarding_completed',
} as const;

/** Minimum block count to skip onboarding (user already has content) */
const MIN_BLOCKS_TO_SKIP_ONBOARDING = 2;

interface OnboardingProfile {
  name: string;
  bio: string;
}

interface UseDashboardOnboardingOptions {
  isUserReady: boolean;
  isPageReady: boolean;
  /** Current block count on the page */
  blockCount: number;
  onNicheComplete: (profile: OnboardingProfile, blocks: Block[], niche: Niche) => void;
}

export function useDashboardOnboarding({
  isUserReady,
  isPageReady,
  blockCount,
  onNicheComplete,
}: UseDashboardOnboardingOptions) {
  const { t } = useTranslation();
  const [showAIBuilderWizard, setShowAIBuilderWizard] = useState(false);

  // Check onboarding status on mount — show wizard ONLY for brand-new users
  useEffect(() => {
    if (!isUserReady || !isPageReady) return;

    const hasUsedAIBuilder = storage.get<string>(STORAGE_KEYS.AI_BUILDER_USED);
    const hasCompletedNiche = storage.get<string>(STORAGE_KEYS.NICHE_COMPLETED);
    const hasCompletedOnboarding = storage.get<string>(STORAGE_KEYS.ONBOARDING_COMPLETED);

    // Skip if user already has content (more than 2 blocks)
    const hasExistingContent = blockCount > MIN_BLOCKS_TO_SKIP_ONBOARDING;

    if (hasExistingContent || hasUsedAIBuilder || hasCompletedNiche || hasCompletedOnboarding) {
      // Auto-mark as completed
      if (!hasCompletedNiche) storage.set(STORAGE_KEYS.NICHE_COMPLETED, 'true');
      if (!hasCompletedOnboarding) storage.set(STORAGE_KEYS.ONBOARDING_COMPLETED, 'true');
      return;
    }

    // New user with no content — show AI Builder wizard
    setTimeout(() => setShowAIBuilderWizard(true), 500);
  }, [isUserReady, isPageReady, blockCount]);

  const handleAIBuilderClose = useCallback(() => {
    storage.set(STORAGE_KEYS.NICHE_COMPLETED, 'true');
    storage.set(STORAGE_KEYS.ONBOARDING_COMPLETED, 'true');
    setShowAIBuilderWizard(false);
  }, []);

  const handleAIBuilderComplete = useCallback(
    (profile: OnboardingProfile, blocks: Block[], niche: Niche) => {
      onNicheComplete(profile, blocks, niche);
      storage.set(STORAGE_KEYS.AI_BUILDER_USED, 'true');
      storage.set(STORAGE_KEYS.NICHE_COMPLETED, 'true');
      storage.set(STORAGE_KEYS.ONBOARDING_COMPLETED, 'true');
      setShowAIBuilderWizard(false);
    },
    [onNicheComplete]
  );

  // Manual open from settings (for existing users)
  const openAIBuilderFromSettings = useCallback(() => {
    setShowAIBuilderWizard(true);
  }, []);

  return {
    showAIBuilderWizard,
    handleAIBuilderClose,
    handleAIBuilderComplete,
    openAIBuilderFromSettings,
  };
}

import { useState, useCallback } from 'react';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';
import { getPublicPageUrl, copyToClipboard } from '@/lib/utils/url-helpers';
import { incrementChallengeProgress, recordActivity } from '@/services/social';

const STORAGE_KEYS = {
  INSTALL_PROMPT_SHOWN: 'linkmax_install_prompt_shown',
  SHARE_DIALOG_COUNT: 'linkmax_share_dialog_count',
} as const;

interface UseDashboardSharingOptions {
  onPublish: () => Promise<string | null>;
  onSave: () => Promise<void>;
  onQuestComplete?: (questKey: string) => void;
  onSaveVersion?: () => Promise<void>;
}

/**
 * Hook to manage sharing, preview, referral dialog, and install prompt logic
 */
export function useDashboardSharing({ onPublish, onSave, onQuestComplete, onSaveVersion }: UseDashboardSharingOptions) {
  const { t } = useTranslation();
  const [showInstallPrompt, setShowInstallPrompt] = useState(false);
  const [showShareDialog, setShowShareDialog] = useState(false);
  const [publishedUrl, setPublishedUrl] = useState('');

  const handleShare = useCallback(async () => {
    const slug = await onPublish();
    if (!slug) return;

    // Save version snapshot on publish
    await onSaveVersion?.();

    // Mark page as published for achievements
    localStorage.setItem('linkmax_published', 'true');

    const url = getPublicPageUrl(slug);
    setPublishedUrl(url);
    
    const copied = await copyToClipboard(url);

    if (copied) {
      toast.success(t('toasts.sharing.linkCopied'));
      // Trigger share_page quest
      onQuestComplete?.('share_page');
      // Track challenge progress
      incrementChallengeProgress('share_page');
      // Record activity for friends feed
      recordActivity('page_published', { slug });
    } else {
      toast.error(t('toasts.sharing.copyError'));
    }

    // Show share/referral dialog periodically (every 3 publishes)
    const shareCount = parseInt(localStorage.getItem(STORAGE_KEYS.SHARE_DIALOG_COUNT) || '0', 10);
    const newCount = shareCount + 1;
    localStorage.setItem(STORAGE_KEYS.SHARE_DIALOG_COUNT, newCount.toString());
    
    // Show on first publish and every 3rd publish
    if (newCount === 1 || newCount % 3 === 0) {
      setTimeout(() => setShowShareDialog(true), 500);
    }

    // Show install prompt for first-time publishers
    const hasSeenInstallPrompt = localStorage.getItem(STORAGE_KEYS.INSTALL_PROMPT_SHOWN);
    if (!hasSeenInstallPrompt && newCount === 1) {
      setTimeout(() => setShowInstallPrompt(true), 2000);
      localStorage.setItem(STORAGE_KEYS.INSTALL_PROMPT_SHOWN, 'true');
    }
  }, [onPublish, onQuestComplete, onSaveVersion, t]);

  const handlePreview = useCallback(async () => {
    await onSave();
    const slug = await onPublish();
    if (slug) {
      window.open(`/${slug}`, '_blank');
    }
  }, [onSave, onPublish]);

  const closeInstallPrompt = useCallback(() => {
    setShowInstallPrompt(false);
  }, []);

  const closeShareDialog = useCallback(() => {
    setShowShareDialog(false);
  }, []);

  return {
    showInstallPrompt,
    showShareDialog,
    publishedUrl,
    handleShare,
    handlePreview,
    closeInstallPrompt,
    closeShareDialog,
  };
}

/**
 * Dashboard v2 State Hook
 * Provides state management for the new dashboard layout
 */
import { useState, useCallback, useMemo } from 'react';
import { useNavigate, useSearchParams } from 'react-router-dom';
import { useDashboard } from '@/hooks/dashboard/useDashboard';
import { usePremiumStatus } from '@/hooks/user/usePremiumStatus';
import { usePageAnalytics } from '@/hooks/analytics/usePageAnalytics';
import { useLeads } from '@/hooks/crm/useLeads';

export type DashboardTab = 'home' | 'pages' | 'activity' | 'insights' | 'monetize' | 'settings';

export function useDashboardV2() {
  const navigate = useNavigate();
  const [searchParams, setSearchParams] = useSearchParams();
  const dashboard = useDashboard();
  const { isPremium, tier, inTrial, trialEndsAt, isLoading: premiumLoading } = usePremiumStatus();
  const { analytics, loading: analyticsLoading } = usePageAnalytics();
  const { leads, loading: leadsLoading, getLeadStats } = useLeads();

  // Current active tab from URL
  const activeTab = useMemo<DashboardTab>(() => {
    const tab = searchParams.get('tab');
    const validTabs: DashboardTab[] = ['home', 'pages', 'activity', 'insights', 'monetize', 'settings'];
    if (tab && validTabs.includes(tab as DashboardTab)) {
      return tab as DashboardTab;
    }
    return 'home';
  }, [searchParams]);

  // Change tab
  const setActiveTab = useCallback((tab: DashboardTab) => {
    setSearchParams({ tab });
  }, [setSearchParams]);

  // Activity badge count (leads + registrations)
  const activityBadge = useMemo(() => {
    return leads.filter(l => l.status === 'new').length;
  }, [leads]);

  // Page list for PagesScreen
  const pages = useMemo(() => {
    if (!dashboard.pageData) return [];

    // Currently single page, but structure supports multiple
    return [{
      id: dashboard.pageData.id,
      title: dashboard.profileBlock?.name || 'My Page',
      slug: dashboard.pageData.slug,
      isPublished: dashboard.pageData.isPublished,
      updatedAt: new Date().toISOString(),
      viewCount: analytics?.totalViews || 0,
      coverUrl: undefined,
    }];
  }, [dashboard.pageData, dashboard.profileBlock, analytics]);

  // Quick stats for HomeScreen
  const quickStats = useMemo(() => {
    return {
      views: analytics?.totalViews || 0,
      leads: leads.length || 0,
      conversions: analytics?.totalConversions || 0,
    };
  }, [analytics, leads]);

  // Handle navigation to editor
  const openEditor = useCallback(() => {
    setSearchParams({ tab: 'editor' });
  }, [setSearchParams]);

  // Handle preview
  const handlePreview = useCallback(() => {
    dashboard.sharingState.handlePreview();
  }, [dashboard.sharingState]);

  // Handle share
  const handleShare = useCallback(() => {
    dashboard.sharingState.handleShare();
  }, [dashboard.sharingState]);

  // Handle sign out
  const handleSignOut = useCallback(() => {
    dashboard.handleSignOut();
  }, [dashboard.handleSignOut]);

  // Handle upgrade click
  const handleUpgrade = useCallback(() => {
    navigate('/pricing');
  }, [navigate]);

  return {
    // Core state
    user: dashboard.user,
    pageData: dashboard.pageData,
    profileBlock: dashboard.profileBlock,
    loading: dashboard.loading,
    saving: dashboard.saving,
    saveStatus: dashboard.saveStatus,

    // Tab state
    activeTab,
    setActiveTab,

    // Premium state
    isPremium,
    tier: tier || 'free',
    inTrial: inTrial || false,
    trialEndsAt,
    premiumLoading,

    // Data
    pages,
    quickStats,
    activityBadge,

    // Actions
    openEditor,
    handlePreview,
    handleShare,
    handleSignOut,
    handleUpgrade,

    // Pass through dashboard for legacy compatibility
    dashboard,
  };
}

import { useState, useCallback, useRef } from 'react';
import { useTranslation } from 'react-i18next';
import { toast } from 'sonner';
import { Button } from '@/components/ui/button';
import { Undo2 } from 'lucide-react';
import { createBlock } from '@/lib/blocks/block-factory';
import { PREMIUM_BLOCK_TYPES } from '@/lib/blocks/block-registry';
import { APP_CONFIG } from '@/lib/constants';
import { incrementChallengeProgress, recordActivity } from '@/services/social';
import type { Block, BlockType } from '@/types/page';
import type { DeletedBlockInfo, BlockInsertResult } from '@/types/block-editor-types';

interface UseBlockEditorOptions {
  isPremium: boolean;
  addBlock: (block: Block, position?: number) => void;
  updateBlock: (id: string, updates: Partial<Block>) => void;
  deleteBlock: (id: string) => void;
  blocks: Block[];
  playAdd?: () => void;
  playDelete?: () => void;
  playError?: () => void;
  hapticSuccess?: () => void;
  onBlockHint?: (blockType: string, blockId: string) => void;
  onQuestComplete?: (questKey: string) => void;
  onClaimBlockToken?: () => Promise<boolean>;
}

/**
 * Hook to manage block editing operations with undo support
 * 
 * Provides:
 * - Block insertion with premium checks
 * - Block editing modal state
 * - Block deletion with undo capability
 * - Sound and haptic feedback integration
 */
export function useBlockEditor({
  isPremium,
  addBlock,
  updateBlock,
  deleteBlock,
  blocks,
  playAdd,
  playDelete,
  playError,
  hapticSuccess,
  onBlockHint,
  onQuestComplete,
  onClaimBlockToken,
}: UseBlockEditorOptions) {
  const { t } = useTranslation();
  const [editingBlock, setEditingBlock] = useState<Block | null>(null);
  const [editorOpen, setEditorOpen] = useState(false);
  const [deletedBlocks, setDeletedBlocks] = useState<DeletedBlockInfo[]>([]);
  
  // Track if an operation is in progress to prevent race conditions
  const operationInProgressRef = useRef(false);

  /**
   * Check if block type requires premium subscription
   */
  const isPremiumBlock = useCallback(
    (blockType: string): boolean => {
      return (PREMIUM_BLOCK_TYPES as readonly string[]).includes(blockType) && !isPremium;
    },
    [isPremium]
  );

  /**
   * Insert a new block at specified position
   */
  const handleInsertBlock = useCallback(
    (blockType: string, position: number): BlockInsertResult => {
      try {
        // Check premium requirement
        if (isPremiumBlock(blockType)) {
          toast.error(t('blocks.premiumRequired', 'This block requires Premium'));
          playError?.();
          return { success: false, error: 'Premium required' };
        }

        const newBlock = createBlock(blockType);
        addBlock(newBlock, position);
        playAdd?.();
        toast.success(t('blocks.added', 'Block added'));
        onBlockHint?.(blockType, newBlock.id);
        
        // Trigger add_block quest
        onQuestComplete?.('add_block');
        // Claim token reward for adding block (once per day)
        onClaimBlockToken?.();
        // Track challenge progress
        incrementChallengeProgress('add_blocks');
        recordActivity('new_block', { block_type: blockType });
        
        return { success: true, blockId: newBlock.id };
      } catch (error) {
        toast.error(t('blocks.addFailed', 'Failed to add block'));
        playError?.();
        return { success: false, error: 'Block creation failed' };
      }
    },
    [isPremiumBlock, addBlock, playAdd, playError, onBlockHint, onQuestComplete, onClaimBlockToken]
  );

  /**
   * Open block editor for a specific block
   */
  const handleEditBlock = useCallback((block: Block) => {
    setEditingBlock(block);
    setEditorOpen(true);
  }, []);

  /**
   * Save block changes and close editor
   */
  const handleSaveBlock = useCallback(
    (updates: Partial<Block>) => {
      if (editingBlock) {
        updateBlock(editingBlock.id, updates);
        // Don't close here - BlockEditorV2.performSave calls onClose() separately
      }
    },
    [editingBlock, updateBlock]
  );

  /**
   * Close block editor without saving
   */
  const closeEditor = useCallback(() => {
    setEditorOpen(false);
    // Delay clearing editingBlock so Drawer/Dialog can animate closed
    // before the component unmounts
    setTimeout(() => {
      setEditingBlock(null);
    }, 350);
  }, []);

  /**
   * Delete block with undo support
   * Profile blocks cannot be deleted
   */
  const handleDeleteBlock = useCallback(
    (blockId: string) => {
      // Prevent concurrent operations
      if (operationInProgressRef.current) return;
      
      const blockIndex = blocks.findIndex((b) => b.id === blockId);
      const block = blocks.find((b) => b.id === blockId);

      // Prevent profile block deletion
      if (!block || block.type === 'profile') return;

      operationInProgressRef.current = true;

      // Store for undo
      const deletedInfo: DeletedBlockInfo = {
        block,
        position: blockIndex,
        blockId: block.id,
        deletedAt: Date.now(),
      };

      setDeletedBlocks((prev) => [...prev, deletedInfo]);

      // Auto-remove from undo stack after timeout
      setTimeout(() => {
        setDeletedBlocks((prev) => prev.filter((d) => d.blockId !== block.id));
      }, APP_CONFIG.undoTimeout);

      // Perform deletion
      deleteBlock(blockId);
      playDelete?.();
      
      // Reset operation flag after a short delay
      setTimeout(() => {
        operationInProgressRef.current = false;
      }, 100);

      // Show toast with undo button
      toast(
        <div className="flex items-center gap-3">
          <span>{t('blocks.deleted', 'Block deleted')}</span>
          <Button
            size="sm"
            variant="outline"
            className="h-7 px-2 gap-1"
            onClick={(e) => {
              e.stopPropagation();
              if (operationInProgressRef.current) return;
              operationInProgressRef.current = true;
              
              hapticSuccess?.();
              addBlock(block, blockIndex);
              setDeletedBlocks((prev) => prev.filter((d) => d.blockId !== block.id));
              toast.success(t('blocks.restored', 'Block restored'));
              
              setTimeout(() => {
                operationInProgressRef.current = false;
              }, 100);
            }}
          >
            <Undo2 className="h-3.5 w-3.5" />
            {t('editor.undo', 'Undo')}
          </Button>
        </div>,
        { duration: APP_CONFIG.undoTimeout }
      );
    },
    [blocks, deleteBlock, addBlock, playDelete, hapticSuccess, t]
  );

  /**
   * Restore last deleted block
   */
  const undoLastDelete = useCallback(() => {
    if (operationInProgressRef.current) return;
    
    const lastDeleted = deletedBlocks[deletedBlocks.length - 1];
    if (!lastDeleted) return;

    operationInProgressRef.current = true;
    hapticSuccess?.();
    addBlock(lastDeleted.block, lastDeleted.position);
    setDeletedBlocks((prev) => prev.slice(0, -1));
    toast.success(t('blocks.restored', 'Block restored'));
    
    setTimeout(() => {
      operationInProgressRef.current = false;
    }, 100);
  }, [deletedBlocks, addBlock, hapticSuccess, t]);

  return {
    // Editor state
    editingBlock,
    editorOpen,

    // Block operations
    handleInsertBlock,
    handleEditBlock,
    handleSaveBlock,
    handleDeleteBlock,
    closeEditor,

    // Undo
    deletedBlocks,
    undoLastDelete,
    hasUndo: deletedBlocks.length > 0,

    // Helpers
    isPremiumBlock,
  };
}

/**
 * useEditorHistory - Undo/Redo system with 7-step history
 * Provides complete action history management for the editor
 */
import { useState, useCallback, useRef } from 'react';
import { toast } from 'sonner';
import { useTranslation } from 'react-i18next';
import type { Block } from '@/types/page';

export interface HistoryAction {
  id: string;
  type: 'add' | 'delete' | 'update' | 'reorder' | 'bulk';
  label: string;
  timestamp: number;
  previousState: Block[];
  newState: Block[];
  blockId?: string;
  blockType?: string;
}

interface UseEditorHistoryOptions {
  maxHistorySize?: number;
  onStateChange?: (blocks: Block[]) => void;
}

const MAX_HISTORY_SIZE = 7;

export type EditorHistoryType = ReturnType<typeof useEditorHistory>;

export function useEditorHistory(
  initialBlocks: Block[],
  options: UseEditorHistoryOptions = {}
) {
  const { t } = useTranslation();
  const { maxHistorySize = MAX_HISTORY_SIZE, onStateChange } = options;
  
  const [history, setHistory] = useState<HistoryAction[]>([]);
  const [currentIndex, setCurrentIndex] = useState(-1);
  const [currentBlocks, setCurrentBlocks] = useState<Block[]>(initialBlocks);
  
  // Ref to track the last action for toast dismissal
  const lastToastIdRef = useRef<string | number | undefined>(undefined);

  // Can undo/redo
  const canUndo = currentIndex >= 0;
  const canRedo = currentIndex < history.length - 1;

  // Record a new action
  const recordAction = useCallback((
    type: HistoryAction['type'],
    previousState: Block[],
    newState: Block[],
    label: string,
    blockId?: string,
    blockType?: string
  ) => {
    const action: HistoryAction = {
      id: `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
      type,
      label,
      timestamp: Date.now(),
      previousState: [...previousState],
      newState: [...newState],
      blockId,
      blockType,
    };

    setHistory((prev) => {
      // Remove any future history if we're not at the end
      const newHistory = prev.slice(0, currentIndex + 1);
      // Add new action and limit to max size
      const updated = [...newHistory, action].slice(-maxHistorySize);
      return updated;
    });

    setCurrentIndex((prev) => Math.min(prev + 1, maxHistorySize - 1));
    setCurrentBlocks(newState);
    onStateChange?.(newState);

    // Show toast with undo option
    if (lastToastIdRef.current) {
      toast.dismiss(lastToastIdRef.current);
    }

    lastToastIdRef.current = toast(label, {
      description: t('editor.history.undoHint', 'Нажмите чтобы отменить'),
      action: {
        label: t('editor.undo', 'Отменить'),
        onClick: () => {
          // Will trigger undo
          undo();
        },
      },
      duration: 5000,
    });
  }, [currentIndex, maxHistorySize, onStateChange, t]);

  // Undo last action
  const undo = useCallback(() => {
    if (!canUndo) return null;

    const action = history[currentIndex];
    if (!action) return null;

    setCurrentBlocks(action.previousState);
    setCurrentIndex((prev) => prev - 1);
    onStateChange?.(action.previousState);

    toast.success(t('editor.history.undone', 'Действие отменено'), {
      description: action.label,
      duration: 2000,
    });

    return action;
  }, [canUndo, history, currentIndex, onStateChange, t]);

  // Redo action
  const redo = useCallback(() => {
    if (!canRedo) return null;

    const nextIndex = currentIndex + 1;
    const action = history[nextIndex];
    if (!action) return null;

    setCurrentBlocks(action.newState);
    setCurrentIndex(nextIndex);
    onStateChange?.(action.newState);

    toast.success(t('editor.history.redone', 'Действие повторено'), {
      description: action.label,
      duration: 2000,
    });

    return action;
  }, [canRedo, history, currentIndex, onStateChange, t]);

  // Clear history
  const clearHistory = useCallback(() => {
    setHistory([]);
    setCurrentIndex(-1);
  }, []);

  // Reset with new blocks (e.g., after loading)
  const resetWithBlocks = useCallback((blocks: Block[]) => {
    setCurrentBlocks(blocks);
    clearHistory();
  }, [clearHistory]);

  // Helper methods for common operations
  const recordBlockAdd = useCallback((
    previousBlocks: Block[],
    newBlocks: Block[],
    blockType: string,
    blockId: string
  ) => {
    recordAction(
      'add',
      previousBlocks,
      newBlocks,
      t('editor.history.blockAdded', 'Блок добавлен: {{type}}', { type: t(`blocks.${blockType}`, blockType) }),
      blockId,
      blockType
    );
  }, [recordAction, t]);

  const recordBlockDelete = useCallback((
    previousBlocks: Block[],
    newBlocks: Block[],
    blockType: string,
    blockId: string
  ) => {
    recordAction(
      'delete',
      previousBlocks,
      newBlocks,
      t('editor.history.blockDeleted', 'Блок удалён: {{type}}', { type: t(`blocks.${blockType}`, blockType) }),
      blockId,
      blockType
    );
  }, [recordAction, t]);

  const recordBlockUpdate = useCallback((
    previousBlocks: Block[],
    newBlocks: Block[],
    blockType: string,
    blockId: string
  ) => {
    recordAction(
      'update',
      previousBlocks,
      newBlocks,
      t('editor.history.blockUpdated', 'Блок изменён: {{type}}', { type: t(`blocks.${blockType}`, blockType) }),
      blockId,
      blockType
    );
  }, [recordAction, t]);

  const recordBlocksReorder = useCallback((
    previousBlocks: Block[],
    newBlocks: Block[]
  ) => {
    recordAction(
      'reorder',
      previousBlocks,
      newBlocks,
      t('editor.history.blocksReordered', 'Порядок блоков изменён')
    );
  }, [recordAction, t]);

  return {
    // Current state
    currentBlocks,
    history,
    currentIndex,
    
    // Capabilities
    canUndo,
    canRedo,
    historyLength: history.length,
    
    // Actions
    undo,
    redo,
    clearHistory,
    resetWithBlocks,
    
    // Recording helpers
    recordAction,
    recordBlockAdd,
    recordBlockDelete,
    recordBlockUpdate,
    recordBlocksReorder,
  };
}

/**
 * useMultiPage - Hook for multi-page state management
 * Handles page switching, limits, and CRUD operations
 */
import { useState, useEffect, useCallback, useMemo } from 'react';
import { useAuth } from '@/hooks/user/useAuth';
import { usePremiumStatus } from '@/hooks/user/usePremiumStatus';
import { supabase } from '@/platform/supabase/client';
import { logger } from '@/lib/utils/logger';
import { storage } from '@/lib/storage';

// ============= Types =============

export interface UserPage {
  id: string;
  title: string;
  slug: string;
  isPublished: boolean;
  isPaid: boolean;
  isPrimaryPaid: boolean;
  viewCount: number;
  updatedAt: string;
  createdAt: string;
  previewUrl?: string;
  custom_domain?: string | null;
}

export interface PageLimits {
  tier: 'free' | 'pro';
  currentPages: number;
  maxPages: number;
  paidPages: number;
  freePages: number;
  canCreate: boolean;
}

interface CreatePageResult {
  success: boolean;
  error?: string;
  pageId?: string;
  slug?: string;
  limits?: PageLimits;
}

// DB row type (columns that may not be in generated types yet)
interface PageRow {
  id: string;
  title: string | null;
  slug: string;
  is_published: boolean | null;
  is_paid?: boolean | null;
  is_primary_paid?: boolean | null;
  view_count: number | null;
  updated_at: string | null;
  created_at: string | null;
  preview_url: string | null;
  custom_domain?: string | null;
}

// ============= Constants =============

const ACTIVE_PAGE_KEY = 'active_page_id';

// ============= Hook =============

export function useMultiPage() {
  const { user } = useAuth();
  const { isPremium, tier } = usePremiumStatus();

  const [pages, setPages] = useState<UserPage[]>([]);
  const [activePageId, setActivePageId] = useState<string | null>(null);
  const [limits, setLimits] = useState<PageLimits | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // Get active page from list
  const activePage = useMemo(() => {
    if (!activePageId) return pages[0] || null;
    return pages.find(p => p.id === activePageId) || pages[0] || null;
  }, [pages, activePageId]);

  // Load user pages
  const loadPages = useCallback(async () => {
    if (!user?.id) {
      setPages([]);
      setLoading(false);
      return;
    }

    try {
      setLoading(true);
      setError(null);

      // Get pages directly from table (use * to include new columns)
      const { data: pagesData, error: pagesError } = await supabase
        .from('pages')
        .select('*')
        .eq('user_id', user.id)
        .order('created_at', { ascending: false });

      if (pagesError) {
        throw pagesError;
      }

      // Cast to our row type that includes new columns
      const rows = (pagesData || []) as unknown as PageRow[];

      const userPages: UserPage[] = rows.map((p) => ({
        id: p.id,
        title: p.title || 'Untitled',
        slug: p.slug,
        isPublished: p.is_published ?? false,
        isPaid: p.is_paid ?? false,
        isPrimaryPaid: p.is_primary_paid ?? false,
        viewCount: p.view_count ?? 0,
        updatedAt: p.updated_at || '',
        createdAt: p.created_at || '',
        previewUrl: p.preview_url ?? undefined,
        custom_domain: p.custom_domain,
      }));

      setPages(userPages);

      // Calculate limits based on user tier
      const userTier = isPremium ? 'pro' : 'free';
      const maxPages = userTier === 'free' ? 1 : 6;
      const paidPages = userPages.filter(p => p.isPaid).length;
      const freePages = userPages.filter(p => !p.isPaid).length;

      setLimits({
        tier: userTier,
        currentPages: userPages.length,
        maxPages,
        paidPages,
        freePages,
        canCreate: userPages.length < maxPages,
      });

      // Restore active page from storage
      const savedActiveId = storage.get<string>(ACTIVE_PAGE_KEY);
      if (savedActiveId && userPages.some(p => p.id === savedActiveId)) {
        setActivePageId(savedActiveId);
      } else if (userPages.length > 0) {
        setActivePageId(userPages[0].id);
      }

    } catch (err) {
      logger.error('Error loading pages', err, { context: 'useMultiPage' });
      setError(err instanceof Error ? err.message : 'Failed to load pages');
    } finally {
      setLoading(false);
    }
  }, [user?.id, isPremium]);

  // Initial load
  useEffect(() => {
    loadPages();
  }, [loadPages]);

  // Switch active page
  const switchPage = useCallback((pageId: string) => {
    if (pages.some(p => p.id === pageId)) {
      setActivePageId(pageId);
      storage.set(ACTIVE_PAGE_KEY, pageId);
    }
  }, [pages]);

  // Create new page
  const createPage = useCallback(async (title: string, slug?: string): Promise<CreatePageResult> => {
    if (!user?.id) {
      return { success: false, error: 'not_authenticated' };
    }

    // Check limits first
    const currentLimits = limits;
    if (currentLimits && !currentLimits.canCreate) {
      return {
        success: false,
        error: 'page_limit_exceeded',
        limits: currentLimits,
      };
    }

    try {
      // Generate a unique slug
      let finalSlug = slug?.toLowerCase().replace(/[^a-z0-9-]/g, '') || '';

      if (!finalSlug) {
        finalSlug = `page-${Date.now().toString(36)}`;
      }

      // Check slug uniqueness
      const { data: existingSlug } = await supabase
        .from('pages')
        .select('id')
        .eq('slug', finalSlug)
        .maybeSingle();

      if (existingSlug) {
        finalSlug = `${finalSlug}-${Date.now().toString(36).slice(-4)}`;
      }

      // Create the page (use insert with object that matches existing schema)
      const { data: newPage, error: createError } = await supabase
        .from('pages')
        .insert({
          user_id: user.id,
          title: title || 'My Page',
          slug: finalSlug,
          theme_settings: {
            backgroundColor: 'hsl(var(--background))',
            textColor: 'hsl(var(--foreground))',
            buttonStyle: 'rounded',
            fontFamily: 'sans',
          },
          seo_meta: {
            title: title || 'My lnkmx.my Page',
            description: 'Check out my links',
            keywords: [],
          },
          editor_mode: 'grid',
        })
        .select('id, slug')
        .single();

      if (createError) {
        throw createError;
      }

      // Create default profile block
      if (newPage) {
        await supabase
          .from('blocks')
          .insert({
            page_id: newPage.id,
            type: 'profile',
            position: 0,
            content: {
              id: `profile-${newPage.id}`,
              type: 'profile',
              name: title || 'My Page',
            },
            is_premium: false,
          });
      }

      // Refresh pages list
      await loadPages();

      // Switch to new page
      if (newPage?.id) {
        switchPage(newPage.id);
      }

      return {
        success: true,
        pageId: newPage?.id,
        slug: newPage?.slug,
      };
    } catch (err) {
      logger.error('Error creating page', err, { context: 'useMultiPage' });
      return {
        success: false,
        error: err instanceof Error ? err.message : 'Failed to create page',
      };
    }
  }, [user?.id, limits, loadPages, switchPage]);

  // Set primary paid page
  const setPrimaryPaidPage = useCallback(async (pageId: string): Promise<{ success: boolean; error?: string }> => {
    if (!user?.id) {
      return { success: false, error: 'not_authenticated' };
    }

    if (!isPremium) {
      return { success: false, error: 'pro_required' };
    }

    try {
      // Verify page belongs to user
      const page = pages.find(p => p.id === pageId);
      if (!page) {
        return { success: false, error: 'page_not_found' };
      }

      // Use raw SQL via RPC since columns may not be in types yet
      // For now, we'll just refresh the pages
      await loadPages();

      return { success: true };
    } catch (err) {
      logger.error('Error setting primary paid page', err, { context: 'useMultiPage' });
      return {
        success: false,
        error: err instanceof Error ? err.message : 'Failed to set primary paid page',
      };
    }
  }, [user?.id, isPremium, pages, loadPages]);

  // Delete page
  const deletePage = useCallback(async (pageId: string): Promise<{ success: boolean; error?: string }> => {
    if (!user?.id) {
      return { success: false, error: 'not_authenticated' };
    }

    // Cannot delete if only one page
    if (pages.length <= 1) {
      return { success: false, error: 'cannot_delete_last_page' };
    }

    try {
      const { error: deleteError } = await supabase
        .from('pages')
        .delete()
        .eq('id', pageId)
        .eq('user_id', user.id);

      if (deleteError) {
        throw deleteError;
      }

      // If deleted page was active, switch to first remaining
      if (activePageId === pageId) {
        const remaining = pages.filter(p => p.id !== pageId);
        if (remaining.length > 0) {
          switchPage(remaining[0].id);
        }
      }

      // Refresh pages
      await loadPages();

      return { success: true };
    } catch (err) {
      logger.error('Error deleting page', err, { context: 'useMultiPage', data: { pageId } });
      return {
        success: false,
        error: err instanceof Error ? err.message : 'Failed to delete page',
      };
    }
  }, [user?.id, pages, activePageId, loadPages, switchPage]);

  // Update page slug
  const updatePageSlug = useCallback(async (pageId: string, newSlug: string): Promise<{ success: boolean; error?: string }> => {
    if (!user?.id) {
      return { success: false, error: 'not_authenticated' };
    }

    // Validate slug
    const slugRegex = /^[a-z0-9-]+$/;
    if (!slugRegex.test(newSlug) || newSlug.length < 3 || newSlug.length > 30) {
      return { success: false, error: 'invalid_slug' };
    }

    try {
      // Check slug availability
      const { data: existing } = await supabase
        .from('pages')
        .select('id')
        .eq('slug', newSlug)
        .neq('id', pageId)
        .maybeSingle();

      if (existing) {
        return { success: false, error: 'slug_taken' };
      }

      const { error: updateError } = await supabase
        .from('pages')
        .update({ slug: newSlug })
        .eq('id', pageId)
        .eq('user_id', user.id);

      if (updateError) {
        throw updateError;
      }

      await loadPages();

      return { success: true };
    } catch (err) {
      logger.error('Error updating slug', err, { context: 'useMultiPage', data: { pageId, newSlug } });
      return {
        success: false,
        error: err instanceof Error ? err.message : 'Failed to update slug',
      };
    }
  }, [user?.id, loadPages]);

  // Update custom domain
  const updatePageCustomDomain = useCallback(async (pageId: string, customDomain: string | null): Promise<{ success: boolean; error?: string }> => {
    if (!user?.id) {
      return { success: false, error: 'not_authenticated' };
    }

    // Basic format check if not null
    if (customDomain) {
      const domainRegex = /^(?:[a-z0-9](?:[a-z0-9-]{0,61}[a-z0-9])?\.)+[a-z0-9][a-z0-9-]{0,61}[a-z0-9]$/i;
      if (!domainRegex.test(customDomain)) {
        return { success: false, error: 'invalid_domain_format' };
      }
    }

    try {
      const { error: updateError } = await supabase
        .from('pages')
        .update({ custom_domain: customDomain } as any)
        .eq('id', pageId)
        .eq('user_id', user.id);

      if (updateError) {
        if (updateError.code === '23505') return { success: false, error: 'domain_taken' };
        throw updateError;
      }

      await loadPages();

      return { success: true };
    } catch (err) {
      logger.error('Error updating custom domain', err, { context: 'useMultiPage', data: { pageId, customDomain } });
      return {
        success: false,
        error: err instanceof Error ? err.message : 'Failed to update custom domain',
      };
    }
  }, [user?.id, loadPages]);

  return {
    // State
    pages,
    activePage,
    activePageId,
    limits,
    loading,
    error,
    isPremium,
    tier,

    // Actions
    loadPages,
    switchPage,
    createPage,
    deletePage,
    updatePageSlug,
    setPrimaryPaidPage,
    updatePageCustomDomain,
  };
}

/**
 * usePageVersions - Hook for managing page version history
 * Saves up to 5 versions when publishing, allows restoring previous versions
 */
import { useState, useCallback } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { logger } from '@/lib/utils/logger';
import { toast } from 'sonner';
import type { Block, PageTheme } from '@/types/page';
import type { Json } from '@/platform/supabase/types';

export interface PageVersion {
  id: string;
  versionId: string;
  publishedAt: string;
  blocks: Block[];
  theme?: PageTheme;
  seo?: { title?: string; description?: string };
}

interface UsePageVersionsResult {
  versions: PageVersion[];
  loading: boolean;
  fetchVersions: (pageId: string) => Promise<void>;
  saveVersion: (pageId: string, blocks: Block[], theme?: PageTheme, seo?: object) => Promise<boolean>;
  restoreVersion: (version: PageVersion) => void;
}

const MAX_VERSIONS = 5;

export function usePageVersions(onRestore?: (blocks: Block[], theme?: PageTheme, seo?: object) => void): UsePageVersionsResult {
  const [versions, setVersions] = useState<PageVersion[]>([]);
  const [loading, setLoading] = useState(false);

  const fetchVersions = useCallback(async (pageId: string) => {
    if (!pageId) return;

    setLoading(true);
    try {
      const { data, error } = await (supabase as any)
        .from('page_snapshots')
        .select('*')
        .eq('page_id', pageId)
        .order('published_at', { ascending: false })
        .limit(MAX_VERSIONS);

      if (error) throw error;

      const mapped: PageVersion[] = (data || []).map((row: any) => ({
        id: row.id,
        versionId: row.version_id,
        publishedAt: row.published_at,
        blocks: row.blocks_json as unknown as Block[],
        theme: row.theme_json as unknown as PageTheme | undefined,
        seo: row.seo_json as unknown as { title?: string; description?: string } | undefined,
      }));

      setVersions(mapped);
    } catch (err) {
      logger.error('Failed to fetch versions', err, { context: 'usePageVersions' });
    } finally {
      setLoading(false);
    }
  }, []);

  const saveVersion = useCallback(async (
    pageId: string,
    blocks: Block[],
    theme?: PageTheme,
    seo?: object
  ): Promise<boolean> => {
    if (!pageId) return false;

    try {
      // Generate content hash for deduplication
      const contentHash = btoa(JSON.stringify(blocks).slice(0, 100));
      const versionId = `v-${Date.now()}`;

      // Insert new version
      const { error: insertError } = await (supabase as any)
        .from('page_snapshots')
        .insert({
          page_id: pageId,
          version_id: versionId,
          blocks_json: JSON.parse(JSON.stringify(blocks)) as Json,
          theme_json: theme ? (JSON.parse(JSON.stringify(theme)) as Json) : null,
          seo_json: seo ? (JSON.parse(JSON.stringify(seo)) as Json) : null,
          content_hash: contentHash,
          published_at: new Date().toISOString(),
        });

      if (insertError) throw insertError;

      // Clean up old versions (keep only MAX_VERSIONS)
      const { data: allVersions } = await (supabase as any)
        .from('page_snapshots')
        .select('id, published_at')
        .eq('page_id', pageId)
        .order('published_at', { ascending: false });

      if (allVersions && allVersions.length > MAX_VERSIONS) {
        const toDelete = allVersions.slice(MAX_VERSIONS).map((v: any) => v.id);
        await (supabase as any)
          .from('page_snapshots')
          .delete()
          .in('id', toDelete);
      }

      // Refresh versions list
      await fetchVersions(pageId);

      return true;
    } catch (err) {
      logger.error('Failed to save version', err, { context: 'usePageVersions' });
      return false;
    }
  }, [fetchVersions]);

  const restoreVersion = useCallback((version: PageVersion) => {
    if (onRestore) {
      onRestore(version.blocks, version.theme, version.seo);
      toast.success('Версия восстановлена');
    }
  }, [onRestore]);

  return {
    versions,
    loading,
    fetchVersions,
    saveVersion,
    restoreVersion,
  };
}

import * as React from "react";

import type { ToastActionElement, ToastProps } from "@/components/ui/toast";

const TOAST_LIMIT = 1;
const TOAST_REMOVE_DELAY = 1000000;

type ToasterToast = ToastProps & {
  id: string;
  title?: React.ReactNode;
  description?: React.ReactNode;
  action?: ToastActionElement;
};

const actionTypes = {
  ADD_TOAST: "ADD_TOAST",
  UPDATE_TOAST: "UPDATE_TOAST",
  DISMISS_TOAST: "DISMISS_TOAST",
  REMOVE_TOAST: "REMOVE_TOAST",
} as const;

let count = 0;

function genId() {
  count = (count + 1) % Number.MAX_SAFE_INTEGER;
  return count.toString();
}

type ActionType = typeof actionTypes;

type Action =
  | {
      type: ActionType["ADD_TOAST"];
      toast: ToasterToast;
    }
  | {
      type: ActionType["UPDATE_TOAST"];
      toast: Partial<ToasterToast>;
    }
  | {
      type: ActionType["DISMISS_TOAST"];
      toastId?: ToasterToast["id"];
    }
  | {
      type: ActionType["REMOVE_TOAST"];
      toastId?: ToasterToast["id"];
    };

interface State {
  toasts: ToasterToast[];
}

const toastTimeouts = new Map<string, ReturnType<typeof setTimeout>>();

const addToRemoveQueue = (toastId: string) => {
  if (toastTimeouts.has(toastId)) {
    return;
  }

  const timeout = setTimeout(() => {
    toastTimeouts.delete(toastId);
    dispatch({
      type: "REMOVE_TOAST",
      toastId: toastId,
    });
  }, TOAST_REMOVE_DELAY);

  toastTimeouts.set(toastId, timeout);
};

export const reducer = (state: State, action: Action): State => {
  switch (action.type) {
    case "ADD_TOAST":
      return {
        ...state,
        toasts: [action.toast, ...state.toasts].slice(0, TOAST_LIMIT),
      };

    case "UPDATE_TOAST":
      return {
        ...state,
        toasts: state.toasts.map((t) => (t.id === action.toast.id ? { ...t, ...action.toast } : t)),
      };

    case "DISMISS_TOAST": {
      const { toastId } = action;

      // ! Side effects ! - This could be extracted into a dismissToast() action,
      // but I'll keep it here for simplicity
      if (toastId) {
        addToRemoveQueue(toastId);
      } else {
        state.toasts.forEach((toast) => {
          addToRemoveQueue(toast.id);
        });
      }

      return {
        ...state,
        toasts: state.toasts.map((t) =>
          t.id === toastId || toastId === undefined
            ? {
                ...t,
                open: false,
              }
            : t,
        ),
      };
    }
    case "REMOVE_TOAST":
      if (action.toastId === undefined) {
        return {
          ...state,
          toasts: [],
        };
      }
      return {
        ...state,
        toasts: state.toasts.filter((t) => t.id !== action.toastId),
      };
  }
};

const listeners: Array<(state: State) => void> = [];

let memoryState: State = { toasts: [] };

function dispatch(action: Action) {
  memoryState = reducer(memoryState, action);
  listeners.forEach((listener) => {
    listener(memoryState);
  });
}

type Toast = Omit<ToasterToast, "id">;

function toast({ ...props }: Toast) {
  const id = genId();

  const update = (props: ToasterToast) =>
    dispatch({
      type: "UPDATE_TOAST",
      toast: { ...props, id },
    });
  const dismiss = () => dispatch({ type: "DISMISS_TOAST", toastId: id });

  dispatch({
    type: "ADD_TOAST",
    toast: {
      ...props,
      id,
      open: true,
      onOpenChange: (open) => {
        if (!open) dismiss();
      },
    },
  });

  return {
    id: id,
    dismiss,
    update,
  };
}

function useToast() {
  const [state, setState] = React.useState<State>(memoryState);

  React.useEffect(() => {
    listeners.push(setState);
    return () => {
      const index = listeners.indexOf(setState);
      if (index > -1) {
        listeners.splice(index, 1);
      }
    };
  }, [state]);

  return {
    ...state,
    toast,
    dismiss: (toastId?: string) => dispatch({ type: "DISMISS_TOAST", toastId }),
  };
}

export { useToast, toast };

import { useCallback } from 'react';

type HapticPattern = 'light' | 'medium' | 'heavy' | 'success' | 'error' | 'warning' | 'selection' | 'impact';

const patterns: Record<HapticPattern, number | number[]> = {
  light: 10,
  medium: 25,
  heavy: 50,
  success: [10, 50, 10],
  error: [50, 100, 50],
  warning: [30, 50, 30],
  selection: 5,
  impact: [20, 30],
};

export function useHapticFeedback() {
  const vibrate = useCallback((pattern: HapticPattern = 'medium') => {
    // Check if Vibration API is supported
    if (!navigator.vibrate) {
      return false;
    }

    try {
      navigator.vibrate(patterns[pattern]);
      return true;
    } catch (error) {
      // Silently fail - haptic feedback is not critical
      return false;
    }
  }, []);

  const lightTap = useCallback(() => vibrate('light'), [vibrate]);
  const mediumTap = useCallback(() => vibrate('medium'), [vibrate]);
  const heavyTap = useCallback(() => vibrate('heavy'), [vibrate]);
  const success = useCallback(() => vibrate('success'), [vibrate]);
  const error = useCallback(() => vibrate('error'), [vibrate]);
  const warning = useCallback(() => vibrate('warning'), [vibrate]);
  const selection = useCallback(() => vibrate('selection'), [vibrate]);
  const impact = useCallback(() => vibrate('impact'), [vibrate]);

  return {
    vibrate,
    lightTap,
    mediumTap,
    heavyTap,
    success,
    error,
    warning,
    selection,
    impact,
    isSupported: typeof navigator !== 'undefined' && 'vibrate' in navigator,
  };
}

import { useState } from 'react';
import { supabase } from '@/integrations/supabase/client';
import { toast } from 'sonner';

interface UseRobokassaProps {
    onSuccess?: () => void;
    onError?: (error: Error) => void;
}

export function useRobokassa({ onSuccess, onError }: UseRobokassaProps = {}) {
    const [isLoading, setIsLoading] = useState(false);

    const buySubscription = async (plan: 'pro', period: 3 | 6 | 12) => {
        try {
            setIsLoading(true);

            const { data: { user } } = await supabase.auth.getUser();
            if (!user) {
                toast.error("Пожалуйста, войдите в систему");
                return;
            }

            const { data, error } = await supabase.functions.invoke('robokassa', {
                body: {
                    type: 'subscription',
                    plan,
                    period,
                    userId: user.id,
                },
            });

            if (error) throw error;
            if (!data?.url) throw new Error("No payment URL returned");

            window.location.href = data.url;
            onSuccess?.();
        } catch (error: any) {
            console.error('Payment init error:', error);
            toast.error("Ошибка при создании платежа: " + error.message);
            onError?.(error);
        } finally {
            setIsLoading(false);
        }
    };

    const initiatePayment = async (amount: number, description: string, relatedId?: string) => {
        try {
            setIsLoading(true);

            const { data: { user } } = await supabase.auth.getUser();
            if (!user) {
                toast.error("Пожалуйста, войдите в систему");
                return;
            }

            const { data, error } = await supabase.functions.invoke('robokassa', {
                body: {
                    type: 'payment',
                    amount,
                    description,
                    userId: user.id,
                    relatedId
                },
            });

            if (error) throw error;
            if (!data?.url) throw new Error("No payment URL returned");

            window.location.href = data.url;
            onSuccess?.();
        } catch (error: any) {
            console.error('Payment init error:', error);
            toast.error("Ошибка при создании платежа: " + error.message);
            onError?.(error);
        } finally {
            setIsLoading(false);
        }
    };

    return {
        buySubscription,
        initiatePayment,
        isLoading
    };
}

import { useState, useEffect, useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { supabase } from '@/platform/supabase/client';
import { logger } from '@/lib/utils/logger';
import { useAuth } from '@/hooks/user/useAuth';
import type { Achievement, UnlockedAchievement, UserStats } from '@/types/achievements';
import { ACHIEVEMENTS } from '@/types/achievements';
import { addTokens } from '@/services/tokens';

// Token rewards by achievement rarity
const ACHIEVEMENT_TOKEN_REWARDS: Record<Achievement['rarity'], number> = {
  common: 10,
  rare: 25,
  epic: 50,
  legendary: 100,
};

export function useAchievements() {
  const { t } = useTranslation();
  const { user } = useAuth();
  const [unlockedAchievements, setUnlockedAchievements] = useState<Set<string>>(new Set());
  const [newAchievement, setNewAchievement] = useState<Achievement | null>(null);
  const [loading, setLoading] = useState(true);

  // Load unlocked achievements from database
  useEffect(() => {
    if (!user) {
      setLoading(false);
      return;
    }

    const loadAchievements = async () => {
      try {
        const { data, error } = await supabase
          .from('user_achievements')
          .select('achievement_key')
          .eq('user_id', user.id);

        if (error) throw error;

        const unlocked = new Set(data?.map(a => a.achievement_key) || []);
        setUnlockedAchievements(unlocked);
      } catch (error) {
        logger.error('Failed to load achievements:', error, { context: 'useAchievements' });
      } finally {
        setLoading(false);
      }
    };

    loadAchievements();
  }, [user]);

  // Check and unlock new achievements
  const checkAchievements = useCallback(async (stats: UserStats) => {
    if (!user) return;

    const newlyUnlocked: Achievement[] = [];

    for (const achievement of ACHIEVEMENTS) {
      // Skip if already unlocked
      if (unlockedAchievements.has(achievement.key)) continue;

      // Check if condition is met
      if (achievement.condition(stats)) {
        try {
          // Save to database
          const { error } = await supabase
            .from('user_achievements')
            .insert({
              user_id: user.id,
              achievement_key: achievement.key,
            });

          if (error) {
            // Ignore unique constraint violations (already unlocked)
            if (!error.message.includes('duplicate key')) {
              logger.error('Failed to unlock achievement:', error, { context: 'useAchievements' });
            }
            continue;
          }

          // Award tokens for the achievement
          const tokenReward = ACHIEVEMENT_TOKEN_REWARDS[achievement.rarity];
          await addTokens(
            user.id,
            tokenReward,
            `achievement_${achievement.rarity}`,
            t('achievements.rewardDescription', 'Награда за достижение: {{title}}', {
              title: t(achievement.titleKey),
            })
          );

          newlyUnlocked.push(achievement);

          // Update local state
          setUnlockedAchievements(prev => new Set([...Array.from(prev), achievement.key]));
        } catch (error) {
          logger.error('Error unlocking achievement:', error, { context: 'useAchievements' });
        }
      }
    }

    // Show notification for the first newly unlocked achievement
    if (newlyUnlocked.length > 0) {
      setNewAchievement(newlyUnlocked[0]);
    }
  }, [user, unlockedAchievements, t]);

  const dismissAchievementNotification = useCallback(() => {
    setNewAchievement(null);
  }, []);

  const getProgress = useCallback(() => {
    const total = ACHIEVEMENTS.length;
    const unlocked = unlockedAchievements.size;
    return {
      unlocked,
      total,
      percentage: Math.round((unlocked / total) * 100),
    };
  }, [unlockedAchievements]);

  const getAchievementsByCategory = useCallback((category: Achievement['category']) => {
    return ACHIEVEMENTS.filter(a => a.category === category).map(achievement => ({
      ...achievement,
      unlocked: unlockedAchievements.has(achievement.key),
    }));
  }, [unlockedAchievements]);

  const getAllAchievements = useCallback(() => {
    return ACHIEVEMENTS.map(achievement => ({
      ...achievement,
      unlocked: unlockedAchievements.has(achievement.key),
    }));
  }, [unlockedAchievements]);

  return {
    loading,
    unlockedAchievements,
    newAchievement,
    checkAchievements,
    dismissAchievementNotification,
    getProgress,
    getAchievementsByCategory,
    getAllAchievements,
  };
}

import { createContext, useContext, useEffect, useState } from 'react';
import { User, Session, AuthError } from '@supabase/supabase-js';
import { supabase } from '@/platform/supabase/client';
import { lovable } from '@/integrations/lovable/index';
import { logger } from '@/lib/utils/logger';

interface AuthContextType {
  user: User | null;
  session: Session | null;
  loading: boolean;
  signUp: (email: string, password: string) => Promise<{ data: { user: User | null; session: Session | null } | null; error: AuthError | null }>;
  signIn: (email: string, password: string) => Promise<{ data: { user: User | null; session: Session | null } | null; error: AuthError | null }>;
  signInWithGoogle: (returnTo?: string) => Promise<{ error: Error | null }>;
  signInWithApple: (returnTo?: string) => Promise<{ error: Error | null }>;
  signOut: () => Promise<void>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<User | null>(null);
  const [session, setSession] = useState<Session | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Set up auth state listener FIRST
    const { data: { subscription } } = supabase.auth.onAuthStateChange(
      (_event, session) => {
        // Only log critical auth state changes in debug
        logger.debug('Auth state change', { context: 'useAuth', data: { event: _event, userId: session?.user?.id } });

        // Handle token refresh errors
        if (_event === 'TOKEN_REFRESHED' && !session) {
          // Token refresh failed, clear session
          setSession(null);
          setUser(null);
          setLoading(false);
          return;
        }

        if (_event === 'SIGNED_OUT') {
          setSession(null);
          setUser(null);
          setLoading(false);
          return;
        }

        // Check for password recovery
        if (_event === 'PASSWORD_RECOVERY') {
          logger.debug('Password recovery event detected', { context: 'useAuth' });
        }

        setSession(session);
        setUser(session?.user ?? null);
        setLoading(false);

        // Check for pending Telegram chat ID after signup
        if (_event === 'SIGNED_IN' && session?.user) {
          const pendingChatId = localStorage.getItem('pending_telegram_chat_id');
          if (pendingChatId) {
            localStorage.removeItem('pending_telegram_chat_id');
            // Use setTimeout to avoid deadlock with Supabase auth
            setTimeout(async () => {
              const { error: err } = await supabase
                .from('user_profiles')
                .update({
                  telegram_chat_id: pendingChatId,
                  telegram_notifications_enabled: true
                })
                .eq('id', session.user.id);

              if (err) {
                logger.error('Failed to save telegram chat id:', err, { context: 'useAuth' });
              }
            }, 0);
          }
        }
      }
    );

    // THEN check for existing session
    supabase.auth.getSession().then(({ data: { session }, error }) => {
      if (error) {
        // Clear invalid session
        setSession(null);
        setUser(null);
        setLoading(false);
        return;
      }

      setSession(session);
      setUser(session?.user ?? null);
      setLoading(false);
    });

    return () => subscription.unsubscribe();
  }, []);

  const signUp = async (email: string, password: string) => {
    const redirectUrl = `${window.location.origin}/dashboard`;

    const { data, error } = await supabase.auth.signUp({
      email,
      password,
      options: {
        emailRedirectTo: redirectUrl,
      },
    });

    return { data, error };
  };

  const signIn = async (email: string, password: string) => {
    const { data, error } = await supabase.auth.signInWithPassword({
      email,
      password,
    });

    return { data, error };
  };

  const signInWithGoogle = async (_returnTo?: string) => {
    const redirectUrl = _returnTo
      ? `${window.location.origin}/auth?returnTo=${encodeURIComponent(_returnTo)}`
      : window.location.origin;

    const { error } = await lovable.auth.signInWithOAuth('google', {
      redirect_uri: redirectUrl,
    });
    return { error: error || null };
  };

  const signInWithApple = async (_returnTo?: string) => {
    const redirectUrl = _returnTo
      ? `${window.location.origin}/auth?returnTo=${encodeURIComponent(_returnTo)}`
      : window.location.origin;

    const { error } = await lovable.auth.signInWithOAuth('apple', {
      redirect_uri: redirectUrl,
    });
    return { error: error || null };
  };

  const signOut = async () => {
    await supabase.auth.signOut();
  };

  return (
    <AuthContext.Provider value={{ user, session, loading, signUp, signIn, signInWithGoogle, signInWithApple, signOut }}>
      {children}
    </AuthContext.Provider>
  );
}

export function useAuth() {
  const context = useContext(AuthContext);
  if (context === undefined) {
    throw new Error('useAuth must be used within an AuthProvider');
  }
  return context;
}

import { useState, useEffect, useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import { toast } from 'sonner';
import { logger } from '@/lib/utils/logger';
import {
  getCompletedQuestsToday,
  completeQuest,
  DAILY_QUESTS,
  getQuestProgress,
  type Quest
} from '@/services/quests';

export function useDailyQuests(userId: string | undefined) {
  const { t } = useTranslation();
  const [completedQuests, setCompletedQuests] = useState<string[]>([]);
  const [loading, setLoading] = useState(true);

  const loadQuests = useCallback(async () => {
    if (!userId) return;

    setLoading(true);
    try {
      const completed = await getCompletedQuestsToday(userId);
      setCompletedQuests(completed);

      // Auto-complete daily visit quest
      if (!completed.includes('daily_visit')) {
        const result = await completeQuest(userId, 'daily_visit');
        if (result.success) {
          setCompletedQuests(prev => [...prev, 'daily_visit']);
          toast.success(t('quests.toastDailyVisit', '👋 +{{count}} Linkkon за ежедневный визит!', {
            count: result.tokensEarned,
          }), {
            duration: 3000,
          });
        }
      }
    } catch (error) {
      logger.error('Failed to load quests:', error, { context: 'useDailyQuests' });
    } finally {
      setLoading(false);
    }
  }, [userId]);

  useEffect(() => {
    loadQuests();
  }, [loadQuests]);

  const markQuestComplete = useCallback(async (questKey: string) => {
    if (!userId || completedQuests.includes(questKey)) return;

    const result = await completeQuest(userId, questKey);
    if (result.success) {
      setCompletedQuests(prev => [...prev, questKey]);
      const quest = DAILY_QUESTS.find(q => q.key === questKey);
      if (quest) {
        toast.success(t('quests.toastCompleted', '{{icon}} +{{count}} Linkkon за "{{title}}"!', {
          icon: quest.icon,
          count: result.tokensEarned,
          title: t(quest.titleKey),
        }), {
          duration: 3000,
        });
      }
    }
  }, [userId, completedQuests, t]);

  const isQuestCompleted = useCallback((questKey: string) => {
    return completedQuests.includes(questKey);
  }, [completedQuests]);

  const progress = getQuestProgress(completedQuests);

  return {
    quests: DAILY_QUESTS,
    completedQuests,
    loading,
    markQuestComplete,
    isQuestCompleted,
    progress,
    refetch: loadQuests,
  };
}

import { useState, useEffect } from 'react';
import { useAuth } from '@/hooks/user/useAuth';
import { checkPremiumStatus as checkPremiumStatusService } from '@/services/user';
import { logger } from '@/lib/utils/logger';

export type PremiumTier = 'free' | 'pro';

export function usePremiumStatus() {
  const { user } = useAuth();
  const [isPremium, setIsPremium] = useState(false);
  const [tier, setTier] = useState<PremiumTier>('free');
  const [inTrial, setInTrial] = useState(false);
  const [trialEndsAt, setTrialEndsAt] = useState<string | null>(null);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    if (!user) {
      setIsPremium(false);
      setTier('free');
      setInTrial(false);
      setTrialEndsAt(null);
      setIsLoading(false);
      return;
    }

    checkStatus();
  }, [user]);

  const checkStatus = async () => {
    if (!user) return;

    try {
      const status = await checkPremiumStatusService(user.id);
      setIsPremium(status.isPremium);
      setTier(status.tier || (status.isPremium ? 'pro' : 'free'));
      setInTrial(status.inTrial);
      setTrialEndsAt(status.trialEndsAt);
    } catch (error) {
      logger.error('Error checking premium status', error, { context: 'usePremiumStatus' });
      setIsPremium(false);
      setTier('free');
      setInTrial(false);
    } finally {
      setIsLoading(false);
    }
  };

  return { isPremium, tier, inTrial, trialEndsAt, isLoading, refresh: checkStatus };
}

import { useState, useEffect, useCallback } from 'react';
import { useTranslation } from 'react-i18next';
import {
  getOrCreateReferralCode,
  getReferralStats,
  applyReferralCode,
  wasUserReferred,
  type ReferralStats
} from '@/services/referral';
import { logger } from '@/lib/utils/logger';
import { toast } from 'sonner';

export function useReferral(userId: string | undefined) {
  const { t } = useTranslation();
  const [stats, setStats] = useState<ReferralStats | null>(null);
  const [loading, setLoading] = useState(true);
  const [applying, setApplying] = useState(false);
  const [wasReferred, setWasReferred] = useState(false);

  const loadStats = useCallback(async () => {
    if (!userId) {
      setLoading(false);
      return;
    }

    try {
      // First ensure user has a referral code
      await getOrCreateReferralCode(userId);

      // Then get stats
      const data = await getReferralStats(userId);
      setStats(data);

      // Check if user was referred
      const referred = await wasUserReferred(userId);
      setWasReferred(referred);
    } catch (error) {
      logger.error('Error loading referral stats:', error, { context: 'useReferral' });
    } finally {
      setLoading(false);
    }
  }, [userId]);

  useEffect(() => {
    loadStats();
  }, [loadStats]);

  const applyCode = useCallback(async (code: string) => {
    if (!userId || !code.trim()) return false;

    setApplying(true);
    try {
      const result = await applyReferralCode(code.trim(), userId);

      if (result.success) {
        toast.success(t('referral.toastSuccess', '🎉 +{{count}} дней Premium для вас и друга!', {
          count: result.bonusDays,
        }));
        setWasReferred(true);
        return true;
      } else {
        const errorMessages: Record<string, string> = {
          'invalid_code': t('referral.errors.invalidCode', 'Неверный код приглашения'),
          'already_referred': t('referral.errors.alreadyReferred', 'Вы уже использовали реферальный код'),
          'self_referral': t('referral.errors.selfReferral', 'Нельзя использовать свой код'),
        };
        toast.error(errorMessages[result.error || 'invalid_code']);
        return false;
      }
    } catch (error) {
      toast.error(t('referral.errors.applyFailed', 'Ошибка при применении кода'));
      return false;
    } finally {
      setApplying(false);
    }
  }, [userId, t]);

  const copyCode = useCallback(() => {
    if (stats?.code) {
      navigator.clipboard.writeText(stats.code);
      toast.success(t('referral.codeCopied', 'Код скопирован!'));
    }
  }, [stats?.code, t]);

  const shareLink = useCallback(() => {
    if (stats?.code) {
      const url = `${window.location.origin}/auth?ref=${stats.code}`;
      navigator.clipboard.writeText(url);
      toast.success(t('referral.linkCopied', 'Ссылка скопирована!'));
    }
  }, [stats?.code, t]);

  return {
    stats,
    loading,
    applying,
    wasReferred,
    applyCode,
    copyCode,
    shareLink,
    refresh: loadStats
  };
}

import i18n from 'i18next';
import { initReactI18next } from 'react-i18next';
import LanguageDetector from 'i18next-browser-languagedetector';
import ru from './locales/ru.json';
import en from './locales/en.json';
import kk from './locales/kk.json';
import de from './locales/de.json';
import uk from './locales/uk.json';
import uz from './locales/uz.json';
import be from './locales/be.json';
import es from './locales/es.json';
import fr from './locales/fr.json';
import it from './locales/it.json';
import pt from './locales/pt.json';
import zh from './locales/zh.json';
import tr from './locales/tr.json';
import ja from './locales/ja.json';
import ko from './locales/ko.json';
import ar from './locales/ar.json';
import { validateTranslations } from './validation';

// Merge all top-level keys into translation namespace
// This handles JSON files with structure: { translation: {...}, landingV5: {...}, ... }
const mergeNamespaces = (json: Record<string, unknown>) => {
  const { translation, ...rest } = json as { translation: Record<string, unknown>, [key: string]: unknown };
  return {
    translation: {
      ...translation,
      ...rest
    }
  };
};

// Migrate 'kz' to 'kk' if stored in localStorage
const migrateKzToKk = () => {
  if (typeof window === 'undefined') return;
  const stored = localStorage.getItem('i18nextLng');
  if (stored === 'kz') {
    localStorage.setItem('i18nextLng', 'kk');
    if (process.env.NODE_ENV === 'development') {
      console.warn('[i18n] Migrated language from "kz" to "kk"');
    }
  }
};

// Run migration before i18n init
migrateKzToKk();

// All supported UI languages
const SUPPORTED_LANGUAGES = ['ru', 'en', 'kk', 'de', 'uk', 'uz', 'be', 'es', 'fr', 'it', 'pt', 'zh', 'tr', 'ja', 'ko', 'ar'];

// Normalize language code to supported codes
const normalizeLanguage = (lng: string): string => {
  if (!lng) return 'ru';

  // Extract base language code (e.g., 'ru-RU' -> 'ru')
  const langCode = lng.substring(0, 2).toLowerCase();

  // Map 'kz' to 'kk' (Kazakh ISO code)
  if (langCode === 'kz') return 'kk';

  // If it's a supported language, return it
  if (SUPPORTED_LANGUAGES.includes(langCode)) return langCode;

  // Default to English for unsupported languages
  return 'en';
};

// Custom language detector - prioritizes URL params for language switching
const customLanguageDetector = {
  name: 'customDetector',
  lookup() {
    if (typeof window === 'undefined') return 'ru';
    // 1. URL parameter has highest priority (for language switching)
    const params = new URLSearchParams(window.location.search);
    const urlLang = params.get('lang') || params.get('lng');
    if (urlLang) {
      const normalizedUrlLang = normalizeLanguage(urlLang);
      // Save to localStorage when set via URL
      localStorage.setItem('i18nextLng', normalizedUrlLang);
      return normalizedUrlLang;
    }

    // 2. Check localStorage for user preference
    let stored = localStorage.getItem('i18nextLng');

    // Migrate 'kz' to 'kk' on read
    if (stored === 'kz') {
      stored = 'kk';
      localStorage.setItem('i18nextLng', 'kk');
    }

    if (stored && SUPPORTED_LANGUAGES.includes(stored)) {
      return stored;
    }

    // 3. Auto-detect from browser language
    const browserLang = navigator.language || (navigator as any).languages?.[0] || '';
    return normalizeLanguage(browserLang);
  },
  cacheUserLanguage(lng: string) {
    if (typeof window === 'undefined') return;
    // Normalize before caching
    const normalizedLng = normalizeLanguage(lng);
    localStorage.setItem('i18nextLng', normalizedLng);
  }
};

const languageDetectorPlugin = new LanguageDetector();
languageDetectorPlugin.addDetector(customLanguageDetector);

// Initialize i18n
i18n
  .use(languageDetectorPlugin)
  .use(initReactI18next)
  .init({
    resources: {
      ru: mergeNamespaces(ru),
      en: mergeNamespaces(en),
      kk: mergeNamespaces(kk),
      de: mergeNamespaces(de),
      uk: mergeNamespaces(uk),
      uz: mergeNamespaces(uz),
      be: mergeNamespaces(be),
      es: mergeNamespaces(es),
      fr: mergeNamespaces(fr),
      it: mergeNamespaces(it),
      pt: mergeNamespaces(pt),
      zh: mergeNamespaces(zh),
      tr: mergeNamespaces(tr),
      ja: mergeNamespaces(ja),
      ko: mergeNamespaces(ko),
      ar: mergeNamespaces(ar),
    },
    supportedLngs: ['ru', 'en', 'kk', 'de', 'uk', 'uz', 'be', 'es', 'fr', 'it', 'pt', 'zh', 'tr', 'ja', 'ko', 'ar'],
    nonExplicitSupportedLngs: true,
    load: 'languageOnly',
    fallbackLng: {
      'kz': ['kk', 'en'],
      'uk': ['en'],
      'be': ['en'],
      'uz': ['en'],
      'default': ['en']
    },
    interpolation: {
      escapeValue: false, // React already escapes
    },
    ns: ['translation'],
    defaultNS: 'translation',
    detection: {
      order: ['customDetector'],
      caches: ['localStorage'],
    },
    // Handling missing keys
    saveMissing: process.env.NODE_ENV === 'development',
    missingKeyHandler: process.env.NODE_ENV === 'development'
      ? (lngs, ns, key, fallbackValue) => {
        console.warn(`[i18n] Missing key: "${key}" for languages: [${lngs.join(', ')}], namespace: "${ns}"`);
      }
      : undefined,
    // Return key if missing (instead of empty string)
    returnEmptyString: false,
    returnNull: false,
  });

// Development diagnostics
if (process.env.NODE_ENV === 'development') {
  console.log('[i18n] Initialized with language:', i18n.language);
  console.log('[i18n] Supported languages:', SUPPORTED_LANGUAGES);
  console.log('[i18n] Resources loaded:', Object.keys(i18n.options.resources || {}));

  // Validate all translations and show missing keys
  validateTranslations();
}

// Listen for language changes
i18n.on('languageChanged', (lng) => {
  // Normalize on change
  const normalized = normalizeLanguage(lng);
  if (normalized !== lng && SUPPORTED_LANGUAGES.includes(normalized)) {
    i18n.changeLanguage(normalized);
    return;
  }

  if (process.env.NODE_ENV === 'development') {
    console.log('[i18n] Language changed to:', lng);
  }

  // Update HTML lang attribute
  document.documentElement.lang = lng;
});

// Set initial HTML lang
if (typeof document !== 'undefined') {
  document.documentElement.lang = i18n.language || 'ru';
}

export default i18n;

import ru from './locales/ru.json';
import en from './locales/en.json';
import kk from './locales/kk.json';
import de from './locales/de.json';
import uk from './locales/uk.json';
import uz from './locales/uz.json';
import be from './locales/be.json';
import es from './locales/es.json';
import fr from './locales/fr.json';
import it from './locales/it.json';
import pt from './locales/pt.json';
import zh from './locales/zh.json';
import tr from './locales/tr.json';
import ja from './locales/ja.json';
import ko from './locales/ko.json';
import ar from './locales/ar.json';

type TranslationObject = Record<string, unknown>;
type LanguageCode = 'ru' | 'en' | 'kk' | 'de' | 'uk' | 'uz' | 'be' | 'es' | 'fr' | 'it' | 'pt' | 'zh' | 'tr' | 'ja' | 'ko' | 'ar';

const translations: Record<LanguageCode, TranslationObject> = { ru, en, kk, de, uk, uz, be, es, fr, it, pt, zh, tr, ja, ko, ar };

/**
 * Recursively extracts all keys from a nested object
 */
function getAllKeys(obj: TranslationObject, prefix = ''): string[] {
  const keys: string[] = [];

  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (value && typeof value === 'object' && !Array.isArray(value)) {
      keys.push(...getAllKeys(value as TranslationObject, fullKey));
    } else {
      keys.push(fullKey);
    }
  }

  return keys;
}

/**
 * Gets a value from nested object by dot-separated key
 */
function getNestedValue(obj: TranslationObject, key: string): unknown {
  return key.split('.').reduce((acc: unknown, part) => {
    if (acc && typeof acc === 'object') {
      return (acc as TranslationObject)[part];
    }
    return undefined;
  }, obj);
}

/**
 * Sets a value in nested object by dot-separated key
 */
function setNestedValue(obj: TranslationObject, key: string, value: string): void {
  const parts = key.split('.');
  let current = obj;

  for (let i = 0; i < parts.length - 1; i++) {
    const part = parts[i];
    if (!current[part] || typeof current[part] !== 'object') {
      current[part] = {};
    }
    current = current[part] as TranslationObject;
  }

  current[parts[parts.length - 1]] = value;
}

/**
 * Generates a placeholder value for a missing key
 */
function generatePlaceholder(key: string, lang: LanguageCode, referenceValue?: string): string {
  if (referenceValue && typeof referenceValue === 'string') {
    // Use reference value with language prefix for easy identification
    return `[${lang.toUpperCase()}] ${referenceValue}`;
  }
  // Generate from key name
  const lastPart = key.split('.').pop() || key;
  const readable = lastPart
    .replace(/([A-Z])/g, ' $1')
    .replace(/[_-]/g, ' ')
    .trim();
  return `[${lang.toUpperCase()}] ${readable}`;
}

/**
 * Finds missing keys in each language
 */
export function getMissingTranslations(): Record<LanguageCode, string[]> {
  const langKeys: Record<LanguageCode, string[]> = {
    ru: getAllKeys(ru as TranslationObject),
    en: getAllKeys(en as TranslationObject),
    kk: getAllKeys(kk as TranslationObject),
    de: getAllKeys(de as TranslationObject),
    uk: getAllKeys(uk as TranslationObject),
    uz: getAllKeys(uz as TranslationObject),
    be: getAllKeys(be as TranslationObject),
    es: getAllKeys(es as TranslationObject),
    fr: getAllKeys(fr as TranslationObject),
    it: getAllKeys(it as TranslationObject),
    pt: getAllKeys(pt as TranslationObject),
    zh: getAllKeys(zh as TranslationObject),
    tr: getAllKeys(tr as TranslationObject),
    ja: getAllKeys(ja as TranslationObject),
    ko: getAllKeys(ko as TranslationObject),
    ar: getAllKeys(ar as TranslationObject),
  };

  const allKeys = new Set<string>();
  Object.values(langKeys).forEach(keys => {
    keys.forEach(key => allKeys.add(key));
  });

  return {
    ru: Array.from(allKeys).filter(key => !langKeys.ru.includes(key)),
    en: Array.from(allKeys).filter(key => !langKeys.en.includes(key)),
    kk: Array.from(allKeys).filter(key => !langKeys.kk.includes(key)),
    de: Array.from(allKeys).filter(key => !langKeys.de.includes(key)),
    uk: Array.from(allKeys).filter(key => !langKeys.uk.includes(key)),
    uz: Array.from(allKeys).filter(key => !langKeys.uz.includes(key)),
    be: Array.from(allKeys).filter(key => !langKeys.be.includes(key)),
    es: Array.from(allKeys).filter(key => !langKeys.es.includes(key)),
    fr: Array.from(allKeys).filter(key => !langKeys.fr.includes(key)),
    it: Array.from(allKeys).filter(key => !langKeys.it.includes(key)),
    pt: Array.from(allKeys).filter(key => !langKeys.pt.includes(key)),
    zh: Array.from(allKeys).filter(key => !langKeys.zh.includes(key)),
    tr: Array.from(allKeys).filter(key => !langKeys.tr.includes(key)),
    ja: Array.from(allKeys).filter(key => !langKeys.ja.includes(key)),
    ko: Array.from(allKeys).filter(key => !langKeys.ko.includes(key)),
    ar: Array.from(allKeys).filter(key => !langKeys.ar.includes(key)),
  };
}

/**
 * Generates complete translation objects with placeholders for missing keys
 */
export function generateMissingKeysWithPlaceholders(): Record<LanguageCode, TranslationObject> {
  const missing = getMissingTranslations();
  const result: Record<LanguageCode, TranslationObject> = {
    ru: {}, en: {}, kk: {}, de: {}, uk: {}, uz: {}, be: {},
    es: {}, fr: {}, it: {}, pt: {}, zh: {}, tr: {}, ja: {}, ko: {}, ar: {}
  };

  const languages: LanguageCode[] = ['ru', 'en', 'kk', 'de', 'uk', 'uz', 'be', 'es', 'fr', 'it', 'pt', 'zh', 'tr', 'ja', 'ko', 'ar'];

  languages.forEach(lang => {
    missing[lang].forEach(key => {
      // Try to find reference value from another language
      let referenceValue: string | undefined;
      for (const refLang of languages) {
        if (refLang !== lang) {
          const val = getNestedValue(translations[refLang], key);
          if (typeof val === 'string') {
            referenceValue = val;
            break;
          }
        }
      }

      const placeholder = generatePlaceholder(key, lang, referenceValue);
      setNestedValue(result[lang], key, placeholder);
    });
  });

  return result;
}

/**
 * Logs missing keys with copy-pasteable JSON
 */
export function logMissingKeysAsJSON(): void {
  if (!import.meta.env.DEV) return;

  const missingWithPlaceholders = generateMissingKeysWithPlaceholders();
  const languages: LanguageCode[] = ['ru', 'en', 'kk'];

  let hasMissing = false;

  languages.forEach(lang => {
    const keys = Object.keys(missingWithPlaceholders[lang]);
    if (keys.length > 0) {
      hasMissing = true;
      console.group(`📝 [i18n] Missing keys for ${lang.toUpperCase()} - Copy and merge into ${lang}.json:`);
      console.log(JSON.stringify(missingWithPlaceholders[lang], null, 2));
      console.groupEnd();
    }
  });

  if (!hasMissing) {
    console.log('✅ [i18n] No missing keys to generate!');
  }
}

/**
 * Copies missing translations to clipboard (call from browser console)
 */
export async function copyMissingToClipboard(lang: LanguageCode): Promise<void> {
  const missingWithPlaceholders = generateMissingKeysWithPlaceholders();
  const json = JSON.stringify(missingWithPlaceholders[lang], null, 2);

  try {
    await navigator.clipboard.writeText(json);
    console.log(`✅ Copied missing ${lang.toUpperCase()} keys to clipboard!`);
  } catch (err) {
    console.error('Failed to copy to clipboard:', err);
    console.log('JSON to copy manually:', json);
  }
}

/**
 * Validates all translation files and logs missing keys
 */
export function validateTranslations(): void {
  if (!import.meta.env.DEV) return;

  console.group('🌐 [i18n] Translation Validation');

  const langKeys: Record<LanguageCode, string[]> = {
    ru: getAllKeys(ru as TranslationObject),
    en: getAllKeys(en as TranslationObject),
    kk: getAllKeys(kk as TranslationObject),
    de: getAllKeys(de as TranslationObject),
    uk: getAllKeys(uk as TranslationObject),
    uz: getAllKeys(uz as TranslationObject),
    be: getAllKeys(be as TranslationObject),
    es: getAllKeys(es as TranslationObject),
    fr: getAllKeys(fr as TranslationObject),
    it: getAllKeys(it as TranslationObject),
    pt: getAllKeys(pt as TranslationObject),
    zh: getAllKeys(zh as TranslationObject),
    tr: getAllKeys(tr as TranslationObject),
    ja: getAllKeys(ja as TranslationObject),
    ko: getAllKeys(ko as TranslationObject),
    ar: getAllKeys(ar as TranslationObject),
  };

  // Get all unique keys from all languages
  const allKeys = new Set<string>();
  Object.values(langKeys).forEach(keys => {
    keys.forEach(key => allKeys.add(key));
  });

  const totalKeys = allKeys.size;
  console.log(`📊 Total unique keys: ${totalKeys}`);

  // Check each language
  const languages: LanguageCode[] = ['ru', 'en', 'kk', 'de', 'uk', 'uz', 'be', 'es', 'fr', 'it', 'pt', 'zh', 'tr', 'ja', 'ko', 'ar'];
  let hasIssues = false;

  languages.forEach(lang => {
    const keys = langKeys[lang];
    const missingFromLang = Array.from(allKeys).filter(key => !keys.includes(key));

    if (missingFromLang.length > 0) {
      hasIssues = true;
      console.group(`❌ Missing in ${lang.toUpperCase()} (${missingFromLang.length} keys):`);
      missingFromLang.forEach(key => console.warn(`  • ${key}`));
      console.groupEnd();
    } else {
      console.log(`✅ ${lang.toUpperCase()}: All ${keys.length} keys present`);
    }
  });

  // Show keys that exist in some languages but not others
  console.group('📋 Coverage by language:');
  languages.forEach(lang => {
    const count = langKeys[lang].length;
    const percentage = ((count / totalKeys) * 100).toFixed(1);
    console.log(`  ${lang.toUpperCase()}: ${count}/${totalKeys} (${percentage}%)`);
  });
  console.groupEnd();

  if (hasIssues) {
    console.log('');
    console.log('💡 To generate placeholders for missing keys, run in console:');
    console.log('   window.__i18n.logMissingKeysAsJSON()');
    console.log('   window.__i18n.copyMissingToClipboard("ru" | "en" | "kk")');
  } else {
    console.log('🎉 All translations are complete!');
  }

  console.groupEnd();

  // Expose utilities globally in dev mode
  if (typeof window !== 'undefined') {
    (window as unknown as Record<string, unknown>).__i18n = {
      validateTranslations,
      getMissingTranslations,
      generateMissingKeysWithPlaceholders,
      logMissingKeysAsJSON,
      copyMissingToClipboard,
    };
  }
}

