    rejected: { ru: 'Отклонён', en: 'Rejected', kk: 'Қабылданбады' },
    cancelled: { ru: 'Отменён', en: 'Cancelled', kk: 'Болдырылмады' },
  };
  return translations[status]?.[lang] || status;
}

