interface AutoFAQContext {
  name: string;
  niche?: string;
  location?: string;
  services: string[];
  minPrice?: number;
  currency?: string;
  hasBooking: boolean;
}

/**
 * Generate auto FAQ based on profile context
 */
export function generateAutoFAQ(
  context: AutoFAQContext,
  language: 'ru' | 'en' | 'kk' = 'ru',
  maxItems: number = 5
): AutoFAQItem[] {
  const templates = FAQ_TEMPLATES[language];
  const faqs: AutoFAQItem[] = [];

  const replacePlaceholders = (text: string): string => {
    return text
      .replace(/\{name\}/g, context.name || 'специалист')
      .replace(/\{niche\}/g, context.niche || 'своей сфере')
      .replace(/\{location\}/g, context.location || 'онлайн')
      .replace(/\{services\}/g, context.services.slice(0, 2).join(', ') || 'профессиональные услуги')
      .replace(/\{minPrice\}/g, String(context.minPrice || ''))
      .replace(/\{currency\}/g, context.currency || 'KZT');
  };

  // Priority 1: Pricing question (if has pricing)
  if (context.minPrice) {
    faqs.push({
      question: replacePlaceholders(templates.howMuch.q),
      answer: replacePlaceholders(templates.howMuch.a),
    });
  }

  // Priority 2: How to book (if has booking)
  if (context.hasBooking) {
    faqs.push({
      question: replacePlaceholders(templates.howToBook.q),
      answer: replacePlaceholders(templates.howToBook.a),
    });
  }

  // Priority 3: How it works
  faqs.push({
    question: replacePlaceholders(templates.howWorks.q),
    answer: replacePlaceholders(templates.howWorks.a),
  });

  // Priority 4: Who is suitable
  if (context.services.length > 0) {
    faqs.push({
      question: replacePlaceholders(templates.whoSuitable.q),
      answer: replacePlaceholders(templates.whoSuitable.a),
    });
  }

  // Priority 5: Results
  faqs.push({
    question: replacePlaceholders(templates.whatResults.q),
    answer: replacePlaceholders(templates.whatResults.a),
  });

  // Priority 6: Payment methods (if has pricing)
  if (context.minPrice) {
    faqs.push({
      question: replacePlaceholders(templates.paymentMethods.q),
      answer: replacePlaceholders(templates.paymentMethods.a),
    });
  }

  // Priority 7: Cancellation (if has booking)
  if (context.hasBooking) {
    faqs.push({
      question: replacePlaceholders(templates.cancellation.q),
      answer: replacePlaceholders(templates.cancellation.a),
    });
  }

  return faqs.slice(0, maxItems);
}

/**
 * Extract FAQ context from blocks
 */
export function extractFAQContext(
  blocks: Block[],
  name: string | undefined,
  niche: string | undefined,
  location: string | undefined,
  language: 'ru' | 'en' | 'kk'
): AutoFAQContext {
  // Guard against undefined/null blocks
  const validBlocks = (blocks || []).filter((b): b is Block => b != null && typeof b === 'object' && 'type' in b);
  const pricingBlock = validBlocks.find(b => b.type === 'pricing') as PricingBlock | undefined;
  const hasBooking = validBlocks.some(b => b.type === 'booking');

  // Extract services
  const services: string[] = [];
  if (pricingBlock?.items) {
    for (const item of (pricingBlock.items || []).filter((i): i is NonNullable<typeof i> => i != null && typeof i === 'object')) {
      if (!item.name) continue;
      const serviceName = getI18nText(item.name, language);
      if (serviceName) services.push(serviceName);
    }
  }

  // Find minimum price
  let minPrice: number | undefined;
  let currency: string | undefined;
  if (pricingBlock?.items) {
    const prices = (pricingBlock.items || [])
      .filter((item): item is NonNullable<typeof item> => item != null && typeof item === 'object')
      .map(item => item.price)
      .filter((p): p is number => typeof p === 'number' && p > 0);
    if (prices.length > 0) {
      minPrice = Math.min(...prices);
      currency = pricingBlock.currency || 'KZT';
    }
  }

  return {
    name: name || '',
    niche,
    location,
    services,
    minPrice,
    currency,
    hasBooking,
  };
}

/**
 * Check if user already has sufficient FAQ
 */
export function hasUserFAQ(blocks: Block[]): boolean {
  const validBlocks = (blocks || []).filter((b): b is Block => b != null && typeof b === 'object' && 'type' in b);
  const faqBlock = validBlocks.find(b => b.type === 'faq') as { items?: unknown[] } | undefined;
  return (faqBlock?.items?.length ?? 0) >= 3;
}

/**
 * Entity Linking - Extract sameAs, worksFor, knowsAbout from blocks
 * Automatically builds entity relationships for Schema.org
 */

import type { Block, SocialsBlock, LinkBlock } from '@/types/page';
import { getI18nText } from '@/lib/i18n-helpers';

// Known social platforms for sameAs extraction
const SOCIAL_PLATFORMS: Record<string, string> = {
  linkedin: 'linkedin.com',
  github: 'github.com',
  twitter: 'twitter.com',
  x: 'x.com',
  instagram: 'instagram.com',
  facebook: 'facebook.com',
  youtube: 'youtube.com',
  tiktok: 'tiktok.com',
  vk: 'vk.com',
  telegram: 't.me',
  behance: 'behance.net',
  dribbble: 'dribbble.com',
  medium: 'medium.com',
  pinterest: 'pinterest.com',
  twitch: 'twitch.tv',
  spotify: 'spotify.com',
};

// Extract organization/company domains
const COMPANY_DOMAINS = ['company', 'work', 'organization', 'business', 'corp'];

export interface EntityLinks {
  sameAs: string[];
  worksFor?: {
    '@type': 'Organization';
    name: string;
    url?: string;
  };
  alumniOf?: Array<{
    '@type': 'Organization';
    name: string;
  }>;
  knowsAbout: string[];
  jobTitle?: string;
}

/**
 * Extract all entity links from blocks
 */
export function extractEntityLinks(
  blocks: Block[],
  language: 'ru' | 'en' | 'kk' = 'ru'
): EntityLinks {
  const result: EntityLinks = {
    sameAs: [],
    knowsAbout: [],
  };

  // Guard against undefined/null blocks
  const validBlocks = (blocks || []).filter((b): b is Block => b != null && typeof b === 'object' && 'type' in b);

  // Extract sameAs from socials block
  const socialsBlock = validBlocks.find(b => b.type === 'socials') as SocialsBlock | undefined;
  if (socialsBlock?.platforms) {
    for (const platform of (socialsBlock.platforms || []).filter(p => p != null && typeof p === 'object')) {
      if (platform.url && isValidUrl(platform.url)) {
        result.sameAs.push(normalizeUrl(platform.url));
      }
    }
  }

  // Extract sameAs from link blocks (only known social platforms)
  const linkBlocks = validBlocks.filter(b => b.type === 'link' || b.type === 'button') as LinkBlock[];
  for (const block of linkBlocks) {
    if (block.url && isValidUrl(block.url)) {
      const url = block.url.toLowerCase();
      for (const [, domain] of Object.entries(SOCIAL_PLATFORMS)) {
        if (url.includes(domain)) {
          result.sameAs.push(normalizeUrl(block.url));
          break;
        }
      }
    }
  }

  // Extract knowsAbout from pricing/services
  const pricingBlock = validBlocks.find(b => b.type === 'pricing') as any;
  if (pricingBlock?.items) {
    for (const item of (pricingBlock.items || []).filter((i: any): i is NonNullable<typeof i> => i != null && typeof i === 'object')) {
      if (!item.name) continue;
      const name = getI18nText(item.name, language);
      if (name && name.length > 2 && name.length < 50) {
        result.knowsAbout.push(name);
      }
    }
  }

  // Extract knowsAbout from catalog categories
  const catalogBlock = validBlocks.find(b => b.type === 'catalog') as any;
  if (catalogBlock?.categories) {
    for (const category of (catalogBlock.categories || []).filter((c: any) => c != null && typeof c === 'object' && c.name)) {
      const name = getI18nText(category.name, language);
      if (name && name.length > 2 && name.length < 50) {
        result.knowsAbout.push(name);
      }
    }
  }

  // Remove duplicates
  result.sameAs = Array.from(new Set(result.sameAs));
  result.knowsAbout = Array.from(new Set(result.knowsAbout));

  return result;
}

/**
 * Validate URL format
 */
function isValidUrl(url: string): boolean {
  try {
    new URL(url);
    return true;
  } catch {
    return false;
  }
}

/**
 * Normalize URL (remove trailing slashes, lowercase domain)
 */
function normalizeUrl(url: string): string {
  try {
    const parsed = new URL(url);
    return `${parsed.protocol}//${parsed.host.toLowerCase()}${parsed.pathname.replace(/\/$/, '')}`;
  } catch {
    return url;
  }
}

/**
 * Generate structured skills/tags from pricing and catalog
 */
export function extractSkillTags(
  blocks: Block[],
  language: 'ru' | 'en' | 'kk' = 'ru'
): string[] {
  const tags: string[] = [];

  // Guard against undefined/null blocks
  const validBlocks = (blocks || []).filter((b): b is Block => b != null && typeof b === 'object' && 'type' in b);

  // From pricing serviceType
  const pricingBlock = validBlocks.find(b => b.type === 'pricing') as any;
  if (pricingBlock?.items) {
    for (const item of (pricingBlock.items || []).filter((i: any) => i != null && typeof i === 'object')) {
      if (item.serviceType && item.serviceType !== 'other') {
        tags.push(item.serviceType);
      }
    }
  }

  // From catalog categories
  const catalogBlock = validBlocks.find(b => b.type === 'catalog') as any;
  if (catalogBlock?.categories) {
    for (const category of (catalogBlock.categories || []).filter((c: any) => c != null && typeof c === 'object' && c.name)) {
      const name = getI18nText(category.name, language);
      if (name) {
        tags.push(name.toLowerCase().replace(/\s+/g, '-'));
      }
    }
  }

  return Array.from(new Set(tags)).slice(0, 10);
}

/**
 * GEO (Generative Engine Optimization) Schemas
 * 
 * Advanced Schema.org generators for AI citability.
 * Includes Person, Organization, LocalBusiness, Service, Event schemas
 * with enhanced entity linking.
 */

import type { Block, PricingBlock, EventBlock, FAQBlock, SocialsBlock, BookingBlock, MapBlock } from '@/types/page';
import { getI18nText } from '@/lib/i18n-helpers';
import type { AnswerBlockData } from './answer-block';

export interface GEOSchemas {
  /** Main entity schema (Person/Organization/LocalBusiness) */
  mainEntity: object;
  /** ProfilePage/WebPage schema */
  webPage: object;
  /** BreadcrumbList schema */
  breadcrumb: object;
