/**
 * Key Facts Generator for AEO/GEO
 * 
 * Generates structured "key facts" bullets for AI extraction.
 * These are the atomic facts that AI engines can cite directly.
 */

import type { Block, PricingBlock, SocialsBlock, BookingBlock, EventBlock } from '@/types/page';
import { getI18nText } from '@/lib/i18n-helpers';
import type { AnswerBlockData } from './answer-block';

export interface KeyFact {
  /** Fact category for grouping */
  category: 'identity' | 'services' | 'location' | 'contact' | 'features' | 'social';
  /** Fact label */
  label: string;
  /** Fact value */
  value: string;
  /** Schema.org property if applicable */
  schemaProperty?: string;
}

interface FactTemplates {
  name: string;
  role: string;
  location: string;
  services: string;
  servicesCount: string;
  priceFrom: string;
  booking: string;
  events: string;
  eventsCount: string;
  socials: string;
  languages: string;
  experience: string;
}

const FACT_LABELS: Record<'ru' | 'en' | 'kk', FactTemplates> = {
  ru: {
    name: 'Имя',
    role: 'Специализация',
    location: 'Локация',
    services: 'Услуги',
    servicesCount: 'Количество услуг',
    priceFrom: 'Цены от',
    booking: 'Онлайн-запись',
    events: 'Мероприятия',
    eventsCount: 'Событий',
    socials: 'Соцсети',
    languages: 'Языки',
    experience: 'Опыт',
  },
  en: {
    name: 'Name',
    role: 'Specialization',
    location: 'Location',
    services: 'Services',
    servicesCount: 'Number of services',
    priceFrom: 'Prices from',
    booking: 'Online booking',
    events: 'Events',
    eventsCount: 'Events count',
    socials: 'Social media',
    languages: 'Languages',
    experience: 'Experience',
  },
  kk: {
    name: 'Аты',
    role: 'Мамандығы',
    location: 'Орналасуы',
    services: 'Қызметтер',
    servicesCount: 'Қызмет саны',
    priceFrom: 'Бағалар',
    booking: 'Онлайн жазылу',
    events: 'Іс-шаралар',
    eventsCount: 'Оқиғалар саны',
    socials: 'Әлеуметтік желілер',
    languages: 'Тілдер',
    experience: 'Тәжірибе',
  },
};

/**
 * Generate comprehensive key facts from blocks
 */
export function generateKeyFacts(
  blocks: Block[],
  answerBlock: AnswerBlockData,
  name: string | undefined,
  language: 'ru' | 'en' | 'kk' = 'ru'
): KeyFact[] {
  const facts: KeyFact[] = [];
  const labels = FACT_LABELS[language];

  // Guard against undefined/null blocks
  const validBlocks = (blocks || []).filter((b): b is Block => b != null && typeof b === 'object' && 'type' in b);

  // 1. Identity facts
  if (name) {
    facts.push({
      category: 'identity',
      label: labels.name,
      value: name,
      schemaProperty: 'name',
    });
  }

  if (answerBlock.niche) {
    facts.push({
      category: 'identity',
      label: labels.role,
      value: answerBlock.niche,
      schemaProperty: 'jobTitle',
    });
  }

  // 2. Location
  if (answerBlock.location) {
    facts.push({
      category: 'location',
      label: labels.location,
      value: answerBlock.location,
      schemaProperty: 'address',
    });
  }

  // 3. Services
  const pricingBlock = validBlocks.find(b => b.type === 'pricing') as PricingBlock | undefined;
  if (pricingBlock?.items?.length) {
    // Filter out undefined/null items
    const validItems = (pricingBlock.items || []).filter(
      (item: any): item is NonNullable<typeof item> => item != null && typeof item === 'object'
    );

    // Service count
    facts.push({
      category: 'services',
      label: labels.servicesCount,
      value: String(validItems.length),
    });

    // Service names (top 3)
    const serviceNames = validItems
      .slice(0, 3)
      .map((item: any) => item.name ? getI18nText(item.name, language) : '')
      .filter(Boolean)
      .join(', ');

    if (serviceNames) {
      facts.push({
        category: 'services',
        label: labels.services,
        value: serviceNames,
        schemaProperty: 'knowsAbout',
      });
    }

    // Min price
    const prices = validItems
      .map((item: any) => item.price)
      .filter((p: any): p is number => typeof p === 'number' && p > 0);

    if (prices.length > 0) {
      const minPrice = Math.min(...prices);
      const currency = pricingBlock.currency || 'KZT';
      facts.push({
        category: 'services',
        label: labels.priceFrom,
        value: `${minPrice.toLocaleString()} ${currency}`,
        schemaProperty: 'priceRange',
      });
    }
  }

  // 4. Booking availability
  const hasBooking = validBlocks.some(b => b.type === 'booking');
  if (hasBooking) {
    facts.push({
      category: 'features',
      label: labels.booking,
      value: language === 'ru' ? 'Доступна' : language === 'kk' ? 'Қолжетімді' : 'Available',
    });
  }

  // 5. Events
  const eventBlocks = validBlocks.filter(b => b.type === 'event') as EventBlock[];
  const activeEvents = eventBlocks.filter(e => e.status === 'published');
  if (activeEvents.length > 0) {
    facts.push({
      category: 'features',
      label: labels.eventsCount,
      value: String(activeEvents.length),
    });
  }

  // 6. Social links count
  const socialsBlock = validBlocks.find(b => b.type === 'socials') as SocialsBlock | undefined;
  if (socialsBlock?.platforms?.length) {
    const platformNames = (socialsBlock.platforms || [])
      .filter((p: any) => p != null && typeof p === 'object')
      .slice(0, 4)
      .map((p: any) => p.name || p.url?.split('/')[2]?.replace('www.', ''))
      .filter(Boolean)
      .join(', ');

    if (platformNames) {
      facts.push({
        category: 'social',
        label: labels.socials,
        value: platformNames,
        schemaProperty: 'sameAs',
      });
    }
  }

  return facts;
}

/**
 * Format facts as bullet list for HTML
 */
export function formatFactsAsBullets(facts: KeyFact[], language: 'ru' | 'en' | 'kk'): string {
  if (facts.length === 0) return '';

  const items = facts.map(f => `• ${f.label}: ${f.value}`);
  return items.join('\n');
}

/**
 * Format facts as HTML list
 */
export function formatFactsAsHtml(facts: KeyFact[]): string {
  if (facts.length === 0) return '';

  const items = facts.map(f => {
    const prop = f.schemaProperty ? ` itemprop="${f.schemaProperty}"` : '';
    return `<li${prop}><strong>${f.label}:</strong> ${f.value}</li>`;
  });

  return `<ul class="key-facts">${items.join('')}</ul>`;
}

/**
 * Group facts by category
 */
export function groupFactsByCategory(facts: KeyFact[]): Record<KeyFact['category'], KeyFact[]> {
  const groups: Record<KeyFact['category'], KeyFact[]> = {
    identity: [],
    services: [],
    location: [],
    contact: [],
    features: [],
    social: [],
  };

  for (const fact of facts) {
    groups[fact.category].push(fact);
  }

  return groups;
}

/**
 * Secure localStorage wrapper utility
 * - Namespaced keys to prevent collisions
 * - Type-safe API
 * - JSON serialization/deserialization
 * - Error handling
 * - Prevents XSS attacks through key isolation
 */

import { logger } from '@/lib/utils/logger';

const STORAGE_PREFIX = 'inkmax_';
const STORAGE_VERSION = 'v2_';

/**
 * Get namespaced key
 */
function getKey(key: string): string {
    return `${STORAGE_PREFIX}${STORAGE_VERSION}${key}`;
}

/**
 * Secure storage interface
 */
export const storage = {
    /**
     * Get item from localStorage
     * @param key - Storage key (will be namespaced automatically)
     * @returns Parsed value or null if not found
     */
    get<T = unknown>(key: string): T | null {
        if (typeof window === 'undefined') return null;
        try {
            const item = localStorage.getItem(getKey(key));
            if (item === null) return null;
            return JSON.parse(item) as T;
        } catch (error) {
            logger.error(`Error reading from storage: ${key}`, error, { context: 'storage' });
            return null;
        }
    },

    /**
     * Set item in localStorage
     * @param key - Storage key (will be namespaced automatically)
     * @param value - Value to store (will be JSON stringified)
     */
    set<T = unknown>(key: string, value: T): void {
        if (typeof window === 'undefined') return;
        try {
            localStorage.setItem(getKey(key), JSON.stringify(value));
        } catch (error) {
            logger.error(`Error writing to storage: ${key}`, error, { context: 'storage' });
            // Handle quota exceeded error
            if (error instanceof DOMException && error.name === 'QuotaExceededError') {
                logger.warn('localStorage quota exceeded, clearing old data', { context: 'storage' });
                this.clearOldVersions();
            }
        }
    },

    /**
     * Remove item from localStorage
     * @param key - Storage key (will be namespaced automatically)
     */
    remove(key: string): void {
        if (typeof window === 'undefined') return;
        try {
            localStorage.removeItem(getKey(key));
        } catch (error) {
            logger.error(`Error removing from storage: ${key}`, error, { context: 'storage' });
        }
    },

    /**
     * Check if key exists in localStorage
     * @param key - Storage key (will be namespaced automatically)
     */
    has(key: string): boolean {
        if (typeof window === 'undefined') return false;
        return localStorage.getItem(getKey(key)) !== null;
    },

    /**
     * Clear all inkmax storage (keeps other apps' data)
     */
    clear(): void {
        if (typeof window === 'undefined') return;
        try {
            const keys = Object.keys(localStorage);
            keys.forEach((key) => {
                if (key.startsWith(STORAGE_PREFIX)) {
                    localStorage.removeItem(key);
                }
            });
        } catch (error) {
            logger.error('Error clearing storage', error, { context: 'storage' });
        }
    },

    /**
     * Get all keys (namespaced)
     */
    keys(): string[] {
        if (typeof window === 'undefined') return [];
        const keys = Object.keys(localStorage);
        return keys
            .filter((key) => key.startsWith(getKey('')))
            .map((key) => key.replace(getKey(''), ''));
    },

    /**
     * Get storage size in bytes (approximate)
     */
    getSize(): number {
        if (typeof window === 'undefined') return 0;
        let size = 0;
        try {
            const keys = Object.keys(localStorage);
            keys.forEach((key) => {
                if (key.startsWith(STORAGE_PREFIX)) {
                    const value = localStorage.getItem(key);
                    if (value) {
                        size += key.length + value.length;
                    }
                }
            });
        } catch (error) {
            logger.error('Error calculating storage size', error, { context: 'storage' });
        }
        return size;
    },

    /**
     * Clear old version data (migration utility)
     */
    clearOldVersions(): void {
        if (typeof window === 'undefined') return;
        try {
            const keys = Object.keys(localStorage);
            keys.forEach((key) => {
                // Remove keys with old version or no version
                if (key.startsWith(STORAGE_PREFIX) && !key.startsWith(getKey(''))) {
                    localStorage.removeItem(key);
                }
            });
        } catch (error) {
            logger.error('Error clearing old versions', error, { context: 'storage' });
        }
    },

    /**
     * Get raw value without parsing (for debugging)
     */
    getRaw(key: string): string | null {
        if (typeof window === 'undefined') return null;
        return localStorage.getItem(getKey(key));
    },

    /**
     * Set raw value without stringifying (use with caution)
     */
    setRaw(key: string, value: string): void {
        if (typeof window === 'undefined') return;
        localStorage.setItem(getKey(key), value);
    },
};

/**
 * Secure session storage interface
 */
export const session = {
    /**
     * Get item from sessionStorage
     */
    get<T = unknown>(key: string): T | null {
        if (typeof window === 'undefined') return null;
        try {
            const item = sessionStorage.getItem(getKey(key));
            if (item === null) return null;
            return JSON.parse(item) as T;
        } catch (error) {
            logger.error(`Error reading from session storage: ${key}`, error, { context: 'storage' });
            return null;
        }
    },

    /**
     * Set item in sessionStorage
     */
    set<T = unknown>(key: string, value: T): void {
        if (typeof window === 'undefined') return;
        try {
            sessionStorage.setItem(getKey(key), JSON.stringify(value));
        } catch (error) {
            logger.error(`Error writing to session storage: ${key}`, error, { context: 'storage' });
        }
    },

    /**
     * Remove item from sessionStorage
     */
    remove(key: string): void {
        if (typeof window === 'undefined') return;
        try {
            sessionStorage.removeItem(getKey(key));
        } catch (error) {
            logger.error(`Error removing from session storage: ${key}`, error, { context: 'storage' });
        }
    },

    /**
     * Check if key exists in sessionStorage
     */
    has(key: string): boolean {
        if (typeof window === 'undefined') return false;
        return sessionStorage.getItem(getKey(key)) !== null;
    },

    /**
     * Clear all inkmax session storage
     */
    clear(): void {
        if (typeof window === 'undefined') return;
        try {
            const keys = Object.keys(sessionStorage);
            keys.forEach((key) => {
                if (key.startsWith(STORAGE_PREFIX)) {
                    sessionStorage.removeItem(key);
                }
            });
        } catch (error) {
            logger.error('Error clearing session storage', error, { context: 'storage' });
        }
    },
};

