                })}

                {/* Add Language Button */}
                <Dialog open={addLanguageOpen} onOpenChange={setAddLanguageOpen}>
                  <DialogTrigger asChild>
                    <Button variant="outline" className="h-auto py-2 px-3">
                      <Plus className="h-4 w-4 mr-1" />
